using System.Globalization;
using System.Numerics;
using System.Text;
using System.Xml;
using PhoenixmlDb.Core;
using PhoenixmlDb.Xdm;
using PhoenixmlDb.Xdm.Nodes;
using PhoenixmlDb.Xdm.Serialization;
using PhoenixmlDb.XQuery.Ast;
using PhoenixmlDb.Xslt.Ast;
// XPath 4.0 ordered map: insertion-order iteration as a structural guarantee.
// xslt keeps its existing default key-equality (pass EqualityComparer<object>.Default
// at each construction site) — this change is about iteration order only.
using OrderedXdmMap = PhoenixmlDb.XQuery.Execution.OrderedXdmMap;

namespace PhoenixmlDb.Xslt.Engine;

/// <summary>
/// Collects variable and function references from expressions for dependency analysis.
/// </summary>
internal sealed class DependencyCollector : XQueryExpressionWalker
{
    public HashSet<QName> VariableRefs { get; } = new();
    public HashSet<QName> FunctionRefs { get; } = new();

    public override object? VisitVariableReference(VariableReference expr)
    {
        VariableRefs.Add(expr.Name);
        return null;
    }

    public override object? VisitFunctionCallExpression(FunctionCallExpression expr)
    {
        // Track function calls - we need to analyze function bodies for transitive dependencies
        FunctionRefs.Add(expr.Name);
        // Also walk the arguments
        foreach (var arg in expr.Arguments)
            Walk(arg);
        return null;
    }
}

/// <summary>
/// Represents a global declaration (param or variable) for dependency sorting.
/// </summary>
internal sealed class GlobalDeclaration
{
    public required QName Name { get; init; }
    public bool IsParam { get; init; }
    public XQueryExpression? Select { get; init; }
    public XsltSequenceConstructor? Content { get; init; }
    public XdmSequenceType? As { get; init; }
    public object? OriginalDeclaration { get; init; }
    public Uri? BaseUri { get; init; }
    public string? Version { get; init; }
}

/// <summary>
/// XSLT transformation engine.
/// </summary>
public sealed class XsltTransformEngine
{
    private readonly XsltStylesheet _stylesheet;
    private readonly TemplateIndex _templateIndex;
    private readonly PhoenixmlDb.XQuery.ISchemaProvider? _schemaProvider;

    // Temp-tree base-URI preservation sentinel. Emitted by the temp-tree serializer only
    // (gated by _tempTreeSerializeDepth) and always stripped by the reparse, so it never
    // appears in any user-visible output. See TryEmitBaseSentinel / ReadXdmElementFromReader
    // / ConvertXmlNode for the round-trip.
    internal const string BaseSentinelNs = "http://phoenixmldb/internal/base-uri";
    internal const string BaseSentinelPrefix = "_pxbase_";
    internal const string BaseSentinelLocalName = "base";

    /// <summary>
    /// Secondary result documents from the last transformation, keyed by href URI.
    /// </summary>
    public IReadOnlyDictionary<string, string> SecondaryResultDocuments { get; private set; }
        = new Dictionary<string, string>();

    public XsltTransformEngine(XsltStylesheet stylesheet,
        PhoenixmlDb.XQuery.ISchemaProvider? schemaProvider = null)
    {
        ArgumentNullException.ThrowIfNull(stylesheet);
        _stylesheet = stylesheet;
        _templateIndex = new TemplateIndex(stylesheet);
        _schemaProvider = schemaProvider;
    }

    /// <summary>
    /// Converts a Uri to string, distinguishing two cases that look similar through .NET's
    /// <see cref="Uri"/> API but need opposite handling:
    /// <list type="bullet">
    ///   <item><b>Windows drive-letter path</b> (e.g. <c>C:\Users\…\file.xsl</c> or
    ///         <c>C:/Users/…/file.xsl</c>) — produces <see cref="Uri.Scheme"/> = "file"
    ///         and <see cref="Uri.OriginalString"/> as the path. We want the proper file
    ///         URI form (<c>file:///C:/Users/…</c>) so <c>doc()</c> on the other side
    ///         can recognize and read the file.</item>
    ///   <item><b>Non-standard scheme URI</b> (e.g. <c>d://tests/</c>) — .NET on Linux
    ///         mangles this to <c>file:///d://tests/</c> via <see cref="Uri.ToString"/>.
    ///         We want to preserve <see cref="Uri.OriginalString"/>.</item>
    /// </list>
    /// The distinguishing pattern: a Windows drive path starts with one ASCII letter
    /// then ":" then "\" or "/". A non-standard scheme URI has a multi-char scheme name
    /// before "://", or uses a single-letter scheme followed by content that doesn't
    /// look like a drive path. The earlier "any colon means scheme mangling" heuristic
    /// caught both cases and broke <c>doc()</c> on Windows (Martin Honnen's report:
    /// <c>localization-base-uri: C:/Users/marti/…/locale/</c> instead of <c>file:///C:/…</c>).
    /// </summary>
    internal static string? UriString(Uri? uri)
    {
        if (uri == null) return null;
        if (uri.Scheme == "file" && !uri.OriginalString.StartsWith("file:", StringComparison.OrdinalIgnoreCase))
        {
            // Windows drive-letter path: ASCII letter + ":" + ("\" or "/").
            // Use the canonical file URI form so downstream parsers recognize it.
            if (LooksLikeWindowsDrivePath(uri.OriginalString))
                return uri.AbsoluteUri;
            // Otherwise the original looked like a non-standard URI scheme that .NET
            // mangled. Preserve OriginalString so the original semantics survive.
            if (uri.OriginalString.Contains(':', StringComparison.Ordinal))
                return uri.OriginalString;
        }
        return uri.ToString();
    }

    private static bool LooksLikeWindowsDrivePath(string s)
    {
        // C:\... or C:/... — exactly one ASCII letter, then ':', then '\' or '/'.
        if (s.Length < 3) return false;
        if (!char.IsAsciiLetter(s[0])) return false;
        if (s[1] != ':') return false;
        return s[2] == '\\' || s[2] == '/';
    }

    private static XQueryExpression ToLiteralExpression(object? value) => value switch
    {
        string s => new StringLiteral { Value = s },
        int i => new IntegerLiteral { Value = (long)i },
        long l => new IntegerLiteral { Value = l },
        double d => new DoubleLiteral { Value = d },
        bool b => b ? BooleanLiteral.True : BooleanLiteral.False,
        null => EmptySequence.Instance,
        _ => new StringLiteral { Value = value.ToString()! }
    };

    /// <summary>
    /// Transforms an XML document using the stylesheet.
    /// </summary>
    public Task<string> TransformAsync(XdmNode source, XsltTransformOptions? options = null)
        => TransformAsync(source, options, null);

    internal async Task<string> TransformAsync(XdmNode source, XsltTransformOptions? options, XdmInMemoryStore? nodeStore)
    {
        ArgumentNullException.ThrowIfNull(source);
        options ??= new XsltTransformOptions();

        var outputBuilder = new StringBuilder();
        var context = new DefaultXsltExecutionContext(
            _stylesheet,
            _templateIndex,
            source,
            outputBuilder,
            options,
            nodeStore,
            _schemaProvider);
        context.Owner = this;

        // When there is no source document, the context item is absent during global variable
        // evaluation (XSLT 3.0 §5.4.1: global variables are evaluated with the initial focus).
        if (!options.HasSourceDocument)
            context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

        // Initialize global parameters and variables in dependency order
        await InitializeGlobalsInDependencyOrderAsync(context, outputBuilder).ConfigureAwait(false);

        if (!options.HasSourceDocument)
            context.PopContextItem();

        // Bind initial parameters as global variables (overriding stylesheet defaults)
        foreach (var (name, value) in options.InitialParameters)
        {
            context.GlobalVariables[name] = value;
        }

        // XTDE0050: Check that all required global parameters have been supplied
        foreach (var param in _stylesheet.Parameters)
        {
            if (param.Required && !options.InitialParameters.ContainsKey(param.Name))
                throw new XsltException($"XTDE0050: Required parameter ${param.Name.LocalName} was not supplied");
        }

        // xsl:global-context-item enforcement
        if (_stylesheet.GlobalContextItemUse == Ast.ContextItemUse.Required && !options.HasSourceDocument)
            throw new XsltException("XTDE3086: The stylesheet requires a global context item (use=\"required\"), but none was supplied");
        if (_stylesheet.GlobalContextItemUse == Ast.ContextItemUse.Absent && options.HasSourceDocument)
            throw new XsltException("XTSE3088: The stylesheet specifies that no global context item should be supplied (use=\"absent\"), but a source document was provided");

        // xsl:global-context-item type checking
        if (_stylesheet.GlobalContextItemAs != null && options.HasSourceDocument)
        {
            var typeMatches = XQuery.Execution.TypeCastHelper.MatchesSequenceItemType(source, _stylesheet.GlobalContextItemAs);

            // Additional check for document-node(element(name))
            if (typeMatches && _stylesheet.GlobalContextItemAs.DocumentElementName != null
                && source is XdmDocument gciDoc)
            {
                // Resolve document element via node store
                XdmElement? docElem = null;
                if (nodeStore != null)
                {
                    docElem = gciDoc.Children
                        .Select(id => nodeStore.GetNode(id))
                        .OfType<XdmElement>()
                        .FirstOrDefault();
                }

                if (docElem == null || docElem.LocalName != _stylesheet.GlobalContextItemAs.DocumentElementName)
                    typeMatches = false;
            }

            if (!typeMatches)
                throw new XsltException("XTTE0590: The global context item does not match the required type declared by xsl:global-context-item");
        }

        // Pre-compute accumulators on the source document if the initial mode specifies use-accumulators.
        // This happens after globals (accumulator initial values may reference parameters) but before
        // template application (templates and global variables may access accumulator values via
        // accumulator-before/after functions).
        if (source is XdmDocument sourceDoc && nodeStore != null && _stylesheet.Accumulators.Count > 0)
        {
            var initialModeKey = options.InitialMode ?? new QName(NamespaceId.None, "");
            if (_stylesheet.Modes.TryGetValue(initialModeKey, out var modeDecl))
            {
                List<XsltAccumulator>? accumulators = null;
                if (modeDecl.UseAllAccumulators)
                {
                    accumulators = _stylesheet.Accumulators.Values.ToList();
                }
                else if (modeDecl.UseAccumulatorNames.Count > 0)
                {
                    accumulators = new List<XsltAccumulator>();
                    foreach (var accName in modeDecl.UseAccumulatorNames)
                    {
                        if (_stylesheet.Accumulators.TryGetValue(accName, out var acc))
                            accumulators.Add(acc);
                    }
                }
                if (accumulators is { Count: > 0 })
                {
                    await context.PreComputeAccumulatorsAsync(sourceDoc, accumulators, nodeStore).ConfigureAwait(false);
                }
            }
        }

        // Check if output method is JSON or Adaptive — enable sequence collection
        var principalOutput = _stylesheet.Outputs.FirstOrDefault();
        var isJsonOutput = principalOutput?.EffectiveMethod is OutputMethod.Json or OutputMethod.Adaptive or OutputMethod.Csv;
        if (isJsonOutput)
            context.BeginSequenceCollection();

        // If an initial function is specified, call it directly (XSLT 3.0 "call function" invocation)
        if (options.InitialFunction != null)
        {
            var funcName = options.InitialFunction.Value;
            var arity = options.InitialFunctionArguments.Count;
            var funcKey = (funcName, arity);
            if (!_stylesheet.Functions.TryGetValue(funcKey, out var func))
                throw new XsltException(
                    $"XTDE0041: No public stylesheet function '{funcName.LocalName}' with arity {arity} is available");
            if (func.Visibility is not (Ast.Visibility.Public or Ast.Visibility.Final))
                throw new XsltException(
                    $"XTDE0041: Stylesheet function '{funcName.LocalName}' is not public");
            // Mirror the TransformRawAsync path (line ~637): if any args arrived as
            // CrossStoreNodeRef wrappers (outer XQuery passed nodes across the engine
            // boundary), re-parse into this engine's node store so xsl:evaluate can
            // navigate children/attributes. Without this they reach the function as
            // opaque CrossStoreNodeRef items and xpath axis steps throw XPTY0020.
            IReadOnlyList<object?> initialFuncArgs = TranslateNodeArgumentsToLocalStore(
                options.InitialFunctionArguments, context._nodeStore);
            var result = await context.CallXsltFunctionAsync(func, initialFuncArgs).ConfigureAwait(false);
            if (options.ReturnRawXdm)
            {
                // delivery-format='raw' from fn:transform: callers want the typed XDM
                // value end-to-end (booleans, maps, nodes…). Skip the text serialization
                // path that would otherwise stringify and lose the type. Found in Martin
                // Honnen's testing of fn:transform with initial-function returning
                // xs:boolean from xsl:evaluate.
                // Wrap any node items as CrossStoreNodeRef so the caller can re-anchor
                // them in its store — inner-store NodeIds don't resolve outside.
                options.RawResult.Value = WrapNodesForCrossStoreTransport(result, context);
            }
            else
            {
                // Default path: serialize the function result to the output
                context.SerializeFunctionResult(result, outputBuilder);
            }
        }
        // If an initial template is specified, call it directly instead of applying templates
        // Also auto-detect xsl:initial-template from the parsed stylesheet
        else if (options.InitialTemplate != null || (!options.HasSourceDocument && _stylesheet.NamedTemplates.Keys.Any(k => k.LocalName == "initial-template")))
        {
            var initialTemplate = options.InitialTemplate;
            if (initialTemplate == null)
            {
                initialTemplate = _stylesheet.NamedTemplates.Keys.First(k => k.LocalName == "initial-template");
            }

            // XTDE0040: Check that initial template is public (in packages)
            // Now that xsl:expose is implemented, visibility is correctly set on all components.
            if (_stylesheet.IsPackage
                && _stylesheet.NamedTemplates.TryGetValue(initialTemplate.Value, out var tmpl)
                && tmpl.Visibility is not (Ast.Visibility.Public or Ast.Visibility.Final))
                throw new XsltException($"XTDE0040: Initial template '{initialTemplate.Value.LocalName}' is not public");

            // Convert initial template parameters to xsl:with-param entries.
            // Only pass explicitly-set template params; global InitialParameters are set as
            // stylesheet-level variables separately and should NOT be passed as with-params.
            var withParams = new List<Ast.XsltWithParam>();
            foreach (var (name, value) in options.InitialTemplateParameters)
            {
                withParams.Add(new Ast.XsltWithParam
                {
                    Name = name,
                    Select = ToLiteralExpression(value)
                });
            }
            foreach (var (name, value) in options.InitialTunnelParameters)
            {
                withParams.Add(new Ast.XsltWithParam
                {
                    Name = name,
                    Select = ToLiteralExpression(value),
                    Tunnel = true
                });
            }
            // When calling an initial template with no source document, the context item
            // should be absent per XSLT 3.0 §2.3
            if (!options.HasSourceDocument)
                context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);
            await context.CallTemplateAsync(initialTemplate.Value, withParams).ConfigureAwait(false);
            if (!options.HasSourceDocument)
                context.PopContextItem();
        }
        else
        {
            // XTDE0044: It is a dynamic error if the invocation of the stylesheet specifies
            // an initial mode and no initial match selection is supplied.
            if (options.InitialMode.HasValue && !options.HasSourceDocument && options.InitialModeSelect == null)
                throw new XsltException("XTDE0044: The invocation of the stylesheet specifies an initial mode but no initial match selection is supplied");

            // Apply templates to the document node itself (XSLT semantics: initial match is against "/")
            // If no explicit initial mode was requested, use the stylesheet's default-mode.
            var effectiveInitialMode = options.InitialMode ?? _stylesheet.DefaultMode;

            // XTDE0045: The initial mode must be a mode used in the stylesheet.
            // A mode is "used" if a template explicitly declares it (not just #all)
            // or if it is declared via xsl:mode.
            // Skip the check for the default mode (#unnamed / #default) — per spec,
            // the error only applies to modes "other than the default mode".
            if (options.InitialMode.HasValue)
            {
                var m = options.InitialMode.Value;
                var isDefaultMode = m.LocalName is "#unnamed" or "#default" or ""
                    || m.Equals(_stylesheet.DefaultMode);
                if (!isDefaultMode
                    && !_templateIndex.IsModeExplicitlyUsed(m)
                    && !_stylesheet.Modes.ContainsKey(m))
                    throw new XsltException($"XTDE0045: The initial mode '{m.LocalName}' is not a mode used in the stylesheet");

                // XTDE0045: A mode is eligible as initial mode only if it has public or
                // final visibility, or it is the default mode. In packages, modes default
                // to private; in stylesheets, only explicitly-declared private modes are affected.
                if (!isDefaultMode
                    && _stylesheet.Modes.TryGetValue(m, out var modeDecl)
                    && (modeDecl.VisibilityAttr != null || _stylesheet.IsPackage)
                    && modeDecl.Visibility is Ast.Visibility.Private)
                    throw new XsltException($"XTDE0045: The initial mode '{m.LocalName}' is not eligible as an initial mode (it has private visibility)");
            }

            // Build with-params from initial template/mode parameters
            var applyWithParams = new List<Ast.XsltWithParam>();
            foreach (var (name, value) in options.InitialTemplateParameters)
            {
                applyWithParams.Add(new Ast.XsltWithParam
                {
                    Name = name,
                    Select = ToLiteralExpression(value)
                });
            }
            foreach (var (name, value) in options.InitialTunnelParameters)
            {
                applyWithParams.Add(new Ast.XsltWithParam
                {
                    Name = name,
                    Select = ToLiteralExpression(value),
                    Tunnel = true
                });
            }

            // If InitialModeSelect is specified, evaluate it and apply templates to the result
            if (options.InitialModeSelect != null)
            {
                var selectExpr = new XQuery.Parser.XQueryParserFacade { AllowNamespaceAxis = true }.Parse(options.InitialModeSelect);
                await context.ApplyTemplatesAsync(
                    selectExpr,
                    effectiveInitialMode,
                    [],
                    applyWithParams).ConfigureAwait(false);
            }
            else
            {
                await context.ApplyTemplatesAsync(
                    ContextItemExpression.Instance, // select="." yields the document node
                    effectiveInitialMode,
                    [],
                    applyWithParams).ConfigureAwait(false);
            }
        }

        // For JSON/Adaptive output: collect sequence items and serialize as JSON
        if (isJsonOutput)
        {
            FinalizeJsonOutput(context, outputBuilder, principalOutput, nodeStore, options);
        }

        // Capture secondary result documents from this transform
        SecondaryResultDocuments = context.SecondaryResults;

        var output = outputBuilder.ToString();

        // Apply output method post-processing
        // When result-document claimed primary output with a named format, use that declaration
        var outputDecl = context.PrimaryOutputMatchedDeclaration ?? _stylesheet.Outputs.FirstOrDefault();
        return FinalizeOutput(output, outputDecl, context.PrincipalOutputCharacterMaps, FinalizeKind.Primary);
    }

    /// <summary>
    /// Identifies which delivery path invoked <see cref="FinalizeOutput"/>. Later tasks may
    /// branch on this; the post-processing body is currently identical for all kinds.
    /// </summary>
    internal enum FinalizeKind { Primary, ResultDocument, StreamingSink }

    /// <summary>
    /// Applies the shared serialization post-processing pipeline (text/html post-process,
    /// content-type meta, indentation, character maps, Unicode normalization, XML declaration,
    /// doctype, BOM, escape-uri-attributes, sentinel restore) to <paramref name="output"/>.
    /// </summary>
    internal string FinalizeOutput(string output, XsltOutput? outputDecl, IReadOnlyList<QName>? resultDocCharacterMaps, FinalizeKind kind)
    {
        if (outputDecl != null)
        {
            if (outputDecl.EffectiveMethod == OutputMethod.Text)
            {
                // Text output: strip all markup, return only text content.
                // The secondary xsl:result-document path (FinalizeKind.ResultDocument) has already
                // stripped its text content WITHOUT sentinel protection, so re-stripping here would
                // re-process decoded markup characters and corrupt the output. Skip the strip for
                // that path; the primary result-document path uses FinalizeKind.Primary (and sentinel
                // escaping), so it still strips correctly here.
                if (kind != FinalizeKind.ResultDocument)
                    output = DefaultXsltExecutionContext.StripXmlMarkup(output);
            }
            else if (outputDecl.EffectiveMethod == OutputMethod.Html || outputDecl.EffectiveMethod == OutputMethod.Xhtml)
            {
                output = DefaultXsltExecutionContext.PostProcessHtmlOutput(output);
            }

            // Insert <meta http-equiv="Content-Type"> in <head> when include-content-type is yes (default)
            if ((outputDecl.EffectiveMethod == OutputMethod.Html || outputDecl.EffectiveMethod == OutputMethod.Xhtml) &&
                outputDecl.IncludeContentType != false)
            {
                output = DefaultXsltExecutionContext.InsertContentTypeMeta(output, outputDecl);
            }

            // Apply indentation. Per XSLT 3.0 §20: default is yes for html/xhtml, no for xml.
            var effectiveIndent = outputDecl.Indent
                ?? (outputDecl.EffectiveMethod is OutputMethod.Html or OutputMethod.Xhtml);
            if (effectiveIndent &&
                outputDecl.EffectiveMethod is OutputMethod.Xml or OutputMethod.Xhtml or OutputMethod.Html)
            {
                output = ApplyIndentation(output, outputDecl.EffectiveMethod, outputDecl.SuppressIndentation);
            }
        }

        // Apply character maps: merge xsl:output maps with xsl:result-document maps.
        // Per XSLT 3.0 §20: result-document maps supplement and take precedence.
        if (_stylesheet.CharacterMaps.Count > 0)
        {
            var outputMaps = outputDecl?.UseCharacterMaps;
            var rdMaps = resultDocCharacterMaps;
            if ((outputMaps != null && outputMaps.Count > 0) || (rdMaps != null && rdMaps.Count > 0))
            {
                // Build merged list: output maps first, then result-document maps (later ones override)
                var mergedMaps = new List<QName>();
                if (outputMaps != null) mergedMaps.AddRange(outputMaps);
                if (rdMaps != null) mergedMaps.AddRange(rdMaps);
                output = ApplyCharacterMaps(output, mergedMaps);
            }
        }

        // Apply Unicode normalization if specified
        if (outputDecl?.NormalizationForm != null)
        {
            output = outputDecl.NormalizationForm.ToUpperInvariant() switch
            {
                "NFC" => output.Normalize(System.Text.NormalizationForm.FormC),
                "NFD" => output.Normalize(System.Text.NormalizationForm.FormD),
                "NFKC" => output.Normalize(System.Text.NormalizationForm.FormKC),
                "NFKD" => output.Normalize(System.Text.NormalizationForm.FormKD),
                _ => output
            };
        }

        // Emit XML declaration if requested
        if (outputDecl != null &&
            (outputDecl.EffectiveMethod == OutputMethod.Xml || outputDecl.EffectiveMethod == OutputMethod.Xhtml) &&
            outputDecl.OmitXmlDeclaration != true &&
            !output.StartsWith("<?xml", StringComparison.Ordinal))
        {
            var encoding = outputDecl.Encoding ?? "UTF-8";
            var version = outputDecl.Version ?? "1.0";
            var decl = $"<?xml version=\"{version}\" encoding=\"{encoding}\"";
            if (outputDecl.Standalone.HasValue)
                decl += outputDecl.Standalone.Value ? " standalone=\"yes\"" : " standalone=\"no\"";
            decl += "?>";
            output = decl + output;
        }

        // Emit DOCTYPE declaration if doctype-system (and optionally doctype-public) is set
        if (outputDecl != null && outputDecl.DoctypeSystem != null)
        {
            output = InsertDoctype(output, outputDecl.DoctypePublic, outputDecl.DoctypeSystem);
        }

        // Prepend UTF-8 BOM when byte-order-mark="yes"
        if (outputDecl?.ByteOrderMark == true)
        {
            output = "\uFEFF" + output;
        }

        // escape-uri-attributes: in HTML/XHTML output, percent-encode non-ASCII characters
        // in URI-valued attributes (href, src, action, cite, data, formaction, poster, srcset, usemap)
        if (outputDecl != null &&
            (outputDecl.EffectiveMethod == OutputMethod.Html || outputDecl.EffectiveMethod == OutputMethod.Xhtml) &&
            outputDecl.EscapeUriAttributes != false)
        {
            output = EscapeUriAttributes(output);
        }

        // undeclare-prefixes="yes" only has effect for XML 1.1 output. Since this engine
        // produces XML 1.0 output, namespace undeclarations (xmlns:prefix="") are not
        // generated. This is correct per the serialization spec: undeclare-prefixes is a
        // no-op for XML 1.0 because namespace undeclarations are not permitted in XML 1.0.

        // Restore sentinel-escaped text content from method="text" result-documents.
        // Sentinels protect text node content (from xsl:sequence/xsl:value-of/xsl:text)
        // from StripXmlMarkup which only strips generated XML markup.
        if (output.Contains('\uFDD0', StringComparison.Ordinal))
        {
            output = output
                .Replace("\uFDD0", "<", StringComparison.Ordinal)
                .Replace("\uFDD1", ">", StringComparison.Ordinal)
                .Replace("\uFDD2", "&", StringComparison.Ordinal);
        }

        return output;
    }

    /// <summary>
    /// Transforms with "raw" delivery: returns the raw XDM result value(s) instead of
    /// serialized output. Used by fn:transform with delivery-format='raw'.
    /// Function items, maps, and atomic values are preserved as-is.
    /// </summary>
    internal async Task<object?> TransformRawAsync(XdmNode source, XsltTransformOptions? options, XdmInMemoryStore? nodeStore)
    {
        ArgumentNullException.ThrowIfNull(source);
        options ??= new XsltTransformOptions();

        var outputBuilder = new StringBuilder();
        var context = new DefaultXsltExecutionContext(
            _stylesheet,
            _templateIndex,
            source,
            outputBuilder,
            options,
            nodeStore,
            _schemaProvider);
        context.Owner = this;

        if (!options.HasSourceDocument)
            context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

        await InitializeGlobalsInDependencyOrderAsync(context, outputBuilder).ConfigureAwait(false);

        if (!options.HasSourceDocument)
            context.PopContextItem();

        foreach (var (name, value) in options.InitialParameters)
            context.GlobalVariables[name] = value;

        // Enable sequence collection to capture raw XDM values (function items, maps, etc.)
        context.BeginSequenceCollection();

        if (options.InitialFunction != null)
        {
            var funcName = options.InitialFunction.Value;
            var arity = options.InitialFunctionArguments.Count;
            var funcKey = (funcName, arity);
            if (!_stylesheet.Functions.TryGetValue(funcKey, out var func))
                throw new XsltException($"XTDE0041: No public stylesheet function '{funcName.LocalName}' with arity {arity}");
            // Translate XdmNode arguments into this engine's node store so XPath/xsl:evaluate
            // inside the function can navigate them (string-value, child axes, etc.).
            // Without this, a node passed across fn:transform's engine boundary reaches
            // the function as an opaque reference — name() works but string() returns ""
            // because the inner store can't resolve the foreign Children NodeIds
            // (Martin Honnen 2026-05-18, fn:transform with initial-function +
            // xsl:evaluate context-item passing a node from the outer engine).
            IReadOnlyList<object?> translatedArgs = TranslateNodeArgumentsToLocalStore(
                options.InitialFunctionArguments, context._nodeStore);
            var result = await context.CallXsltFunctionAsync(func, translatedArgs).ConfigureAwait(false);
            // Always preserve the raw function result through RawResult so callers can
            // surface the typed XDM value (xs:boolean, map, function, etc.) instead of
            // the text-serialized form (Martin Honnen 2026-05-18: fn:transform with
            // delivery-format='raw' and an XSLT-internal initial-function call was
            // returning the string "false" where the function returned xs:boolean true).
            options.RawResult.Value = WrapNodesForCrossStoreTransport(result, context);
            if (!options.ReturnRawXdm)
                context.SerializeFunctionResult(result, outputBuilder);
        }
        else if (options.InitialTemplate != null || (!options.HasSourceDocument && _stylesheet.NamedTemplates.Keys.Any(k => k.LocalName == "initial-template")))
        {
            var initialTemplate = options.InitialTemplate
                ?? _stylesheet.NamedTemplates.Keys.First(k => k.LocalName == "initial-template");
            // XTDE0040: Check that initial template is public (in packages)
            // In TransformRawAsync (used by fn:transform), check all templates since
            // fn:transform targets specific packages — xsl:expose visibility is enforced.
            if (_stylesheet.IsPackage
                && _stylesheet.NamedTemplates.TryGetValue(initialTemplate, out var rawTmpl)
                && rawTmpl.Visibility is not (Ast.Visibility.Public or Ast.Visibility.Final))
                throw new XsltException($"XTDE0040: Initial template '{initialTemplate.LocalName}' is not public");
            if (!options.HasSourceDocument)
                context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);
            await context.CallTemplateAsync(initialTemplate, []).ConfigureAwait(false);
            if (!options.HasSourceDocument)
                context.PopContextItem();
        }
        else if (options.InitialModeSelect != null)
        {
            var selectExpr = new XQuery.Parser.XQueryParserFacade { AllowNamespaceAxis = true }.Parse(options.InitialModeSelect);
            var effectiveInitialMode = options.InitialMode ?? new QName(NamespaceId.None, "");
            await context.ApplyTemplatesAsync(selectExpr, effectiveInitialMode, [], []).ConfigureAwait(false);
        }
        else
        {
            var effectiveInitialMode = options.InitialMode ?? new QName(NamespaceId.None, "");
            await context.ApplyTemplatesAsync(
                ContextItemExpression.Instance,
                effectiveInitialMode, [], []).ConfigureAwait(false);
        }

        var rawItems = context.EndSequenceCollection();
        SecondaryResultDocuments = context.SecondaryResults;

        // If sequence items were collected, return them. Wrap any node items so they
        // survive the trip out of the inner store (caller re-anchors).
        if (rawItems.Count > 0)
        {
            object? raw = rawItems.Count == 1 ? rawItems[0] : rawItems.ToArray();
            return WrapNodesForCrossStoreTransport(raw, context);
        }

        // InitialFunction returned a single raw XDM value (booleans, maps, function items,
        // arrays, etc.) — surface it directly so type identity isn't lost to text
        // serialization. The InitialFunction branch sets RawResult unconditionally
        // (already wrapped above when set).
        if (options.InitialFunction != null && options.RawResult.Value != null)
            return options.RawResult.Value;

        // Fallback: if no sequence items but text was generated, return the text
        var text = outputBuilder.ToString();
        return !string.IsNullOrEmpty(text) ? text : null;
    }

    /// <summary>
    /// Wrapper for an XdmNode argument crossing fn:transform's engine boundary.
    /// The outer engine serializes the node to XML; the inner engine re-parses
    /// into its own node store so XPath/xsl:evaluate inside the called function
    /// can navigate children, compute string-value, etc.
    /// </summary>
    internal sealed record CrossStoreNodeRef(string Xml, bool IsElement);

    /// <summary>
    /// Returns a copy of <paramref name="args"/> with any <see cref="CrossStoreNodeRef"/>
    /// arguments re-parsed into <paramref name="store"/>. Non-wrapped arguments pass
    /// through unchanged.
    /// </summary>
#pragma warning disable CA1859
    private static List<object?> TranslateNodeArgumentsToLocalStore(
        IReadOnlyList<object?> args, XdmInMemoryStore? store)
#pragma warning restore CA1859
    {
        if (store == null || args.Count == 0)
            return args is List<object?> list ? list : new List<object?>(args);
        bool anyWrapped = false;
        for (var i = 0; i < args.Count; i++)
        {
            if (args[i] is CrossStoreNodeRef) { anyWrapped = true; break; }
        }
        if (!anyWrapped) return args is List<object?> list ? list : new List<object?>(args);
        var translated = new List<object?>(args.Count);
        foreach (var arg in args)
        {
            if (arg is CrossStoreNodeRef wrapped)
                translated.Add(ReparseCrossStoreNode(wrapped, store));
            else
                translated.Add(arg);
        }
        return translated;
    }

    /// <summary>
    /// Wraps any <see cref="Xdm.Nodes.XdmElement"/> / <see cref="Xdm.Nodes.XdmDocument"/>
    /// items in <paramref name="value"/> as <see cref="CrossStoreNodeRef"/>s, serialized
    /// via <paramref name="context"/> so the inner engine's store can be walked while it
    /// is still live. The caller (e.g. <c>XsltTransformProvider</c>) re-anchors into its
    /// own store before handing the result back to the user.
    ///
    /// Without this wrap, raw-delivery node results carry Children/Parent NodeIds from
    /// the now-dying inner store: outer-side serialization yields stripped subtrees
    /// (Martin Honnen: <c>&lt;root/&gt;</c> instead of <c>&lt;root&gt;text&lt;/root&gt;</c>),
    /// and <c>path()</c> walks the wrong ancestor chain when Parent NodeIds collide with
    /// unrelated nodes in the outer store.
    /// </summary>
    internal static object? WrapNodesForCrossStoreTransport(object? value, DefaultXsltExecutionContext context)
    {
        if (value is null) return null;
        if (value is Xdm.Nodes.XdmElement or Xdm.Nodes.XdmDocument)
        {
            var node = (Xdm.Nodes.XdmNode)value;
            var xml = context.SerializeXdmNodeToXml(node);
            return new CrossStoreNodeRef(xml, IsElement: node is Xdm.Nodes.XdmElement);
        }
        if (value is object?[] arr)
        {
            var wrapped = new object?[arr.Length];
            for (var i = 0; i < arr.Length; i++)
                wrapped[i] = WrapNodesForCrossStoreTransport(arr[i], context);
            return wrapped;
        }
        return value;
    }

    private static object? ReparseCrossStoreNode(CrossStoreNodeRef wrapped, XdmInMemoryStore store)
    {
        if (string.IsNullOrEmpty(wrapped.Xml)) return null;
        try
        {
            var doc = new XmlDocument { PreserveWhitespace = true };
            doc.LoadXml(wrapped.Xml);
            var localDoc = ConvertToXdm(doc, store);
            if (wrapped.IsElement && localDoc.DocumentElement.HasValue)
            {
                var rootId = localDoc.DocumentElement.Value;
                return (object?)(store.GetNode(rootId) as Xdm.Nodes.XdmElement) ?? localDoc;
            }
            return localDoc;
        }
        catch (XmlException)
        {
            return null;
        }
    }

    /// <summary>
    /// Transforms a string XML source with raw delivery.
    /// </summary>
    /// <summary>
    /// Raw transform whose initial context item is an arbitrary XDM item — typically
    /// a map or array produced by a previous transform's <c>parse-json</c> call,
    /// chained back in via <see cref="XsltTransformer.TransformToSequenceAsync"/>.
    /// The XSLT data model allows the context item to be any item, but the engine
    /// surface previously required a source node, which silently lost non-node
    /// inputs (Martin Honnen 2026-05-21 JSON-chaining repro: lookup on
    /// XdmDocument because the map was replaced with a synthetic <c>&lt;empty/&gt;</c>).
    /// </summary>
    internal async Task<object?> TransformRawWithInitialContextItemAsync(
        object initialContextItem,
        XsltTransformOptions? options,
        XdmInMemoryStore nodeStore)
    {
        ArgumentNullException.ThrowIfNull(initialContextItem);
        ArgumentNullException.ThrowIfNull(nodeStore);
        options ??= new XsltTransformOptions();

        // Synthetic empty XdmDocument satisfies the executor's constructor (it always
        // wants *some* node to seed the context stack); the real focus is pushed below.
        var syntheticDocId = nodeStore.NextId();
        var syntheticDoc = new XdmDocument
        {
            Id = syntheticDocId,
            Document = new DocumentId(0),
            Children = [],
            BaseUri = options.SourceDocumentUri?.AbsoluteUri
        };
        nodeStore.Register(syntheticDoc);

        var outputBuilder = new StringBuilder();
        var context = new DefaultXsltExecutionContext(
            _stylesheet,
            _templateIndex,
            syntheticDoc,
            outputBuilder,
            options,
            nodeStore,
            _schemaProvider);
        context.Owner = this;

        // Globals init with absent focus — same as the no-source path.
        context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);
        await InitializeGlobalsInDependencyOrderAsync(context, outputBuilder).ConfigureAwait(false);
        context.PopContextItem();

        foreach (var (name, value) in options.InitialParameters)
            context.GlobalVariables[name] = value;

        // Replace the constructor's synthetic-doc focus with the caller's actual item.
        // PopContextItem first drops the synthetic doc that the constructor seeded.
        context.PopContextItem();
        context.PushContextItem(initialContextItem, 1, 1);

        context.BeginSequenceCollection();
        try
        {
            if (options.InitialTemplate != null
                || (!options.HasSourceDocument && _stylesheet.NamedTemplates.Keys.Any(k => k.LocalName == "initial-template")))
            {
                var initialTemplate = options.InitialTemplate
                    ?? _stylesheet.NamedTemplates.Keys.First(k => k.LocalName == "initial-template");
                if (_stylesheet.IsPackage
                    && _stylesheet.NamedTemplates.TryGetValue(initialTemplate, out var rawTmpl)
                    && rawTmpl.Visibility is not (Ast.Visibility.Public or Ast.Visibility.Final))
                    throw new XsltException($"XTDE0040: Initial template '{initialTemplate.LocalName}' is not public");
                await context.CallTemplateAsync(initialTemplate, []).ConfigureAwait(false);
            }
            else
            {
                var effectiveInitialMode = options.InitialMode ?? new QName(NamespaceId.None, "");
                // ContextItemExpression.Instance evaluates to '.' — the supplied item.
                await context.ApplyTemplatesAsync(
                    ContextItemExpression.Instance,
                    effectiveInitialMode, [], []).ConfigureAwait(false);
            }
        }
        finally
        {
            context.PopContextItem();
        }

        var rawItems = context.EndSequenceCollection();
        SecondaryResultDocuments = context.SecondaryResults;

        if (rawItems.Count > 0)
        {
            // When the caller wants a serialized string (TransformAsync, i.e. not the
            // raw-XDM chaining path used by TransformToSequenceAsync) and the principal
            // output is a JSON-family method, serialize the collected map / array / atomic
            // items as JSON rather than returning them raw — otherwise the string facade
            // ToString()s the result into a CLR type name like
            // "PhoenixmlDb.XQuery.Execution.OrderedXdmMap" (Martin Honnen 2026-06-14,
            // JSON input fed through TransformAsync(XdmSequence)).
            if (!options.ReturnRawXdm)
            {
                var jsonOutDecl = context.PrimaryOutputMatchedDeclaration ?? _stylesheet.Outputs.FirstOrDefault();
                if (jsonOutDecl?.EffectiveMethod is OutputMethod.Json or OutputMethod.Adaptive or OutputMethod.Csv)
                {
                    var jsonBuilder = new StringBuilder();
                    AppendJsonItems(rawItems, jsonBuilder, jsonOutDecl, nodeStore);
                    var jsonOut = jsonBuilder.ToString();
                    // Route JSON-family output through full finalization so character-maps /
                    // normalization / sentinel restore apply. FinalizeOutput only runs the
                    // indentation step for XML/HTML/XHTML methods, so already-emitted JSON is
                    // not re-indented or corrupted.
                    return FinalizeOutput(jsonOut, jsonOutDecl, context.PrincipalOutputCharacterMaps, FinalizeKind.Primary);
                }
            }

            object? raw = rawItems.Count == 1 ? rawItems[0] : rawItems.ToArray();
            return WrapNodesForCrossStoreTransport(raw, context);
        }

        if (outputBuilder.Length == 0)
            return null;

        var serialized = outputBuilder.ToString();

        // The raw-XDM chaining caller (TransformToSequenceAsync, ReturnRawXdm) re-parses
        // this serialized markup back into a navigable node downstream, so it must receive
        // the bare markup — full finalization would prepend an XML declaration / DOCTYPE /
        // BOM that breaks that re-parse. Leave it raw, matching the rawItems branches above.
        if (options.ReturnRawXdm)
            return serialized;

        // Route serialized output through the same full finalization the main TransformAsync
        // path applies — otherwise serialized output produced from a non-node (e.g. JSON-map)
        // initial context item ignored xsl:output indent="yes", character maps, normalization,
        // etc. (Martin Honnen 2026-06-12).
        var rawOutputDecl = context.PrimaryOutputMatchedDeclaration ?? _stylesheet.Outputs.FirstOrDefault();
        return FinalizeOutput(serialized, rawOutputDecl, context.PrincipalOutputCharacterMaps, FinalizeKind.Primary);
    }

    internal async Task<object?> TransformRawAsync(string xmlSource, XsltTransformOptions? options = null)
    {
        ArgumentNullException.ThrowIfNull(xmlSource);
        if (xmlSource.Length > 0 && xmlSource[0] == '\uFEFF')
            xmlSource = xmlSource[1..];

        var doc = new XmlDocument { PreserveWhitespace = true };
        doc.LoadXml(xmlSource);

        var nodeStore = new XdmInMemoryStore();
        var xdmDoc = ConvertToXdm(doc, nodeStore);

        _templateIndex.ResolvePatternNamespaces(nodeStore.InternNamespace);
        foreach (var keyDef in _stylesheet.Keys.Values)
        {
            TemplateIndex.ResolveNamespacesInPattern(keyDef.Match, nodeStore.InternNamespace);
            if (keyDef.OtherDefinitions != null)
                foreach (var other in keyDef.OtherDefinitions)
                    TemplateIndex.ResolveNamespacesInPattern(other.Match, nodeStore.InternNamespace);
        }
        foreach (var acc in _stylesheet.Accumulators.Values)
            foreach (var rule in acc.Rules)
                TemplateIndex.ResolveNamespacesInPattern(rule.Match, nodeStore.InternNamespace);
        foreach (var nt in _stylesheet.StripSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);
        foreach (var nt in _stylesheet.PreserveSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);
        if (_stylesheet.StripSpace.Count > 0)
            StripWhitespaceNodes(xdmDoc, _stylesheet.StripSpace, _stylesheet.PreserveSpace, nodeStore);

        return await TransformRawAsync(xdmDoc, options, nodeStore).ConfigureAwait(false);
    }

    /// <summary>
    /// Serializes a single XDM item as JSON (for method="json") or adaptive output.
    /// </summary>
    /// <summary>
    /// Serializes XDM items as CSV (XSLT 4.0 output method="csv").
    /// Each array/sequence is a row; atomic values are cells.
    /// </summary>
    internal static string SerializeAsCsv(List<object?> items)
    {
        var sb = new System.Text.StringBuilder();
        foreach (var item in items)
        {
            if (item is List<object?> row)
            {
                for (var i = 0; i < row.Count; i++)
                {
                    if (i > 0) sb.Append(',');
                    AppendCsvField(sb, row[i]?.ToString() ?? "");
                }
                sb.Append('\n');
            }
            else if (item is object?[] arrRow)
            {
                for (var i = 0; i < arrRow.Length; i++)
                {
                    if (i > 0) sb.Append(',');
                    AppendCsvField(sb, arrRow[i]?.ToString() ?? "");
                }
                sb.Append('\n');
            }
            else
            {
                AppendCsvField(sb, item?.ToString() ?? "");
                sb.Append('\n');
            }
        }
        return sb.ToString();
    }

    private static void AppendCsvField(System.Text.StringBuilder sb, string value)
    {
        if (value.Contains(',', StringComparison.Ordinal) || value.Contains('"', StringComparison.Ordinal)
            || value.Contains('\n', StringComparison.Ordinal) || value.Contains('\r', StringComparison.Ordinal))
        {
            sb.Append('"');
            sb.Append(value.Replace("\"", "\"\"", StringComparison.Ordinal));
            sb.Append('"');
        }
        else
        {
            sb.Append(value);
        }
    }

    /// <summary>
    /// Drains the JSON sequence-collection accumulator on <paramref name="context"/> and
    /// serializes its items into <paramref name="outputBuilder"/> per the principal
    /// xsl:output declaration's method/indent/allow-duplicate-names settings. Used by
    /// both the non-streaming and streaming transform entry points so they share
    /// identical JSON/Adaptive/CSV emission — without this shared path, the streaming
    /// path fell through to <c>CreateMapAsync</c>'s no-accumulator branch which serialized
    /// in adaptive mode (unquoted strings, no indent). Reported by Martin Honnen.
    /// </summary>
    internal static void FinalizeJsonOutput(
        DefaultXsltExecutionContext context,
        StringBuilder outputBuilder,
        XsltOutput? principalOutput,
        XdmInMemoryStore? nodeStore,
        XsltTransformOptions options)
    {
        var jsonItems = context.EndSequenceCollection();
        if (options.ReturnRawXdm)
        {
            object? rawValue = jsonItems.Count switch
            {
                0 => null,
                1 => jsonItems[0],
                _ => jsonItems.ToArray()
            };
            options.RawResult.Value = WrapNodesForCrossStoreTransport(rawValue, context);
        }
        var textContent = outputBuilder.ToString();
        outputBuilder.Clear();
        if (!string.IsNullOrEmpty(textContent) && jsonItems.Count == 0)
        {
            outputBuilder.Append(textContent);
            return;
        }
        if (jsonItems.Count == 0)
            return;

        AppendJsonItems(jsonItems, outputBuilder, principalOutput, nodeStore);
    }

    /// <summary>
    /// Serializes a non-empty list of JSON-family items (map / array / atomic) into
    /// <paramref name="outputBuilder"/> per the principal output's method, indent, and
    /// allow-duplicate-names settings. Shared by <see cref="FinalizeJsonOutput"/> and the
    /// initial-context-item transform path so both emit identical JSON / Adaptive / CSV.
    /// </summary>
    internal static void AppendJsonItems(
        List<object?> jsonItems,
        StringBuilder outputBuilder,
        XsltOutput? principalOutput,
        XdmInMemoryStore? nodeStore)
    {
        var effectiveMethod = principalOutput?.EffectiveMethod ?? OutputMethod.Json;
        if (effectiveMethod == OutputMethod.Csv)
        {
            outputBuilder.Append(SerializeAsCsv(jsonItems));
            return;
        }

        var allowDupNames = principalOutput?.AllowDuplicateNames == true;
        var jsonNodeMethod = principalOutput?.JsonNodeOutputMethod;
        var jsonIndent = effectiveMethod == OutputMethod.Json
            && (principalOutput?.Indent == true);
        if (jsonItems.Count == 1)
        {
            outputBuilder.Append(SerializeItemAsJson(jsonItems[0], effectiveMethod == OutputMethod.Adaptive, allowDupNames, nodeStore, jsonNodeMethod, jsonIndent));
            return;
        }
        if (effectiveMethod == OutputMethod.Adaptive)
        {
            for (int i = 0; i < jsonItems.Count; i++)
            {
                if (i > 0) outputBuilder.Append('\n');
                outputBuilder.Append(SerializeItemAsJson(jsonItems[i], true, allowDupNames, nodeStore, jsonNodeMethod));
            }
            return;
        }
        outputBuilder.Append('[');
        for (int i = 0; i < jsonItems.Count; i++)
        {
            if (i > 0) outputBuilder.Append(',');
            if (jsonIndent) { outputBuilder.Append('\n'); outputBuilder.Append("  "); }
            outputBuilder.Append(SerializeItemAsJson(jsonItems[i], false, allowDupNames, nodeStore, jsonNodeMethod, jsonIndent, 1));
        }
        if (jsonIndent && jsonItems.Count > 0) outputBuilder.Append('\n');
        outputBuilder.Append(']');
    }

    /// <summary>
    /// Appends a JSON newline followed by <paramref name="depth"/> levels of two-space
    /// indentation. Single-sourced so the JSON output method (<see cref="SerializeItemAsJson"/>)
    /// and the xml-to-json emitter (<c>XsltXmlToJsonFunction.SerializeJsonElement</c>) produce
    /// byte-identical indented layouts.
    /// </summary>
    internal static void AppendJsonNewlineIndent(StringBuilder sb, int depth)
    {
        sb.Append('\n');
        sb.Append(' ', depth * 2);
    }

    /// <summary>Records a JSON object key for duplicate detection. Returns false if the key
    /// was already present (the caller raises its own error: SERE0022 for the json output
    /// method, FOJS0006 for fn:xml-to-json).</summary>
    internal static bool TryAddJsonKey(HashSet<string> seen, string key) => seen.Add(key);

    internal static string SerializeItemAsJson(object? item, bool adaptive, bool allowDuplicateNames = false, XdmInMemoryStore? store = null, string? jsonNodeOutputMethod = null, bool indent = false, int depth = 0)
    {
        if (item == null) return "null";

        // Indent only applies to JSON method (not adaptive). When indenting, expand
        // braces/brackets across lines with two-space indentation per depth level.
        var doIndent = indent && !adaptive;
        var colonSep = doIndent ? ": " : ":";

        switch (item)
        {
            case IDictionary<object, object?> map:
            {
                var sb = new StringBuilder();
                sb.Append('{');
                bool first = true;
                var seenKeys = new HashSet<string>(StringComparer.Ordinal);
                foreach (var (key, value) in map)
                {
                    var keyStr = DefaultXsltExecutionContext.StringValueOf(key);
                    // SERE0022: duplicate key names when allow-duplicate-names is no (default for JSON)
                    if (!adaptive && !allowDuplicateNames && !TryAddJsonKey(seenKeys, keyStr))
                        throw new XsltException($"SERE0022: Duplicate key '{keyStr}' in JSON map serialization");
                    if (!first) sb.Append(',');
                    if (doIndent) AppendJsonNewlineIndent(sb, depth + 1);
                    first = false;
                    sb.Append('"');
                    sb.Append(JsonEscapeString(keyStr));
                    sb.Append('"');
                    sb.Append(colonSep);
                    sb.Append(SerializeItemAsJson(value, adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth + 1));
                }
                if (!first && doIndent)
                    AppendJsonNewlineIndent(sb, depth);
                sb.Append('}');
                return sb.ToString();
            }
            case List<object?> array:
            {
                var sb = new StringBuilder();
                sb.Append('[');
                for (int i = 0; i < array.Count; i++)
                {
                    if (i > 0) sb.Append(',');
                    if (doIndent) AppendJsonNewlineIndent(sb, depth + 1);
                    // Array members that are sequences (object?[]) need flattening
                    if (array[i] is object?[] memberSeq)
                    {
                        if (memberSeq.Length == 1)
                            sb.Append(SerializeItemAsJson(memberSeq[0], adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth + 1));
                        else
                        {
                            sb.Append('[');
                            for (int j = 0; j < memberSeq.Length; j++)
                            {
                                if (j > 0) sb.Append(',');
                                if (doIndent) AppendJsonNewlineIndent(sb, depth + 2);
                                sb.Append(SerializeItemAsJson(memberSeq[j], adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth + 2));
                            }
                            if (memberSeq.Length > 0 && doIndent)
                                AppendJsonNewlineIndent(sb, depth + 1);
                            sb.Append(']');
                        }
                    }
                    else
                        sb.Append(SerializeItemAsJson(array[i], adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth + 1));
                }
                if (array.Count > 0 && doIndent)
                    AppendJsonNewlineIndent(sb, depth);
                sb.Append(']');
                return sb.ToString();
            }
            case bool b:
                return b ? "true" : "false";
            case int i:
                return i.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case long l:
                return l.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case double d:
                if (double.IsNaN(d) || double.IsInfinity(d))
                    return "null"; // JSON doesn't support NaN/Infinity
                return DefaultXsltExecutionContext.FormatDouble(d);
            case decimal m:
                return m.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case float f:
                if (float.IsNaN(f) || float.IsInfinity(f))
                    return "null";
                return DefaultXsltExecutionContext.FormatFloat(f);
            case string s:
                if (adaptive) return s; // Adaptive mode: strings output as-is (no quotes)
                return $"\"{JsonEscapeString(s)}\"";
            case object?[] seq:
            {
                // Sequence — serialize items
                if (seq.Length == 1) return SerializeItemAsJson(seq[0], adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth);
                var sb = new StringBuilder();
                sb.Append('[');
                for (int i = 0; i < seq.Length; i++)
                {
                    if (i > 0) sb.Append(',');
                    if (doIndent) AppendJsonNewlineIndent(sb, depth + 1);
                    sb.Append(SerializeItemAsJson(seq[i], adaptive, allowDuplicateNames, store, jsonNodeOutputMethod, indent, depth + 1));
                }
                if (seq.Length > 0 && doIndent)
                    AppendJsonNewlineIndent(sb, depth);
                sb.Append(']');
                return sb.ToString();
            }
            case PhoenixmlDb.XQuery.Ast.XQueryFunction func:
            {
                // Adaptive mode: function items are implementation-defined (XSLT 3.0 §26.3)
                // JSON mode: function items cannot be serialized (SERE0021)
                if (!adaptive)
                    throw new XsltException("SERE0021: Function items cannot be serialized using JSON output method");
                var funcName = func.Name.LocalName ?? "anonymous";
                return $"function#{funcName}/{func.Arity}";
            }
            case Xdm.Nodes.XdmNode node:
            {
                // Adaptive mode always serializes nodes as XML
                if (adaptive)
                    return SerializeXdmNodeAsXml(node, store);
                // JSON mode: json-node-output-method controls how nodes are serialized
                // Default is "xml" per XSLT 3.0 spec §26.1
                var nodeMethod = jsonNodeOutputMethod ?? "xml";
                if (nodeMethod == "xml")
                {
                    var xml = SerializeXdmNodeAsXml(node, store, omitXmlDeclaration: true);
                    return $"\"{JsonEscapeString(xml)}\"";
                }
                // text method: use string value
                var nodeStr = node.StringValue ?? "";
                return $"\"{JsonEscapeString(nodeStr)}\"";
            }
            default:
                // Other atomic values: serialize as JSON string
                var strVal = DefaultXsltExecutionContext.StringValueOf(item);
                if (adaptive) return strVal;
                return $"\"{JsonEscapeString(strVal)}\"";
        }
    }

    /// <summary>
    /// Serializes an XDM node as XML markup for adaptive output.
    /// For documents and elements, uses the node store for full tree serialization.
    /// </summary>
    private static string SerializeXdmNodeAsXml(Xdm.Nodes.XdmNode node, XdmInMemoryStore? store = null, bool omitXmlDeclaration = false)
    {
        switch (node)
        {
            case Xdm.Nodes.XdmAttribute attr:
                return $"{(!string.IsNullOrEmpty(attr.Prefix) ? attr.Prefix + ":" : "")}{attr.LocalName}=\"{attr.Value}\"";
            case Xdm.Nodes.XdmComment comment:
                return $"<!--{comment.StringValue}-->";
            case Xdm.Nodes.XdmProcessingInstruction pi:
                return $"<?{pi.Target} {pi.StringValue}?>";
            case Xdm.Nodes.XdmText text:
                return text.Value ?? "";
            case Xdm.Nodes.XdmDocument:
            case Xdm.Nodes.XdmElement:
                if (store != null)
                    return SerializeNodeTreeAsXml(node, store, omitXmlDeclaration);
                return node.StringValue ?? "";
            default:
                return node.StringValue ?? "";
        }
    }

    /// <summary>
    /// Serializes an XDM document or element node to XML markup using the node store.
    /// </summary>
    private static string SerializeNodeTreeAsXml(Xdm.Nodes.XdmNode node, XdmInMemoryStore store, bool omitXmlDeclaration = false)
    {
        var sb = new System.Text.StringBuilder();

        if (node is Xdm.Nodes.XdmDocument doc)
        {
            if (!omitXmlDeclaration)
                sb.Append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
            foreach (var childId in doc.Children)
            {
                var child = store.GetNode(childId);
                if (child != null)
                    SerializeNodeTreeRecursive(child, store, sb);
            }
        }
        else
        {
            SerializeNodeTreeRecursive(node, store, sb);
        }
        return sb.ToString();
    }

    private static void SerializeNodeTreeRecursive(Xdm.Nodes.XdmNode node, XdmInMemoryStore store, System.Text.StringBuilder sb)
    {
        switch (node)
        {
            case Xdm.Nodes.XdmElement elem:
            {
                var ns = store.GetNamespaceUri(elem.Namespace) ?? "";
                var name = !string.IsNullOrEmpty(elem.Prefix) ? $"{elem.Prefix}:{elem.LocalName}" : elem.LocalName;
                sb.Append('<').Append(name);

                // Namespace declarations
                foreach (var nsDecl in elem.NamespaceDeclarations)
                {
                    var declUri = store.GetNamespaceUri(nsDecl.Namespace) ?? "";
                    if (string.IsNullOrEmpty(nsDecl.Prefix))
                        sb.Append(" xmlns=\"").Append(declUri).Append('"');
                    else
                        sb.Append(" xmlns:").Append(nsDecl.Prefix).Append("=\"").Append(declUri).Append('"');
                }

                // Attributes
                foreach (var attrId in elem.Attributes)
                {
                    if (store.GetNode(attrId) is Xdm.Nodes.XdmAttribute attr)
                    {
                        var attrName = !string.IsNullOrEmpty(attr.Prefix) ? $"{attr.Prefix}:{attr.LocalName}" : attr.LocalName;
                        sb.Append(' ').Append(attrName).Append("=\"");
                        AppendEscapedXmlAttribute(sb, attr.Value);
                        sb.Append('"');
                    }
                }

                if (elem.Children.Count == 0)
                {
                    sb.Append("/>");
                }
                else
                {
                    sb.Append('>');
                    foreach (var childId in elem.Children)
                    {
                        var child = store.GetNode(childId);
                        if (child != null)
                            SerializeNodeTreeRecursive(child, store, sb);
                    }
                    sb.Append("</").Append(name).Append('>');
                }
                break;
            }
            case Xdm.Nodes.XdmText text:
                AppendEscapedXmlText(sb, text.Value ?? "");
                break;
            case Xdm.Nodes.XdmComment comment:
                sb.Append("<!--").Append(comment.Value).Append("-->");
                break;
            case Xdm.Nodes.XdmProcessingInstruction pi:
                sb.Append("<?").Append(pi.Target).Append(' ').Append(pi.Value).Append("?>");
                break;
        }
    }

    private static void AppendEscapedXmlAttribute(System.Text.StringBuilder sb, string value)
        => CharacterEscaper.AppendXmlAttribute(sb, value);

    private static void AppendEscapedXmlText(System.Text.StringBuilder sb, string value)
        => CharacterEscaper.AppendXmlText(sb, value);

    internal static string JsonEscapeString(string s)
    {
        var sb = new StringBuilder(s.Length + 8);
        XsltXmlToJsonFunction.AppendJsonString(s, sb);
        return sb.ToString();
    }

    /// <summary>
    /// Serializes an XDM item in adaptive output mode.
    /// Maps use XPath map{} notation, arrays use [...], strings are unquoted,
    /// and orphan attributes use name="value" format.
    /// </summary>
    internal static string SerializeItemAdaptive(object? item, XdmInMemoryStore? store = null)
    {
        if (item == null) return "";

        switch (item)
        {
            case Xdm.Nodes.XdmAttribute attr:
            {
                // Orphan attribute: name="value" format
                var sb = new StringBuilder();
                if (!string.IsNullOrEmpty(attr.Prefix))
                {
                    sb.Append(attr.Prefix);
                    sb.Append(':');
                }
                sb.Append(attr.LocalName);
                sb.Append("=\"");
                sb.Append(attr.Value);
                sb.Append('"');
                return sb.ToString();
            }
            case IDictionary<object, object?> map:
            {
                var sb = new StringBuilder();
                sb.Append("map{");
                bool first = true;
                foreach (var (key, value) in map)
                {
                    if (!first) sb.Append(',');
                    first = false;
                    var keyStr = DefaultXsltExecutionContext.StringValueOf(key);
                    // Key is always quoted in map{} notation
                    sb.Append('"');
                    sb.Append(keyStr);
                    sb.Append("\":");
                    sb.Append(SerializeItemAdaptive(value, store));
                }
                sb.Append('}');
                return sb.ToString();
            }
            case List<object?> array:
            {
                var sb = new StringBuilder();
                sb.Append('[');
                for (int i = 0; i < array.Count; i++)
                {
                    if (i > 0) sb.Append(',');
                    sb.Append(SerializeItemAdaptive(array[i], store));
                }
                sb.Append(']');
                return sb.ToString();
            }
            case bool b:
                return b ? "true" : "false";
            case int i:
                return i.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case long l:
                return l.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case double d:
                return DefaultXsltExecutionContext.FormatDouble(d);
            case decimal m:
                return m.ToString(System.Globalization.CultureInfo.InvariantCulture);
            case float f:
                return DefaultXsltExecutionContext.FormatFloat(f);
            case PhoenixmlDb.XQuery.Ast.XQueryFunction func:
            {
                var funcName = func.Name.LocalName ?? "anonymous";
                return $"function#{funcName}/{func.Arity}";
            }
            case Xdm.Nodes.XdmNode node when node is not Xdm.Nodes.XdmAttribute:
                return SerializeXdmNodeAsXml(node, store);
            default:
                return DefaultXsltExecutionContext.StringValueOf(item);
        }
    }

    /// <summary>
    /// Block-level HTML elements that should be preceded by a newline when indenting HTML output.
    /// </summary>
    private static readonly HashSet<string> HtmlBlockElements = new(StringComparer.OrdinalIgnoreCase)
    {
        "html", "head", "body", "div", "p", "table", "thead", "tbody", "tfoot", "tr", "th", "td",
        "ul", "ol", "li", "dl", "dt", "dd", "h1", "h2", "h3", "h4", "h5", "h6",
        "section", "article", "header", "footer", "nav", "main", "aside", "details", "summary",
        "form", "fieldset", "legend", "blockquote", "pre", "figure", "figcaption", "hr", "br",
        "script", "style", "link", "meta", "title", "base", "noscript"
    };

    /// <summary>
    /// Inserts a DOCTYPE declaration into the output, after any XML declaration and before the root element.
    /// Per the serialization spec:
    ///   - If both public and system: &lt;!DOCTYPE root PUBLIC "public" "system"&gt;
    ///   - If only system: &lt;!DOCTYPE root SYSTEM "system"&gt;
    /// </summary>
    internal static string InsertDoctype(string output, string? doctypePublic, string doctypeSystem)
    {
        // Find the root element name
        var searchStart = 0;
        if (output.StartsWith("<?xml", StringComparison.Ordinal))
        {
            var declEnd = output.IndexOf("?>", StringComparison.Ordinal);
            if (declEnd >= 0)
                searchStart = declEnd + 2;
        }

        // Skip the BOM if present
        if (searchStart < output.Length && output[searchStart] == '\uFEFF')
            searchStart++;

        // Find the first element start tag
        var elemStart = output.IndexOf('<', searchStart);
        while (elemStart >= 0 && elemStart < output.Length - 1)
        {
            var nextChar = output[elemStart + 1];
            // Skip processing instructions, comments
            if (nextChar == '?' || nextChar == '!')
            {
                elemStart = output.IndexOf('<', elemStart + 1);
                continue;
            }
            break;
        }

        if (elemStart < 0 || elemStart >= output.Length - 1)
            return output;

        // Extract the root element name
        var nameStart = elemStart + 1;
        var nameEnd = nameStart;
        while (nameEnd < output.Length && output[nameEnd] != ' ' && output[nameEnd] != '>'
               && output[nameEnd] != '/' && output[nameEnd] != '\t' && output[nameEnd] != '\n'
               && output[nameEnd] != '\r')
            nameEnd++;

        if (nameEnd <= nameStart)
            return output;

        var rootName = output[nameStart..nameEnd];

        // Build the DOCTYPE declaration
        string doctype;
        if (doctypePublic != null)
            doctype = $"<!DOCTYPE {rootName} PUBLIC \"{doctypePublic}\" \"{doctypeSystem}\">";
        else
            doctype = $"<!DOCTYPE {rootName} SYSTEM \"{doctypeSystem}\">";

        // Insert before the root element, with a newline separator
        return output[..elemStart] + doctype + "\n" + output[elemStart..];
    }

    /// <summary>
    /// URI-valued HTML attributes whose values should be percent-encoded when
    /// escape-uri-attributes is enabled (default for HTML/XHTML output).
    /// </summary>
    private static readonly HashSet<string> HtmlUriAttributes = new(StringComparer.OrdinalIgnoreCase)
    {
        "href", "src", "action", "cite", "data", "formaction", "poster", "srcset", "usemap"
    };

    /// <summary>
    /// Applies URI escaping to URI-valued HTML attributes: percent-encodes non-ASCII characters
    /// as required by the serialization spec when escape-uri-attributes="yes".
    /// </summary>
    internal static string EscapeUriAttributes(string output)
    {
        // Process attribute values in URI-valued attributes
        var sb = new StringBuilder(output.Length);
        int pos = 0;
        while (pos < output.Length)
        {
            if (output[pos] == '<' && pos + 1 < output.Length && output[pos + 1] != '/' && output[pos + 1] != '!')
            {
                // Find end of tag
                var tagEnd = output.IndexOf('>', pos);
                if (tagEnd < 0) { sb.Append(output, pos, output.Length - pos); break; }

                var tag = output.AsSpan(pos, tagEnd - pos + 1);

                // Check for attributes within the tag
                var tagStr = output[pos..(tagEnd + 1)];
                var processed = EscapeUriAttributesInTag(tagStr);
                sb.Append(processed);
                pos = tagEnd + 1;
            }
            else
            {
                sb.Append(output[pos]);
                pos++;
            }
        }
        return sb.ToString();
    }

    private static string EscapeUriAttributesInTag(string tag)
    {
        // Simple attribute pattern: attrname="value" or attrname='value'
        var sb = new StringBuilder(tag.Length);
        int i = 0;

        // Skip past the element name
        while (i < tag.Length && tag[i] != ' ' && tag[i] != '\t' && tag[i] != '\n'
               && tag[i] != '\r' && tag[i] != '>' && tag[i] != '/')
        {
            sb.Append(tag[i]);
            i++;
        }

        while (i < tag.Length)
        {
            if (tag[i] == '>' || (tag[i] == '/' && i + 1 < tag.Length && tag[i + 1] == '>'))
            {
                sb.Append(tag, i, tag.Length - i);
                break;
            }

            // Skip whitespace
            if (char.IsWhiteSpace(tag[i]))
            {
                sb.Append(tag[i]);
                i++;
                continue;
            }

            // Try to parse attribute name
            var nameStart = i;
            while (i < tag.Length && tag[i] != '=' && tag[i] != ' ' && tag[i] != '>'
                   && tag[i] != '/' && tag[i] != '\t')
                i++;

            var attrName = tag[nameStart..i];

            // Skip whitespace before =
            while (i < tag.Length && char.IsWhiteSpace(tag[i])) { sb.Append(tag[nameStart..i]); nameStart = i; i++; }

            if (i >= tag.Length || tag[i] != '=')
            {
                sb.Append(tag, nameStart, i - nameStart);
                continue;
            }

            sb.Append(tag, nameStart, i - nameStart);
            sb.Append('=');
            i++; // skip =

            // Skip whitespace after =
            while (i < tag.Length && char.IsWhiteSpace(tag[i])) { sb.Append(tag[i]); i++; }

            if (i >= tag.Length) break;

            var quote = tag[i];
            if (quote != '"' && quote != '\'')
            {
                sb.Append(tag[i]);
                i++;
                continue;
            }

            sb.Append(quote);
            i++; // skip opening quote

            var valueStart = i;
            while (i < tag.Length && tag[i] != quote) i++;
            var attrValue = tag[valueStart..i];

            if (HtmlUriAttributes.Contains(attrName))
            {
                // Percent-encode non-ASCII characters in URI attribute values
                sb.Append(PercentEncodeNonAscii(attrValue));
            }
            else
            {
                sb.Append(attrValue);
            }

            if (i < tag.Length)
            {
                sb.Append(quote); // closing quote
                i++;
            }
        }
        return sb.ToString();
    }

    private static string PercentEncodeNonAscii(string value)
    {
        bool hasNonAscii = false;
        foreach (char c in value)
        {
            if (c > 127) { hasNonAscii = true; break; }
        }
        if (!hasNonAscii) return value;

        var sb = new StringBuilder(value.Length * 2);
        foreach (char c in value)
        {
            if (c > 127)
            {
                // Encode the character as UTF-8 bytes, then percent-encode each byte
                var bytes = System.Text.Encoding.UTF8.GetBytes(new[] { c });
                foreach (var b in bytes)
                    sb.Append(System.Globalization.CultureInfo.InvariantCulture, $"%{b:X2}");
            }
            else
            {
                sb.Append(c);
            }
        }
        return sb.ToString();
    }

    /// <summary>
    /// Applies indentation to serialized output when xsl:output indent="yes" is specified.
    /// For XML/XHTML, re-parses and re-serializes with XmlWriter indentation.
    /// For HTML, adds newlines and indentation before block-level elements.
    /// </summary>
    internal static string ApplyIndentation(string output, OutputMethod method, HashSet<QName>? suppressIndentation = null)
    {
        if (method is OutputMethod.Xml or OutputMethod.Xhtml)
        {
            var result = ApplyXmlIndentation(output);
            if (suppressIndentation != null && suppressIndentation.Count > 0)
                result = RemoveSuppressedIndentation(result, suppressIndentation);
            return result;
        }
        else if (method == OutputMethod.Html)
        {
            var result = ApplyHtmlIndentation(output);
            if (suppressIndentation != null && suppressIndentation.Count > 0)
                result = RemoveSuppressedIndentation(result, suppressIndentation);
            return result;
        }
        return output;
    }

    /// <summary>
    /// Post-processes indented output to remove indentation whitespace inside elements
    /// listed in suppress-indentation. Collapses added whitespace-only text nodes
    /// between child elements back to no whitespace.
    /// </summary>
    private static string RemoveSuppressedIndentation(string output, HashSet<QName> suppressedElements)
    {
        // Build a simple set of local names for fast matching (most stylesheets use unprefixed names)
        var suppressedNames = new HashSet<string>(StringComparer.Ordinal);
        foreach (var qn in suppressedElements)
            suppressedNames.Add(qn.LocalName);

        var sb = new StringBuilder(output.Length);
        int suppressDepth = 0; // nesting depth inside suppressed elements
        int pos = 0;
        while (pos < output.Length)
        {
            if (output[pos] == '<')
            {
                var tagEnd = output.IndexOf('>', pos);
                if (tagEnd < 0) { sb.Append(output, pos, output.Length - pos); break; }

                bool isClosing = pos + 1 < output.Length && output[pos + 1] == '/';
                bool isSelfClosing = output[tagEnd - 1] == '/';
                bool isComment = pos + 3 < output.Length && output[pos + 1] == '!' && output[pos + 2] == '-';
                bool isPI = pos + 1 < output.Length && output[pos + 1] == '?';
                bool isDoctype = pos + 1 < output.Length && output[pos + 1] == '!';

                // Extract element name
                string? elemName = null;
                if (!isComment && !isPI && !isDoctype)
                {
                    int nameStart = isClosing ? pos + 2 : pos + 1;
                    int nameEnd2 = nameStart;
                    while (nameEnd2 <= tagEnd && nameEnd2 < output.Length
                           && output[nameEnd2] != ' ' && output[nameEnd2] != '>'
                           && output[nameEnd2] != '/' && output[nameEnd2] != '\t'
                           && output[nameEnd2] != '\n' && output[nameEnd2] != '\r')
                        nameEnd2++;
                    if (nameEnd2 > nameStart)
                        elemName = output[nameStart..nameEnd2];
                }

                // Strip the prefix for matching (e.g., "ns:elem" -> "elem")
                var localName = elemName;
                if (localName != null && localName.Contains(':', StringComparison.Ordinal))
                    localName = localName[(localName.IndexOf(':', StringComparison.Ordinal) + 1)..];

                if (isClosing && localName != null && suppressedNames.Contains(localName))
                {
                    // Closing a suppressed element
                    suppressDepth = Math.Max(0, suppressDepth - 1);
                }

                sb.Append(output, pos, tagEnd - pos + 1);
                pos = tagEnd + 1;

                if (!isClosing && !isSelfClosing && localName != null && suppressedNames.Contains(localName))
                {
                    // Opening a suppressed element
                    suppressDepth++;
                }
            }
            else if (suppressDepth > 0)
            {
                // Inside a suppressed element: skip indentation whitespace before tags
                // (whitespace-only runs that precede a '<')
                int wsStart = pos;
                while (pos < output.Length && (output[pos] == ' ' || output[pos] == '\t'
                       || output[pos] == '\n' || output[pos] == '\r'))
                    pos++;
                if (pos < output.Length && output[pos] == '<')
                {
                    // This was indentation whitespace before a tag — skip it
                }
                else
                {
                    // Not followed by a tag — preserve the text content
                    sb.Append(output, wsStart, pos - wsStart);
                }
            }
            else
            {
                sb.Append(output[pos]);
                pos++;
            }
        }
        return sb.ToString();
    }

    private static string ApplyXmlIndentation(string output)
    {
        try
        {
            // Check for and strip XML declaration before parsing, then re-add it after
            string? xmlDecl = null;
            var parseInput = output;
            if (parseInput.StartsWith("<?xml", StringComparison.Ordinal))
            {
                var declEnd = parseInput.IndexOf("?>", StringComparison.Ordinal);
                if (declEnd >= 0)
                {
                    xmlDecl = parseInput[..(declEnd + 2)];
                    parseInput = parseInput[(declEnd + 2)..].TrimStart('\r', '\n');
                }
            }

            var xdoc = System.Xml.Linq.XDocument.Parse(parseInput, System.Xml.Linq.LoadOptions.PreserveWhitespace);
            var settings = new XmlWriterSettings
            {
                Indent = true,
                IndentChars = "  ",
                OmitXmlDeclaration = true, // We handle the declaration separately
                NewLineHandling = NewLineHandling.Replace
            };
            using var sw = new System.IO.StringWriter();
            using (var xw = XmlWriter.Create(sw, settings))
            {
                xdoc.WriteTo(xw);
            }
            var indented = sw.ToString();
            return xmlDecl != null ? xmlDecl + "\n" + indented : indented;
        }
        catch (XmlException)
        {
            // If the output isn't well-formed XML (e.g., multiple root elements or fragments),
            // fall back to the unindented output rather than crashing
            return output;
        }
    }

    private static string ApplyHtmlIndentation(string output)
    {
        // Simple HTML indentation: add newlines and indentation before block-level elements
        var sb = new StringBuilder(output.Length + output.Length / 10);
        int depth = 0;
        int i = 0;
        while (i < output.Length)
        {
            if (output[i] == '<')
            {
                // Find the end of the tag
                var tagEnd = output.IndexOf('>', i);
                if (tagEnd < 0)
                {
                    sb.Append(output, i, output.Length - i);
                    break;
                }

                var tag = output.AsSpan(i, tagEnd - i + 1);
                bool isClosing = tag.Length > 1 && tag[1] == '/';
                bool isSelfClosing = tag[^2] == '/' || tag.EndsWith("/>".AsSpan());
                bool isComment = tag.StartsWith("<!--".AsSpan());
                bool isDoctype = tag.StartsWith("<!DOCTYPE".AsSpan(), StringComparison.OrdinalIgnoreCase);
                bool isProcessingInstruction = tag.Length > 1 && tag[1] == '?';

                // Extract the element name
                string? elemName = null;
                if (!isComment && !isDoctype && !isProcessingInstruction)
                {
                    int nameStart = isClosing ? 2 : 1;
                    int nameEnd = nameStart;
                    while (nameEnd < tag.Length && tag[nameEnd] != ' ' && tag[nameEnd] != '>'
                           && tag[nameEnd] != '/' && tag[nameEnd] != '\t' && tag[nameEnd] != '\n')
                        nameEnd++;
                    if (nameEnd > nameStart)
                        elemName = tag[nameStart..nameEnd].ToString();
                }

                bool isBlock = elemName != null && HtmlBlockElements.Contains(elemName);

                if (isBlock)
                {
                    if (isClosing)
                        depth = Math.Max(0, depth - 1);

                    // Add newline and indentation before block elements
                    if (sb.Length > 0 && sb[^1] != '\n')
                        sb.Append('\n');
                    sb.Append(' ', depth * 2);

                    if (!isClosing && !isSelfClosing)
                        depth++;
                }

                sb.Append(output, i, tagEnd - i + 1);
                i = tagEnd + 1;
            }
            else
            {
                sb.Append(output[i]);
                i++;
            }
        }
        return sb.ToString();
    }

    private string ApplyCharacterMaps(string output, List<QName> useCharacterMaps)
    {
        // Collect character mappings from referenced maps in declaration order.
        // Later maps in the list override earlier ones (XSLT 3.0 §25.1).
        var allMappings = new Dictionary<char, string>();
        var visited = new HashSet<QName>();
        foreach (var mapName in useCharacterMaps)
        {
            if (_stylesheet.CharacterMaps.TryGetValue(mapName, out var map))
                CollectCharacterMappings(map, allMappings, visited);
        }

        if (allMappings.Count == 0)
            return output;
        var sb = new StringBuilder(output.Length);
        var inTag = false;
        var inCdata = false;
        for (var i = 0; i < output.Length; i++)
        {
            var c = output[i];
            // Track CDATA sections — character maps do not apply inside CDATA
            if (!inTag && i + 8 < output.Length && output[i] == '<' && output[i + 1] == '!' &&
                output[i + 2] == '[' && output[i + 3] == 'C' && output[i + 4] == 'D' &&
                output[i + 5] == 'A' && output[i + 6] == 'T' && output[i + 7] == 'A' &&
                output[i + 8] == '[')
            {
                inCdata = true;
                sb.Append(c);
                continue;
            }
            if (inCdata)
            {
                if (i + 2 < output.Length && c == ']' && output[i + 1] == ']' && output[i + 2] == '>')
                {
                    sb.Append("]]>");
                    i += 2;
                    inCdata = false;
                }
                else
                {
                    sb.Append(c);
                }
                continue;
            }
            // Track XML tags — character maps do not apply inside tags
            if (c == '<' && !inCdata)
            {
                inTag = true;
                sb.Append(c);
                continue;
            }
            if (c == '>' && inTag)
            {
                inTag = false;
                sb.Append(c);
                continue;
            }
            if (inTag)
            {
                sb.Append(c);
                continue;
            }
            // Apply character map to text content
            if (allMappings.TryGetValue(c, out var replacement))
                sb.Append(replacement);
            else
                sb.Append(c);
        }
        return sb.ToString();
    }

    private void CollectCharacterMappings(XsltCharacterMap map, Dictionary<char, string> target, HashSet<QName> visited)
    {
        if (!visited.Add(map.Name))
            return;

        // First apply referenced character maps
        foreach (var refName in map.UseCharacterMaps)
        {
            if (_stylesheet.CharacterMaps.TryGetValue(refName, out var refMap))
                CollectCharacterMappings(refMap, target, visited);
        }

        // Then apply this map's own mappings (later declarations override earlier ones)
        foreach (var (ch, replacement) in map.Mappings)
        {
            target[ch] = replacement;
        }
    }

    /// <summary>
    /// Initializes global parameters and variables in dependency order.
    /// This ensures that if param $x references $y, then $y is initialized first.
    /// Also handles transitive dependencies through function calls.
    /// </summary>
    private async Task InitializeGlobalsInDependencyOrderAsync(
        DefaultXsltExecutionContext context,
        StringBuilder outputBuilder)
    {
        // Collect all global declarations (including from imports)
        var globals = new List<GlobalDeclaration>();
        var seenNames = new HashSet<QName>();
        CollectGlobalDeclarations(_stylesheet, globals, seenNames);

        // Build dependency graph: which globals does each global depend on?
        var globalNames = new HashSet<QName>(globals.Select(g => g.Name));
        var dependencies = new Dictionary<QName, HashSet<QName>>();
        var functionDeps = BuildFunctionDependencies();

        foreach (var global in globals)
        {
            var deps = new HashSet<QName>();

            // Collect direct variable references
            if (global.Select != null)
            {
                var collector = new DependencyCollector();
                collector.Walk(global.Select);

                // Add direct variable dependencies (only those that are globals)
                foreach (var varRef in collector.VariableRefs)
                {
                    if (globalNames.Contains(varRef))
                        deps.Add(varRef);
                }

                // Add transitive dependencies through function calls
                AddTransitiveFunctionDependencies(collector.FunctionRefs, functionDeps, globalNames, deps);
            }

            // Also analyze Content for dependencies (xsl:value-of, etc.)
            if (global.Content != null)
            {
                var collector = new DependencyCollector();
                foreach (var instruction in global.Content.Instructions)
                {
                    CollectInstructionDependencies(instruction, collector);
                }

                // Add direct variable dependencies
                foreach (var varRef in collector.VariableRefs)
                {
                    if (globalNames.Contains(varRef))
                        deps.Add(varRef);
                }

                // Add transitive dependencies through function calls
                AddTransitiveFunctionDependencies(collector.FunctionRefs, functionDeps, globalNames, deps);
            }

            dependencies[global.Name] = deps;
        }

        // Topologically sort globals
        var sorted = TopologicalSort(globals, dependencies);

        // Collect externally-supplied parameter names so we can skip evaluating their defaults.
        // External params must be bound first so that global variables depending on them see the
        // supplied values rather than the stylesheet defaults.
        var externalParams = context._options.InitialParameters;

        // Pre-populate pending globals map for lazy evaluation.
        // When a global variable's select expression references another global that hasn't been
        // initialized yet (and wasn't detected by the dependency analysis), GetVariable can
        // trigger lazy initialization instead of throwing "not bound".
        context._pendingGlobals = new Dictionary<QName, GlobalDeclaration>();
        foreach (var global in sorted)
            context._pendingGlobals[global.Name] = global;

        // Initialize in dependency order
        foreach (var global in sorted)
        {
            // Push per-element version for backwards-compatible mode propagation
            if (global.Version != null)
                context.PushVersion(global.Version);
            // Push the global declaration's own module URI as the static base URI so
            // static-base-uri() inside the global's select/body returns the module that
            // declared it, not the principal stylesheet. (XSLT 3.0 §5.4.2 / fn:static-base-uri.)
            // Without this, a global xsl:variable in modules/x.xsl saw the principal
            // stylesheet's URI, causing resolve-uri('templates.xml', sbu) to look one
            // directory above the module — Martin's Docbook templates.xml report.
            var globalSbu = XsltTransformEngine.UriString(global.BaseUri);
            if (globalSbu != null)
                context.PushStaticBaseUri(globalSbu);
            try
            {
            // If this is a param with an externally-supplied value, use that instead of the default
            if (global.IsParam && externalParams.TryGetValue(global.Name, out var extValue))
            {
                // Validate externally-supplied value against the param's as type
                if (global.As != null)
                    context.ValidateValueMatchesType(extValue, global.As, "XTTE0590",
                        $"Parameter ${global.Name.LocalName}");
                context.GlobalVariables[global.Name] = extValue;
            }
            else if (global.Select != null)
            {
                context._globalsBeingEvaluated.Add(global.Name);
                try
                {
                    var value = await context.EvaluateAsync(global.Select).ConfigureAwait(false);
                    context.GlobalVariables[global.Name] = value;
                }
                finally { context._globalsBeingEvaluated.Remove(global.Name); }
            }
            else if (global.Content != null)
            {
                context._globalsBeingEvaluated.Add(global.Name);
                try
                {
                // Check if this is a sequence type that needs accumulator.
                // Include element() and attribute() types regardless of occurrence — and
                // regardless of whether the type was named (element(foo)) or unconstrained
                // (element()) — since they need proper XDM node creation via the sequence
                // accumulator. The earlier `ElementName == null` guard skipped the accumulator
                // path for *named* element types, which then fell to the no-as RTF path and
                // bound the variable to a ResultTreeFragment (a document wrapper). Downstream
                // path steps like `$locale/l:group` then saw a document-node and looked for
                // `l:group` children of the document — which there are none of, so the lookup
                // returned the empty sequence. Found in Docbook chunk-cleanup name-style
                // localization (`as="element(l:l10n)"` global).
                var needsNodeOrphan = global.As != null &&
                    global.As.ItemType is ItemType.Element or ItemType.Attribute or ItemType.Node;
                // Map / array / function / record items must come through the accumulator so
                // xsl:map / xsl:array constructions land as the live Dictionary or List object,
                // not as their JSON-serialized text form (the default top-level fallback path).
                // Without this, `<xsl:variable as="map(*)"><xsl:map>…</xsl:map></xsl:variable>`
                // ends up as a JSON string and downstream `map:contains($v, …)` calls fail with
                // XPTY0004 "must be a single map".
                var isContainerItem = global.As != null &&
                    global.As.ItemType is ItemType.Map or ItemType.Array
                                        or ItemType.Function or ItemType.Record;
                var isSequenceType = global.As != null &&
                    (global.As.Occurrence == Occurrence.ZeroOrMore
                    || global.As.Occurrence == Occurrence.OneOrMore
                    || needsNodeOrphan
                    || isContainerItem);

                if (isSequenceType)
                {
                    // Use sequence accumulator to collect individual items from xsl:sequence
                    context.BeginSequenceCollection();
                    // When the target type is text(), collect each text write as a separate
                    // accumulator item so they remain individual text nodes.
                    var needsTextCollection = global.As != null &&
                        global.As.ItemType is ItemType.Text;
                    var savedCollectText = context._collectTextAsSequenceItems;
                    var savedElemDepth = context._serializingElementDepth;
                    if (needsTextCollection)
                    {
                        context._collectTextAsSequenceItems = true;
                        context._serializingElementDepth = 0;
                    }
                    var savedLen = outputBuilder.Length;
                    try
                    { await global.Content.ExecuteAsync(context).ConfigureAwait(false); }
                    finally
                    {
                        context._collectTextAsSequenceItems = savedCollectText;
                        context._serializingElementDepth = savedElemDepth;
                    }
                    var textContent = outputBuilder.ToString(savedLen, outputBuilder.Length - savedLen);
                    outputBuilder.Length = savedLen;

                    var collected = context.EndSequenceCollection();

                    // Combine accumulated items with serialized literal elements
                    var seqItems = new List<object?>();
                    var wrapAsTextNode = context._nodeStore != null && global.As != null
                        && global.As.ItemType is ItemType.Text or ItemType.Node;
                    foreach (var item in collected)
                    {
                        if (item != null)
                        {
                            if (wrapAsTextNode && item is string strItem)
                            {
                                var textId = context._nodeStore!.NextId();
                                seqItems.Add(new Xdm.Nodes.XdmText
                                {
                                    Id = textId,
                                    Document = DocumentId.None,
                                    Parent = NodeId.None,
                                    Value = strItem
                                });
                            }
                            else if (wrapAsTextNode && item is Xdm.TextNodeItem tni)
                            {
                                var textId = context._nodeStore!.NextId();
                                seqItems.Add(new Xdm.Nodes.XdmText
                                {
                                    Id = textId,
                                    Document = DocumentId.None,
                                    Parent = NodeId.None,
                                    Value = tni.Value
                                });
                            }
                            else
                            {
                                seqItems.Add(item);
                            }
                        }
                    }

                    if (!string.IsNullOrEmpty(textContent) && context._nodeStore != null && textContent.Contains('<', StringComparison.Ordinal))
                    {
                        try
                        {
                            var globalSeqBaseUri = XsltTransformEngine.UriString(global.BaseUri) ?? XsltTransformEngine.UriString(_stylesheet.BaseUri);

                            // Stream-parse rather than allocating a full XmlDocument.
                            var initSettings = new System.Xml.XmlReaderSettings
                            {
                                DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                IgnoreWhitespace = false,
                                IgnoreComments = false,
                                IgnoreProcessingInstructions = false,
                            };
                            using var initStringReader = new System.IO.StringReader($"<_seq_root_>{textContent}</_seq_root_>");
                            using var initReader = System.Xml.XmlReader.Create(initStringReader, initSettings);
                            var initParsed = new List<object?>();
                            context.ReadAsBodyChunkChildren(initReader, initParsed);

                            // When as="document-node()", create a proper XdmDocument node
                            // wrapping the content, rather than extracting individual children
                            if (global.As?.ItemType == ItemType.Document)
                            {
                                var docId = context._nodeStore.NextId();
                                var children = new List<NodeId>();
                                NodeId docElementId = NodeId.None;
                                foreach (var item in initParsed)
                                {
                                    if (item is XdmNode cn)
                                    {
                                        cn.Parent = docId;
                                        children.Add(cn.Id);
                                        if (cn is XdmElement && docElementId == NodeId.None)
                                            docElementId = cn.Id;
                                    }
                                }
                                string? docElemLocalName = docElementId != NodeId.None
                                    ? (context._nodeStore.GetNode(docElementId) as XdmElement)?.LocalName : null;
                                var docNode = new XdmDocument
                                {
                                    Id = docId,
                                    Document = new DocumentId(1),
                                    Parent = NodeId.None,
                                    DocumentElement = docElementId,
                                    Children = children,
                                    DocumentElementLocalName = docElemLocalName,
                                };
                                docNode.BaseUri = globalSeqBaseUri;
                                context._nodeStore.Register(docNode);
                                seqItems.Add(docNode);
                            }
                            else
                            {
                                foreach (var item in initParsed)
                                {
                                    // Detach children from the synthetic _seq_root_ wrapper
                                    // so they become parentless nodes per XSLT as="node()*" semantics
                                    if (item is XdmNode childNode)
                                    {
                                        childNode.Parent = null;
                                        // Set construction context base URI so parentless
                                        // nodes can resolve relative xml:base attributes
                                        if (globalSeqBaseUri != null)
                                            childNode.BaseUri = globalSeqBaseUri;
                                    }
                                    seqItems.Add(item);
                                }
                            }
                        }
                        catch (System.Xml.XmlException)
                        {
                            var seqBaseUri = XsltTransformEngine.UriString(global.BaseUri) ?? XsltTransformEngine.UriString(_stylesheet.BaseUri);
                            seqItems.Add(new ResultTreeFragment(textContent, seqBaseUri));
                        }
                    }
                    else if (!string.IsNullOrEmpty(textContent))
                    {
                        // When as="text()" or as="node()", create actual text nodes
                        if (context._nodeStore != null && global.As != null
                            && global.As.ItemType is ItemType.Text or ItemType.Node or ItemType.Item)
                        {
                            var textId = context._nodeStore.NextId();
                            var textNode = new Xdm.Nodes.XdmText
                            {
                                Id = textId,
                                Document = DocumentId.None,
                                Parent = NodeId.None,
                                Value = textContent
                            };
                            seqItems.Add(textNode);
                        }
                        else
                        {
                            seqItems.Add(textContent);
                        }
                    }

                    // Apply type coercion from the as="" declaration
                    if (global.As != null && global.As.ItemType != ItemType.Item && global.As.ItemType != ItemType.Node)
                    {
                        for (int si = 0; si < seqItems.Count; si++)
                            seqItems[si] = PhoenixmlDb.XQuery.Execution.TypeCastHelper.CastValue(seqItems[si], global.As.ItemType);
                    }

                    // For ExactlyOne/ZeroOrOne: unwrap to single item
                    var occurrence = global.As!.Occurrence;
                    if (occurrence == Occurrence.ExactlyOne || occurrence == Occurrence.ZeroOrOne)
                        context.GlobalVariables[global.Name] = seqItems.Count == 1 ? seqItems[0] : null;
                    else
                        context.GlobalVariables[global.Name] = seqItems.Count > 0 ? seqItems.ToArray() : Array.Empty<object?>();
                }
                else
                {
                    var savedLen = outputBuilder.Length;
                    await global.Content.ExecuteAsync(context).ConfigureAwait(false);
                    var content = outputBuilder.ToString(savedLen, outputBuilder.Length - savedLen);
                    outputBuilder.Length = savedLen;
                    var globalBaseUri = XsltTransformEngine.UriString(global.BaseUri) ?? XsltTransformEngine.UriString(_stylesheet.BaseUri);
                    // XSLT 2.0: variables with content and no 'as' always create a temporary tree
                    if (global.As == null)
                        context.GlobalVariables[global.Name] = new ResultTreeFragment(content, globalBaseUri);
                    else if (context._nodeStore != null
                        && global.As.ItemType is ItemType.Text or ItemType.Node
                        && !content.Contains('<', StringComparison.Ordinal))
                    {
                        // as="text()" or as="node()": create proper XDM text node
                        var textId = context._nodeStore.NextId();
                        context.GlobalVariables[global.Name] = new Xdm.Nodes.XdmText
                        {
                            Id = textId,
                            Document = DocumentId.None,
                            Parent = NodeId.None,
                            Value = content
                        };
                    }
                    else if (context._nodeStore != null && global.As.ItemType == ItemType.Document)
                    {
                        // as="document-node()": parse content into a proper XdmDocument so
                        // downstream `/` and `*` axis steps work. Falling through to the RTF/string
                        // path produced an xs:string "" for empty content, which then failed
                        // axis-step evaluation with XPTY0020 (Martin Honnen's Docbook TNG
                        // $v:templates → fp:construct-templates path).
                        var docId = context._nodeStore.NextId();
                        var docChildren = new List<NodeId>();
                        NodeId docElementId = NodeId.None;
                        string? docElemLocalName = null;
                        var sb = new StringBuilder();
                        if (content.Length > 0)
                        {
                            try
                            {
                                var settings = new System.Xml.XmlReaderSettings
                                {
                                    DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                    IgnoreWhitespace = false,
                                    IgnoreComments = false,
                                    IgnoreProcessingInstructions = false,
                                };
                                using var sr = new System.IO.StringReader($"<_doc_root_>{content}</_doc_root_>");
                                using var rdr = System.Xml.XmlReader.Create(sr, settings);
                                var children = new List<object?>();
                                context.ReadAsBodyChunkChildren(rdr, children);
                                foreach (var item in children)
                                {
                                    if (item is XdmNode cn)
                                    {
                                        cn.Parent = docId;
                                        docChildren.Add(cn.Id);
                                        if (cn is XdmElement xe)
                                        {
                                            if (docElementId == NodeId.None)
                                                docElementId = cn.Id;
                                            docElemLocalName ??= xe.LocalName;
                                        }
                                        sb.Append(cn.StringValue);
                                    }
                                }
                            }
                            catch (System.Xml.XmlException)
                            {
                                // Malformed content (e.g. raw text). Empty document; the
                                // failure will surface elsewhere if it matters.
                            }
                        }
                        var docNode = new XdmDocument
                        {
                            Id = docId,
                            Document = new DocumentId(1),
                            Parent = NodeId.None,
                            DocumentElement = docElementId,
                            Children = docChildren,
                            DocumentElementLocalName = docElemLocalName,
                            _stringValue = sb.ToString(),
                        };
                        // Carry the variable's base URI so base-uri()/document()/relative-URI
                        // resolution inside the temp tree works (mirrors the as="item()*" sibling
                        // above). Without it the document-node temp tree had a null base URI.
                        docNode.BaseUri = globalBaseUri;
                        context._nodeStore.Register(docNode);
                        context.GlobalVariables[global.Name] = docNode;
                    }
                    else
                    {
                        // For global xsl:variable with as="atomic-type" body, coerce the body's
                        // text content to the declared type. Without this, the variable was
                        // bound to the raw STRING (e.g. "2147483647") and downstream comparisons
                        // like `$depth gt 1` failed with XPTY0004 ("Cannot compare xs:string with
                        // numeric type"). Found in Docbook xslTNG `vp:section-toc-depth`
                        // (as="xs:integer" with xsl:choose+xsl:sequence body) — minimal repro:
                        // `<xsl:variable as="xs:integer"><xsl:sequence select="2147483647"/></xsl:variable>`.
                        if (DefaultXsltExecutionContext.IsStrictAtomicTypePublic(global.As.ItemType)
                            && !content.Contains('<', StringComparison.Ordinal))
                        {
                            var coerced = DefaultXsltExecutionContext.TryCoerceStringToTypePublic(content, global.As.ItemType);
                            context.GlobalVariables[global.Name] = coerced ?? (object)content;
                        }
                        else
                        {
                            context.GlobalVariables[global.Name] = content.Contains('<', StringComparison.Ordinal)
                                ? new ResultTreeFragment(content)
                                : (object)content;
                        }
                    }
                }
                }
                finally { context._globalsBeingEvaluated.Remove(global.Name); }
            }
            else
            {
                // Per XSLT spec: variable with no select and no content defaults to empty
                // value. The exact "empty" semantics depend on the declared `as=` type:
                //   - cardinality allows empty (?, *) → empty sequence (null)
                //   - cardinality requires ≥1 (1, +) → XTDE0700 for param, "" for variable
                //     (the legacy "empty string" default for untyped variables)
                //
                // The previous code treated the null/"" choice based on `IsParam` rather
                // than on the type's cardinality, so an `xsl:variable as="element()*"`
                // with no value got "" — and downstream `<xsl:sequence select="$x"/>`
                // emitted the empty string as a stray item, breaking sequence
                // construction (Docbook TNG `$v:user-title-groups` → `$v:title-groups`
                // got an extra empty-string item, then iterate failed XPTY0020 trying
                // to navigate `@xpath` on the string).
                if (global.As != null
                    && (global.As.Occurrence == Occurrence.ZeroOrOne
                        || global.As.Occurrence == Occurrence.ZeroOrMore))
                    context.GlobalVariables[global.Name] = null;
                else if (global.IsParam && global.As != null
                    && (global.As.Occurrence == Occurrence.ExactlyOne
                        || global.As.Occurrence == Occurrence.OneOrMore))
                {
                    // XTDE0700: param requires a typed value but none supplied and no default
                    throw new XsltException(
                        $"XTDE0700: Parameter ${global.Name.LocalName} requires type {global.As} but no value was supplied");
                }
                else
                    context.GlobalVariables[global.Name] = "";
            }
            }
            finally
            {
                if (globalSbu != null)
                    context.PopStaticBaseUri();
                if (global.Version != null)
                    context.PopVersion();
            }
            // Remove from pending now that it's been initialized
            context._pendingGlobals?.Remove(global.Name);
        }
        // Clear pending map — all globals should be initialized now
        context._pendingGlobals = null;
    }

    /// <summary>
    /// Initializes a single pending global variable on demand (lazy evaluation).
    /// Called by GetVariable when a variable isn't in GlobalVariables but is in _pendingGlobals.
    /// </summary>
    internal static async Task InitializePendingGlobalAsync(
        DefaultXsltExecutionContext context,
        GlobalDeclaration global,
        StringBuilder outputBuilder)
    {
        // Remove from pending to prevent re-entrant initialization
        context._pendingGlobals!.Remove(global.Name);

        // Push per-element version for backwards-compatible mode propagation
        if (global.Version != null)
            context.PushVersion(global.Version);
        // Push the global declaration's own module URI as the static base URI — see
        // matching comment in InitializeGlobalsAsync. Required for static-base-uri()
        // inside a global declared in an imported/included module to return the
        // module's own URI rather than the principal stylesheet's.
        var globalSbu = XsltTransformEngine.UriString(global.BaseUri);
        if (globalSbu != null)
            context.PushStaticBaseUri(globalSbu);
        try
        {
            var externalParams = context._options.InitialParameters;
            if (global.IsParam && externalParams.TryGetValue(global.Name, out var extValue))
            {
                if (global.As != null)
                    context.ValidateValueMatchesType(extValue, global.As, "XTTE0590",
                        $"Parameter ${global.Name.LocalName}");
                context.GlobalVariables[global.Name] = extValue;
            }
            else if (global.Select != null)
            {
                context._globalsBeingEvaluated.Add(global.Name);
                try
                {
                    var value = await context.EvaluateAsync(global.Select).ConfigureAwait(false);
                    context.GlobalVariables[global.Name] = value;
                }
                finally { context._globalsBeingEvaluated.Remove(global.Name); }
            }
            else if (global.Content != null)
            {
                // For content-based globals, just evaluate the content as an RTF
                context._globalsBeingEvaluated.Add(global.Name);
                try
                {
                    var savedLen = outputBuilder.Length;
                    await global.Content.ExecuteAsync(context).ConfigureAwait(false);
                    var content = outputBuilder.ToString(savedLen, outputBuilder.Length - savedLen);
                    outputBuilder.Length = savedLen;
                    context.GlobalVariables[global.Name] = content.Length > 0 ? content : "";
                }
                finally { context._globalsBeingEvaluated.Remove(global.Name); }
            }
            else
            {
                // Default: empty string for params, empty string for variables
                if (global.IsParam && global.As != null
                    && (global.As.Occurrence == Occurrence.ZeroOrOne
                        || global.As.Occurrence == Occurrence.ZeroOrMore))
                    context.GlobalVariables[global.Name] = null;
                else
                    context.GlobalVariables[global.Name] = "";
            }
        }
        finally
        {
            if (globalSbu != null)
                context.PopStaticBaseUri();
            if (global.Version != null)
                context.PopVersion();
        }
    }

    /// <summary>
    /// Adds transitive dependencies from function calls to the dependency set.
    /// </summary>
    private static void AddTransitiveFunctionDependencies(
        HashSet<QName> functionRefs,
        Dictionary<QName, HashSet<QName>> functionDeps,
        HashSet<QName> globalNames,
        HashSet<QName> deps)
    {
        foreach (var funcRef in functionRefs)
        {
            HashSet<QName>? funcVarDeps = null;

            // Direct lookup (works when namespace IDs match)
            if (!functionDeps.TryGetValue(funcRef, out funcVarDeps) && funcRef.Namespace == default && funcRef.Prefix != null)
            {
                // XPath parser doesn't resolve namespaces at parse time, so function calls
                // have NamespaceId.None with a prefix. Match by prefix + localname against
                // the resolved function names in the dependency map.
                foreach (var (key, value) in functionDeps)
                {
                    if (key.LocalName == funcRef.LocalName && key.Prefix == funcRef.Prefix)
                    {
                        funcVarDeps = value;
                        break;
                    }
                }
            }

            if (funcVarDeps != null)
            {
                foreach (var varDep in funcVarDeps)
                {
                    if (globalNames.Contains(varDep))
                        deps.Add(varDep);
                }
            }
        }
    }

    /// <summary>
    /// Recursively collects global declarations from a stylesheet and its imports.
    /// Main stylesheet declarations take precedence over imported ones (first seen wins).
    /// </summary>
    private static void CollectGlobalDeclarations(
        XsltStylesheet stylesheet,
        List<GlobalDeclaration> globals,
        HashSet<QName> seenNames)
    {
        foreach (var param in stylesheet.Parameters)
        {
            if (seenNames.Add(param.Name))
            {
                globals.Add(new GlobalDeclaration
                {
                    Name = param.Name,
                    IsParam = true,
                    Select = param.Select,
                    Content = param.Content,
                    As = param.As,
                    OriginalDeclaration = param,
                    BaseUri = param.BaseUri,
                    Version = param.Version
                });
            }
        }

        foreach (var variable in stylesheet.Variables)
        {
            if (seenNames.Add(variable.Name))
            {
                globals.Add(new GlobalDeclaration
                {
                    Name = variable.Name,
                    IsParam = false,
                    Select = variable.Select,
                    Content = variable.Content,
                    As = variable.As,
                    OriginalDeclaration = variable,
                    BaseUri = variable.BaseUri,
                    Version = variable.Version
                });
            }
        }

        // Recursively collect from imports (lower precedence than importing stylesheet).
        // Later imports have higher precedence than earlier ones, so iterate in reverse.
        for (var i = stylesheet.Imports.Count - 1; i >= 0; i--)
        {
            CollectGlobalDeclarations(stylesheet.Imports[i], globals, seenNames);
        }
    }

    /// <summary>
    /// Builds a map of function names to the global variables they reference (transitively).
    /// </summary>
    private Dictionary<QName, HashSet<QName>> BuildFunctionDependencies()
    {
        var result = new Dictionary<QName, HashSet<QName>>();

        // First pass: collect direct dependencies for each function
        foreach (var func in _stylesheet.Functions.Values)
        {
            var collector = new DependencyCollector();

            // Walk the function body to find variable references
            foreach (var instruction in func.Body.Instructions)
            {
                CollectInstructionDependencies(instruction, collector);
            }

            result[func.Name] = new HashSet<QName>(collector.VariableRefs);
        }

        // Second pass: resolve transitive dependencies through function calls
        // (This is a simplified version - a full implementation would use fixed-point iteration)
        var changed = true;
        var maxIterations = 10; // Prevent infinite loops
        while (changed && maxIterations-- > 0)
        {
            changed = false;
            foreach (var func in _stylesheet.Functions.Values)
            {
                var collector = new DependencyCollector();
                foreach (var instruction in func.Body.Instructions)
                {
                    CollectInstructionDependencies(instruction, collector);
                }

                var currentDeps = result[func.Name];
                var originalCount = currentDeps.Count;

                // Add dependencies from called functions
                foreach (var calledFunc in collector.FunctionRefs)
                {
                    if (result.TryGetValue(calledFunc, out var calledDeps))
                    {
                        foreach (var dep in calledDeps)
                            currentDeps.Add(dep);
                    }
                }

                if (currentDeps.Count > originalCount)
                    changed = true;
            }
        }

        return result;
    }

    /// <summary>
    /// Collects variable and function references from an XSLT instruction.
    /// </summary>
    private static void CollectInstructionDependencies(XsltInstruction instruction, DependencyCollector collector)
    {
        switch (instruction)
        {
            case XsltValueOf valueOf when valueOf.Select != null:
                collector.Walk(valueOf.Select);
                break;
            case XsltCopyOf copyOf:
                collector.Walk(copyOf.Select);
                break;
            case XsltIf ifInstr:
                collector.Walk(ifInstr.Test);
                foreach (var child in ifInstr.Then.Instructions)
                    CollectInstructionDependencies(child, collector);
                break;
            case XsltForEach forEach:
                collector.Walk(forEach.Select);
                foreach (var child in forEach.Body.Instructions)
                    CollectInstructionDependencies(child, collector);
                break;
            case XsltChoose choose:
                foreach (var when in choose.When)
                {
                    collector.Walk(when.Test);
                    foreach (var child in when.Body.Instructions)
                        CollectInstructionDependencies(child, collector);
                }
                if (choose.Otherwise != null)
                {
                    foreach (var child in choose.Otherwise.Instructions)
                        CollectInstructionDependencies(child, collector);
                }
                break;
            case XsltSequence seq when seq.Select != null:
                collector.Walk(seq.Select);
                break;
                // Add more instruction types as needed
        }
    }

    /// <summary>
    /// Topologically sorts global declarations based on their dependencies.
    /// </summary>
    private static List<GlobalDeclaration> TopologicalSort(
        List<GlobalDeclaration> globals,
        Dictionary<QName, HashSet<QName>> dependencies)
    {
        var result = new List<GlobalDeclaration>();
        var visited = new HashSet<QName>();
        var visiting = new HashSet<QName>(); // For cycle detection
        // Use last-wins for any remaining duplicates (importing stylesheet takes precedence)
        var globalMap = new Dictionary<QName, GlobalDeclaration>();
        foreach (var g in globals)
            globalMap[g.Name] = g;

        void Visit(GlobalDeclaration global)
        {
            if (visited.Contains(global.Name))
                return;

            if (visiting.Contains(global.Name))
            {
                // Circular dependency detected - just continue
                // XSLT spec says this is a static error, but we'll handle it gracefully
                return;
            }

            visiting.Add(global.Name);

            // Visit dependencies first
            if (dependencies.TryGetValue(global.Name, out var deps))
            {
                foreach (var depName in deps)
                {
                    if (globalMap.TryGetValue(depName, out var depGlobal))
                        Visit(depGlobal);
                }
            }

            visiting.Remove(global.Name);
            visited.Add(global.Name);
            result.Add(global);
        }

        foreach (var global in globals)
            Visit(global);

        return result;
    }

    /// <summary>
    /// Transforms an XML string using the stylesheet.
    /// </summary>
    public async Task<string> TransformAsync(string xmlSource, XsltTransformOptions? options = null)
    {
        ArgumentNullException.ThrowIfNull(xmlSource);
        // Strip leading BOM character (U+FEFF) — XmlDocument.LoadXml rejects it
        if (xmlSource.Length > 0 && xmlSource[0] == '\uFEFF')
            xmlSource = xmlSource[1..];

        // Check if initial mode is streamable — if so, use streaming execution.
        // Exception: when the document-node template (match="/") that would drive the
        // streaming pass contains content we cannot drive off the live reader at the
        // document level (xsl:fork / xsl:for-each-group with group-by — no streaming
        // dispatch), the forward pass would evaluate group-by against an empty synthetic
        // document and emit nothing. Materialize the whole input and run the in-memory
        // engine instead, which evaluates group-by correctly.
        //
        // Exception 2: when the invocation entry point is an initial template (or an
        // auto-detected xsl:initial-template invoked with no source document), the streamed
        // input does NOT belong to the document-node dispatch at all — it belongs to an
        // xsl:source-document instruction INSIDE the called template, which SourceDocumentAsync
        // streams (and where a deferred XTSE3430 streamability error is surfaced). Taking the
        // document-level streaming fast path here would silently skip the initial template,
        // shallow-copy the synthetic empty document, and drop any deferred streamability error.
        // Fall through to the XdmNode dispatch so the initial template runs.
        bool entryIsInitialTemplate = options?.InitialTemplate != null
            || options?.InitialFunction != null
            || (options?.HasSourceDocument == false
                && _stylesheet.NamedTemplates.Keys.Any(k => k.LocalName == "initial-template"));
        var initialModeKey = options?.InitialMode ?? new QName(NamespaceId.None, "");
        if (_stylesheet.Modes.TryGetValue(initialModeKey, out var initialModeDecl) && initialModeDecl.Streamable
            && !entryIsInitialTemplate
            && !DocNodeTemplateRequiresWholeInputBuffer(options))
        {
            return await TransformStreamingAsync(xmlSource, options).ConfigureAwait(false);
        }

        // Parse the XML to an XdmNode tree
        // PreserveWhitespace must be true BEFORE LoadXml to preserve whitespace-only text nodes
        var doc = new XmlDocument { PreserveWhitespace = true };
        // Use XmlReader with base URI when a source document URI is provided,
        // so XmlNode.BaseURI is populated for document() relative URI resolution.
        if (options?.SourceDocumentUri != null)
        {
            using var sr = new System.IO.StringReader(xmlSource);
            using var reader = XmlReader.Create(sr, new XmlReaderSettings { DtdProcessing = DtdProcessing.Parse }, options.SourceDocumentUri.AbsoluteUri);
            doc.Load(reader);
        }
        else
        {
            doc.LoadXml(xmlSource);
        }

        var nodeStore = new XdmInMemoryStore();
        var xdmDoc = ConvertToXdm(doc, nodeStore, options?.SourceDocumentUri?.ToString());

        // Resolve namespace URIs in patterns to NamespaceIds
        _templateIndex.ResolvePatternNamespaces(nodeStore.InternNamespace);

        // Resolve namespaces in xsl:key match patterns
        foreach (var keyDef in _stylesheet.Keys.Values)
        {
            TemplateIndex.ResolveNamespacesInPattern(keyDef.Match, nodeStore.InternNamespace);
            if (keyDef.OtherDefinitions != null)
            {
                foreach (var other in keyDef.OtherDefinitions)
                    TemplateIndex.ResolveNamespacesInPattern(other.Match, nodeStore.InternNamespace);
            }
        }

        // Resolve namespaces in accumulator rule match patterns
        foreach (var acc in _stylesheet.Accumulators.Values)
        {
            foreach (var rule in acc.Rules)
                TemplateIndex.ResolveNamespacesInPattern(rule.Match, nodeStore.InternNamespace);
        }

        // Resolve namespaces in strip-space/preserve-space NameTests
        foreach (var nt in _stylesheet.StripSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);
        foreach (var nt in _stylesheet.PreserveSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);

        // Apply xsl:strip-space declarations
        if (_stylesheet.StripSpace.Count > 0)
        {
            StripWhitespaceNodes(xdmDoc, _stylesheet.StripSpace, _stylesheet.PreserveSpace, nodeStore);
        }

        // If SourceSelect is specified, navigate to the selected node
        XdmNode sourceNode = xdmDoc;
        if (options?.SourceSelect != null)
        {
            var selected = NavigateSourceSelect(xdmDoc, options.SourceSelect, nodeStore);
            if (selected != null)
            {
                sourceNode = selected;
            }
            else
            {
                // Selected node not found (e.g., stripped whitespace text node) — treat as absent context
                options.HasSourceDocument = false;
            }
        }

        return await TransformAsync(sourceNode, options, nodeStore).ConfigureAwait(false);
    }

    /// <summary>
    /// Returns true when <paramref name="initialMode"/> (or the default mode, when null)
    /// resolves to a declared streamable mode in the loaded stylesheet. Used by the facade
    /// to decide whether the streaming fast path applies.
    /// </summary>
    internal bool IsInitialModeStreamable(QName? initialMode = null)
    {
        var key = initialMode ?? new QName(NamespaceId.None, "");
        return _stylesheet.Modes.TryGetValue(key, out var mode) && mode.Streamable;
    }

    /// <summary>
    /// Streams an XML input from an <see cref="XmlReader"/> through the stylesheet and
    /// writes the serialized result incrementally to <paramref name="output"/>. Only valid
    /// when the stylesheet's initial mode is streamable; otherwise throws.
    /// </summary>
    /// <remarks>
    /// Cancellation is not transactional: if the caller cancels mid-stream, partial output
    /// already delivered to <paramref name="output"/> is not recoverable. Post-processing
    /// of the result (indentation, XML declaration, doctype, BOM, escape-uri-attributes)
    /// requires the full output buffer and is NOT applied on this path — the raw
    /// per-event serialized output is what reaches the caller's writer.
    /// </remarks>
    public async Task TransformAsync(XmlReader input, TextWriter output, XsltTransformOptions? options = null)
    {
        ArgumentNullException.ThrowIfNull(input);
        ArgumentNullException.ThrowIfNull(output);

        var initialModeKey = options?.InitialMode ?? new QName(NamespaceId.None, "");
        if (!_stylesheet.Modes.TryGetValue(initialModeKey, out var initialModeDecl) || !initialModeDecl.Streamable)
            throw new XsltException(
                "TransformAsync(XmlReader, TextWriter) requires a streamable initial mode. " +
                "For non-streaming transforms use TransformAsync(string) or TransformAsync(XdmNode).");

        var outputBuilder = new StringBuilder();
        await TransformStreamingCoreAsync(input, outputBuilder, output, options).ConfigureAwait(false);
    }

    /// <summary>
    /// Transforms an XML string using streaming execution (XmlReader-based forward pass).
    /// Used when the initial mode is declared as streamable="yes".
    /// </summary>
    private async Task<string> TransformStreamingAsync(string xmlSource, XsltTransformOptions? options)
    {
        using var stringReader = new System.IO.StringReader(xmlSource);
        var settings = new XmlReaderSettings { DtdProcessing = DtdProcessing.Parse, Async = true };
        using var xmlReader = XmlReader.Create(stringReader, settings,
            options?.SourceDocumentUri?.AbsoluteUri ?? "");
        var sb = new StringBuilder();
        await TransformStreamingCoreAsync(xmlReader, sb, outputSink: null, options).ConfigureAwait(false);
        return sb.ToString();
    }

    /// <summary>
    /// Core streaming pass shared by <see cref="TransformStreamingAsync(string, XsltTransformOptions?)"/>
    /// and <see cref="TransformAsync(XmlReader, TextWriter, XsltTransformOptions?)"/>. The caller
    /// owns the <see cref="XmlReader"/> lifetime and the result <see cref="StringBuilder"/>.
    /// When <paramref name="outputSink"/> is non-null, the execution context drains the builder
    /// to the sink at each event boundary; result post-processing (which requires the full
    /// buffer) is then skipped because it cannot apply to an incrementally-delivered stream.
    /// </summary>
    private async Task TransformStreamingCoreAsync(
        XmlReader inputReader,
        StringBuilder outputBuilder,
        TextWriter? outputSink,
        XsltTransformOptions? options)
    {
        options ??= new XsltTransformOptions();

        // Streaming is invoked with an XML source document, so mark it as present.
        // This ensures xsl:global-context-item use="required" validation passes
        // and use="absent" correctly rejects the invocation.
        options.HasSourceDocument = true;

        var nodeStore = new XdmInMemoryStore();
        _templateIndex.ResolvePatternNamespaces(nodeStore.InternNamespace);

        // Resolve namespaces in key match patterns
        foreach (var keyDef in _stylesheet.Keys.Values)
        {
            TemplateIndex.ResolveNamespacesInPattern(keyDef.Match, nodeStore.InternNamespace);
            if (keyDef.OtherDefinitions != null)
            {
                foreach (var other in keyDef.OtherDefinitions)
                    TemplateIndex.ResolveNamespacesInPattern(other.Match, nodeStore.InternNamespace);
            }
        }

        // Resolve namespaces in accumulator rule match patterns
        foreach (var acc in _stylesheet.Accumulators.Values)
        {
            foreach (var rule in acc.Rules)
                TemplateIndex.ResolveNamespacesInPattern(rule.Match, nodeStore.InternNamespace);
        }

        // Resolve namespaces in strip-space/preserve-space NameTests
        foreach (var nt in _stylesheet.StripSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);
        foreach (var nt in _stylesheet.PreserveSpace)
            nt.ResolveNamespace(nodeStore.InternNamespace);

        // Create a synthetic document node for the context
        var syntheticDocId = nodeStore.NextId();
        var syntheticDoc = new XdmDocument
        {
            Id = syntheticDocId,
            Document = new DocumentId(0),
            Children = [],
            BaseUri = options.SourceDocumentUri?.AbsoluteUri
        };
        nodeStore.Register(syntheticDoc);

        var context = new DefaultXsltExecutionContext(
            _stylesheet,
            _templateIndex,
            syntheticDoc,
            outputBuilder,
            options,
            nodeStore);
        context.Owner = this;

        // Attach the optional external sink BEFORE global initialization and the streaming
        // pass so DrainStreamingOutputAsync at every event boundary flushes incrementally
        // and bounds peak buffered output.
        context._streamingOutputSink = outputSink;

        // For sink-driven streaming, post-processing (indentation, XML declaration, doctype,
        // BOM, escape-uri-attributes) cannot be applied because it requires the full buffer.
        // We emit an XML declaration up-front (when the output declaration requires one) so
        // callers consuming the writer get a well-formed prologue.
        if (outputSink != null)
        {
            var prologDecl = _stylesheet.Outputs.FirstOrDefault();
            if (prologDecl != null &&
                (prologDecl.EffectiveMethod == OutputMethod.Xml || prologDecl.EffectiveMethod == OutputMethod.Xhtml) &&
                prologDecl.OmitXmlDeclaration != true)
            {
                var encoding = prologDecl.Encoding ?? "UTF-8";
                var version = prologDecl.Version ?? "1.0";
                var decl = $"<?xml version=\"{version}\" encoding=\"{encoding}\"";
                if (prologDecl.Standalone.HasValue)
                    decl += prologDecl.Standalone.Value ? " standalone=\"yes\"" : " standalone=\"no\"";
                decl += "?>";
                await outputSink.WriteAsync(decl).ConfigureAwait(false);
            }
        }

        // In streaming mode, global variables are initialized with absent focus because
        // the source document has not been read yet. The streaming processor provides
        // per-node context during execution. This mirrors the call-template invocation
        // path in the non-streaming TransformAsync (XSLT 3.0 §5.4.1).
        context.PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

        await InitializeGlobalsInDependencyOrderAsync(context, outputBuilder).ConfigureAwait(false);

        context.PopContextItem();

        // Bind initial parameters as global variables
        foreach (var (name, value) in options.InitialParameters)
            context.GlobalVariables[name] = value;

        // XTDE0050: Check that all required global parameters have been supplied
        foreach (var param in _stylesheet.Parameters)
        {
            if (param.Required && !options.InitialParameters.ContainsKey(param.Name))
                throw new XsltException($"XTDE0050: Required parameter ${param.Name.LocalName} was not supplied");
        }

        // xsl:global-context-item enforcement (same as non-streaming path)
        if (_stylesheet.GlobalContextItemUse == Ast.ContextItemUse.Required && !options.HasSourceDocument)
            throw new XsltException("XTDE3086: The stylesheet requires a global context item (use=\"required\"), but none was supplied");
        if (_stylesheet.GlobalContextItemUse == Ast.ContextItemUse.Absent && options.HasSourceDocument)
            throw new XsltException("XTSE3088: The stylesheet specifies that no global context item should be supplied (use=\"absent\"), but a source document was provided");

        // Resolve applicable accumulators for the streaming pass
        var streamingAccumulators = _stylesheet.Accumulators.Count > 0
            ? _stylesheet.Accumulators.Values.ToList()
            : null;

        // For JSON/Adaptive/CSV output, mirror the non-streaming TransformAsync path:
        // collect top-level items via the sequence accumulator so xsl:map/xsl:array
        // build typed XDM values that FinalizeJsonOutput serializes once at the end.
        // Without this, top-level CreateMapAsync sees a null accumulator and falls
        // through to its adaptive-text branch (unquoted string values, no indent).
        // Reported by Martin Honnen against streamed JSON output.
        var streamingPrincipalOutput = _stylesheet.Outputs.FirstOrDefault();
        var isStreamingJsonOutput = streamingPrincipalOutput?.EffectiveMethod is OutputMethod.Json or OutputMethod.Adaptive or OutputMethod.Csv;
        if (isStreamingJsonOutput)
            context.BeginSequenceCollection();

        // Document-node template dispatch (XSLT 3.0 §6.6.1): before the streaming
        // crawl reaches the root element, the document node (/) must be offered to
        // user templates. The streaming processor's event loop starts at the first
        // ELEMENT event and so never dispatches the document node — without this,
        // a global <xsl:template match="/"> never fires and the built-in document
        // rule (recurse into children → text-only output) runs instead.
        //
        // If a user template matches the synthetic document node, execute its body
        // using the same subscription mechanism the xsl:source-document streamable
        // path uses: scan the body for streamable xsl:for-each subscriptions /
        // consuming watchers, build the processor with them, and (when the body has
        // no xsl:apply-templates) run the forward pass in subscription-dispatch-only
        // mode so the for-each bodies dispatch per matching element while the default
        // template machinery stays inert. When NO user template matches, fall through
        // to the original behavior so existing streaming stylesheets are unaffected.
        XsltTemplate? docNodeTemplate;
        using (var mc = context.AcquireMatchContext())
            docNodeTemplate = _templateIndex.FindMatchingTemplate(syntheticDoc, options.InitialMode, mc.Value);

        if (docNodeTemplate != null)
        {
            var scanner = new StreamingExpressionScanner();
            var scanResult = scanner.ScanWithSubscriptions(docNodeTemplate.Body);
            var docWatchers = scanResult.Watchers.Count > 0 ? scanResult.Watchers : null;
            var docSubscriptions = scanResult.Subscriptions.Count > 0 ? scanResult.Subscriptions : null;

            bool bodyHasApplyTemplates = ContentContainsApplyTemplatesStreaming(docNodeTemplate.Body);

            // Subscription-dispatch-only: the body drives the stream through scanned
            // for-each subscriptions (or carries no streaming consumption at all, e.g.
            // a body that only constructs literal result elements). In either case the
            // default per-element template machinery must stay inert during the pass.
            bool subscriptionOnly = !bodyHasApplyTemplates;

            var docProcessor = new StreamingXmlProcessor(
                _stylesheet, _templateIndex, context, nodeStore, options.InitialMode,
                streamingAccumulators, docWatchers, docSubscriptions, subscriptionOnly);

            // Expose the document node as the focus so the body's grounded expressions
            // (and the subscription path matchers, which are relative to /) resolve
            // against the document being streamed.
            context.PushContextItem(syntheticDoc, 1, 1);
            var savedDocProcessor = context._activeStreamingProcessor;
            var savedDocReader = context._activeStreamingReader;
            var savedDocCt = context._activeStreamingCancellationToken;
            var savedDocWatchers = context._activeStreamWatchers;
            context._activeStreamingProcessor = docProcessor;
            context._activeStreamingReader = inputReader;
            context._activeStreamingCancellationToken = options.CancellationToken;
            context._activeStreamWatchers = docWatchers;
            try
            {
                if (subscriptionOnly)
                {
                    // The body's for-each subscriptions are dispatched per matching
                    // element during the forward pass; bodies with no streaming
                    // consumption (literal-only) execute once before the drain. Mirror
                    // the source-document subscription-only path: clear the active
                    // processor/reader so the body's own evaluation doesn't re-trigger
                    // streaming, run any grounded body instructions, then stream.
                    context._activeStreamingProcessor = null;
                    context._activeStreamingReader = null;

                    if (docSubscriptions == null)
                    {
                        // Literal-only body (e.g. match="/" producing <ROOTRAN/>):
                        // execute once; the forward pass below merely drains the reader
                        // in dispatch-only mode without firing built-in templates.
                        await docNodeTemplate.Body.ExecuteAsync(context).ConfigureAwait(false);
                    }

                    await docProcessor.ProcessAsync(inputReader, options.CancellationToken).ConfigureAwait(false);
                }
                else
                {
                    // The body contains xsl:apply-templates: executing it triggers the
                    // streaming processor through the active-processor handle, exactly
                    // as the source-document apply-templates path does.
                    await docNodeTemplate.Body.ExecuteAsync(context).ConfigureAwait(false);
                }
            }
            finally
            {
                context._activeStreamingProcessor = savedDocProcessor;
                context._activeStreamingReader = savedDocReader;
                context._activeStreamingCancellationToken = savedDocCt;
                context._activeStreamWatchers = savedDocWatchers;
                context.PopContextItem();
            }

            await context.DrainStreamingOutputAsync(options.CancellationToken).ConfigureAwait(false);

            if (isStreamingJsonOutput)
                FinalizeJsonOutput(context, outputBuilder, streamingPrincipalOutput, nodeStore, options);

            SecondaryResultDocuments = context.SecondaryResults;

            if (outputSink != null)
                return;

            var docOutput = outputBuilder.ToString();
            var docOutDecl = context.PrimaryOutputMatchedDeclaration ?? _stylesheet.Outputs.FirstOrDefault();
            docOutput = FinalizeOutput(docOutput, docOutDecl, context.PrincipalOutputCharacterMaps, FinalizeKind.Primary);
            outputBuilder.Clear();
            outputBuilder.Append(docOutput);
            return;
        }

        var processor = new StreamingXmlProcessor(
            _stylesheet, _templateIndex, context, nodeStore, options.InitialMode,
            streamingAccumulators);
        await processor.ProcessAsync(inputReader, options.CancellationToken)
            .ConfigureAwait(false);

        // Final drain — anything emitted after the last event-boundary drain.
        await context.DrainStreamingOutputAsync(options.CancellationToken).ConfigureAwait(false);

        if (isStreamingJsonOutput)
            FinalizeJsonOutput(context, outputBuilder, streamingPrincipalOutput, nodeStore, options);

        // Surface secondary results to the engine regardless of sink mode.
        SecondaryResultDocuments = context.SecondaryResults;

        // Sink path (FinalizeKind.StreamingSink): the unified FinalizeOutput post-processing
        // (indentation / decl / doctype / BOM / escape-uri / character maps / normalization)
        // operates on a fully-buffered string and so cannot apply to output that was already
        // delivered incrementally to the TextWriter sink. This is the one delivery path that
        // intentionally does NOT route through FinalizeOutput; secondary results were already
        // surfaced above, so we leave the builder empty and return.
        if (outputSink != null)
            return;

        var output = outputBuilder.ToString();

        // Route buffered streaming output through the same full finalization the non-streaming
        // delivery paths use (TransformAsync, node-source, initial-context-item). Previously this
        // path applied a bespoke subset (indentation / xml-decl / doctype / BOM / escape-uri) and
        // omitted text-strip, html method handling, content-type, character maps, and
        // normalization \u2014 that divergence was the bug. FinalizeOutput only runs the indentation
        // step for XML/HTML/XHTML methods, so JSON already serialized via FinalizeJsonOutput above
        // is not re-indented or corrupted.
        var streamOutputDecl = context.PrimaryOutputMatchedDeclaration ?? _stylesheet.Outputs.FirstOrDefault();
        output = FinalizeOutput(output, streamOutputDecl, context.PrincipalOutputCharacterMaps, FinalizeKind.Primary);

        // Replace the builder's contents with the post-processed output so the calling
        // wrapper sees the same string the original method returned.
        outputBuilder.Clear();
        outputBuilder.Append(output);
    }

    /// <summary>
    /// Recursively checks whether a sequence constructor contains an
    /// <c>xsl:apply-templates</c> instruction. Used by the streaming document-node
    /// template dispatch to decide whether the body drives the forward pass itself
    /// (apply-templates) or whether the processor must run in subscription-dispatch-only
    /// mode. Mirrors the local <c>ContentContainsApplyTemplates</c> helper used by the
    /// xsl:source-document streamable path.
    /// </summary>
    /// <summary>
    /// Returns true when a streamable transform would dispatch through a document-node
    /// template (<c>match="/"</c>) whose body cannot be driven off the live reader at the
    /// document level (see <see cref="StreamingSubtreeBufferDetector.RequiresWholeInputBuffer"/>).
    /// Such a body must run against a fully materialized input, so the caller routes to the
    /// in-memory engine instead of the streaming pass.
    /// </summary>
    private bool DocNodeTemplateRequiresWholeInputBuffer(XsltTransformOptions? options)
    {
        // Named-initial-template invocations don't dispatch through match="/".
        if (options?.InitialTemplate != null) return false;

        var probeStore = new XdmInMemoryStore();
        var probeDoc = new XdmDocument
        {
            Id = probeStore.NextId(),
            Document = new DocumentId(0),
            Children = []
        };
        probeStore.Register(probeDoc);

        XsltTemplate? docNodeTemplate;
        var ctx = new DefaultXsltExecutionContext(
            _stylesheet, _templateIndex, probeDoc, new StringBuilder(),
            options ?? new XsltTransformOptions(), probeStore);
        ctx.Owner = this;
        using (var mc = ctx.AcquireMatchContext())
            docNodeTemplate = _templateIndex.FindMatchingTemplate(probeDoc, options?.InitialMode, mc.Value);

        return docNodeTemplate != null
            && StreamingSubtreeBufferDetector.RequiresWholeInputBuffer(docNodeTemplate.Body);
    }

    private static bool ContentContainsApplyTemplatesStreaming(Ast.XsltSequenceConstructor? body)
    {
        if (body == null) return false;
        foreach (var insn in body.Instructions)
        {
            switch (insn)
            {
                case Ast.XsltApplyTemplates:
                    return true;
                // apply-templates is commonly wrapped in literal result elements
                // (e.g. <html>…<section><xsl:apply-templates/></section></html>) —
                // descend into every container so the doc-node dispatch correctly
                // recognizes the body as driving the stream via apply-templates
                // (and does NOT run in subscription-dispatch-only mode, which would
                // leave child elements unmatched). xsl:result-document is one such
                // container: a match="/" body of <xsl:result-document><xsl:apply-templates/>
                // </xsl:result-document> must keep the active streaming processor live
                // so the inner apply-templates streams into the redirected secondary
                // output rather than running against the empty synthetic document.
                case Ast.XsltLiteralResultElement lre when ContentContainsApplyTemplatesStreaming(lre.Content):
                case Ast.XsltCopy cp when ContentContainsApplyTemplatesStreaming(cp.Content):
                case Ast.XsltForEach fe when ContentContainsApplyTemplatesStreaming(fe.Body):
                case Ast.XsltResultDocument rd when ContentContainsApplyTemplatesStreaming(rd.Content):
                case Ast.XsltSequenceConstructor nested when ContentContainsApplyTemplatesStreaming(nested):
                    return true;
                case Ast.XsltIf i when ContentContainsApplyTemplatesStreaming(i.Then):
                    return true;
                case Ast.XsltChoose c:
                    foreach (var w in c.When)
                        if (ContentContainsApplyTemplatesStreaming(w.Body)) return true;
                    if (ContentContainsApplyTemplatesStreaming(c.Otherwise)) return true;
                    break;
                // xsl:try is transparent to the streaming crawl: a body-form
                // <xsl:try><xsl:apply-templates/><xsl:catch/></xsl:try> at match="/"
                // drives the stream through the wrapped apply-templates exactly as a
                // bare apply-templates would (the catch only supplies a grounded fallback
                // on error). Descend into the try body and each catch body so the
                // doc-node dispatch keeps the active streaming processor live rather than
                // running in subscription-dispatch-only mode — which would leave the
                // wrapped apply-templates evaluating against the empty synthetic document
                // and emit nothing (si-try-200).
                case Ast.XsltTry tr:
                    if (tr.Body != null && ContentContainsApplyTemplatesStreaming(tr.Body)) return true;
                    foreach (var cat in tr.Catches)
                        if (cat.Body != null && ContentContainsApplyTemplatesStreaming(cat.Body)) return true;
                    break;
            }
        }
        return false;
    }

    /// <summary>
    /// Navigates from a document root to the node specified by a simple XPath expression.
    /// Supports expressions like "/doc", "/doc/child", "/*".
    /// </summary>
    private static XdmNode? NavigateSourceSelect(XdmDocument doc, string select, XdmInMemoryStore store)
    {
        var trimmed = select.Trim();
        if (string.IsNullOrEmpty(trimmed) || trimmed == "/")
            return doc;

        // Parse simple path: /name1/name2/...
        if (!trimmed.StartsWith('/'))
            return null;

        XdmNode current = doc;
        var segments = trimmed[1..].Split('/');
        foreach (var segment in segments)
        {
            if (string.IsNullOrEmpty(segment))
                continue;

            // Find matching child node
            XdmNode? found = null;
            var children = current switch
            {
                XdmDocument docNode => docNode.Children,
                XdmElement elemNode => elemNode.Children,
                _ => []
            };

            if (segment == "text()")
            {
                // Select first text child
                foreach (var childId in children)
                {
                    var child = store.GetNode(childId);
                    if (child is XdmText)
                    {
                        found = child;
                        break;
                    }
                }
            }
            else
            {
                // Select first matching element child
                foreach (var childId in children)
                {
                    var child = store.GetNode(childId);
                    if (child is XdmElement elem && (segment == "*" || elem.LocalName == segment))
                    {
                        found = child;
                        break;
                    }
                }
            }

            if (found == null)
                return null;
            current = found;
        }

        return current;
    }

    internal static XdmDocument ConvertToXdm(XmlDocument doc, XdmInMemoryStore store, string? documentUri = null)
    {
        var docId = store.NextId();
        var docElementId = NodeId.None;

        var children = new List<NodeId>();
        foreach (XmlNode child in doc.ChildNodes)
        {
            // Skip text nodes (including whitespace) at the document level.
            // While the XDM spec allows text children of document nodes, in practice
            // XML parsers may add whitespace artifacts. Exclude them from children but
            // still include in string value (computed from doc.InnerText).
            if (child.NodeType is XmlNodeType.Text or XmlNodeType.Whitespace
                or XmlNodeType.SignificantWhitespace or XmlNodeType.CDATA)
                continue;

            var effectiveDocUri = documentUri ?? doc.BaseURI;
            var childNode = ConvertXmlNode(child, store, docId, new DocumentId(1), effectiveDocUri);
            if (childNode != null)
            {
                children.Add(childNode.Id);
                if (childNode is XdmElement && docElementId == NodeId.None)
                    docElementId = childNode.Id;
            }
        }

        var docNode = new XdmDocument
        {
            Id = docId,
            Document = new DocumentId(1),
            Parent = NodeId.None,
            DocumentElement = docElementId,
            DocumentUri = documentUri ?? doc.BaseURI,
            Children = children,
            DocumentElementLocalName = doc.DocumentElement?.LocalName
        };
        // Compute string value (concatenation of all descendant text nodes).
        // Use DocumentElement.InnerText to exclude document-level whitespace text nodes
        // that aren't modeled as XDM children (we skip text at document level above).
        docNode._stringValue = doc.DocumentElement?.InnerText ?? "";

        store.Register(docNode);
        return docNode;
    }

    private static XdmNode? ConvertXmlNode(XmlNode xmlNode, XdmInMemoryStore store, NodeId parentId, DocumentId docId, string? documentBaseUri = null)
    {
        switch (xmlNode.NodeType)
        {
            case XmlNodeType.Element:
            {
                var elemId = store.NextId();
                var elemNsId = store.InternNamespace(xmlNode.NamespaceURI ?? "");

                // RECOVER (temp-tree base-URI preservation): capture and drop the sentinel
                // namespace declaration + attribute, stamping CopySourceBaseUri below.
                string? recoveredBaseUri = null;

                // Collect all in-scope namespace declarations (including inherited ones)
                var nsDecls = new List<NamespaceBinding>();
                var seenPrefixes = new HashSet<string>();
                if (xmlNode is XmlElement xmlElem)
                {
                    var nav = xmlElem.CreateNavigator()!;
                    foreach (var kvp in nav.GetNamespacesInScope(System.Xml.XmlNamespaceScope.All))
                    {
                        if (kvp.Key == "xml")
                            continue; // Skip xml namespace
                        if (string.Equals(kvp.Value, BaseSentinelNs, StringComparison.Ordinal))
                            continue; // drop the sentinel namespace declaration
                        nsDecls.Add(new NamespaceBinding(kvp.Key, store.InternNamespace(kvp.Value)));
                        seenPrefixes.Add(kvp.Key);
                    }
                }
                else if (xmlNode.Attributes != null)
                {
                    foreach (XmlAttribute attr in xmlNode.Attributes)
                    {
                        if (attr.Name == "xmlns")
                        {
                            nsDecls.Add(new NamespaceBinding("", store.InternNamespace(attr.Value)));
                        }
                        else if (attr.Name.StartsWith("xmlns:", StringComparison.Ordinal))
                        {
                            if (string.Equals(attr.Value, BaseSentinelNs, StringComparison.Ordinal))
                                continue; // drop the sentinel namespace declaration
                            var prefix = attr.Name[6..];
                            nsDecls.Add(new NamespaceBinding(prefix, store.InternNamespace(attr.Value)));
                        }
                    }
                }

                // Convert attributes
                var attrIds = new List<NodeId>();
                if (xmlNode.Attributes != null)
                {
                    foreach (XmlAttribute attr in xmlNode.Attributes)
                    {
                        // Skip xmlns declarations
                        if (attr.Name == "xmlns" || attr.Name.StartsWith("xmlns:", StringComparison.Ordinal))
                            continue;
                        // Capture + drop the sentinel attribute (never a real XDM attribute)
                        if (string.Equals(attr.NamespaceURI, BaseSentinelNs, StringComparison.Ordinal)
                            && attr.LocalName == BaseSentinelLocalName)
                        {
                            recoveredBaseUri = attr.Value;
                            continue;
                        }

                        var attrId = store.NextId();
                        var isId = (attr.LocalName == "id" && attr.Prefix == "xml")
                            || attr.SchemaInfo?.SchemaType?.TypeCode == System.Xml.Schema.XmlTypeCode.Id
                            || (attr.OwnerDocument?.GetElementById(attr.Value) == attr.OwnerElement
                                && attr.OwnerElement != null);
                        var xdmAttr = new XdmAttribute
                        {
                            Id = attrId,
                            Document = docId,
                            Parent = elemId,
                            Namespace = store.InternNamespace(attr.NamespaceURI ?? ""),
                            LocalName = attr.LocalName,
                            Prefix = string.IsNullOrEmpty(attr.Prefix) ? null : attr.Prefix,
                            Value = attr.Value,
                            IsId = isId
                        };
                        store.Register(xdmAttr);
                        attrIds.Add(attrId);
                    }
                }

                // Convert children
                var childIds = new List<NodeId>();
                foreach (XmlNode child in xmlNode.ChildNodes)
                {
                    var childNode = ConvertXmlNode(child, store, elemId, docId, documentBaseUri);
                    if (childNode != null)
                        childIds.Add(childNode.Id);
                }

                // Compute string value (concatenation of all descendant text)
                var stringValue = xmlNode.InnerText;

                // Capture entity-derived base URI when it differs from the document's base URI
                string? entityBaseUri = null;
                if (!string.IsNullOrEmpty(xmlNode.BaseURI) && documentBaseUri != null
                    && !string.Equals(xmlNode.BaseURI, documentBaseUri, StringComparison.Ordinal))
                {
                    entityBaseUri = xmlNode.BaseURI;
                }

                var elem = new XdmElement
                {
                    Id = elemId,
                    Document = docId,
                    Parent = parentId,
                    Namespace = elemNsId,
                    LocalName = xmlNode.LocalName,
                    Prefix = string.IsNullOrEmpty(xmlNode.Prefix) ? null : xmlNode.Prefix,
                    BaseUri = entityBaseUri,
                    CopySourceBaseUri = recoveredBaseUri,
                    Attributes = attrIds,
                    Children = childIds,
                    NamespaceDeclarations = nsDecls.Count > 0
                        ? nsDecls.ToArray()
                        : XdmElement.EmptyNamespaceDeclarations
                };
                elem._stringValue = stringValue;
                store.Register(elem);
                return elem;
            }

            case XmlNodeType.Text:
            case XmlNodeType.CDATA:
            case XmlNodeType.Whitespace:
            case XmlNodeType.SignificantWhitespace:
            {
                var textId = store.NextId();
                var text = new XdmText
                {
                    Id = textId,
                    Document = docId,
                    Parent = parentId,
                    Value = xmlNode.Value ?? ""
                };
                store.Register(text);
                return text;
            }

            case XmlNodeType.Comment:
            {
                var commentId = store.NextId();
                var comment = new XdmComment
                {
                    Id = commentId,
                    Document = docId,
                    Parent = parentId,
                    Value = xmlNode.Value ?? ""
                };
                store.Register(comment);
                return comment;
            }

            case XmlNodeType.ProcessingInstruction:
            {
                var piId = store.NextId();
                // Capture entity-derived base URI for PIs
                string? piBaseUri = null;
                if (!string.IsNullOrEmpty(xmlNode.BaseURI) && documentBaseUri != null
                    && !string.Equals(xmlNode.BaseURI, documentBaseUri, StringComparison.Ordinal))
                {
                    piBaseUri = xmlNode.BaseURI;
                }
                var pi = new XdmProcessingInstruction
                {
                    Id = piId,
                    Document = docId,
                    Parent = parentId,
                    Target = xmlNode.Name,
                    Value = xmlNode.Value ?? "",
                    BaseUri = piBaseUri
                };
                store.Register(pi);
                return pi;
            }

            default:
                return null;
        }
    }

    /// <summary>
    /// Strips whitespace-only text nodes from elements matching xsl:strip-space declarations.
    /// Per XSLT spec: a whitespace text node is removed if its parent element matches
    /// strip-space and does NOT match preserve-space (preserve takes priority when both match).
    /// </summary>
    internal static void StripWhitespaceNodes(XdmDocument doc, List<NameTest> stripSpace, List<NameTest> preserveSpace, XdmInMemoryStore store)
    {
        StripWhitespaceRecursive(doc, stripSpace, preserveSpace, store);

        // Recompute document string value once after all stripping is complete
        var sb = new StringBuilder();
        foreach (var childId in doc.Children)
        {
            var child = store.GetNode(childId);
            if (child is XdmText t)
                sb.Append(t.Value);
            else if (child is XdmElement e)
                sb.Append(e.StringValue);
        }
        doc._stringValue = sb.ToString();
    }

    private static void StripWhitespaceRecursive(XdmNode parent, List<NameTest> stripSpace, List<NameTest> preserveSpace, XdmInMemoryStore store)
    {
        var children = parent switch
        {
            XdmDocument d => d.Children,
            XdmElement e => e.Children,
            _ => null
        };
        if (children == null || children.Count == 0)
            return;

        // Recurse into child elements FIRST (bottom-up processing ensures
        // children have correct string values before parent recomputation)
        foreach (var childId in children)
        {
            var childNode = store.GetNode(childId);
            if (childNode is XdmElement or XdmDocument)
            {
                StripWhitespaceRecursive(childNode, stripSpace, preserveSpace, store);
            }
        }

        // If this is an element, check whether to strip whitespace text children
        if (parent is XdmElement elem)
        {
            // Find best-matching strip and preserve declarations by priority.
            // Per XSLT spec: QName=0, prefix:*=-0.25, *=-0.5
            var bestStripPriority = double.NegativeInfinity;
            var hasStripMatch = false;
            foreach (var test in stripSpace)
            {
                if (test.Matches(XdmNodeKind.Element, elem.Namespace, elem.LocalName))
                {
                    var p = NameTestDefaultPriority(test);
                    if (p > bestStripPriority)
                        bestStripPriority = p;
                    hasStripMatch = true;
                }
            }
            var bestPreservePriority = double.NegativeInfinity;
            var hasPreserveMatch = false;
            if (hasStripMatch)
            {
                foreach (var test in preserveSpace)
                {
                    if (test.Matches(XdmNodeKind.Element, elem.Namespace, elem.LocalName))
                    {
                        var p = NameTestDefaultPriority(test);
                        if (p > bestPreservePriority)
                            bestPreservePriority = p;
                        hasPreserveMatch = true;
                    }
                }
            }
            // Strip wins if it matched and either no preserve matched or strip has higher priority
            var shouldStrip = hasStripMatch &&
                (!hasPreserveMatch || bestStripPriority >= bestPreservePriority);

            if (shouldStrip && children is List<NodeId> childList)
            {
                var countBefore = childList.Count;
                childList.RemoveAll(id =>
                {
                    var node = store.GetNode(id);
                    return node is XdmText text && string.IsNullOrWhiteSpace(text.Value);
                });
                // Recompute only this element's string value (children already have
                // correct values from bottom-up processing above)
                if (childList.Count != countBefore)
                    RecomputeStringValueLocal(elem, store);
            }
        }
    }

    /// <summary>
    /// Recomputes only this element's cached _stringValue after strip-space.
    /// Does NOT walk ancestors — callers should handle ancestor recomputation separately.
    /// </summary>
    private static void RecomputeStringValueLocal(XdmElement elem, XdmInMemoryStore store)
    {
        var sb = new StringBuilder();
        CollectTextContent(elem, store, sb);
        elem._stringValue = sb.ToString();
    }

    /// <summary>
    /// Recomputes the cached _stringValue of an element after children have been modified
    /// (e.g., after strip-space removes whitespace-only text nodes).
    /// </summary>
    private static void RecomputeStringValue(XdmElement elem, XdmInMemoryStore store)
    {
        var sb = new StringBuilder();
        CollectTextContent(elem, store, sb);
        elem._stringValue = sb.ToString();

        // Also recompute ancestors up to the document root
        static void RecomputeAncestors(XdmNode node, XdmInMemoryStore s)
        {
            if (!node.Parent.HasValue || node.Parent.Value == NodeId.None)
                return;
            var parent = s.GetNode(node.Parent.Value);
            if (parent is XdmElement parentElem)
            {
                var parentSb = new StringBuilder();
                CollectTextContent(parentElem, s, parentSb);
                parentElem._stringValue = parentSb.ToString();
                RecomputeAncestors(parentElem, s);
            }
            else if (parent is XdmDocument parentDoc)
            {
                var docSb = new StringBuilder();
                foreach (var childId in parentDoc.Children)
                {
                    var child = s.GetNode(childId);
                    if (child is XdmText t)
                        docSb.Append(t.Value);
                    else if (child is XdmElement e)
                    { CollectTextContent(e, s, docSb); }
                }
                parentDoc._stringValue = docSb.ToString();
            }
        }
        RecomputeAncestors(elem, store);
    }

    private static void CollectTextContent(XdmElement elem, XdmInMemoryStore store, StringBuilder sb)
    {
        foreach (var childId in elem.Children)
        {
            var child = store.GetNode(childId);
            if (child is XdmText text)
                sb.Append(text.Value);
            else if (child is XdmElement childElem)
                CollectTextContent(childElem, store, sb);
        }
    }

    /// <summary>
    /// Computes default priority for a NameTest used in strip-space/preserve-space.
    /// QName = 0, prefix:* = -0.25, * = -0.5
    /// </summary>
    private static double NameTestDefaultPriority(NameTest test)
    {
        if (!test.IsLocalNameWildcard)
            return 0; // QName — specific element name
        if (!string.IsNullOrEmpty(test.NamespaceUri) && test.NamespaceUri != "*")
            return -0.25; // prefix:* — specific namespace, wildcard name
        return -0.5; // * — matches everything
    }

    /// <summary>
    /// Scoped capture of writes to a <see cref="StringBuilder"/> via a length cursor,
    /// not via a string copy of the existing content.
    /// </summary>
    /// <remarks>
    /// <para>
    /// Replaces the historical pattern:
    /// </para>
    /// <code>
    /// var savedOutput = _output.ToString();   // O(N) alloc of whole buffer
    /// _output.Clear();
    /// ... write inner content ...
    /// var inner = _output.ToString();         // O(M) alloc of inner
    /// _output.Clear();
    /// _output.Append(savedOutput);            // O(N) copy back
    /// </code>
    /// <para>
    /// with the cursor-based equivalent that allocates only the inner string and
    /// truncates the builder back to its saved length on disposal:
    /// </para>
    /// <code>
    /// var saved = new XsltTransformEngine.ScopedOutputBuffer(_output);
    /// ... write inner content ...
    /// var inner = saved.GetWritten();         // O(M) alloc — the only one
    /// saved.Dispose();                        // O(1) truncate
    /// </code>
    /// <para>
    /// At <c>N = 100 MB</c> outer / <c>M = 1 KB</c> inner, the historical pattern
    /// allocates ~200 MB and copies the buffer twice; the cursor-based form
    /// allocates ~1 KB. This shows up most acutely in deeply-nested or
    /// many-iteration XSLT constructs over Dataverse-scale source documents.
    /// </para>
    /// <para>
    /// Used as a regular struct (not <c>using var</c> ref-struct) so it can be
    /// stored in a try/finally block for code that wants to do the truncate
    /// after a possibly-throwing body — many of the existing save/restore sites
    /// have that shape.
    /// </para>
    /// </remarks>
    internal struct ScopedOutputBuffer
    {
        private readonly System.Text.StringBuilder _buffer;
        private readonly int _savedLength;

        public ScopedOutputBuffer(System.Text.StringBuilder buffer)
        {
            _buffer = buffer;
            _savedLength = buffer.Length;
        }

        /// <summary>The length of <c>_output</c> at the time this scope was opened.</summary>
        public readonly int SavedLength => _savedLength;

        /// <summary>The number of characters written to <c>_output</c> since this scope was opened.</summary>
        public readonly int WrittenLength => _buffer.Length - _savedLength;

        /// <summary>Returns the slice of <c>_output</c> written since this scope was opened, as a new string.</summary>
        public readonly string GetWritten()
            => WrittenLength == 0 ? string.Empty : _buffer.ToString(_savedLength, WrittenLength);

        /// <summary>Truncates <c>_output</c> back to its saved length, discarding anything written in this scope.</summary>
        public readonly void Dispose() => _buffer.Length = _savedLength;
    }

}

/// <summary>
/// Wrapper for result tree fragments — XML content produced by variable/parameter body
/// that should be serialized as raw XML (not escaped text) when used in copy-of/sequence.
/// </summary>
internal sealed class ResultTreeFragment(string xmlContent, string? baseUri = null)
{
    public string XmlContent { get; } = xmlContent;
    public string? BaseUri { get; } = baseUri;

    /// <summary>
    /// Cached parsed document node for this RTF. Once parsed, the same XDM tree
    /// is reused to preserve node identity across pattern matching and navigation.
    /// </summary>
    internal XdmNode? CachedDocumentNode { get; set; }

    /// <summary>
    /// Returns the string value of this RTF (text content with XML markup stripped and entities decoded).
    /// This is the XPath string value of the document node.
    /// </summary>
    public override string ToString() => DefaultXsltExecutionContext.StripXmlMarkup(XmlContent);
}

/// <summary>
/// Lazy wrapper for variable values. Allows deferred evaluation of variables
/// to support XSLT's requirement that unused variables with circular references
/// don't cause errors.
/// </summary>
internal sealed class LazyValue
{
    private readonly Func<ValueTask<object?>> _evaluator;
    private object? _value;
    private bool _evaluated;
    private bool _evaluating; // Guard against circular evaluation
    private Exception? _error;

    public LazyValue(Func<ValueTask<object?>> evaluator)
    {
        _evaluator = evaluator;
    }

    public async ValueTask<object?> GetValueAsync()
    {
        if (_evaluated)
        {
            if (_error != null)
                throw _error;
            return _value;
        }

        if (_evaluating)
        {
            // Circular reference - return null to avoid infinite loop
            return null;
        }

        _evaluating = true;
        try
        {
            var result = await _evaluator().ConfigureAwait(false);
            // Unwrap nested LazyValue if present
            while (result is LazyValue nested)
            {
                result = await nested.GetValueAsync().ConfigureAwait(false);
            }
            _value = result;
            _evaluated = true;
            return _value;
        }
        catch (Exception ex)
        {
            _error = ex;
            _evaluated = true;
            throw;
        }
        finally
        {
            _evaluating = false;
        }
    }
}

/// <summary>
/// Options for XSLT transformation.
/// </summary>
/// <summary>
/// Mutable holder for the raw XDM result of a transformation invoked with
/// <see cref="XsltTransformOptions.ReturnRawXdm"/>. Used so the engine can write
/// back to the caller's options object while the rest of <see cref="XsltTransformOptions"/>
/// stays init-only. The boxed `Value` is the raw XDM: a single item, an `object?[]`
/// for sequences, or `null` for the empty sequence.
/// </summary>
public sealed class RawResultBox
{
    /// <summary>The raw XDM items captured during the most recent transformation.</summary>
    public object? Value { get; set; }
}

public sealed class XsltTransformOptions
{
    /// <summary>
    /// Initial mode for template matching.
    /// </summary>
    public QName? InitialMode { get; init; }

    /// <summary>
    /// Initial template to call (instead of applying templates).
    /// </summary>
    public QName? InitialTemplate { get; init; }

    /// <summary>
    /// Initial parameters to pass to the stylesheet (global stylesheet parameters).
    /// </summary>
    public Dictionary<QName, object?> InitialParameters { get; init; } = new();

    /// <summary>
    /// Parameters to pass specifically to the initial template call (via xsl:with-param).
    /// When non-empty, these are used instead of InitialParameters for the template call.
    /// </summary>
    public Dictionary<QName, object?> InitialTemplateParameters { get; init; } = new();

    /// <summary>
    /// Tunnel parameters to pass to the initial template call.
    /// </summary>
    public Dictionary<QName, object?> InitialTunnelParameters { get; init; } = new();

    /// <summary>
    /// Initial function to call (instead of applying templates).
    /// The function is identified by name; arity is determined from InitialFunctionArguments.
    /// </summary>
    public QName? InitialFunction { get; init; }

    /// <summary>
    /// Positional arguments to pass to the initial function call.
    /// </summary>
    public List<object?> InitialFunctionArguments { get; init; } = [];

    /// <summary>
    /// When <c>true</c>, the engine captures the raw XDM return value of the
    /// transformation (initial-function call, initial-template call, or
    /// apply-templates) into <see cref="RawResult"/> instead of serializing it
    /// to the output buffer. Used by <c>fn:transform()</c> with
    /// <c>delivery-format='raw'</c>, where callers expect typed XDM items
    /// (booleans, maps, nodes…) preserved end-to-end rather than serialized
    /// as XML markup and reparsed.
    /// </summary>
    public bool ReturnRawXdm { get; init; }

    /// <summary>
    /// Output channel populated by the engine when <see cref="ReturnRawXdm"/>
    /// is <c>true</c>. Holds the raw XDM result of the transformation: a single
    /// item, an <c>object?[]</c> for sequences, or <c>null</c> for the empty
    /// sequence. Mutable so the engine can write to it from inside the
    /// transformation; callers read it after <c>TransformAsync</c> returns.
    /// </summary>
    public RawResultBox RawResult { get; init; } = new();

    /// <summary>
    /// Output format to use.
    /// </summary>
    public QName? OutputFormat { get; init; }

    /// <summary>
    /// Base URI for resolving relative URIs.
    /// </summary>
    public Uri? BaseUri { get; init; }

    /// <summary>
    /// Document URI for the source document (used by fn:base-uri, fn:document-uri).
    /// </summary>
    public Uri? SourceDocumentUri { get; init; }

    /// <summary>
    /// Message listener for xsl:message output. Receives (message, terminate).
    /// </summary>
    public Action<string, bool>? MessageListener { get; init; }

    /// <summary>
    /// Extended message listener that also receives source location.
    /// Receives (message, terminate, line, column). Takes precedence over <see cref="MessageListener"/>.
    /// </summary>
    public Action<string, bool, int, int>? MessageListenerWithLocation { get; init; }

    /// <summary>
    /// Trace listener for debugging. Receives (depth, eventType, details) where eventType
    /// is "match", "apply", "call-template", "call-function", or "built-in".
    /// Depth indicates call nesting level.
    /// </summary>
    public Action<int, string, string>? TraceListener { get; init; }

    /// <summary>
    /// Whether a source document was explicitly supplied by the calling application.
    /// Used for xsl:global-context-item enforcement.
    /// </summary>
    public bool HasSourceDocument { get; set; }

    /// <summary>
    /// Cancellation token for cooperative cancellation of transformation.
    /// When cancelled, the transformation throws OperationCanceledException.
    /// </summary>
    public CancellationToken CancellationToken { get; init; }

    /// <summary>
    /// Maximum output size in characters. When the output StringBuilder exceeds this limit,
    /// the transformation throws an XsltException. Default is 50MB (~100MB in memory for UTF-16).
    /// Set to 0 to disable the limit.
    /// </summary>
    public int MaxOutputSize { get; init; } = 50 * 1024 * 1024;

    /// <summary>
    /// XPath expression to evaluate against the source document to determine the initial context node.
    /// When null, the document root is used. Example: "/doc" selects the document element named "doc".
    /// </summary>
    public string? SourceSelect { get; init; }

    /// <summary>
    /// XPath expression to determine the initial match selection for the initial mode.
    /// When set, the expression is evaluated with the source document as context,
    /// and templates are applied to each item in the resulting sequence instead of the document root.
    /// </summary>
    public string? InitialModeSelect { get; init; }

    /// <summary>
    /// Named collections of document file paths for fn:collection().
    /// Key is the collection URI, value is the list of document file paths.
    /// </summary>
    public Dictionary<string, List<string>>? Collections { get; init; }

    /// <summary>
    /// Optional resource security policy. When set, controls which URIs the transformation
    /// can access via doc(), unparsed-text(), collection(), xsl:result-document, and xsl:import/include.
    /// </summary>
    public PhoenixmlDb.XQuery.Security.ResourcePolicy? ResourcePolicy { get; init; }

    /// <summary>
    /// Optional pre-fetched contents for URIs that <c>fn:doc()</c> / <c>document()</c> would
    /// otherwise need to fetch over HTTP synchronously. Required on Blazor WebAssembly,
    /// which cannot block the calling thread; ignored on runtimes that can. See
    /// <see cref="PreloadedResources"/>.
    /// </summary>
    public PreloadedResources? PreloadedResources { get; init; }
}

/// <summary>
/// Index for efficient template lookup.
/// </summary>
internal sealed class TemplateIndex
{
    /// <summary>Sentinel QName for mode="#all" — matches any mode.</summary>
    internal static readonly QName AllModeSentinel = new(NamespaceId.None, "#all");
    /// <summary>Sentinel QName for mode="#default" when combined with named modes.</summary>
    internal static readonly QName DefaultModeSentinel = new(NamespaceId.None, "#default");

    private readonly Dictionary<QName, List<XsltTemplate>> _templatesByMode = new();
    private readonly List<XsltTemplate> _defaultModeTemplates = new();
    private readonly List<XsltTemplate> _allModeTemplates = new();
    private readonly List<TemplateIndex> _importedIndexes = new();
    // Cache for merged+sorted mode template lists to avoid re-allocating and re-sorting per call
    private readonly Dictionary<QName, List<XsltTemplate>> _mergedModeCache = new();

    /// <summary>Maps templates to their owning TemplateIndex for apply-imports module scoping.</summary>
    private readonly Dictionary<XsltTemplate, TemplateIndex> _templateOwners = new();

    public TemplateIndex(XsltStylesheet stylesheet)
    {
        IndexTemplates(stylesheet.Templates);

        // Build indexes for imported stylesheets (lower precedence)
        foreach (var imported in stylesheet.Imports)
        {
            _importedIndexes.Add(new TemplateIndex(imported));
        }
    }

    /// <summary>
    /// Finds a matching template searching only the imported stylesheet indexes
    /// (lower precedence). Used by xsl:apply-imports which must skip
    /// same-precedence templates and only search imports.
    /// </summary>
    public XsltTemplate? FindImportedTemplate(object node, QName? mode, XsltContext context)
    {
        for (var i = _importedIndexes.Count - 1; i >= 0; i--)
        {
            var match = _importedIndexes[i].FindMatchingTemplate(node, mode, context);
            if (match != null)
                return match;
        }
        return null;
    }

    /// <summary>
    /// Finds the TemplateIndex that directly owns a given template.
    /// Searches this index and all nested imported indexes.
    /// </summary>
    public TemplateIndex? FindOwnerIndex(XsltTemplate template)
    {
        if (_templateOwners.ContainsKey(template))
            return this;
        foreach (var imported in _importedIndexes)
        {
            var found = imported.FindOwnerIndex(template);
            if (found != null)
                return found;
        }
        return null;
    }

    private void IndexTemplates(List<XsltTemplate> templates)
    {
        foreach (var template in templates)
        {
            if (template.Match == null)
                continue;

            // Split union patterns into separate template entries
            var expandedTemplates = ExpandUnionPattern(template);

            foreach (var t in expandedTemplates)
            {
                _templateOwners[t] = this;
                if (t.Modes.Count == 0)
                {
                    _defaultModeTemplates.Add(t);
                }
                else if (t.Modes.Contains(AllModeSentinel))
                {
                    // mode="#all" — add to all-modes list AND default mode
                    _allModeTemplates.Add(t);
                    _defaultModeTemplates.Add(t);
                }
                else
                {
                    foreach (var mode in t.Modes)
                    {
                        if (mode == DefaultModeSentinel)
                        {
                            _defaultModeTemplates.Add(t);
                            continue;
                        }
                        if (!_templatesByMode.TryGetValue(mode, out var list))
                        {
                            list = new List<XsltTemplate>();
                            _templatesByMode[mode] = list;
                        }
                        list.Add(t);
                    }
                }
            }
        }

        // Stable sort by priority (higher first); last-declared wins for equal priority.
        // Since templates are added in declaration order, we use a stable sort
        // which preserves insertion order for equal keys.
        StableSortByPriority(_defaultModeTemplates);
        StableSortByPriority(_allModeTemplates);

        foreach (var list in _templatesByMode.Values)
        {
            StableSortByPriority(list);
        }
    }

    /// <summary>
    /// Expands a template with a union match pattern into multiple templates,
    /// one per union alternative, each with its own default priority.
    /// Non-union templates are returned as-is.
    /// </summary>
    private static List<XsltTemplate> ExpandUnionPattern(XsltTemplate template)
    {
        if (template.Match is not UnionPattern union)
            return [template];

        // Shared identity so that on-multiple-match="fail" checks can skip
        // alternatives from the same union pattern (spec bug 30402).
        // For next-match: only skip when there is an explicit priority (all
        // alternatives share it and represent one rule). Without explicit
        // priority each alternative is a separate rule (XSLT 3.0 §6.6).
        var groupId = new object();
        var result = new List<XsltTemplate>(union.Patterns.Count);
        foreach (var pattern in union.Patterns)
        {
            result.Add(new XsltTemplate
            {
                Name = template.Name,
                Match = pattern,
                Priority = template.Priority, // explicit priority overrides all alternatives
                Modes = template.Modes,
                As = template.As,
                Parameters = template.Parameters,
                Body = template.Body,
                Visibility = template.Visibility,
                UnionGroupId = groupId
            });
        }
        return result;
    }

    /// <summary>
    /// Stable sort by descending priority. For equal priorities, last-declared
    /// template wins (maintained by stable sort preserving insertion order,
    /// then the natural iteration picks the last matching one... but we need
    /// last-declared to be first in list). We reverse equal-priority elements
    /// so that last-declared appears first when iterating.
    /// </summary>
    private static void StableSortByPriority(List<XsltTemplate> templates)
    {
        // Decorate with original index for stable sort
        var indexed = templates.Select((t, i) => (template: t, index: i)).ToList();
        // Sort by priority descending, then by index descending (last-declared wins)
        indexed.Sort((a, b) =>
        {
            var cmp = EffectivePriority(b.template).CompareTo(EffectivePriority(a.template));
            return cmp != 0 ? cmp : b.index.CompareTo(a.index);
        });
        for (var i = 0; i < templates.Count; i++)
        {
            templates[i] = indexed[i].template;
        }
    }

    public static double EffectivePriority(XsltTemplate template)
    {
        return template.Priority ?? template.Match?.DefaultPriority ?? 0.5;
    }

    /// <summary>
    /// Resolves namespace URIs in patterns to NamespaceIds using the provided resolver.
    /// This should be called once per transformation when the node store is available.
    /// </summary>
    public void ResolvePatternNamespaces(Func<string, NamespaceId> namespaceResolver)
    {
        ResolveNamespacesInTemplates(_defaultModeTemplates, namespaceResolver);
        ResolveNamespacesInTemplates(_allModeTemplates, namespaceResolver);
        foreach (var list in _templatesByMode.Values)
        {
            ResolveNamespacesInTemplates(list, namespaceResolver);
        }
        foreach (var importedIndex in _importedIndexes)
        {
            importedIndex.ResolvePatternNamespaces(namespaceResolver);
        }
    }

    private static void ResolveNamespacesInTemplates(List<XsltTemplate> templates, Func<string, NamespaceId> resolver)
    {
        foreach (var template in templates)
        {
            ResolveNamespacesInPattern(template.Match, resolver);
        }
    }

    internal static void ResolveNamespacesInPattern(XsltPattern? pattern, Func<string, NamespaceId> resolver)
    {
        switch (pattern)
        {
            case PathPattern pp:
                foreach (var step in pp.Steps)
                {
                    if (step.NodeTest is NameTest nt)
                    {
                        nt.ResolveNamespace(resolver);
                    }
                }
                break;
            case UnionPattern up:
                foreach (var p in up.Patterns)
                {
                    ResolveNamespacesInPattern(p, resolver);
                }
                break;
            case ExceptPattern ep:
                ResolveNamespacesInPattern(ep.Left, resolver);
                ResolveNamespacesInPattern(ep.Right, resolver);
                break;
            case IntersectPattern ip:
                ResolveNamespacesInPattern(ip.Left, resolver);
                ResolveNamespacesInPattern(ip.Right, resolver);
                break;
        }
    }

    /// <summary>
    /// Returns true if the given mode name is explicitly used by a template rule
    /// (not just via mode="#all") or declared via xsl:mode.
    /// </summary>
    public bool IsModeExplicitlyUsed(QName mode)
    {
        if (_templatesByMode.ContainsKey(mode))
            return true;
        foreach (var imported in _importedIndexes)
        {
            if (imported.IsModeExplicitlyUsed(mode))
                return true;
        }
        return false;
    }

    public XsltTemplate? FindMatchingTemplate(object node, QName? mode, XsltContext context)
    {
        return FindMatchingTemplate(node, mode, context, after: null);
    }

    public XsltTemplate? FindMatchingTemplate(object node, QName? mode, XsltContext context, XsltTemplate? after)
    {
        // Treat unnamed/default mode (empty string QName) same as null — use default mode templates
        var isDefaultMode = !mode.HasValue || mode.Value.LocalName.Length == 0;
        List<XsltTemplate> templates;
        if (!isDefaultMode && _templatesByMode.TryGetValue(mode!.Value, out var modeTemplates))
        {
            // Merge mode-specific templates with #all templates, sorted by priority
            if (_allModeTemplates.Count > 0)
            {
                // Use cached merged list to avoid re-allocating and re-sorting per call
                if (!_mergedModeCache.TryGetValue(mode.Value, out templates!))
                {
                    templates = new List<XsltTemplate>(modeTemplates.Count + _allModeTemplates.Count);
                    templates.AddRange(modeTemplates);
                    templates.AddRange(_allModeTemplates);
                    templates.Sort((a, b) => EffectivePriority(b).CompareTo(EffectivePriority(a)));
                    _mergedModeCache[mode.Value] = templates;
                }
            }
            else
            {
                templates = modeTemplates;
            }
        }
        else if (!isDefaultMode && _allModeTemplates.Count > 0)
        {
            // No mode-specific templates, but #all templates apply
            templates = _allModeTemplates;
        }
        else if (!isDefaultMode)
        {
            // Named mode with no matching templates — don't fall back to
            // default mode. Per XSLT spec, modes are separate matching
            // contexts; return null to trigger built-in template rules.
            templates = _allModeTemplates; // empty if no #all templates
        }
        else
        {
            templates = _defaultModeTemplates;
        }

        var pastAfter = after == null;
        // For next-match: skip remaining union alternatives only when the
        // template has an explicit priority (all alternatives share it and
        // represent one template rule). Without explicit priority, each
        // alternative is a separate rule per XSLT 3.0 §6.6.
        var skipUnionGroup = (after?.Priority.HasValue == true) ? after.UnionGroupId : null;
        foreach (var template in templates)
        {
            if (!pastAfter)
            {
                if (ReferenceEquals(template, after))
                    pastAfter = true;
                continue;
            }

            // Skip remaining alternatives of the same union pattern (same template rule body)
            if (skipUnionGroup != null && template.UnionGroupId == skipUnionGroup)
                continue;

            if (template.Match!.Matches(node, context))
            {
                return template;
            }
        }

        // Search imported stylesheets (lower precedence, in reverse order per XSLT spec)
        // If we haven't passed 'after' yet, carry it through imports
        for (var i = _importedIndexes.Count - 1; i >= 0; i--)
        {
            var match = _importedIndexes[i].FindMatchingTemplate(node, mode, context, pastAfter ? null : after);
            if (match != null)
                return match;
            // If this import contained 'after' but had no subsequent match,
            // mark it consumed so remaining lower-precedence imports search freely
            if (!pastAfter && after != null && _importedIndexes[i].FindOwnerIndex(after) != null)
                pastAfter = true;
        }

        return null;
    }
}

/// <summary>
/// Default implementation of XSLT execution context.
/// </summary>
internal sealed partial class DefaultXsltExecutionContext : XsltExecutionContext
{
    /// <summary>
    /// The engine that created this context. Used by the xsl:result-document path to route
    /// secondary-document serialization through the shared <see cref="XsltTransformEngine.FinalizeOutput"/>
    /// pipeline (the engine owns the character-map application that depends on the stylesheet).
    /// </summary>
    internal XsltTransformEngine? Owner { get; set; }

    internal readonly XsltStylesheet _stylesheet;
    private readonly TemplateIndex _templateIndex;
    private readonly Stack<Scope> _scopes = new();
    private readonly Stack<object?> _contextItems = new();
    private readonly Stack<(int position, int last)> _contextPositions = new();
    private readonly Stack<object?> _currentItems = new(); // For XSLT current() function
    private readonly StringBuilder _output;
    internal readonly XsltTransformOptions _options;
    internal readonly XdmInMemoryStore? _nodeStore;
    private readonly PhoenixmlDb.XQuery.Functions.FunctionLibrary _functionLibrary;
    private readonly XsltDocumentResolver _documentResolver;
    private readonly PhoenixmlDb.XQuery.Security.PolicyEnforcingResolver? _policyResolver;
    private readonly PhoenixmlDb.XQuery.ISchemaProvider? _schemaProvider;

    public Dictionary<QName, object?> GlobalVariables { get; } = new();

    // Cache optimized query plans by expression identity to avoid re-optimizing in loops
    private readonly Dictionary<XQueryExpression, PhoenixmlDb.XQuery.Execution.ExecutionPlan> _planCache = new(ReferenceEqualityComparer.Instance);

    // Attribute collection mode for xsl:element
    // Use a stack to support nested element construction
    private readonly Stack<StringBuilder> _collectedAttributesStack = new();
    private int _textContentDepth; // >0 when collecting simple text content (attribute/comment/PI body)
    private int _attributeContentDepth; // >0 when collecting attribute value content (no space joining)
    private int _documentNodeDepth; // >0 when inside xsl:document (cannot add attributes/namespaces)
    private SourceLocation? _currentInstructionLocation; // Most-recent attribute-emitting instruction location, for XTDE0410/0420 messages

    // Offset in `_output` below which content is considered "outer" — owned by an enclosing
    // scope, not by anything currently executing. Updated by `ScopedOutputBuffer` to the
    // saved length on entry and restored to the previous value on dispose.
    //
    // Why it exists: the historical pattern was to do `_output.ToString()` + `_output.Clear()`
    // before executing a body that could produce e.g. an `xsl:attribute`, then restore via
    // `_output.Clear()` + `_output.Append(savedOutput)`. The `Clear()` step had a functional
    // side effect beyond restoration: it made `_output.Length == 0` inside the body, which
    // is what the XTDE0410 / XTDE0420 / simple-content-spacing checks compare against to
    // decide "has any child content been produced yet?". When we replace the save/restore
    // pattern with a length-cursor (eliminating the O(N) string copy on big documents), we
    // need a separate signal for "logical start of the current scope" so those checks still
    // see "no children yet." Otherwise an inner xsl:attribute fires a spurious XTDE0410
    // because outer content makes `_output.Length > 0`.
    private int _outputLogicalStart;

    /// <summary>
    /// Optional external sink for incremental streaming output. When non-null, the
    /// <see cref="StreamingXmlProcessor"/> calls <see cref="DrainStreamingOutputAsync"/>
    /// at each safe event boundary to flush <see cref="_output"/> here and reset its
    /// length to zero, bounding peak memory for large streamed transforms. The sink is
    /// only meaningful when the context is driving a streaming transform; non-streaming
    /// callers leave it null.
    /// </summary>
    internal TextWriter? _streamingOutputSink;

    // When a template/function body is being captured for `as=` type-checking, we have two
    // parallel output channels: `_output` (LREs, text) and `_sequenceAccumulator`
    // (xsl:attribute, xsl:sequence, xsl:document). To recover document order at result
    // assembly, an `AsBodyCapture` records the `_output` offset at the moment each
    // accumulator item is added. Position recording only fires when the current accumulator
    // is the capture's accumulator — items routed through *inner* accumulators (e.g. an
    // `xsl:variable` body that allocates its own accumulator) don't pollute the outer
    // capture's position list.
    private sealed class AsBodyCapture
    {
        public required List<object?> Accumulator { get; init; }
        public required int OutputBaseLen { get; init; }
        public List<int> Positions { get; } = [];
    }

    private AsBodyCapture? _currentAsBodyCapture;

    private int _textOutputModeDepth; // >0 when inside method="text" result-document; text from xsl:sequence/value-of gets sentinel-escaped to protect from StripXmlMarkup
    private int _insideXslEvaluateDepth; // >0 when inside xsl:evaluate; XSLT-specific functions raise XTDE3160
    private int _templateDepth; // Nesting depth for trace output
    private Dictionary<string, string>? _evaluateNamespaceBindings; // Namespace bindings override during xsl:evaluate
    private readonly HashSet<QName> _activeAttributeSets = new(); // Detect circular attribute set references (XTDE0640)
    internal readonly HashSet<QName> _globalsBeingEvaluated = new(); // Detect circular global variable/param references (XTDE0640)

    // Streaming execution state: when true, built-in template recursion into children is
    // a no-op because the streaming loop (StreamingXmlProcessor) handles child dispatch.
    internal bool _isStreamingExecution;
    // Stack of element qualified names whose start tags have been written during streaming
    // but whose end tags must be deferred until the StreamingXmlProcessor sees EndElement.
    internal readonly Stack<string> _streamingOpenElements = new();
    // Active streaming processor reference for triggering streaming from apply-templates
    // inside xsl:source-document Content bodies.
    internal StreamingXmlProcessor? _activeStreamingProcessor;
    internal XmlReader? _activeStreamingReader;
    internal CancellationToken _activeStreamingCancellationToken;
    internal IReadOnlyList<StreamWatcher>? _activeStreamWatchers;

    /// <summary>
    /// Set by streaming-aware operators (notably xsl:for-each-group) when they consumed
    /// an event from <see cref="_activeStreamingReader"/> that the
    /// <see cref="StreamingXmlProcessor"/> still needs to process. The processor checks
    /// this flag at the top of its event loop; if true, it skips its own
    /// <c>ReadAsync</c> and processes the current reader position, then clears the flag.
    /// Use case: for-each-group consumes the parent's EndElement to detect end-of-children;
    /// the processor still needs to do its EndElement bookkeeping (pop ancestor stack,
    /// fire end-phase accumulators, write deferred close tag).
    /// </summary>
    internal bool _streamingDeferReadOnNextIteration;

    /// <summary>
    /// Set by <see cref="MatchAndExecuteStreamingNodeAsync"/> when the matched
    /// template required snapshot()/copy-of() of the matched subtree, so the
    /// engine consumed events from <see cref="_activeStreamingReader"/> via
    /// <c>ReadSubtree()</c>, parsed them into an in-memory XdmElement, and ran
    /// the body against that buffered tree. The processor checks this flag
    /// after MatchAndExecute returns: when set it skips ancestor-stack push
    /// and fires End-phase accumulator + watcher events manually (the matching
    /// EndElement event was consumed by ReadSubtree and won't arrive separately).
    /// </summary>
    internal bool _streamingSubtreeBufferConsumed;

    /// <summary>
    /// One entry on <see cref="_streamingDeferredExecutions"/>. Captures everything
    /// needed to run a template body at the parent EndElement event with watcher
    /// results substituted into consuming aggregates.
    /// </summary>
    internal sealed class DeferredStreamingExecution
    {
        public required Ast.XsltTemplate Template;
        public required object Element;          // the matched node (XdmElement)
        public required QName? Mode;
        public required int Position;
        public required int ParentDepth;          // streaming reader depth where this fired
        public required IReadOnlyList<StreamWatcher> Watchers;
        public IReadOnlyList<StreamWatcher>? PriorActiveWatchers;
    }

    /// <summary>
    /// Stack of templates whose bodies were deferred because they contain consuming
    /// aggregates (count(*), sum(*), etc.). Watchers accumulate as the streaming
    /// processor reads the matched element's children; on the parent EndElement,
    /// the body is executed with <see cref="_activeStreamWatchers"/> set so the
    /// existing TryResolveFromWatchers path substitutes accumulated values into the
    /// expressions.
    /// </summary>
    internal readonly Stack<DeferredStreamingExecution> _streamingDeferredExecutions = new();

    /// <summary>
    /// Try to resolve an expression (or its sub-expressions) from watcher results.
    /// Handles direct matches and map constructors with watcher entry values.
    /// </summary>
    /// <summary>
    /// Group A: returns the watcher whose <c>SourceExpression</c> is exactly
    /// <paramref name="expr"/> (reference identity), or null. Used by the resolve
    /// path to surface a wrapped-aggregation watcher carrying an outer op
    /// (predicates / SimpleMap RIGHT) to apply to the grounded accumulated sequence.
    /// </summary>
    private static StreamWatcher? FindDirectWatcher(
        PhoenixmlDb.XQuery.Ast.XQueryExpression expr,
        IReadOnlyList<StreamWatcher> watchers)
    {
        foreach (var watcher in watchers)
            if (ReferenceEquals(expr, watcher.SourceExpression))
                return watcher;
        return null;
    }

    private static (bool Resolved, object? Value) TryResolveFromWatchers(
        PhoenixmlDb.XQuery.Ast.XQueryExpression expr,
        IReadOnlyList<StreamWatcher> watchers)
    {
        // Direct match: the entire expression is a watched sub-expression
        foreach (var watcher in watchers)
        {
            if (ReferenceEquals(expr, watcher.SourceExpression))
                return (true, watcher.GetResult());
        }

        // Map constructor: resolve each entry's value from watchers and build the map
        if (expr is PhoenixmlDb.XQuery.Ast.MapConstructor mapCtor)
        {
            var hasWatcherEntries = false;
            foreach (var entry in mapCtor.Entries)
            {
                foreach (var watcher in watchers)
                {
                    if (ReferenceEquals(entry.Value, watcher.SourceExpression))
                    {
                        hasWatcherEntries = true;
                        break;
                    }
                }
                if (hasWatcherEntries) break;
            }

            if (hasWatcherEntries)
            {
                var map = new OrderedXdmMap(EqualityComparer<object>.Default);
                foreach (var entry in mapCtor.Entries)
                {
                    object? key = entry.Key switch
                    {
                        PhoenixmlDb.XQuery.Ast.StringLiteral sl => sl.Value,
                        PhoenixmlDb.XQuery.Ast.IntegerLiteral il => il.Value,
                        _ => entry.Key.ToString()
                    };

                    object? value = null;
                    foreach (var watcher in watchers)
                    {
                        if (ReferenceEquals(entry.Value, watcher.SourceExpression))
                        {
                            value = watcher.GetResult();
                            break;
                        }
                    }

                    if (key != null)
                        map[key] = value;
                }
                return (true, map);
            }
        }

        return (false, null);
    }

    /// <summary>
    /// Attempts to resolve a single expression to a scalar object using only
    /// watcher results and literal values — no streaming context needed.
    /// Returns (true, value) if the expression can be fully resolved this way.
    /// </summary>
    private (bool Resolved, object? Value) TryResolveExprFromWatchers(
        PhoenixmlDb.XQuery.Ast.XQueryExpression expr,
        IReadOnlyList<StreamWatcher> watchers)
    {
        // Direct watcher match
        var watcherMatch = TryResolveFromWatchers(expr, watchers);
        if (watcherMatch.Resolved) return watcherMatch;

        // Literal values are always resolvable
        switch (expr)
        {
            case PhoenixmlDb.XQuery.Ast.StringLiteral sl: return (true, sl.Value);
            case PhoenixmlDb.XQuery.Ast.IntegerLiteral il: return (true, il.Value);
            case PhoenixmlDb.XQuery.Ast.DoubleLiteral dl: return (true, dl.Value);
            case PhoenixmlDb.XQuery.Ast.DecimalLiteral decL: return (true, decL.Value);
            case PhoenixmlDb.XQuery.Ast.BooleanLiteral bl: return (true, bl.Value);
            case PhoenixmlDb.XQuery.Ast.EmptySequence: return (true, Array.Empty<object?>());
            // Variable references: look up via XSLT scope (globals + lexical scopes).
            // Needed so subsequence(copy-of(/path), $start, $length) resolves the
            // grounded integer parameters when the inner watcher provides the seq.
            case PhoenixmlDb.XQuery.Ast.VariableReference vref:
                try
                {
                    var val = GetVariable(vref.Name);
                    return (true, val);
                }
                catch (XsltException)
                {
                    return (false, null);
                }
                catch (KeyNotFoundException)
                {
                    return (false, null);
                }
        }

        // Named function reference: e.g., f:test#1 or fn:lower-case#1.
        // Resolve directly via the function library so higher-order calls like
        // filter(copy-of(/path), f:test#1) and fold-right(seq, 0, f:add#2)
        // can pass the all-args-resolvable gate without re-entering the eval
        // pipeline (which would crawl the synthetic empty document).
        if (expr is PhoenixmlDb.XQuery.Ast.NamedFunctionRef nfr)
        {
            var func = _functionLibrary.Resolve(nfr.Name, nfr.Arity);
            if (func == null) return (false, null);
            // Match NamedFunctionRefOperator: variadic functions get wrapped so they
            // expose the requested arity to the dynamic caller.
            object item = func.IsVariadic
                ? new PhoenixmlDb.XQuery.Execution.VariadicFunctionRefItem(func, nfr.Arity)
                : func;
            return (true, item);
        }

        // Inline function expression: e.g., function($x) { $x + 1 }.
        // Materialise as an InlineFunctionItem with a minimal captured context so
        // the closure remains invokable by the HOF that receives it.
        if (expr is PhoenixmlDb.XQuery.Ast.InlineFunctionExpression ife)
        {
            // The captured context is owned by the InlineFunctionItem closure for its
            // lifetime — it cannot be disposed eagerly here.
#pragma warning disable CA2000
            var capturedContext = new PhoenixmlDb.XQuery.Execution.QueryExecutionContext(
                container: default,
                functions: _functionLibrary,
                nodeProvider: _nodeStore,
                documentResolver: null,
                schemaProvider: _schemaProvider,
                namespaceResolver: null);
#pragma warning restore CA2000
            capturedContext.DefaultCollation = DefaultCollation;
            capturedContext.StaticBaseUri = StaticBaseUri;
            var inlineItem = new PhoenixmlDb.XQuery.Execution.InlineFunctionItem(
                ife.Parameters, ife.Body, capturedContext, ife.ReturnType);
            return (true, inlineItem);
        }

        // Sequence of literals: e.g., ('a', 'b', 'c') — evaluable without context
        if (expr is PhoenixmlDb.XQuery.Ast.SequenceExpression seqExpr)
        {
            var allResolved = true;
            var items = new List<object?>();
            foreach (var item in seqExpr.Items)
            {
                var (itemResolved, itemVal) = TryResolveExprFromWatchers(item, watchers);
                if (!itemResolved) { allResolved = false; break; }
                items.Add(itemVal);
            }
            if (allResolved)
                return (true, items.Count == 1 ? items[0] : items.ToArray());
        }

        return (false, null);
    }

    /// <summary>
    /// Walks an expression tree and substitutes any watched sub-expression
    /// (by reference identity against <paramref name="watchers"/>) with a
    /// <see cref="VariableReference"/> to the synthetic
    /// <c>$__streaming_watcher_N</c> binding. Returns the original
    /// <paramref name="expr"/> unchanged when no watched node is found anywhere
    /// inside, so the plan cache stays warm for non-streaming hot paths.
    /// Handles only the AST shapes that matter for current streaming patterns
    /// (PathExpression with InitialExpression and FunctionCallExpression args);
    /// other shapes are returned unchanged but their children are still walked
    /// when descending through the recognised shapes.
    /// </summary>
    private static XQueryExpression RewriteWithWatcherVariables(
        PhoenixmlDb.XQuery.Ast.XQueryExpression expr,
        IReadOnlyList<StreamWatcher> watchers)
    {
        // Direct match: replace the whole node with $__streaming_watcher_N.
        for (var wi = 0; wi < watchers.Count; wi++)
        {
            var w = watchers[wi];
            if (ReferenceEquals(expr, w.SourceExpression))
            {
                var varRef = new PhoenixmlDb.XQuery.Ast.VariableReference
                {
                    Name = new QName(NamespaceId.None, $"__streaming_watcher_{wi}")
                };

                // Group A wrapped-aggregation watcher (outermost/head/remove(path)
                // carrying OUTER positional predicates). The watcher's SourceExpression
                // is the WHOLE FilterExpression `wrapped(path)[pred…]`, but the bound
                // $__streaming_watcher_N variable holds only the GROUNDED BASE sequence
                // (inner result + outermost-dedup + remove-skip) — the outer predicates
                // are NOT baked into the variable value. When this watcher is used as an
                // operand of a surrounding expression (e.g. `outermost(//PRICE)[1] + $two`),
                // substituting the bare variable DROPS the outer `[1]`, yielding the whole
                // unfiltered sequence and an "arithmetic operand is a sequence of more than
                // one item" error (sx-arithmetic-002 regression). Preserve the outer
                // predicates by re-wrapping the variable in a FilterExpression:
                // `$__streaming_watcher_N[pred…]`. NB this branch only fires for wrappers
                // with OuterPredicates; a filtered attribute-axis general-comparison watcher
                // ((a/b/@v[pred]) = C) folds its predicate into the inner path (empty
                // OuterPredicates), so the whole operand is substituted with no residual
                // predicate — the two cases stay distinct.
                if (w.OuterPredicates.Count > 0)
                {
                    return new PhoenixmlDb.XQuery.Ast.FilterExpression
                    {
                        Primary = varRef,
                        Predicates = w.OuterPredicates,
                    };
                }

                return varRef;
            }
        }

        switch (expr)
        {
            case PhoenixmlDb.XQuery.Ast.PathExpression pe:
            {
                var initial = pe.InitialExpression;
                XQueryExpression? newInitial = null;
                if (initial != null)
                {
                    var rw = RewriteWithWatcherVariables(initial, watchers);
                    if (!ReferenceEquals(rw, initial)) newInitial = rw;
                }
                // Steps may carry predicates with watched sub-expressions; for
                // the current shape (snapshot(path)//tail/@attr) predicates are
                // not exercised, so leave them as-is to avoid touching shape
                // we have no test coverage for. If a future shape needs it,
                // extend here.
                if (newInitial == null) return expr;
                return new PhoenixmlDb.XQuery.Ast.PathExpression
                {
                    IsAbsolute = pe.IsAbsolute,
                    InitialExpression = newInitial,
                    Steps = pe.Steps,
                };
            }

            case PhoenixmlDb.XQuery.Ast.FunctionCallExpression fc:
            {
                XQueryExpression[]? newArgs = null;
                for (var i = 0; i < fc.Arguments.Count; i++)
                {
                    var orig = fc.Arguments[i];
                    var rw = RewriteWithWatcherVariables(orig, watchers);
                    if (!ReferenceEquals(rw, orig))
                    {
                        if (newArgs == null)
                        {
                            newArgs = new XQueryExpression[fc.Arguments.Count];
                            for (var j = 0; j < i; j++) newArgs[j] = fc.Arguments[j];
                        }
                        newArgs[i] = rw;
                    }
                    else if (newArgs != null)
                    {
                        newArgs[i] = orig;
                    }
                }
                if (newArgs == null) return expr;
                return new PhoenixmlDb.XQuery.Ast.FunctionCallExpression
                {
                    Name = fc.Name,
                    Arguments = newArgs,
                };
            }

            // Binary operator (arithmetic / value / general comparison) whose
            // operands may be watched sub-expressions — e.g. a lone
            // (a/b/@v[pred]) = 4.32 where the LEFT is a streamed filtered
            // attribute sequence. Substitute each watched operand with its
            // $__streaming_watcher_N variable so the comparison runs against the
            // accumulated sequence instead of re-evaluating the (now-closed)
            // path against the synthetic empty document (which short-circuits
            // to false). Without this the whole binary is returned unchanged and
            // the watcher value is never seen — the regression behind
            // sx-GeneralComp-*-019/119 over a predicated attribute axis.
            case PhoenixmlDb.XQuery.Ast.BinaryExpression bin:
            {
                var newLeft = RewriteWithWatcherVariables(bin.Left, watchers);
                var newRight = RewriteWithWatcherVariables(bin.Right, watchers);
                if (ReferenceEquals(newLeft, bin.Left) && ReferenceEquals(newRight, bin.Right))
                    return expr;
                return new PhoenixmlDb.XQuery.Ast.BinaryExpression
                {
                    Left = newLeft,
                    Operator = bin.Operator,
                    Right = newRight,
                };
            }

            // SimpleMap: descend into Left so a watched LHS (e.g.
            // outermost(//PRICE) inside `outermost(//PRICE) ! string(.)`) gets
            // replaced with $__streaming_watcher_N. The Right is a per-item
            // expression that runs against each materialized item — leave it
            // unchanged so per-item context evaluation works naturally.
            case PhoenixmlDb.XQuery.Ast.SimpleMapExpression sme:
            {
                var newLeft = RewriteWithWatcherVariables(sme.Left, watchers);
                if (ReferenceEquals(newLeft, sme.Left)) return expr;
                return new PhoenixmlDb.XQuery.Ast.SimpleMapExpression
                {
                    Left = newLeft,
                    Right = sme.Right,
                    IsPathStep = sme.IsPathStep,
                };
            }
        }

        return expr;
    }

    /// <summary>
    /// Attempts to evaluate a function call by resolving all its arguments from
    /// stream watchers or literals, then invoking the function directly.
    /// Returns (true, value) if all arguments were resolvable; (false, null) otherwise.
    ///
    /// This handles consuming sub-expressions used as arguments to non-consuming
    /// functions — e.g., translate(head(//AUTHOR), ' ', '_') in an AVT attribute name.
    /// </summary>
    private async ValueTask<(bool Resolved, object? Value)> TryEvaluateFunctionWithWatcherArgs(
        PhoenixmlDb.XQuery.Ast.FunctionCallExpression fcall,
        IReadOnlyList<StreamWatcher> watchers)
    {
        // Resolve each argument; give up if any can't be resolved
        var args = new object?[fcall.Arguments.Count];
        for (var i = 0; i < fcall.Arguments.Count; i++)
        {
            var (resolved, val) = TryResolveExprFromWatchers(fcall.Arguments[i], watchers);
            if (!resolved) return (false, null);
            args[i] = val;
        }

        // Only handle standard library functions (fn: or unqualified namespace).
        // User-defined XSLT functions (any other namespace) require the full XSLT execution
        // context and cannot be invoked with the minimal execContext here.
        var ns = fcall.Name.Namespace;
        if (ns != PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn && ns != NamespaceId.None)
            return (false, null);

        // Look up the function in the function library and invoke it
        var fn = _functionLibrary.Resolve(fcall.Name, fcall.Arguments.Count);
        if (fn == null) return (false, null);

        // Build a minimal execution context for the function invocation
        using var execContext = new PhoenixmlDb.XQuery.Execution.QueryExecutionContext(
            container: default,
            functions: _functionLibrary,
            nodeProvider: _nodeStore,
            documentResolver: null,
            schemaProvider: _schemaProvider,
            namespaceResolver: null);
        execContext.DefaultCollation = DefaultCollation;
        execContext.StaticBaseUri = StaticBaseUri;

        var result = await fn.InvokeAsync(args, execContext).ConfigureAwait(false);
        return (true, result);
    }

    private static bool IsGeneralComparison(BinaryOperator op)
        => op is BinaryOperator.GeneralEqual or BinaryOperator.GeneralNotEqual
              or BinaryOperator.GeneralLessThan or BinaryOperator.GeneralLessOrEqual
              or BinaryOperator.GeneralGreaterThan or BinaryOperator.GeneralGreaterOrEqual;

    /// <summary>
    /// When a general-comparison expression has one operand that is a
    /// SimpleMap watcher source (e.g. <c>/path!xs:NMTOKENS(.)!xs:decimal(.)</c>),
    /// re-apply the SimpleMap's tail (Right) against each item the watcher
    /// captured during the streaming pass, then run the general comparison
    /// against the other operand. This surfaces type errors (XPTY0004) that
    /// the optimizer/plan would otherwise mask by re-evaluating the streamable
    /// path against the synthetic empty document and short-circuiting to false.
    /// </summary>
    private async ValueTask<(bool Resolved, object? Value)> TryEvaluateGeneralCompWithSimpleMapWatcherAsync(
        BinaryExpression cmp,
        IReadOnlyList<StreamWatcher> watchers)
    {
        StreamWatcher? leftWatcher = null;
        StreamWatcher? rightWatcher = null;
        foreach (var w in watchers)
        {
            if (w.SourceExpression is not SimpleMapExpression) continue;
            if (ReferenceEquals(cmp.Left, w.SourceExpression)) leftWatcher = w;
            if (ReferenceEquals(cmp.Right, w.SourceExpression)) rightWatcher = w;
        }
        if (leftWatcher == null && rightWatcher == null) return (false, null);

        var leftItems = leftWatcher != null
            ? await ApplySimpleMapTailAsync((SimpleMapExpression)leftWatcher.SourceExpression, leftWatcher.GetResult()).ConfigureAwait(false)
            : await EvaluateToListAsync(cmp.Left).ConfigureAwait(false);
        var rightItems = rightWatcher != null
            ? await ApplySimpleMapTailAsync((SimpleMapExpression)rightWatcher.SourceExpression, rightWatcher.GetResult()).ConfigureAwait(false)
            : await EvaluateToListAsync(cmp.Right).ConfigureAwait(false);

        return (true, RunGeneralComparison(cmp.Operator, leftItems, rightItems));
    }

    /// <summary>
    /// Evaluates each per-item tail step of a watched SimpleMap against the
    /// watcher's captured items, in the same left-to-right order that
    /// <c>a!b!c</c> would: apply <c>b</c> to each captured item (flattening),
    /// then apply <c>c</c> to each result, etc.
    /// </summary>
    private async ValueTask<List<object?>> ApplySimpleMapTailAsync(SimpleMapExpression sm, object? sourceItems)
    {
        // Walk down the Left chain to collect tail-step Rights in order.
        // SimpleMap(SimpleMap(path, R1), R2) ⇒ [R1, R2].
        var tailSteps = new List<XQueryExpression>();
        XQueryExpression current = sm;
        while (current is SimpleMapExpression mapNode)
        {
            tailSteps.Add(mapNode.Right);
            current = mapNode.Left;
        }
        tailSteps.Reverse();

        var working = NormalizeToList(sourceItems);
        foreach (var step in tailSteps)
        {
            var next = new List<object?>();
            for (var i = 0; i < working.Count; i++)
            {
                PushContextItem(working[i], i + 1, working.Count);
                try
                {
                    var stepResult = await EvaluateAsync(step).ConfigureAwait(false);
                    AppendFlattened(next, stepResult);
                }
                finally
                {
                    PopContextItem();
                }
            }
            working = next;
        }
        return working;
    }

    /// <summary>
    /// Group A: applies a wrapped-aggregation watcher's stored outer op to its
    /// grounded accumulated sequence. The sequence is fully materialized in memory
    /// (inner head/outermost/remove result + outermost-dedup + remove-skip), so the
    /// outer SimpleMap RIGHT or positional predicates run via the existing per-item
    /// evaluator with correct <c>position()</c>/<c>last()</c>. Returns an
    /// <c>object[]</c> (the grounded result) for <c>value-of</c>/<c>copy-of</c> to emit.
    /// </summary>
    private async ValueTask<object?> ApplyWrappedOuterOpAsync(StreamWatcher watcher)
    {
        var working = new List<object?>();
        foreach (var it in watcher.ProduceAccumulated())
            working.Add(it);

        // SimpleMap RIGHT: apply per item, flattening (mirrors ApplySimpleMapTailAsync).
        if (watcher.OuterSimpleMapRight is { } right)
        {
            var next = new List<object?>();
            for (var i = 0; i < working.Count; i++)
            {
                PushContextItem(working[i], i + 1, working.Count);
                try
                {
                    var stepResult = await EvaluateAsync(right).ConfigureAwait(false);
                    AppendFlattened(next, stepResult);
                }
                finally { PopContextItem(); }
            }
            return next.ToArray();
        }

        // Positional predicates: apply each left-to-right against the grounded
        // sequence, re-counting between predicates so position()/last() are correct.
        foreach (var pred in watcher.OuterPredicates)
        {
            var kept = new List<object?>();
            var count = working.Count;
            for (var i = 0; i < working.Count; i++)
            {
                PushContextItem(working[i], i + 1, count);
                try
                {
                    // A bare numeric literal [N] means position() = N; the generic
                    // EvaluateBooleanAsync would return the literal's effective boolean
                    // (always true for non-zero), so handle it positionally here.
                    bool ok = IsNumericLiteral(pred)
                        ? NumericLiteralEqualsPosition(pred, i + 1)
                        : await EvaluateBooleanAsync(pred).ConfigureAwait(false);
                    if (ok) kept.Add(working[i]);
                }
                finally { PopContextItem(); }
            }
            working = kept;
        }

        return working.ToArray();
    }

    private static bool IsNumericLiteral(XQueryExpression e) =>
        e is IntegerLiteral or DecimalLiteral or DoubleLiteral;

    private static bool NumericLiteralEqualsPosition(XQueryExpression lit, int position) => lit switch
    {
        IntegerLiteral i => i.LongValue is { } l && l == position,
        DecimalLiteral d => d.Value == position,
        DoubleLiteral db => db.Value == position,
        _ => false
    };

    private async ValueTask<List<object?>> EvaluateToListAsync(XQueryExpression expr)
    {
        var v = await EvaluateAsync(expr).ConfigureAwait(false);
        var list = new List<object?>();
        AppendFlattened(list, v);
        return list;
    }

    private static List<object?> NormalizeToList(object? value)
    {
        var list = new List<object?>();
        AppendFlattened(list, value);
        return list;
    }

    private static void AppendFlattened(List<object?> list, object? value)
    {
        switch (value)
        {
            case null:
                return;
            case string:
            case XdmNode:
                list.Add(value);
                return;
            case object?[] arr:
                foreach (var it in arr) AppendFlattened(list, it);
                return;
            // An XDM array is a single item, represented as List<object?>; an XDM map is a
            // single item, represented as IDictionary. Neither flattens — only a CLR
            // object?[] (the engine's sequence representation) does. Without these guards a
            // top-level JSON array/map round-tripped through xsl:sequence was spread into
            // its members (Martin Honnen 2026-06-14).
            case List<object?>:
            case System.Collections.IDictionary:
                list.Add(value);
                return;
            case System.Collections.IEnumerable seq:
                foreach (var it in seq) AppendFlattened(list, it);
                return;
            default:
                list.Add(value);
                return;
        }
    }

    /// <summary>
    /// Materializes the result of <c>EvaluateAsync(select)</c> into the items that an
    /// item-processing instruction iterates over (xsl:for-each, xsl:iterate,
    /// xsl:for-each-group, xsl:perform-sort, xsl:merge for-each-* — and, analogously,
    /// xsl:sequence / xsl:apply-templates which handle this inline).
    /// <para>
    /// An XDM array (<see cref="List{T}"/> of object?) and an XDM map
    /// (<see cref="System.Collections.IDictionary"/>) are SINGLE items and are NOT
    /// flattened into their members/entries; <c>object?[]</c> is the engine's sequence
    /// representation and is flattened (dropping empty/null slots); any other
    /// <c>IEnumerable&lt;object&gt;</c> (e.g. a node sequence) is returned as-is.
    /// </para>
    /// <para>
    /// This is ONLY for item-preserving contexts. Atomizing contexts (xsl:value-of,
    /// xsl:number, string-value) must flatten an array to its members and must not use
    /// this. Reported by Martin Honnen 2026-06 across xsl:sequence / apply-templates /
    /// for-each-group; centralized here so the same flatten-the-array bug can't recur.
    /// </para>
    /// </summary>
    internal static IEnumerable<object> SelectResultItems(object? result) => result switch
    {
        null => [],
        string or XdmNode or List<object?> or System.Collections.IDictionary => [result!],
        object?[] arr => arr.Where(static x => x != null).Cast<object>(),
        IEnumerable<object> seq => seq,
        _ => [result],
    };

    /// <summary>
    /// Runs XPath general comparison between two atomized item lists. Raises
    /// XPTY0004 when atomic types are incompatible (e.g. xs:decimal vs
    /// xs:string with non-numeric content). Empty operand ⇒ false per spec.
    /// </summary>
    private static bool RunGeneralComparison(BinaryOperator op, List<object?> left, List<object?> right)
    {
        if (left.Count == 0 || right.Count == 0) return false;
        foreach (var l in left)
        {
            foreach (var r in right)
            {
                if (CompareAtomic(op, l, r)) return true;
            }
        }
        return false;
    }

    private static bool CompareAtomic(BinaryOperator op, object? left, object? right)
    {
        // Promote untyped strings to numeric if the other side is numeric.
        // Mirrors XPath 3.0 general comparison rules.
        var leftP = left;
        var rightP = right;
        if (leftP is string ls && rightP is not string && IsWatcherNumeric(rightP))
        {
            if (!TryParseWatcherNumber(ls, out leftP))
                throw new PhoenixmlDb.XQuery.Functions.XQueryException("XPTY0004",
                    $"Cannot compare xs:string '{ls}' with numeric type — value is not a valid number");
        }
        else if (rightP is string rs && leftP is not string && IsWatcherNumeric(leftP))
        {
            if (!TryParseWatcherNumber(rs, out rightP))
                throw new PhoenixmlDb.XQuery.Functions.XQueryException("XPTY0004",
                    $"Cannot compare xs:string '{rs}' with numeric type — value is not a valid number");
        }

        // Numeric vs numeric
        if (IsWatcherNumeric(leftP) && IsWatcherNumeric(rightP))
        {
            var ld = ToWatcherDouble(leftP!);
            var rd = ToWatcherDouble(rightP!);
            return op switch
            {
                BinaryOperator.GeneralEqual => ld == rd,
                BinaryOperator.GeneralNotEqual => ld != rd,
                BinaryOperator.GeneralLessThan => ld < rd,
                BinaryOperator.GeneralLessOrEqual => ld <= rd,
                BinaryOperator.GeneralGreaterThan => ld > rd,
                BinaryOperator.GeneralGreaterOrEqual => ld >= rd,
                _ => false
            };
        }

        // String vs string
        if (leftP is string lstr && rightP is string rstr)
        {
            var cmp = string.CompareOrdinal(lstr, rstr);
            return op switch
            {
                BinaryOperator.GeneralEqual => cmp == 0,
                BinaryOperator.GeneralNotEqual => cmp != 0,
                BinaryOperator.GeneralLessThan => cmp < 0,
                BinaryOperator.GeneralLessOrEqual => cmp <= 0,
                BinaryOperator.GeneralGreaterThan => cmp > 0,
                BinaryOperator.GeneralGreaterOrEqual => cmp >= 0,
                _ => false
            };
        }

        // Fallback: equality via Equals
        return op switch
        {
            BinaryOperator.GeneralEqual => Equals(leftP, rightP),
            BinaryOperator.GeneralNotEqual => !Equals(leftP, rightP),
            _ => throw new PhoenixmlDb.XQuery.Functions.XQueryException("XPTY0004",
                $"Cannot compare {leftP?.GetType().Name} with {rightP?.GetType().Name}")
        };
    }

    private static bool IsWatcherNumeric(object? v)
        => v is int or long or double or float or decimal;

    private static double ToWatcherDouble(object v) => v switch
    {
        int i => i,
        long l => l,
        double d => d,
        float f => f,
        decimal dc => (double)dc,
        _ => throw new InvalidOperationException()
    };

    private static bool TryParseWatcherNumber(string s, out object? result)
    {
        if (double.TryParse(s, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out var d))
        {
            result = d;
            return true;
        }
        result = null;
        return false;
    }

    internal Dictionary<QName, GlobalDeclaration>? _pendingGlobals; // Lazy global init: declarations not yet evaluated
    private bool _lastResultWasAtomic; // Track adjacent atomic values for space separation
    private string? _itemSeparatorOverride; // When set, overrides default space separator between sequence items
    private List<QName>? _principalOutputCharacterMaps; // Character maps from xsl:result-document targeting principal output
    private readonly Stack<string?> _baseUriStack = new(); // Effective base URI for node construction
    private string? EffectiveBaseUri => _baseUriStack.Count > 0 ? _baseUriStack.Peek() : XsltTransformEngine.UriString(_stylesheet.BaseUri);

    /// <summary>
    /// Computes the base URI of a source XDM element by checking xml:base attributes
    /// and walking up ancestors. Used by xsl:copy to preserve source base URI.
    /// </summary>
    private string? ComputeSourceBaseUri(Xdm.Nodes.XdmElement elem)
    {
        // Check for xml:base attribute on the element
        string? xmlBase = null;
        foreach (var attrId in elem.Attributes)
        {
            var attr = _nodeStore!.GetNode(attrId) as Xdm.Nodes.XdmAttribute;
            if (attr != null && attr.Namespace == NamespaceId.Xml && attr.LocalName == "base")
            {
                xmlBase = attr.Value;
                break;
            }
        }
        if (xmlBase != null)
        {
            // Resolve against parent's base URI if relative
            if (Uri.TryCreate(xmlBase, UriKind.Absolute, out _))
                return xmlBase;
            var parentBase = GetAncestorBaseUri(elem);
            if (parentBase != null && Uri.TryCreate(parentBase, UriKind.Absolute, out var parentUri)
                && Uri.TryCreate(parentUri, xmlBase, out var resolved))
                return resolved.OriginalString;
            return xmlBase;
        }
        // Fall back to entity-derived base URI
        if (elem.BaseUri != null)
            return elem.BaseUri;
        // Inherit from parent
        return GetAncestorBaseUri(elem);
    }

    private string? GetAncestorBaseUri(Xdm.Nodes.XdmNode node)
    {
        if (!node.Parent.HasValue || node.Parent.Value == NodeId.None || _nodeStore == null)
            return null;
        var parent = _nodeStore.GetNode(node.Parent.Value);
        if (parent is Xdm.Nodes.XdmElement parentElem)
            return ComputeSourceBaseUri(parentElem);
        if (parent is Xdm.Nodes.XdmDocument doc)
            return doc.BaseUri;
        return parent?.BaseUri;
    }

    private readonly Stack<string?> _staticBaseUriStack = new(); // Static base URI for static-base-uri() function
    internal string? StaticBaseUri => _staticBaseUriStack.Count > 0 ? _staticBaseUriStack.Peek() : XsltTransformEngine.UriString(_stylesheet.BaseUri);

    /// <summary>
    /// The source location of the XSLT instruction or XPath expression currently being
    /// evaluated, or <c>null</c> when no executor has installed one. Pushed via
    /// <see cref="PushInstructionLocation"/>; consumed by <see cref="Error(string)"/>
    /// to auto-attach module/line/column to <see cref="XsltException"/>.
    /// </summary>
    /// <remarks>
    /// Phase A of the source-location audit: storage and helpers exist; Phase B
    /// wires push/pop into individual executors. Existing set-and-forget writes to
    /// <c>_currentInstructionLocation</c> (e.g. <c>CreateAttributeAsync</c> for
    /// XTDE0410/0420) remain valid — Phase B replaces them with scoped pushes.
    /// </remarks>
    internal SourceLocation? CurrentInstructionLocation => _currentInstructionLocation;

    private readonly Stack<SourceLocation?> _locationStack = new();

    /// <inheritdoc/>
    public override void PushInstructionLocation(SourceLocation location)
    {
        _locationStack.Push(_currentInstructionLocation);
        _currentInstructionLocation = location;
    }

    /// <inheritdoc/>
    public override void PopInstructionLocation()
    {
        _currentInstructionLocation = _locationStack.Count > 0 ? _locationStack.Pop() : null;
    }

    /// <summary>
    /// Constructs an <see cref="XsltException"/> tagged with <see cref="CurrentInstructionLocation"/>.
    /// Use as <c>throw context.Error("XTTE0570: ...");</c> to auto-attach location info.
    /// </summary>
    internal XsltException Error(string message)
        => new(message, _currentInstructionLocation);

    /// <summary>
    /// Same as <see cref="Error(string)"/> but wraps an inner exception.
    /// </summary>
    internal XsltException Error(string message, Exception innerException)
        => new(message, _currentInstructionLocation, innerException);
    private bool _simpleContentLastWasNode; // Track node→text transitions for space insertion in simple content
    private StringBuilder? _collectedAttributes => _collectedAttributesStack.Count > 0 ? _collectedAttributesStack.Peek() : null;
    private bool _attributeCollecting => _collectedAttributesStack.Count > 0;

    // Map/array construction stacks
    private readonly Stack<IDictionary<object, object?>> _mapBuildStack = new();
    private readonly Stack<List<object?>> _arrayBuildStack = new();

    // Track current template for next-match/apply-imports
    private XsltTemplate? _currentTemplate;
    private QName? _currentMode;

    public override QName? CurrentMode => _currentMode;

    public override bool IsBackwardsCompatibleMode => IsBackwardsCompatible;

    public override void PushVersion(string version) => _effectiveVersionStack.Push(version);
    public override void PopVersion() => _effectiveVersionStack.Pop();
    public override void PushCollation(string collation) => _defaultCollationStack.Push(collation);
    public override void PopCollation() => _defaultCollationStack.Pop();
    public override void PushStaticBaseUri(string baseUri) => _staticBaseUriStack.Push(baseUri);
    public override void PopStaticBaseUri() => _staticBaseUriStack.Pop();
    public override string? DefaultCollation =>
        _defaultCollationStack.Count > 0 ? _defaultCollationStack.Peek() : _stylesheet.DefaultCollation;

    // Recursion depth guard
    private int _recursionDepth;
    private const int MaxRecursionDepth = 1200;

    /// <summary>
    /// Stack tracking the current xsl:function being executed, for xsl:original resolution.
    /// When a function overrides a package component, its OriginalFunction chain is used
    /// to resolve calls to xsl:original.
    /// </summary>
    internal readonly Stack<XsltFunction> _currentXsltFunctionStack = new();

    /// <summary>
    /// Stack tracking the current named template being executed, for xsl:original resolution.
    /// </summary>
    internal readonly Stack<XsltTemplate> _currentTemplateStack = new();

    // Per XSLT 3.0 §10.3: cache="yes" memoization for stylesheet functions
    // Key: (function QName key string, serialized argument list)
    private readonly Dictionary<string, object?> _functionCache = new(StringComparer.Ordinal);

    /// <summary>
    /// Appends a type-aware cache key representation for a function argument.
    /// Different types need different key strategies to preserve identity/equality semantics.
    /// </summary>
    private static void AppendCacheKey(System.Text.StringBuilder sb, object? arg)
    {
        switch (arg)
        {
            case null:
                sb.Append("()");
                break;
            case QName qn:
                // Use resolved namespace URI — QNames from node-name() have RuntimeNamespace,
                // not ExpandedNamespace, so ToString() only shows prefix:local
                sb.Append("Q{").Append(qn.ResolvedNamespace ?? "").Append('}').Append(qn.LocalName);
                break;
            case XdmNode node:
                // Node identity: use runtime hash code (reference identity)
                sb.Append("node@").Append(System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode(node));
                break;
            case IDictionary<object, object?> map:
                // Map deep content: serialize entries deterministically
                sb.Append("map{");
                var first = true;
                foreach (var kvp in map.OrderBy(k => k.Key?.ToString() ?? "", StringComparer.Ordinal))
                {
                    if (!first) sb.Append(',');
                    first = false;
                    AppendCacheKey(sb, kvp.Key);
                    sb.Append(':');
                    AppendCacheKey(sb, kvp.Value);
                }
                sb.Append('}');
                break;
            case List<object?> array:
                // Array deep content
                sb.Append('[');
                for (var i = 0; i < array.Count; i++)
                {
                    if (i > 0) sb.Append(',');
                    AppendCacheKey(sb, array[i]);
                }
                sb.Append(']');
                break;
            case PhoenixmlDb.XQuery.Ast.XQueryFunction func:
                // Function identity: use runtime hash code
                sb.Append("fn@").Append(System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode(func));
                break;
            default:
                sb.Append(arg.ToString());
                break;
        }
    }

    // Cooperative cancellation and output size guard
    private readonly CancellationToken _ct;
    private readonly int _maxOutputSize;

    /// <summary>
    /// Checks cancellation token and output size limit. Called at loop boundaries
    /// (apply-templates per-node, for-each per-item, iterate per-item) and template entry
    /// to ensure runaway transformations are terminated promptly.
    /// </summary>
    private void CheckResourceLimits()
    {
        _ct.ThrowIfCancellationRequested();
        if (_maxOutputSize > 0 && _output.Length > _maxOutputSize)
            throw Error(
                $"XTRE0000: Output size limit exceeded ({_output.Length:N0} characters > {_maxOutputSize:N0} limit). " +
                "The transformation may contain an infinite loop or produce excessively large output.");

        // Guard the native stack. Deep user recursion (recursive stylesheet functions,
        // nested apply-templates) expands into ~15 .NET async frames per logical call,
        // so the physical stack can overflow — an uncatchable StackOverflowException that
        // aborts the whole process with SIGABRT — long before _recursionDepth reaches
        // MaxRecursionDepth. Probe the remaining stack and convert exhaustion into a
        // catchable engine error, mirroring the XQuery engine's
        // QueryExecutionContext.EnterFunctionCall guard.
        try
        {
            System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack();
        }
        catch (InsufficientExecutionStackException ex)
        {
            throw Error(
                "XTDE0000: The transformation exhausted the execution stack before reaching " +
                $"the recursion-depth limit ({MaxRecursionDepth}). It may contain unbounded " +
                "recursion; if the recursion is intentional, run the host on a thread with a larger stack.",
                ex);
        }
    }

    // Namespace scope tracking for deduplication during serialization
    private readonly Stack<Dictionary<string, string>> _outputNsScopes = new();

    // Sequence accumulator: when active, xsl:sequence items are collected into this list
    // instead of being serialized to the output. Used for variable/param bodies with as="type *".
    private List<object?>? _sequenceAccumulator;

    // When true, WriteText redirects text to _sequenceAccumulator as individual items
    // instead of appending to _output. Used by xsl:perform-sort content to collect
    // individual text items for sorting rather than concatenating them.
    internal bool _collectTextAsSequenceItems;
    internal int _serializingElementDepth; // >0 when inside element serialization
    private bool _forceDefaultNsUndeclaration; // inherit-namespaces="no" requires children to emit xmlns=""

    // Base-URI preservation across the temp-tree serialize→reparse boundary.
    //
    // Temp trees (xsl:document, as=document-node()/element() variable bodies) serialize
    // child output to TEXT in _output, then reparse it. Plain XML text carries no
    // per-node base URI, so a SOURCE element copied into the temp tree loses its base URI
    // and base-uri() later returns empty. To bridge the gap, the temp-tree serializer
    // EMITS a sentinel attribute (_pxbase_:base) carrying the source base URI on the root
    // of each copied subtree whose base differs from the enclosing serialization context;
    // the reparse RECOVERS it onto XdmNode.CopySourceBaseUri and DROPS the attribute so it
    // never becomes a real attribute or reaches user-visible output.
    //
    // _tempTreeSerializeDepth gates EMIT: it is >0 ONLY while serializing into a buffer
    // that will be reparsed (temp-tree boundaries). The final-output serializer never
    // raises it, so the sentinel is structurally impossible to leak into the result.
    // _serializeBaseContext tracks the base URI currently in effect during serialization
    // so the sentinel is emitted only on subtree roots where the base actually changes
    // (descendants inherit and stay silent).
    private int _tempTreeSerializeDepth; // >0 while serializing content destined for reparse
    private string? _serializeBaseContext; // base URI currently in effect during temp-tree serialization

    // Element name stack for CDATA section serialization
    private readonly Stack<QName> _outputElementStack = new();
    // Track whether the current output element has a namespace (for XTDE0440)
    private readonly Stack<bool> _outputElementHasNsStack = new();
    // Track whether the current element is a literal result element (for XTDE0430 scope)
    private readonly Stack<bool> _outputElementIsLreStack = new();
    // Track namespace bindings from xsl:namespace instructions per element (for XTDE0430)
    private readonly Stack<Dictionary<string, string>> _xslNamespaceBindings = new();

    /// <summary>
    /// Begins sequence collection mode. xsl:sequence items will be collected into a list
    /// instead of being serialized to output.
    /// </summary>
    public void BeginSequenceCollection()
    {
        _sequenceAccumulator = new List<object?>();
    }

    /// <summary>
    /// Ends sequence collection mode and returns the collected items.
    /// </summary>
    public List<object?> EndSequenceCollection()
    {
        var result = _sequenceAccumulator ?? new List<object?>();
        _sequenceAccumulator = null;
        return result;
    }

    // Tracks whether "real" content has been added during xsl:where-populated execution.
    // This is a stack because where-populated can be nested.
    // When active (count > 0), content-producing operations should call MarkContentProduced().
    private readonly Stack<bool> _populatedTracking = new();

    // Effective XSLT version stack — tracks xsl:version overrides on literal result elements.
    // When empty, the stylesheet's version is used. Top of stack is current effective version.
    private readonly Stack<string> _effectiveVersionStack = new();

    // Default collation stack — tracks default-collation overrides on XSLT elements.
    // When empty, the stylesheet's default collation (or codepoint) is used.
    private readonly Stack<string> _defaultCollationStack = new();

    // XSLT 3.0 accumulator state: maps (accumulator name, node ID) → (before-value, after-value)
    internal Dictionary<QName, Dictionary<NodeId, (object? before, object? after)>>? _accumulatorValues;
    private HashSet<(QName, NodeId)>? _evaluatingAccEndPhase; // Cycle detection for accumulator-after
    private HashSet<NodeId>? _accumulatorComputedDocuments; // Documents that have had accumulators pre-computed

    // XTDE1490: Track result-document output URIs to detect duplicates.
    private readonly HashSet<string> _resultDocumentUris = new(StringComparer.OrdinalIgnoreCase);
    // Secondary result documents: href → serialized content
    private readonly Dictionary<string, string> _secondaryResultDocuments = new(StringComparer.OrdinalIgnoreCase);
    // Maximum secondary result documents allowed (0 = unlimited). Security limit.
    internal int MaxResultDocuments { get; init; } = 1000;
    // XTDE1480: Track whether we're in temporary output state (variable/param body)
    private int _temporaryOutputDepth;
    // Track nesting depth of secondary result-document redirects
    private int _resultDocumentRedirectDepth;
    // XTDE1490: Set when an explicit xsl:result-document href="" has claimed the primary output
    private bool _primaryOutputClaimedByResultDocument;
    private XsltOutput? _primaryOutputMatchedDeclaration;
    // Pending primary output from nested xsl:result-document href="" inside a secondary redirect
    private string? _pendingPrimaryContent;
    // Active output declaration for current result-document (used for cdata-section-elements)
    private XsltOutput? _activeResultDocumentOutput;
    // Track when inside function body so xsl:value-of routes to sequence accumulator
    private int _functionBodyDepth;
    // Track when inside xsl:where-populated so XTDE0410 is suppressed during trial evaluation
    private int _wherePopulatedDepth;
    // Count of characters written to _output as atomic value separators (spaces between
    // adjacent atomic values in xsl:sequence). Used by content tracking to distinguish
    // separator-only growth from significant content growth.
    private int _separatorCharsWritten;
    // When > 0, text nodes should not break atomic value adjacency chain.
    // Used in Phase 2 of on-non-empty (when !wasPopulated) so that non-conditional
    // instructions producing empty text don't disrupt separator spacing for on-empty content.
    private int _preserveAtomicState;
    // Principal source document ID for accumulator applicability checks (§18.2.2)
    private DocumentId? _principalSourceDocId;

    /// <summary>Secondary result documents produced by xsl:result-document with non-empty href.</summary>
    internal IReadOnlyDictionary<string, string> SecondaryResults => _secondaryResultDocuments;
    internal XsltOutput? PrimaryOutputMatchedDeclaration => _primaryOutputMatchedDeclaration;

    /// <summary>Character maps from xsl:result-document targeting principal output (persists for serialization).</summary>
    internal List<QName>? PrincipalOutputCharacterMaps => _principalOutputCharacterMaps;

    /// <summary>
    /// Checks if a namespace binding (prefix → uri) is already in scope from an ancestor element.
    /// </summary>
    private bool IsNamespaceInScope(string prefix, string uri)
    {
        foreach (var scope in _outputNsScopes)
        {
            if (scope.TryGetValue(prefix, out var scopedUri))
                return scopedUri == uri;
        }
        return false;
    }

    /// <summary>
    /// Builds xmlns:prefix="uri" declarations for all in-scope namespaces, for use as
    /// attributes on a synthetic wrapper element when re-parsing serialized template/function output.
    /// </summary>
    private string BuildInScopeNamespaceDeclarations()
    {
        var sb = new StringBuilder();
        var seen = new HashSet<string>();
        foreach (var scope in _outputNsScopes)
        {
            foreach (var (prefix, uri) in scope)
            {
                if (string.IsNullOrEmpty(uri) || !seen.Add(prefix))
                    continue;
                if (prefix.Length > 0)
                {
                    sb.Append(" xmlns:");
                    sb.Append(prefix);
                    sb.Append("=\"");
                    sb.Append(EscapeAttributeValue(uri));
                    sb.Append('"');
                }
                else
                {
                    sb.Append(" xmlns=\"");
                    sb.Append(EscapeAttributeValue(uri));
                    sb.Append('"');
                }
            }
        }
        return sb.ToString();
    }

    /// <summary>
    /// Appends an item to <c>_sequenceAccumulator</c> while also recording the current
    /// <c>_output</c> offset into <see cref="AsBodyCapture.Positions"/> when an `as=` body
    /// capture is in progress. The parallel position list is what
    /// <see cref="AssembleAsBodyResultItems"/> uses to weave accumulator items back into
    /// document order at result assembly time.
    /// </summary>
    private void AppendToSeqAccumulator(object? item)
    {
        // Record the `_output` offset only when the item is going into the current
        // `as=` body's accumulator — not into some inner accumulator (e.g. an
        // xsl:variable's typed-sequence buffer) that just happens to be active.
        if (_currentAsBodyCapture is { } capture && ReferenceEquals(_sequenceAccumulator, capture.Accumulator))
            capture.Positions.Add(_output.Length - capture.OutputBaseLen);
        _sequenceAccumulator!.Add(item);
    }

    /// <summary>
    /// Reassembles the result items of an `as=`-typed template/function body in document order.
    /// </summary>
    /// <remarks>
    /// During body execution, two output channels run in parallel: <c>_output</c> captures
    /// LRE/text serialization, while <c>_sequenceAccumulator</c> captures distinct XDM items
    /// (xsl:attribute → XdmAttribute, xsl:sequence → arbitrary items, xsl:document → XdmDocument).
    /// <paramref name="accumulatorPositions"/> records, for each accumulator entry, the
    /// <c>_output</c> offset (relative to body start) at the moment the entry was added.
    /// We walk those offsets in order, parsing the <paramref name="bodyOutput"/> chunk preceding
    /// each one, then emitting the corresponding accumulator item at its recorded position.
    /// This restores creation order so a subsequent element constructor sees attributes
    /// before non-attribute children, avoiding spurious XTDE0410. Reported by Martin Honnen
    /// against Schxslt2 1.10.3 transpile.xsl.
    /// </remarks>
    private List<object?> AssembleAsBodyResultItems(string bodyOutput, List<object?> accumulatorItems, List<int> accumulatorPositions)
    {
        var result = new List<object?>();
        var cursor = 0;

        for (var i = 0; i < accumulatorItems.Count; i++)
        {
            var item = accumulatorItems[i];
            if (item == null)
                continue;
            var position = i < accumulatorPositions.Count ? accumulatorPositions[i] : bodyOutput.Length;
            if (position > bodyOutput.Length)
                position = bodyOutput.Length;
            if (position > cursor)
            {
                AddBodyOutputChunk(bodyOutput.Substring(cursor, position - cursor), result);
                cursor = position;
            }
            result.Add(item);
        }

        if (cursor < bodyOutput.Length)
            AddBodyOutputChunk(bodyOutput[cursor..], result);

        return result;
    }

    /// <summary>
    /// Parses a chunk of serialized body output into top-level XDM nodes (or a raw string
    /// when parsing fails) and appends them to <paramref name="result"/>.
    /// </summary>
    private void AddBodyOutputChunk(string chunk, List<object?> result)
    {
        if (string.IsNullOrEmpty(chunk))
            return;

        if (_nodeStore != null && chunk.Contains('<', StringComparison.Ordinal))
        {
            try
            {
                // Stream the chunk through XmlReader instead of allocating an XmlDocument
                // and walking its DOM. The previous path allocated O(N) XmlNode objects per
                // call where N = nodes in the chunk; for an `xsl:variable as="element(…)"`
                // body inside a deep for-each (Schxslt2 / Dataverse-shape transforms), that
                // adds up to many thousands of XmlDocuments built and discarded per second.
                // Direct reader → XDM eliminates the DOM intermediary entirely.
                var nsDecls = BuildInScopeNamespaceDeclarations();
                var wrapped = $"<_tmpl_wrap_{nsDecls}>{chunk}</_tmpl_wrap_>";
                var settings = new System.Xml.XmlReaderSettings
                {
                    DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                    IgnoreWhitespace = false,
                    IgnoreComments = false,
                    IgnoreProcessingInstructions = false,
                };
                using var stringReader = new System.IO.StringReader(wrapped);
                using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                ReadAsBodyChunkChildren(reader, result);
                return;
            }
            catch (System.Xml.XmlException)
            {
                // Fall through to add as raw string
            }
        }

        result.Add(chunk);
    }

    /// <summary>
    /// Streams the children of the synthetic <c>_tmpl_wrap_</c> wrapper out of the
    /// supplied <see cref="System.Xml.XmlReader"/> and into <paramref name="result"/>
    /// as live XDM nodes registered in <c>_nodeStore</c>. Mirrors what
    /// <c>ConvertToXdm</c> does, but driven by reader events rather than a built DOM —
    /// avoids the per-call XmlDocument allocation that dominates wall time on workloads
    /// with many small <c>as=</c>-typed bodies.
    /// </summary>
    internal void ReadAsBodyChunkChildren(System.Xml.XmlReader reader, List<object?> result)
    {
        // Walk to the wrapper start tag, then descend one level so we read its children.
        if (!reader.Read())
            return;
        while (reader.NodeType != System.Xml.XmlNodeType.Element)
        {
            if (!reader.Read()) return;
        }
        // Reader is now at the start of `<_tmpl_wrap_>`. Step inside.
        if (reader.IsEmptyElement)
            return;
        reader.Read();

        // Read top-level children until the matching end tag.
        while (reader.NodeType != System.Xml.XmlNodeType.EndElement)
        {
            var node = ReadXdmNodeFromReader(reader, NodeId.None, new DocumentId(1));
            if (node != null)
                result.Add(node);
            else if (!reader.Read())
                break;
        }
    }

    /// <summary>
    /// Reads a single XDM-relevant node (element subtree, text, comment, PI) out of
    /// <paramref name="reader"/> and returns it. Returns <c>null</c> for irrelevant
    /// node types (whitespace at the wrapper level, XML declarations, etc.) and
    /// advances the reader past them so the caller can continue.
    /// </summary>
    private XdmNode? ReadXdmNodeFromReader(System.Xml.XmlReader reader, NodeId parentId, DocumentId docId)
    {
        switch (reader.NodeType)
        {
            case System.Xml.XmlNodeType.Element:
                return ReadXdmElementFromReader(reader, parentId, docId);

            case System.Xml.XmlNodeType.Text:
            case System.Xml.XmlNodeType.CDATA:
            case System.Xml.XmlNodeType.Whitespace:
            case System.Xml.XmlNodeType.SignificantWhitespace:
            {
                var textId = _nodeStore!.NextId();
                var value = reader.Value;
                var text = new XdmText
                {
                    Id = textId,
                    Document = docId,
                    Parent = parentId,
                    Value = value,
                };
                _nodeStore.Register(text);
                reader.Read();
                return text;
            }

            case System.Xml.XmlNodeType.Comment:
            {
                var commentId = _nodeStore!.NextId();
                var value = reader.Value;
                var comment = new XdmComment
                {
                    Id = commentId,
                    Document = docId,
                    Parent = parentId,
                    Value = value,
                };
                _nodeStore.Register(comment);
                reader.Read();
                return comment;
            }

            case System.Xml.XmlNodeType.ProcessingInstruction:
            {
                var piId = _nodeStore!.NextId();
                var pi = new XdmProcessingInstruction
                {
                    Id = piId,
                    Document = docId,
                    Parent = parentId,
                    Target = reader.Name,
                    Value = reader.Value,
                };
                _nodeStore.Register(pi);
                reader.Read();
                return pi;
            }

            default:
                // XmlDeclaration, DocumentType, EntityReference, etc. — skip
                reader.Read();
                return null;
        }
    }

    /// <summary>
    /// Reads an element subtree (start tag, attributes, namespaces, recursive children,
    /// end tag) out of <paramref name="reader"/> and returns it as a registered
    /// <see cref="XdmElement"/>. The reader is positioned past the matching end tag on
    /// return.
    /// </summary>
    private XdmElement ReadXdmElementFromReader(System.Xml.XmlReader reader, NodeId parentId, DocumentId docId)
    {
        var elemId = _nodeStore!.NextId();
        var localName = reader.LocalName;
        var prefix = reader.Prefix;
        var nsUri = reader.NamespaceURI;
        var elemNsId = _nodeStore.InternNamespace(nsUri ?? "");
        var isEmpty = reader.IsEmptyElement;

        // Walk attributes, splitting xmlns declarations from real attributes.
        var nsDecls = new List<NamespaceBinding>();
        var attrIds = new List<NodeId>();
        // RECOVER (temp-tree base-URI preservation): the sentinel attribute round-trips a
        // source element's base URI through the text serialize→reparse boundary. Capture it
        // here, stamp it onto CopySourceBaseUri below, and DROP both the attribute and its
        // namespace declaration so it never becomes a real XDM node or reaches output.
        string? recoveredBaseUri = null;
        if (reader.HasAttributes)
        {
            for (var i = 0; i < reader.AttributeCount; i++)
            {
                reader.MoveToAttribute(i);
                if (reader.Prefix == "xmlns")
                {
                    if (string.Equals(reader.Value, XsltTransformEngine.BaseSentinelNs, StringComparison.Ordinal))
                        continue; // drop the sentinel namespace declaration
                    nsDecls.Add(new NamespaceBinding(reader.LocalName, _nodeStore.InternNamespace(reader.Value)));
                }
                else if (string.IsNullOrEmpty(reader.Prefix) && reader.LocalName == "xmlns")
                {
                    nsDecls.Add(new NamespaceBinding("", _nodeStore.InternNamespace(reader.Value)));
                }
                else if (string.Equals(reader.NamespaceURI, XsltTransformEngine.BaseSentinelNs, StringComparison.Ordinal)
                    && reader.LocalName == XsltTransformEngine.BaseSentinelLocalName)
                {
                    recoveredBaseUri = reader.Value; // drop the sentinel attribute
                }
                else
                {
                    var attrId = _nodeStore.NextId();
                    var xdmAttr = new XdmAttribute
                    {
                        Id = attrId,
                        Document = docId,
                        Parent = elemId,
                        Namespace = _nodeStore.InternNamespace(reader.NamespaceURI ?? ""),
                        LocalName = reader.LocalName,
                        Prefix = string.IsNullOrEmpty(reader.Prefix) ? null : reader.Prefix,
                        Value = reader.Value,
                    };
                    _nodeStore.Register(xdmAttr);
                    attrIds.Add(attrId);
                }
            }
            reader.MoveToElement();
        }

        var childIds = new List<NodeId>();
        if (!isEmpty)
        {
            reader.Read(); // step inside the element
            while (reader.NodeType != System.Xml.XmlNodeType.EndElement)
            {
                var child = ReadXdmNodeFromReader(reader, elemId, docId);
                if (child != null)
                    childIds.Add(child.Id);
                else if (reader.NodeType != System.Xml.XmlNodeType.EndElement && !reader.Read())
                    break;
            }
        }
        reader.Read(); // consume the end tag (or the self-closing element itself)

        var elem = new XdmElement
        {
            Id = elemId,
            Document = docId,
            Parent = parentId,
            Namespace = elemNsId,
            LocalName = localName,
            Prefix = string.IsNullOrEmpty(prefix) ? null : prefix,
            Attributes = attrIds,
            Children = childIds,
            NamespaceDeclarations = nsDecls.Count > 0 ? nsDecls.ToArray() : XdmElement.EmptyNamespaceDeclarations,
            CopySourceBaseUri = recoveredBaseUri,
        };
        // Precompute _stringValue bottom-up from child text and (already-finalized)
        // child element string values. Mirrors StreamingSubtreeMaterializer.FinalizeFrame
        // and XmlDocumentParser. Without this, value-of select="." on a variable-
        // constructed element (XdmElement.StringValue is non-lazy) returns "".
        if (childIds.Count > 0)
        {
            var sb = new System.Text.StringBuilder();
            foreach (var childId in childIds)
            {
                var child = _nodeStore.GetNode(childId);
                switch (child)
                {
                    case XdmText t: sb.Append(t.Value); break;
                    case XdmElement ce: sb.Append(ce.StringValue); break;
                    // Comments and PIs contribute nothing to element string value.
                }
            }
            elem._stringValue = sb.ToString();
        }
        else
        {
            elem._stringValue = string.Empty;
        }
        _nodeStore.Register(elem);
        return elem;
    }

    /// <summary>
    /// Generates a unique namespace prefix by appending _0, _1, etc. to the base prefix.
    /// Used during namespace fixup when xsl:namespace conflicts with an element's own prefix.
    /// </summary>
    private string GenerateUniquePrefix(string basePrefix)
    {
        var counter = 0;
        string candidate;
        do
        {
            candidate = $"{basePrefix}_{counter}";
            counter++;
        } while (IsPrefixInUse(candidate));
        return candidate;
    }

    /// <summary>
    /// Checks if a prefix is already bound in any output namespace scope.
    /// </summary>
    private bool IsPrefixInUse(string prefix)
    {
        foreach (var scope in _outputNsScopes)
        {
            if (scope.ContainsKey(prefix))
                return true;
        }
        return false;
    }

    /// <summary>
    /// Gets the in-scope default namespace URI (for prefix ""), or null if none is in scope.
    /// </summary>
    private string? GetInScopeDefaultNamespace()
    {
        foreach (var scope in _outputNsScopes)
        {
            if (scope.TryGetValue("", out var uri))
            {
                // Empty string means xmlns="" (undeclaration) — return null to indicate no default ns
                return string.IsNullOrEmpty(uri) ? null : uri;
            }
        }
        return null;
    }

    private void PushOutputNsScope(Dictionary<string, string> nsBindings)
    {
        _outputNsScopes.Push(nsBindings);
    }

    private void PopOutputNsScope()
    {
        if (_outputNsScopes.Count > 0)
            _outputNsScopes.Pop();
    }

    /// <summary>
    /// Begins tracking for xsl:where-populated. Call before executing content.
    /// </summary>
    private void BeginPopulatedTracking()
    {
        _populatedTracking.Push(false);
    }

    /// <summary>
    /// Ends tracking for xsl:where-populated. Returns true if content was produced.
    /// </summary>
    private bool EndPopulatedTracking()
    {
        return _populatedTracking.Count > 0 && _populatedTracking.Pop();
    }

    /// <summary>
    /// Call this when "real" content is produced (elements, non-whitespace text, etc.)
    /// This marks the current where-populated scope as having content.
    /// </summary>
    private void MarkContentProduced()
    {
        if (_populatedTracking.Count > 0)
        {
            // Pop the current value and push true
            _populatedTracking.Pop();
            _populatedTracking.Push(true);
        }
    }

    // Snapshot-based content tracking for xsl:on-empty/xsl:on-non-empty.
    // Unlike where-populated tracking (which only counts significant child content),
    // on-empty tracking counts ALL output including attributes and whitespace text.
    private readonly Stack<(int outputLen, int attrsLen, int accumLen, bool lastAtomic)> _contentTrackingStack = new();

    /// <summary>Begin content tracking for xsl:on-empty/xsl:on-non-empty support.</summary>
    public override void BeginContentTracking()
    {
        var outputLen = _output.Length;
        var attrsLen = _collectedAttributesStack.Count > 0 ? _collectedAttributesStack.Peek().Length : 0;
        var accumLen = _sequenceAccumulator?.Count ?? 0;
        _contentTrackingStack.Push((outputLen, attrsLen, accumLen, _lastResultWasAtomic));
        // Reset atomic state so content within this tracking scope starts fresh.
        // This prevents atomic state from a previous scope (e.g., on-empty output
        // in one for-each iteration) from leaking into the next scope and causing
        // spurious space separators before empty-string atomic values.
        _lastResultWasAtomic = false;
        _separatorCharsWritten = 0;
    }

    /// <summary>End content tracking and return whether content was produced.</summary>
    public override bool EndContentTracking()
    {
        if (_contentTrackingStack.Count == 0)
            return false;
        var (outputLen, attrsLen, accumLen, savedLastAtomic) = _contentTrackingStack.Pop();
        var outputGrew = _output.Length > outputLen;
        // If output grew, check if it was only separator spaces between zero-length strings.
        // Zero-length strings are insignificant per XSLT 3.0 §11.4, and their separators
        // should not make content appear non-empty.
        var significantOutput = outputGrew && (_output.Length - outputLen) > _separatorCharsWritten;
        var wasPopulated = significantOutput
            || (_collectedAttributesStack.Count > 0 && _collectedAttributesStack.Peek().Length > attrsLen)
            || (_sequenceAccumulator != null && _sequenceAccumulator.Count > accumLen);
        // When no content was produced, restore atomic spacing state to what it was
        // before the tracking scope. This undoes any side effects from non-on-empty
        // instructions (e.g., serializing an empty string sets the flag but produces
        // no output) while preserving state from before the scope for correct
        // cross-iteration spacing in for-each.
        if (!wasPopulated)
            _lastResultWasAtomic = savedLastAtomic;
        return wasPopulated;
    }

    /// <summary>Save current output state for on-non-empty probe phase.</summary>
    public override object SaveOutput()
    {
        var outputStr = _output.ToString();
        var attrsStr = _collectedAttributesStack.Count > 0 ? _collectedAttributesStack.Peek().ToString() : null;
        return (outputStr, attrsStr, _lastResultWasAtomic);
    }

    /// <summary>Restore output to a previously saved state.</summary>
    public override void RestoreOutput(object savedState)
    {
        var (outputStr, attrsStr, lastAtomic) = ((string, string?, bool))savedState;
        _output.Clear();
        _output.Append(outputStr);
        _lastResultWasAtomic = lastAtomic;
        if (attrsStr != null && _collectedAttributesStack.Count > 0)
        {
            _collectedAttributesStack.Peek().Clear();
            _collectedAttributesStack.Peek().Append(attrsStr);
        }
    }

    public override void SuppressEmptyStringSeparators()
    {
        _wherePopulatedDepth++;
        _preserveAtomicState++;
    }

    public override void RestoreEmptyStringSeparators()
    {
        _wherePopulatedDepth--;
        _preserveAtomicState--;
    }

    /// <summary>
    /// Returns true if we're currently inside a where-populated tracking scope.
    /// </summary>
    private bool IsTrackingPopulated => _populatedTracking.Count > 0;

    /// <summary>
    /// Gets the current effective XSLT version (from xsl:version on LRE or stylesheet version).
    /// </summary>
    private string EffectiveVersion =>
        _effectiveVersionStack.Count > 0 ? _effectiveVersionStack.Peek() : _stylesheet.Version;

    /// <summary>
    /// Returns true if backwards-compatible mode is active (effective version is numerically less than 2.0).
    /// Per XSLT spec, the version attribute is interpreted as a number — values like " 001 ", "+0.5", "-29"
    /// are valid and determine backwards-compatible mode by numeric comparison.
    /// </summary>
    private bool IsBackwardsCompatible =>
        ParseVersionNumber(EffectiveVersion) < 2.0m;

    private static decimal ParseVersionNumber(string version)
    {
        if (decimal.TryParse(version.Trim(), System.Globalization.NumberStyles.AllowLeadingSign | System.Globalization.NumberStyles.AllowDecimalPoint | System.Globalization.NumberStyles.AllowLeadingWhite | System.Globalization.NumberStyles.AllowTrailingWhite, System.Globalization.CultureInfo.InvariantCulture, out var result))
            return result;
        // Non-numeric version strings default to 2.0 (no backwards compat) per spec
        return 2.0m;
    }

    public DefaultXsltExecutionContext(
        XsltStylesheet stylesheet,
        TemplateIndex templateIndex,
        XdmNode source,
        StringBuilder output,
        XsltTransformOptions options,
        XdmInMemoryStore? nodeStore = null,
        PhoenixmlDb.XQuery.ISchemaProvider? schemaProvider = null)
    {
        _stylesheet = stylesheet;
        _templateIndex = templateIndex;
        _output = output;
        _options = options;
        _nodeStore = nodeStore;
        _schemaProvider = schemaProvider;
        _ct = options.CancellationToken;
        _maxOutputSize = options.MaxOutputSize;
        _documentResolver = new XsltDocumentResolver(stylesheet, nodeStore)
        {
            PreloadedResources = options.PreloadedResources
        };
        if (options.Collections != null)
            _documentResolver.SetCollections(options.Collections);
        if (options.ResourcePolicy != null)
            _policyResolver = new PhoenixmlDb.XQuery.Security.PolicyEnforcingResolver(_documentResolver, options.ResourcePolicy);
        // Seed the resolver cache with the source document for identity preservation
        if (source is XdmDocument sourceDoc)
        {
            _documentResolver.SeedSourceDocument(sourceDoc);
            // Only track principal source doc ID when there IS a real source document.
            // When HasSourceDocument is false, the source is a synthetic <empty/> placeholder
            // and should not trigger XTDE3362 accumulator applicability checks.
            if (options.HasSourceDocument)
                _principalSourceDocId = sourceDoc.Document;
        }

        // Build function library: standard XPath/XQuery functions + XSLT user-defined functions
        _functionLibrary = BuildFunctionLibrary(stylesheet);

        _scopes.Push(new Scope());
        _contextItems.Push(source);
        _contextPositions.Push((1, 1));
    }

    /// <summary>
    /// Drains <c>_output</c> to <see cref="_streamingOutputSink"/> and resets its
    /// length to zero. Caller is responsible for invoking this only at points where
    /// no <see cref="XsltTransformEngine.ScopedOutputBuffer"/> is open — typically at
    /// the top of each <see cref="StreamingXmlProcessor.ProcessAsync"/> loop iteration,
    /// before reading the next XML event. No-op when no sink is attached or the
    /// buffer is empty.
    /// </summary>
    internal async ValueTask DrainStreamingOutputAsync(CancellationToken ct)
    {
        if (_streamingOutputSink == null) return;
        if (_output.Length == 0) return;
        var chunk = _output.ToString();
        _output.Clear();
        _outputLogicalStart = 0;
        await _streamingOutputSink.WriteAsync(chunk.AsMemory(), ct).ConfigureAwait(false);
    }

    /// <summary>
    /// Checks the resource policy for text access and tries the custom resolver first.
    /// Returns null to indicate the caller should fall through to default file-based resolution.
    /// Throws <see cref="PhoenixmlDb.XQuery.Security.ResourceAccessDeniedException"/> if denied.
    /// </summary>
    internal string? ResolveUnparsedTextViaPolicy(string href, string? encoding)
    {
        if (_policyResolver == null)
            return null; // No policy — fall through to default

        return _policyResolver.ResolveText(href, encoding);
    }

    /// <summary>
    /// Checks whether the policy allows text access without throwing.
    /// </summary>
    internal bool IsUnparsedTextAvailableViaPolicy(string href)
    {
        if (_policyResolver == null)
            return true; // No policy — allow default check

        return _policyResolver.IsTextAvailable(href);
    }

    /// <summary>
    /// Checks the resource policy for write access (xsl:result-document).
    /// Throws <see cref="PhoenixmlDb.XQuery.Security.ResourceAccessDeniedException"/> if denied.
    /// </summary>
    internal void CheckResultDocumentPolicy(string href)
    {
        _policyResolver?.CheckWriteAccess(href);
    }

    private PhoenixmlDb.XQuery.Functions.FunctionLibrary BuildFunctionLibrary(XsltStylesheet stylesheet)
    {
        var lib = new PhoenixmlDb.XQuery.Functions.FunctionLibrary();

        // Copy all standard functions
        foreach (var func in PhoenixmlDb.XQuery.Functions.FunctionLibrary.Standard.GetAllFunctions())
            lib.Register(func);

        // Register all namespace URI → NamespaceId mappings so EQName function calls (Q{uri}local)
        // can resolve to user-defined functions (includes URIs from child elements like xsl:function)
        foreach (var (uri, nsId) in StylesheetParser.DynamicNamespaces)
            lib.RegisterNamespaceUri(uri, nsId);
        foreach (var (prefix, uri) in stylesheet.Namespaces)
        {
            var nsId = StylesheetParser.ResolveNamespaceUri(uri);
            if (nsId != NamespaceId.None)
                lib.RegisterPrefix(prefix, nsId);
        }

        // Register XSLT user-defined functions (xsl:function)
        foreach (var (key, xsltFunc) in stylesheet.Functions)
        {
            var adapter = new XsltUserFunctionAdapter(xsltFunc, this);
            lib.Register(adapter);
            // Register prefix-to-namespace mapping so XPath can resolve prefixed calls
            if (xsltFunc.Name.Prefix != null && xsltFunc.Name.Namespace != NamespaceId.None)
                lib.RegisterPrefix(xsltFunc.Name.Prefix, xsltFunc.Name.Namespace);
        }

        // Register xsl:original function for package overrides — resolved dynamically
        // at runtime via _currentXsltFunctionStack
        lib.Register(new XsltOriginalFunctionAdapter(this));

        // Register XSLT-specific built-in functions
        var rootFunc = new XsltRootFunction(this);
        var root0Func = new XsltRoot0Function(this);
        root0Func.SetRootFunc(rootFunc);
        lib.Register(rootFunc);
        lib.Register(root0Func);
        lib.Register(new XsltGenerateIdFunction(this));
        lib.Register(new XsltGenerateId0Function(this));
        lib.Register(new XsltCurrentFunction(this));
        lib.Register(new XsltCurrentGroupFunction(this));
        lib.Register(new XsltCurrentGroupingKeyFunction(this));
        lib.Register(new XsltCurrentMergeGroupFunction(this));
        lib.Register(new XsltCurrentMergeGroup1Function(this));
        lib.Register(new XsltCurrentMergeKeyFunction(this));
        lib.Register(new XsltRegexGroupFunction(this));
        lib.Register(new XsltFunctionAvailableFunction(lib));
        lib.Register(new XsltElementAvailableFunction(_stylesheet.ExtensionElementPrefixes));
        lib.Register(new XsltSystemPropertyFunction());
        lib.Register(new XsltAvailableSystemPropertiesFunction());
        lib.Register(new XsltTypeAvailableFunction());
        lib.Register(new XsltUnparsedTextFunction(this));
        lib.Register(new XsltUnparsedText2Function(this));
        lib.Register(new XsltUnparsedTextAvailableFunction(this));
        lib.Register(new XsltUnparsedTextAvailable2Function(this));
        lib.Register(new XsltUnparsedTextLinesFunction(this));
        lib.Register(new XsltUnparsedTextLines2Function(this));
        lib.Register(new XsltCurrentOutputUriFunction());
        lib.Register(new XsltUnparsedEntityUriFunction(this));
        lib.Register(new XsltUnparsedEntityPublicIdFunction(this));
        lib.Register(new XsltStreamAvailableFunction(this));
        lib.Register(new XsltDocumentFunction(this));
        lib.Register(new XsltDocument2Function(this));
        lib.Register(new XsltKeyFunction(this));
        lib.Register(new XsltKey3Function(this));
        lib.Register(new XsltAccumulatorBeforeFunction(this));
        lib.Register(new XsltAccumulatorAfterFunction(this));
        lib.Register(new XsltLangFunction(this));
        lib.Register(new XsltLang2Function(this));
        lib.Register(new XsltDeepEqualFunction(this));
        lib.Register(new XsltOutermostFunction(this));
        lib.Register(new XsltInnermostFunction(this));
        lib.Register(new XsltSnapshotFunction(this));
        lib.Register(new XsltSnapshot0Function(this));
        lib.Register(new XsltFormatNumberFunction(this));
        lib.Register(new XsltFormatNumber3Function(this));
        lib.Register(new XsltCopyOfFunction(this));
        lib.Register(new XsltCopyOf0Function(this));
        lib.Register(new XsltPathFunction(this));
        lib.Register(new XsltPath0Function(this));
        lib.Register(new XsltNilledFunction());
        lib.Register(new XsltNilled0Function(this));
        lib.Register(new XsltDocumentUri0Function(this));
        lib.Register(new XsltHasChildrenFunction(this));
        lib.Register(new XsltHasChildren0Function(this));
        lib.Register(new XsltXmlToJsonFunction(this));
        lib.Register(new XsltXmlToJson2Function(this));
        lib.Register(new XsltJsonToXmlFunction(this));
        lib.Register(new XsltJsonToXml2Function(this));
        lib.Register(new XsltParseJsonFunction(this));
        lib.Register(new XsltParseJson2Function(this));
        lib.Register(new XsltParseXmlFunction(this));
        lib.Register(new XsltParseXmlFragmentFunction(this));
        lib.Register(new XsltStaticBaseUriFunction(this));
        lib.Register(new XsltIdFunction(this));
        lib.Register(new XsltId2Function(this));
        lib.Register(new XsltAnalyzeStringFunction());
        lib.Register(new XsltAnalyzeString3Function());

        // fn:transform — run XSLT transformation from within XPath
        lib.Register(new XsltTransformFunction(this));

        // EXSLT extension functions (used by XSLT 1.0 stylesheets like DocBook)
        lib.Register(new ExslNodeSetFunction(this));

        return lib;
    }

    public object? ContextItem => _contextItems.Count > 0 ? _contextItems.Peek() : null;
    public int Position => _contextPositions.Count > 0 ? _contextPositions.Peek().position : 0;
    public int Last => _contextPositions.Count > 0 ? _contextPositions.Peek().last : 0;

    /// <summary>
    /// Returns the "current" item for XSLT current() function.
    /// This is the outer XSLT context item, not the inner context used for pattern evaluation.
    /// </summary>
    public object? CurrentItem => _currentItems.Count > 0 ? _currentItems.Peek() : ContextItem;

    public void PushContextItem(object? item, int position, int last)
    {
        _contextItems.Push(item);
        _contextPositions.Push((position, last));
    }

    public void PopContextItem()
    {
        _contextItems.Pop();
        _contextPositions.Pop();
    }

    /// <summary>
    /// Pushes a new "current" item for XSLT current() function.
    /// Call this when entering a new XSLT instruction context (template, for-each, etc).
    /// </summary>
    public void PushCurrentItem(object? item)
    {
        _currentItems.Push(item);
    }

    /// <summary>
    /// Pops the "current" item stack.
    /// </summary>
    public void PopCurrentItem()
    {
        if (_currentItems.Count > 0)
            _currentItems.Pop();
    }

    // Pooled Scope reuse. Profiling showed ~8% of post-context-pool streaming alloc
    // was the Scope object itself. PushScope draws from the pool when available;
    // PopScope resets and returns to the pool (bounded).
    private readonly Stack<Scope> _scopePool = new();
    private const int MaxPooledScopes = 32;

    public void PushScope()
    {
        if (_scopePool.TryPop(out var pooled))
        {
            pooled.Parent = _scopes.Peek();
            _scopes.Push(pooled);
        }
        else
        {
            _scopes.Push(new Scope(_scopes.Peek()));
        }
    }

    public void PopScope()
    {
        var s = _scopes.Pop();
        if (_scopePool.Count >= MaxPooledScopes) return;
        s.Reset();
        _scopePool.Push(s);
    }

    public object? GetVariable(QName name)
    {
        foreach (var scope in _scopes)
        {
            if (scope.VariablesOrNull is { } vars && vars.TryGetValue(name, out var value))
            {
                // Handle lazy evaluation: if the value is a LazyValue, evaluate it now
                if (value is LazyValue lazy)
                {
                    var evaluated = lazy.GetValueAsync().AsTask().GetAwaiter().GetResult();
                    // Cache the evaluated value for future accesses
                    vars[name] = evaluated;
                    return evaluated;
                }
                return value;
            }
        }

        if (GlobalVariables.TryGetValue(name, out var globalValue))
        {
            // Handle lazy evaluation for globals too (though they're typically not lazy)
            if (globalValue is LazyValue lazyGlobal)
            {
                var evaluated = lazyGlobal.GetValueAsync().AsTask().GetAwaiter().GetResult();
                GlobalVariables[name] = evaluated;
                return evaluated;
            }
            return globalValue;
        }

        // Lazy global initialization: if the variable is pending (not yet evaluated by the
        // topological sort), initialize it on demand. This handles dependencies the static
        // analysis missed (e.g., large stylesheets like DocBook with 300+ globals).
        if (_pendingGlobals != null)
        {
            GlobalDeclaration? pendingGlobal = null;
            if (_pendingGlobals.TryGetValue(name, out pendingGlobal))
            {
                // Found by exact QName match
            }
            else
            {
                // Try matching by local name only (for QName resolution mismatches)
                foreach (var (pName, pDecl) in _pendingGlobals)
                {
                    if (pName.LocalName == name.LocalName)
                    {
                        pendingGlobal = pDecl;
                        break;
                    }
                }
            }
            if (pendingGlobal != null)
            {
                XsltTransformEngine.InitializePendingGlobalAsync(this, pendingGlobal, _output).GetAwaiter().GetResult();
                if (GlobalVariables.TryGetValue(pendingGlobal.Name, out var lazyInitValue))
                    return lazyInitValue;
            }
        }

        // XTDE0640: Detect circular references — if this global is currently being evaluated,
        // accessing it means we have a circular dependency (e.g., param → key → param).
        if (_globalsBeingEvaluated.Contains(name))
            throw Error($"XTDE0640: Circular reference detected while evaluating global variable/parameter ${name.LocalName}");
        // Also check circularity via prefix fallback matching
        foreach (var beingEvaluated in _globalsBeingEvaluated)
        {
            if (VariableNameMatches(beingEvaluated, name))
                throw Error($"XTDE0640: Circular reference detected while evaluating global variable/parameter ${name.LocalName}");
        }

        // Fallback: XPath parser creates QNames with NamespaceId.None for prefixed/EQName names
        // because it doesn't have XSLT namespace context. Try matching by prefix+localname or EQName.
        if (name.Prefix != null || name.ExpandedNamespace != null)
        {
            var result = FindVariableByPrefixFallback(name);
            if (result != null)
                return result;
        }

        throw Error($"XPST0008: Variable ${name.LocalName} not defined");
    }

    /// <summary>
    /// Fallback variable lookup when exact QName match fails. Matches by local name
    /// and prefix, handling the case where XPath-parsed QNames have unresolved namespaces.
    /// Also handles the case where different prefixes map to the same namespace.
    /// </summary>
    private object? FindVariableByPrefixFallback(QName name)
    {
        // Search scoped variables
        foreach (var scope in _scopes)
        {
            foreach (var (varName, value) in scope.Variables)
            {
                if (VariableNameMatches(varName, name))
                {
                    if (value is LazyValue lazy)
                    {
                        var evaluated = lazy.GetValueAsync().AsTask().GetAwaiter().GetResult();
                        scope.Variables[varName] = evaluated;
                        return evaluated;
                    }
                    return value;
                }
            }
        }

        // Search global variables
        foreach (var (varName, value) in GlobalVariables)
        {
            if (VariableNameMatches(varName, name))
            {
                if (value is LazyValue lazyGlobal)
                {
                    var evaluated = lazyGlobal.GetValueAsync().AsTask().GetAwaiter().GetResult();
                    GlobalVariables[varName] = evaluated;
                    return evaluated;
                }
                return value;
            }
        }

        return null;
    }

    /// <summary>
    /// Checks if a declared variable name matches a reference name.
    /// Handles the case where XPath parser creates QNames with unresolved namespaces.
    /// </summary>
    private static bool VariableNameMatches(QName declared, QName reference)
    {
        if (declared.LocalName != reference.LocalName)
            return false;

        // EQName match: both have expanded namespace URIs
        if (reference.ExpandedNamespace != null && declared.ExpandedNamespace != null)
            return reference.ExpandedNamespace == declared.ExpandedNamespace;

        // EQName reference matching resolved declaration: compare URI to declared namespace
        if (reference.ExpandedNamespace != null && declared.Namespace != NamespaceId.None)
            return true; // Best effort: same local name with non-null expanded ns

        // Same prefix is always a match
        if (declared.Prefix == reference.Prefix)
            return true;

        // Both have resolved namespaces: compare by namespace
        if (reference.Namespace != NamespaceId.None && declared.Namespace == reference.Namespace)
            return true;

        // Reference has unresolved namespace but has a prefix: match any namespaced variable
        // with the same local name. This handles $new:me matching $txt:me when both
        // prefixes refer to the same namespace (which XPath parser can't resolve).
        if (reference.Prefix != null && reference.Namespace == NamespaceId.None &&
            declared.Namespace != NamespaceId.None)
            return true;

        return false;
    }

    /// <summary>
    /// Searches the scope stack for a tunnel parameter with the given name.
    /// Returns true and the value if found, false otherwise.
    /// </summary>
    private bool TryGetTunnelParam(QName name, out object? value)
    {
        foreach (var scope in _scopes)
        {
            if (scope.TunnelParametersOrNull is { } tunnels && tunnels.TryGetValue(name, out value))
                return true;
            // Stop at function boundaries — tunnel params don't propagate through functions
            if (scope.IsTunnelBarrier)
                break;
        }
        value = null;
        return false;
    }

    /// <summary>
    /// Tries to get a variable value without throwing if not found.
    /// Used by context-dependent functions like current-group() that should
    /// return empty sequence when called outside their expected context.
    /// </summary>
    public bool TryGetVariable(QName name, out object? value)
    {
        foreach (var scope in _scopes)
        {
            if (scope.VariablesOrNull is { } vars && vars.TryGetValue(name, out value))
            {
                if (value is LazyValue lazy)
                {
                    value = lazy.GetValueAsync().AsTask().GetAwaiter().GetResult();
                    vars[name] = value;
                }
                return true;
            }
        }

        if (GlobalVariables.TryGetValue(name, out value))
        {
            if (value is LazyValue lazyGlobal)
            {
                value = lazyGlobal.GetValueAsync().AsTask().GetAwaiter().GetResult();
                GlobalVariables[name] = value;
            }
            return true;
        }

        // Fallback: prefix-based matching for unresolved namespaces
        if (name.Prefix != null)
        {
            var fallback = FindVariableByPrefixFallback(name);
            if (fallback != null)
            {
                value = fallback;
                return true;
            }
        }

        value = null;
        return false;
    }

    public void SetVariable(QName name, object? value)
    {
        _scopes.Peek().Variables[name] = value;
    }

    /// <summary>
    /// Evaluates the body content of an xsl:param / xsl:with-param (when no `select`
    /// attribute is present) into a typed value, preserving xsl:sequence-emitted items.
    ///
    /// The naive path (write to output buffer, then atomize the text) destroys typed
    /// items: an xsl:sequence emitting a document-node would serialize to text, then
    /// the text would be wrapped as XsUntypedAtomic, then bound to the parameter.
    /// Downstream code expecting `as="document-node()"` to preserve the doc-node would
    /// see XsUntypedAtomic and fail XPTY0020 on axis steps. Found in Docbook TNG
    /// fp:run-transforms's xsl:next-iteration with-param="document"; same shape as the
    /// xsl:variable accumulator-isolation fix earlier.
    ///
    /// Strategy: install a fresh sequence accumulator around the body. xsl:sequence
    /// inside the body appends items to it; literal text falls through to the output
    /// buffer. After execution, prefer the accumulator items when present (they retain
    /// type), otherwise fall back to the output text wrapped as untyped atomic.
    /// </summary>
    internal async ValueTask<object?> EvaluateBodyContentToValueAsync(XsltSequenceConstructor body)
    {
        var savedAccumulator = _sequenceAccumulator;
        _sequenceAccumulator = new List<object?>();
        var savedLen = _output.Length;
        _temporaryOutputDepth++;
        List<object?> captured;
        try
        {
            await body.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            captured = _sequenceAccumulator;
            _sequenceAccumulator = savedAccumulator;
            _temporaryOutputDepth--;
        }
        var content = _output.ToString(savedLen, _output.Length - savedLen);
        _output.Length = savedLen;
        if (captured.Count > 0)
        {
            // Typed items captured — return them (single-item unwrapped, multi as array).
            return captured.Count == 1 ? captured[0] : captured.ToArray();
        }
        // Fall back to text content as untyped atomic / RTF.
        return content.Contains('<', StringComparison.Ordinal)
            ? (object)new ResultTreeFragment(content)
            : new Xdm.XsUntypedAtomic(StripXmlMarkup(content));
    }

    private void ClearMergeGroupContext()
    {
        SetVariable(new QName(NamespaceId.None, "current-merge-group"), null);
        SetVariable(new QName(NamespaceId.None, "current-merge-key"), null);
    }

    public override async ValueTask ApplyTemplatesAsync(
        XQueryExpression? select,
        QName? mode,
        List<XsltSort> sorts,
        List<XsltWithParam> withParams)
    {
        CheckResourceLimits();
        if (_recursionDepth >= MaxRecursionDepth)
            return;

        _recursionDepth++;
        try
        {
            await ApplyTemplatesCoreAsync(select, mode, sorts, withParams).ConfigureAwait(false);
        }
        finally
        {
            _recursionDepth--;
        }
    }

    private async ValueTask ApplyTemplatesCoreAsync(
        XQueryExpression? select,
        QName? mode,
        List<XsltSort> sorts,
        List<XsltWithParam> withParams)
    {
        // Streaming interception: when a streaming processor is active and
        // apply-templates is called on the document's children (select is null, or a
        // striding child-axis select like ./account naming top-level elements), delegate
        // to the streaming processor. The processor's forward pass offers each top-level
        // element to template matching, so a striding select restricting to a named child
        // dispatches exactly the templates that match that name (si-result-document-301/
        // 303/304, where the matched account template body writes an xsl:result-document).
        if (_activeStreamingProcessor != null && _activeStreamingReader != null
            && (select == null || IsDocumentLevelStridingSelect(select)))
        {
            var ci = ContextItem;
            if (ci is XdmDocument)
            {
                var proc = _activeStreamingProcessor;
                var rdr = _activeStreamingReader;
                var ct = _activeStreamingCancellationToken;
                // Clear the active processor so it's not re-triggered during
                // the streaming pass (the processor calls MatchAndExecuteStreamingNodeAsync
                // which may invoke templates that call apply-templates again).
                _activeStreamingProcessor = null;
                _activeStreamingReader = null;
                // Phase 2a (#143): propagate THIS apply-templates' explicit mode into the
                // processor's forward pass so a wrapped/conditional apply-templates carrying
                // mode="t" (deep-copy) etc. dispatches under that mode's template-matching and
                // built-in on-no-match rules — not the processor's construction-time mode
                // (the enclosing template's mode). Restored after the pass.
                var savedDispatchMode = proc.DispatchMode;
                if (mode != null)
                    proc.DispatchMode = mode;
                try
                {
                    await proc.ProcessAsync(rdr, ct).ConfigureAwait(false);
                }
                finally
                {
                    proc.DispatchMode = savedDispatchMode;
                }
                return;
            }
        }

        // Streaming interception inside a template body: when we're already inside
        // the streaming processor's pass and apply-templates is called on a
        // consuming select (children of the current node), drive the reader directly
        // to consume each child event, fire templates inline, and stop at the parent's
        // EndElement. This makes the body of a user template see the correct ordering
        // (`<pre/> apply-templates <post/>` puts `<post/>` AFTER processed children,
        // not before). Without this, apply-templates returned immediately, `<post/>`
        // emitted, then the processor's outer loop read the children as siblings.
        if (_isStreamingExecution && _activeStreamingReader != null
            && IsConsumingChildSelect(select))
        {
            await ApplyTemplatesStreamingAsync(mode, withParams).ConfigureAwait(false);
            return;
        }

        // Get nodes to process
        IEnumerable<object> nodes;
        if (select != null)
        {
            var result = await EvaluateAsync(select).ConfigureAwait(false);
            nodes = result switch
            {
                null => [],
                // An XDM array (List<object?>) or map (IDictionary) is a single item:
                // apply-templates processes it as one item, it does NOT iterate the
                // array's members or the map's entries. Everything else that is
                // IEnumerable<object> (notably object?[], the engine's sequence
                // representation) is iterated. Without these guards a JSON array fed as
                // the context item was spread into its members and the template fired
                // once per member (Martin Honnen 2026-06-14).
                List<object?> arr => [arr],
                System.Collections.IDictionary dict => [dict],
                IEnumerable<object> seq => seq,
                object obj => [obj]
            };
        }
        else
        {
            // Default: children of context node — context item must be a node (XTTE0510)
            var ci = ContextItem;
            if (ci != null && ci is not XdmNode && ci is not ResultTreeFragment
                && !ReferenceEquals(ci, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
                throw new InvalidOperationException("XTTE0510: Context item for xsl:apply-templates must be a node");
            nodes = GetChildren(ci);
        }

        // Apply sorts if specified
        if (sorts.Count > 0)
        {
            nodes = await SortNodesAsync(nodes, sorts).ConfigureAwait(false);
        }

        var nodeList = nodes.ToList();

        // Expand any ResultTreeFragments to their XDM document nodes
        var expandedNodes = new List<object>();
        foreach (var item in nodeList)
        {
            if (item is ResultTreeFragment rtf)
            {
                // Parse RTF to XDM document node for template matching
                var docNode = ParseResultTreeFragment(rtf);
                if (docNode != null)
                    expandedNodes.Add(docNode);
            }
            else
            {
                expandedNodes.Add(item);
            }
        }

        // Pre-evaluate with-param values in the CALLING context (before the per-node loop changes context)
        var preEvaluatedParams = new Dictionary<QName, object?>();
        foreach (var param in withParams)
        {
            preEvaluatedParams[param.Name] = await EvaluateWithParamAsync(param).ConfigureAwait(false);
        }

        var position = 0;
        var lastTemplateResultWasAtomic = false; // Track for space-separating adjacent atomic values
        foreach (var node in expandedNodes)
        {
            CheckResourceLimits();
            position++;
            PushContextItem(node, position, expandedNodes.Count);
            PushCurrentItem(node); // For XSLT current() function
            PushScope();

            // XTDE3480: Clear merge-group context — not available in applied templates
            ClearMergeGroupContext();

            try
            {
                // Propagate tunnel parameters: first inherit from parent scopes,
                // then override with explicitly provided tunnel params.
                // NOTE: We only store in TunnelParameters here, NOT as variables.
                // Variables are bound later based on each template param's tunnel flag.
                foreach (var scope in _scopes.Skip(1)) // Skip current (just-pushed) scope
                {
                    foreach (var (name, value) in scope.TunnelParameters)
                    {
                        if (!_scopes.Peek().TunnelParameters.ContainsKey(name))
                        {
                            _scopes.Peek().TunnelParameters[name] = value;
                        }
                    }
                    if (scope.IsTunnelBarrier)
                        break;
                }
                foreach (var param in withParams.Where(p => p.Tunnel))
                {
                    var value = preEvaluatedParams[param.Name];
                    _scopes.Peek().TunnelParameters[param.Name] = value;
                }

                // Find matching template
                XsltTemplate? template;
                using (var mc = AcquireMatchContext())
                    template = _templateIndex.FindMatchingTemplate(node, mode, mc.Value);

                // XTDE0540: Check on-multiple-match="fail"
                if (template != null)
                {
                    var modeKey = mode ?? new QName(NamespaceId.None, "");
                    if (_stylesheet.Modes.TryGetValue(modeKey, out var modeDecl2) &&
                        modeDecl2.OnMultipleMatch == OnMultipleMatchBehavior.Fail)
                    {
                        // Check if there's another matching template at the same priority.
                        // Skip union siblings: matching two branches of a union pattern
                        // doesn't count as multiple match (spec bug 30402).
                        XsltTemplate? next;
                        using (var mc = AcquireMatchContext())
                            next = _templateIndex.FindMatchingTemplate(node, mode, mc.Value, template);
                        while (next != null
                            && template.UnionGroupId != null
                            && next.UnionGroupId == template.UnionGroupId
                            && TemplateIndex.EffectivePriority(next) == TemplateIndex.EffectivePriority(template))
                        {
                            using var mc2 = AcquireMatchContext();
                            next = _templateIndex.FindMatchingTemplate(node, mode, mc2.Value, next);
                        }
                        if (next != null && TemplateIndex.EffectivePriority(next) == TemplateIndex.EffectivePriority(template))
                            throw Error($"XTDE0540: Multiple template rules match the node in a mode with on-multiple-match='fail'");
                    }
                }

                if (template != null)
                {
                    // Trace: template match
                    if (_options?.TraceListener != null)
                    {
                        var nodeDesc = DescribeTraceNode(node);
                        var templateDesc = template.Name.HasValue
                            ? $"name=\"{template.Name.Value.LocalName}\""
                            : $"match=\"{template.Match}\"";
                        var modeDesc = mode.HasValue ? $" mode=\"{mode.Value.LocalName}\"" : "";
                        var priorityDesc = template.Priority.HasValue ? $" priority={template.Priority.Value}" : "";
                        _options.TraceListener(_templateDepth, "match", $"{nodeDesc} → {templateDesc}{modeDesc}{priorityDesc}");
                    }

                    // Enforce xsl:context-item constraints
                    var makeContextAbsent = EnforceContextItemConstraint(template);

                    // Bind non-tunnel parameters (only to non-tunnel template params)
                    foreach (var param in withParams.Where(p => !p.Tunnel))
                    {
                        var templateParam = template.Parameters.FirstOrDefault(tp =>
                            tp.Name.Equals(param.Name) && !tp.Tunnel);

                        if (templateParam != null)
                        {
                            var value = preEvaluatedParams[param.Name];
                            if (templateParam.As != null)
                            {
                                value = CoerceToType(value, templateParam.As);
                                ValidateValueMatchesType(value, templateParam.As, "XTTE0590",
                                    $"Parameter ${param.Name.LocalName}");
                            }
                            SetVariable(param.Name, value);
                        }
                    }

                    // Bind template parameters with defaults
                    foreach (var param in template.Parameters)
                    {
                        if (!_scopes.Peek().Variables.ContainsKey(param.Name))
                        {
                            // For tunnel params not yet bound, check the tunnel param stack
                            if (param.Tunnel && TryGetTunnelParam(param.Name, out var tunnelValue))
                            {
                                if (param.As != null)
                                {
                                    tunnelValue = CoerceToType(tunnelValue, param.As);
                                    ValidateValueMatchesType(tunnelValue, param.As, "XTTE0590",
                                        $"Parameter ${param.Name.LocalName}");
                                }
                                SetVariable(param.Name, tunnelValue);
                            }
                            else if (param.Required)
                            {
                                throw Error($"Required parameter ${param.Name.LocalName} not supplied");
                            }
                            else if (param.Select != null)
                            {
                                var value = await EvaluateAsync(param.Select).ConfigureAwait(false);
                                if (param.As != null)
                                {
                                    value = CoerceToType(value, param.As);
                                    ValidateValueMatchesType(value, param.As, "XTTE0600",
                                        $"Parameter ${param.Name.LocalName} default value");
                                }
                                SetVariable(param.Name, value);
                            }
                            else if (param.Content != null)
                            {
                                // Route through the accumulator-isolating helper so xsl:sequence
                                // inside the default body preserves typed items (nodes, maps, …)
                                // instead of being serialized to text and re-wrapped as untyped
                                // atomic. Same shape as the with-param fix for #19.
                                var value = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
                                if (param.As != null)
                                {
                                    value = CoerceToType(value, param.As);
                                    ValidateValueMatchesType(value, param.As, "XTTE0600",
                                        $"Parameter ${param.Name.LocalName} default value");
                                }
                                SetVariable(param.Name, value);
                            }
                            else
                            {
                                // No select, no content: default is empty sequence.
                                // Per XSLT 3.0 spec, if 'as' requires a non-empty value
                                // and the type is a strict atomic type where empty sequence is not valid,
                                // the parameter is effectively required — raise XTDE0700.
                                if (param.As != null && param.As.Occurrence is Occurrence.ExactlyOne or Occurrence.OneOrMore
                                    && IsStrictAtomicType(param.As.ItemType))
                                    throw Error($"XTDE0700: Required parameter ${param.Name.LocalName} not supplied (type {param.As.ItemType} requires a value)");
                                else if (param.As != null && param.As.Occurrence is Occurrence.ZeroOrOne or Occurrence.ZeroOrMore)
                                    SetVariable(param.Name, null);
                                else
                                    SetVariable(param.Name, "");
                            }
                        }
                    }

                    // Track current template for next-match
                    var savedTemplate = _currentTemplate;
                    var savedMode = _currentMode;
                    _currentTemplate = template;
                    _currentMode = mode;

                    // If use="absent" or optional type mismatch, push absent focus
                    if (template.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                        PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

                    // Push template-level version, collation, and static base URI for scoping
                    if (template.Version != null)
                        _effectiveVersionStack.Push(template.Version);
                    if (template.DefaultCollation != null)
                        _defaultCollationStack.Push(template.DefaultCollation);
                    if (template.BaseUri != null)
                        _staticBaseUriStack.Push(XsltTransformEngine.UriString(template.BaseUri)!);
                    _templateDepth++;
                    try
                    {

                        // Execute template body, capturing output for type checking if 'as' is declared
                        if (template.As != null)
                        {
                            var savedAccum = _sequenceAccumulator;
                            var savedCapture = _currentAsBodyCapture;
                            var savedLen = _output.Length;
                            var bodyAccum = new List<object?>();
                            _sequenceAccumulator = bodyAccum;
                            _currentAsBodyCapture = new AsBodyCapture { Accumulator = bodyAccum, OutputBaseLen = savedLen };
                            await template.Body.ExecuteAsync(this).ConfigureAwait(false);
                            var bodyOutput = _output.ToString(savedLen, _output.Length - savedLen);
                            _output.Length = savedLen;
                            var bodyCapture = _currentAsBodyCapture;
                            _currentAsBodyCapture = savedCapture;

                            // Reassemble in document order using recorded offsets — without
                            // this, a template body that writes an LRE before an xsl:sequence
                            // emits items in the wrong order at the parent constructor.
                            var resultItems = AssembleAsBodyResultItems(bodyOutput, bodyCapture.Accumulator, bodyCapture.Positions);

                            // Track whether results are only from body serialization
                            // (no sequence accumulator items). When true, emit bodyOutput
                            // directly to preserve exact namespace declarations (e.g. xmlns=""
                            // from inherit-namespaces="no") and disable-output-escaping text
                            // that would be lost by XDM re-serialization round-trip.
                            bool canEmitBodyDirectly = bodyCapture.Accumulator.Count == 0
                                && !string.IsNullOrEmpty(bodyOutput);

                            _sequenceAccumulator = savedAccum;

                            // XTTE0505: Validate template return value against 'as' type
                            ValidateTemplateReturnType(template, resultItems);

                            // If an outer sequence accumulator is active (e.g., raw delivery
                            // from fn:transform), propagate items there instead of serializing
                            if (_sequenceAccumulator != null && resultItems.Count > 0)
                            {
                                foreach (var item in resultItems)
                                    AppendToSeqAccumulator(item);
                                var lastItem = resultItems[^1];
                                lastTemplateResultWasAtomic = lastItem is not (XdmNode or ResultTreeFragment);
                            }
                            // Re-serialize validated items to output
                            // Adjacent atomic values from consecutive template invocations
                            // are space-separated per XSLT spec section 5.7.2
                            else if (resultItems.Count > 0)
                            {
                                var firstItem = resultItems[0];
                                bool firstIsAtomic = firstItem is not (XdmNode or ResultTreeFragment);
                                if (firstIsAtomic && lastTemplateResultWasAtomic && _textContentDepth == 0)
                                {
                                    _output.Append(' ');
                                    // Reset so SerializeSequenceItems doesn't add a duplicate separator
                                    _lastResultWasAtomic = false;
                                }
                                if (canEmitBodyDirectly)
                                {
                                    // Append bodyOutput directly to preserve DOE text,
                                    // xmlns="" undeclarations, and other serialization details
                                    // that would be lost by XDM round-trip re-serialization.
                                    _output.Append(bodyOutput);
                                    _lastResultWasAtomic = false;
                                }
                                else
                                {
                                    SerializeSequenceItems(resultItems);
                                }
                                var lastItem = resultItems[^1];
                                lastTemplateResultWasAtomic = lastItem is not (XdmNode or ResultTreeFragment);
                            }
                        }
                        else
                        {
                            await template.Body.ExecuteAsync(this).ConfigureAwait(false);
                            lastTemplateResultWasAtomic = false;
                        }

                    }
                    finally
                    {
                        _templateDepth--;
                        if (template.BaseUri != null)
                            _staticBaseUriStack.Pop();
                        if (template.DefaultCollation != null)
                            _defaultCollationStack.Pop();
                        if (template.Version != null)
                            _effectiveVersionStack.Pop();
                    }

                    // Pop absent context if pushed
                    if (template.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                        PopContextItem();

                    _currentTemplate = savedTemplate;
                    _currentMode = savedMode;
                }
                else
                {
                    // Built-in template rules
                    if (_options?.TraceListener != null)
                        _options.TraceListener(_templateDepth, "built-in", DescribeTraceNode(node));
                    await ApplyBuiltInTemplateAsync(node, mode, withParams).ConfigureAwait(false);
                }
            }
            finally
            {
                PopScope();
                PopCurrentItem();
                PopContextItem();
            }
        }
    }

    private bool IsTypedMode(QName? mode)
    {
        if (mode != null && _stylesheet.Modes.TryGetValue(mode.Value, out var modeDecl))
            return modeDecl.Typed;
        var unnamed = new QName(default, "");
        if (_stylesheet.Modes.TryGetValue(unnamed, out var unnamedMode))
            return unnamedMode.Typed;
        return false;
    }

    private OnNoMatchBehavior GetOnNoMatchBehavior(QName? mode)
    {
        if (mode != null && _stylesheet.Modes.TryGetValue(mode.Value, out var modeDecl))
            return modeDecl.OnNoMatch ?? OnNoMatchBehavior.TextOnlyCopy;
        // Check unnamed mode
        var unnamed = new QName(default, "");
        if (_stylesheet.Modes.TryGetValue(unnamed, out var unnamedMode))
            return unnamedMode.OnNoMatch ?? OnNoMatchBehavior.TextOnlyCopy;
        return OnNoMatchBehavior.TextOnlyCopy; // XSLT default
    }

    private async ValueTask ApplyBuiltInTemplateAsync(
        object node,
        QName? mode,
        List<XsltWithParam> withParams)
    {
        // XTTE3100: typed="yes" mode disallows untyped nodes in built-in templates
        if (node is XdmElement or XdmDocument && IsTypedMode(mode))
            throw Error("XTTE3100: Built-in template rule invoked for an untyped node in a mode with typed='yes'");

        var behavior = GetOnNoMatchBehavior(mode);

        switch (behavior)
        {
            case OnNoMatchBehavior.TextOnlyCopy:
                await ApplyBuiltInTextOnlyCopyAsync(node, mode, withParams).ConfigureAwait(false);
                break;
            case OnNoMatchBehavior.ShallowCopy:
                await ApplyBuiltInShallowCopyAsync(node, mode, withParams).ConfigureAwait(false);
                break;
            case OnNoMatchBehavior.DeepCopy:
                await ApplyBuiltInDeepCopyAsync(node, mode, withParams).ConfigureAwait(false);
                break;
            case OnNoMatchBehavior.DeepSkip:
                // Skip the node and all descendants entirely.
                // Exception: document nodes still recurse into children (otherwise nothing would ever match).
                // In streaming mode, child recursion is handled by the streaming loop.
                if (node is XdmDocument && !_isStreamingExecution)
                    await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                break;
            case OnNoMatchBehavior.ShallowSkip:
                // Skip the node but apply templates to @* | node() (per XSLT spec)
                if (node is XdmDocument or XdmElement)
                {
                    // Apply templates to attributes (element nodes only)
                    if (node is XdmElement elemSkip && _nodeStore != null)
                    {
                        foreach (var attr in _nodeStore.GetAttributes(elemSkip))
                        {
                            XsltTemplate? template;
                            using (var mc = AcquireMatchContext())
                                template = _templateIndex.FindMatchingTemplate(attr, mode, mc.Value);
                            if (template != null)
                            {
                                await ExecuteMatchedTemplateAsync(template, attr, mode, withParams)
                                    .ConfigureAwait(false);
                            }
                            // If no match, shallow-skip does nothing for attributes
                        }
                    }
                    // In streaming mode, child recursion is handled by the streaming loop.
                    if (!_isStreamingExecution)
                        await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                }
                break;
            case OnNoMatchBehavior.Fail:
                throw new InvalidOperationException(
                    $"XTDE0555: No matching template found for node in mode with on-no-match='fail'");
        }
    }

    private async ValueTask ApplyBuiltInTextOnlyCopyAsync(object node, QName? mode, List<XsltWithParam> withParams)
    {
        switch (node)
        {
            case XdmDocument:
            case XdmElement:
                // In streaming mode, child recursion is handled by the streaming loop —
                // the built-in template only needs to handle the current node.
                if (!_isStreamingExecution)
                    await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                break;
            case XdmText text:
                WriteText(text.Value, false);
                break;
            case XdmAttribute attr:
                WriteText(attr.Value, false);
                break;
            case XdmNamespace:
                // XSLT 3.0 §6.7: Namespace nodes produce no text output
                break;
            default:
                // XSLT 3.0 §6.7: Function items (maps, arrays, functions) — no action
                if (node is IDictionary<object, object?> or List<object?> or XQueryFunction)
                    break;
                // Atomic values: output string value (XSLT 3.0 §6.7)
                if (node is not XdmNode)
                    WriteText(StringValueOf(node), false);
                break;
        }
    }

    private async ValueTask ApplyBuiltInShallowCopyAsync(object node, QName? mode, List<XsltWithParam> withParams)
    {
        switch (node)
        {
            case XdmDocument:
                // In streaming mode, child recursion is handled by the streaming loop.
                if (!_isStreamingExecution)
                    await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                break;
            case XdmElement elem:
            {
                // Shallow copy: copy element, apply-templates to @* | node() (per XSLT spec)
                var nsUri = _nodeStore?.GetNamespaceUri(elem.Namespace) ?? "";
                var prefix = elem.Prefix ?? "";
                var localName = elem.LocalName;
                var qname = !string.IsNullOrEmpty(prefix) ? $"{prefix}:{localName}" : localName;

                _output.Append('<');
                _output.Append(qname);

                // Copy namespace declarations
                foreach (var nsDecl in elem.NamespaceDeclarations)
                {
                    var nsDeclUri = _nodeStore?.GetNamespaceUri(nsDecl.Namespace) ?? "";
                    var nsDeclPrefix = nsDecl.Prefix ?? "";
                    if (string.IsNullOrEmpty(nsDeclPrefix))
                    {
                        _output.Append(" xmlns=\"");
                        _output.Append(EscapeAttributeValue(nsDeclUri));
                        _output.Append('"');
                    }
                    else
                    {
                        _output.Append(" xmlns:");
                        _output.Append(nsDeclPrefix);
                        _output.Append("=\"");
                        _output.Append(EscapeAttributeValue(nsDeclUri));
                        _output.Append('"');
                    }
                }

                // EMIT (temp-tree base-URI preservation): built-in shallow-copy writes the
                // copied SOURCE element's start tag directly to _output (it does not go through
                // SerializeNode). When this output is destined for a temp-tree reparse
                // (_tempTreeSerializeDepth > 0, e.g. an xsl:variable as="document-node()" body),
                // stamp the source element's base URI as a sentinel so the reparse recovers it
                // onto CopySourceBaseUri. Mirrors SerializeNode's element case. Context is
                // restored after the child recursion / close tag below so siblings re-evaluate.
                var savedShallowCopyBaseContext = _serializeBaseContext;
                TryEmitBaseSentinel(elem, ref _serializeBaseContext);

                // Apply templates to attributes: attributes with no matching user template
                // are copied directly (built-in shallow-copy for attributes); attributes with
                // a matching user template have their template output as child content.
                List<(XsltTemplate template, XdmAttribute attr)>? templateMatches = null;
                if (_nodeStore != null)
                {
                    foreach (var attr in _nodeStore.EnumerateAttributes(elem))
                    {
                        XsltTemplate? template;
                        using (var mc = AcquireMatchContext())
                            template = _templateIndex.FindMatchingTemplate(attr, mode, mc.Value);
                        if (template != null)
                        {
                            (templateMatches ??= new()).Add((template, attr));
                        }
                        else
                        {
                            // Built-in: copy attribute directly
                            var attrPrefix = attr.Prefix ?? "";
                            var attrName = !string.IsNullOrEmpty(attrPrefix)
                                ? $"{attrPrefix}:{attr.LocalName}"
                                : attr.LocalName;
                            _output.Append(' ');
                            _output.Append(attrName);
                            _output.Append("=\"");
                            _output.Append(EscapeAttributeValue(attr.Value));
                            _output.Append('"');
                        }
                    }
                }

                // Execute user templates for matched attributes using attribute collection
                // so xsl:attribute instructions produce proper attributes, not text content.
                // Non-attribute output from templates (e.g. elements) becomes child content.
                var templateChildContent = string.Empty;
                if (templateMatches is { Count: > 0 })
                {
                    _collectedAttributesStack.Push(new StringBuilder());
                    var scope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                    // Reset _outputLogicalStart to the scope's start so the XTDE0410 check
                    // ("attribute after children") uses the correct baseline. Without this, the
                    // check compares _output.Length against the default value of 0, which causes
                    // a false positive when there is already content in _output from ancestor
                    // elements (e.g. shallow-copy of parent elements in streaming mode).
                    var savedLogicalStartForAttrTemplate = _outputLogicalStart;
                    _outputLogicalStart = scope.SavedLength;
                    foreach (var (matchedTemplate, matchedAttr) in templateMatches)
                    {
                        await ExecuteMatchedTemplateAsync(matchedTemplate, matchedAttr, mode, withParams)
                            .ConfigureAwait(false);
                    }
                    _outputLogicalStart = savedLogicalStartForAttrTemplate;
                    var collectedAttrs = _collectedAttributesStack.Pop();
                    templateChildContent = scope.GetWritten();
                    scope.Dispose();
                    _output.Append(collectedAttrs);
                }

                _output.Append('>');

                // Insert any non-attribute content from matched attribute templates as children
                if (templateChildContent.Length > 0)
                    _output.Append(templateChildContent);

                // Apply templates to children — suspend accumulator and track element depth
                // so inner templates with 'as' serialize to _output (child content)
                // instead of redirecting to an outer sequence accumulator.
                // In streaming mode, child recursion is handled by the streaming loop:
                // we leave the element open (no closing tag) and push the qname so that
                // StreamingXmlProcessor can write the closing tag on EndElement.
                if (_isStreamingExecution)
                {
                    _streamingOpenElements.Push(qname);
                    // Descendants in the streaming loop inherit this subtree's base context;
                    // restore happens on the matching EndElement is out of scope here, so
                    // restore now — sentinel already emitted on the open tag above.
                    _serializeBaseContext = savedShallowCopyBaseContext;
                }
                else
                {
                    var savedSeqAccumSC = _sequenceAccumulator;
                    _sequenceAccumulator = null;
                    _serializingElementDepth++;
                    try
                    {
                        await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                    }
                    finally
                    {
                        _serializingElementDepth--;
                        _sequenceAccumulator = savedSeqAccumSC;
                        // Restore base context so following siblings re-evaluate whether their
                        // own base differs (mirrors SerializeNode's element case).
                        _serializeBaseContext = savedShallowCopyBaseContext;
                    }

                    _output.Append("</");
                    _output.Append(qname);
                    _output.Append('>');
                }
                break;
            }
            case XdmText text:
                WriteText(text.Value, false);
                break;
            case XdmAttribute attr2:
            {
                // Shallow-copy of attribute: write as attribute (into collected attrs if inside element)
                var attrTarget = _attributeCollecting ? _collectedAttributes! : _output;
                var attrName = !string.IsNullOrEmpty(attr2.Prefix)
                    ? $"{attr2.Prefix}:{attr2.LocalName}"
                    : attr2.LocalName;
                attrTarget.Append(' ');
                attrTarget.Append(attrName);
                attrTarget.Append("=\"");
                attrTarget.Append(EscapeAttributeValue(attr2.Value));
                attrTarget.Append('"');
                break;
            }
            case XdmComment comment:
                _output.Append("<!--");
                _output.Append(EscapeCommentValue(comment.Value));
                _output.Append("-->");
                break;
            case XdmProcessingInstruction pi:
                _output.Append("<?");
                _output.Append(pi.Target);
                if (!string.IsNullOrEmpty(pi.Value))
                {
                    _output.Append(' ');
                    _output.Append(pi.Value);
                }
                _output.Append("?>");
                break;
            case XdmNamespace ns2:
            {
                // Shallow/deep copy: emit namespace declaration
                var nsTarget = _attributeCollecting ? _collectedAttributes! : _output;
                nsTarget.Append(" xmlns");
                if (!string.IsNullOrEmpty(ns2.Prefix))
                {
                    nsTarget.Append(':');
                    nsTarget.Append(ns2.Prefix);
                }
                nsTarget.Append("=\"");
                nsTarget.Append(EscapeAttributeValue(ns2.Uri));
                nsTarget.Append('"');
                break;
            }
            default:
                // XSLT 3.0 §6.7: Function items (maps, arrays, functions) — deep copy (pass through)
                if (node is IDictionary<object, object?> or List<object?> or XQueryFunction)
                {
                    if (_sequenceAccumulator != null)
                        AppendToSeqAccumulator(node);
                    break;
                }
                // Atomic values: output string value (XSLT 3.0 §6.7)
                if (node is not XdmNode)
                    WriteText(StringValueOf(node), false);
                break;
        }
    }

    /// <summary>
    /// Execute a matched template against a single node with full context management.
    /// Used by built-in templates that need to apply templates to individual nodes
    /// (e.g., shallow-copy/shallow-skip processing element attributes).
    /// </summary>
    private async ValueTask ExecuteMatchedTemplateAsync(
        XsltTemplate template, object node, QName? mode, List<XsltWithParam> withParams)
    {
        PushContextItem(node, 1, 1);
        PushCurrentItem(node);
        PushScope();

        // XTDE3480: Clear merge-group context — not available in applied templates
        ClearMergeGroupContext();

        // Propagate tunnel parameters from parent scopes
        foreach (var scope in _scopes.Skip(1))
        {
            foreach (var (name, value) in scope.TunnelParameters)
            {
                if (!_scopes.Peek().TunnelParameters.ContainsKey(name))
                    _scopes.Peek().TunnelParameters[name] = value;
            }
            if (scope.IsTunnelBarrier)
                break;
        }
        foreach (var param in withParams.Where(p => p.Tunnel))
        {
            var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
            _scopes.Peek().TunnelParameters[param.Name] = value;
        }

        // Bind template parameters
        foreach (var param in withParams.Where(p => !p.Tunnel))
        {
            var templateParam = template.Parameters.FirstOrDefault(tp =>
                tp.Name.Equals(param.Name) && !tp.Tunnel);
            if (templateParam != null)
            {
                var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
                if (templateParam.As != null)
                {
                    value = CoerceToType(value, templateParam.As);
                    ValidateValueMatchesType(value, templateParam.As, "XTTE0590",
                        $"Parameter ${param.Name.LocalName}");
                }
                SetVariable(param.Name, value);
            }
        }
        foreach (var param in template.Parameters)
        {
            if (!_scopes.Peek().Variables.ContainsKey(param.Name))
            {
                if (param.Tunnel && TryGetTunnelParam(param.Name, out var tunnelValue))
                {
                    if (param.As != null)
                    {
                        tunnelValue = CoerceToType(tunnelValue, param.As);
                        ValidateValueMatchesType(tunnelValue, param.As, "XTTE0590",
                            $"Parameter ${param.Name.LocalName}");
                    }
                    SetVariable(param.Name, tunnelValue);
                }
                else if (param.Select != null)
                {
                    var defaultVal = await EvaluateAsync(param.Select).ConfigureAwait(false);
                    if (param.As != null)
                    {
                        defaultVal = CoerceToType(defaultVal, param.As);
                        ValidateValueMatchesType(defaultVal, param.As, "XTTE0600",
                            $"Parameter ${param.Name.LocalName} default value");
                    }
                    SetVariable(param.Name, defaultVal);
                }
                else if (param.Content != null)
                {
                    // Accumulator-isolating evaluation — see comment at the helper definition.
                    var defaultVal = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
                    if (param.As != null)
                    {
                        defaultVal = CoerceToType(defaultVal, param.As);
                        ValidateValueMatchesType(defaultVal, param.As, "XTTE0600",
                            $"Parameter ${param.Name.LocalName} default value");
                    }
                    SetVariable(param.Name, defaultVal);
                }
                else
                {
                    // No select, no content, no caller value: default is empty sequence.
                    if (param.As != null && param.As.Occurrence is Occurrence.ExactlyOne or Occurrence.OneOrMore
                        && IsStrictAtomicType(param.As.ItemType))
                        throw Error($"XTDE0700: Required parameter ${param.Name.LocalName} not supplied (type {param.As.ItemType} requires a value)");
                    else if (param.As != null && param.As.Occurrence is Occurrence.ZeroOrOne or Occurrence.ZeroOrMore)
                        SetVariable(param.Name, null);
                    else
                        SetVariable(param.Name, "");
                }
            }
        }

        var savedTemplate = _currentTemplate;
        var savedMode = _currentMode;
        _currentTemplate = template;
        _currentMode = mode;

        if (template.Version != null)
            _effectiveVersionStack.Push(template.Version);
        if (template.DefaultCollation != null)
            _defaultCollationStack.Push(template.DefaultCollation);
        if (template.BaseUri != null)
            _staticBaseUriStack.Push(XsltTransformEngine.UriString(template.BaseUri)!);
        try
        {
            await template.Body.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            if (template.BaseUri != null)
                _staticBaseUriStack.Pop();
            if (template.DefaultCollation != null)
                _defaultCollationStack.Pop();
            if (template.Version != null)
                _effectiveVersionStack.Pop();
            _currentTemplate = savedTemplate;
            _currentMode = savedMode;
            PopScope();
            PopCurrentItem();
            PopContextItem();
        }
    }

    /// <summary>
    /// Matches a streaming node against templates in the given mode and executes
    /// the matched template (or built-in rules). Called by StreamingXmlProcessor
    /// for each node encountered during streaming execution.
    /// </summary>
    /// <summary>
    /// Writes a closing tag for a streaming element whose start tag was deferred.
    /// Called by StreamingXmlProcessor on EndElement events.
    /// </summary>
    internal void WriteStreamingEndTag(string qname)
    {
        _output.Append("</");
        _output.Append(qname);
        _output.Append('>');
    }

    /// <summary>
    /// Matches and executes a template for a streaming node.
    /// Returns true if the matched template suppressed the node (empty body = no output)
    /// OR if execution was deferred — in either case the streaming processor should
    /// treat children as suppressed (no template execution; watchers and accumulators
    /// still fire).
    /// </summary>
    internal async ValueTask<bool> MatchAndExecuteStreamingNodeAsync(XdmNode node, QName? mode, int position)
    {
        // last=0 signals "unknown in streaming mode". The StreamabilityChecker rejects
        // last() in streamable templates, so this value should never be accessed.
        PushContextItem(node, position, 0);
        PushCurrentItem(node);
        PushScope();
        var pushedScope = true;
        try
        {
            XsltTemplate? template;
            using (var mc = AcquireMatchContext())
                template = _templateIndex.FindMatchingTemplate(node, mode, mc.Value);
            if (template != null)
            {
                // Pre-scan template body for snapshot()/copy-of() of the matched subtree.
                // If found, the body needs an in-memory XdmElement (XPath cannot deliver
                // a buffered subtree from the streaming reader). Consume the subtree via
                // XmlReader.ReadSubtree(), parse it into an XdmDocument fragment, and
                // run the body against the parsed root. The processor sees
                // _streamingSubtreeBufferConsumed and skips the now-impossible EndElement
                // bookkeeping (ReadSubtree already advanced the parent reader past it).
                if (_activeStreamingReader != null
                    && node is Xdm.Nodes.XdmElement bufElem
                    && (StreamingSubtreeBufferDetector.RequiresSubtreeBuffer(template.Body)
                        || StreamingSubtreeBufferDetector.RequiresSubtreeBufferForAbsorbingFunctions(
                            template.Body, _stylesheet.Functions)))
                {
                    await ExecuteWithBufferedSubtreeAsync(template, bufElem, mode, position).ConfigureAwait(false);
                    PopScope(); pushedScope = false;
                    PopCurrentItem();
                    PopContextItem();
                    _streamingSubtreeBufferConsumed = true;
                    return true;
                }

                // Pre-scan template body for consuming aggregates (count(*), sum(*), …).
                // If found AND the body doesn't itself call apply-templates (which would
                // consume children directly), DEFER body execution to parent EndElement
                // so watchers can accumulate the consuming-expression results first.
                // Without this deferral, the body evaluates count(*) before any children
                // have been read and gets 0.
                if (_activeStreamingReader != null
                    && node is Xdm.Nodes.XdmElement deferredElem
                    && TryBuildDeferredExecution(template, deferredElem, mode, position) is { } deferredEntry)
                {
                    _streamingDeferredExecutions.Push(deferredEntry);
                    deferredEntry.PriorActiveWatchers = _activeStreamWatchers;
                    _activeStreamWatchers = deferredEntry.Watchers;
                    // Pop the temporary scope/context — the real ones will be re-pushed
                    // when the deferred body executes at parent EndElement.
                    PopScope(); pushedScope = false;
                    PopCurrentItem();
                    PopContextItem();
                    return true; // signal suppression so processor skips child template execution
                }

                // An empty template body in streaming mode means "suppress this element"
                // — skip the element and all its children. Return true so the streaming
                // processor can skip child events.
                var isSuppression = template.Body.Instructions.Count == 0
                    && node is Xdm.Nodes.XdmElement;

                var savedTemplate = _currentTemplate;
                var savedMode = _currentMode;
                _currentTemplate = template;
                _currentMode = mode;

                // Bind template parameters with defaults
                foreach (var param in template.Parameters)
                {
                    if (param.Select != null)
                    {
                        var defaultVal = await EvaluateAsync(param.Select).ConfigureAwait(false);
                        if (param.As != null)
                        {
                            defaultVal = CoerceToType(defaultVal, param.As);
                        }
                        SetVariable(param.Name, defaultVal);
                    }
                    else
                    {
                        SetVariable(param.Name, "");
                    }
                }

                if (template.Version != null)
                    _effectiveVersionStack.Push(template.Version);
                if (template.DefaultCollation != null)
                    _defaultCollationStack.Push(template.DefaultCollation);
                if (template.BaseUri != null)
                    _staticBaseUriStack.Push(XsltTransformEngine.UriString(template.BaseUri)!);
                try
                {
                    await template.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    if (template.BaseUri != null)
                        _staticBaseUriStack.Pop();
                    if (template.DefaultCollation != null)
                        _defaultCollationStack.Pop();
                    if (template.Version != null)
                        _effectiveVersionStack.Pop();
                    _currentTemplate = savedTemplate;
                    _currentMode = savedMode;
                }

                return isSuppression;
            }
            else
            {
                // Phase 2a (#143): streaming built-in DEEP-COPY of an unmatched element.
                // The streamed element is shallow (its children have not yet been read),
                // so serializing it directly would emit just an empty tag while the loop
                // reads the descendants as flat siblings. Instead buffer the whole subtree
                // from the live reader (same materialize + deferred-EndElement contract the
                // snapshot()/copy-of() path uses) and serialize the buffered tree. Setting
                // _streamingSubtreeBufferConsumed tells the processor's loop that the
                // matching EndElement was already consumed, so it skips the ancestor push.
                if (_activeStreamingReader != null
                    && node is Xdm.Nodes.XdmElement deepCopyElem
                    && GetOnNoMatchBehavior(mode) == OnNoMatchBehavior.DeepCopy)
                {
                    var bufferedRoot = StreamingSubtreeMaterializer.Materialize(
                        _activeStreamingReader, _nodeStore!, new DocumentId(0)) ?? deepCopyElem;
                    SerializeElement(bufferedRoot);
                    _streamingSubtreeBufferConsumed = true;
                    return false;
                }
                // Apply built-in template rules
                await ApplyBuiltInTemplateAsync(node, mode, []).ConfigureAwait(false);
            }
        }
        finally
        {
            if (pushedScope)
            {
                PopScope();
                PopCurrentItem();
                PopContextItem();
            }
        }
        return false;
    }

    /// <summary>
    /// Pre-scans <paramref name="template"/>'s body for consuming aggregates that
    /// require deferred execution. Returns a deferred-execution entry when:
    /// <list type="bullet">
    ///   <item>The body has at least one aggregate over a consuming expression
    ///         (count(*), sum(*), string-join(*/text(),', '), etc.); AND</item>
    ///   <item>The body does NOT contain xsl:apply-templates (which would itself
    ///         consume children — incompatible with deferral).</item>
    /// </list>
    /// Returns null when deferral isn't applicable; the caller falls through to
    /// the immediate-execution path.
    /// </summary>
    private DeferredStreamingExecution? TryBuildDeferredExecution(
        Ast.XsltTemplate template, Xdm.Nodes.XdmElement element, QName? mode, int position)
    {
        if (_activeStreamingReader == null) return null;
        var scanner = new StreamingExpressionScanner();
        // Anchor the deferred watchers to the matched element's depth: their paths
        // are relative to the matched template's context node, not the document root.
        var watchers = scanner.Scan(template.Body, _activeStreamingReader.Depth);
        if (watchers.Count == 0) return null;
        if (BodyContainsApplyTemplates(template.Body)) return null;
        return new DeferredStreamingExecution
        {
            Template = template,
            Element = element,
            Mode = mode,
            Position = position,
            ParentDepth = _activeStreamingReader.Depth,
            Watchers = watchers
        };
    }

    /// <summary>
    /// Streaming-mode fallback for templates whose body uses snapshot()/copy-of()
    /// of the matched subtree. Consumes the current element and all its descendants
    /// from <see cref="_activeStreamingReader"/> via <c>ReadSubtree()</c>, parses
    /// the events into an in-memory <see cref="XdmDocument"/> fragment, and runs
    /// the template body against the parsed root. The processor's main loop sees
    /// <see cref="_streamingSubtreeBufferConsumed"/> and skips the matching
    /// EndElement bookkeeping (already consumed by ReadSubtree).
    /// </summary>
    private async ValueTask ExecuteWithBufferedSubtreeAsync(
        Ast.XsltTemplate template, Xdm.Nodes.XdmElement element, QName? mode, int position)
    {
        var reader = _activeStreamingReader!;
        Xdm.Nodes.XdmElement bufferedRoot;
        if (_nodeStore != null)
        {
            // Walk reader events directly into XdmElement/XdmAttribute/XdmText
            // — no string serialize-then-parse round-trip. The materializer leaves
            // the reader positioned at the matched EndElement (or on the empty
            // element if self-closing); the processor's main loop reads past it
            // on the next iteration, so we do NOT set _streamingDeferReadOnNextIteration
            // here (unlike the prior ReadOuterXml path, which advanced too far).
            bufferedRoot = StreamingSubtreeMaterializer.Materialize(reader, _nodeStore, new DocumentId(0))
                           ?? element;
        }
        else
        {
            bufferedRoot = element;
        }

        var savedTemplate = _currentTemplate;
        var savedMode = _currentMode;
        _currentTemplate = template;
        _currentMode = mode;

        PushContextItem(bufferedRoot, position, 1);
        PushCurrentItem(bufferedRoot);
        PushScope();

        foreach (var param in template.Parameters)
        {
            if (param.Select != null)
            {
                var defaultVal = await EvaluateAsync(param.Select).ConfigureAwait(false);
                if (param.As != null)
                    defaultVal = CoerceToType(defaultVal, param.As);
                SetVariable(param.Name, defaultVal);
            }
            else
            {
                SetVariable(param.Name, "");
            }
        }

        if (template.Version != null) _effectiveVersionStack.Push(template.Version);
        if (template.DefaultCollation != null) _defaultCollationStack.Push(template.DefaultCollation);
        if (template.BaseUri != null) _staticBaseUriStack.Push(XsltTransformEngine.UriString(template.BaseUri)!);

        // The subtree is now fully buffered in memory. Clear the streaming flag and
        // the active reader so the body's downward navigation (xsl:apply-templates,
        // xsl:for-each, xsl:iterate — including those inside xsl:fork prongs) runs
        // against the buffered tree instead of trying to drive the already-consumed
        // live reader. Mirrors the subscription-dispatch path in StreamingXmlProcessor.
        var prevStreamingExec = _isStreamingExecution;
        var prevStreamingReader = _activeStreamingReader;
        _isStreamingExecution = false;
        _activeStreamingReader = null;
        try
        {
            await template.Body.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            _isStreamingExecution = prevStreamingExec;
            _activeStreamingReader = prevStreamingReader;
            if (template.BaseUri != null) _staticBaseUriStack.Pop();
            if (template.DefaultCollation != null) _defaultCollationStack.Pop();
            if (template.Version != null) _effectiveVersionStack.Pop();
            _currentTemplate = savedTemplate;
            _currentMode = savedMode;
            PopScope();
            PopCurrentItem();
            PopContextItem();
        }
    }

    /// <summary>
    /// Recursively walks an XsltSequenceConstructor to detect xsl:apply-templates.
    /// Used by <see cref="TryBuildDeferredExecution"/> to disqualify deferral when
    /// the body would consume children itself (deferral is only safe when the body
    /// is purely output + consuming-aggregate evaluations).
    /// </summary>
    private static bool BodyContainsApplyTemplates(Ast.XsltSequenceConstructor? body)
    {
        if (body == null) return false;
        foreach (var insn in body.Instructions)
        {
            if (insn is Ast.XsltApplyTemplates) return true;
            if (insn is Ast.XsltSequenceConstructor child && BodyContainsApplyTemplates(child)) return true;
            if (insn is Ast.XsltLiteralResultElement lre && BodyContainsApplyTemplates(lre.Content)) return true;
            if (insn is Ast.XsltIf ifInsn && BodyContainsApplyTemplates(ifInsn.Then)) return true;
            if (insn is Ast.XsltChoose choose)
            {
                foreach (var w in choose.When)
                    if (BodyContainsApplyTemplates(w.Body)) return true;
                if (BodyContainsApplyTemplates(choose.Otherwise)) return true;
            }
            if (insn is Ast.XsltCopy copy && BodyContainsApplyTemplates(copy.Content)) return true;
        }
        return false;
    }

    /// <summary>
    /// Executes a deferred template body at the parent's EndElement. Called by
    /// <see cref="StreamingXmlProcessor"/> after watcher accumulation completes.
    /// Restores context/scope as if the template were running fresh, executes
    /// the body (consuming-aggregate sub-expressions resolve to the watcher values
    /// via <see cref="TryResolveFromWatchers"/>), then restores the prior
    /// <see cref="_activeStreamWatchers"/> so nested deferred executions stack
    /// cleanly.
    /// </summary>
    internal async ValueTask ExecuteDeferredAsync(DeferredStreamingExecution entry)
    {
        PushContextItem(entry.Element, entry.Position, 0);
        PushCurrentItem(entry.Element);
        PushScope();
        var savedTemplate = _currentTemplate;
        var savedMode = _currentMode;
        _currentTemplate = entry.Template;
        _currentMode = entry.Mode;
        try
        {
            // Bind template parameters with defaults (mirrors MatchAndExecuteStreamingNodeAsync)
            foreach (var param in entry.Template.Parameters)
            {
                if (param.Select != null)
                {
                    var defaultVal = await EvaluateAsync(param.Select).ConfigureAwait(false);
                    if (param.As != null)
                        defaultVal = CoerceToType(defaultVal, param.As);
                    SetVariable(param.Name, defaultVal);
                }
                else
                {
                    SetVariable(param.Name, "");
                }
            }
            if (entry.Template.Version != null)
                _effectiveVersionStack.Push(entry.Template.Version);
            if (entry.Template.DefaultCollation != null)
                _defaultCollationStack.Push(entry.Template.DefaultCollation);
            if (entry.Template.BaseUri != null)
                _staticBaseUriStack.Push(XsltTransformEngine.UriString(entry.Template.BaseUri)!);
            try
            {
                await entry.Template.Body.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                if (entry.Template.BaseUri != null) _staticBaseUriStack.Pop();
                if (entry.Template.DefaultCollation != null) _defaultCollationStack.Pop();
                if (entry.Template.Version != null) _effectiveVersionStack.Pop();
            }
        }
        finally
        {
            _currentTemplate = savedTemplate;
            _currentMode = savedMode;
            PopScope();
            PopCurrentItem();
            PopContextItem();
            _activeStreamWatchers = entry.PriorActiveWatchers;
        }
    }

    private async ValueTask ApplyBuiltInDeepCopyAsync(object node, QName? mode, List<XsltWithParam> withParams)
    {
        // Deep copy: serialize the entire node subtree
        switch (node)
        {
            case XdmDocument:
                // In streaming mode, child recursion is handled by the streaming loop.
                if (!_isStreamingExecution)
                    await ApplyTemplatesAsync(null, mode, [], withParams).ConfigureAwait(false);
                break;
            case XdmElement elem:
                SerializeElement(elem);
                break;
            case XdmText text:
                WriteText(text.Value, false);
                break;
            case XdmAttribute attr:
            {
                // Deep-copy of attribute: write as attribute (into collected attrs if inside element)
                var attrTarget = _attributeCollecting ? _collectedAttributes! : _output;
                var attrName = !string.IsNullOrEmpty(attr.Prefix)
                    ? $"{attr.Prefix}:{attr.LocalName}"
                    : attr.LocalName;
                attrTarget.Append(' ');
                attrTarget.Append(attrName);
                attrTarget.Append("=\"");
                attrTarget.Append(EscapeAttributeValue(attr.Value));
                attrTarget.Append('"');
                break;
            }
            case XdmComment comment:
                _output.Append("<!--");
                _output.Append(EscapeCommentValue(comment.Value));
                _output.Append("-->");
                break;
            case XdmProcessingInstruction pi:
                _output.Append("<?");
                _output.Append(pi.Target);
                if (!string.IsNullOrEmpty(pi.Value))
                {
                    _output.Append(' ');
                    _output.Append(pi.Value);
                }
                _output.Append("?>");
                break;
            case XdmNamespace ns3:
            {
                // Deep copy: emit namespace declaration
                var nsTarget3 = _attributeCollecting ? _collectedAttributes! : _output;
                nsTarget3.Append(" xmlns");
                if (!string.IsNullOrEmpty(ns3.Prefix))
                {
                    nsTarget3.Append(':');
                    nsTarget3.Append(ns3.Prefix);
                }
                nsTarget3.Append("=\"");
                nsTarget3.Append(EscapeAttributeValue(ns3.Uri));
                nsTarget3.Append('"');
                break;
            }
            default:
                // XSLT 3.0 §6.7: Function items (maps, arrays, functions) — deep copy (pass through)
                if (node is IDictionary<object, object?> or List<object?> or XQueryFunction)
                {
                    if (_sequenceAccumulator != null)
                        AppendToSeqAccumulator(node);
                    break;
                }
                // Atomic values: output string value (XSLT 3.0 §6.7)
                if (node is not XdmNode)
                    WriteText(StringValueOf(node), false);
                break;
        }
    }

    private void SerializeElement(XdmElement elem)
    {
        var nsUri = _nodeStore?.GetNamespaceUri(elem.Namespace) ?? "";
        var prefix = elem.Prefix ?? "";
        var localName = elem.LocalName;
        var qname = !string.IsNullOrEmpty(prefix) ? $"{prefix}:{localName}" : localName;

        _output.Append('<');
        _output.Append(qname);

        // Namespace declarations
        foreach (var nsDecl in elem.NamespaceDeclarations)
        {
            var nsDeclUri = _nodeStore?.GetNamespaceUri(nsDecl.Namespace) ?? "";
            var nsDeclPrefix = nsDecl.Prefix ?? "";
            if (string.IsNullOrEmpty(nsDeclPrefix))
            {
                _output.Append(" xmlns=\"");
                _output.Append(EscapeAttributeValue(nsDeclUri));
                _output.Append('"');
            }
            else
            {
                _output.Append(" xmlns:");
                _output.Append(nsDeclPrefix);
                _output.Append("=\"");
                _output.Append(EscapeAttributeValue(nsDeclUri));
                _output.Append('"');
            }
        }

        // Attributes and then child nodes
        if (_nodeStore != null)
        {
            // Element attributes live in elem.Attributes, NOT in GetChildren(elem)
            // (which yields only element/text/comment/PI children). Emit them here so a
            // deep-copied element retains its attributes (e.g. <record id="a">). The
            // legacy "child is XdmAttribute" guard below is kept defensively for any
            // store shape that threads attributes through the child list.
            foreach (var attr in _nodeStore.GetAttributes(elem))
            {
                var attrPrefix0 = attr.Prefix ?? "";
                var attrName0 = !string.IsNullOrEmpty(attrPrefix0)
                    ? $"{attrPrefix0}:{attr.LocalName}"
                    : attr.LocalName;
                _output.Append(' ');
                _output.Append(attrName0);
                _output.Append("=\"");
                _output.Append(EscapeAttributeValue(attr.Value));
                _output.Append('"');
            }
            var childElements = new List<XdmNode>();
            foreach (var child in _nodeStore.GetChildren(elem))
            {
                if (child is XdmAttribute attr)
                {
                    var attrPrefix = attr.Prefix ?? "";
                    var attrName = !string.IsNullOrEmpty(attrPrefix)
                        ? $"{attrPrefix}:{attr.LocalName}"
                        : attr.LocalName;
                    _output.Append(' ');
                    _output.Append(attrName);
                    _output.Append("=\"");
                    _output.Append(EscapeAttributeValue(attr.Value));
                    _output.Append('"');
                }
                else
                {
                    childElements.Add(child);
                }
            }
            _output.Append('>');
            foreach (var child in childElements)
            {
                switch (child)
                {
                    case XdmElement childElem:
                        SerializeElement(childElem);
                        break;
                    case XdmText text:
                        WriteText(text.Value, false);
                        break;
                    case XdmComment comment:
                        _output.Append("<!--");
                        _output.Append(EscapeCommentValue(comment.Value));
                        _output.Append("-->");
                        break;
                    case XdmProcessingInstruction pi:
                        _output.Append("<?");
                        _output.Append(pi.Target);
                        if (!string.IsNullOrEmpty(pi.Value))
                        {
                            _output.Append(' ');
                            _output.Append(pi.Value);
                        }
                        _output.Append("?>");
                        break;
                }
            }
        }
        else
        {
            _output.Append('>');
        }

        _output.Append("</");
        _output.Append(qname);
        _output.Append('>');
    }

    /// <summary>
    /// Parses a ResultTreeFragment (temporary tree) into an XDM document node.
    /// This allows RTFs to be processed by apply-templates.
    /// </summary>
    private XdmDocument? ParseResultTreeFragment(ResultTreeFragment rtf)
    {
        if (_nodeStore == null)
            return null;

        // Return cached parse result to preserve node identity across accesses
        if (rtf.CachedDocumentNode is XdmDocument cached)
            return cached;

        try
        {
            var xmlDoc = new System.Xml.XmlDocument();
            xmlDoc.PreserveWhitespace = true;
            // Wrap in a root element if the RTF is a fragment (multiple root elements or text at root)
            var content = rtf.XmlContent;
            var wasWrapped = false;
            try
            {
                xmlDoc.LoadXml(content);
            }
            catch (System.Xml.XmlException)
            {
                // Fragment - wrap in temporary root
                xmlDoc.LoadXml($"<_rtf_root_>{content}</_rtf_root_>");
                wasWrapped = true;
            }

            var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, _nodeStore, documentUri: null);
            // Temporary trees have no document URI per XSLT 3.0 §11.9.1,
            // but need BaseUri for base-uri() resolution.
            xdmDoc.DocumentUri = null;
            xdmDoc.BaseUri = rtf.BaseUri;

            // If we wrapped in _rtf_root_, unwrap by promoting its children to be
            // direct children of the document node. This allows XPath like $var/*
            // to return the actual content elements, not the artificial wrapper.
            if (wasWrapped && xdmDoc.DocumentElement.HasValue && xdmDoc.DocumentElement.Value != NodeId.None)
            {
                var wrapperElem = _nodeStore.GetNode(xdmDoc.DocumentElement.Value) as XdmElement;
                if (wrapperElem != null && wrapperElem.LocalName == "_rtf_root_")
                {
                    // Reparent _rtf_root_'s children to the document
                    var newChildren = new List<NodeId>();
                    foreach (var childId in _nodeStore.GetChildren(wrapperElem).Select(c => c.Id))
                    {
                        newChildren.Add(childId);
                    }

                    // Find the first element child for DocumentElement
                    var newDocElemId = NodeId.None;
                    string? newDocElemLocalName = null;
                    foreach (var childId in newChildren)
                    {
                        if (_nodeStore.GetNode(childId) is XdmElement docElem)
                        {
                            newDocElemId = childId;
                            newDocElemLocalName = docElem.LocalName;
                            break;
                        }
                    }

                    // Create an updated document with unwrapped children
                    // Compute string value as concatenation of all text descendant values
                    var svBuilder = new System.Text.StringBuilder();
                    foreach (var childId in newChildren)
                    {
                        CollectStringValue(childId, svBuilder);
                    }

                    var newDoc = new XdmDocument
                    {
                        Id = xdmDoc.Id,
                        Document = xdmDoc.Document,
                        Parent = xdmDoc.Parent,
                        DocumentElement = newDocElemId,
                        DocumentUri = null, // RTFs have no document URI
                        Children = newChildren,
                        DocumentElementLocalName = newDocElemLocalName
                    };
                    newDoc.BaseUri = rtf.BaseUri;
                    newDoc._stringValue = svBuilder.ToString();
                    _nodeStore.Register(newDoc); // Overwrites the old registration
                    rtf.CachedDocumentNode = newDoc;
                    return newDoc;
                }
            }

            rtf.CachedDocumentNode = xdmDoc;
            return xdmDoc;
        }
        catch (System.Xml.XmlException)
        {
            // Invalid XML content - cannot parse RTF
            return null;
        }
    }

    /// <summary>
    /// Recursively collects text content from a node and its descendants.
    /// </summary>
    private void CollectStringValue(NodeId nodeId, System.Text.StringBuilder sb)
    {
        var node = _nodeStore?.GetNode(nodeId);
        if (node is XdmText text)
            sb.Append(text.Value);
        else if (node is XdmElement elem)
        {
            foreach (var child in _nodeStore!.GetChildren(elem))
                CollectStringValue(child.Id, sb);
        }
    }

    /// <summary>
    /// Converts ResultTreeFragment values to XDM documents for XQuery evaluation.
    /// This allows XPath expressions like $var/path to navigate into RTFs.
    /// </summary>
    internal object? ConvertRtfForXQuery(object? value)
    {
        if (value is ResultTreeFragment rtf)
        {
            var doc = ParseResultTreeFragment(rtf);
            return doc ?? value; // Return original if parsing fails
        }

        if (value is object?[] arr)
        {
            var converted = new object?[arr.Length];
            for (int i = 0; i < arr.Length; i++)
            {
                converted[i] = ConvertRtfForXQuery(arr[i]);
            }
            return converted;
        }

        if (value is LazyValue)
        {
            // Don't convert lazy values - they'll be converted when evaluated
            return value;
        }

        return value;
    }

    public override async ValueTask CallTemplateAsync(QName name, List<XsltWithParam> withParams)
    {
        // Trace: call-template
        if (_options?.TraceListener != null)
            _options.TraceListener(_templateDepth, "call-template", name.LocalName);

        CheckResourceLimits();
        if (_recursionDepth >= MaxRecursionDepth)
            return;

        XsltTemplate? template;

        // xsl:original resolution — call the overridden template from a package
        if (name.LocalName == "original" && name.Namespace == NamespaceId.Xslt)
        {
            // Look for the original template in the current template stack
            template = null;
            if (_currentTemplateStack.Count > 0)
            {
                var currentTemplate = _currentTemplateStack.Peek();
                template = currentTemplate.OriginalTemplate;
            }
            if (template == null)
                throw Error("XTDE3058: xsl:original invoked but no overridden template is available");
        }
        else if (!_stylesheet.NamedTemplates.TryGetValue(name, out template))
        {
            throw Error($"Named template '{name.LocalName}' not found");
        }

        // Pre-evaluate ALL with-param values in the CALLING context before pushing scope.
        // This prevents parameter cross-contamination where a later param sees the value
        // of an earlier param that was already bound in the new scope.
        var preEvaluatedParams = new Dictionary<QName, object?>();
        foreach (var wp in withParams)
        {
            preEvaluatedParams[wp.Name] = await EvaluateWithParamAsync(wp).ConfigureAwait(false);
        }

        // Enforce xsl:context-item constraints
        var makeContextAbsent = EnforceContextItemConstraint(template);

        _recursionDepth++;
        _currentTemplateStack.Push(template);
        PushScope();

        try
        {
            // XTDE3480: Clear merge-group context — not available in called templates
            ClearMergeGroupContext();

            // If use="absent" or optional type mismatch, make context item absent
            if (template.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

            // Forward inherited tunnel parameters from parent scopes.
            // NOTE: Only store in TunnelParameters, NOT as variables.
            // Variables are bound later based on each template param's tunnel flag.
            foreach (var scope in _scopes.Skip(1))
            {
                foreach (var (tName, tValue) in scope.TunnelParameters)
                {
                    if (!_scopes.Peek().TunnelParameters.ContainsKey(tName))
                    {
                        _scopes.Peek().TunnelParameters[tName] = tValue;
                    }
                }
                if (scope.IsTunnelBarrier)
                    break;
            }

            // Track explicitly provided tunnel params (using pre-evaluated values)
            foreach (var wp in withParams.Where(p => p.Tunnel))
            {
                var value = preEvaluatedParams[wp.Name];
                _scopes.Peek().TunnelParameters[wp.Name] = value;
            }

            // Bind parameters (using pre-evaluated values)
            foreach (var param in template.Parameters)
            {
                var withParam = withParams.FirstOrDefault(p => p.Name.Equals(param.Name) && !p.Tunnel);

                if (withParam != null && !param.Tunnel)
                {
                    // Non-tunnel with-param binds only to non-tunnel template param
                    var value = preEvaluatedParams[withParam.Name];
                    if (param.As != null)
                    {
                        value = CoerceToType(value, param.As);
                        ValidateValueMatchesType(value, param.As, "XTTE0590",
                            $"Parameter ${param.Name.LocalName}");
                    }
                    SetVariable(param.Name, value);
                }
                else if (param.Tunnel && TryGetTunnelParam(param.Name, out var tunnelValue))
                {
                    if (param.As != null)
                    {
                        tunnelValue = CoerceToType(tunnelValue, param.As);
                        ValidateValueMatchesType(tunnelValue, param.As, "XTTE0590",
                            $"Parameter ${param.Name.LocalName}");
                    }
                    SetVariable(param.Name, tunnelValue);
                }
                else if (param.Required)
                {
                    throw Error($"Required parameter ${param.Name.LocalName} not supplied");
                }
                else if (param.Select != null)
                {
                    var value = await EvaluateAsync(param.Select).ConfigureAwait(false);
                    if (param.As != null)
                    {
                        value = CoerceToType(value, param.As);
                        ValidateValueMatchesType(value, param.As, "XTTE0600",
                            $"Parameter ${param.Name.LocalName} default value");
                    }
                    SetVariable(param.Name, value);
                }
                else if (param.Content != null)
                {
                    // Accumulator-isolating evaluation — see comment at the helper definition.
                    var value = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
                    if (param.As != null)
                    {
                        value = CoerceToType(value, param.As);
                        ValidateValueMatchesType(value, param.As, "XTTE0600",
                            $"Parameter ${param.Name.LocalName} default value");
                    }
                    SetVariable(param.Name, value);
                }
                else
                {
                    // No select, no content, no with-param: default is empty sequence.
                    if (param.As != null && param.As.Occurrence is Occurrence.ExactlyOne or Occurrence.OneOrMore
                        && IsStrictAtomicType(param.As.ItemType))
                        throw Error($"XTDE0700: Required parameter ${param.Name.LocalName} not supplied (type {param.As.ItemType} requires a value)");
                    else if (param.As != null && param.As.Occurrence is Occurrence.ZeroOrOne or Occurrence.ZeroOrMore)
                        SetVariable(param.Name, null);
                    else
                        SetVariable(param.Name, "");
                }
            }

            // XTSE0680: In XSLT 2.0+, passing a non-tunnel parameter that the template doesn't declare,
            // or that matches a tunnel param, is a static error.
            // Note: tunnel with-params matching non-tunnel params are NOT errors — they pass through.
            if (!IsBackwardsCompatible)
            {
                foreach (var wp in withParams.Where(p => !p.Tunnel))
                {
                    var matchingParam = template.Parameters.FirstOrDefault(p => p.Name.Equals(wp.Name));
                    if (matchingParam == null)
                        throw Error($"XTSE0680: Parameter '{wp.Name.LocalName}' is not declared in the called template '{name.LocalName}'");
                    if (matchingParam.Tunnel)
                        throw Error($"XTSE0680: Non-tunnel parameter '{wp.Name.LocalName}' in xsl:call-template does not match tunnel parameter in template '{name.LocalName}'");
                }
            }

            if (template.Version != null)
                _effectiveVersionStack.Push(template.Version);
            if (template.DefaultCollation != null)
                _defaultCollationStack.Push(template.DefaultCollation);
            if (template.BaseUri != null)
                _staticBaseUriStack.Push(XsltTransformEngine.UriString(template.BaseUri)!);
            try
            {
                // Execute template body, capturing output for type checking if 'as' is declared
                if (template.As != null)
                {
                    var savedAccum = _sequenceAccumulator;
                    var savedCapture = _currentAsBodyCapture;
                    var savedLen = _output.Length;
                    var bodyAccum = new List<object?>();
                    _sequenceAccumulator = bodyAccum;
                    _currentAsBodyCapture = new AsBodyCapture { Accumulator = bodyAccum, OutputBaseLen = savedLen };
                    await template.Body.ExecuteAsync(this).ConfigureAwait(false);
                    var bodyOutput = _output.ToString(savedLen, _output.Length - savedLen);
                    _output.Length = savedLen;
                    var bodyCapture = _currentAsBodyCapture;
                    _currentAsBodyCapture = savedCapture;

                    // Reassemble in document order: parse `bodyOutput` into top-level XDM nodes,
                    // then weave accumulator items in at the offsets recorded when each was added.
                    var resultItems = AssembleAsBodyResultItems(bodyOutput, bodyCapture.Accumulator, bodyCapture.Positions);
                    // Track whether results are only from body serialization
                    // (no sequence accumulator items). When true, emit bodyOutput
                    // directly to preserve exact namespace declarations (e.g. xmlns=""
                    // from inherit-namespaces="no") and disable-output-escaping text
                    // that would be lost by XDM re-serialization round-trip.
                    bool canEmitBodyDirectly2 = bodyCapture.Accumulator.Count == 0
                        && !string.IsNullOrEmpty(bodyOutput);

                    _sequenceAccumulator = savedAccum;

                    // XTTE0505: Validate template return value against 'as' type
                    ValidateTemplateReturnType(template, resultItems);

                    // Re-output validated items: if the outer context is collecting
                    // individual items (e.g. another template with 'as'), preserve them
                    // in the accumulator. Otherwise serialize to _output.
                    if (resultItems.Count > 0)
                    {
                        if (_sequenceAccumulator != null)
                        {
                            // When the outer scope is itself an `as=` body capture, each
                            // item we forward records its position via AppendToSeqAccumulator
                            // so the outer reassembly can interleave correctly.
                            foreach (var item in resultItems)
                                AppendToSeqAccumulator(item);
                        }
                        else if (canEmitBodyDirectly2)
                        {
                            // Append bodyOutput directly to preserve DOE text,
                            // xmlns="" undeclarations, and other serialization details
                            // that would be lost by XDM round-trip re-serialization.
                            _output.Append(bodyOutput);
                            _lastResultWasAtomic = false;
                        }
                        else
                        {
                            SerializeSequenceItems(resultItems);
                        }
                    }
                }
                else
                {
                    await template.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
            }
            finally
            {
                if (template.BaseUri != null)
                    _staticBaseUriStack.Pop();
                if (template.DefaultCollation != null)
                    _defaultCollationStack.Pop();
                if (template.Version != null)
                    _effectiveVersionStack.Pop();
            }
        }
        finally
        {
            if (template.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                PopContextItem();
            PopScope();
            _currentTemplateStack.Pop();
            _recursionDepth--;
        }
    }

    public override async ValueTask ApplyImportsAsync(List<XsltWithParam> withParams)
    {
        CheckResourceLimits();
        // XTDE0560: apply-imports requires a current template rule
        if (_currentTemplate == null)
            throw Error("XTDE0560: xsl:apply-imports can only be used when there is a current template rule");
        var node = ContextItem;
        // XTDE0560: apply-imports requires a context item (fails when context-item use="absent")
        if (node == null || ReferenceEquals(node, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
            throw Error("XTDE0560: xsl:apply-imports requires a context item, but the context item is absent");

        // apply-imports searches only templates from imported stylesheets
        // (lower precedence than the module containing the current template).
        // This differs from next-match which searches all templates in priority order.
        var ownerIndex = _templateIndex.FindOwnerIndex(_currentTemplate);
        XsltTemplate? importedTemplate;
        using (var mc = AcquireMatchContext())
            importedTemplate = ownerIndex?.FindImportedTemplate(node, _currentMode, mc.Value);

        if (importedTemplate != null)
        {
            PushScope();
            try
            {
                // Propagate tunnel parameters from parent scopes
                foreach (var scope in _scopes.Skip(1))
                {
                    foreach (var (tName, tValue) in scope.TunnelParameters)
                    {
                        if (!_scopes.Peek().TunnelParameters.ContainsKey(tName))
                            _scopes.Peek().TunnelParameters[tName] = tValue;
                    }
                    if (scope.IsTunnelBarrier)
                        break;
                }

                // Store explicit tunnel with-params
                foreach (var param in withParams.Where(p => p.Tunnel))
                {
                    var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
                    _scopes.Peek().TunnelParameters[param.Name] = value;
                }

                // Bind non-tunnel with-params to non-tunnel template params
                foreach (var param in withParams.Where(p => !p.Tunnel))
                {
                    var tp = importedTemplate.Parameters.FirstOrDefault(t =>
                        t.Name.Equals(param.Name) && !t.Tunnel);
                    if (tp != null)
                    {
                        var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
                        SetVariable(param.Name, value);
                    }
                }

                foreach (var p in importedTemplate.Parameters)
                {
                    if (!_scopes.Peek().Variables.ContainsKey(p.Name))
                    {
                        if (p.Tunnel && TryGetTunnelParam(p.Name, out var tunnelValue))
                        {
                            SetVariable(p.Name, tunnelValue);
                        }
                        else if (p.Select != null)
                        {
                            var value = await EvaluateAsync(p.Select).ConfigureAwait(false);
                            SetVariable(p.Name, value);
                        }
                    }
                }

                var savedTemplate = _currentTemplate;
                _currentTemplate = importedTemplate;
                if (importedTemplate.Version != null)
                    _effectiveVersionStack.Push(importedTemplate.Version);
                if (importedTemplate.DefaultCollation != null)
                    _defaultCollationStack.Push(importedTemplate.DefaultCollation);
                try
                {
                    await importedTemplate.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    if (importedTemplate.DefaultCollation != null)
                        _defaultCollationStack.Pop();
                    if (importedTemplate.Version != null)
                        _effectiveVersionStack.Pop();
                }
                _currentTemplate = savedTemplate;
            }
            finally
            {
                PopScope();
            }
        }
        else
        {
            // No matching imported template - apply built-in template rule
            await ApplyBuiltInTemplateAsync(node, _currentMode, withParams).ConfigureAwait(false);
        }
    }

    public override async ValueTask NextMatchAsync(List<XsltWithParam> withParams, XsltSequenceConstructor? fallback)
    {
        CheckResourceLimits();
        // XTDE0560: next-match requires a current template rule
        if (_currentTemplate == null)
            throw Error("XTDE0560: xsl:next-match can only be used when there is a current template rule");
        var node = ContextItem;
        // XTDE0560: next-match requires a context item (fails when context-item use="absent")
        if (node == null || ReferenceEquals(node, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
        {
            throw Error("XTDE0560: xsl:next-match requires a context item, but the context item is absent");
        }

        XsltTemplate? nextTemplate;
        using (var mc = AcquireMatchContext())
            nextTemplate = _templateIndex.FindMatchingTemplate(node, _currentMode, mc.Value, _currentTemplate);

        if (nextTemplate != null)
        {
            // Enforce xsl:context-item constraints
            var makeContextAbsent = EnforceContextItemConstraint(nextTemplate);

            PushScope();
            try
            {
                // If use="absent" or optional type mismatch, push absent focus
                if (nextTemplate.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                    PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

                // Propagate tunnel parameters from parent scopes
                foreach (var scope in _scopes.Skip(1))
                {
                    foreach (var (tName, tValue) in scope.TunnelParameters)
                    {
                        if (!_scopes.Peek().TunnelParameters.ContainsKey(tName))
                            _scopes.Peek().TunnelParameters[tName] = tValue;
                    }
                    if (scope.IsTunnelBarrier)
                        break;
                }

                // Store explicit tunnel with-params
                foreach (var param in withParams.Where(p => p.Tunnel))
                {
                    var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
                    _scopes.Peek().TunnelParameters[param.Name] = value;
                }

                // Bind non-tunnel with-params to non-tunnel template params
                foreach (var param in withParams.Where(p => !p.Tunnel))
                {
                    var tp = nextTemplate.Parameters.FirstOrDefault(t =>
                        t.Name.Equals(param.Name) && !t.Tunnel);
                    if (tp != null)
                    {
                        var value = await EvaluateWithParamAsync(param).ConfigureAwait(false);
                        SetVariable(param.Name, value);
                    }
                }

                // Bind template parameters with defaults
                foreach (var param in nextTemplate.Parameters)
                {
                    if (!_scopes.Peek().Variables.ContainsKey(param.Name))
                    {
                        if (param.Tunnel && TryGetTunnelParam(param.Name, out var tunnelValue))
                        {
                            SetVariable(param.Name, tunnelValue);
                        }
                        else if (param.Select != null)
                        {
                            var value = await EvaluateAsync(param.Select).ConfigureAwait(false);
                            SetVariable(param.Name, value);
                        }
                    }
                }

                var savedTemplate = _currentTemplate;
                _currentTemplate = nextTemplate;
                if (nextTemplate.Version != null)
                    _effectiveVersionStack.Push(nextTemplate.Version);
                if (nextTemplate.DefaultCollation != null)
                    _defaultCollationStack.Push(nextTemplate.DefaultCollation);
                try
                {
                    await nextTemplate.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    if (nextTemplate.DefaultCollation != null)
                        _defaultCollationStack.Pop();
                    if (nextTemplate.Version != null)
                        _effectiveVersionStack.Pop();
                }
                _currentTemplate = savedTemplate;
            }
            finally
            {
                if (nextTemplate.ContextItemUse == ContextItemUse.Absent || makeContextAbsent)
                    PopContextItem();
                PopScope();
            }
        }
        else
        {
            // No matching template found - apply built-in template rule
            // Note: xsl:fallback is NOT executed since we support xsl:next-match
            await ApplyBuiltInTemplateAsync(node, _currentMode, withParams).ConfigureAwait(false);
        }
    }

    /// <summary>
    /// SM-ctx (OP-bucket phase 1) streaming handoff for a consuming simple-map
    /// <c>LEFT ! RIGHT</c> in an <c>xsl:value-of</c>/<c>xsl:sequence</c> select. When the
    /// select is the SimpleMap whose RIGHT was registered as an inline-driven
    /// <see cref="ForEachSubscription.PerItemSelect"/> on the active streaming processor
    /// (and the live reader has not yet been consumed), hand off to the processor's
    /// forward pass: it drives the reader, matches the subscription's LEFT path, and for
    /// each matched item materializes it and evaluates RIGHT in place into the
    /// currently-open output. Mirrors the wrapped-for-each handoff in
    /// <see cref="ForEachAsync"/>. Returns true when the handoff fired (caller returns).
    /// </summary>
    private async ValueTask<bool> TryHandoffSimpleMapContextStreamingAsync(XQueryExpression? select)
    {
        if (_activeStreamingProcessor == null || _activeStreamingReader == null)
            return false;
        if (select is not SimpleMapExpression sm)
            return false;
        var subs = _activeStreamingProcessor.Subscriptions;
        if (subs == null)
            return false;

        ForEachSubscription? matchSub = null;
        foreach (var s in subs)
        {
            if (s.InlineDriven && s.PerItemSelect != null
                && ReferenceEquals(s.PerItemSelect, sm.Right))
            {
                matchSub = s;
                break;
            }
        }
        if (matchSub == null)
            return false;

        var proc = _activeStreamingProcessor;
        var rdr = _activeStreamingReader;
        var ct = _activeStreamingCancellationToken;
        // Clear the handles so the per-match RIGHT evaluation (which runs against the
        // buffered materialized snapshot, not the live reader) doesn't re-enter here.
        _activeStreamingProcessor = null;
        _activeStreamingReader = null;
        try
        {
            await proc.ProcessAsync(rdr, ct).ConfigureAwait(false);
        }
        finally
        {
            _activeStreamingProcessor = proc;
            _activeStreamingReader = rdr;
        }
        return true;
    }

    /// <summary>
    /// ForExpr streaming handoff (sx-ForExpr): when <paramref name="select"/> is a
    /// <c>for $x in CONSUMING-PATH return EXPR</c> registered as an inline-driven
    /// subscription on the active streaming processor, drive the forward pass in place so
    /// the surrounding LRE is emitted around the concatenated per-item results. Mirrors
    /// <see cref="TryHandoffSimpleMapContextStreamingAsync"/>. Returns true when fired.
    /// </summary>
    private async ValueTask<bool> TryHandoffForExpressionStreamingAsync(XQueryExpression? select)
    {
        if (_activeStreamingProcessor == null || _activeStreamingReader == null)
            return false;
        if (select is not PhoenixmlDb.XQuery.Ast.FlworExpression flwor)
            return false;
        var subs = _activeStreamingProcessor.Subscriptions;
        if (subs == null)
            return false;

        ForEachSubscription? matchSub = null;
        foreach (var s in subs)
        {
            if (s.InlineDriven && s.RangeVariable != null
                && ReferenceEquals(s.PerItemSelect, flwor.ReturnExpression))
            {
                matchSub = s;
                break;
            }
        }
        if (matchSub == null)
            return false;

        var proc = _activeStreamingProcessor;
        var rdr = _activeStreamingReader;
        var ct = _activeStreamingCancellationToken;
        // Clear the handles so the per-match return evaluation (against the buffered
        // snapshot, not the live reader) doesn't re-enter here.
        _activeStreamingProcessor = null;
        _activeStreamingReader = null;
        try
        {
            await proc.ProcessAsync(rdr, ct).ConfigureAwait(false);
        }
        finally
        {
            _activeStreamingProcessor = proc;
            _activeStreamingReader = rdr;
        }
        return true;
    }

    public override async ValueTask ForEachAsync(
        XQueryExpression select,
        List<XsltSort> sorts,
        XsltSequenceConstructor body)
    {
        // Wrapped (inline-driven) streamable for-each handoff: when this for-each is
        // the source instruction of an inline-driven subscription registered on the
        // active streaming processor, and the live reader has not yet been consumed
        // (the body is running linearly so the enclosing construction has already been
        // emitted), hand off to the processor's forward pass. It drives the reader,
        // matches the subscription's path, and dispatches THIS for-each body per match
        // into the currently-open output. On return, linear execution continues and
        // emits the construction's close tag — so the wrapper survives. Mirrors the
        // apply-templates streaming intercept below.
        if (_activeStreamingProcessor != null && _activeStreamingReader != null
            && sorts.Count == 0)
        {
            var subs = _activeStreamingProcessor.Subscriptions;
            if (subs != null)
            {
                ForEachSubscription? matchSub = null;
                foreach (var s in subs)
                {
                    if (s.InlineDriven && s.SourceInstruction != null
                        && ReferenceEquals(s.SourceInstruction.Body, body))
                    {
                        matchSub = s;
                        break;
                    }
                }
                if (matchSub != null)
                {
                    var proc = _activeStreamingProcessor;
                    var rdr = _activeStreamingReader;
                    var ct = _activeStreamingCancellationToken;
                    // Clear the handles so the body dispatched per-match doesn't
                    // re-enter this handoff (the for-each body runs against buffered
                    // snapshots, not the live reader).
                    _activeStreamingProcessor = null;
                    _activeStreamingReader = null;
                    try
                    {
                        await proc.ProcessAsync(rdr, ct).ConfigureAwait(false);
                    }
                    finally
                    {
                        _activeStreamingProcessor = proc;
                        _activeStreamingReader = rdr;
                    }
                    return;
                }
            }
        }

        // Streaming: when inside a streamable template with a consuming child-axis
        // select, drive the reader directly instead of pre-evaluating select.
        // Mirrors the apply-templates streaming intercept above. Sorts are not
        // applicable in this path (a sort would force materialization, defeating
        // streaming) — fall back to the buffered impl if sorts are present.
        if (_isStreamingExecution && _activeStreamingReader != null
            && sorts.Count == 0 && IsConsumingChildSelect(select))
        {
            await ForEachStreamingAsync(body).ConfigureAwait(false);
            return;
        }

        // Fast path for range expressions (1 to N) without sorts — avoid boxing N integers
        if (select is PhoenixmlDb.XQuery.Ast.RangeExpression rangeExpr && sorts.Count == 0)
        {
            var startVal = await EvaluateAsync(rangeExpr.Start).ConfigureAwait(false);
            var endVal = await EvaluateAsync(rangeExpr.End).ConfigureAwait(false);
            if (startVal != null && endVal != null)
            {
                var s = Convert.ToInt64(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(startVal), CultureInfo.InvariantCulture);
                var e = Convert.ToInt64(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(endVal), CultureInfo.InvariantCulture);
                var count = (int)Math.Max(0, e - s + 1);
                // Check if range body is trivially empty (e.g., xsl:if with always-false test)
                // In that case, skip the entire loop — just set position context for the end
                if (!RangeBodyHasEffect(body, count))
                {
                    // No observable effect — skip entire loop
                }
                else
                {
                    // Use a single shared scope for the entire range loop to avoid N dictionary allocations.
                    PushScope();
                    var savedTemplate = _currentTemplate;
                    _currentTemplate = null;
                    // Per XSLT 3.0 §13.4.1, xsl:for-each does NOT change the current mode.
                    // Only the current template rule is absent inside xsl:for-each (XTDE0560).
                    // `mode="#current"` on a nested xsl:apply-templates must still see the
                    // enclosing template's mode.
                    try
                    {
                        for (var i = s; i <= e; i++)
                        {
                            if ((i - s) % 4096 == 0) CheckResourceLimits();
                            var position = (int)(i - s + 1);
                            PushContextItem(i, position, count);
                            PushCurrentItem(i);
                            try
                            {
                                await body.ExecuteAsync(this).ConfigureAwait(false);
                            }
                            finally
                            {
                                PopCurrentItem();
                                PopContextItem();
                            }
                        }
                    }
                    finally
                    {
                        _currentTemplate = savedTemplate;
                        PopScope();
                    }
                }
                return;
            }
        }

        var result = await EvaluateAsync(select).ConfigureAwait(false);
        // An XDM array/map selected here is a single item to iterate once, not flattened.
        IEnumerable<object> items = SelectResultItems(result);

        if (sorts.Count > 0)
        {
            items = await SortNodesAsync(items, sorts).ConfigureAwait(false);
        }

        var itemList = items.ToList();
        var position2 = 0;

        foreach (var item in itemList)
        {
            CheckResourceLimits();
            position2++;
            // Convert ResultTreeFragments to XDM documents so accumulators and XPath navigation work
            var effectiveItem = item is ResultTreeFragment rtf && _nodeStore != null
                ? (object?)ParseResultTreeFragment(rtf) ?? item
                : item;
            PushContextItem(effectiveItem, position2, itemList.Count);
            PushCurrentItem(effectiveItem); // For XSLT current() function
            PushScope();

            // XTDE0560: the current template rule is absent inside xsl:for-each — but
            // per XSLT 3.0 §13.4.1, the *current mode* is unchanged. Don't null it: a
            // nested xsl:apply-templates with mode="#current" must still see the
            // enclosing template's mode.
            var savedTemplate = _currentTemplate;
            _currentTemplate = null;

            try
            {
                await body.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _currentTemplate = savedTemplate;
                PopScope();
                PopCurrentItem();
                PopContextItem();
            }
        }
    }

    public override async ValueTask SwitchAsync(Ast.XsltSwitch instruction)
    {
        // Evaluate select expression — the result becomes the context item for each when/test
        var selectResult = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
        PushContextItem(selectResult, 1, 1);
        try
        {
            foreach (var when in instruction.When)
            {
                if (await EvaluateBooleanAsync(when.Test).ConfigureAwait(false))
                {
                    await when.Body.ExecuteAsync(this).ConfigureAwait(false);
                    return;
                }
            }
            if (instruction.Otherwise != null)
                await instruction.Otherwise.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            PopContextItem();
        }
    }

    public override async ValueTask ForEachMemberAsync(Ast.XsltForEachMember instruction)
    {
        var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);

        // Get array members
        IList<object?> members;
        if (result is List<object?> list)
            members = list;
        else if (result is object?[] arr)
            members = arr;
        else if (result != null)
            members = [result];
        else
            return;

        var position = 0;
        foreach (var member in members)
        {
            position++;
            PushContextItem(member, position, members.Count);
            try
            {
                await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                PopContextItem();
            }
        }
    }

    public override async ValueTask ForEachGroupAsync(XsltForEachGroup instruction)
    {
        // Resolve namespace IDs in group-starting-with / group-ending-with patterns
        // (similar to xsl:number count/from patterns, these need runtime resolution)
        ResolvePatternNamespacesLocal(instruction.GroupStartingWith);
        ResolvePatternNamespacesLocal(instruction.GroupEndingWith);

        // Streaming for-each-group: when inside a streamable template with the active
        // XmlReader available, drive the reader directly instead of pre-evaluating
        // select. Currently handles the two patterns Martin Honnen reported against
        // 1.3.10 — group-starting-with and group-adjacent — for select="*" or
        // similar child-axis expressions. group-by needs full materialization (later).
        if (_isStreamingExecution && _activeStreamingReader != null
            && (instruction.GroupStartingWith != null
                || instruction.GroupEndingWith != null
                || instruction.GroupAdjacent != null))
        {
            await ForEachGroupStreamingAsync(instruction).ConfigureAwait(false);
            return;
        }

        var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
        // An XDM array/map is a single item to group, not flattened into members/entries.
        var items = SelectResultItems(result).ToList();

        List<(object Key, List<object> Items)>? groupList = null;

        if (instruction.GroupBy != null)
        {
            // Group by key value — items with the same key are grouped together
            if (instruction.Composite)
            {
                // XSLT 3.0 composite keys: use value-based comparison
                // Resolve collation for composite key string comparison
                string? compositeCollation = instruction.Collation != null
                    ? await EvaluateAvtAsync(instruction.Collation).ConfigureAwait(false)
                    : DefaultCollation;
                ValidateCollation(compositeCollation, "XTDE1110");
                StringComparer compositeComparer = GetCollationComparer(compositeCollation);

                var compositeGroups = new List<(List<object?> Key, List<object> Items)>();

                var pos = 0;
                foreach (var item in items)
                {
                    pos++;
                    PushContextItem(item, pos, items.Count);
                    try
                    {
                        var key = await EvaluateAsync(instruction.GroupBy).ConfigureAwait(false);

                        // Convert key to list for composite comparison. An empty
                        // sequence yields an empty composite key (the item still
                        // joins a group keyed by the empty tuple — composite="yes"
                        // permits empty/multi-value keys, XSLT 3.0 §19.2).
                        var keyList = key switch
                        {
                            null => new List<object?>(),
                            object?[] arr => arr.ToList(),
                            string s => new List<object?> { s },
                            IEnumerable<object?> seq => seq.ToList(),
                            _ => new List<object?> { key }
                        };

                        // Find existing group with matching composite key
                        var found = false;
                        foreach (var group in compositeGroups)
                        {
                            if (CompositeKeysEqual(group.Key, keyList, compositeComparer))
                            {
                                group.Items.Add(item);
                                found = true;
                                break;
                            }
                        }
                        if (!found)
                        {
                            compositeGroups.Add((keyList, new List<object> { item }));
                        }
                    }
                    finally
                    {
                        PopContextItem();
                    }
                }

                groupList = compositeGroups.Select(g => ((object)g.Key, g.Items)).ToList();
            }
            else
            {
                // Non-composite: string-based comparison with optional collation,
                // with value-based fallback for mixed numeric types.
                // Per XSLT 3.0 §15.3, grouping uses the eq operator, which means
                // numeric types follow promotion rules (float/decimal/double interop).
                string? resolvedCollation = instruction.Collation != null
                    ? await EvaluateAvtAsync(instruction.Collation).ConfigureAwait(false)
                    : DefaultCollation;
                ValidateCollation(resolvedCollation, "XTDE1110");
                StringComparer groupByComparer = GetCollationComparer(resolvedCollation);
                var groups = new Dictionary<string, (object Key, List<object> Items)>(groupByComparer);
                var orderedKeys = new List<string>();

                var pos = 0;
                foreach (var item in items)
                {
                    pos++;
                    PushContextItem(item, pos, items.Count);
                    try
                    {
                        var key = await EvaluateAsync(instruction.GroupBy).ConfigureAwait(false);

                        // Non-composite: if the key expression returns a sequence,
                        // the item is added to a group for EACH value (XSLT 3.0 §19.2).
                        // If it atomizes to the EMPTY SEQUENCE, the item contributes
                        // ZERO grouping keys and joins NO group — it is skipped.
                        IEnumerable<object?> keyValues = key switch
                        {
                            null => [],                              // empty sequence → no group
                            object?[] keyArr => keyArr,              // sequence → one group per value
                            string => [key],                         // strings are atomic, not sequences
                            IEnumerable<object?> keySeq => keySeq,
                            _ => [key]                               // single atomic value
                        };

                        foreach (var singleKey in keyValues)
                        {
                            var keyStr = GroupingKeyString(singleKey);
                            bool added = false;
                            if (groups.TryGetValue(keyStr, out var entry))
                            {
                                entry.Items.Add(item);
                                added = true;
                            }
                            else if (IsNumeric(singleKey))
                            {
                                // For numeric keys, check value-based equality against existing
                                // groups to handle cross-type promotion (float/decimal/double)
                                foreach (var existingKey in orderedKeys)
                                {
                                    var existingEntry = groups[existingKey];
                                    if (IsNumeric(existingEntry.Key) && ValuesEqual(singleKey, existingEntry.Key))
                                    {
                                        existingEntry.Items.Add(item);
                                        added = true;
                                        break;
                                    }
                                }
                            }
                            if (!added)
                            {
                                var newEntry = (singleKey ?? (object)keyStr, new List<object> { item });
                                groups[keyStr] = newEntry;
                                orderedKeys.Add(keyStr);
                            }
                        }
                    }
                    finally
                    {
                        PopContextItem();
                    }
                }

                groupList = orderedKeys.Select(k => groups[k]).ToList();
            }
        }
        else if (instruction.GroupAdjacent != null)
        {
            // Group adjacent — consecutive items with the same key form a group
            groupList = new List<(object Key, List<object> Items)>();
            string? currentKeyStr = null;

            // Determine collation-aware comparison for group-adjacent
            string? groupCollation = instruction.Collation != null
                ? await EvaluateAvtAsync(instruction.Collation).ConfigureAwait(false)
                : DefaultCollation;
            ValidateCollation(groupCollation, "XTDE1110");
            StringComparer adjacentComparer = GetCollationComparer(groupCollation);

            var pos = 0;
            foreach (var item in items)
            {
                pos++;
                PushContextItem(item, pos, items.Count);
                try
                {
                    var key = await EvaluateAsync(instruction.GroupAdjacent).ConfigureAwait(false);
                    // XTTE1100: group-adjacent expression must return a single atomic value (unless composite="yes")
                    if (!instruction.Composite)
                    {
                        if (key == null || (key is object[] keyArr && keyArr.Length == 0)
                            || (key is IEnumerable<object?> keySeq && !keySeq.Any()))
                            throw Error("XTTE1100: The group-adjacent expression must return a single atomic value; it returned an empty sequence");
                        if (key is object[] multiArr && multiArr.Length > 1)
                            throw Error("XTTE1100: The group-adjacent expression must return a single atomic value; it returned a sequence of " + multiArr.Length + " items");
                    }
                    var keyStr = GroupingKeyString(key);
                    if (groupList.Count == 0 || adjacentComparer.Compare(keyStr, currentKeyStr!) != 0)
                    {
                        groupList.Add((key ?? "", new List<object> { item }));
                        currentKeyStr = keyStr;
                    }
                    else
                    {
                        groupList[^1].Items.Add(item);
                    }
                }
                finally
                {
                    PopContextItem();
                }
            }
        }
        else if (instruction.GroupStartingWith != null)
        {
            // Group starting with — new group starts when item matches the pattern
            groupList = new List<(object Key, List<object> Items)>();

            foreach (var item in items)
            {
                var matches = MatchesPattern(item, instruction.GroupStartingWith);
                if (matches || groupList.Count == 0)
                {
                    groupList.Add((item, new List<object> { item }));
                }
                else
                {
                    groupList[^1].Items.Add(item);
                }
            }
        }
        else if (instruction.GroupEndingWith != null)
        {
            // Group ending with — group ends when item matches the pattern
            groupList = new List<(object Key, List<object> Items)>();
            groupList.Add((items.Count > 0 ? items[0] : "", new List<object>()));

            foreach (var item in items)
            {
                groupList[^1].Items.Add(item);
                var matches = MatchesPattern(item, instruction.GroupEndingWith);
                if (matches)
                {
                    // Current group ended, start new one for next items
                    groupList.Add((item, new List<object>()));
                }
            }

            // Remove trailing empty group
            if (groupList.Count > 0 && groupList[^1].Items.Count == 0)
                groupList.RemoveAt(groupList.Count - 1);
        }

        if (groupList != null)
        {
            // Apply sorting if specified
            if (instruction.Sorts.Count > 0)
            {
                groupList = await SortGroupsAsync(groupList, instruction.Sorts).ConfigureAwait(false);
            }

            var position = 0;
            foreach (var (key, group) in groupList)
            {
                CheckResourceLimits();
                position++;
                PushContextItem(group[0], position, groupList.Count);
                PushCurrentItem(group[0]);
                PushScope();
                SetVariable(new QName(NamespaceId.None, "current-group"), group);
                // current-grouping-key is only available for group-by and group-adjacent,
                // not for group-starting-with or group-ending-with (XTDE1071)
                SetVariable(new QName(NamespaceId.None, "current-grouping-key"),
                    instruction.GroupBy != null || instruction.GroupAdjacent != null ? key : null);

                // XTDE0560: the current template rule is absent inside xsl:for-each-group —
                // but the current mode is unchanged (XSLT 3.0 §15). Don't null it: a nested
                // xsl:apply-templates with mode="#current" must still see the enclosing
                // template's mode.
                var savedTemplate = _currentTemplate;
                _currentTemplate = null;

                try
                {
                    await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _currentTemplate = savedTemplate;
                    PopScope();
                    PopCurrentItem();
                    PopContextItem();
                }
            }
        }
    }

    /// <summary>
    /// Returns true when <paramref name="select"/> consumes the children of the current
    /// context node — i.e., it would, in non-streaming mode, evaluate to the result of
    /// the <c>child::</c> axis. Used to route streaming-aware operators
    /// (apply-templates, for-each, for-each-group, iterate) to a reader-driven
    /// implementation. Conservative: only matches the common cases (null = default
    /// children, single child-axis step, child step wrapped in a PathExpression).
    /// </summary>
    private static bool IsConsumingChildSelect(XQueryExpression? select)
    {
        if (select == null) return true; // null select = default children
        // Single child-axis step
        if (select is PhoenixmlDb.XQuery.Ast.StepExpression step
            && step.Axis == PhoenixmlDb.XQuery.Ast.Axis.Child
            && step.Predicates.Count == 0)
            return true;
        // PathExpression with single child-axis step and no initial expression
        if (select is PhoenixmlDb.XQuery.Ast.PathExpression path
            && path.InitialExpression == null
            && path.Steps.Count == 1
            && path.Steps[0] is PhoenixmlDb.XQuery.Ast.StepExpression s2
            && s2.Axis == PhoenixmlDb.XQuery.Ast.Axis.Child
            && s2.Predicates.Count == 0)
            return true;
        return false;
    }

    /// <summary>
    /// Returns true when <paramref name="select"/> is a document-level "striding" select
    /// — a child-axis name-test path evaluated from the document node that selects one or
    /// more top-level elements (e.g. <c>account</c>, <c>./account</c>, <c>/account</c>).
    /// Such a select on a streamable <c>xsl:apply-templates</c> whose context is the
    /// document node is driven through the streaming processor: its forward pass offers
    /// each top-level element to template matching, and only templates whose pattern
    /// matches the selected element name fire — reproducing the striding select without
    /// materializing the document. Conservative: rejects predicates, non-child axes,
    /// descendant hops, attribute tails, and multi-step descent so nothing but a
    /// top-level element striding select routes here.
    /// </summary>
    private static bool IsDocumentLevelStridingSelect(XQueryExpression? select)
    {
        if (select is not PhoenixmlDb.XQuery.Ast.PathExpression path)
            return false;
        // A leading '.' parses as ContextItemExpression InitialExpression; a leading '/'
        // sets IsAbsolute. Both anchor at the document node when the context IS the
        // document node. Any other initial expression means the path is not rooted at
        // the streamed document root.
        if (path.InitialExpression != null
            && path.InitialExpression is not PhoenixmlDb.XQuery.Ast.ContextItemExpression)
            return false;
        if (path.Steps.Count != 1) return false;
        var step = path.Steps[0];
        if (step.Axis != PhoenixmlDb.XQuery.Ast.Axis.Child) return false;
        if (step.Predicates.Count > 0) return false;
        // Require a name test (or *) — a kind test / text() tail is not a striding
        // element select.
        return step.NodeTest is PhoenixmlDb.XQuery.Ast.NameTest;
    }

    /// <summary>
    /// Streaming implementation of xsl:apply-templates over the children of the
    /// current context node. Drives <see cref="_activeStreamingReader"/> directly,
    /// firing templates inline as each child element arrives, until the parent's
    /// EndElement event signals end-of-children. Sets
    /// <see cref="_streamingDeferReadOnNextIteration"/> so the streaming processor's
    /// outer loop can process the EndElement itself (close any deferred parent tag).
    /// </summary>
    private async ValueTask ApplyTemplatesStreamingAsync(QName? mode, List<XsltWithParam> withParams)
    {
        var reader = _activeStreamingReader!;
        var ct = _activeStreamingCancellationToken;
        var parentDepth = reader.Depth;
        var position = 0;

        while (await reader.ReadAsync().ConfigureAwait(false))
        {
            ct.ThrowIfCancellationRequested();

            if (reader.NodeType == System.Xml.XmlNodeType.EndElement && reader.Depth == parentDepth)
            {
                _streamingDeferReadOnNextIteration = true;
                break;
            }

            switch (reader.NodeType)
            {
                case System.Xml.XmlNodeType.Element:
                {
                    var elem = await ReadStreamingElementForDispatchAsync(reader, ct).ConfigureAwait(false);
                    position++;
                    // Fire matching template (or default rule) inline, same path the main
                    // streaming processor uses. Pop any deferred element close on the way
                    // out — element template body's shallow-copy / xsl:copy may have pushed.
                    await MatchAndExecuteStreamingNodeAsync(elem, mode, position).ConfigureAwait(false);
                    // After the template runs, the deferred-close stack may contain the
                    // element's open tag (if shallow-copy / xsl:copy was used). Close it
                    // now, since we already consumed the element's full subtree.
                    if (_streamingOpenElements.Count > 0)
                    {
                        var qn = _streamingOpenElements.Pop();
                        WriteStreamingEndTag(qn);
                    }
                    break;
                }
                case System.Xml.XmlNodeType.Text:
                case System.Xml.XmlNodeType.CDATA:
                case System.Xml.XmlNodeType.SignificantWhitespace:
                {
                    // Apply templates to text node — default rule copies text to output
                    var textNode = new Xdm.Nodes.XdmText
                    {
                        Id = new NodeId(_nextStreamGroupNodeId++),
                        Document = DocumentId.None,
                        Value = reader.Value
                    };
                    _nodeStore!.Register(textNode);
                    position++;
                    await MatchAndExecuteStreamingNodeAsync(textNode, mode, position).ConfigureAwait(false);
                    break;
                }
                // Comments and PIs skipped — they're not matched by the default rule
                // for templating in this engine; out of scope for first cut.
            }
        }
    }

    /// <summary>
    /// Streaming implementation of xsl:for-each over the children of the current node.
    /// Drives <see cref="_activeStreamingReader"/> directly: for each child element,
    /// builds a full subtree, binds it as the focus, and runs the body. Sorts are
    /// not supported in this path (the caller falls back to the buffered impl).
    /// </summary>
    private async ValueTask ForEachStreamingAsync(XsltSequenceConstructor body)
    {
        var reader = _activeStreamingReader!;
        var ct = _activeStreamingCancellationToken;
        var parentDepth = reader.Depth;
        var savedTemplate = _currentTemplate;
        _currentTemplate = null; // current template rule is absent inside xsl:for-each
        var position = 0;
        try
        {
            while (await reader.ReadAsync().ConfigureAwait(false))
            {
                ct.ThrowIfCancellationRequested();
                if (reader.NodeType == System.Xml.XmlNodeType.EndElement && reader.Depth == parentDepth)
                {
                    _streamingDeferReadOnNextIteration = true;
                    break;
                }
                if (reader.NodeType != System.Xml.XmlNodeType.Element) continue;

                var elem = await ReadStreamingElementForDispatchAsync(reader, ct).ConfigureAwait(false);
                position++;
                PushContextItem(elem, position, 0);
                PushCurrentItem(elem);
                PushScope();
                // Body iterates a buffered XdmElement — suspend streaming-execution
                // so shallow-copy / xsl:copy inside the body use normal close-tag emission.
                var savedStreaming = _isStreamingExecution;
                _isStreamingExecution = false;
                try
                {
                    await body.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _isStreamingExecution = savedStreaming;
                    PopScope();
                    PopCurrentItem();
                    PopContextItem();
                }
            }
        }
        finally
        {
            _currentTemplate = savedTemplate;
        }
    }

    /// <summary>
    /// Streaming implementation of xsl:iterate. Drives the reader, runs the body
    /// per child element, handles xsl:next-iteration state updates and xsl:break.
    /// Initial-params are bound once before the loop; xsl:next-iteration's
    /// xsl:with-param bindings overwrite them on each iteration. xsl:on-completion
    /// runs after the last item (or on early break — same as non-streaming impl).
    /// </summary>
    private async ValueTask IterateStreamingAsync(XsltIterate instruction)
    {
        var reader = _activeStreamingReader!;
        var ct = _activeStreamingCancellationToken;
        var parentDepth = reader.Depth;

        // Bind initial iteration parameters once
        PushScope();
        foreach (var param in instruction.Params)
        {
            object? value;
            if (param.Select != null)
                value = await EvaluateAsync(param.Select).ConfigureAwait(false);
            else if (param.Content != null)
                value = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
            else
                value = null;
            SetVariable(param.Name, value);
        }

        var brokeOut = false;
        var position = 0;
        try
        {
            while (await reader.ReadAsync().ConfigureAwait(false))
            {
                ct.ThrowIfCancellationRequested();
                if (reader.NodeType == System.Xml.XmlNodeType.EndElement && reader.Depth == parentDepth)
                {
                    _streamingDeferReadOnNextIteration = true;
                    break;
                }
                if (reader.NodeType != System.Xml.XmlNodeType.Element) continue;

                var elem = await ReadStreamingElementForDispatchAsync(reader, ct).ConfigureAwait(false);
                position++;
                PushContextItem(elem, position, 0);
                PushCurrentItem(elem);
                var savedStreaming = _isStreamingExecution;
                _isStreamingExecution = false; // body iterates a buffered element
                try
                {
                    await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                catch (BreakException)
                {
                    brokeOut = true;
                    break;
                }
                catch (NextIterationException next)
                {
                    // Evaluate all next-iteration with-param values BEFORE writing them,
                    // so params don't see each other's new values during evaluation.
                    var newValues = new List<(QName Name, object? Value)>();
                    foreach (var p in next.WithParams)
                    {
                        object? value;
                        if (p.Select != null)
                            value = await EvaluateAsync(p.Select).ConfigureAwait(false);
                        else if (p.Content != null)
                            value = await EvaluateBodyContentToValueAsync(p.Content).ConfigureAwait(false);
                        else
                            value = null;
                        newValues.Add((p.Name, value));
                    }
                    foreach (var (name, value) in newValues)
                        SetVariable(name, value);
                }
                finally
                {
                    _isStreamingExecution = savedStreaming;
                    PopCurrentItem();
                    PopContextItem();
                }
            }

            // xsl:on-completion fires after the loop unless an outer xsl:break
            // explicitly suppressed it (BreakException reaches the outer loop).
            // Streaming mirrors the non-streaming policy: on-completion fires when
            // either we exhausted the input naturally OR an inner break exited early.
            if (instruction.OnCompletion != null)
            {
                _ = brokeOut; // brokeOut tracked for parity; on-completion fires either way
                await instruction.OnCompletion.ExecuteAsync(this).ConfigureAwait(false);
            }
        }
        finally
        {
            PopScope();
        }
    }

    /// <summary>
    /// Reads a full element subtree from the streaming reader starting at the current
    /// StartElement event, building a complete <see cref="Xdm.Nodes.XdmElement"/> with
    /// attributes and child element / text content. Consumes events through the
    /// matching EndElement. Used by both <see cref="ApplyTemplatesStreamingAsync"/> and
    /// <see cref="ForEachGroupStreamingAsync"/>.
    /// </summary>
    private async ValueTask<Xdm.Nodes.XdmElement> ReadStreamingElementForDispatchAsync(
        System.Xml.XmlReader reader, CancellationToken ct)
    {
        var startDepth = reader.Depth;
        var startName = reader.LocalName;
        var startNs = reader.NamespaceURI;
        var startPrefix = reader.Prefix;
        var startId = new NodeId(_nextStreamGroupNodeId++);
        var attrIds = new List<NodeId>();
        var nsId = !string.IsNullOrEmpty(startNs)
            ? _nodeStore!.InternNamespace(startNs)
            : NamespaceId.None;

        if (reader.HasAttributes)
        {
            for (int i = 0; i < reader.AttributeCount; i++)
            {
                reader.MoveToAttribute(i);
                if (reader.Prefix == "xmlns" || (reader.Prefix.Length == 0 && reader.LocalName == "xmlns"))
                    continue;
                var attrNsId = !string.IsNullOrEmpty(reader.NamespaceURI)
                    ? _nodeStore!.InternNamespace(reader.NamespaceURI)
                    : NamespaceId.None;
                var attrId = new NodeId(_nextStreamGroupNodeId++);
                var attrNode = new Xdm.Nodes.XdmAttribute
                {
                    Id = attrId,
                    Document = DocumentId.None,
                    Parent = startId,
                    LocalName = reader.LocalName,
                    Namespace = attrNsId,
                    Prefix = string.IsNullOrEmpty(reader.Prefix) ? null : reader.Prefix,
                    Value = reader.Value
                };
                _nodeStore!.Register(attrNode);
                attrIds.Add(attrId);
            }
            reader.MoveToElement();
        }

        var children = new List<NodeId>();
        if (!reader.IsEmptyElement)
        {
            while (await reader.ReadAsync().ConfigureAwait(false))
            {
                ct.ThrowIfCancellationRequested();
                if (reader.NodeType == System.Xml.XmlNodeType.EndElement && reader.Depth == startDepth)
                    break;
                switch (reader.NodeType)
                {
                    case System.Xml.XmlNodeType.Element:
                    {
                        var child = await ReadStreamingElementForDispatchAsync(reader, ct).ConfigureAwait(false);
                        child.Parent = startId;
                        children.Add(child.Id);
                        break;
                    }
                    case System.Xml.XmlNodeType.Text:
                    case System.Xml.XmlNodeType.CDATA:
                    case System.Xml.XmlNodeType.SignificantWhitespace:
                    case System.Xml.XmlNodeType.Whitespace:
                    {
                        var textId = new NodeId(_nextStreamGroupNodeId++);
                        var textNode = new Xdm.Nodes.XdmText
                        {
                            Id = textId,
                            Document = DocumentId.None,
                            Parent = startId,
                            Value = reader.Value
                        };
                        _nodeStore!.Register(textNode);
                        children.Add(textId);
                        break;
                    }
                }
            }
        }

        var elem = new Xdm.Nodes.XdmElement
        {
            Id = startId,
            Document = DocumentId.None,
            Parent = NodeId.None,
            LocalName = startName,
            Namespace = nsId,
            Prefix = string.IsNullOrEmpty(startPrefix) ? null : startPrefix,
            Children = children,
            Attributes = attrIds,
            NamespaceDeclarations = Array.Empty<NamespaceBinding>()
        };
        _nodeStore!.Register(elem);
        return elem;
    }

    /// <summary>
    /// Streaming implementation of xsl:for-each-group. Drives the active XmlReader
    /// directly, building one full XdmElement subtree per child element event,
    /// applying the grouping logic (group-starting-with / group-ending-with /
    /// group-adjacent), and firing the body per group with current-group() bound
    /// to the buffered items.
    /// </summary>
    /// <remarks>
    /// <para>
    /// Group accumulation buffers the items of the CURRENT group only — group-by
    /// (which needs all items materialized for cross-group aggregation) falls back
    /// to the non-streaming path; this method handles only the three single-pass
    /// patterns. The body executes with <see cref="_isStreamingExecution"/>
    /// temporarily cleared so apply-templates over current-group() uses normal
    /// (non-streaming) semantics on the buffered XdmNodes — without that toggle,
    /// the shallow-copy fallback would push to <see cref="_streamingOpenElements"/>
    /// and corrupt close-tag bookkeeping.
    /// </para>
    /// <para>
    /// End-of-children detection: when an EndElement event at the parent's depth
    /// fires, this method has consumed it but the StreamingXmlProcessor still needs
    /// to do its own EndElement bookkeeping (pop ancestor stack, close deferred
    /// tag). We set <see cref="_streamingDeferReadOnNextIteration"/> so the
    /// processor skips its next ReadAsync and processes the position we already
    /// reached.
    /// </para>
    /// </remarks>
    private async ValueTask ForEachGroupStreamingAsync(XsltForEachGroup instruction)
    {
        var reader = _activeStreamingReader!;
        var ct = _activeStreamingCancellationToken;
        // Reader is currently positioned just past the parent's StartElement.
        // The parent's depth is reader.Depth (children appear at parent.Depth + 1
        // when we read them). We stop when we see an EndElement at parent.Depth
        // (the parent's own EndElement).
        var parentDepth = reader.Depth;

        var currentGroup = new List<object>();
        object? currentKey = null;
        var firstItem = true;
        // 1-based position of the current item within the whole SELECTED sequence
        // (not within its group) — the context position() for the grouping-key
        // expression, e.g. 032's group-adjacent="(position()-1) idiv $block-size".
        var selectedPosition = 0;

        // The select expression names which child elements are grouped. For a
        // striding leaf like select="transaction" (or "record/copy-of()", whose
        // striding step is `record`), only elements with that local name are
        // members — a mixed-content parent (007's <account-number> sibling of the
        // <transaction>s) would otherwise pollute the first group and evaluate the
        // grouping key against the wrong element. select="*" (or any wildcard leaf)
        // yields null → every child element is a member.
        var selectLeafName = StreamingForEachGroupSelectLeafName(instruction.Select);

        // Helper: build a full XdmElement subtree starting from the current
        // StartElement event, delegating to the shared streaming materializer so
        // the accumulated group members are REAL nodes: text descendants captured
        // and _stringValue precomputed (so value-of/aggregate/copy-of/snapshot over
        // current-group() all resolve). The materializer leaves the reader ON the
        // matching EndElement (or on the empty element) — the outer child loop's
        // next ReadAsync advances past it to the next sibling.
        Xdm.Nodes.XdmElement ReadElementSubtree()
        {
            ct.ThrowIfCancellationRequested();
            var elem = StreamingSubtreeMaterializer.Materialize(reader, _nodeStore!, DocumentId.None)!;
            // Detach the materialized root: as a selected group member it stands on
            // its own, and later snapshot(current-group())/.. synthesizes the parent.
            elem.Parent = NodeId.None;
            return elem;
        }

        // Helper: flush the current group through the body
        async ValueTask FlushAsync()
        {
            if (currentGroup.Count == 0) return;
            var savedStreaming = _isStreamingExecution;
            _isStreamingExecution = false; // body iterates buffered items, not the stream
            PushContextItem(currentGroup[0], 1, 1);
            PushCurrentItem(currentGroup[0]);
            PushScope();
            SetVariable(new QName(NamespaceId.None, "current-group"), currentGroup);
            // current-grouping-key is bound only for group-by/group-adjacent
            SetVariable(new QName(NamespaceId.None, "current-grouping-key"),
                instruction.GroupAdjacent != null ? currentKey : null);
            var savedTemplate = _currentTemplate;
            _currentTemplate = null; // current template rule is absent inside for-each-group
            try
            {
                await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _currentTemplate = savedTemplate;
                PopScope();
                PopCurrentItem();
                PopContextItem();
                _isStreamingExecution = savedStreaming;
            }
        }

        // Drive the reader through the parent's children
        while (await reader.ReadAsync().ConfigureAwait(false))
        {
            ct.ThrowIfCancellationRequested();

            if (reader.NodeType == System.Xml.XmlNodeType.EndElement && reader.Depth == parentDepth)
            {
                // Reached the parent's EndElement. We've consumed it but the processor
                // still needs to do its own EndElement bookkeeping — signal it.
                _streamingDeferReadOnNextIteration = true;
                break;
            }

            if (reader.NodeType != System.Xml.XmlNodeType.Element)
                continue; // text/whitespace/comment between children are not selected by *

            // Non-selected sibling element (wrong local name): consume its subtree so
            // the reader advances, but do NOT treat it as a group member. Its presence
            // does not break an adjacent run (the spec's selected sequence simply omits
            // it), matching the buffered path where select filters before grouping.
            if (selectLeafName != null && reader.LocalName != selectLeafName)
            {
                ReadElementSubtree();
                continue;
            }

            // Build full subtree for this child element
            var child = ReadElementSubtree();

            // Apply grouping decision
            if (instruction.GroupStartingWith != null)
            {
                var matches = MatchesPattern(child, instruction.GroupStartingWith);
                if (matches || firstItem)
                {
                    await FlushAsync().ConfigureAwait(false);
                    currentGroup = new List<object>();
                }
                currentGroup.Add(child);
                firstItem = false;
            }
            else if (instruction.GroupEndingWith != null)
            {
                currentGroup.Add(child);
                if (MatchesPattern(child, instruction.GroupEndingWith))
                {
                    await FlushAsync().ConfigureAwait(false);
                    currentGroup = new List<object>();
                }
                firstItem = false;
            }
            else // GroupAdjacent
            {
                // Evaluate the key expression with the child as context item, using
                // its position in the whole selected sequence (position() support).
                selectedPosition++;
                PushContextItem(child, selectedPosition, 0);
                object? key;
                try
                {
                    key = await EvaluateAsync(instruction.GroupAdjacent!).ConfigureAwait(false);
                }
                finally
                {
                    PopContextItem();
                }
                if (firstItem)
                {
                    currentKey = key;
                    firstItem = false;
                }
                else if (!GroupAdjacentKeysEqual(currentKey, key))
                {
                    await FlushAsync().ConfigureAwait(false);
                    currentGroup = new List<object>();
                    currentKey = key;
                }
                currentGroup.Add(child);
            }
        }

        // Final flush
        await FlushAsync().ConfigureAwait(false);
    }

    /// <summary>
    /// Streaming-group node-id allocator. Sits above the principal source's id range
    /// and below <see cref="StreamingXmlProcessor"/>'s allocator (1_000_000) by enough
    /// margin that practical streams don't collide. Reset on each group flush would be
    /// nice but the buffered nodes outlive the loop iteration, so we just monotonically
    /// increment.
    /// </summary>
    private ulong _nextStreamGroupNodeId = 5_000_000;

    /// <summary>
    /// Equality on group-adjacent keys. A composite key (composite="yes") is a
    /// SEQUENCE of atomic values (e.g. 007's <c>(year, week)</c>) surfaced as an
    /// <see cref="object"/> array; equality is member-wise so two distinct tuples
    /// that happen to string-concatenate alike are still separated. Single atomic
    /// keys fall back to value-then-string comparison.
    /// </summary>
    private static bool GroupAdjacentKeysEqual(object? a, object? b)
    {
        if (a == null && b == null) return true;
        if (a == null || b == null) return false;

        var aSeq = a as object?[];
        var bSeq = b as object?[];
        if (aSeq != null || bSeq != null)
        {
            aSeq ??= new[] { a };
            bSeq ??= new[] { b };
            if (aSeq.Length != bSeq.Length) return false;
            for (int i = 0; i < aSeq.Length; i++)
                if (!GroupAdjacentKeysEqual(aSeq[i], bSeq[i])) return false;
            return true;
        }

        return Equals(a, b) || string.Equals(StringValueOf(a), StringValueOf(b), StringComparison.Ordinal);
    }

    /// <summary>
    /// Extracts the child-element local name a streaming for-each-group <c>select</c>
    /// picks, so the reader-driven accumulator can skip non-selected siblings. Returns
    /// <c>null</c> ("match every child element") for a wildcard leaf (<c>*</c>) or any
    /// shape this simple extractor doesn't recognise (the caller then admits all child
    /// elements — the pre-existing behaviour, sound for <c>select="*"</c>).
    /// <para>
    /// Handles the streamable striding shapes in the si-for-each-group cluster:
    /// <c>transaction</c> (single child step), <c>product</c>, and
    /// <c>record/copy-of()</c> (whose striding step is <c>record</c>; the trailing
    /// grounding <c>copy-of()</c> function step is ignored). A leaf whose last
    /// element step is <c>text()</c> or an attribute is treated as "no element-name
    /// filter" (null) — those forms are handled elsewhere or fall through unchanged.
    /// </para>
    /// </summary>
    private static string? StreamingForEachGroupSelectLeafName(XQueryExpression select)
    {
        if (select is not PhoenixmlDb.XQuery.Ast.PathExpression path || path.Steps.Count == 0)
            return null;

        // Walk from the end to the last child-axis element name step, skipping a
        // trailing grounding function step (copy-of()/snapshot()) which parses as a
        // separate step with a non-NameTest node test.
        for (int i = path.Steps.Count - 1; i >= 0; i--)
        {
            var step = path.Steps[i];
            if (step.Axis != PhoenixmlDb.XQuery.Ast.Axis.Child)
            {
                // The striding leaf must be a child-axis element step; anything else
                // (attribute/text tail, a leading grounding step) → no name filter.
                if (step.NodeTest is PhoenixmlDb.XQuery.Ast.NameTest) return null;
                continue;
            }
            if (step.NodeTest is PhoenixmlDb.XQuery.Ast.NameTest nt)
                return nt.IsLocalNameWildcard ? null : nt.LocalName;
            // A kind test (text()/node()/element()) leaf → no simple element-name filter.
            return null;
        }
        return null;
    }

    private bool MatchesPattern(object item, XsltPattern pattern)
    {
        // XSLT 3.0 allows patterns to match atomic values (e.g., ".[. instance of xs:string]")
        // Let the pattern decide if it can match the item type
        using var mc = AcquireMatchContext();
        return pattern.Matches(item, mc.Value);
    }

    private async Task<List<(object Key, List<object> Items)>> SortGroupsAsync(
        List<(object Key, List<object> Items)> groups,
        List<XsltSort> sorts)
    {
        // Resolve sort properties (AVTs) once
        var sortOrders = new List<string>();
        var sortDataTypes = new List<string>();
        foreach (var sort in sorts)
        {
            sortOrders.Add(sort.Order != null ? await EvaluateAvtAsync(sort.Order).ConfigureAwait(false) : "ascending");
            sortDataTypes.Add(sort.DataType != null ? await EvaluateAvtAsync(sort.DataType).ConfigureAwait(false) : "text");
        }

        // Build sort keys for each group (using the first item as context)
        var keyed = new List<(object Key, List<object> Items, List<string> SortKeys)>();
        foreach (var (key, items) in groups)
        {
            var sortKeys = new List<string>();
            PushContextItem(items[0], 1, 1);
            PushScope();
            // Set current-group and current-grouping-key for sort key evaluation (e.g., sort by current-grouping-key())
            SetVariable(new QName(NamespaceId.None, "current-group"), items);
            SetVariable(new QName(NamespaceId.None, "current-grouping-key"), key);
            try
            {
                foreach (var sort in sorts)
                {
                    if (sort.Select != null)
                    {
                        var val = await EvaluateAsync(sort.Select).ConfigureAwait(false);
                        sortKeys.Add(StringValueOf(val));
                    }
                    else
                    {
                        sortKeys.Add(StringValueOf(items[0]));
                    }
                }
            }
            finally
            {
                PopScope();
                PopContextItem();
            }
            keyed.Add((key, items, sortKeys));
        }

        // Sort using all sort keys
        keyed.Sort((a, b) =>
        {
            for (var i = 0; i < sorts.Count && i < a.SortKeys.Count && i < b.SortKeys.Count; i++)
            {
                var cmp = sortDataTypes[i] == "number"
                    ? CompareNumeric(a.SortKeys[i], b.SortKeys[i])
                    : string.Compare(a.SortKeys[i], b.SortKeys[i], StringComparison.Ordinal);
                if (sortOrders[i] == "descending")
                    cmp = -cmp;
                if (cmp != 0)
                    return cmp;
            }
            return 0;
        });

        return keyed.Select(k => (k.Key, k.Items)).ToList();
    }

    private static int CompareNumeric(string a, string b)
    {
        var aOk = double.TryParse(a, NumberStyles.Float, CultureInfo.InvariantCulture, out var aVal);
        var bOk = double.TryParse(b, NumberStyles.Float, CultureInfo.InvariantCulture, out var bVal);
        if (aOk && bOk)
            return aVal.CompareTo(bVal);
        if (aOk)
            return -1; // numbers before non-numbers
        if (bOk)
            return 1;
        return string.Compare(a, b, StringComparison.Ordinal);
    }

    public override async ValueTask IterateAsync(XsltIterate instruction)
    {
        // Streaming: when inside a streamable template with a consuming child-axis
        // select, drive the reader directly. State passing via xsl:next-iteration
        // mirrors the non-streaming impl (NextIterationException carries the new
        // param bindings).
        if (_isStreamingExecution && _activeStreamingReader != null
            && IsConsumingChildSelect(instruction.Select))
        {
            await IterateStreamingAsync(instruction).ConfigureAwait(false);
            return;
        }

        var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);

        // Use lazy enumeration when possible to avoid materializing large sequences.
        // xsl:iterate with xsl:break can exit early, so full materialization is wasteful.
        // Only materialize to a list when last() might be needed (we use -1 for unknown).
        IEnumerable<object> items;
        int itemCount;
        if (result == null)
        {
            items = [];
            itemCount = 0;
        }
        else if (result is List<object?> or System.Collections.IDictionary)
        {
            // An XDM array/map is a single item to iterate, not flattened.
            items = [result];
            itemCount = 1;
        }
        else if (result is object?[] arr)
        {
            items = arr.Where(x => x != null).Cast<object>();
            itemCount = arr.Length;
        }
        else if (result is IEnumerable<object> seq)
        {
            // Keep lazy — don't ToList() for large sequences
            items = seq;
            itemCount = -1; // unknown, use -1 for last()
        }
        else
        {
            items = [result];
            itemCount = 1;
        }

        // Initialize iteration parameters
        PushScope();
        foreach (var param in instruction.Params)
        {
            object? value;
            if (param.Select != null)
            {
                value = await EvaluateAsync(param.Select).ConfigureAwait(false);
            }
            else if (param.Content != null)
            {
                value = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
            }
            else
            {
                value = null;
            }
            SetVariable(param.Name, value);
        }

        try
        {
            var position = 0;
            var brokeOut = false;
            foreach (var item in items)
            {
                CheckResourceLimits();
                position++;
                PushContextItem(item, position, itemCount > 0 ? itemCount : position);
                PushCurrentItem(item); // For XSLT current() function

                try
                {
                    await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
                }
                catch (BreakException)
                {
                    brokeOut = true;
                    break;
                }
                catch (NextIterationException next)
                {
                    // Evaluate ALL with-param values first using old parameter values,
                    // then set them all at once. This ensures params don't see each other's
                    // new values during evaluation (XSLT spec requirement).
                    var newValues = new List<(QName Name, object? Value)>();
                    foreach (var param in next.WithParams)
                    {
                        object? value;
                        if (param.Select != null)
                        {
                            value = await EvaluateAsync(param.Select).ConfigureAwait(false);
                        }
                        else if (param.Content != null)
                        {
                            // Use accumulator-isolated body eval so xsl:sequence emitting typed
                            // items (doc-nodes, elements, etc.) is preserved instead of being
                            // serialized to text and rebound as XsUntypedAtomic. Found in Docbook
                            // TNG where xsl:next-iteration with-param="document" rebinds $document
                            // each iteration via `<xsl:sequence select="$next-result?output"/>`.
                            value = await EvaluateBodyContentToValueAsync(param.Content).ConfigureAwait(false);
                        }
                        else
                        {
                            value = null;
                        }
                        // Apply type coercion based on the matching xsl:param's as type
                        var matchingParam = instruction.Params.FirstOrDefault(p => p.Name == param.Name);
                        if (matchingParam?.As != null && value != null)
                        {
                            value = CoerceToType(value, matchingParam.As);
                        }
                        newValues.Add((param.Name, value));
                    }
                    // Now apply all new values
                    foreach (var (name, val) in newValues)
                    {
                        SetVariable(name, val);
                    }
                }
                finally
                {
                    PopCurrentItem();
                    PopContextItem();
                }
            }

            // On completion - only runs if iteration completed normally (not via xsl:break)
            // Context item/position/size are undefined in on-completion (XPDY0002)
            if (!brokeOut && instruction.OnCompletion != null)
            {
                PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);
                try
                {
                    await instruction.OnCompletion.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    PopContextItem();
                }
            }
        }
        finally
        {
            PopScope();
        }
    }

    public override async ValueTask TryAsync(XsltTry instruction)
    {
        // Save the full output content, not just length, because exceptions propagating
        // through nested element constructors (LRE, xsl:element) replace _output content
        // with the inner element's partial content. The outer content would be lost.
        var savedOutputContent = _output.ToString();
        var savedAttrStackDepth = _collectedAttributesStack.Count;
        try
        {
            if (instruction.SelectExpression != null)
            {
                // Evaluate the select expression and handle the result.
                // Must respect _sequenceAccumulator (like xsl:sequence) so typed values
                // (e.g. boolean false) are preserved, not serialized to string "false".
                var result = await EvaluateAsync(instruction.SelectExpression).ConfigureAwait(false);
                if (result != null && _sequenceAccumulator != null)
                {
                    if (result is object?[] tryArr)
                    {
                        foreach (var item in tryArr)
                            AppendToSeqAccumulator(item);
                    }
                    else if (result is System.Collections.IEnumerable tryEnum && result is not string && result is not XdmNode && result is not IDictionary<object, object?>)
                    {
                        foreach (var item in tryEnum)
                            AppendToSeqAccumulator(item);
                    }
                    else
                    {
                        AppendToSeqAccumulator(result);
                    }
                }
                else
                {
                    OutputValue(result);
                }
            }
            else if (instruction.Body != null)
            {
                await instruction.Body.ExecuteAsync(this).ConfigureAwait(false);
            }
        }
        catch (Exception ex) when (ex is XsltException or XQuery.Execution.XQueryRuntimeException or XQuery.Functions.XQueryException or InvalidOperationException or FormatException or OverflowException or ArgumentException or NullReferenceException or ArithmeticException)
        {
            // Discard output produced during failed try block (rollback-output behavior).
            // Restore from snapshot because _output may have been replaced by nested
            // element constructors whose assembly code was skipped by the exception.
            if (instruction.Rollback)
            {
                _output.Clear();
                _output.Append(savedOutputContent);
                // Pop any _collectedAttributesStack entries pushed by interrupted element constructors
                while (_collectedAttributesStack.Count > savedAttrStackDepth)
                    _collectedAttributesStack.Pop();
            }
            else if (_output.Length > savedOutputContent.Length)
            {
                // XTDE3530: When rollback-output="no" and output has been committed,
                // recovery is not possible — the output state cannot be rolled back.
                throw Error("XTDE3530: Recovery from a dynamic error is not possible because rollback-output='no' and output has already been written");
            }

            var errorCode = ex is XQuery.Execution.XQueryRuntimeException xqEx ? xqEx.ErrorCode
                : ex is XQuery.Functions.XQueryException xqFnEx ? xqFnEx.ErrorCode
                : ExtractErrorCode(ex.Message) ?? "XSLT0000";
            // Determine error namespace: standard error codes (FO/XP/XT/XQ/SE prefix + 4 digits)
            // are in the standard error namespace; user-defined codes are in no namespace
            var isStandardError = errorCode.Length >= 8
                && char.IsUpper(errorCode[0]) && char.IsUpper(errorCode[1])
                && char.IsLetterOrDigit(errorCode[2]) && char.IsLetterOrDigit(errorCode[3])
                && errorCode[4..].All(char.IsDigit);

            // Find matching catch
            foreach (var @catch in instruction.Catches)
            {
                // Check if error matches — per XSLT spec, namespace must match
                var matches = @catch.Errors.Count == 0; // Empty = catch all
                if (!matches && @catch.Errors.Any(e =>
                {
                    if (e.LocalName == "*" && (e.Namespace == NamespaceId.None || e.Prefix == null))
                        return true; // * or Q{ns}* wildcard
                    if (e.LocalName != errorCode)
                        return false;
                    // Wildcard prefix *:code matches any namespace
                    if (e.Prefix == "*")
                        return true;
                    // Namespace check: standard errors are in the error namespace;
                    // user-defined errors (from fn:error with custom QName) are in no namespace
                    if (isStandardError)
                    {
                        // Standard error — catch must have err: prefix or be in the error namespace
                        return e.Prefix == "err" || e.Namespace != NamespaceId.None;
                    }
                    // User-defined error — catch must also have no namespace (no prefix)
                    return e.Namespace == NamespaceId.None && e.Prefix == null;
                }))
                {
                    matches = true;
                }

                if (matches)
                {
                    PushScope();
                    // Set $err:code, $err:description, $err:value, $err:module, $err:line-number, $err:column-number
                    // Register with both NamespaceId (for prefix-resolved references like $err:code)
                    // and ExpandedNamespace (for EQName references like $Q{uri}code).
                    // QName is a record struct — Dictionary equality uses all fields — so we register
                    // under both forms for correct lookup.
                    const string errUri = "http://www.w3.org/2005/xqt-errors";
                    var errNs = StylesheetParser.ResolveNamespaceUri(errUri);
                    SetVariable(new QName(errNs, "description", "err"), ex.Message);
                    SetVariable(new QName(NamespaceId.None, "description", "") { ExpandedNamespace = errUri }, ex.Message);
                    var errCodeValue = isStandardError
                        ? (object)new QName(errNs, errorCode, "err")
                        : (object)new QName(NamespaceId.None, errorCode);
                    SetVariable(new QName(errNs, "code", "err"), errCodeValue);
                    SetVariable(new QName(NamespaceId.None, "code", "") { ExpandedNamespace = errUri }, errCodeValue);
                    SetVariable(new QName(errNs, "value", "err"), null);
                    SetVariable(new QName(NamespaceId.None, "value", "") { ExpandedNamespace = errUri }, null);
                    var errLocation = (ex as XsltException)?.Location;
                    var errModule = errLocation != null ? XsltTransformEngine.UriString(_stylesheet.BaseUri) ?? "" : "";
                    var errLine = errLocation?.Line ?? 0;
                    var errColumn = errLocation?.Column ?? 0;
                    SetVariable(new QName(errNs, "module", "err"), errModule.Length > 0 ? errModule : null);
                    SetVariable(new QName(NamespaceId.None, "module", "") { ExpandedNamespace = errUri }, errModule.Length > 0 ? errModule : null);
                    SetVariable(new QName(errNs, "line-number", "err"), errLine > 0 ? (object)errLine : null);
                    SetVariable(new QName(NamespaceId.None, "line-number", "") { ExpandedNamespace = errUri }, errLine > 0 ? (object)errLine : null);
                    SetVariable(new QName(errNs, "column-number", "err"), errColumn > 0 ? (object)errColumn : null);
                    SetVariable(new QName(NamespaceId.None, "column-number", "") { ExpandedNamespace = errUri }, errColumn > 0 ? (object)errColumn : null);

                    try
                    {
                        if (@catch.SelectExpression != null)
                        {
                            var result = await EvaluateAsync(@catch.SelectExpression).ConfigureAwait(false);
                            if (result != null && _sequenceAccumulator != null)
                            {
                                if (result is object?[] catchArr)
                                {
                                    foreach (var item in catchArr)
                                        AppendToSeqAccumulator(item);
                                }
                                else if (result is System.Collections.IEnumerable catchEnum && result is not string && result is not XdmNode && result is not IDictionary<object, object?>)
                                {
                                    foreach (var item in catchEnum)
                                        AppendToSeqAccumulator(item);
                                }
                                else
                                {
                                    AppendToSeqAccumulator(result);
                                }
                            }
                            else
                            {
                                OutputValue(result);
                            }
                        }
                        else if (@catch.Body != null)
                        {
                            await @catch.Body.ExecuteAsync(this).ConfigureAwait(false);
                        }
                    }
                    finally
                    {
                        PopScope();
                    }

                    return;
                }
            }

            throw; // Re-throw if no catch matches
        }
    }

    /// <summary>
    /// Extracts a standard error code (e.g., "XTTE1000") from an exception message
    /// that starts with "XTTE1000: ..." or similar pattern.
    /// </summary>
    private static string? ExtractErrorCode(string message)
    {
        if (message.Length >= 8
            && char.IsUpper(message[0]) && char.IsUpper(message[1])
            && char.IsLetterOrDigit(message[2]) && char.IsLetterOrDigit(message[3])
            && char.IsDigit(message[4]) && char.IsDigit(message[5])
            && char.IsDigit(message[6]) && char.IsDigit(message[7])
            && (message.Length == 8 || message[8] == ':' || message[8] == ' '))
        {
            return message[..8];
        }
        return null;
    }

    /// <summary>
    /// Validates that a string is a plausible BCP 47 language tag (e.g., "en", "de-AT").
    /// Must start with a letter and contain only letters, digits, and hyphens.
    /// </summary>
    private static bool IsValidLanguageTag(string tag)
    {
        if (tag.Length == 0 || !char.IsLetter(tag[0]))
            return false;
        for (var i = 1; i < tag.Length; i++)
        {
            if (!char.IsLetterOrDigit(tag[i]) && tag[i] != '-')
                return false;
        }
        return true;
    }

    public override async ValueTask<bool> EvaluateBooleanAsync(XQueryExpression expr)
    {
        var result = await EvaluateAsync(expr).ConfigureAwait(false);
        return EffectiveBooleanValue(result);
    }

    /// <summary>
    /// Resolves NamespaceUri strings on NameTests to NamespaceIds using the node store.
    /// This bridges between parse-time prefix→URI resolution and execution-time URI→ID resolution.
    /// </summary>
    private void ResolveExpressionNamespaceIds(XQueryExpression expr)
    {
        switch (expr)
        {
            case StepExpression se:
                if (se.NodeTest is NameTest nt)
                {
                    // If prefix is set but URI wasn't resolved at parse time, resolve from stylesheet namespaces
                    if (nt.Prefix != null && string.IsNullOrEmpty(nt.NamespaceUri) && nt.NamespaceUri != "*")
                    {
                        if (_stylesheet.Namespaces.TryGetValue(nt.Prefix, out var uri))
                            nt.NamespaceUri = uri;
                    }
                    // Apply stylesheet-level xpath-default-namespace for unprefixed element name tests
                    else if (nt.Prefix == null && string.IsNullOrEmpty(nt.NamespaceUri) && !nt.IsLocalNameWildcard
                             && se.Axis != Axis.Attribute && se.Axis != Axis.Namespace
                             && _stylesheet.XpathDefaultNamespace != null && !nt.ResolvedNamespace.HasValue)
                    {
                        nt.NamespaceUri = _stylesheet.XpathDefaultNamespace;
                    }
                    nt.ResolveNamespace(_nodeStore!.InternNamespace);
                }
                foreach (var pred in se.Predicates)
                    ResolveExpressionNamespaceIds(pred);
                break;
            case PathExpression pe:
                if (pe.InitialExpression != null)
                    ResolveExpressionNamespaceIds(pe.InitialExpression);
                foreach (var step in pe.Steps)
                    ResolveExpressionNamespaceIds(step);
                break;
            case BinaryExpression be:
                ResolveExpressionNamespaceIds(be.Left);
                ResolveExpressionNamespaceIds(be.Right);
                break;
            case UnaryExpression ue:
                ResolveExpressionNamespaceIds(ue.Operand);
                break;
            case FilterExpression fe:
                ResolveExpressionNamespaceIds(fe.Primary);
                foreach (var pred in fe.Predicates)
                    ResolveExpressionNamespaceIds(pred);
                break;
            case FunctionCallExpression fc:
                foreach (var arg in fc.Arguments)
                    ResolveExpressionNamespaceIds(arg);
                break;
            case IfExpression ie:
                ResolveExpressionNamespaceIds(ie.Condition);
                ResolveExpressionNamespaceIds(ie.Then);
                if (ie.Else != null)
                    ResolveExpressionNamespaceIds(ie.Else);
                break;
            case SequenceExpression seq:
                foreach (var item in seq.Items)
                    ResolveExpressionNamespaceIds(item);
                break;
            case FlworExpression flwor:
                foreach (var clause in flwor.Clauses)
                {
                    if (clause is ForClause forClause)
                        foreach (var binding in forClause.Bindings)
                            ResolveExpressionNamespaceIds(binding.Expression);
                    else if (clause is LetClause letClause)
                        foreach (var binding in letClause.Bindings)
                            ResolveExpressionNamespaceIds(binding.Expression);
                    else if (clause is WhereClause whereClause)
                        ResolveExpressionNamespaceIds(whereClause.Condition);
                    else if (clause is OrderByClause orderBy)
                        foreach (var spec in orderBy.OrderSpecs)
                            ResolveExpressionNamespaceIds(spec.Expression);
                }
                ResolveExpressionNamespaceIds(flwor.ReturnExpression);
                break;
            case SimpleMapExpression sme:
                ResolveExpressionNamespaceIds(sme.Left);
                ResolveExpressionNamespaceIds(sme.Right);
                break;
            case InstanceOfExpression inst:
                ResolveExpressionNamespaceIds(inst.Expression);
                break;
            case CastExpression cast:
                ResolveExpressionNamespaceIds(cast.Expression);
                break;
            case CastableExpression castable:
                ResolveExpressionNamespaceIds(castable.Expression);
                break;
            case TreatExpression treat:
                ResolveExpressionNamespaceIds(treat.Expression);
                break;
            case StringConcatExpression sce:
                foreach (var operand in sce.Operands)
                    ResolveExpressionNamespaceIds(operand);
                break;
            case RangeExpression re:
                ResolveExpressionNamespaceIds(re.Start);
                ResolveExpressionNamespaceIds(re.End);
                break;
            case ArrowExpression ae:
                ResolveExpressionNamespaceIds(ae.Expression);
                ResolveExpressionNamespaceIds(ae.FunctionCall);
                break;
        }
    }

    public override async ValueTask<object?> EvaluateAsync(XQueryExpression expr)
    {
        // Fast path for simple expressions
        switch (expr)
        {
            case StringLiteral sl:
                return sl.Value;
            case IntegerLiteral il:
                return il.Value;
            case DoubleLiteral dl:
                return dl.Value;
            case BooleanLiteral bl:
                return bl.Value;
            case VariableReference vr:
                return GetVariable(vr.Name);
            case ContextItemExpression:
                var ci = ContextItem;
                if (ReferenceEquals(ci, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
                    throw new InvalidOperationException("XPDY0002: Context item is absent");
                return ci;
            // Fast path: position() and last() — avoid full XQuery pipeline in loops
            case FunctionCallExpression { Arguments.Count: 0 } fce
                when fce.Name.LocalName == "position" && (fce.Name.Namespace == NamespaceId.None || fce.Name.Namespace == NamespaceId.Fn):
                if (ReferenceEquals(ContextItem, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
                    throw new InvalidOperationException("XPDY0002: Context position is absent");
                return (long)Position;
            case FunctionCallExpression { Arguments.Count: 0 } fce2
                when fce2.Name.LocalName == "last" && (fce2.Name.Namespace == NamespaceId.None || fce2.Name.Namespace == NamespaceId.Fn):
                if (ReferenceEquals(ContextItem, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
                    throw new InvalidOperationException("XPDY0002: Context size is absent");
                return (long)Last;
            // Fast path: simple comparisons with position()/last() and integer literals
            case BinaryExpression { Operator: var op } be
                when (op >= BinaryOperator.Equal && op <= BinaryOperator.GreaterOrEqual
                   || op >= BinaryOperator.GeneralEqual && op <= BinaryOperator.GeneralGreaterOrEqual)
                && TryEvaluateSimpleComparison(be) is { } result:
                return result;
        }

        // Check for stream watcher result substitution.
        // This handles both direct matches (entire expr is a watcher) and
        // nested matches (expr contains watcher sub-expressions, e.g., map entries).
        if (_activeStreamWatchers != null)
        {
            // Group A — wrapped head/outermost/remove aggregation. When the whole
            // select is a watched wrapper carrying an outer op (positional
            // predicates / SimpleMap RIGHT), apply that op to the grounded
            // accumulated sequence (inner result + outermost-dedup + remove-skip)
            // via the existing per-item evaluator, and return the post-processed
            // grounded sequence for emission.
            var directWatcher = FindDirectWatcher(expr, _activeStreamWatchers);
            if (directWatcher != null
                && (directWatcher.OuterPredicates.Count > 0 || directWatcher.OuterSimpleMapRight != null))
            {
                return await ApplyWrappedOuterOpAsync(directWatcher).ConfigureAwait(false);
            }

            var watcherResult = TryResolveFromWatchers(expr, _activeStreamWatchers);
            if (watcherResult.Resolved)
                return watcherResult.Value;

            // For function calls where all arguments are resolvable from watchers or literals,
            // evaluate them directly to avoid losing watcher values inside the XQuery plan.
            // This handles patterns like translate(head(//AUTHOR), ' ', '_') in AVT contexts.
            if (expr is FunctionCallExpression fcall && fcall.Arguments.Count > 0)
            {
                var fnResult = await TryEvaluateFunctionWithWatcherArgs(fcall, _activeStreamWatchers).ConfigureAwait(false);
                if (fnResult.Resolved)
                    return fnResult.Value;
            }

            // General comparison whose operand is a watched SimpleMap source —
            // e.g. (/*/*/ITEM/DIMENSIONS!xs:NMTOKENS(.)!xs:decimal(.)) = $s.
            // The plan-level path inside the SimpleMap re-evaluates against
            // the synthetic empty doc and short-circuits to false. Instead,
            // substitute the watcher's captured items into the SimpleMap by
            // re-running its tail (Right) per item with the item as context,
            // then run a general comparison against the other operand. This
            // surfaces XPTY0004 from the tail casts rather than masking it.
            if (expr is BinaryExpression cmp
                && IsGeneralComparison(cmp.Operator))
            {
                var compResult = await TryEvaluateGeneralCompWithSimpleMapWatcherAsync(cmp, _activeStreamWatchers).ConfigureAwait(false);
                if (compResult.Resolved)
                    return compResult.Value;
            }

            // Last-resort substitution: if the expression contains a watched
            // sub-expression strictly *inside* it (e.g. snapshot(/chapter) deep
            // within innermost(snapshot(/chapter)//section)/@id), rewrite the
            // watched sub-expression to a synthetic $__streaming_watcher_N
            // variable reference and re-evaluate. The XQuery engine then runs
            // naturally against the materialised subtree without re-touching
            // the now-closed stream.
            var rewritten = RewriteWithWatcherVariables(expr, _activeStreamWatchers);
            if (!ReferenceEquals(rewritten, expr))
            {
                return await EvaluateAsync(rewritten).ConfigureAwait(false);
            }
        }

        // Resolve NamespaceUri → ResolvedNamespace on NameTests using node store
        if (_nodeStore != null)
            ResolveExpressionNamespaceIds(expr);

        // Full XQuery evaluation via optimizer + executor (with plan caching)
        if (!_planCache.TryGetValue(expr, out var plan))
        {
            var optimizer = new PhoenixmlDb.XQuery.Optimizer.QueryOptimizer();
            var optContext = new PhoenixmlDb.XQuery.Optimizer.OptimizationContext { Container = default, BackwardsCompatible = IsBackwardsCompatible, FunctionLibrary = _functionLibrary };
            plan = optimizer.Optimize(expr, optContext);
            _planCache[expr] = plan;
        }

        // Pass the node store directly as the node provider — this preserves INodeBuilder
        // so XQuery constructors can create proper XDM elements instead of serialized strings
        PhoenixmlDb.XQuery.INodeProvider? nodeProvider = _nodeStore;

        using var execContext = new PhoenixmlDb.XQuery.Execution.QueryExecutionContext(
            container: default,
            functions: _functionLibrary,
            nodeProvider: nodeProvider,
            documentResolver: (PhoenixmlDb.XQuery.IDocumentResolver?)_policyResolver ?? _documentResolver,
            schemaProvider: _schemaProvider,
            namespaceResolver: _nodeStore != null ? _nodeStore.GetNamespaceUri : null);
        // Provide in-scope namespace prefix bindings so XSLT functions (system-property, etc.)
        // can resolve prefixed QName string arguments at runtime
        // When inside xsl:evaluate with namespace-context, use those bindings instead
        execContext.PrefixNamespaceBindings = _evaluateNamespaceBindings != null
            ? (IReadOnlyDictionary<string, string>)_evaluateNamespaceBindings
            : _stylesheet.Namespaces;
        execContext.BackwardsCompatible = IsBackwardsCompatible;
        execContext.InsideXslEvaluate = _insideXslEvaluateDepth > 0;
        execContext.DefaultCollation = DefaultCollation;
        execContext.StaticBaseUri = StaticBaseUri;

        // Set up variable fallback for lazy global initialization.
        // When the XQuery engine encounters a variable not yet bound, this callback
        // triggers the XSLT GetVariable which can lazily initialize pending globals.
        execContext.VariableFallback = varName =>
        {
            try
            {
                var value = GetVariable(varName);
                return (true, ConvertRtfForXQuery(value));
            }
            catch (XsltException ex) when (!ex.Message.Contains("XTDE0640", StringComparison.Ordinal))
            {
                return (false, null);
            }
        };

        // Bind XSLT variables into XQuery context
        // Bind outer scopes first, then inner scopes, so inner scope values override (proper shadowing)
        // Convert ResultTreeFragments to XDM documents so XPath can navigate into them
        foreach (var (name, value) in GlobalVariables)
        {
            execContext.BindVariable(name, ConvertRtfForXQuery(value));
        }
        // Reverse iteration: bind outer scopes before inner scopes
        foreach (var scope in _scopes.Reverse())
        {
            foreach (var (name, value) in scope.Variables)
            {
                execContext.BindVariable(name, ConvertRtfForXQuery(value));
            }
        }

        // Bind stream watcher results as synthetic variables for map constructor entries etc.
        if (_activeStreamWatchers != null)
        {
            for (var wi = 0; wi < _activeStreamWatchers.Count; wi++)
            {
                var watcherVar = new QName(NamespaceId.None, $"__streaming_watcher_{wi}");
                var w = _activeStreamWatchers[wi];
                // Group A wrapped-aggregation watcher: bind the GROUNDED BASE sequence
                // (inner result + outermost-dedup + remove-skip) so a re-wrapped outer
                // predicate — `$__streaming_watcher_N[pred…]`, injected by
                // RewriteWithWatcherVariables for operands like `outermost(//PRICE)[1] + $two`
                // — filters over the correct base. Bare (non-wrapped) watchers keep the
                // GetResult() contract used by map-entry / general-comparison consumers.
                var bound = (w.OuterPredicates.Count > 0 || w.OuterSimpleMapRight != null)
                    ? (object?)w.ProduceAccumulated()
                    : w.GetResult();
                execContext.BindVariable(watcherVar, bound);
            }
        }

        // Set context item
        if (ContextItem != null)
        {
            execContext.PushContextItem(ContextItem, Position, Last);
        }

        // Execute and collect results.
        // Catch XQueryException missing source-module info and re-throw with the offending
        // XPath expression text + AST type prefixed. Without this, errors like
        // "XPTY0020: [line 2, col 24] An axis step was used..." give no clue WHICH
        // expression in WHICH XSLT module raised them. The expression text alone is
        // enough to bisect Docbook-TNG-scale stylesheets where many xpaths look alike.
        var results = new List<object?>();
        try
        {
            await foreach (var item in plan.Root.ExecuteAsync(execContext).ConfigureAwait(false))
            {
                results.Add(item);
            }
        }
        catch (PhoenixmlDb.XQuery.Functions.XQueryException xqe) when (string.IsNullOrEmpty(xqe.Module))
        {
            var snippet = expr.ToString() ?? "(unknown)";
            if (snippet.Length > 200) snippet = snippet[..200] + "…";
            // If the XSLT compiler stamped this expression's Location with the source
            // module URI (StylesheetParser.AttachXsltSourceLocation), surface that as
            // a [module:line] prefix. The original [line N, col M] from xqe.Message stays —
            // it pinpoints the position WITHIN the inline XPath string. Together they
            // identify "which XSLT element + which character in its XPath."
            var sourcePrefix = expr.Location is { Module: { Length: > 0 } mod } loc
                ? $"[{mod}:{loc.Line}] "
                : "";
            throw new PhoenixmlDb.XQuery.Functions.XQueryException(
                xqe.ErrorCode,
                $"{sourcePrefix}{xqe.Message}\n  ↳ in expression ({expr.GetType().Name}): {snippet}",
                xqe);
        }

        return results.Count switch
        {
            0 => null,
            1 => results[0],
            _ => results.ToArray()
        };
    }

    /// <summary>
    /// Checks if a range for-each body can have any observable effect.
    /// Returns false if the body consists entirely of xsl:if/xsl:choose with statically false tests.
    /// </summary>
    private static bool RangeBodyHasEffect(XsltSequenceConstructor body, int count)
    {
        foreach (var instruction in body.Instructions)
        {
            if (!InstructionIsNoOp(instruction, count)) return true;
        }
        return false;

        static bool InstructionIsNoOp(XsltInstruction instruction, int count)
        {
            // xsl:if with test="position() = N" where N < 0 or N > count is always false
            if (instruction is XsltIf xif && IsAlwaysFalsePositionTest(xif.Test, count))
                return true;
            return false;
        }

        static bool IsAlwaysFalsePositionTest(XQueryExpression test, int count)
        {
            if (test is not BinaryExpression { Operator: BinaryOperator.GeneralEqual or BinaryOperator.Equal } be)
                return false;
            // position() = N where N is out of range
            if (IsPositionCall(be.Left) && TryGetIntegerValue(be.Right) is { } val)
                return val < 1 || val > count;
            if (IsPositionCall(be.Right) && TryGetIntegerValue(be.Left) is { } val2)
                return val2 < 1 || val2 > count;
            return false;
        }

        static long? TryGetIntegerValue(XQueryExpression expr) => expr switch
        {
            IntegerLiteral il when il.Value is long lv => lv,
            // -N is parsed as UnaryExpression(Minus, IntegerLiteral(N))
            UnaryExpression { Operator: UnaryOperator.Minus, Operand: IntegerLiteral il2 } when il2.Value is long lv2 => -lv2,
            UnaryExpression { Operator: UnaryOperator.Plus, Operand: IntegerLiteral il3 } when il3.Value is long lv3 => lv3,
            _ => null
        };

        static bool IsPositionCall(XQueryExpression expr)
            => expr is FunctionCallExpression { Arguments.Count: 0 } fce
               && fce.Name.LocalName == "position";
    }

    /// <summary>
    /// Fast-path evaluation for simple comparisons like position() = N, last() gt 1, etc.
    /// Returns null if the expression can't be evaluated via fast path.
    /// </summary>
    private object? TryEvaluateSimpleComparison(BinaryExpression be)
    {
        var leftVal = TryEvaluateSimpleOperand(be.Left);
        var rightVal = TryEvaluateSimpleOperand(be.Right);
        if (leftVal is null || rightVal is null) return null;

        var l = (long)leftVal;
        var r = (long)rightVal;
        return be.Operator switch
        {
            BinaryOperator.Equal or BinaryOperator.GeneralEqual => l == r,
            BinaryOperator.NotEqual or BinaryOperator.GeneralNotEqual => l != r,
            BinaryOperator.LessThan or BinaryOperator.GeneralLessThan => l < r,
            BinaryOperator.LessOrEqual or BinaryOperator.GeneralLessOrEqual => l <= r,
            BinaryOperator.GreaterThan or BinaryOperator.GeneralGreaterThan => l > r,
            BinaryOperator.GreaterOrEqual or BinaryOperator.GeneralGreaterOrEqual => l >= r,
            _ => null
        };
    }

    private long? TryEvaluateSimpleOperand(XQueryExpression expr) => expr switch
    {
        IntegerLiteral il when il.Value is long lv => lv,
        FunctionCallExpression { Arguments.Count: 0 } fce
            when fce.Name.LocalName == "position" && (fce.Name.Namespace == NamespaceId.None || fce.Name.Namespace == NamespaceId.Fn)
            => Position,
        FunctionCallExpression { Arguments.Count: 0 } fce2
            when fce2.Name.LocalName == "last" && (fce2.Name.Namespace == NamespaceId.None || fce2.Name.Namespace == NamespaceId.Fn)
            => Last,
        _ => null
    };

    public override async ValueTask CreateElementAsync(XsltElement instruction)
    {
        if (_recursionDepth >= MaxRecursionDepth)
            return;
        _recursionDepth++;
        try
        {
            await RunInstructionWithValidationAsync(
                instruction.Validation, "xsl:element", instruction.Location,
                () => CreateElementCoreAsync(instruction)).ConfigureAwait(false);
        }
        finally
        {
            _recursionDepth--;
        }
    }

    /// <summary>
    /// Returns true when the instruction's <c>validation=</c> attribute is set to
    /// <c>strict</c> or <c>lax</c> (the modes that actually trigger schema processing).
    /// </summary>
    private static bool ShouldRunValidation(Ast.ValidationMode? mode)
        => mode is Ast.ValidationMode.Strict or Ast.ValidationMode.Lax;

    /// <summary>
    /// Executes <paramref name="body"/> and validates the XML fragment it appends to the
    /// primary output buffer. Captures via length-marker so that surrounding output (parent
    /// elements still being serialized) is preserved correctly.
    ///
    /// Validation is skipped when the body runs in text-content mode (xsl:attribute /
    /// xsl:comment / xsl:processing-instruction body, where output is atomized text) or
    /// when a sequence accumulator is active (xsl:variable, xsl:document XDM construction
    /// — those paths build XdmNode trees rather than serialized markup, and a separate
    /// validation hook on the constructing instruction handles them).
    /// </summary>
    private async ValueTask RunInstructionWithValidationAsync(Ast.ValidationMode? mode,
        string instructionName, SourceLocation? location, Func<ValueTask> body)
    {
        var shouldValidate = ShouldRunValidation(mode)
            && _textContentDepth == 0
            && _sequenceAccumulator is null;

        if (!shouldValidate)
        {
            await body().ConfigureAwait(false);
            return;
        }

        var startLength = _output.Length;
        await body().ConfigureAwait(false);
        if (_output.Length > startLength)
        {
            var fragment = _output.ToString(startLength, _output.Length - startLength);
            RunValidation(mode, fragment, ValidationKind.Fragment, instructionName, location);
        }
    }

    private async ValueTask CreateElementCoreAsync(XsltElement instruction)
    {
        // Inside attribute/comment/PI content, suppress element tags and pass through
        // only text content (atomization per XSLT spec 5.7.2)
        if (_textContentDepth > 0)
        {
            // When collecting simple content items, atomized elements are separate items
            // (not text nodes), so they get space separators in the final join (step 5).
            if (_collectTextAsSequenceItems && _sequenceAccumulator != null && _serializingElementDepth == 0)
            {
                // Flush any pending text in _output as a TextNodeItem
                var pending = _output.ToString();
                if (pending.Length > 0)
                {
                    AppendToSeqAccumulator(new Xdm.TextNodeItem(pending));
                    _output.Clear();
                }
                // Execute element content with _collectTextAsSequenceItems disabled
                // so text goes to _output (not accumulator) for this element only
                _collectTextAsSequenceItems = false;
                try
                {
                    if (instruction.Content != null)
                        await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _collectTextAsSequenceItems = true;
                }
                // Add the element's atomized content as a plain string (separate item)
                var elementText = _output.ToString();
                _output.Clear();
                if (elementText.Length > 0)
                    AppendToSeqAccumulator(elementText);
                return;
            }
            // Simple content construction: space between items from different nodes
            // (only for comment/PI content; attribute content uses empty-string separator)
            if (_attributeContentDepth == 0 && _output.Length > 0)
                _output.Append(' ');
            if (instruction.Content != null)
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            if (_attributeContentDepth == 0)
                _simpleContentLastWasNode = true;
            return;
        }

        var name = (await EvaluateAvtAsync(instruction.Name).ConfigureAwait(false)).Trim();

        // XTDE0820: Reject empty or invalid element names
        if (string.IsNullOrEmpty(name))
            throw Error("XTDE0820: The effective value of the 'name' attribute of xsl:element is a zero-length string");
        try
        {
            // Verify the computed name is a valid QName (prefix:local or just local)
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx >= 0)
            {
                System.Xml.XmlConvert.VerifyNCName(name[..colonIdx]);
                System.Xml.XmlConvert.VerifyNCName(name[(colonIdx + 1)..]);
            }
            else
            {
                System.Xml.XmlConvert.VerifyNCName(name);
            }
        }
        catch (System.Xml.XmlException)
        {
            throw Error($"XTDE0820: The effective value of the 'name' attribute of xsl:element ('{name}') is not a valid QName");
        }

        string? nsUri = null;
        if (instruction.Namespace != null)
        {
            nsUri = await EvaluateAvtAsync(instruction.Namespace).ConfigureAwait(false);
            // When namespace="" is explicit, the element is in no namespace and any prefix is discarded
            if (nsUri != null && nsUri.Length == 0)
            {
                var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
                if (colonIdx > 0)
                    name = name[(colonIdx + 1)..];
            }
        }

        // Process use-attribute-sets
        var attrParts = new StringBuilder();
        await ApplyAttributeSetsAsync(instruction.UseAttributeSets, attrParts).ConfigureAwait(false);

        // Process content — attributes and non-attribute content are interleaved
        // Resolve namespace before processing content so children can inherit it
        if (nsUri == null)
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx > 0)
            {
                var prefix = name[..colonIdx];
                if (instruction.InScopeNamespaces.TryGetValue(prefix, out var resolvedUri))
                {
                    nsUri = resolvedUri;
                }
                else if (prefix == "xml")
                {
                    nsUri = "http://www.w3.org/XML/1998/namespace";
                }
                else
                {
                    // XTDE0830: Prefixed name with no namespace attribute and undeclared prefix
                    throw Error($"XTDE0830: The prefix '{prefix}' in the element name '{name}' is not declared in any in-scope namespace declaration");
                }
            }
            else
            {
                // Unprefixed name: use default namespace if declared
                if (instruction.InScopeNamespaces.TryGetValue("", out var defaultNs)
                    && !string.IsNullOrEmpty(defaultNs))
                {
                    nsUri = defaultNs;
                }
            }
        }

        // XTDE0835: Element namespace must not be the xmlns namespace
        if (nsUri == "http://www.w3.org/2000/xmlns/")
            throw Error("XTDE0835: The namespace URI 'http://www.w3.org/2000/xmlns/' is not allowed for xsl:element");

        // Build namespace bindings for this element
        var elemNsBindings = new Dictionary<string, string>();
        if (nsUri != null)
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            var prefix = colonIdx > 0 ? name[..colonIdx] : "";
            elemNsBindings[prefix] = nsUri;
        }
        else
        {
            // Element has no namespace — if parent has a default namespace, record the undeclaration
            // in the scope so children know the default namespace has been cleared
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx < 0 && GetInScopeDefaultNamespace() != null)
            {
                elemNsBindings[""] = "";
            }
        }

        // inherit-namespaces="no" on parent: add default ns undeclaration so children
        // don't inherit the parent's xmlns="..." in the serialized output
        if (_forceDefaultNsUndeclaration && !elemNsBindings.ContainsKey("")
            && GetInScopeDefaultNamespace() != null)
        {
            elemNsBindings[""] = "";
        }

        // Use attribute-collection mode flag (push new buffer for nesting support)
        _collectedAttributesStack.Push(new StringBuilder());

        var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
        var savedLogicalStart = _outputLogicalStart;
        _outputLogicalStart = _output.Length;
        var savedLastAtomic = _lastResultWasAtomic;
        _lastResultWasAtomic = false;

        // Track element name for CDATA section serialization
        var localName = name;
        var colonIdx2 = name.IndexOf(':', StringComparison.Ordinal);
        if (colonIdx2 > 0)
            localName = name[(colonIdx2 + 1)..];
        _outputElementStack.Push(new QName(NamespaceId.None, localName));
        _outputElementHasNsStack.Push(nsUri != null || colonIdx2 > 0);
        _outputElementIsLreStack.Push(false); // xsl:element — not an LRE
        _xslNamespaceBindings.Push(new Dictionary<string, string>());

        PushOutputNsScope(elemNsBindings);
        PushOutputNsScope(new Dictionary<string, string>()); // Separate scope for attribute-emitted ns decls
        PushScope(); // Variables declared inside this element should be scoped to this element
        var savedSeqAccum1 = _sequenceAccumulator;
        _sequenceAccumulator = null; // Suspend accumulation inside element content
        _serializingElementDepth++;
        Dictionary<string, string>? xslNsBindingsForFixup = null;
        // inherit-namespaces="no": children must emit xmlns="" to undeclare the default namespace
        // that this element introduces in the serialized output
        var savedForceNsUndecl = _forceDefaultNsUndeclaration;
        _forceDefaultNsUndeclaration = instruction.InheritNamespaces == false
            && elemNsBindings.ContainsKey("") && !string.IsNullOrEmpty(elemNsBindings[""]);
        // Push xml:base onto static base URI stack so resolve-uri() resolves against it
        if (instruction.BaseUri != null)
            _staticBaseUriStack.Push(XsltTransformEngine.UriString(instruction.BaseUri)!);
        try
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            if (instruction.BaseUri != null)
                _staticBaseUriStack.Pop();
            _forceDefaultNsUndeclaration = savedForceNsUndecl;
            _serializingElementDepth--;
            _sequenceAccumulator = savedSeqAccum1;
            PopScope();
            PopOutputNsScope(); // attribute ns decls scope
            PopOutputNsScope(); // element ns scope
            _outputElementStack.Pop();
            _outputElementHasNsStack.Pop();
            _outputElementIsLreStack.Pop();
            // Save xsl:namespace bindings for namespace fixup before popping
            if (_xslNamespaceBindings.Peek().Count > 0)
                xslNsBindingsForFixup = new Dictionary<string, string>(_xslNamespaceBindings.Peek());
            _xslNamespaceBindings.Pop();
        }

        var collectedAttrs = _collectedAttributesStack.Pop();
        var content = savedScope.GetWritten();
        savedScope.Dispose();
        _outputLogicalStart = savedLogicalStart;
        // After producing an element node, reset atomic state (nodes break atomic adjacency)
        _lastResultWasAtomic = false;

        // Namespace fixup: if xsl:namespace redefined the element's prefix to a different URI,
        // rename the element's prefix to avoid the conflict (XSLT 3.0 §11.7)
        string? fixupNewPrefix = null;
        if (xslNsBindingsForFixup != null && nsUri != null && nsUri.Length > 0)
        {
            var fixupColonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (fixupColonIdx > 0)
            {
                var elemPfx = name[..fixupColonIdx];
                if (xslNsBindingsForFixup.TryGetValue(elemPfx, out var xslUri) && xslUri != nsUri)
                {
                    fixupNewPrefix = GenerateUniquePrefix(elemPfx);
                    name = $"{fixupNewPrefix}:{name[(fixupColonIdx + 1)..]}";
                }
            }
        }

        _output.Append('<');
        _output.Append(name);

        // Emit namespace declaration if not already in scope
        if (nsUri != null && nsUri.Length > 0)
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx > 0)
            {
                var prefix = name[..colonIdx];
                if (!IsNamespaceInScope(prefix, nsUri))
                {
                    _output.Append(" xmlns:");
                    _output.Append(prefix);
                    _output.Append("=\"");
                    _output.Append(EscapeAttributeValue(nsUri));
                    _output.Append('"');
                }
            }
            else
            {
                if (!IsNamespaceInScope("", nsUri))
                {
                    _output.Append(" xmlns=\"");
                    _output.Append(EscapeAttributeValue(nsUri));
                    _output.Append('"');
                }
            }
        }
        else
        {
            // Element is in no namespace (nsUri is null or empty string).
            // If the in-scope default namespace is non-empty, emit xmlns="" to undeclare it.
            var colonIdx3 = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx3 < 0)
            {
                var parentDefaultNs = GetInScopeDefaultNamespace();
                if (parentDefaultNs != null)
                {
                    _output.Append(" xmlns=\"\"");
                }
            }
        }

        // Deduplicate attributes (last-wins)
        var attrs = new Dictionary<string, string>();
        ParseAttributeString(attrParts.ToString(), attrs);
        ParseAttributeString(collectedAttrs.ToString(), attrs);
        foreach (var (attrName, attrValue) in attrs)
        {
            _output.Append(' ');
            _output.Append(attrName);
            _output.Append("=\"");
            _output.Append(attrValue);
            _output.Append('"');
        }

        if (content.Length > 0)
        {
            _output.Append('>');
            _output.Append(content);
            _output.Append("</");
            _output.Append(name);
            _output.Append('>');
        }
        else
        {
            _output.Append("/>");
        }

        // Element is "significant" for where-populated only if it has child content
        // (attributes alone don't count as "populated" per XSLT 3.0 spec)
        if (content.Length > 0)
            MarkContentProduced();
    }

    public override async ValueTask CreateAttributeAsync(XsltAttribute instruction)
    {
        // Set ambient location so XTDE0410/0420 raised from helper paths (CopySingleItemAsync,
        // SerializeNode) can attribute the error to *this* xsl:attribute. We don't restore on
        // exit — the next instruction will overwrite, and the value is best-effort diagnostics.
        _currentInstructionLocation = instruction.Location ?? _currentInstructionLocation;

        // XTDE0420: Cannot add attribute to a document node
        if (_documentNodeDepth > 0 && !_attributeCollecting)
            throw new XsltException("XTDE0420: Cannot add an attribute node to a document node", instruction.Location);

        // XTDE0410: Cannot add attribute after child content has been added to the element
        // Inside xsl:where-populated, defer this check until after insignificant items are filtered
        if (_attributeCollecting && _output.Length > _outputLogicalStart && _wherePopulatedDepth == 0)
        {
            if (!IsBackwardsCompatible)
                throw new XsltException("XTDE0410: Cannot add an attribute to an element after children have been added", instruction.Location);
            // In backwards-compatible (1.0) mode, silently ignore the attribute
            return;
        }

        var name = await EvaluateAvtAsync(instruction.Name).ConfigureAwait(false);

        // XTDE0850: Validate attribute name is a valid QName
        if (string.IsNullOrEmpty(name))
            throw Error("XTDE0850: The effective value of the 'name' attribute of xsl:attribute is a zero-length string");
        // XTDE0855: The name "xmlns" without a namespace attribute is not allowed
        if (name == "xmlns" && instruction.Namespace == null)
            throw Error("XTDE0855: The attribute name 'xmlns' is not allowed on xsl:attribute without a namespace attribute");
        try
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx >= 0)
            {
                System.Xml.XmlConvert.VerifyNCName(name[..colonIdx]);
                System.Xml.XmlConvert.VerifyNCName(name[(colonIdx + 1)..]);
            }
            else
            {
                System.Xml.XmlConvert.VerifyNCName(name);
            }
        }
        catch (System.Xml.XmlException)
        {
            throw Error($"XTDE0850: The effective value of the 'name' attribute of xsl:attribute ('{name}') is not a valid QName");
        }

        // XTDE0860: Prefixed name with no namespace attribute — prefix must be declared
        if (instruction.Namespace == null)
        {
            var colonIdx2 = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx2 > 0)
            {
                var prefix = name[..colonIdx2];
                // The xml prefix is always implicitly bound to http://www.w3.org/XML/1998/namespace
                string? prefixNsUri = null;
                if (prefix != "xml" && !instruction.InScopeNamespaces.TryGetValue(prefix, out prefixNsUri))
                    throw Error($"XTDE0860: The prefix '{prefix}' in the attribute name '{name}' is not declared in any in-scope namespace declaration");
                // Emit namespace declaration for the prefix if not already in scope
                // Skip when accumulating XDM nodes — the attribute node stores namespace info natively
                if (_sequenceAccumulator == null && prefix != "xml" && prefixNsUri != null && !IsNamespaceInScope(prefix, prefixNsUri))
                {
                    var target2 = _attributeCollecting ? _collectedAttributes! : _output;
                    target2.Append(" xmlns:");
                    target2.Append(prefix);
                    target2.Append("=\"");
                    target2.Append(EscapeAttributeValue(prefixNsUri));
                    target2.Append('"');
                    if (_outputNsScopes.Count > 0)
                        _outputNsScopes.Peek()[prefix] = prefixNsUri;
                }
            }
        }

        // Handle namespace attribute
        string? explicitNsUri = null;
        if (instruction.Namespace != null)
        {
            explicitNsUri = await EvaluateAvtAsync(instruction.Namespace).ConfigureAwait(false);
            // XTDE0865: Attribute namespace must not be the xmlns namespace
            if (explicitNsUri == "http://www.w3.org/2000/xmlns/")
                throw Error("XTDE0865: The namespace URI 'http://www.w3.org/2000/xmlns/' is not allowed for xsl:attribute");
            // When namespace="" is explicit, the attribute is in no namespace and any prefix is discarded
            if (explicitNsUri != null && explicitNsUri.Length == 0)
            {
                var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
                if (colonIdx > 0)
                    name = name[(colonIdx + 1)..];
            }
            if (!string.IsNullOrEmpty(explicitNsUri))
            {
                var colonIdx2 = name.IndexOf(':', StringComparison.Ordinal);
                if (colonIdx2 < 0)
                {
                    // No prefix — generate one
                    var prefix = GenerateNsPrefix(explicitNsUri);
                    name = $"{prefix}:{name}";
                }
                else
                {
                    // Has prefix — check if it's already bound to a different namespace
                    var existingPrefix = name[..colonIdx2];
                    if (_stylesheet.Namespaces.TryGetValue(existingPrefix, out var existingNs) && existingNs != explicitNsUri)
                    {
                        // Prefix conflict — generate a new prefix based on original
                        var newPrefix = $"{existingPrefix}_1";
                        name = $"{newPrefix}:{name[(colonIdx2 + 1)..]}";
                    }
                }
                // Emit namespace declaration for the prefix if not already in scope
                // Skip when accumulating XDM nodes — the attribute node stores namespace info natively
                if (_sequenceAccumulator == null)
                {
                    var attrPrefix = name[..name.IndexOf(':', StringComparison.Ordinal)];
                    if (!IsNamespaceInScope(attrPrefix, explicitNsUri))
                    {
                        var target2 = _attributeCollecting ? _collectedAttributes! : _output;
                        target2.Append(" xmlns:");
                        target2.Append(attrPrefix);
                        target2.Append("=\"");
                        target2.Append(EscapeAttributeValue(explicitNsUri));
                        target2.Append('"');
                        // Register in the current scope so child elements won't re-emit it
                        if (_outputNsScopes.Count > 0)
                            _outputNsScopes.Peek()[attrPrefix] = explicitNsUri;
                    }
                }
            }
        }

        // Evaluate separator AVT once (it may contain dynamic expressions)
        string? resolvedSeparator = instruction.Separator != null
            ? await EvaluateAvtAsync(instruction.Separator).ConfigureAwait(false)
            : null;

        string value;
        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            var sep = resolvedSeparator ?? " ";
            if (result is IEnumerable<object> seq && result is not string)
            {
                value = string.Join(sep, seq.Select(StringValueOf));
            }
            else
            {
                value = StringValueOf(result);
            }
        }
        else if (instruction.Content != null)
        {
            // When an explicit separator is specified on xsl:attribute with content form,
            // use the sequence accumulator to collect individual items, then join with separator.
            // Per XSLT 3.0 spec 5.7.2, the default separator for content form is zero-length string.
            if (resolvedSeparator != null)
            {
                var savedAccumulator = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                _textContentDepth++;
                _attributeContentDepth++;
                // Disable outer text collection so attribute content text goes to
                // _output (attribute uses its own accumulator for separator handling)
                var savedCollectText1 = _collectTextAsSequenceItems;
                _collectTextAsSequenceItems = false;
                try
                {
                    await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _collectTextAsSequenceItems = savedCollectText1;
                    _attributeContentDepth--;
                    _textContentDepth--;
                }
                // Collect items from both accumulator and output buffer
                var items = new List<string>();
                foreach (var item in _sequenceAccumulator)
                {
                    if (item != null)
                        items.Add(StringValueOf(item));
                }
                var textContent = savedScope.GetWritten();
                if (!string.IsNullOrEmpty(textContent))
                    items.Add(textContent);
                value = string.Join(resolvedSeparator, items);
                savedScope.Dispose();
                _sequenceAccumulator = savedAccumulator;
            }
            else
            {
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                _textContentDepth++;
                _attributeContentDepth++;
                // Disable text collection so attribute content text goes to _output
                // (not the outer variable's sequence accumulator)
                var savedCollectText2 = _collectTextAsSequenceItems;
                _collectTextAsSequenceItems = false;
                try
                {
                    await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _collectTextAsSequenceItems = savedCollectText2;
                    _attributeContentDepth--;
                    _textContentDepth--;
                }
                value = savedScope.GetWritten();
                savedScope.Dispose();
            }
        }
        else
        {
            value = "";
        }

        // xsl:attribute validation. The XSLT 3.0 spec §27.2 says attribute validation is
        // considered to occur in the context of an element. Without that context here, we
        // do the part we can do reliably: confirm the global schema-attribute declaration
        // exists when validation="strict" (raise XQDY0027 otherwise), and skip silently
        // for lax. Value-against-type checking is a TODO; today it relies on the parent
        // element's validation= when one is set.
        ValidateAttributeIfRequested(instruction, name, explicitNsUri);

        // If sequence accumulator is active, create an XdmAttribute node for the sequence
        if (_sequenceAccumulator != null)
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            var localName = colonIdx >= 0 ? name[(colonIdx + 1)..] : name;
            var prefix = colonIdx >= 0 ? name[..colonIdx] : null;
            var attrNsId = NamespaceId.None;
            if (!string.IsNullOrEmpty(explicitNsUri))
            {
                attrNsId = _nodeStore!.InternNamespace(explicitNsUri);
            }
            else if (prefix != null && _stylesheet.Namespaces.TryGetValue(prefix, out var prefixUri))
            {
                attrNsId = _nodeStore!.InternNamespace(prefixUri);
            }
            var attr = new XdmAttribute
            {
                Document = DocumentId.None,
                LocalName = localName,
                Prefix = prefix,
                Namespace = attrNsId,
                Value = value,
                Id = NodeId.None,
                Parent = NodeId.None
            };
            AppendToSeqAccumulator(attr);
            return;
        }

        var target = _attributeCollecting ? _collectedAttributes! : _output;
        target.Append(' ');
        target.Append(name);
        target.Append("=\"");
        target.Append(EscapeAttributeValue(value));
        target.Append('"');
    }

    public override void WriteText(string value, bool disableOutputEscaping)
    {
        // XTDE1490: Reject writes to primary output after it was claimed by result-document href=""
        if (_primaryOutputClaimedByResultDocument && _resultDocumentRedirectDepth == 0
            && _temporaryOutputDepth == 0 && _textContentDepth == 0
            && !string.IsNullOrWhiteSpace(value))
            throw Error("XTDE1490: Cannot write to the primary output destination — it has already been written by an explicit xsl:result-document");

        // In text output mode (method="text" result-document), protect text content from
        // StripXmlMarkup by sentinel-escaping < > & chars. Only actual XML markup (generated
        // by LRE/xsl:element which writes directly to _output) will be stripped.
        if (_textOutputModeDepth > 0 && (value.Contains('<', StringComparison.Ordinal)
            || value.Contains('>', StringComparison.Ordinal) || value.Contains('&', StringComparison.Ordinal)))
        {
            value = value.Replace("&", "\uFDD2", StringComparison.Ordinal)
                         .Replace("<", "\uFDD0", StringComparison.Ordinal)
                         .Replace(">", "\uFDD1", StringComparison.Ordinal);
        }

        // When collecting simple content items (§5.7.2), redirect text to accumulator
        // as TextNodeItem to distinguish from atomic strings. Takes priority over
        // _textContentDepth since we need proper item interleaving in comment/PI bodies.
        if (_collectTextAsSequenceItems && _serializingElementDepth == 0
            && _sequenceAccumulator != null)
        {
            AppendToSeqAccumulator(new Xdm.TextNodeItem(value));
        }
        else if ((disableOutputEscaping && _temporaryOutputDepth == 0) || _textContentDepth > 0)
        {
            // Don't XML-escape when inside attribute/comment/PI body collection,
            // as the collected text is handled by the parent instruction
            // Per XSLT spec, disable-output-escaping is ignored when writing to a temporary tree
            // Simple content: insert space when transitioning from node-contributed text to new text
            // (only for comment/PI content; attribute content uses empty-string separator)
            if (_simpleContentLastWasNode && _textContentDepth > 0 && _attributeContentDepth == 0 && _output.Length > 0)
                _output.Append(' ');
            if (_attributeContentDepth == 0)
                _simpleContentLastWasNode = false;
            _output.Append(value);
        }
        else if (IsInCdataSectionElement())
        {
            // Wrap in CDATA section — escape any embedded "]]>" sequences
            _output.Append("<![CDATA[");
            _output.Append(value.Replace("]]>", "]]]]><![CDATA[>", StringComparison.Ordinal));
            _output.Append("]]>");
        }
        else
        {
            _output.Append(EscapeText(value));
        }

        // Non-whitespace text counts as "populated" for xsl:where-populated,
        // but only when at the element content level (not inside attribute/comment/PI body).
        // Use XML whitespace definition (only #x20, #x9, #xD, #xA), not .NET's broader one.
        if (IsTrackingPopulated && _textContentDepth == 0 && !IsXmlWhitespaceOnly(value))
        {
            MarkContentProduced();
        }

        // Text output (even zero-length) breaks adjacent atomic value chain.
        // Per XSLT 3.0 spec, text nodes in a sequence (even empty from xsl:text/xsl:value-of)
        // break adjacency between atomic values, preventing space insertion.
        // Skip when _preserveAtomicState > 0 (Phase 2 of on-non-empty when !wasPopulated):
        // non-conditional instructions producing empty text shouldn't break the chain
        // between the previous iteration's last atomic and on-empty's atomic output.
        if (_preserveAtomicState == 0)
            _lastResultWasAtomic = false;
    }

    private bool IsInCdataSectionElement()
    {
        if (_outputElementStack.Count == 0)
            return false;
        var outputDecl = _activeResultDocumentOutput ?? _stylesheet.Outputs.FirstOrDefault();
        if (outputDecl?.CdataSectionElements == null || outputDecl.CdataSectionElements.Count == 0)
            return false;
        var currentElem = _outputElementStack.Peek();
        return outputDecl.CdataSectionElements.Contains(currentElem);
    }

    public override void WriteTextItem(string value)
    {
        // If sequence accumulation is active, add as a TextNodeItem marker
        // to distinguish text nodes from atomic strings (for §5.7.2 processing)
        if (_sequenceAccumulator != null)
        {
            AppendToSeqAccumulator(new Xdm.TextNodeItem(value));
            // In function bodies at the top level (not inside value-of, attribute,
            // comment/PI content), also write escaped text to _output so that
            // text and LRE elements preserve their source order when the function
            // result is assembled from both _sequenceAccumulator and _output.
            if (_functionBodyDepth > 0 && _textContentDepth == 0)
                _output.Append(EscapeText(value));
        }
        else
        {
            _output.Append(EscapeText(value));
