            }
            else if (result is System.Collections.IEnumerable enumerable && result is not string && result is not XdmNode)
            {
                var sep = resolvedSeparator ?? " ";
                var items = new List<object?>();
                foreach (var item in enumerable)
                    items.Add(item);
