            // In attribute context: items concatenated without separator (XSLT 2.0 spec 5.7.2)
            // In comment/PI context: items separated by single space
            if (_attributeContentDepth > 0 && (result is object?[] || (result is IEnumerable<object?> && result is not string && result is not XdmNode && result is not ResultTreeFragment)))
            {
                var items = result is object?[] a ? a : ((IEnumerable<object?>)result).ToArray();
                foreach (var item in items)
                    _output.Append(StringValueOf(item));
            }
            else
            {
                _output.Append(StringValueOf(result));
            }
            return;
        }

        // XTDE3362: copy-accumulators="yes" when accumulator not applicable to source tree
        if (instruction.CopyAccumulators == true && _stylesheet.Accumulators.Count > 0 && _principalSourceDocId.HasValue)
        {
            var sourceDocId = FindDocumentIdForInput(result);
            if (sourceDocId.HasValue && sourceDocId.Value == _principalSourceDocId.Value)
            {
                foreach (var accName in _stylesheet.Accumulators.Keys)
                {
                    if (!IsAccumulatorApplicableForCopy(accName))
                        throw Error($"XTDE3362: Accumulator '{accName.LocalName}' is not applicable to the source tree (not listed in use-accumulators for the initial mode)");
                }
            }
        }

        // When sequence accumulator is active and copy-accumulators="yes", deep-copy nodes
        // with accumulator value propagation and add directly to accumulator (avoiding
        // serialization to XML which would lose accumulator values).
        if (_sequenceAccumulator != null && instruction.CopyAccumulators == true && result is XdmNode or object?[])
        {
            var copied = await DeepCopyWithAccumulatorsAsync(result).ConfigureAwait(false);
            if (copied is object?[] copiedArr)
            {
                foreach (var item in copiedArr)
                    if (item != null)
                        AppendToSeqAccumulator(item);
            }
            else if (copied != null)
            {
                AppendToSeqAccumulator(copied);
            }
            return;
        }

        // When sequence accumulator is active, redirect attribute and document nodes to the accumulator —
        // attributes can't be serialized to XML output buffer, they need to stay as XdmAttribute objects.
        // Document nodes must stay as XdmDocument objects for instance-of document-node() to work.
        // Other node types (elements, etc.) go through normal serialization to get proper orphan copies.
        if (_sequenceAccumulator != null && ShouldAccumulate(result))
        {
            if (result is object?[] accArr)
            {
                foreach (var item in accArr)
                    if (item != null)
                        AppendToSeqAccumulator(CopyNodeForAccumulator(item));
            }
            else if (result is IEnumerable<object> accSeq && result is not string)
            {
                foreach (var item in accSeq)
                    AppendToSeqAccumulator(CopyNodeForAccumulator(item));
            }
            else if (result != null)
            {
                AppendToSeqAccumulator(CopyNodeForAccumulator(result));
            }
            return;
        }

        // XSLT 3.0 §11.9.1: xsl:copy-of preserves the SOURCE element's base URI on the
        // copied element. When a sequence accumulator is active (e.g. copy-of inside a
        // variable/param/function body), materialize copied element nodes — serialize,
        // reparse, orphan, and stamp CopySourceBaseUri — rather than flattening to text,
        // so a later read-side step can have base-uri() on the copy return the source's
        // base URI. Mirrors the xsl:copy set-site in CopyAsync. Only engages when the
        // source has a non-empty computed base URI to preserve; otherwise the normal
        // text-serialization path below runs unchanged.
        if (_sequenceAccumulator != null && _nodeStore != null
            && TryGetCopyOfElements(result, out var copyOfElems))
        {
            if (await TryAccumulateCopyOfElementsWithBaseUriAsync(copyOfElems!, copyNs).ConfigureAwait(false))
                return;
        }

        if (result is ResultTreeFragment rtf)
        {
            // Parse RTF to XDM and serialize through SerializeNode for proper namespace fixup.
            // This ensures redundant namespace declarations are stripped and missing undeclarations
            // are added based on the current output namespace context.
            var rtfDoc = ParseResultTreeFragment(rtf);
            if (rtfDoc != null)
                SerializeNode(rtfDoc, copyNs);
            else
                _output.Append(rtf.XmlContent);
        }
        else if (result is System.Xml.Linq.XNode linqNode)
        {
            // LINQ XML nodes (from fn:analyze-string, fn:json-to-xml, etc.)
            _output.Append(linqNode.ToString(System.Xml.Linq.SaveOptions.DisableFormatting));
        }
        else if (result is object?[] arr)
        {
            SerializeCopyOfItems(arr, copyNs);
        }
        else if (result is IEnumerable<object> seq)
        {
            SerializeCopyOfItems(seq.ToArray(), copyNs);
        }
        else if (result != null)
        {
            // For atomic values (string, number, etc.), add space separator between
            // adjacent atomic values per XSLT 3.0 §5.7.2
            if (result is not XdmNode and not XdmDocument and not ResultTreeFragment
                and not System.Xml.Linq.XNode and not Xdm.TextNodeItem)
            {
                if (_lastResultWasAtomic && _attributeContentDepth == 0)
                    WriteText(" ", false);
                SerializeNode(result, copyNs);
                _lastResultWasAtomic = true;
            }
            else
            {
                SerializeNode(result, copyNs, faithfulNamespaces: result is XdmDocument);
                _lastResultWasAtomic = false;
            }
        }
    }

    /// <summary>
    /// Extracts the element nodes from an xsl:copy-of result. Returns false unless the
    /// result is exclusively element node(s) (single element or a sequence of elements).
    /// Mixed or non-element results fall back to the normal serialization path so this
    /// base-URI-preserving branch never changes behavior for other node/atomic kinds.
    /// </summary>
    private static bool TryGetCopyOfElements(object? result, out List<XdmElement>? elements)
    {
        elements = null;
        if (result is XdmElement single)
        {
            elements = new List<XdmElement> { single };
            return true;
        }
        IEnumerable<object?>? items = result switch
        {
            object?[] arr => arr,
            IEnumerable<object?> seq when result is not string => seq,
            _ => null
        };
        if (items == null)
            return false;
        var collected = new List<XdmElement>();
        foreach (var item in items)
        {
            if (item is XdmElement e)
                collected.Add(e);
            else
                return false; // not a pure element sequence — defer to normal path
        }
        if (collected.Count == 0)
            return false;
        elements = collected;
        return true;
    }

    /// <summary>
    /// XSLT 3.0 §11.9.1 write-side: serialize each source element, reparse it into an
    /// orphaned <see cref="XdmElement"/>, stamp <see cref="XdmNode.CopySourceBaseUri"/>
    /// from the source's computed base URI, and append to the active sequence accumulator.
    /// Returns true only if every element was successfully materialized with a non-empty
    /// source base URI; otherwise returns false (leaving the accumulator untouched) so
    /// the caller runs the unchanged text-serialization path. Mirrors the xsl:copy
    /// set-site in <see cref="CopyAsync"/>.
    /// </summary>
    private ValueTask<bool> TryAccumulateCopyOfElementsWithBaseUriAsync(List<XdmElement> sourceElems, bool copyNamespaces)
    {
        // First pass: compute each source's base URI. Bail (return false) if any is
        // null/empty so we never partially accumulate then fall through to text.
        var baseUris = new string?[sourceElems.Count];
        for (int i = 0; i < sourceElems.Count; i++)
        {
            var bu = ComputeSourceBaseUri(sourceElems[i]);
            if (string.IsNullOrEmpty(bu))
                return new ValueTask<bool>(false);
            baseUris[i] = bu;
        }

        var staged = new List<XdmElement>(sourceElems.Count);
        for (int i = 0; i < sourceElems.Count; i++)
        {
            // Serialize the source element into an isolated buffer, then reparse into an
            // orphaned XdmElement (same mechanism as the xsl:copy accumulator path).
            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            var savedLogicalStart = _outputLogicalStart;
            _outputLogicalStart = _output.Length;
            string elemXml;
            try
            {
                SerializeNode(sourceElems[i], copyNamespaces);
                elemXml = savedScope.GetWritten();
            }
            finally
            {
                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;
            }

            XdmElement? copiedRoot = null;
            try
            {
                var settingsCopy = new System.Xml.XmlReaderSettings
                {
                    DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                    IgnoreWhitespace = false,
                    IgnoreComments = false,
                    IgnoreProcessingInstructions = false,
                };
                using var stringReaderCopy = new System.IO.StringReader($"<_copy_root_>{elemXml}</_copy_root_>");
                using var readerCopy = System.Xml.XmlReader.Create(stringReaderCopy, settingsCopy);
                var copyChildren = new List<object?>();
                ReadAsBodyChunkChildren(readerCopy, copyChildren);
                foreach (var child in copyChildren)
                {
                    if (child is XdmElement copyElem)
                    {
                        copyElem.Parent = null;
                        // Never overwrite a non-null value (e.g. a nested copy already stamped).
                        copyElem.CopySourceBaseUri ??= baseUris[i];
                        copiedRoot = copyElem;
                        break;
                    }
                }
            }
            catch (System.Xml.XmlException)
            {
                copiedRoot = null;
            }

            if (copiedRoot == null)
                return new ValueTask<bool>(false); // reparse failed — let caller fall back to text
            staged.Add(copiedRoot);
        }

        foreach (var copiedRoot in staged)
            AppendToSeqAccumulator(copiedRoot);
        return new ValueTask<bool>(true);
    }

    /// <summary>
    /// Checks whether a copy-of result contains attribute nodes that need accumulator handling.
    /// </summary>
    private static bool ShouldAccumulate(object? result)
    {
        if (result is XdmAttribute or XdmDocument)
            return true;
        if (result is object?[] arr)
            return arr.Length > 0 && arr[0] is XdmAttribute or XdmDocument;
        if (result is IEnumerable<object> seq && result is not string)
        {
            foreach (var item in seq)
                return item is XdmAttribute or XdmDocument; // check first item only
        }
        return false;
    }

    /// <summary>
    /// Creates a parentless copy of a node for sequence accumulator use.
    /// Attribute and namespace nodes need copies with no parent reference.
    /// </summary>
    private object CopyNodeForAccumulator(object item)
    {
        if (item is XdmAttribute attr)
        {
            return new XdmAttribute
            {
                Document = DocumentId.None,
                LocalName = attr.LocalName,
                Prefix = attr.Prefix,
                Namespace = attr.Namespace,
                Value = attr.Value,
                Id = _nodeStore?.NextId() ?? NodeId.None,
                Parent = NodeId.None
            };
        }
        // Deep-copy document nodes so copies have fresh node identity
        // (needed for union deduplication to work correctly)
        if (item is XdmDocument doc && _nodeStore != null)
        {
            return DeepCopyDocument(doc);
        }
        return item;
    }

    /// <summary>
    /// Creates a deep copy of an XdmDocument with fresh node IDs.
    /// Needed when copy-of in functions should return distinct node copies.
    /// </summary>
    private XdmDocument DeepCopyDocument(XdmDocument original)
    {
        var newDocId = _nodeStore!.NextId();
        var newChildren = new List<NodeId>();
        NodeId newDocElem = NodeId.None;

        foreach (var childId in original.Children)
        {
            var child = _nodeStore.GetNode(childId);
            if (child != null)
            {
                var copiedChild = DeepCopyNode(child, newDocId);
                newChildren.Add(copiedChild.Id);
                if (copiedChild is XdmElement && newDocElem == NodeId.None)
                    newDocElem = copiedChild.Id;
            }
        }

        string? docElemLocalName = newDocElem != NodeId.None
            ? (_nodeStore.GetNode(newDocElem) as XdmElement)?.LocalName : null;

        var newDoc = new XdmDocument
        {
            Id = newDocId,
            Document = new DocumentId((uint)newDocId.Value),
            Parent = NodeId.None,
            DocumentElement = newDocElem,
            Children = newChildren,
            DocumentElementLocalName = docElemLocalName
        };
        _nodeStore.Register(newDoc);
        return newDoc;
    }

    /// <summary>
    /// Recursively deep-copies an XDM node with fresh IDs, setting the given parent.
    /// </summary>
    private XdmNode DeepCopyNode(object node, NodeId parentId)
    {
        switch (node)
        {
            case XdmElement elem:
            {
                var newId = _nodeStore!.NextId();
                var newChildren = new List<NodeId>();
                foreach (var childId in elem.Children)
                {
                    var child = _nodeStore.GetNode(childId);
                    if (child != null)
                    {
                        var copied = DeepCopyNode(child, newId);
                        newChildren.Add(copied.Id);
                    }
                }
                var newAttrs = new List<NodeId>();
                foreach (var attrId in elem.Attributes)
                {
                    if (_nodeStore.GetNode(attrId) is XdmAttribute origAttr)
                    {
                        var newAttr = new XdmAttribute
                        {
                            Id = _nodeStore.NextId(),
                            Document = origAttr.Document,
                            Parent = newId,
                            LocalName = origAttr.LocalName,
                            Prefix = origAttr.Prefix,
                            Namespace = origAttr.Namespace,
                            Value = origAttr.Value
                        };
                        _nodeStore.Register(newAttr);
                        newAttrs.Add(newAttr.Id);
                    }
                }
                var newElem = new XdmElement
                {
                    Id = newId,
                    Document = elem.Document,
                    Parent = parentId,
                    LocalName = elem.LocalName,
                    Prefix = elem.Prefix,
                    Namespace = elem.Namespace,
                    NamespaceDeclarations = new List<NamespaceBinding>(elem.NamespaceDeclarations),
                    Children = newChildren,
                    Attributes = newAttrs
                };
                newElem._stringValue = elem.StringValue;
                _nodeStore.Register(newElem);
                return newElem;
            }
            case XdmText text:
            {
                var newText = new XdmText
                {
                    Id = _nodeStore!.NextId(),
                    Document = text.Document,
                    Parent = parentId,
                    Value = text.Value
                };
                _nodeStore.Register(newText);
                return newText;
            }
            case XdmComment comment:
            {
                var newComment = new XdmComment
                {
                    Id = _nodeStore!.NextId(),
                    Document = comment.Document,
                    Parent = parentId,
                    Value = comment.Value
                };
                _nodeStore.Register(newComment);
                return newComment;
            }
            case XdmProcessingInstruction pi:
            {
                var newPi = new XdmProcessingInstruction
                {
                    Id = _nodeStore!.NextId(),
                    Document = pi.Document,
                    Parent = parentId,
                    Target = pi.Target,
                    Value = pi.Value
                };
                _nodeStore.Register(newPi);
                return newPi;
            }
            default:
                return (XdmNode)node;
        }
    }

    private async ValueTask ApplyAttributeSetsAsync(List<QName> attrSetNames, StringBuilder target)
    {
        foreach (var attrSetName in attrSetNames)
        {
            // XTDE0640: detect circular attribute set references using field-level tracker
            // so cycles through LRE elements (which create new call frames) are caught
            if (!_activeAttributeSets.Add(attrSetName))
            {
                throw Error($"XTDE0640: Circular reference in attribute set '{attrSetName}'");
            }

            try
            {
                if (_stylesheet.AttributeSets.TryGetValue(attrSetName, out var attrSet))
                {
                    // Temporarily disable attribute collection mode so that the xsl:attribute
                    // instructions write to _output (which we capture) instead of _collectedAttributes
                    // Save and clear the stack, then restore after
                    var savedStack = _collectedAttributesStack.ToArray();
                    _collectedAttributesStack.Clear();

                    // Attribute sets are always applied to elements, not document nodes.
                    // Save and reset _documentNodeDepth so XTDE0420 checks don't fire.
                    var savedDocDepth = _documentNodeDepth;
                    _documentNodeDepth = 0;

                    // Per XSLT spec: only top-level variables and parameters are visible
                    // within attribute set declarations. Save/replace scope stack.
                    var savedScopes = _scopes.ToArray();
                    _scopes.Clear();
                    _scopes.Push(new Scope()); // Fresh scope with access to GlobalVariables only

                    var savedForAttr = _output.ToString();
                    _output.Clear();

                    if (attrSet.Parts is { Count: > 0 })
                    {
                        // Multiple definitions: evaluate each part's use-attribute-sets
                        // then its local attributes, in document order (XSLT 3.0 §10.2.2)
                        foreach (var part in attrSet.Parts)
                        {
                            // Flush any accumulated output before recursive call
                            target.Append(_output);
                            _output.Clear();
                            // Push xml:base onto static base URI stack for this part
                            if (part.BaseUri != null)
                                _staticBaseUriStack.Push(XsltTransformEngine.UriString(part.BaseUri)!);
                            try
                            {
                                if (part.UseAttributeSets.Count > 0)
                                    await ApplyAttributeSetsAsync(part.UseAttributeSets, target).ConfigureAwait(false);
                                foreach (var attr in part.Attributes)
                                    await attr.ExecuteAsync(this).ConfigureAwait(false);
                            }
                            finally
                            {
                                if (part.BaseUri != null)
                                    _staticBaseUriStack.Pop();
                            }
                        }
                    }
                    else
                    {
                        // Single definition: expand inherited sets first, then local attributes
                        if (attrSet.BaseUri != null)
                            _staticBaseUriStack.Push(XsltTransformEngine.UriString(attrSet.BaseUri)!);
                        try
                        {
                            if (attrSet.UseAttributeSets.Count > 0)
                                await ApplyAttributeSetsAsync(attrSet.UseAttributeSets, target).ConfigureAwait(false);
                            foreach (var attr in attrSet.Attributes)
                                await attr.ExecuteAsync(this).ConfigureAwait(false);
                        }
                        finally
                        {
                            if (attrSet.BaseUri != null)
                                _staticBaseUriStack.Pop();
                        }
                    }

                    target.Append(_output);
                    _output.Clear();
                    _output.Append(savedForAttr);

                    // Restore scope stack
                    _scopes.Clear();
                    foreach (var scope in savedScopes.Reverse())
                        _scopes.Push(scope);

                    // Restore attribute collection stack and document node depth
                    _documentNodeDepth = savedDocDepth;
                    foreach (var sb in savedStack.Reverse())
                        _collectedAttributesStack.Push(sb);
                }
            }
            finally
            {
                _activeAttributeSets.Remove(attrSetName);
            }
        }
    }

    /// <summary>
    /// EMIT side of temp-tree base-URI preservation. When <c>_tempTreeSerializeDepth &gt; 0</c>
    /// (i.e. serializing into a buffer that will be reparsed) and <paramref name="elem"/>'s
    /// computed source base URI is non-empty and differs from the enclosing serialization
    /// context (<paramref name="context"/>), appends the sentinel namespace declaration and
    /// <c>_pxbase_:base</c> attribute to the just-written start tag and updates
    /// <paramref name="context"/> to that base URI so descendants of this subtree inherit it
    /// and do not re-emit. Does nothing during final-output serialization, so the sentinel
    /// is structurally impossible to leak into the transform result. The reparse step
    /// (<see cref="ReadXdmElementFromReader"/> / <see cref="XsltTransformEngine.ConvertXmlNode"/>)
    /// always strips it.
    /// </summary>
    private void TryEmitBaseSentinel(XdmElement elem, ref string? context)
    {
        if (_tempTreeSerializeDepth <= 0 || _nodeStore == null)
            return;
        // Prefer an already-preserved source base URI (set by an earlier copy that hasn't
        // yet crossed a text boundary); otherwise compute it from the source tree position.
        var srcBase = elem.CopySourceBaseUri ?? ComputeSourceBaseUri(elem);
        if (string.IsNullOrEmpty(srcBase) || string.Equals(srcBase, context, StringComparison.Ordinal))
            return;
        _output.Append(" xmlns:");
        _output.Append(XsltTransformEngine.BaseSentinelPrefix);
        _output.Append("=\"");
        _output.Append(EscapeAttributeValue(XsltTransformEngine.BaseSentinelNs));
        _output.Append("\" ");
        _output.Append(XsltTransformEngine.BaseSentinelPrefix);
        _output.Append(':');
        _output.Append(XsltTransformEngine.BaseSentinelLocalName);
        _output.Append("=\"");
        _output.Append(EscapeAttributeValue(srcBase));
        _output.Append('"');
        context = srcBase;
    }

    private void SerializeNode(object node, bool copyNamespaces = true, bool faithfulNamespaces = false)
    {
        switch (node)
        {
            case XdmDocument doc:
                if (_nodeStore != null)
                {
                    foreach (var child in _nodeStore.GetChildren(doc))
                        SerializeNode(child, copyNamespaces, faithfulNamespaces);
                }
                break;

            case XdmElement elem:
            {
                var eName = !string.IsNullOrEmpty(elem.Prefix) ? $"{elem.Prefix}:{elem.LocalName}" : elem.LocalName;
                _output.Append('<');
                _output.Append(eName);

                // Serialize namespace declarations, skipping those already in scope
                var nsBindings = new Dictionary<string, string>();
                foreach (var nsDecl in elem.NamespaceDeclarations)
                {
                    var uri = _nodeStore?.GetNamespaceUri(nsDecl.Namespace) ?? "";
                    var prefix = nsDecl.Prefix ?? "";
                    nsBindings[prefix] = uri;

                    // When copy-namespaces="no", only emit namespaces that are in use
                    // (element prefix or attribute prefix)
                    if (!copyNamespaces)
                    {
                        var isUsedByElement = prefix == (elem.Prefix ?? "");
                        var isUsedByAttr = false;
                        if (_nodeStore != null)
                        {
                            foreach (var a in _nodeStore.GetAttributes(elem))
                            {
                                if (a.Prefix == prefix && !string.IsNullOrEmpty(prefix))
                                {
                                    isUsedByAttr = true;
                                    break;
                                }
                            }
                        }
                        if (!isUsedByElement && !isUsedByAttr)
                            continue;
                    }

                    // Skip if already declared by an ancestor with same prefix→URI
                    if (IsNamespaceInScope(prefix, uri))
                        continue;

                    _output.Append(" xmlns");
                    if (!string.IsNullOrEmpty(prefix))
                    {
                        _output.Append(':');
                        _output.Append(prefix);
                    }
                    _output.Append("=\"");
                    _output.Append(EscapeAttributeValue(uri));
                    _output.Append('"');
                }

                // Default namespace undeclaration: if the element has no default namespace
                // binding in its namespace declarations, but the output context has a non-empty
                // default namespace, emit xmlns="" to undeclare it.
                if (!nsBindings.ContainsKey(""))
                {
                    var needsUndeclaration = false;
                    if (string.IsNullOrEmpty(elem.Prefix))
                    {
                        // Unprefixed element in null namespace — always undeclare
                        var elemNsUri = _nodeStore?.GetNamespaceUri(elem.Namespace) ?? "";
                        if (string.IsNullOrEmpty(elemNsUri))
                            needsUndeclaration = true;
                    }
                    else if (faithfulNamespaces)
                    {
                        // Prefixed element during faithful document copy — the source had
                        // xmlns="" (which GetNamespacesInScope(All) omits during XDM parsing).
                        // Check if the XDM parent element has a default namespace that this
                        // element lacks, indicating we need to preserve the undeclaration.
                        if (_nodeStore != null)
                        {
                            var parentNode = elem.Parent.HasValue && elem.Parent.Value != NodeId.None
                                ? _nodeStore.GetNode(elem.Parent.Value) : null;
                            if (parentNode is XdmElement parentElem)
                            {
                                foreach (var nsDecl in parentElem.NamespaceDeclarations)
                                {
                                    if (string.IsNullOrEmpty(nsDecl.Prefix))
                                    {
                                        var parentNsUri = _nodeStore.GetNamespaceUri(nsDecl.Namespace) ?? "";
                                        if (!string.IsNullOrEmpty(parentNsUri))
                                            needsUndeclaration = true;
                                        break;
                                    }
                                }
                            }
                        }
                    }

                    if (needsUndeclaration)
                    {
                        var parentDefaultNs = GetInScopeDefaultNamespace();
                        if (parentDefaultNs != null)
                        {
                            _output.Append(" xmlns=\"\"");
                            nsBindings[""] = "";
                        }
                    }
                }

                // Namespace fixup: ensure the element's own prefix→URI is declared. When a
                // node is detached from its source tree (e.g. selected via xsl:sequence from
                // a variable) and serialized in a new context, the prefix binding from the
                // source's ancestor chain is not present in either the local declarations or
                // the output scope. Emit it now so re-parsing produces a well-formed document.
                {
                    var elemPrefixForFixup = elem.Prefix ?? "";
                    if (!string.IsNullOrEmpty(elemPrefixForFixup) && !nsBindings.ContainsKey(elemPrefixForFixup))
                    {
                        var elemNsUri = _nodeStore?.GetNamespaceUri(elem.Namespace) ?? "";
                        if (!string.IsNullOrEmpty(elemNsUri) && !IsNamespaceInScope(elemPrefixForFixup, elemNsUri))
                        {
                            _output.Append(" xmlns:");
                            _output.Append(elemPrefixForFixup);
                            _output.Append("=\"");
                            _output.Append(EscapeAttributeValue(elemNsUri));
                            _output.Append('"');
                            nsBindings[elemPrefixForFixup] = elemNsUri;
                        }
                    }
                }

                // Serialize attributes
                if (_nodeStore != null)
                {
                    foreach (var a in _nodeStore.GetAttributes(elem))
                    {
                        var aName = a.Prefix != null ? $"{a.Prefix}:{a.LocalName}" : a.LocalName;
                        _output.Append(' ');
                        _output.Append(aName);
                        _output.Append("=\"");
                        _output.Append(EscapeAttributeValue(a.Value));
                        _output.Append('"');
                    }
                }

                // EMIT (temp-tree base-URI preservation): when serializing into a buffer that
                // will be reparsed and this element's source base URI differs from the enclosing
                // serialization context, append the sentinel xmlns + attribute to the start tag.
                // Only fires on subtree roots where the base changes; descendants inherit the
                // updated context and stay silent. Never fires for final-output serialization
                // (_tempTreeSerializeDepth == 0).
                var savedBaseContext = _serializeBaseContext;
                TryEmitBaseSentinel(elem, ref _serializeBaseContext);

                // Serialize children with namespace scope tracking
                var hasChildren = false;
                if (_nodeStore != null)
                {
                    var children = _nodeStore.GetChildren(elem).ToList();
                    if (children.Count > 0)
                    {
                        hasChildren = true;
                        _output.Append('>');
                        PushOutputNsScope(nsBindings);
                        foreach (var child in children)
                            SerializeNode(child, copyNamespaces, faithfulNamespaces);
                        PopOutputNsScope();
                        _output.Append("</");
                        _output.Append(eName);
                        _output.Append('>');
                    }
                }
                if (!hasChildren)
                    _output.Append("/>");
                _serializeBaseContext = savedBaseContext;
                break;
            }

            case XdmAttribute attr:
            {
                // XTDE0420: Cannot add attribute to a document node
                if (_documentNodeDepth > 0 && !_attributeCollecting)
                    throw new XsltException("XTDE0420: Cannot add an attribute node to a document node", _currentInstructionLocation);
                // XTDE0410: Cannot add attribute after child content has been added
                // Inside xsl:where-populated, defer this check until after filtering
                if (_attributeCollecting && _output.Length > _outputLogicalStart && !IsBackwardsCompatible && _wherePopulatedDepth == 0)
                    throw new XsltException("XTDE0410: Cannot add an attribute to an element after children have been added", _currentInstructionLocation);

                var target = _attributeCollecting ? _collectedAttributes! : _output;
                var attrPrefix = attr.Prefix;
                var attrLocalName = attr.LocalName;

                // Namespace fixup: emit namespace declaration for prefixed attributes
                if (!string.IsNullOrEmpty(attrPrefix) && attrPrefix != "xml" && _sequenceAccumulator == null)
                {
                    var attrNsUri = _nodeStore?.GetNamespaceUri(attr.Namespace) ?? "";
                    if (!string.IsNullOrEmpty(attrNsUri))
                    {
                        if (!IsNamespaceInScope(attrPrefix, attrNsUri))
                        {
                            // Check for prefix clash: same prefix bound to different URI
                            if (IsPrefixInUse(attrPrefix))
                            {
                                attrPrefix = GenerateUniquePrefix(attrPrefix);
                            }
                            target.Append(" xmlns:");
                            target.Append(attrPrefix);
                            target.Append("=\"");
                            target.Append(EscapeAttributeValue(attrNsUri));
                            target.Append('"');
                            if (_outputNsScopes.Count > 0)
                                _outputNsScopes.Peek()[attrPrefix] = attrNsUri;
                        }
                    }
                }

                var aName = attrPrefix != null ? $"{attrPrefix}:{attrLocalName}" : attrLocalName;
                target.Append(' ');
                target.Append(aName);
                target.Append("=\"");
                target.Append(EscapeAttributeValue(attr.Value));
                target.Append('"');
                break;
            }

            case XdmNamespace nsNode:
            {
                // Per XSLT 3.0 §5.7.3.1, copying a namespace node adds the namespace
                // declaration to the containing element. Without this case, the node
                // fell through to default (WriteText(node.ToString())) which emitted
                // the URI as text content. Found while transpiling Docbook xform-locale.xsl,
                // whose `xsl:copy-of select="@*,namespace::*[…]"` poisoned every locale
                // template with a leading docbook-namespace text node.
                if (_documentNodeDepth > 0 && !_attributeCollecting)
                    throw new XsltException("XTDE0440: Cannot add a namespace node to a document node", _currentInstructionLocation);
                if (_attributeCollecting && _output.Length > _outputLogicalStart && !IsBackwardsCompatible && _wherePopulatedDepth == 0)
                    throw new XsltException("XTDE0410: Cannot add a namespace node to an element after children have been added", _currentInstructionLocation);

                var prefix = nsNode.Prefix ?? "";
                var uri = nsNode.Uri ?? "";

                // Skip the special "xml" prefix — it's always implicitly bound and must not be redeclared.
                if (prefix == "xml")
                    break;
                // Suppress redundant declarations already in the output namespace scope.
                if (IsNamespaceInScope(prefix, uri))
                    break;

                var target = _attributeCollecting ? _collectedAttributes! : _output;
                target.Append(" xmlns");
                if (!string.IsNullOrEmpty(prefix))
                {
                    target.Append(':');
                    target.Append(prefix);
                }
                target.Append("=\"");
                target.Append(EscapeAttributeValue(uri));
                target.Append('"');
                if (_outputNsScopes.Count > 0)
                    _outputNsScopes.Peek()[prefix] = uri;
                break;
            }

            case XdmText text:
                WriteText(text.Value, false);
                break;

            case XdmComment comment:
                _output.Append("<!--");
                _output.Append(EscapeCommentValue(comment.Value));
                _output.Append("-->");
                break;

            case XdmProcessingInstruction pi:
                _output.Append("<?");
                _output.Append(pi.Target);
                if (!string.IsNullOrEmpty(pi.Value))
                {
                    _output.Append(' ');
                    _output.Append(EscapePIValue(pi.Value));
                }
                _output.Append("?>");
                break;

            case ResultTreeFragment rtf:
                _output.Append(rtf.XmlContent);
                break;

            case System.Xml.Linq.XNode linqNode:
                _output.Append(linqNode.ToString(System.Xml.Linq.SaveOptions.DisableFormatting));
                break;

            case Xdm.TextNodeItem tni:
                WriteText(tni.Value, false);
                break;

            case string str:
                WriteText(str, false);
                break;

            case bool b:
                WriteText(b ? "true" : "false", false);
                break;

            case float f:
                WriteText(FormatFloat(f), false);
                break;

            case double d:
                WriteText(FormatDouble(d), false);
                break;

            case Xdm.DayTimeDuration dtd:
                WriteText(dtd.ToString(), false);
                break;

            default:
                WriteText(node.ToString() ?? "", false);
                break;
        }
    }

    public override async ValueTask SequenceAsync(XsltSequence instruction)
    {
        // SM-ctx streaming handoff: a consuming simple-map LEFT ! RIGHT select whose
        // RIGHT was registered as an inline-driven subscription streams in place.
        if (await TryHandoffSimpleMapContextStreamingAsync(instruction.Select).ConfigureAwait(false))
            return;

        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            if (result != null)
            {
                // If we're collecting sequence items (variable body with as="type *"),
                // add individual items rather than serializing to output
                if (_sequenceAccumulator != null)
                {
                    if (result is object?[] arr)
                    {
                        foreach (var item in arr)
                            AppendToSeqAccumulator(item);
                    }
                    else if (result is System.Collections.IEnumerable enumerable && result is not string && result is not XdmNode && result is not IDictionary<object, object?> && result is not List<object?>)
                    {
                        foreach (var item in enumerable)
                            AppendToSeqAccumulator(item);
                    }
                    else
                    {
                        AppendToSeqAccumulator(result);
                    }
                }
                else
                {
                    // xsl:sequence produces atomic values — strings from XPath expressions
                    // are xs:string atomic values that need space separation per XSLT 3.0 spec 5.7.2.
                    if (result is string str)
                    {
                        // In where-populated scopes (Phase 2 of on-non-empty), empty strings
                        // are insignificant (XSLT 3.0 §11.4). Skip emitting separators for them
                        // so zero-length items don't produce whitespace in the final output.
                        if (str.Length == 0 && _wherePopulatedDepth > 0)
                        {
                            // Don't emit separator or content, but preserve atomic state
                        }
                        else
                        {
                            if (_lastResultWasAtomic && _attributeContentDepth == 0)
                            {
                                var sep = _itemSeparatorOverride ?? " ";
                                WriteText(sep, false);
                                // Track separator chars so EndContentTracking can distinguish
                                // separator-only growth from significant content growth.
                                if (_contentTrackingStack.Count > 0)
                                    _separatorCharsWritten += sep.Length;
                            }
                            WriteText(str, false);
                            _lastResultWasAtomic = true;
                        }
                    }
                    else
                    {
                        SerializeResult(result!);
                    }
                }
            }
        }
        else if (instruction.Content != null)
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
    }

    /// <summary>
    /// SM-ctx (OP-bucket phase 1): evaluates a consuming simple-map RIGHT expression
    /// against the currently-bound (materialized) context item and emits its result to
    /// the active output exactly as <c>xsl:value-of</c>/<c>xsl:sequence</c> would — atomic
    /// results space-separated per XPath atomization (with cross-call continuity via
    /// <see cref="_lastResultWasAtomic"/> so successive matched items separate correctly),
    /// node results serialized. Called once per matched item by the streaming dispatch.
    /// </summary>
    /// <summary>
    /// ForExpr streaming (sx-ForExpr): emits one matched item of a streamable
    /// <c>for $x in CONSUMING-PATH return EXPR</c>. The matched element snapshot is the
    /// current context item; this evaluates the trailing grounding step
    /// (<see cref="ForEachSubscription.RangeBindExpression"/>) against it to produce the
    /// range variable's value, binds <see cref="ForEachSubscription.RangeVariable"/> in a
    /// fresh scope (iterating if the grounded value is a sequence, per XPath <c>for</c>
    /// semantics), evaluates the <c>return</c> expression
    /// (<see cref="ForEachSubscription.PerItemSelect"/>), and emits each result through the
    /// same atomic-spacing/serialization path as <see cref="EmitSimpleMapContextResultAsync"/>.
    /// </summary>
    internal async ValueTask EmitForExpressionResultAsync(ForEachSubscription sub)
    {
        var bindValue = await EvaluateAsync(sub.RangeBindExpression!).ConfigureAwait(false);

        // Normalize the grounded bind value to the sequence of items the range variable
        // iterates. A single atomic/node binds once; a sequence binds once per member.
        PushScope();
        try
        {
            if (bindValue is object?[] arr)
            {
                foreach (var member in arr)
                {
                    SetVariable(sub.RangeVariable!.Value, member);
                    await EmitForExpressionReturnAsync(sub.PerItemSelect!).ConfigureAwait(false);
                }
            }
            else if (bindValue is System.Collections.IEnumerable en && bindValue is not string
                && bindValue is not XdmNode && bindValue is not ResultTreeFragment)
            {
                foreach (var member in en)
                {
                    SetVariable(sub.RangeVariable!.Value, member);
                    await EmitForExpressionReturnAsync(sub.PerItemSelect!).ConfigureAwait(false);
                }
            }
            else
            {
                // Empty sequence (null) still iterates zero times under for semantics.
                if (bindValue != null)
                {
                    SetVariable(sub.RangeVariable!.Value, bindValue);
                    await EmitForExpressionReturnAsync(sub.PerItemSelect!).ConfigureAwait(false);
                }
            }
        }
        finally
        {
            PopScope();
        }
    }

    /// <summary>
    /// Evaluates and emits a single <c>return</c> result of a streamable ForExpr, with the
    /// range variable already bound. Mirrors <see cref="EmitSimpleMapContextResultAsync"/>'s
    /// atomic-string spacing and node serialization.
    /// </summary>
    private async ValueTask EmitForExpressionReturnAsync(XQueryExpression returnExpr)
    {
        var result = await EvaluateAsync(returnExpr).ConfigureAwait(false);
        if (result == null)
            return;

        if (result is string str)
        {
            if (str.Length == 0 && _wherePopulatedDepth > 0)
                return;
            if (_lastResultWasAtomic && _attributeContentDepth == 0)
            {
                var sep = _itemSeparatorOverride ?? " ";
                WriteText(sep, false);
                if (_contentTrackingStack.Count > 0)
                    _separatorCharsWritten += sep.Length;
            }
            WriteText(str, false);
            _lastResultWasAtomic = true;
        }
        else
        {
            SerializeResult(result);
        }
    }

    internal async ValueTask EmitSimpleMapContextResultAsync(XQueryExpression perItemSelect)
    {
        var result = await EvaluateAsync(perItemSelect).ConfigureAwait(false);
        if (result == null)
            return;

        // Mirror SequenceAsync's atomic-string handling: a top-level string from an
        // XPath expression is an xs:string atomic value that takes a space separator
        // from a preceding atomic item (XSLT 3.0 §5.7.2). SerializeResult handles
        // sequences/arrays/nodes (and their internal atomic spacing) directly.
        if (result is string str)
        {
            if (str.Length == 0 && _wherePopulatedDepth > 0)
                return;
            if (_lastResultWasAtomic && _attributeContentDepth == 0)
            {
                var sep = _itemSeparatorOverride ?? " ";
                WriteText(sep, false);
                if (_contentTrackingStack.Count > 0)
                    _separatorCharsWritten += sep.Length;
            }
            WriteText(str, false);
            _lastResultWasAtomic = true;
        }
        else
        {
            SerializeResult(result);
        }
    }

    /// <summary>
    /// Serializes a result value: XDM nodes are serialized as XML, atomic values as text.
    /// Adjacent atomic values in a sequence are separated by a space.
    /// </summary>
    private void SerializeResult(object result)
    {
        // XTDE0450: Maps and function items cannot be serialized as element/document content
        if (result is IDictionary<object, object?>)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a map");
        if (result is PhoenixmlDb.XQuery.Ast.XQueryFunction)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a function item");
        // XSLT 3.0 §5.7.2: Arrays in content sequences are flattened — members extracted recursively
        if (result is List<object?> arrayList)
        {
            foreach (var member in arrayList)
            {
                if (member != null)
                    SerializeResult(member);
            }
            return;
        }

        if (result is XdmNode)
        {
            // In simple content mode (comment/PI/attribute body), atomize nodes
            // to their string value instead of serializing as XML markup.
            if (_textContentDepth > 0)
                WriteText(StringValueOf(result), false);
            else
                SerializeNode(result);
            _lastResultWasAtomic = false;
        }
        else if (result is ResultTreeFragment rtf)
        {
            // Parse RTF and serialize through SerializeNode for proper namespace fixup
            var rtfDoc = ParseResultTreeFragment(rtf);
            if (rtfDoc != null)
                SerializeNode(rtfDoc);
            else
                _output.Append(rtf.XmlContent);
            _lastResultWasAtomic = false;
        }
        else if (result is System.Xml.Linq.XNode linqNode)
        {
            // LINQ XML nodes (from fn:analyze-string, fn:parse-xml, etc.)
            if (_textContentDepth > 0)
                WriteText(linqNode.ToString(System.Xml.Linq.SaveOptions.DisableFormatting), false);
            else
                _output.Append(linqNode.ToString(System.Xml.Linq.SaveOptions.DisableFormatting));
            _lastResultWasAtomic = false;
        }
        else if (result is object?[] arr)
        {
            SerializeSequenceItems(arr);
        }
        else if (result is System.Collections.IEnumerable enumerable && result is not string)
        {
            var items = new System.Collections.ArrayList();
            foreach (var item in enumerable)
                if (item != null)
                    items.Add(item);
            SerializeSequenceItems(items);
        }
        else if (result is Xdm.TextNodeItem tni)
        {
            // TextNodeItem: text node from sequence accumulator — not atomic.
            WriteText(tni.Value, false);
            _lastResultWasAtomic = false;
        }
        else if (result is string str)
        {
            // Text content (from sort results, text nodes, etc.) — not atomic.
            // Atomic string spacing is handled at the source (SequenceAsync, OnEmptyAsync)
            // where we know the string comes from an XPath expression.
            WriteText(str, false);
            _lastResultWasAtomic = false;
        }
        else
        {
            // Atomic value: add separator if previous result was also atomic
            if (_lastResultWasAtomic && _attributeContentDepth == 0)
                WriteText(_itemSeparatorOverride ?? " ", false);
            if (result is bool b)
                WriteText(b ? "true" : "false", false);
            else if (result is TimeSpan ts)
                WriteText(System.Xml.XmlConvert.ToString(ts), false);
            else if (result is Xdm.DayTimeDuration dtd)
                WriteText(dtd.ToString(), false);
            else if (result is float f)
                WriteText(FormatFloat(f), false);
            else if (result is double d)
                WriteText(FormatDouble(d), false);
            else if (result is decimal m)
                // Canonical xs:decimal lexical form (e.g. 25.0m → "25"); CLR
                // decimal.ToString() retains the source scale ("25.0").
                WriteText(FormatDecimal(m), false);
            else
                WriteText(result.ToString() ?? "", false);
            _lastResultWasAtomic = true;
        }
    }

    /// <summary>
    /// §5.7.2 simple content merging: merge adjacent text nodes (TextNodeItem, XdmText),
    /// remove zero-length text nodes, then join remaining items with separator.
    /// Plain strings (from xsl:sequence of atomic values) are NOT merged with text nodes.
    /// </summary>
    private static string MergeSimpleContent(List<object?> items, string separator)
    {
        // Step 1: Merge adjacent text nodes (TextNodeItem, XdmText, XdmNode text)
        var merged = new List<object?>();
        System.Text.StringBuilder? textRun = null;
        foreach (var item in items)
        {
            if (item is Xdm.TextNodeItem tni)
            {
                textRun ??= new System.Text.StringBuilder();
                textRun.Append(tni.Value);
            }
            else if (item is Xdm.Nodes.XdmText xt)
            {
                textRun ??= new System.Text.StringBuilder();
                textRun.Append(xt.Value);
            }
            else
            {
                if (textRun != null)
                {
                    // Step 2: Remove zero-length merged text nodes
                    if (textRun.Length > 0)
                        merged.Add(textRun.ToString());
                    textRun = null;
                }
                if (item != null)
                    merged.Add(item);
            }
        }
        if (textRun != null && textRun.Length > 0)
            merged.Add(textRun.ToString());

        // Step 3: Convert to strings and join with separator
        return string.Join(separator, merged.Select(StringValueOf));
    }

    private void SerializeSequenceItems(System.Collections.IList items)
    {
        // Use local tracking for inter-item spacing within the sequence.
        // Inherit _lastResultWasAtomic for space before first item (cross-call continuity).
        var lastWasAtomic = _lastResultWasAtomic;
        // Separator between adjacent atomized items:
        // - In element content or comment/PI body: single space (or item-separator override)
        // - In attribute content: zero-length (no separator)
        var useSeparator = _attributeContentDepth == 0;
        var separator = _itemSeparatorOverride ?? " ";
        foreach (var item in items)
        {
            if (item == null)
                continue;
            var isNode = item is XdmNode || item is Xdm.TextNodeItem;
            // In text content mode, nodes are atomized to strings, so treat as atomic for separator logic
            var isAtomic = _textContentDepth > 0 || !isNode;
            if (useSeparator && isAtomic && lastWasAtomic)
            {
                WriteText(separator, false);
            }
            // Reset before inner call to prevent non-string atomics from double-adding spaces
            _lastResultWasAtomic = false;
            SerializeResult(item);
            lastWasAtomic = isAtomic;
        }
        // Set for cross-call continuity after the sequence
        _lastResultWasAtomic = lastWasAtomic;
    }

    /// <summary>
    /// Serializes items from xsl:copy-of, handling text separators for atomic values
    /// and copy-namespaces for node items.
    /// </summary>
    private void SerializeCopyOfItems(object?[] items, bool copyNamespaces)
    {
        var lastWasAtomic = _lastResultWasAtomic;
        var useSeparator = _attributeContentDepth == 0;
        foreach (var item in items)
        {
            if (item == null)
                continue;
            if (item is ResultTreeFragment r)
            {
                _output.Append(r.XmlContent);
                lastWasAtomic = false;
            }
            else if (item is XdmNode || item is XdmDocument)
            {
                SerializeNode(item, copyNamespaces);
                lastWasAtomic = false;
            }
            else if (item is Xdm.TextNodeItem tni)
            {
                WriteText(tni.Value, false);
                lastWasAtomic = false;
            }
            else
            {
                // Atomic value: add text separator between adjacent atomic values
                if (useSeparator && lastWasAtomic)
                    WriteText(" ", false);
                _lastResultWasAtomic = false;
                SerializeResult(item);
                lastWasAtomic = true;
            }
        }
        _lastResultWasAtomic = lastWasAtomic;
    }

    public override async ValueTask CreateCommentAsync(XsltComment instruction)
    {
        string value;

        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            value = StringValueOf(result);
        }
        else if (instruction.Content != null)
        {
            // §5.7.2 simple content: collect each instruction's output as a separate
            // item in the accumulator, then join with space separator.
            var savedAccumulator = _sequenceAccumulator;
            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            var savedCollectText = _collectTextAsSequenceItems;
            var savedElemDepth = _serializingElementDepth;
            var savedLastWasNode = _simpleContentLastWasNode;
            var savedAtomic = _lastResultWasAtomic;
            _sequenceAccumulator = new List<object?>();
            _collectTextAsSequenceItems = true;
            _serializingElementDepth = 0;
            _simpleContentLastWasNode = false;
            _lastResultWasAtomic = false;
            _textContentDepth++;
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _textContentDepth--;
                _collectTextAsSequenceItems = savedCollectText;
                _serializingElementDepth = savedElemDepth;
                _simpleContentLastWasNode = savedLastWasNode;
                _lastResultWasAtomic = savedAtomic;
            }

            // Flush any trailing text to accumulator
            var trailingText = savedScope.GetWritten();
            if (trailingText.Length > 0)
                AppendToSeqAccumulator(new Xdm.TextNodeItem(trailingText));

            value = MergeSimpleContent(_sequenceAccumulator, " ");
            _sequenceAccumulator = savedAccumulator;
            savedScope.Dispose();
        }
        else
        {
            value = "";
        }

        _output.Append("<!--");
        _output.Append(EscapeCommentValue(value));
        _output.Append("-->");

        // Comments count as "populated" for xsl:where-populated
        MarkContentProduced();
        // Comment is a node, so it breaks adjacent atomic value chain
        _lastResultWasAtomic = false;
    }

    public override async ValueTask CreatePIAsync(XsltProcessingInstruction instruction)
    {
        var name = await EvaluateAvtAsync(instruction.Name).ConfigureAwait(false);

        // XTDE0890: The name must be a valid NCName and a valid PITarget
        try
        { System.Xml.XmlConvert.VerifyNCName(name); }
        catch (System.Xml.XmlException)
        {
            throw Error($"XTDE0890: The effective value of the 'name' attribute of xsl:processing-instruction ('{name}') is not a valid NCName");
        }
        if (string.Equals(name, "xml", StringComparison.OrdinalIgnoreCase))
            throw Error($"XTDE0890: The name '{name}' is not allowed as a processing instruction target");

        string value;
        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            value = StringValueOf(result);
        }
        else if (instruction.Content != null)
        {
            // §5.7.2 simple content: same pattern as xsl:comment
            var savedAccumulator = _sequenceAccumulator;
            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            var savedCollectText = _collectTextAsSequenceItems;
            var savedElemDepth = _serializingElementDepth;
            var savedLastWasNode = _simpleContentLastWasNode;
            var savedAtomic = _lastResultWasAtomic;
            _sequenceAccumulator = new List<object?>();
            _collectTextAsSequenceItems = true;
            _serializingElementDepth = 0;
            _simpleContentLastWasNode = false;
            _lastResultWasAtomic = false;
            _textContentDepth++;
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _textContentDepth--;
                _collectTextAsSequenceItems = savedCollectText;
                _serializingElementDepth = savedElemDepth;
                _simpleContentLastWasNode = savedLastWasNode;
                _lastResultWasAtomic = savedAtomic;
            }

            var trailingText = savedScope.GetWritten();
            if (trailingText.Length > 0)
                AppendToSeqAccumulator(new Xdm.TextNodeItem(trailingText));

            value = MergeSimpleContent(_sequenceAccumulator, " ");
            _sequenceAccumulator = savedAccumulator;
            savedScope.Dispose();
        }
        else
        {
            value = "";
        }

        // XSLT spec: strip leading whitespace from PI value
        value = value.TrimStart();

        _output.Append("<?");
        _output.Append(name);
        if (!string.IsNullOrEmpty(value))
        {
            _output.Append(' ');
            _output.Append(EscapePIValue(value));
        }
        _output.Append("?>");

        // Processing instructions count as "populated" for xsl:where-populated
        MarkContentProduced();
        // PI is a node, so it breaks adjacent atomic value chain
        _lastResultWasAtomic = false;
    }

    public override async ValueTask CreateNamespaceAsync(XsltNamespace instruction)
    {
        var prefix = await EvaluateAvtAsync(instruction.Name).ConfigureAwait(false);

        // XTDE0920: Name must be a valid NCName (and not "xmlns")
        if (string.Equals(prefix, "xmlns", StringComparison.Ordinal))
            throw Error("XTDE0920: The name 'xmlns' is not allowed as the prefix for xsl:namespace");
        if (!string.IsNullOrEmpty(prefix))
        {
            try
            { System.Xml.XmlConvert.VerifyNCName(prefix); }
            catch (System.Xml.XmlException)
            {
                throw Error($"XTDE0920: The effective value of the 'name' attribute of xsl:namespace ('{prefix}') is not a valid NCName");
            }
        }

        string uri;
        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            uri = StringValueOf(result);
        }
        else if (instruction.Content != null)
        {
            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            // Save/restore sequence accumulator to prevent xsl:value-of inside namespace
            // content from leaking TextNodeItems into the function's accumulator
            var savedAccumNs = _sequenceAccumulator;
            _sequenceAccumulator = null;
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            _sequenceAccumulator = savedAccumNs;
            uri = savedScope.GetWritten();
            savedScope.Dispose();
        }
        else
        {
            uri = "";
        }

        // XTDE0930: The namespace URI must not be empty when a prefix is specified
        if (!string.IsNullOrEmpty(prefix) && string.IsNullOrEmpty(uri))
            throw Error($"XTDE0930: The string value of the xsl:namespace node is a zero-length string, but a prefix ('{prefix}') was specified");

        // XTDE0925: xml namespace rules
        if (string.Equals(prefix, "xml", StringComparison.Ordinal)
            && !string.Equals(uri, "http://www.w3.org/XML/1998/namespace", StringComparison.Ordinal))
            throw Error("XTDE0925: Prefix 'xml' must be bound to 'http://www.w3.org/XML/1998/namespace'");
        if (!string.Equals(prefix, "xml", StringComparison.Ordinal)
            && string.Equals(uri, "http://www.w3.org/XML/1998/namespace", StringComparison.Ordinal))
            throw Error("XTDE0925: Only the prefix 'xml' can be bound to 'http://www.w3.org/XML/1998/namespace'");

        // XTDE0905: The namespace URI must be valid and not the xmlns namespace
        if (string.Equals(uri, "http://www.w3.org/2000/xmlns/", StringComparison.Ordinal))
            throw Error("XTDE0905: The namespace URI 'http://www.w3.org/2000/xmlns/' is not allowed");
        // XTDE0905: Namespace URI must be a valid xs:anyURI. Use Uri.TryCreate(Absolute)
        // which is permissive (accepts IRI chars like | and "). For relative URIs, accept
        // anything that doesn't have multiple # delimiters (only one fragment allowed).
        if (!string.IsNullOrWhiteSpace(uri)
            && !Uri.TryCreate(uri, UriKind.Absolute, out _))
        {
            // Check for multiple # characters (invalid fragment syntax)
            var firstHash = uri.IndexOf('#', StringComparison.Ordinal);
            if (firstHash >= 0 && uri.AsSpan(firstHash + 1).Contains('#'))
                throw Error($"XTDE0905: The namespace URI '{uri}' is not a valid URI");
        }

        // XTDE0420: Cannot add namespace to a document node
        if (_documentNodeDepth > 0 && !_attributeCollecting)
            throw Error("XTDE0420: Cannot add a namespace node to a document node");

        // XTDE0440: Cannot define a default namespace when the element is in no namespace
        if (string.IsNullOrEmpty(prefix) && !string.IsNullOrEmpty(uri)
            && _outputElementHasNsStack.Count > 0 && !_outputElementHasNsStack.Peek())
            throw Error($"XTDE0440: Cannot define a default namespace ('{uri}') when the element being constructed is in no namespace");

        // XTDE0430: Duplicate namespace nodes with same prefix but different URIs
        var nsPrefix = prefix ?? "";
        if (_xslNamespaceBindings.Count > 0)
        {
            var currentBindings = _xslNamespaceBindings.Peek();
            if (currentBindings.TryGetValue(nsPrefix, out var existingUri) && existingUri != uri)
                throw Error($"XTDE0430: Two namespace nodes with the same prefix '{nsPrefix}' have different namespace URIs ('{existingUri}' and '{uri}')");
            currentBindings[nsPrefix] = uri;
        }

        // Conflicts between xsl:namespace and the element's own namespace bindings
        // are detected at element construction time, where we can check whether
        // exclude-result-prefixes was set (→ namespace fixup) or not (→ XTDE0430).

        // If sequence accumulator is active, create an XdmNamespace node for the sequence
        if (_sequenceAccumulator != null)
        {
            var nsNode = new XdmNamespace
            {
                Id = NodeId.None,
                Document = DocumentId.None,
                Parent = NodeId.None,
                Prefix = prefix ?? "",
                Uri = uri
            };
            AppendToSeqAccumulator(nsNode);
            return;
        }

        // Namespace declarations should appear in the element's start tag,
        // so write to _collectedAttributes when in attribute collection mode
        var target = _attributeCollecting ? _collectedAttributes! : _output;
        target.Append(" xmlns");
        if (!string.IsNullOrEmpty(prefix))
        {
            target.Append(':');
            target.Append(prefix);
        }
        target.Append("=\"");
        target.Append(EscapeAttributeValue(uri));
        target.Append('"');
    }

    public override async ValueTask CreateDocumentAsync(XsltDocument instruction)
    {
        // When in sequence accumulator mode and we have a node store,
        // create a proper XDM document node so pattern matching and
        // document-node functions work correctly.
        if (_sequenceAccumulator != null && _nodeStore != null)
        {
            var seqScope = new XsltTransformEngine.ScopedOutputBuffer(_output);

            // Save and clear the sequence accumulator so that child instructions
            // (like xsl:sequence) serialize to the output buffer instead of
            // leaking items to the outer accumulator.
            var savedAccumulator = _sequenceAccumulator;
            _sequenceAccumulator = null;

            // xsl:document creates a new output scope — if inside text content mode
            // (comment/PI body), temporarily exit so child instructions serialize
            // as proper XML nodes instead of atomized text.
            var savedTextContentDepth = _textContentDepth;
            var savedCollectText = _collectTextAsSequenceItems;
            if (_textContentDepth > 0)
            {
                _textContentDepth = 0;
                _collectTextAsSequenceItems = false;
            }

            _documentNodeDepth++;
            // EMIT context: content serialized here is captured as text and reparsed below,
            // so raise the temp-tree depth and seed the serialization base context with this
            // scope's effective base URI (the same value stamped on the reparsed document).
            // A SOURCE element copied in whose base differs picks up a base sentinel that the
            // reparse recovers onto CopySourceBaseUri.
            _tempTreeSerializeDepth++;
            var savedDocBaseContext = _serializeBaseContext;
            _serializeBaseContext = EffectiveBaseUri;
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _documentNodeDepth--;
                _tempTreeSerializeDepth--;
                _serializeBaseContext = savedDocBaseContext;
                _sequenceAccumulator = savedAccumulator;
                _textContentDepth = savedTextContentDepth;
                _collectTextAsSequenceItems = savedCollectText;
            }

            var content = seqScope.GetWritten();
            seqScope.Dispose();


            if (content.Length > 0)
            {
                RunValidation(instruction.Validation, content, ValidationKind.Fragment,
                    "xsl:document", instruction.Location);
                try
                {
                    // Stream-parse via XmlReader rather than allocating a full XmlDocument.
                    // Same hot-path optimization as AddBodyOutputChunk and the xsl:variable
                    // as=element(...) path: reads one synthetic wrapper element and emits
                    // its children directly into XDM nodes without an intermediate DOM.
                    var settings = new System.Xml.XmlReaderSettings
                    {
                        DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                        IgnoreWhitespace = false,
                        IgnoreComments = false,
                        IgnoreProcessingInstructions = false,
                    };
                    using var stringReader = new System.IO.StringReader($"<_seq_root_>{content}</_seq_root_>");
                    using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                    var seqBaseUri = EffectiveBaseUri;
                    var docId = _nodeStore.NextId();
                    var children = new List<NodeId>();
                    NodeId docElementId = NodeId.None;
                    var parsedChildren = new List<object?>();
                    ReadAsBodyChunkChildren(reader, parsedChildren);
                    var stringValueBuilder = new StringBuilder();
                    foreach (var item in parsedChildren)
                    {
                        if (item is XdmNode cn)
                        {
                            cn.Parent = docId;
                            children.Add(cn.Id);
                            if (cn is XdmElement && docElementId == NodeId.None)
                                docElementId = cn.Id;
                            // Concatenate descendant text values for the document's string value
                            stringValueBuilder.Append(cn.StringValue);
                        }
                    }
                    string? docElemLocalName = docElementId != NodeId.None
                        ? (_nodeStore.GetNode(docElementId) as XdmElement)?.LocalName : null;
                    var docNode = new XdmDocument
                    {
                        Id = docId,
                        Document = new DocumentId(1),
                        Parent = NodeId.None,
                        DocumentElement = docElementId,
                        Children = children,
                        DocumentElementLocalName = docElemLocalName,
                        _stringValue = stringValueBuilder.ToString(),
                    };
                    docNode.BaseUri = seqBaseUri;
                    _nodeStore.Register(docNode);
                    AppendToSeqAccumulator(docNode);
                }
                catch (System.Xml.XmlException)
                {
                    // If XML parsing fails, fall through to text output
                    _output.Append(content);
                }
            }
            else
            {
                // Empty xsl:document creates an empty document node
                var docId = _nodeStore.NextId();
                var docNode = new XdmDocument
                {
                    Id = docId,
                    Document = new DocumentId(1),
                    Parent = NodeId.None,
                    DocumentElement = NodeId.None,
                    Children = new List<NodeId>(),
                    BaseUri = EffectiveBaseUri,
                };
                _nodeStore.Register(docNode);
                AppendToSeqAccumulator(docNode);
            }

            MarkContentProduced();
            return;
        }

        // When inside text content (comment/PI/attribute), create a proper XDM document
        // node so that its string value excludes comment/PI children (per XDM spec).
        if (_textContentDepth > 0 && _nodeStore != null)
        {
            var savedOut2 = _output.ToString();
            _output.Clear();

            // Temporarily leave text content mode so nodes serialize as XML
            var savedTextDepth = _textContentDepth;
            var savedAttrDepth = _attributeContentDepth;
            _textContentDepth = 0;
            _attributeContentDepth = 0;

            _documentNodeDepth++;
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                _documentNodeDepth--;
                _textContentDepth = savedTextDepth;
                _attributeContentDepth = savedAttrDepth;
            }

            var xmlContent = _output.ToString();
            _output.Clear();
            _output.Append(savedOut2);

            if (xmlContent.Length > 0)
            {
                RunValidation(instruction.Validation, xmlContent, ValidationKind.Fragment,
                    "xsl:document", instruction.Location);
                try
                {
                    // Stream descendant text nodes — equivalent to
                    // XmlDocument.DocumentElement.InnerText without DOM allocation.
                    var docSettings = new System.Xml.XmlReaderSettings
                    {
                        Async = true,
                        DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                        IgnoreWhitespace = false,
                        IgnoreComments = true,
                        IgnoreProcessingInstructions = true,
                    };
                    using var docStringReader = new System.IO.StringReader($"<_doc_wrap_>{xmlContent}</_doc_wrap_>");
                    using var docReader = System.Xml.XmlReader.Create(docStringReader, docSettings);
                    while (await docReader.ReadAsync().ConfigureAwait(false))
                    {
                        if (docReader.NodeType is System.Xml.XmlNodeType.Text
                            or System.Xml.XmlNodeType.CDATA
                            or System.Xml.XmlNodeType.SignificantWhitespace
                            or System.Xml.XmlNodeType.Whitespace)
                        {
                            _output.Append(docReader.Value);
                        }
                    }
                }
                catch (System.Xml.XmlException)
                {
                    // Fallback: use raw text content
                    _output.Append(xmlContent);
                }
                MarkContentProduced();
            }
            return;
        }

        // Default path: buffer content to text output
        var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
        var savedLogicalStart = _outputLogicalStart;
        _outputLogicalStart = _output.Length;

        _documentNodeDepth++;
        try
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            _documentNodeDepth--;
        }

        var textContent = savedScope.GetWritten();
        savedScope.Dispose();
        _outputLogicalStart = savedLogicalStart;
        if (textContent.Length > 0)
        {
            RunValidation(instruction.Validation, textContent, ValidationKind.Fragment,
                "xsl:document", instruction.Location);
            _output.Append(textContent);
            // A non-empty document node is significant for where-populated tracking
            MarkContentProduced();
        }
    }

    /// <summary>
    /// Runs the serialized content through the registered <see cref="PhoenixmlDb.XQuery.ISchemaProvider"/>
    /// when the XSLT instruction's <c>validation=</c> attribute requests it. Modes <c>strip</c>
    /// and <c>preserve</c> are no-ops (XSLT 3.0 §27.2): they only affect type annotations on the
    /// XDM tree, which the string-output path doesn't carry.
    /// </summary>
    /// <param name="mode">The validation mode parsed from the instruction.</param>
    /// <param name="content">Already-serialized XML content to validate.</param>
    /// <param name="kind">Validation conformance: document for `xsl:result-document` / `xsl:document`,
    /// fragment for `xsl:element` / `xsl:attribute` / `xsl:copy` / `xsl:copy-of`.</param>
    /// <param name="instructionName">Used in error messages, e.g. "xsl:result-document".</param>
    /// <param name="location">Source location for the diagnostic.</param>
    private void RunValidation(Ast.ValidationMode? mode, string content, ValidationKind kind,
        string instructionName, SourceLocation? location)
    {
        PhoenixmlDb.XQuery.ValidationMode? xqueryMode = mode switch
        {
            Ast.ValidationMode.Strict => PhoenixmlDb.XQuery.ValidationMode.Strict,
            Ast.ValidationMode.Lax => PhoenixmlDb.XQuery.ValidationMode.Lax,
            _ => null,
        };
        if (xqueryMode is null) return;
        if (_schemaProvider is null)
        {
            throw new XsltException(
                $"XTTE1545: {instructionName} validation requires a registered ISchemaProvider on the XsltTransformer",
                location);
        }

        try
        {
            switch (kind)
            {
                case ValidationKind.Document:
                    _schemaProvider.ValidateXml(content, xqueryMode.Value);
                    break;
                case ValidationKind.Fragment:
                    _schemaProvider.ValidateXmlFragment(content, xqueryMode.Value,
                        inScopeNamespaces: SnapshotInScopeNamespaces());
                    break;
            }
        }
        catch (PhoenixmlDb.XQuery.SchemaValidationException ex)
        {
            throw new XsltException(
                $"{ex.ErrorCode}: {instructionName} validation failed: {ex.Message}",
                location);
        }
    }

    /// <summary>
    /// Flattens the engine's namespace scope stack into the prefix→URI bindings currently
    /// in scope (innermost wins on conflicts). Returned to the schema provider so fragment
    /// validation can resolve prefixes whose declarations live on enclosing elements.
    /// </summary>
    private Dictionary<string, string> SnapshotInScopeNamespaces()
    {
        var result = new Dictionary<string, string>(StringComparer.Ordinal);
        // Stack iterates innermost→outermost. Add innermost-first; outer scopes won't
        // overwrite already-set inner bindings (TryAdd preserves the closer declaration).
        foreach (var scope in _outputNsScopes)
        {
            foreach (var kv in scope)
                result.TryAdd(kv.Key, kv.Value);
        }
        // Stylesheet-level prefix bindings are the outermost layer.
        foreach (var kv in _stylesheet.Namespaces)
            result.TryAdd(kv.Key, kv.Value);
        return result;
    }

    private enum ValidationKind { Document, Fragment }

    private void ValidateResultDocumentContent(XsltResultDocument instruction, string content)
        => RunValidation(instruction.Validation, content, ValidationKind.Document,
            "xsl:result-document", instruction.Location);

    /// <summary>
    /// Best-effort schema check for <c>xsl:attribute validation="strict"</c>. The full XSLT
    /// 3.0 contract validates an attribute in the context of its parent element; in that
    /// context lookup we only know the attribute name, namespace, and value. We confirm a
    /// global schema-attribute declaration exists (and otherwise raise XQDY0027). Value-vs-
    /// type checking (typed casts, facet enforcement) is deferred — when the parent element
    /// also carries <c>validation="strict|lax"</c>, the element-level check covers the value.
    /// </summary>
    private void ValidateAttributeIfRequested(XsltAttribute instruction, string name, string? explicitNsUri)
    {
        if (!ShouldRunValidation(instruction.Validation)) return;
        if (_schemaProvider is null)
        {
            throw new XsltException(
                "XTTE1545: xsl:attribute validation requires a registered ISchemaProvider on the XsltTransformer",
                instruction.Location);
        }

        var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
        var localName = colonIdx >= 0 ? name[(colonIdx + 1)..] : name;
        string nsUri = explicitNsUri ?? "";
        if (string.IsNullOrEmpty(nsUri) && colonIdx > 0)
        {
            var prefix = name[..colonIdx];
            if (instruction.InScopeNamespaces.TryGetValue(prefix, out var bound))
                nsUri = bound;
        }

        if (!_schemaProvider.HasAttributeDeclaration(nsUri, localName))
        {
            if (instruction.Validation == Ast.ValidationMode.Strict)
            {
                throw new XsltException(
                    $"XQDY0027: xsl:attribute validation=\"strict\" requires a global schema-attribute declaration for '{name}' (namespace: '{nsUri}'); none found in the loaded schemas",
                    instruction.Location);
            }
            // Lax: silently skip when no declaration is found.
        }
    }

    public override async ValueTask ResultDocumentAsync(XsltResultDocument instruction)
    {
        // XTDE1480: Cannot use result-document in temporary output state (e.g., inside a variable)
        if (_temporaryOutputDepth > 0)
            throw Error("XTDE1480: It is a dynamic error to evaluate xsl:result-document in temporary output state (e.g., within a variable or parameter)");

        // XTDE1460: Validate format attribute and find matching output declaration
        XsltOutput? matchedOutput = null;
        if (instruction.Format != null)
        {
            var formatName = await EvaluateAvtAsync(instruction.Format).ConfigureAwait(false);
            if (!string.IsNullOrEmpty(formatName))
            {
                // Use compile-time resolved QName when available (handles prefix:local namespace resolution)
                if (instruction.ResolvedFormatName != null)
                {
                    var resolved = instruction.ResolvedFormatName.Value;
                    matchedOutput = _stylesheet.Outputs.FirstOrDefault(o =>
                        o.Name != null && o.Name.Value.Namespace == resolved.Namespace && o.Name.Value.LocalName == resolved.LocalName);
                    if (matchedOutput == null)
                        throw Error($"XTDE1460: The format attribute of xsl:result-document ('{formatName}') does not match any xsl:output declaration");
                }
                else
                {
                    // Dynamic AVT: parse the format name as an EQName (Q{uri}local or NCName)
                    string? formatNs = null;
                    string formatLocal = formatName;
                    if (formatName.StartsWith("Q{", StringComparison.Ordinal))
                    {
                        var closeBrace = formatName.IndexOf('}', 2);
                        if (closeBrace > 0 && closeBrace < formatName.Length - 1)
                        {
                            formatNs = formatName[2..closeBrace];
                            formatLocal = formatName[(closeBrace + 1)..];
                        }
                        else
                        {
                            throw Error($"XTDE1460: The format attribute of xsl:result-document ('{formatName}') is not a valid EQName");
                        }
                    }
                    else if (formatName.Contains(':', StringComparison.Ordinal))
                    {
                        // Prefixed QName — resolve prefix using compile-time namespace bindings
                        var colonIdx = formatName.IndexOf(':', StringComparison.Ordinal);
                        var prefix = formatName[..colonIdx];
                        formatLocal = formatName[(colonIdx + 1)..];
                        if (instruction.NamespaceBindings != null
                            && instruction.NamespaceBindings.TryGetValue(prefix, out var ns))
                        {
                            formatNs = ns;
                        }
                        else
                        {
                            throw Error($"XTDE1460: The format attribute of xsl:result-document ('{formatName}') references undeclared prefix '{prefix}'");
                        }
                    }
                    else
                    {
                        try
                        {
                            System.Xml.XmlConvert.VerifyNCName(formatName);
                        }
                        catch (System.Xml.XmlException)
                        {
                            throw Error($"XTDE1460: The format attribute of xsl:result-document ('{formatName}') is not a valid EQName");
                        }
                    }

                    // Resolve formatNs to a NamespaceId for comparison
                    var formatNsId = NamespaceId.None;
                    if (formatNs != null)
                        formatNsId = StylesheetParser.ResolveNamespaceUri(formatNs);

                    foreach (var output in _stylesheet.Outputs)
                    {
                        if (output.Name == null)
                            continue;
                        if (formatNs != null)
                        {
                            // Match by ExpandedNamespace string or by NamespaceId
                            if (output.Name.Value.LocalName == formatLocal
                                && (output.Name.Value.ExpandedNamespace == formatNs
                                    || output.Name.Value.Namespace == formatNsId))
                            { matchedOutput = output; break; }
                        }
                        else
                        {
                            if (output.Name.Value.LocalName == formatLocal && output.Name.Value.Namespace == NamespaceId.None)
                            { matchedOutput = output; break; }
                        }
                    }
                    if (matchedOutput == null)
                        throw Error($"XTDE1460: The format attribute of xsl:result-document ('{formatName}') does not match any xsl:output declaration");
                }
            }
        }

        // XTDE1490: Check for duplicate result-document URIs
        string effectiveHref = "";
        if (instruction.Href != null)
        {
            effectiveHref = await EvaluateAvtAsync(instruction.Href).ConfigureAwait(false);
        }

        // Resource policy: check write access before proceeding
        if (!string.IsNullOrEmpty(effectiveHref))
            CheckResultDocumentPolicy(effectiveHref);

        // XTDE1490: Check for duplicate result-document URIs
        // When targeting primary output (empty href) and NOT inside a secondary redirect,
        // check if primary output has already been written to (implicit content before explicit result-document)
        if (string.IsNullOrEmpty(effectiveHref) && _resultDocumentRedirectDepth == 0 &&
            (_outputElementStack.Count > 0 || _output.Length > 0))
        {
            // Primary output already has content — conflict with explicit href=""
            throw new XsltException("XTDE1490: Cannot write a second result document to the implicit primary output destination", instruction.Location);
        }
        if (!_resultDocumentUris.Add(effectiveHref))
        {
            // Report duplicate for: (a) empty href (primary output) or (b) static href literals
            if (string.IsNullOrEmpty(effectiveHref)
                || (instruction.Href != null && instruction.Href.Parts.All(p => p is AvtLiteral)))
                throw new XsltException($"XTDE1490: A result document has already been written to '{effectiveHref}'", instruction.Location);
        }

        // XTDE1500: Check if we're writing to a URI that was read during this transformation
        if (!string.IsNullOrEmpty(effectiveHref))
        {
            try
            {
                Uri resolvedWriteUri;
                if (Uri.TryCreate(effectiveHref, UriKind.Absolute, out var absUri))
                    resolvedWriteUri = absUri;
                else if (_stylesheet.BaseUri != null)
                    resolvedWriteUri = new Uri(_stylesheet.BaseUri, effectiveHref);
                else
                    resolvedWriteUri = new Uri(effectiveHref, UriKind.RelativeOrAbsolute);

                var writeUriStr = resolvedWriteUri.AbsoluteUri;
                foreach (var readUri in _documentResolver.ReadDocumentUris)
                {
                    if (string.Equals(readUri, writeUriStr, StringComparison.OrdinalIgnoreCase))
                        throw new XsltException($"XTDE1500: Cannot write to URI '{effectiveHref}' — it was read during this transformation", instruction.Location);
                }
            }
            catch (UriFormatException ex) { throw Error($"XTDE1400: Invalid URI in xsl:result-document href: {ex.Message}"); }
        }

        // Evaluate omit-xml-declaration from xsl:result-document (AVT)
        bool? resultOmitXmlDecl = null;
        if (instruction.OmitXmlDeclaration != null)
        {
            var omitStr = await EvaluateAvtAsync(instruction.OmitXmlDeclaration).ConfigureAwait(false);
            resultOmitXmlDecl = omitStr.Trim() is "yes" or "true" or "1";
        }

        // Evaluate indent from xsl:result-document (AVT)
        bool? resultIndent = null;
        if (instruction.Indent != null)
        {
            var indentStr = await EvaluateAvtAsync(instruction.Indent).ConfigureAwait(false);
            resultIndent = indentStr.Trim() is "yes" or "true" or "1";
        }

        // Determine effective output method for this result-document
        // Priority: method attribute on xsl:result-document > matched xsl:output declaration
        OutputMethod? resultMethod = null;
        if (instruction.Method != null)
        {
            var methodStr = await EvaluateAvtAsync(instruction.Method).ConfigureAwait(false);
            resultMethod = methodStr.Trim() switch
            {
                "text" => OutputMethod.Text,
                "html" => OutputMethod.Html,
                "xhtml" => OutputMethod.Xhtml,
                "xml" => OutputMethod.Xml,
                "json" => OutputMethod.Json,
                "adaptive" => OutputMethod.Adaptive,
                _ => null
            };
        }
        resultMethod ??= matchedOutput?.Method;

        // Resolve item-separator: instruction attribute > matched xsl:output > default
        // Special value "#absent" means the parameter is explicitly unset (XSLT 3.0 §20)
        string? itemSeparator = null;
        if (instruction.ItemSeparator != null)
        {
            var sep = await EvaluateAvtAsync(instruction.ItemSeparator).ConfigureAwait(false);
            if (sep != "#absent")
                itemSeparator = sep;
        }
        else if (matchedOutput?.ItemSeparator != null && matchedOutput.ItemSeparator != "#absent")
            itemSeparator = matchedOutput.ItemSeparator;

        // Resolve allow-duplicate-names: instruction attribute > matched xsl:output > default (false)
        bool allowDuplicateNames = matchedOutput?.AllowDuplicateNames == true;
        if (instruction.AllowDuplicateNames != null)
        {
            var adnStr = await EvaluateAvtAsync(instruction.AllowDuplicateNames).ConfigureAwait(false);
            allowDuplicateNames = adnStr.Trim() is "yes" or "true" or "1";
        }

        // Apply item-separator override during content execution
        var savedItemSeparator = _itemSeparatorOverride;
        if (itemSeparator != null)
            _itemSeparatorOverride = itemSeparator;

        // When href is non-empty, redirect output to a separate buffer for the secondary result document
        var redirectToSecondary = !string.IsNullOrEmpty(effectiveHref);
        // When href is empty but we're inside a secondary redirect, we need to redirect
        // back to primary output by saving/restoring the secondary buffer
        var redirectToPrimary = !redirectToSecondary && _resultDocumentRedirectDepth > 0;

        // Track character maps from xsl:result-document targeting principal output.
        // These persist until SerializeResult runs (no save/restore needed since only
        // one result-document can target principal output per XTDE1490).
        if (instruction.UseCharacterMaps.Count > 0 && !redirectToSecondary)
            _principalOutputCharacterMaps = instruction.UseCharacterMaps;
        string? savedOutputContent = null;
        List<Dictionary<string, string>>? savedNsScopes = null;
        List<QName>? savedElementStack = null;
        List<bool>? savedElementHasNs = null;
        List<bool>? savedElementIsLre = null;
        List<Dictionary<string, string>>? savedXslNsBindings = null;
        if (redirectToSecondary || redirectToPrimary)
        {
            // If primary output has content before we redirect, mark it as claimed
            // so nested result-document href="" will correctly detect the duplicate
            if (_resultDocumentRedirectDepth == 0 && (_output.Length > 0 || _outputElementStack.Count > 0))
                _resultDocumentUris.Add("");
            savedOutputContent = _output.ToString();
            _output.Clear();
            // Save and clear namespace/element stacks
            savedNsScopes = new(_outputNsScopes);
            _outputNsScopes.Clear();
            savedElementStack = new(_outputElementStack);
            _outputElementStack.Clear();
            savedElementHasNs = new(_outputElementHasNsStack);
            _outputElementHasNsStack.Clear();
            savedElementIsLre = new(_outputElementIsLreStack);
            _outputElementIsLreStack.Clear();
            savedXslNsBindings = new(_xslNamespaceBindings);
            _xslNamespaceBindings.Clear();
            if (redirectToSecondary)
                _resultDocumentRedirectDepth++;
        }

        var savedActiveOutput = _activeResultDocumentOutput;
        _activeResultDocumentOutput = matchedOutput;
        try
        {
            if (resultMethod == OutputMethod.Text)
            {
                // Text output method (XSLT 3.0 §20.5.3): output the string-value
                // of every text node in the result tree, without escaping.
                // For PRIMARY output: use sentinel escaping to protect text content
                // from the final StripXmlMarkup pass in TransformAsync serialization.
                // For SECONDARY output: no sentinel needed since content goes directly
                // to _secondaryResultDocuments without further stripping.
                var textSaved = _output.ToString();
                _output.Clear();
                var useSentinel = !redirectToSecondary;
                if (useSentinel) _textOutputModeDepth++;
                try
                {
                    await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    if (useSentinel) _textOutputModeDepth--;
                }
                var rawResult = _output.ToString();
                _output.Clear();
                _output.Append(textSaved);
                _output.Append(StripXmlMarkup(rawResult));
            }
            else if (resultMethod is OutputMethod.Json or OutputMethod.Adaptive)
            {
                var isAdaptive = resultMethod == OutputMethod.Adaptive;
                var allowDupNames = allowDuplicateNames;
                var savedAccum = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();
                var jsonSaved = _output.ToString();
                _output.Clear();

                if (isAdaptive)
                {
                    // Adaptive mode: process instructions one by one to preserve interleaving
                    // of XDM items (maps, arrays, atomics) and XML output (elements, attributes)
                    var effectiveSep = itemSeparator ?? "\n";
                    var resultItems = new List<string>();
                    foreach (var childInsn in instruction.Content.Instructions)
                    {
                        var outputBefore = _output.Length;
                        var accumBefore = _sequenceAccumulator!.Count;
                        await childInsn.ExecuteAsync(this).ConfigureAwait(false);

                        // Collect any new sequence items
                        for (int si = accumBefore; si < _sequenceAccumulator!.Count; si++)
                        {
                            resultItems.Add(XsltTransformEngine.SerializeItemAdaptive(_sequenceAccumulator[si]));
                        }

                        // Collect any new XML output
                        if (_output.Length > outputBefore)
                        {
                            var xmlFragment = _output.ToString(outputBefore, _output.Length - outputBefore);
                            _output.Remove(outputBefore, _output.Length - outputBefore);
                            resultItems.Add(xmlFragment);
                        }
                    }
                    _output.Clear();
                    _output.Append(jsonSaved);
                    _sequenceAccumulator = savedAccum;

                    for (int i = 0; i < resultItems.Count; i++)
                    {
                        if (i > 0) _output.Append(effectiveSep);
                        _output.Append(resultItems[i]);
                    }
                }
                else
                {
                    // JSON mode: collect all items, then serialize
                    await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                    var textContent = _output.ToString();
                    _output.Clear();
                    _output.Append(jsonSaved);
                    var jsonItems = _sequenceAccumulator;
                    _sequenceAccumulator = savedAccum;

                    if (jsonItems.Count > 0)
                    {
                        var rdJsonIndent = (resultIndent ?? matchedOutput?.Indent) == true;
                        if (jsonItems.Count == 1)
                            _output.Append(XsltTransformEngine.SerializeItemAsJson(jsonItems[0], false, allowDupNames, indent: rdJsonIndent));
                        else
                        {
                            _output.Append('[');
                            for (int i = 0; i < jsonItems.Count; i++)
                            {
                                if (i > 0) _output.Append(',');
                                if (rdJsonIndent) { _output.Append('\n'); _output.Append("  "); }
                                _output.Append(XsltTransformEngine.SerializeItemAsJson(jsonItems[i], false, allowDupNames, indent: rdJsonIndent, depth: 1));
                            }
                            if (rdJsonIndent) _output.Append('\n');
                            _output.Append(']');
                        }
                    }
                    else if (!string.IsNullOrEmpty(textContent))
                    {
                        _output.Append(textContent);
                    }
                }
            }
            else
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }

            // Store secondary result document content
            if (redirectToSecondary)
            {
                var secondaryContent = _output.ToString();

                // Route secondary result-document serialization through the shared FinalizeOutput
                // pipeline (text/html post-process, content-type meta, indentation, character maps,
                // Unicode normalization, xml-decl, doctype, BOM, escape-uri, sentinel restore) so it
                // gains the same treatment as primary/streaming output instead of a bespoke subset.
                //
                // Build a resolved output declaration for this result-document. The result-document's
                // own attributes (method/indent/omit-xml-declaration) take precedence over its matched
                // xsl:output (format=), which in turn falls back to the stylesheet's default xsl:output
                // for doctype/BOM/suppress-indentation/etc. This reproduces the previous effective
                // method/indent/doctype/BOM resolution exactly while adding the rest of the pipeline.
                //
                // Character maps: the previous secondary path applied NO character maps, so we leave
                // UseCharacterMaps empty and pass no supplementary list, keeping char-map behavior
                // unchanged (FinalizeOutput's character-map step is a no-op in that case).
                var rdBaseOutput = matchedOutput ?? _stylesheet.Outputs.FirstOrDefault();
                var rdOutputDecl = new Ast.XsltOutput
                {
                    Method = resultMethod ?? matchedOutput?.Method,
                    Indent = resultIndent ?? matchedOutput?.Indent,
                    OmitXmlDeclaration = resultOmitXmlDecl ?? rdBaseOutput?.OmitXmlDeclaration,
                    Encoding = rdBaseOutput?.Encoding,
                    Version = rdBaseOutput?.Version,
                    Standalone = rdBaseOutput?.Standalone,
                    DoctypePublic = rdBaseOutput?.DoctypePublic,
                    DoctypeSystem = rdBaseOutput?.DoctypeSystem,
                    MediaType = rdBaseOutput?.MediaType,
                    IncludeContentType = rdBaseOutput?.IncludeContentType,
                    EscapeUriAttributes = rdBaseOutput?.EscapeUriAttributes,
                    NormalizationForm = rdBaseOutput?.NormalizationForm,
                    ByteOrderMark = rdBaseOutput?.ByteOrderMark,
                    SuppressIndentation = matchedOutput?.SuppressIndentation ?? _stylesheet.Outputs.FirstOrDefault()?.SuppressIndentation,
                };
                secondaryContent = Owner!.FinalizeOutput(
                    secondaryContent, rdOutputDecl, resultDocCharacterMaps: null, XsltTransformEngine.FinalizeKind.ResultDocument);

                if (MaxResultDocuments > 0 && _secondaryResultDocuments.Count >= MaxResultDocuments)
                    throw Error($"XTDE1490: Maximum number of secondary result documents ({MaxResultDocuments}) exceeded. " +
                        "Set MaxResultDocuments on XsltTransformer to increase the limit.");
                ValidateResultDocumentContent(instruction, secondaryContent);
                _secondaryResultDocuments[effectiveHref] = secondaryContent;
            }
            else if (redirectToPrimary)
            {
                // Nested xsl:result-document href="" inside a secondary redirect:
                // capture the content as pending primary output
                _pendingPrimaryContent = _output.ToString();
                _primaryOutputClaimedByResultDocument = true;
                // When result-document has explicit method but no format attribute,
                // create a synthetic output declaration so the final serialization
                // uses the correct method (not the xsl:output default)
                _primaryOutputMatchedDeclaration = matchedOutput
                    ?? (resultMethod != null ? CreateSyntheticOutput(resultMethod.Value, resultOmitXmlDecl, resultIndent) : null);
            }
            else
            {
                // XTDE1490: Mark that the primary output has been claimed by an explicit
                // result-document href="", preventing further implicit writes
                _primaryOutputClaimedByResultDocument = true;
                _primaryOutputMatchedDeclaration = matchedOutput
                    ?? (resultMethod != null ? CreateSyntheticOutput(resultMethod.Value, resultOmitXmlDecl, resultIndent) : null);
            }
        }
        finally
        {
            _activeResultDocumentOutput = savedActiveOutput;
            _itemSeparatorOverride = savedItemSeparator;
            if (redirectToSecondary || redirectToPrimary)
            {
                if (redirectToSecondary)
                    _resultDocumentRedirectDepth--;
                _output.Clear();
                // When returning to primary output level and there's pending primary content
                // from a nested xsl:result-document href="", use it instead of the saved content
                if (redirectToSecondary && _resultDocumentRedirectDepth == 0 && _pendingPrimaryContent != null)
                {
                    _output.Append(_pendingPrimaryContent);
                    _pendingPrimaryContent = null;
                }
                else
                {
                    _output.Append(savedOutputContent);
                }
                // Restore namespace/element stacks
                _outputNsScopes.Clear();
                foreach (var scope in savedNsScopes!.AsEnumerable().Reverse())
                    _outputNsScopes.Push(scope);
                _outputElementStack.Clear();
                foreach (var item in savedElementStack!.AsEnumerable().Reverse())
                    _outputElementStack.Push(item);
                _outputElementHasNsStack.Clear();
                foreach (var item in savedElementHasNs!.AsEnumerable().Reverse())
                    _outputElementHasNsStack.Push(item);
                _outputElementIsLreStack.Clear();
                foreach (var item in savedElementIsLre!.AsEnumerable().Reverse())
                    _outputElementIsLreStack.Push(item);
                _xslNamespaceBindings.Clear();
                foreach (var item in savedXslNsBindings!.AsEnumerable().Reverse())
                    _xslNamespaceBindings.Push(item);
            }
        }
    }

    /// <summary>
    /// Creates a synthetic XsltOutput with the given method, inheriting other properties
    /// (omit-xml-declaration, encoding, etc.) from the stylesheet's default output declaration.
    /// Used when xsl:result-document has an explicit method attribute but no format attribute.
    /// </summary>
    private Ast.XsltOutput CreateSyntheticOutput(OutputMethod method, bool? omitXmlDecl = null, bool? indent = null)
    {
        var baseOutput = _stylesheet.Outputs.FirstOrDefault();
        return new Ast.XsltOutput
        {
            Method = method,
            OmitXmlDeclaration = omitXmlDecl ?? baseOutput?.OmitXmlDeclaration,
            Encoding = baseOutput?.Encoding,
            Standalone = baseOutput?.Standalone,
            Indent = indent ?? baseOutput?.Indent,
            Version = baseOutput?.Version,
        };
    }

    /// <summary>
    /// Pre-computes accumulator values by walking the document tree depth-first.
    /// All accumulators are computed simultaneously in a single tree walk so that
    /// cross-references between accumulators (e.g., accumulator-after('other'))
    /// work correctly per XSLT 3.0 §6.5.3.
    /// </summary>
    internal async ValueTask PreComputeAccumulatorsAsync(
        XdmDocument document,
        IReadOnlyList<XsltAccumulator> accumulators,
        XdmInMemoryStore nodeStore)
    {
        _accumulatorValues ??= new();
        _accumulatorComputedDocuments ??= new();
        _accumulatorComputedDocuments.Add(document.Id);

        // Initialize all accumulators and their per-node value stores
        var currentValues = new object?[accumulators.Count];
        var nodeValueMaps = new Dictionary<NodeId, (object? before, object? after)>[accumulators.Count];
        for (var i = 0; i < accumulators.Count; i++)
        {
            // Get or create the per-accumulator node value map (merges across documents)
            if (!_accumulatorValues.TryGetValue(accumulators[i].Name, out var existingMap))
            {
                existingMap = new Dictionary<NodeId, (object? before, object? after)>();
                _accumulatorValues[accumulators[i].Name] = existingMap;
            }
            nodeValueMaps[i] = existingMap;
            try
            {
                var initVal = await EvaluateAsync(accumulators[i].InitialValue).ConfigureAwait(false);
                // Coerce initial value to declared type (e.g. xs:integer 0 → xs:double 0.0)
                if (accumulators[i].As != null)
                    initVal = CoerceAccumulatorValue(initVal, accumulators[i].As!, accumulators[i].Name);
                currentValues[i] = initVal;
            }
#pragma warning disable CA1031 // Dynamic errors in accumulators are intentionally deferred per XSLT 3.0 §6.5.3
            catch (Exception ex)
#pragma warning restore CA1031
            {
                // Defer the error — it will be re-thrown when the value is accessed
                currentValues[i] = new AccumulatorDeferredError(ex);
            }
        }

        // Walk the tree once, processing all accumulators at each node
        await WalkAccumulatorsAsync(document, accumulators, currentValues, nodeValueMaps, nodeStore).ConfigureAwait(false);
    }

    private async ValueTask WalkAccumulatorsAsync(
        object node,
        IReadOnlyList<XsltAccumulator> accumulators,
        object?[] currentValues,
        Dictionary<NodeId, (object? before, object? after)>[] nodeValueMaps,
        XdmInMemoryStore nodeStore)
    {
        NodeId nodeId;
        if (node is XdmDocument doc)
            nodeId = doc.Id;
        else if (node is XdmNode xdmNode)
            nodeId = xdmNode.Id;
        else
            return;

        // Ensure cached delegates are populated (mirrors CreateMatchContext).
        // _matchCtxNodeResolver may capture a different nodeStore here, so we
        // build a per-call resolver only if the cached one doesn't already match.
        EnsureMatchCtxDelegates();
        var matchContext = new XsltContext
        {
            CurrentNode = node,
            Position = 1,
            Last = 1,
            NodeResolver = id => nodeStore.GetNode(id),
            PredicateEvaluator = _matchCtxPredicateEvaluator,
            PositionComputer = _matchCtxPositionComputer,
            KeyPatternEvaluator = _matchCtxKeyPatternEvaluator,
            IdPatternEvaluator = _matchCtxIdPatternEvaluator,
        };

        // Evaluate start-phase rules for ALL accumulators at this node.
        // Store before-values incrementally so cross-accumulator references
        // (e.g., interval-1 calling accumulator-before('latest-1')) work correctly.
        for (var i = 0; i < accumulators.Count; i++)
        {
            // Skip evaluation if the accumulator is in error state
            if (currentValues[i] is AccumulatorDeferredError)
            {
                nodeValueMaps[i][nodeId] = (before: currentValues[i], after: currentValues[i]);
                continue;
            }

            var acc = accumulators[i];
            foreach (var rule in acc.Rules)
            {
                if (rule.Phase != AccumulatorPhase.Start)
                    continue;
                if (!rule.Match.Matches(node, matchContext))
                    continue;

                try
                {
                    currentValues[i] = await EvaluateAccumulatorRuleAsync(
                        node, rule, currentValues[i], acc).ConfigureAwait(false);
                }
#pragma warning disable CA1031 // Dynamic errors in accumulators are intentionally deferred
                catch (Exception ex)
#pragma warning restore CA1031
                {
                    currentValues[i] = new AccumulatorDeferredError(ex);
                }
                break; // Only first matching rule fires
            }

            // Store before-value immediately so other accumulators can reference it
            nodeValueMaps[i][nodeId] = (before: currentValues[i], after: currentValues[i]);
        }

        // Process children
        IReadOnlyList<NodeId>? children = null;
        if (node is XdmDocument d)
            children = d.Children;
        else if (node is XdmElement elem)
            children = elem.Children;

        if (children != null)
        {
            foreach (var childId in children)
            {
                var child = nodeStore.GetNode(childId);
                if (child != null)
                    await WalkAccumulatorsAsync(child, accumulators, currentValues, nodeValueMaps, nodeStore).ConfigureAwait(false);
            }
        }

        // Evaluate end-phase rules for ALL accumulators at this node.
        // Update after-values incrementally so cross-accumulator references work.
        _evaluatingAccEndPhase ??= new();
        for (var i = 0; i < accumulators.Count; i++)
        {
            // Skip evaluation if the accumulator is in error state
            if (currentValues[i] is AccumulatorDeferredError)
                continue;

            var acc = accumulators[i];
            foreach (var rule in acc.Rules)
            {
                if (rule.Phase != AccumulatorPhase.End)
                    continue;
                if (!rule.Match.Matches(node, matchContext))
                    continue;

                var cycleKey = (acc.Name, nodeId);
                _evaluatingAccEndPhase.Add(cycleKey);
                try
                {
                    currentValues[i] = await EvaluateAccumulatorRuleAsync(
                        node, rule, currentValues[i], acc).ConfigureAwait(false);
                }
#pragma warning disable CA1031 // Dynamic errors in accumulators are intentionally deferred
                catch (Exception ex) when (ex is not OutOfMemoryException && !ex.Message.Contains("XTDE3400", StringComparison.Ordinal))
#pragma warning restore CA1031
                {
                    currentValues[i] = new AccumulatorDeferredError(ex);
                }
                finally
                {
                    _evaluatingAccEndPhase.Remove(cycleKey);
                }
                break; // Only first matching rule fires
            }
            // Update this accumulator's after-value immediately so subsequent accumulators can see it
            nodeValueMaps[i][nodeId] = (nodeValueMaps[i][nodeId].before, after: currentValues[i]);
        }
    }

    internal async ValueTask<object?> EvaluateAccumulatorRuleAsync(
        object node, XsltAccumulatorRule rule, object? currentValue, XsltAccumulator accumulator)
    {
        PushScope();
        PushContextItem(node, 1, 1);
        PushCurrentItem(node);
        SetVariable(new QName(NamespaceId.None, "value"), currentValue);
        // XTDE1480: Accumulator rule evaluation is in temporary output state
        _temporaryOutputDepth++;
        try
        {
            if (rule.Select != null)
                currentValue = await EvaluateAsync(rule.Select).ConfigureAwait(false);
            else if (rule.Content != null)
            {
                BeginSequenceCollection();
                await rule.Content.ExecuteAsync(this).ConfigureAwait(false);
                var items = EndSequenceCollection();
                currentValue = items.Count == 1 ? items[0] : items;
            }
        }
        finally
        {
            _temporaryOutputDepth--;
            PopCurrentItem();
            PopContextItem();
            PopScope();
        }
        if (accumulator.As != null)
            currentValue = CoerceAccumulatorValue(currentValue, accumulator.As, accumulator.Name);
        return currentValue;
    }

    internal static object? CoerceAccumulatorValue(object? value, XdmSequenceType declaredType, QName accName)
    {
        // Unwrap single-item lists/arrays to scalar values (may be nested)
        if (declaredType.Occurrence is not (Occurrence.ZeroOrMore or Occurrence.OneOrMore))
        {
            while (true)
            {
                if (value is object[] arr2)
                {
                    if (arr2.Length == 1)
                    { value = arr2[0]; continue; }
                    if (arr2.Length == 0)
                    { value = null; break; }
                    break;
                }
                if (value is IReadOnlyList<object?> rl)
                {
                    if (rl.Count == 1)
                    { value = rl[0]; continue; }
                    if (rl.Count == 0)
                    { value = null; break; }
                    break;
                }
                if (value is System.Collections.IList il)
                {
                    if (il.Count == 1)
                    { value = il[0]; continue; }
                    if (il.Count == 0)
                    { value = null; break; }
                    break;
                }
                break;
            }
        }

        // Handle sequence types (xs:integer*, xs:string+, etc.)
        if (declaredType.Occurrence is Occurrence.ZeroOrMore or Occurrence.OneOrMore)
        {
            // Value may be a list — coerce each item
            if (value is IReadOnlyList<object?> list)
            {
                var coerced = new List<object?>(list.Count);
                foreach (var item in list)
                    coerced.Add(CoerceAtomicValue(item, declaredType.ItemType, accName));
                return coerced;
            }
            // Single item is fine for * or +
            return CoerceAtomicValue(value, declaredType.ItemType, accName);
        }

        if (declaredType.ItemType == ItemType.Map && value is IDictionary<object, object?> map)
        {
            foreach (var key in map.Keys)
            {
                if (declaredType.MapKeyType != null && !MatchesAtomicType(key, declaredType.MapKeyType.Value))
                    throw new XsltException($"XPTY0004: Accumulator {accName.LocalName} declared as map({declaredType.MapKeyType}, ...) but key is {key?.GetType().Name ?? "null"}");
            }
            foreach (var val in map.Values)
            {
                if (declaredType.MapValueType != null && !MatchesAtomicType(val, declaredType.MapValueType.Value))
                    throw new XsltException($"XPTY0004: Accumulator {accName.LocalName} declared as map(..., {declaredType.MapValueType}) but value is {val?.GetType().Name ?? "null"}");
            }
            return value;
        }

        // Coerce atomic value to the declared type
        return CoerceAtomicValue(value, declaredType.ItemType, accName);
    }

    private static object? CoerceAtomicValue(object? value, ItemType targetType, QName accName)
    {
        if (value is null)
            return null;

        // Atomize XDM nodes (attribute nodes → string value, element nodes → text content)
        value = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(value);
        if (value is null)
            return null;

        if (MatchesAtomicType(value, targetType))
            return value;

        // Attempt type coercion (untypedAtomic/string → target type)
        return targetType switch
        {
            ItemType.Double when value is string s =>
                double.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var d)
                    ? d
                    : throw new XsltException($"XPTY0004: Cannot cast '{s}' to xs:double for accumulator '{accName.LocalName}'"),
            ItemType.Double when value is int i => (double)i,
            ItemType.Double when value is long l => (double)l,
            ItemType.Double when value is decimal m => (double)m,
            ItemType.Integer when value is string s =>
                long.TryParse(s, out var l)
                    ? l
                    : throw new XsltException($"XPTY0004: Cannot cast '{s}' to xs:integer for accumulator '{accName.LocalName}'"),
            ItemType.Integer when value is double d => (long)d,
            ItemType.Integer when value is decimal m => (long)m,
            ItemType.Decimal when value is string s =>
                decimal.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var m)
                    ? m
                    : throw new XsltException($"XPTY0004: Cannot cast '{s}' to xs:decimal for accumulator '{accName.LocalName}'"),
            ItemType.Decimal when value is int i => (decimal)i,
            ItemType.Decimal when value is long l => (decimal)l,
            ItemType.Decimal when value is double d => (decimal)d,
            ItemType.String => value.ToString()!,
            ItemType.AnyAtomicType => value, // any value is acceptable
            _ => throw new XsltException($"XPTY0004: Accumulator '{accName.LocalName}' declared as {targetType} but value is {value.GetType().Name}")
        };
    }

    private static bool MatchesAtomicType(object? value, ItemType type) => type switch
    {
        ItemType.String => value is string,
        ItemType.Boolean => value is bool,
        ItemType.Integer => value is int or long,
        ItemType.Double => value is double,
        ItemType.Decimal => value is decimal,
        ItemType.Float => value is float,
        ItemType.AnyAtomicType => true, // any value is acceptable
        // Nodes atomize to untypedAtomic in non-schema-validated mode,
        // so both string values and node values are acceptable for untypedAtomic
        ItemType.UntypedAtomic => value is string or Xdm.XsUntypedAtomic or XdmNode or XdmDocument,
        _ => true // Unknown types: don't reject
    };

    /// <summary>
    /// Resolves an accumulator name string (possibly prefixed like "f:figNr" or EQName like "Q{uri}local")
    /// to a QName matching an accumulator in the stylesheet.
    /// </summary>
    internal QName ResolveAccumulatorName(string name)
    {
        // Handle EQName (Q{uri}local) format
        if (name.StartsWith("Q{", StringComparison.Ordinal))
        {
            var closeBrace = name.IndexOf('}', 2);
            if (closeBrace > 2)
            {
                var nsUri = name[2..closeBrace];
                var localName = name[(closeBrace + 1)..];
                var nsId = StylesheetParser.ResolveNamespaceUri(nsUri);
                var eqName = new QName(nsId, localName);
                if (_stylesheet.Accumulators.ContainsKey(eqName))
                    return eqName;
            }
        }

        // Handle prefixed name (prefix:local) — resolve prefix via stylesheet namespaces
        var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
        if (colonIdx > 0)
        {
            var prefix = name[..colonIdx];
            var localName = name[(colonIdx + 1)..];

            if (_stylesheet.Namespaces.TryGetValue(prefix, out var nsUri))
            {
                var nsId = StylesheetParser.ResolveNamespaceUri(nsUri);
                var nsQname = new QName(nsId, localName);
                if (_stylesheet.Accumulators.ContainsKey(nsQname))
                    return nsQname;
            }
        }

        // Unprefixed name — try direct match
        var accName = new QName(NamespaceId.None, name);
        if (_stylesheet.Accumulators.ContainsKey(accName))
            return accName;

        return accName; // Return as-is; caller will handle not-found
    }

    /// <summary>
    /// Looks up a pre-computed accumulator value for the given node.
    /// </summary>
    internal (object? before, object? after)? GetAccumulatorValue(QName accumulatorName, object node, bool isAfter = false)
    {
        if (_accumulatorValues == null)
            return null;

        if (!_accumulatorValues.TryGetValue(accumulatorName, out var nodeValues))
            return null;

        NodeId nodeId;
        if (node is XdmDocument doc)
            nodeId = doc.Id;
        else if (node is XdmNode xdmNode)
            nodeId = xdmNode.Id;
        else
            return null;

        // XTDE3400: Detect cyclic dependency — accumulator-after called for an accumulator
        // whose end-phase rule is currently being evaluated at this node
        if (isAfter && _evaluatingAccEndPhase?.Contains((accumulatorName, nodeId)) == true)
            throw Error($"XTDE3400: Cyclic dependency detected in accumulator '{accumulatorName}' at the current node");

        return nodeValues.TryGetValue(nodeId, out var value) ? value : null;
    }

    /// <summary>
    /// Finds the XdmDocument containing a given node by walking up the parent chain.
    /// </summary>
    internal XdmDocument? FindDocumentForNode(object node)
    {
        if (node is XdmDocument doc)
            return doc;
        if (node is not XdmNode xdmNode || _nodeStore == null)
            return null;

        // Walk up parent chain to find the document root
        var current = xdmNode;
        while (current.Parent.HasValue && current.Parent.Value != NodeId.None)
        {
            var parent = _nodeStore.GetNode(current.Parent.Value);
            if (parent is XdmDocument parentDoc)
                return parentDoc;
            if (parent is XdmNode parentNode)
                current = parentNode;
            else
                break;
        }

        // The current node itself might be the document (if it has no parent)
        return current as XdmDocument;
    }

    /// <summary>
    /// Gets the DocumentId of the tree containing the input node(s).
    /// For arrays, checks the first node element.
    /// </summary>
    private DocumentId? FindDocumentIdForInput(object? input)
    {
        if (input is XdmDocument doc)
            return doc.Document;
        if (input is XdmNode node)
        {
            var foundDoc = FindDocumentForNode(node);
            return foundDoc?.Document;
        }
        if (input is object?[] arr)
        {
            foreach (var item in arr)
            {
                if (item is XdmNode n)
                {
                    var foundDoc = FindDocumentForNode(n);
                    if (foundDoc != null)
                        return foundDoc.Document;
                }
            }
        }
        return null;
    }

    /// <summary>
    /// Lazily computes accumulators for the document containing the given node,
    /// if they haven't been computed yet. Per XSLT 3.0 §6.5, accumulators are
    /// applicable to any document, not just the principal source document.
    /// </summary>
    /// <summary>
    /// Checks if the given accumulator is applicable in the current mode per §6.5.
    /// Returns true if the mode has use-accumulators="#all" or includes the accumulator name.
    /// Returns true if the mode has no explicit use-accumulators attribute (unspecified = all applicable).
    /// Returns false if the mode has use-accumulators="" (empty = none).
    /// </summary>
    internal bool IsAccumulatorApplicable(QName accumulatorName)
    {
        var modeKey = _currentMode ?? new QName(NamespaceId.None, "");
        if (_stylesheet.Modes.TryGetValue(modeKey, out var modeDecl))
        {
            if (modeDecl.UseAccumulatorsAttr != null)
            {
                // Explicit use-accumulators: check if this accumulator is included
                if (modeDecl.UseAllAccumulators)
                    return true;
                return modeDecl.UseAccumulatorNames.Any(n => n == accumulatorName);
            }
        }
        // No explicit use-accumulators → accumulators are applicable (default behavior for
        // accumulator-before/after access). For copy-accumulators, use the stricter check.
        return true;
    }

    /// <summary>
    /// Strict accumulator applicability check for copy-accumulators="yes" (XTDE3362).
    /// Per §18.2.2 #5: for the principal source document, accumulators are applicable only if
    /// the initial mode's xsl:mode includes them in use-accumulators.
    /// Without any xsl:mode declaration, no accumulators are applicable.
    /// </summary>
    private bool IsAccumulatorApplicableForCopy(QName accumulatorName)
    {
        var modeKey = _currentMode ?? new QName(NamespaceId.None, "");
        if (_stylesheet.Modes.TryGetValue(modeKey, out var modeDecl))
        {
            if (modeDecl.UseAccumulatorsAttr != null)
            {
                if (modeDecl.UseAllAccumulators)
                    return true;
                return modeDecl.UseAccumulatorNames.Any(n => n == accumulatorName);
            }
            // xsl:mode exists but no use-accumulators → default is #all
            return true;
        }
        // No xsl:mode declaration for this mode → no accumulators applicable (§18.2.2 #5)
        return false;
    }

    internal async ValueTask EnsureAccumulatorsComputedAsync(QName accumulatorName, object node)
    {
        if (_nodeStore == null || !_stylesheet.Accumulators.ContainsKey(accumulatorName))
            return;

        // Check if this node already has accumulator values (e.g., from snapshot/copy-of propagation).
        // This prevents recomputing on synthetic/snapshot trees that already carry copied values.
        if (node is XdmNode nodeWithValues)
        {
            if (_accumulatorValues?.TryGetValue(accumulatorName, out var existingNodeValues) == true
                && existingNodeValues.ContainsKey(nodeWithValues.Id))
                return;
        }
        else if (node is XdmDocument docWithValues)
        {
            if (_accumulatorValues?.TryGetValue(accumulatorName, out var existingDocValues) == true
                && existingDocValues.ContainsKey(docWithValues.Id))
                return;
        }

        // Find the document containing this node
        var doc = FindDocumentForNode(node);

        // For orphan nodes (e.g., elements extracted from variables), create a temporary
        // document wrapper so accumulators can be computed fresh on the subtree.
        // But skip if the node already has accumulator values (e.g., from copy-of with
        // accumulator propagation) — we don't want to overwrite copied values.
        if (doc == null && node is XdmNode orphanNode)
        {
            // Walk up to the root of the orphan's subtree
            var root = orphanNode;
            while (root.Parent.HasValue && root.Parent.Value != NodeId.None)
            {
                var parent = _nodeStore.GetNode(root.Parent.Value);
                if (parent is XdmDocument parentDoc)
                {
                    doc = parentDoc;
                    break;
                }
                if (parent is XdmNode parentNode)
                    root = parentNode;
                else
                    break;
            }

            if (doc == null)
            {
                // True orphan — create temp document wrapper for accumulator computation
                var tempDocId = _nodeStore.NextId();
                var rootId = root.Id;
                NodeId? docElemId = root is XdmElement ? rootId : (NodeId?)null;
                doc = new XdmDocument
                {
                    Id = tempDocId,
                    Document = new DocumentId(1),
                    Parent = NodeId.None,
                    Children = [rootId],
                    DocumentElement = docElemId,
                    DocumentElementLocalName = (root as XdmElement)?.LocalName
                };
                doc._stringValue = root.StringValue;
                _nodeStore.Register(doc);
            }
        }

        if (doc == null)
            return;

        // Already computed accumulators for this document?
        if (_accumulatorComputedDocuments?.Contains(doc.Id) == true)
            return;

        // Compute all accumulators for this document (simultaneous walk per §6.5.3)
        var accumulators = _stylesheet.Accumulators.Values.ToList();
        await PreComputeAccumulatorsAsync(doc, accumulators, _nodeStore).ConfigureAwait(false);
    }

    /// <summary>
    /// Copies accumulator values from source nodes to destination nodes using a NodeId mapping.
    /// Used by fn:copy-of() and xsl:copy-of copy-accumulators="yes" to propagate
    /// accumulator values to copied nodes per XSLT 3.0 §6.5.
    /// </summary>
    internal void CopyAccumulatorValues(Dictionary<NodeId, NodeId> nodeMapping)
    {
        if (_accumulatorValues == null || nodeMapping.Count == 0)
            return;

        foreach (var (accName, nodeValues) in _accumulatorValues)
        {
            // Collect entries to add (can't modify during iteration)
            var toAdd = new List<(NodeId destId, (object? before, object? after) values)>();
            foreach (var (sourceId, destId) in nodeMapping)
            {
                if (nodeValues.TryGetValue(sourceId, out var values))
                    toAdd.Add((destId, values));
            }
            foreach (var (destId, values) in toAdd)
                nodeValues[destId] = values;
        }
    }

    /// <summary>
    /// Deep-copies nodes and propagates accumulator values from source to copy.
    /// Ensures accumulators are computed on the source document first.
    /// </summary>
    internal async ValueTask<object?> DeepCopyWithAccumulatorsAsync(object? input)
    {
        if (input == null || _nodeStore == null)
            return input;

        // XTDE3362: Check that accumulators are applicable to the source tree.
        // Per §18.2.2, accumulators on the principal source document are only applicable
        // if declared via use-accumulators on the initial mode's xsl:mode.
        if (_stylesheet.Accumulators.Count > 0 && _principalSourceDocId.HasValue)
        {
            var sourceDocId = FindDocumentIdForInput(input);
            if (sourceDocId.HasValue && sourceDocId.Value == _principalSourceDocId.Value)
            {
                foreach (var accName in _stylesheet.Accumulators.Keys)
                {
                    if (!IsAccumulatorApplicableForCopy(accName))
                        throw Error($"XTDE3362: Accumulator '{accName.LocalName}' is not applicable to the source tree (not listed in use-accumulators for the initial mode)");
                }
            }
        }

        // Ensure accumulators are computed on the source document(s)
        if (_stylesheet.Accumulators.Count > 0)
        {
            foreach (var accName in _stylesheet.Accumulators.Keys)
            {
                await EnsureAccumulatorsComputedForInputAsync(accName, input).ConfigureAwait(false);
            }
        }

        // Deep copy with mapping
        var mapping = new Dictionary<NodeId, NodeId>();
        var result = SnapshotHelper.DeepCopyItems(input, _nodeStore, mapping);

        // Copy accumulator values to the new nodes
        CopyAccumulatorValues(mapping);

        return result;
    }

    internal async ValueTask EnsureAccumulatorsComputedForInputAsync(QName accName, object? input)
    {
        if (input is XdmNode node)
        {
            await EnsureAccumulatorsComputedAsync(accName, node).ConfigureAwait(false);
        }
        else if (input is object?[] arr)
        {
            foreach (var item in arr)
            {
                if (item is XdmNode n)
                {
                    await EnsureAccumulatorsComputedAsync(accName, n).ConfigureAwait(false);
                    break; // All items in same sequence share same document
                }
            }
        }
        else if (input is IEnumerable<object?> seq)
        {
            foreach (var item in seq)
            {
                if (item is XdmNode n)
                {
                    await EnsureAccumulatorsComputedAsync(accName, n).ConfigureAwait(false);
                    break;
                }
            }
        }
    }

    /// <summary>
    /// Evaluates the given grounded operands as for-each iterations against the
    /// subscription body. Each operand expression is evaluated in the current
    /// execution context; the resulting items are iterated in document order and
    /// the subscription's body is executed once per item with the item pushed as
    /// the context item and the xsl:current() item. Used to drain
    /// <see cref="ForEachSubscription.PrefixItems"/> before, and
    /// <see cref="ForEachSubscription.SuffixItems"/> after, the streaming pass
    /// for mixed-sequence xsl:for-each selects.
    /// </summary>
    private async ValueTask ExecuteForEachSubscriptionItemsAsync(
        ForEachSubscription sub,
        IReadOnlyList<XQueryExpression> items)
    {
        if (items.Count == 0) return;
        foreach (var itemExpr in items)
        {
            var result = await EvaluateAsync(itemExpr).ConfigureAwait(false);
            IEnumerable<object> seq = result switch
            {
                IEnumerable<object> s => s,
                object obj => [obj],
                _ => []
            };
            var list = seq.ToList();
            var position = 0;
            foreach (var item in list)
            {
                CheckResourceLimits();
                position++;
                var effectiveItem = item is ResultTreeFragment rtf && _nodeStore != null
                    ? (object?)ParseResultTreeFragment(rtf) ?? item
                    : item;
                PushContextItem(effectiveItem, position, list.Count);
                PushCurrentItem(effectiveItem);
                PushScope();
                var savedTemplate = _currentTemplate;
                _currentTemplate = null;
                try
                {
                    // PrefixItems/SuffixItems drain only ever applies to a for-each
                    // subscription (Body always set); an SM-ctx subscription carries
                    // no prefix/suffix operands, so Body is non-null here.
                    await sub.Body!.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _currentTemplate = savedTemplate;
                    PopScope();
                    PopCurrentItem();
                    PopContextItem();
                }
            }
        }
    }

    public override async ValueTask SourceDocumentAsync(XsltSourceDocument instruction)
    {
        // Deferred XTSE3430 streamability error — throw at runtime instead of parse time
        if (instruction.StreamabilityError != null)
            throw new XsltException(instruction.StreamabilityError, instruction.Location);

        // Evaluate the href AVT to get the URI string
        var href = await EvaluateAvtAsync(instruction.Href).ConfigureAwait(false);

        // Extract fragment identifier before URI construction (.NET Uri may encode # in
        // relative references when base was created from a file path)
        string? fragment = null;
        var hrefForResolve = href;
        var fragmentIdx = href.IndexOf('#', StringComparison.Ordinal);
        if (fragmentIdx >= 0)
        {
            fragment = href[fragmentIdx..]; // includes #
            hrefForResolve = href[..fragmentIdx];
        }

        // Resolve URI relative to the stylesheet base URI
        Uri resolvedUri;
        try
        {
            // Use instruction's effective base URI (accounts for xml:base), falling back to stylesheet base
            var baseUri = instruction.BaseUri ?? _stylesheet.BaseUri;

            if (Uri.TryCreate(hrefForResolve, UriKind.Absolute, out var absUri))
            {
                resolvedUri = absUri;
            }
            else if (baseUri != null)
            {
                resolvedUri = new Uri(baseUri, hrefForResolve);
            }
            else
            {
                // No base URI — try as absolute or throw
                resolvedUri = new Uri(hrefForResolve, UriKind.RelativeOrAbsolute);
                if (!resolvedUri.IsAbsoluteUri)
                    throw Error($"FODC0005: Cannot resolve relative URI '{href}' — no base URI available");
            }
        }
        catch (UriFormatException ex)
        {
            throw Error($"FODC0005: Invalid URI '{href}': {ex.Message}");
        }

        // If streamable="yes", use XmlReader-based streaming instead of full tree loading.
        // Exception: content that cannot be driven off the live reader at the document
        // level (notably xsl:fork / xsl:for-each-group with group-by, which has no
        // streaming dispatch) must materialize the whole input first — fall through to
        // the full-tree load path below, which evaluates group-by correctly.
        if (instruction.Streamable && resolvedUri.IsFile && string.IsNullOrEmpty(fragment)
            && !StreamingSubtreeBufferDetector.RequiresWholeInputBuffer(instruction.Content))
        {
            try
            {
                using var fileStream = System.IO.File.OpenRead(resolvedUri.LocalPath);
                var readerSettings = new XmlReaderSettings
                {
                    DtdProcessing = DtdProcessing.Parse,
                    Async = true
                };
                using var xmlReader = XmlReader.Create(fileStream, readerSettings, resolvedUri.AbsoluteUri);

                var streamNodeStore = _nodeStore ?? new XdmInMemoryStore();
                _templateIndex.ResolvePatternNamespaces(streamNodeStore.InternNamespace);

                // Resolve accumulators for streaming
                var streamAccumulators = new List<XsltAccumulator>();
                if (instruction.UseAccumulators.Count > 0)
                {
                    foreach (var accName in instruction.UseAccumulators)
                    {
                        if (_stylesheet.Accumulators.TryGetValue(accName, out var acc))
                            streamAccumulators.Add(acc);
                    }
                }

                // Pre-scan for consuming expressions that need stream watchers
                var scanner = new StreamingExpressionScanner();
                var scanResult = instruction.Content != null
                    ? scanner.ScanWithSubscriptions(instruction.Content)
                    : default;
                var watchers = scanResult.Watchers ?? (IReadOnlyList<StreamWatcher>)Array.Empty<StreamWatcher>();
                var subscriptions = scanResult.Subscriptions ?? (IReadOnlyList<ForEachSubscription>)Array.Empty<ForEachSubscription>();

                // Subscription-dispatch-only: subscriptions OR watchers exist AND the
                // body has no xsl:apply-templates (so the default template machinery
                // shouldn't fire on non-subscribed/non-watched elements/text during
                // the streaming pass — only the accumulation/dispatch driven by the
                // scanned instructions should run).
                bool subscriptionOnly = (subscriptions.Count > 0 || watchers.Count > 0)
                    && instruction.Content != null
                    && !ContentContainsApplyTemplates(instruction.Content);

                var processor = new StreamingXmlProcessor(
                    _stylesheet, _templateIndex, this, streamNodeStore, _currentMode,
                    streamAccumulators.Count > 0 ? streamAccumulators : null,
                    watchers.Count > 0 ? watchers : null,
                    subscriptions.Count > 0 ? subscriptions : null,
                    subscriptionOnly);

                // Push a synthetic document node as context so the content body can execute
                var syntheticDocId = new NodeId(999_999);
                var syntheticDoc = new XdmDocument
                {
                    Id = syntheticDocId,
                    Document = new DocumentId(0),
                    Children = [],
                    BaseUri = resolvedUri.AbsoluteUri
                };
                streamNodeStore.Register(syntheticDoc);

                PushContextItem(syntheticDoc, 1, 1);
                var savedStreamingProcessor = _activeStreamingProcessor;
                var savedStreamingReader = _activeStreamingReader;
                var savedStreamingCt = _activeStreamingCancellationToken;
                _activeStreamingProcessor = processor;
                _activeStreamingReader = xmlReader;
                _activeStreamingCancellationToken = _options.CancellationToken;
                // Store watchers for result substitution during EvaluateAsync
                var savedWatchers = _activeStreamWatchers;
                _activeStreamWatchers = watchers.Count > 0 ? watchers : null;

                try
                {
                    // If watchers/subscriptions exist but no xsl:apply-templates will trigger
                    // the streaming pass, run ProcessAsync now so watcher results are
                    // available when the content body evaluates variable select expressions
                    // (and so subscription for-each bodies execute per-match during the
                    // forward pass).
                    // A wrapped (inline-driven) for-each must run inside LINEAR body
                    // execution so its surrounding construction (the lexically-enclosing
                    // LRE / xsl:element / xsl:copy) is emitted around its output. When
                    // every subscription is inline-driven and there are no consuming
                    // watchers, fall through to the linear-body branch below; the wrapped
                    // for-each hands off to the live reader at its lexical position via
                    // the ForEachAsync streaming intercept. The forward-pass dispatch is
                    // used only for BARE top-of-body for-each (and watcher) bodies.
                    bool allInlineDriven = subscriptions.Count > 0
                        && watchers.Count == 0
                        && subscriptions.All(s => s.InlineDriven);

                    bool processorRanForSubscriptions = false;
                    if ((watchers.Count > 0 || subscriptions.Count > 0) && instruction.Content != null
                        && !ContentContainsApplyTemplates(instruction.Content)
                        && !allInlineDriven)
                    {
                        _activeStreamingProcessor = null;
                        _activeStreamingReader = null;

                        // Mixed-sequence prefix: grounded operands appearing BEFORE the
                        // streamable path in the for-each select. Evaluate each and
                        // dispatch the body per item, in document order, BEFORE the
                        // streaming pass starts.
                        foreach (var sub in subscriptions)
                        {
                            if (sub.PrefixItems.Count > 0)
                                await ExecuteForEachSubscriptionItemsAsync(sub, sub.PrefixItems).ConfigureAwait(false);
                        }

                        await processor.ProcessAsync(xmlReader, _options.CancellationToken).ConfigureAwait(false);

                        // Mixed-sequence suffix: same as prefix but after streaming.
                        foreach (var sub in subscriptions)
                        {
                            if (sub.SuffixItems.Count > 0)
                                await ExecuteForEachSubscriptionItemsAsync(sub, sub.SuffixItems).ConfigureAwait(false);
                        }

                        processorRanForSubscriptions = subscriptions.Count > 0;
                    }

                    if (instruction.Content != null && !processorRanForSubscriptions)
                    {
                        // Execute the Content body (typically xsl:apply-templates or xsl:iterate).
                        // When ApplyTemplatesAsync is invoked within the Content body and the
                        // streaming processor is active, it triggers the streaming processor
                        // to read the document via XmlReader in a forward pass.
                        // Skipped when subscriptions ran: the for-each body was already
                        // dispatched per-match during ProcessAsync; re-executing it would
                        // double-process against the synthetic empty document.
                        await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                    }
                }
                finally
                {
                    _activeStreamingProcessor = savedStreamingProcessor;
                    _activeStreamingReader = savedStreamingReader;
                    _activeStreamingCancellationToken = savedStreamingCt;
                    _activeStreamWatchers = savedWatchers;
                    PopContextItem();
                    streamNodeStore.Remove(syntheticDocId);
                }
            }
            catch (System.IO.FileNotFoundException)
            {
                throw Error($"FODC0002: Document not found: '{resolvedUri}'");
            }
            catch (System.IO.IOException ex)
            {
                throw Error($"FODC0002: Error loading document '{resolvedUri}': {ex.Message}");
            }

            return; // Skip the full-tree path
        }

        // Helper: check if a content body contains xsl:apply-templates (which triggers streaming)
        static bool ContentContainsApplyTemplates(Ast.XsltSequenceConstructor body)
        {
            foreach (var insn in body.Instructions)
            {
                if (insn is Ast.XsltApplyTemplates) return true;
                if (insn is Ast.XsltSequenceConstructor nested && ContentContainsApplyTemplates(nested)) return true;
            }
            return false;
        }

        // Load the XML document (resolvedUri is already fragment-free)
        string xmlContent;
        try
        {
            if (resolvedUri.IsFile)
            {
                xmlContent = await System.IO.File.ReadAllTextAsync(resolvedUri.LocalPath).ConfigureAwait(false);
            }
            else
            {
                throw Error($"FODC0002: Cannot resolve document URI '{resolvedUri}' — only file:// URIs are supported");
            }
        }
        catch (System.IO.FileNotFoundException)
        {
            throw Error($"FODC0002: Document not found: '{resolvedUri}'");
        }
        catch (System.IO.IOException ex)
        {
            throw Error($"FODC0002: Error loading document '{resolvedUri}': {ex.Message}");
        }

        // Parse and convert to XDM
        var xmlDoc = new XmlDocument { PreserveWhitespace = true };
        xmlDoc.LoadXml(xmlContent);

        var nodeStore = _nodeStore ?? new XdmInMemoryStore();
        var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, nodeStore, resolvedUri.AbsoluteUri);

        // Apply xsl:strip-space declarations
        if (_stylesheet.StripSpace.Count > 0)
        {
            // Ensure namespace resolution for strip-space/preserve-space NameTests
            foreach (var nt in _stylesheet.StripSpace)
                nt.ResolveNamespace(nodeStore.InternNamespace);
            foreach (var nt in _stylesheet.PreserveSpace)
                nt.ResolveNamespace(nodeStore.InternNamespace);

            XsltTransformEngine.StripWhitespaceNodes(xdmDoc, _stylesheet.StripSpace, _stylesheet.PreserveSpace, nodeStore);
        }

        // Pre-compute accumulators if use-accumulators is specified
        var previousAccumulatorValues = _accumulatorValues;
        if (instruction.UseAccumulators.Count > 0)
        {
            var accumulators = new List<XsltAccumulator>();
            foreach (var accName in instruction.UseAccumulators)
            {
                if (_stylesheet.Accumulators.TryGetValue(accName, out var acc))
                    accumulators.Add(acc);
            }
            if (accumulators.Count > 0)
                await PreComputeAccumulatorsAsync(xdmDoc, accumulators, nodeStore).ConfigureAwait(false);
        }

        // If a fragment identifier is present, find the element with matching xml:id
        object contextItem = xdmDoc;
        if (!string.IsNullOrEmpty(fragment))
        {
            var fragmentId = fragment.TrimStart('#');
            var foundElement = FindElementByXmlId(xdmDoc, fragmentId);
            if (foundElement != null)
                contextItem = foundElement;
            // If not found, use the whole document (spec doesn't mandate an error)
        }

        // Push the loaded document (or fragment element) as context item (position=1, last=1)
        PushContextItem(contextItem, 1, 1);
        try
        {
            if (instruction.Content != null)
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            }
        }
        finally
        {
            PopContextItem();
            _accumulatorValues = previousAccumulatorValues;
        }
    }

    /// <summary>
    /// Finds an element with the given xml:id value in an XDM document tree.
    /// </summary>
    private XdmElement? FindElementByXmlId(XdmDocument doc, string id)
    {
        var store = _nodeStore;
        if (store == null) return null;

        foreach (var childId in doc.Children)
        {
            if (store.GetNode(childId) is XdmElement element)
            {
                var found = FindElementByXmlIdRecursive(element, id, store);
                if (found != null) return found;
            }
        }
        return null;
    }

    private static XdmElement? FindElementByXmlIdRecursive(XdmElement element, string id, XdmInMemoryStore store)
    {
        // Check xml:id attribute
        foreach (var attrId in element.Attributes)
        {
            if (store.GetNode(attrId) is XdmAttribute attr
                && attr.LocalName == "id" && attr.Prefix == "xml" && attr.Value == id)
                return element;
        }
        // Recurse into children
        foreach (var childId in element.Children)
        {
            if (store.GetNode(childId) is XdmElement childElement)
            {
                var found = FindElementByXmlIdRecursive(childElement, id, store);
                if (found != null) return found;
            }
        }
        return null;
    }

    public override async ValueTask MessageAsync(XsltMessage instruction)
    {
        string message;

        try
        {
            if (instruction.Select != null)
            {
                var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
                message = StringValueOf(result);
            }
            else if (instruction.Content != null)
            {
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                // Save/restore sequence accumulator so xsl:sequence inside xsl:message
                // doesn't pollute the parent variable's accumulator
                var savedAccumulator = _sequenceAccumulator;
                _sequenceAccumulator = null;
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                _sequenceAccumulator = savedAccumulator;
                message = savedScope.GetWritten();
                savedScope.Dispose();
            }
            else
            {
                message = "";
            }
        }
#pragma warning disable CA1031 // XSLT 3.0: dynamic errors in xsl:message content are recoverable
        catch (Exception)
        {
            return;
        }
#pragma warning restore CA1031

        // Evaluate terminate: can be static bool or dynamic AVT
        var shouldTerminate = instruction.Terminate;
        if (!shouldTerminate && instruction.TerminateAvt != null)
        {
            var terminateStr = (await EvaluateAvtAsync(instruction.TerminateAvt).ConfigureAwait(false)).Trim();
            if (terminateStr is "yes" or "true" or "1")
                shouldTerminate = true;
            else if (terminateStr is not ("no" or "false" or "0"))
                throw Error($"XTDE0030: The effective value of the terminate attribute ('{terminateStr}') is not a valid xs:boolean value (yes|no|true|false|1|0)");
        }

        var msgLine = instruction.Location?.Line ?? 0;
        var msgCol = instruction.Location?.Column ?? 0;
        if (_options.MessageListenerWithLocation != null)
            _options.MessageListenerWithLocation.Invoke(message, shouldTerminate, msgLine, msgCol);
        else
            _options.MessageListener?.Invoke(message, shouldTerminate);

        if (shouldTerminate)
        {
            throw Error($"Transformation terminated: {message}");
        }
    }

    public override async ValueTask AssertAsync(XsltAssert instruction)
    {
        var testResult = await EvaluateBooleanAsync(instruction.Test).ConfigureAwait(false);

        if (!testResult)
        {
            var errorCode = instruction.ErrorCode ?? "XTMM9001";
            string message;
            if (instruction.Select != null)
            {
                var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
                message = StringValueOf(result);
                if (string.IsNullOrEmpty(message))
                    message = "Assertion failed";
            }
            else
            {
                message = "Assertion failed";
            }

            throw Error($"{errorCode}: {message}");
        }
    }

    public override async ValueTask BindVariableAsync(XsltVariableInstruction instruction)
    {

        // Try to evaluate the variable. If it fails with "not defined" error (potential
        // circular reference), store as lazy so it's only evaluated if actually used.
        // This implements the XSLT spec requirement that unused variables with circular
        // refs don't cause errors.
        object? value;

        if (instruction.Select != null)
        {
            try
            {
                value = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            }
            catch (XsltException ex) when (
                ex.Message.Contains("not defined", StringComparison.Ordinal)
                || ex.Message.Contains("XTDE0640", StringComparison.Ordinal))
            {
                // Potential circular reference - defer evaluation.
                // XTDE0640 is raised when a global variable/param being evaluated is re-accessed.
                // If the variable is never used, this deferred error is harmless (per spec).
                var selectExpr = instruction.Select;
                value = new LazyValue(async () => await EvaluateAsync(selectExpr).ConfigureAwait(false));
            }
        }
        else if (instruction.Content != null)
        {
            // Push effective base URI if the instruction has xml:base
            if (instruction.BaseUri != null)
                _baseUriStack.Push(XsltTransformEngine.UriString(instruction.BaseUri)!);

            // Use sequence accumulator to collect individual items when:
            // - ZeroOrMore/OneOrMore: always (existing behavior for multi-item sequences)
            // - ExactlyOne/ZeroOrOne with node types: needed for cardinality checking
            //   (e.g., as="text() ?" with 3 xsl:text items must raise XTTE0570)
            // For atomic types (xs:string, xs:integer, etc.) with ExactlyOne/ZeroOrOne,
            // the non-sequence path handles them correctly.
            var isNodeItemType = instruction.As != null &&
                instruction.As.ItemType is ItemType.Node or ItemType.Element or ItemType.Text
                or ItemType.Comment or ItemType.Document or ItemType.ProcessingInstruction
                or ItemType.Attribute or ItemType.Item or ItemType.Map or ItemType.Array
                or ItemType.Function;
            var isSequenceType = instruction.As != null &&
                (instruction.As.Occurrence == Occurrence.ZeroOrMore
                || instruction.As.Occurrence == Occurrence.OneOrMore
                || isNodeItemType);

            if (isSequenceType)
            {
                var savedAccumulator = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();

                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                var savedLogicalStart = _outputLogicalStart;
                _outputLogicalStart = _output.Length;
                var savedAtomic = _lastResultWasAtomic;
                _lastResultWasAtomic = false;
                // Save and clear namespace scopes so RTF content has all needed declarations
                var savedNsScopes = new List<Dictionary<string, string>>(_outputNsScopes);
                _outputNsScopes.Clear();
                // Save and reset text/attribute content depth so LREs in variable content
                // are processed fully (not suppressed as in attribute/comment/PI bodies)
                var savedTextDepth2 = _textContentDepth;
                var savedAttrContentDepth2 = _attributeContentDepth;
                _textContentDepth = 0;
                _attributeContentDepth = 0;
                // When the target type allows multiple items (text()*, node()*, item()*),
                // collect each text write as a separate accumulator item so they remain
                // individual text nodes (not merged via string concatenation).
                var needsTextCollection = instruction.As != null &&
                    instruction.As.ItemType is ItemType.Text or ItemType.Node or ItemType.Item
                    && instruction.As.Occurrence is Occurrence.ZeroOrMore or Occurrence.OneOrMore;
                var savedCollectText = _collectTextAsSequenceItems;
                var savedElemDepth = _serializingElementDepth;
                if (needsTextCollection)
                {
                    _collectTextAsSequenceItems = true;
                    _serializingElementDepth = 0;
                }
                _temporaryOutputDepth++;
                // EMIT context (temp-tree base-URI preservation): when the declared type is a
                // node type whose body is serialized to TEXT and reparsed below (e.g.
                // as="document-node()" / as="element()*" built via apply-templates or
                // shallow-copy), raise the temp-tree depth and seed the serialize base context
                // so a SOURCE element copied in whose base URI differs picks up a base sentinel
                // that the reparse (ReadAsBodyChunkChildren) recovers onto CopySourceBaseUri.
                // Mirrors CreateDocumentAsync. Scoped to the body serialization only and
                // restored in finally, so the sentinel can never reach final output.
                var raiseTempTreeDepth = _nodeStore != null && isNodeItemType;
                var savedSeqBaseContext = _serializeBaseContext;
                if (raiseTempTreeDepth)
                {
                    _tempTreeSerializeDepth++;
                    _serializeBaseContext = XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri;
                }
                try
                { await instruction.Content.ExecuteAsync(this).ConfigureAwait(false); }
                finally
                {
                    if (raiseTempTreeDepth)
                    {
                        _tempTreeSerializeDepth--;
                        _serializeBaseContext = savedSeqBaseContext;
                    }
                    _temporaryOutputDepth--;
                    _textContentDepth = savedTextDepth2;
                    _attributeContentDepth = savedAttrContentDepth2;
                    _collectTextAsSequenceItems = savedCollectText;
                    _serializingElementDepth = savedElemDepth;
                }
                var textContent = savedScope.GetWritten();

                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;
                _lastResultWasAtomic = savedAtomic;
                // Restore namespace scopes
                _outputNsScopes.Clear();
                foreach (var scope in savedNsScopes.AsEnumerable().Reverse())
                    _outputNsScopes.Push(scope);

                // Combine sequence accumulator items with any serialized output.
                // Literal result elements go to the output buffer; xsl:sequence items go
                // to the accumulator. We need to merge them into a single sequence.
                var sequenceItems = new List<object?>();

                // Add accumulated items (from xsl:sequence select="...")
                var accBaseUri = XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri;
                var wrapAsTextNode = _nodeStore != null && instruction.As != null
                    && instruction.As.ItemType is ItemType.Text or ItemType.Node or ItemType.Item;
                foreach (var item in _sequenceAccumulator)
                {
                    if (item != null)
                    {
                        // Set base URI on orphaned nodes from the construction context.
                        // Skip nodes with CopySourceBaseUri — they preserve the source
                        // element's base URI from xsl:copy (XSLT 3.0 §11.9.1).
                        if (item is XdmNode accNode && accNode.BaseUri == null
                            && accNode.CopySourceBaseUri == null
                            && (!accNode.Parent.HasValue || accNode.Parent.Value == NodeId.None)
                            && accBaseUri != null)
                        {
                            accNode.BaseUri = accBaseUri;
                        }
                        // When as="text()*" or as="node()*", wrap string/TextNodeItem as XDM text nodes
                        // so they remain individual nodes (not merged via string concatenation)
                        if (wrapAsTextNode && item is string strItem)
                        {
                            var textId = _nodeStore!.NextId();
                            var textNode = new Xdm.Nodes.XdmText
                            {
                                Id = textId,
                                Document = DocumentId.None,
                                Parent = NodeId.None,
                                Value = strItem
                            };
                            sequenceItems.Add(textNode);
                        }
                        else if (wrapAsTextNode && item is Xdm.TextNodeItem tni)
                        {
                            var textId = _nodeStore!.NextId();
                            var textNode = new Xdm.Nodes.XdmText
                            {
                                Id = textId,
                                Document = DocumentId.None,
                                Parent = NodeId.None,
                                Value = tni.Value
                            };
                            sequenceItems.Add(textNode);
                        }
                        else
                        {
                            sequenceItems.Add(item);
                        }
                    }
                    else if (wrapAsTextNode)
                    {
                        // null items (from empty xsl:text) also need to be text nodes
                        // to preserve count — skip nulls for non-node types
                    }
                }

                // Parse serialized literal result elements into individual XDM nodes
                if (!string.IsNullOrEmpty(textContent) && _nodeStore != null && textContent.Contains('<', StringComparison.Ordinal))
                {
                    try
                    {
                        var seqBaseUri = XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri;

                        // When as="document-node()", create a proper XDM document node
                        // wrapping the content, rather than extracting individual children
                        if (instruction.As?.ItemType == ItemType.Document)
                        {
                            // Stream-parse rather than allocating a full XmlDocument.
                            var settings = new System.Xml.XmlReaderSettings
                            {
                                DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                IgnoreWhitespace = false,
                                IgnoreComments = false,
                                IgnoreProcessingInstructions = false,
                            };
                            using var stringReader = new System.IO.StringReader($"<_seq_root_>{textContent}</_seq_root_>");
                            using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                            var docId = _nodeStore.NextId();
                            var children = new List<NodeId>();
                            NodeId docElementId = NodeId.None;
                            var parsedChildren = new List<object?>();
                            ReadAsBodyChunkChildren(reader, parsedChildren);
                            foreach (var item in parsedChildren)
                            {
                                if (item is XdmNode cn)
                                {
                                    cn.Parent = docId;
                                    children.Add(cn.Id);
                                    if (cn is XdmElement && docElementId == NodeId.None)
                                        docElementId = cn.Id;
                                }
                            }
                            string? docElemLocalName2 = docElementId != NodeId.None
                                ? (_nodeStore.GetNode(docElementId) as XdmElement)?.LocalName : null;
                            var docNode = new XdmDocument
                            {
                                Id = docId,
                                Document = new DocumentId(1),
                                Parent = NodeId.None,
                                DocumentElement = docElementId,
                                Children = children,
                                DocumentElementLocalName = docElemLocalName2,
                                // XSLT 3.0: a temporary tree's document node takes the static
                                // base URI of the constructing instruction (never null), so
                                // constructed descendants inherit a usable base URI for
                                // resolve-uri()/doc(). Copied descendants still override via
                                // their preserved CopySourceBaseUri.
                                BaseUri = seqBaseUri
                            };
                            _nodeStore.Register(docNode);
                            sequenceItems.Add(docNode);
                        }
                        else
                        {
                            // Stream-parse instead of going through XmlDocument. Hot path for
                            // `xsl:variable as="element(…)"` inside a for-each — fired once per
                            // iteration in workloads like Schxslt2 transpile / Dataverse projection.
                            var settings = new System.Xml.XmlReaderSettings
                            {
                                DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                IgnoreWhitespace = false,
                                IgnoreComments = false,
                                IgnoreProcessingInstructions = false,
                            };
                            using var stringReader = new System.IO.StringReader($"<_seq_root_>{textContent}</_seq_root_>");
                            using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                            var parsedChildren = new List<object?>();
                            ReadAsBodyChunkChildren(reader, parsedChildren);
                            foreach (var child in parsedChildren)
                            {
                                if (child is XdmNode cn)
                                {
                                    cn.Parent = null;
                                    // Don't clobber a base URI recovered from the temp-tree base
                                    // sentinel (a source element copied into the body): that
                                    // preserved source base must win over the construction base,
                                    // mirroring the accumulator handling above.
                                    if (seqBaseUri != null && cn.CopySourceBaseUri == null)
                                        cn.BaseUri = seqBaseUri;
                                }
                                sequenceItems.Add(child);
                            }
                        }
                    }
                    catch (System.Xml.XmlException)
                    {
                        // If parsing fails, wrap as RTF
                        sequenceItems.Add(new ResultTreeFragment(textContent, XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri));
                    }
                }
                else if (!string.IsNullOrEmpty(textContent))
                {
                    // When as="text()" or as="node()", create actual text nodes
                    // so the value is a proper XDM node (can be matched by templates)
                    if (_nodeStore != null && instruction.As != null
                        && instruction.As.ItemType is ItemType.Text or ItemType.Node or ItemType.Item)
                    {
                        var textId = _nodeStore.NextId();
                        var textNode = new Xdm.Nodes.XdmText
                        {
                            Id = textId,
                            Document = DocumentId.None,
                            Parent = NodeId.None,
                            Value = StripXmlMarkup(textContent)
                        };
                        sequenceItems.Add(textNode);
                    }
                    else
                    {
                        // Plain text content — add as atomic value (decode XML entities)
                        sequenceItems.Add(StripXmlMarkup(textContent));
                    }
                }
                else if (textContent != null && textContent.Length == 0 && sequenceItems.Count == 0
                    && instruction.As != null
                    && instruction.As.ItemType is ItemType.Item or ItemType.Text or ItemType.Node)
                {
                    // XSLT 3.0: empty xsl:value-of creates a zero-length text node
                    if (_nodeStore != null)
                    {
                        var textId = _nodeStore.NextId();
                        var textNode = new Xdm.Nodes.XdmText
                        {
                            Id = textId,
                            Document = DocumentId.None,
                            Parent = NodeId.None,
                            Value = ""
                        };
                        sequenceItems.Add(textNode);
                    }
                    else
                    {
                        sequenceItems.Add(textContent);
                    }
                }

                // For ExactlyOne/ZeroOrOne: check cardinality, then unwrap to single item
                // so downstream code sees a single value (not an array).
                var occurrence = instruction.As!.Occurrence;
                if (occurrence == Occurrence.ExactlyOne || occurrence == Occurrence.ZeroOrOne)
                {
                    if (occurrence == Occurrence.ExactlyOne && sequenceItems.Count != 1)
                        throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                    if (occurrence == Occurrence.ZeroOrOne && sequenceItems.Count > 1)
                        throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                    // Unwrap single item so variable value is not an array
                    value = sequenceItems.Count == 1 ? sequenceItems[0] : null;
                }
                else
                {
                    value = sequenceItems.Count > 0 ? sequenceItems.ToArray() : Array.Empty<object?>();
                }

                _sequenceAccumulator = savedAccumulator;
            }
            else
            {
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                var savedLogicalStart = _outputLogicalStart;
                _outputLogicalStart = _output.Length;
                var savedAtomic2 = _lastResultWasAtomic;
                _lastResultWasAtomic = false;
                // Variable content creates a document fragment — isolate attribute collection
                // from parent elements so attributes don't leak (XTDE0420)
                var savedAttrStack = new List<StringBuilder>(_collectedAttributesStack);
                _collectedAttributesStack.Clear();
                // Save and clear namespace scopes so RTF content has all needed declarations
                var savedNsScopes2 = new List<Dictionary<string, string>>(_outputNsScopes);
                _outputNsScopes.Clear();
                // Save and reset text/attribute content depth so LREs in variable content
                // are processed fully (not suppressed as in attribute/comment/PI bodies)
                var savedTextDepth = _textContentDepth;
                var savedAttrContentDepth = _attributeContentDepth;
                _textContentDepth = 0;
                _attributeContentDepth = 0;
                // Save and replace _sequenceAccumulator. When this xsl:variable bind runs
                // inside a function body (which sets up its own accumulator to capture
                // xsl:sequence return values), failing to isolate here means xsl:sequence
                // inside our body leaks into the FUNCTION's accumulator instead of
                // contributing to our variable's value — body output ends up empty and the
                // variable gets the empty string. Found in Docbook TNG `$process` (xs:boolean
                // body inside fp:run-transforms function).
                var savedAccumulatorVar = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();
                _documentNodeDepth++;
                _temporaryOutputDepth++;
                List<object?>? capturedAccumulator;
                try
                { await instruction.Content.ExecuteAsync(this).ConfigureAwait(false); }
                finally
                {
                    capturedAccumulator = _sequenceAccumulator;
                    _sequenceAccumulator = savedAccumulatorVar;
                    _temporaryOutputDepth--;
                    _documentNodeDepth--;
                    _textContentDepth = savedTextDepth;
                    _attributeContentDepth = savedAttrContentDepth;
                    _collectedAttributesStack.Clear();
                    foreach (var sb in savedAttrStack)
                        _collectedAttributesStack.Push(sb);
                    // Restore namespace scopes
                    _outputNsScopes.Clear();
                    foreach (var scope in savedNsScopes2.AsEnumerable().Reverse())
                        _outputNsScopes.Push(scope);
                }
                // RTF construction (no 'as=') only reads the text buffer below — drain
                // any captured accumulator items into _output (still scoped to savedScope)
                // before reading content. Without this, an inner template/instruction whose
                // 'as=' path routes its result into our accumulator-as-barrier vanishes from
                // the variable's tree. Found in SchXslt2 transpile: an `as="element(...)"`
                // template's result was lost when called from inside an unconstrained
                // `<xsl:variable name="transpiled-schematron">…<xsl:apply-templates/>…`.
                if (instruction.As == null && capturedAccumulator is { Count: > 0 })
                {
                    var savedAccDrain = _sequenceAccumulator;
                    _sequenceAccumulator = null;
                    // EMIT context: this drain serializes accumulator items (which may be
                    // source-element copies carrying CopySourceBaseUri) to TEXT that becomes
                    // an RTF and is reparsed below. Raise the temp-tree depth so the base
                    // sentinel rides through and the reparse recovers CopySourceBaseUri.
                    var drainBaseUri = XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri;
                    _tempTreeSerializeDepth++;
                    var savedDrainBaseContext = _serializeBaseContext;
                    _serializeBaseContext = drainBaseUri;
                    try
                    {
                        foreach (var item in capturedAccumulator)
                            if (item != null)
                                SerializeResult(item);
                    }
                    finally
                    {
                        _tempTreeSerializeDepth--;
                        _serializeBaseContext = savedDrainBaseContext;
                        _sequenceAccumulator = savedAccDrain;
                    }
                }
                var content = savedScope.GetWritten();

                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;
                _lastResultWasAtomic = savedAtomic2;
                // XSLT 2.0: variables with content and no 'as' attribute always create a
                // temporary tree (document node). Variables with 'as' that land here have typed
                // content that should remain as-is (e.g., namespace-node(), atomic types).
                var varBaseUri = XsltTransformEngine.UriString(instruction.BaseUri) ?? EffectiveBaseUri;
                if (instruction.As == null)
                    value = new ResultTreeFragment(content, varBaseUri);
                else if (capturedAccumulator is { Count: > 0 } && content.Length == 0)
                {
                    // The body produced typed items via xsl:sequence (or similar) — preserve
                    // them rather than serializing through text. For ExactlyOne/ZeroOrOne the
                    // single item is unwrapped; the downstream type validation handles
                    // cardinality and coercion.
                    var occ = instruction.As.Occurrence;
                    if (occ == Occurrence.ExactlyOne || occ == Occurrence.ZeroOrOne)
                        value = capturedAccumulator.Count == 1 ? capturedAccumulator[0] : capturedAccumulator.ToArray();
                    else
                        value = capturedAccumulator.ToArray();
                }
                // When `as=` allows the empty sequence and the body produced no content
                // (no text and no accumulator items), the value MUST be the empty sequence,
                // not the empty string. Without this guard, an `xsl:variable as="xs:string?"`
                // wrapping an `xsl:for-each` whose body never fires ended up bound to "" —
                // and `empty($style)` then returned false, masking the no-match path.
                // Found in Docbook info.xsl personname → name-style lookup, where the empty
                // string blocked the apply-templates m:gentext fallback that would have
                // produced "first-last" from the locale.
                else if (content.Length == 0
                    && (capturedAccumulator is null || capturedAccumulator.Count == 0)
                    && instruction.As.Occurrence is Occurrence.ZeroOrOne or Occurrence.ZeroOrMore)
                    value = null;
                else
                    value = content.Contains('<', StringComparison.Ordinal)
                        ? new ResultTreeFragment(content, varBaseUri)
                        : (object)DefaultXsltExecutionContext.StripXmlMarkup(content);
            }

            // Pop effective base URI
            if (instruction.BaseUri != null)
                _baseUriStack.Pop();
        }
        else
        {
            // Per XSLT spec: variable with no select and no content defaults to empty string
            value = "";
        }

        // When as="text()" and the content produced a string, wrap as XdmText node
        if (instruction.As != null && instruction.As.ItemType == ItemType.Text && value is string textVal && _nodeStore != null)
        {
            var textId = _nodeStore.NextId();
            value = new Xdm.Nodes.XdmText
            {
                Id = textId,
                Document = DocumentId.None,
                Parent = NodeId.None,
                Value = textVal
            };
        }

        // XTTE0570: Validate value against declared type if 'as' attribute is present
        if (instruction.As != null && value is not LazyValue)
        {
            var targetType = instruction.As.ItemType;
            var occurrence = instruction.As.Occurrence;

            // Handle empty-sequence() type: only empty values are allowed
            if (occurrence == Occurrence.Zero)
            {
                var isEmpty = value == null || (value is object?[] emptyArr && emptyArr.All(i => i == null))
                    || (value is string s && s.Length == 0);
                if (!isEmpty)
                    throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type empty-sequence()");
                goto doneValidation; // skip remaining type checks
            }

            var isNodeType = targetType is ItemType.Node or ItemType.Element or ItemType.Text
                or ItemType.Comment or ItemType.Document or ItemType.ProcessingInstruction
                or ItemType.Attribute or ItemType.Item;

            // For node types, unwrap RTFs and flatten nested arrays into actual XDM nodes
            if (isNodeType && value is object?[] nodeItems)
            {
                var flatItems = FlattenAndUnwrapToNodes(nodeItems, targetType, instruction.As.DocumentElementName);
                value = flatItems;

                // Cardinality check
                if (occurrence == Occurrence.ExactlyOne && flatItems.Length != 1)
                    throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                if (occurrence == Occurrence.ZeroOrOne && flatItems.Length > 1)
                    throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");

                // Item type check (if not generic node()/item())
                if (targetType is not ItemType.Node and not ItemType.Item)
                {
                    foreach (var item in flatItems)
                    {
                        if (item == null)
                            continue;
                        var matches = (targetType, item) switch
                        {
                            (ItemType.Element, XdmElement el) =>
                                instruction.As.ElementName == null || el.LocalName == instruction.As.ElementName,
                            (ItemType.Text, XdmText) => true,
                            (ItemType.Text, string) => true,
                            (ItemType.Text, Xdm.TextNodeItem) => true,
                            (ItemType.Comment, XdmComment) => true,
                            (ItemType.ProcessingInstruction, XdmProcessingInstruction) => true,
                            (ItemType.Attribute, XdmAttribute) => true,
                            (ItemType.Document, XdmDocument doc) =>
                                instruction.As.DocumentElementName == null ||
                                doc.DocumentElementLocalName == instruction.As.DocumentElementName,
                            _ => false
                        };
                        if (!matches)
                            throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                    }
                }
            }
            // Single node value (not in array) — also needs type check
            else if (isNodeType && value is XdmNode or Xdm.TextNodeItem && targetType is not ItemType.Node and not ItemType.Item)
            {
                var matches = (targetType, value) switch
                {
                    (ItemType.Element, XdmElement el) =>
                        instruction.As.ElementName == null || el.LocalName == instruction.As.ElementName,
                    (ItemType.Text, XdmText) => true,
                    (ItemType.Text, Xdm.TextNodeItem) => true,
                    (ItemType.Comment, XdmComment) => true,
                    (ItemType.ProcessingInstruction, XdmProcessingInstruction) => true,
                    (ItemType.Attribute, XdmAttribute) => true,
                    (ItemType.Document, XdmDocument doc) =>
                        instruction.As.DocumentElementName == null ||
                        doc.DocumentElementLocalName == instruction.As.DocumentElementName,
                    _ => false
                };
                if (!matches)
                    throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
            }

            if (!isNodeType)
            {
                // RTF values need atomization: extract string content and coerce
                if (value is ResultTreeFragment rtf)
                {
                    // Parse the RTF to extract text content for atomization
                    var rtfText = rtf.XmlContent;
                    if (rtfText.Contains('<', StringComparison.Ordinal))
                    {
                        try
                        {
                            // Stream the RTF content and accumulate descendant text — equivalent
                            // to XmlDocument.DocumentElement.InnerText but without allocating the
                            // DOM. Same hot-path optimization as the rest of the as= body capture.
                            var settings = new System.Xml.XmlReaderSettings
                            {
                                Async = true,
                                DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                IgnoreWhitespace = false,
                                IgnoreComments = true,
                                IgnoreProcessingInstructions = true,
                            };
                            using var stringReader = new System.IO.StringReader($"<_rtf_>{rtfText}</_rtf_>");
                            using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                            var sb = new StringBuilder();
                            while (await reader.ReadAsync().ConfigureAwait(false))
                            {
                                if (reader.NodeType is System.Xml.XmlNodeType.Text
                                    or System.Xml.XmlNodeType.CDATA
                                    or System.Xml.XmlNodeType.SignificantWhitespace
                                    or System.Xml.XmlNodeType.Whitespace)
                                {
                                    sb.Append(reader.Value);
                                }
                            }
                            rtfText = sb.ToString();
                        }
                        catch (System.Xml.XmlException)
                        {
                            // Intentional fallback: if RTF content contains angle brackets but is not
                            // well-formed XML (e.g. text with embedded < from disable-output-escaping),
                            // fall through and use the raw rtfText string for type coercion below.
                        }
                    }
                    if (CanCoerceToItemType(rtfText, targetType))
                    {
                        value = CoerceToType(rtfText, instruction.As);
                    }
                    else
                    {
                        throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                    }
                }

                object?[] items = value switch
                {
                    object?[] arr => arr,
                    IDictionary<object, object?> => [value], // Maps are single items, don't enumerate
                    List<object?> => [value], // XDM arrays are single items, don't enumerate
                    System.Collections.IEnumerable enumerable when value is not string
                        => enumerable.Cast<object?>().ToArray(),
                    null => [],
                    _ => [value]
                };
                var hasTypeMismatch = items.Any(item =>
                    item != null && !CanCoerceToItemType(item, targetType));
                if (hasTypeMismatch)
                {
                    throw Error($"XTTE0570: Variable ${instruction.Name.LocalName} value does not match declared type {instruction.As.ItemType} {instruction.As.Occurrence}");
                }

                // Coerce values to target type: atomize XDM nodes, apply numeric promotion, etc.
                // Per XSLT spec, when 'as' is declared, values must be coerced to the target type.
                var needsCoercion = items.Any(item => item is XdmNode
                    || (item != null && !XQuery.Execution.TypeCastHelper.MatchesItemType(item, targetType)));
                if (needsCoercion)
                {
                    var coerced = new object?[items.Length];
                    for (int i = 0; i < items.Length; i++)
                    {
                        coerced[i] = items[i] is XdmNode node
                            ? CoerceToType(node.StringValue, instruction.As)
                            : CoerceToType(items[i], instruction.As);
                    }
                    // Unwrap single-element arrays to preserve scalar semantics
                    value = coerced.Length == 1 ? coerced[0] : coerced;
                }
            }
        }

    doneValidation:
        SetVariable(instruction.Name, value);
    }

    public override async ValueTask BindParamAsync(XsltParamInstruction instruction)
    {
        // If already bound (from with-param or tunnel inheritance), skip
        try
        {
            GetVariable(instruction.Name);
            return;
        }
        catch (XsltException)
        {
            // Not bound, continue
        }

        // For tunnel params, check inherited tunnel parameters
        if (instruction.Tunnel && TryGetTunnelParam(instruction.Name, out var tunnelValue))
        {
            SetVariable(instruction.Name, tunnelValue);
            return;
        }

        if (instruction.Required)
        {
            throw Error($"Required parameter ${instruction.Name.LocalName} not supplied");
        }

        object? value;

        if (instruction.Select != null)
        {
            value = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
        }
        else if (instruction.Content != null)
        {
            var isSequenceType = instruction.As != null &&
                (instruction.As.Occurrence == Occurrence.ZeroOrMore || instruction.As.Occurrence == Occurrence.OneOrMore);

            if (isSequenceType)
            {
                var savedAccumulator = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();

                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                var savedLogicalStart = _outputLogicalStart;
                _outputLogicalStart = _output.Length;
                var savedAtomic = _lastResultWasAtomic;
                _lastResultWasAtomic = false;
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                var textContent = savedScope.GetWritten();
                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;
                _lastResultWasAtomic = savedAtomic;

                var sequenceItems = new List<object?>();
                foreach (var item in _sequenceAccumulator)
                    if (item != null)
                        sequenceItems.Add(item);

                if (!string.IsNullOrEmpty(textContent) && _nodeStore != null && textContent.Contains('<', StringComparison.Ordinal))
                {
                    try
                    {
                        // Stream-parse the wrapper rather than allocating a full XmlDocument.
                        var settings = new System.Xml.XmlReaderSettings
                        {
                            DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                            IgnoreWhitespace = false,
                            IgnoreComments = false,
                            IgnoreProcessingInstructions = false,
                        };
                        using var stringReader = new System.IO.StringReader($"<_seq_root_>{textContent}</_seq_root_>");
                        using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                        var parsedChildren = new List<object?>();
                        ReadAsBodyChunkChildren(reader, parsedChildren);
                        foreach (var child in parsedChildren)
                        {
                            if (child is XdmNode cn)
                                cn.Parent = null;
                            sequenceItems.Add(child);
                        }
                    }
                    catch (System.Xml.XmlException)
                    {
                        sequenceItems.Add(new ResultTreeFragment(textContent));
                    }
                }
                else if (!string.IsNullOrEmpty(textContent))
                {
                    sequenceItems.Add(new Xdm.XsUntypedAtomic(StripXmlMarkup(textContent)));
                }

                value = sequenceItems.Count > 0 ? sequenceItems.ToArray() : Array.Empty<object?>();
                _sequenceAccumulator = savedAccumulator;
            }
            else
            {
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                var savedLogicalStart = _outputLogicalStart;
                _outputLogicalStart = _output.Length;
                var savedAtomic2 = _lastResultWasAtomic;
                _lastResultWasAtomic = false;
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                var content = savedScope.GetWritten();
                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;
                _lastResultWasAtomic = savedAtomic2;
                value = content.Contains('<', StringComparison.Ordinal) ? new ResultTreeFragment(content) : (object)new Xdm.XsUntypedAtomic(StripXmlMarkup(content));
            }
        }
        else
        {
            // Per XSLT spec: param with no select and no content defaults to empty string,
            // but if the type allows empty sequence (? or *), default to null (empty sequence)
            if (instruction.As != null && (instruction.As.Occurrence == Occurrence.ZeroOrOne
                || instruction.As.Occurrence == Occurrence.ZeroOrMore))
                value = null;
            else
                value = "";
        }

        SetVariable(instruction.Name, value);
    }

    public override async ValueTask NumberAsync(XsltNumber instruction)
    {
        List<object> numbers;

        if (instruction.Value != null)
        {
            // Explicit value expression — may produce a sequence of numbers
            var result = await EvaluateAsync(instruction.Value).ConfigureAwait(false);
            numbers = ConvertToNumberSequence(result);
            // XTDE0980: value must be non-negative (and not NaN) — only in 2.0+ mode
            // In backwards-compatible (1.0) mode, NaN/negative produce "NaN" output
            if (!IsBackwardsCompatible)
            {
                foreach (var num in numbers)
                {
                    if (num is double d && (double.IsNaN(d) || d < 0))
                        throw new InvalidOperationException("XTDE0980: Value of xsl:number must be a non-negative number");
                    if (num is BigInteger bi && bi < 0)
                        throw new InvalidOperationException("XTDE0980: Value of xsl:number must be a non-negative number");
                }
            }
        }
        else if (instruction.Select != null)
        {
            // Count nodes based on select expression (XSLT 2.0+)
            var selectResult = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            XdmNode? selectedNode = null;
            int nodeCount = 0;
            if (selectResult is XdmNode n)
            {
                selectedNode = n;
                nodeCount = 1;
            }
            else if (selectResult is object?[] arr)
            {
                nodeCount = arr.Length;
                if (arr.Length > 0)
                    selectedNode = arr[0] as XdmNode;
            }
            else if (selectResult is System.Collections.IEnumerable enumerable && selectResult is not string)
            {
                foreach (var item in enumerable)
                {
                    nodeCount++;
                    if (selectedNode == null && item is XdmNode xn)
                        selectedNode = xn;
                }
            }
            // XTTE1000: select must return exactly one node
            if (nodeCount == 0 || selectedNode == null)
                throw new InvalidOperationException("XTTE1000: select expression in xsl:number returned an empty sequence");
            if (nodeCount > 1)
                throw new InvalidOperationException("XTTE1000: select expression in xsl:number returned more than one item");
            numbers = CountNodes(instruction, selectedNode);
        }
        else
        {
            // XTTE0990: context item must be a node when no value/select
            if (ContextItem is not XdmNode)
                throw new InvalidOperationException("XTTE0990: Context item for xsl:number must be a node");
            // Count nodes based on level, count, from (uses context item)
            numbers = CountNodes(instruction, null);
        }

        // Apply start-at offset to all numbers (XSLT 3.0: applies to both counted and explicit value)
        if (instruction.StartAt != null)
        {
            var startAtStr = await EvaluateAvtAsync(instruction.StartAt).ConfigureAwait(false);
            // start-at can be a space-separated list of integers for level="multiple"
            var startAtParts = startAtStr.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            if (startAtParts.Length == 1)
            {
                if (long.TryParse(startAtStr, NumberStyles.Integer, CultureInfo.InvariantCulture, out var startAt) && startAt != 1)
                {
                    for (var i = 0; i < numbers.Count; i++)
                        if (numbers[i] is double d && !double.IsNaN(d))
                            numbers[i] = d + startAt - 1;
                        else if (numbers[i] is BigInteger bi)
                            numbers[i] = bi + startAt - 1;
                }
            }
            else
            {
                // Multiple start-at values for level="multiple"
                for (var i = 0; i < numbers.Count && i < startAtParts.Length; i++)
                {
                    if (long.TryParse(startAtParts[i], NumberStyles.Integer, CultureInfo.InvariantCulture, out var startAt) && startAt != 1)
                        if (numbers[i] is double d && !double.IsNaN(d))
                            numbers[i] = d + startAt - 1;
                        else if (numbers[i] is BigInteger bi)
                            numbers[i] = bi + startAt - 1;
                }
            }
        }

        // Determine format string
        var format = "1";
        if (instruction.Format != null)
        {
            format = await EvaluateAvtAsync(instruction.Format).ConfigureAwait(false);
        }

        // Determine grouping
        string? groupSep = null;
        int groupSize = 0;
        if (instruction.GroupingSeparator != null)
        {
            groupSep = await EvaluateAvtAsync(instruction.GroupingSeparator).ConfigureAwait(false);
        }
        if (instruction.GroupingSize != null)
        {
            var sizeStr = await EvaluateAvtAsync(instruction.GroupingSize).ConfigureAwait(false);
            int.TryParse(sizeStr, NumberStyles.Integer, CultureInfo.InvariantCulture, out groupSize);
        }

        // Determine ordinal
        string? ordinal = null;
        if (instruction.OrdinalValue != null)
        {
            ordinal = await EvaluateAvtAsync(instruction.OrdinalValue).ConfigureAwait(false);
        }

        // Determine language
        string? lang = null;
        if (instruction.Lang != null)
        {
            lang = await EvaluateAvtAsync(instruction.Lang).ConfigureAwait(false);
            // XTDE0030: lang must be a valid language tag (starts with letter, BCP 47-like)
            if (!string.IsNullOrEmpty(lang) && !IsValidLanguageTag(lang))
                throw new InvalidOperationException($"XTDE0030: Invalid language tag '{lang}' in xsl:number");
        }

        // Format the numbers
        var formatted = FormatNumbers(numbers, format, groupSep, groupSize, ordinal, lang);
        _output.Append(formatted);
    }

    private static double ConvertToNumberDouble(object? value)
    {
        value = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(value);
        return value switch
        {
            null => double.NaN,
            long l => l,
            int i => i,
            double d => d,
            decimal m => (double)m,
            System.Numerics.BigInteger bi => (double)bi,
            string s when long.TryParse(s, NumberStyles.Integer, CultureInfo.InvariantCulture, out var n) => n,
            string s when double.TryParse(s, NumberStyles.Float, CultureInfo.InvariantCulture, out var d) => d,
            string => double.NaN,
            object[] arr when arr.Length > 0 => ConvertToNumberDouble(arr[0]),
            _ => double.NaN
        };
    }

    /// <summary>
    /// Converts a value to a number for xsl:number formatting.
    /// Returns double for normal values, BigInteger for values that overflow long.
    /// </summary>
    private static object ConvertToNumberObject(object? value)
    {
        value = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(value);
        return value switch
        {
            null => double.NaN,
            System.Numerics.BigInteger bi => (object)bi,
            long l => (double)l,
            int i => (double)i,
            double d => d,
            decimal m => (double)m,
            string s when long.TryParse(s, NumberStyles.Integer, CultureInfo.InvariantCulture, out var n) => (double)n,
            string s when double.TryParse(s, NumberStyles.Any, CultureInfo.InvariantCulture, out var d2) => d2,
            object[] arr when arr.Length > 0 => ConvertToNumberObject(arr[0]),
            _ => double.NaN
        };
    }

    private List<object> ConvertToNumberSequence(object? value)
    {
        // Empty sequence handling depends on XSLT version:
        // - XSLT 2.0+: empty sequence produces no output (empty list)
        // - XSLT 1.0 (backwards compatible): empty sequence converts to NaN
        if (value == null)
            return IsBackwardsCompatible ? [double.NaN] : [];

        if (value is object?[] arr)
        {
            // Empty array is also an empty sequence
            if (arr.Length == 0)
                return IsBackwardsCompatible ? [double.NaN] : [];
            // XSLT 1.0 backwards-compatible mode: use first item only
            if (IsBackwardsCompatible)
                return [ConvertToNumberObject(arr[0])];
            var result = new List<object>();
            foreach (var item in arr)
                result.Add(ConvertToNumberObject(item));
            return result;
        }
        if (value is IEnumerable<object> seq && value is not string)
        {
            // XSLT 1.0 backwards-compatible mode: use first item only
            if (IsBackwardsCompatible)
            {
                var first = seq.FirstOrDefault();
                return first != null ? [ConvertToNumberObject(first)] : [double.NaN];
            }
            var result = new List<object>();
            foreach (var item in seq)
                result.Add(ConvertToNumberObject(item));
            // If enumerable was empty, handle per version
            if (result.Count == 0 && IsBackwardsCompatible)
                return [double.NaN];
            return result;
        }
        return [ConvertToNumberObject(value)];
    }

    private static long ConvertToNumber(object? value)
    {
        var d = ConvertToNumberDouble(value);
        return double.IsNaN(d) ? 0 : (long)Math.Round(d);
    }

    private List<object> CountNodes(XsltNumber instruction, XdmNode? selectedNode)
    {
        var node = selectedNode ?? ContextItem;
        if (node is not XdmNode xdmNode || _nodeStore == null)
            return [1.0];

        var countPattern = instruction.Count;
        var fromPattern = instruction.From;

        // Ensure namespace IDs are resolved in count/from patterns
        // (template match patterns are resolved during setup, but xsl:number patterns are not)
        ResolvePatternNamespacesLocal(countPattern);
        ResolvePatternNamespacesLocal(fromPattern);

        // Push the target node as current() for count/from pattern predicates.
        // Per XSLT 3.0 §13.4, current() in count/from patterns returns the node being numbered.
        PushCurrentItem(xdmNode);
        try
        {
            return CountNodesCore(instruction, xdmNode, countPattern, fromPattern);
        }
        finally
        {
            PopCurrentItem();
        }
    }

#pragma warning disable CS8602 // _nodeStore guaranteed non-null by caller
    private List<object> CountNodesCore(XsltNumber instruction, XdmNode xdmNode,
        XsltPattern? countPattern, XsltPattern? fromPattern)
    {
        switch (instruction.Level)
        {
            case NumberLevel.Single:
            {
                var current = xdmNode;

                // If no count pattern, default to matching same node type/name
                if (countPattern == null)
                {
                    countPattern = CreateDefaultCountPattern(current);
                }

                // Walk up to find the first ancestor (or self) that matches count
                // but stop if we hit the from pattern
                // Note: For predicates with position(), we need to compute correct position among siblings
                while (current != null && !MatchesWithSiblingPosition(countPattern, current))
                {
                    if (fromPattern != null && MatchesWithSiblingPosition(fromPattern, current))
                        return []; // from found before count — produce no number
                    if (current.Parent is not { } pid || pid == NodeId.None)
                        return [];
                    current = _nodeStore.GetNode(pid);
                }

                if (current == null)
                    return [];

                // If from pattern specified, check if a from ancestor exists.
                // If it does, we count within that scope. If not, we still count
                // (just at the current level without the reset behavior).
                XdmNode? fromAncestor = null;
                if (fromPattern != null)
                {
                    var check = current;
                    while (check != null)
                    {
                        if (MatchesWithSiblingPosition(fromPattern, check))
                        {
                            fromAncestor = check;
                            break;
                        }
                        if (check.Parent is not { } cpid || cpid == NodeId.None)
                            break;
                        check = _nodeStore.GetNode(cpid);
                    }
                    // Note: we no longer return [] when fromAncestor is null.
                    // Per XSLT spec, nodes without a from ancestor are still numbered.
                }

                // Count preceding siblings (including self) that match
                long count = 0;
                if (current.Parent is { } parentId && parentId != NodeId.None)
                {
                    var parent = _nodeStore.GetNode(parentId);
                    if (parent != null)
                    {
                        var children = _nodeStore.GetChildren(parent).ToList();

                        // For pattern predicates using position(), we need to compute:
                        // 1. Total count of siblings matching the node test (for last())
                        // 2. Position of each sibling among those matching node test (for position())
                        int totalMatchingNodeTest = children.Count(c => countPattern.MatchesNodeTest(c));

                        int nodeTestPosition = 0;
                        foreach (var sibling in children)
                        {
                            // Track position among siblings matching node test
                            if (countPattern.MatchesNodeTest(sibling))
                                nodeTestPosition++;

                            // Evaluate full pattern with correct position/size context
                            if (countPattern.Matches(sibling, CreateMatchContext(nodeTestPosition, totalMatchingNodeTest)))
                                count++;

                            if (sibling.Id == current.Id)
                                break;
                        }
                    }
                }
                else
                {
                    // Root-level node (e.g., document node) has no parent/siblings
                    // If it matches the count pattern, its position is 1
                    count = 1;
                }

                return count == 0 ? [] : [(object)(double)count];
            }

            case NumberLevel.Multiple:
            {
                // Count at each level from the matched node up to the from node
                var numbers = new List<object>();
                var current = xdmNode;

                if (countPattern == null)
                    countPattern = CreateDefaultCountPattern(current);

                while (current != null)
                {
                    // First check if current matches the count pattern (with position context)
                    // We need position of current among its siblings for predicate evaluation
                    bool currentMatches = false;
                    if (current.Parent is { } pid2 && pid2 != NodeId.None)
                    {
                        var parent = _nodeStore.GetNode(pid2);
                        if (parent != null)
                        {
                            var children = _nodeStore.GetChildren(parent).ToList();
                            int totalMatchingNodeTest = children.Count(c => countPattern.MatchesNodeTest(c));
                            int currentPosition = 0;

                            foreach (var sibling in children)
                            {
                                if (countPattern.MatchesNodeTest(sibling))
                                    currentPosition++;
                                if (sibling.Id == current.Id)
                                    break;
                            }

                            using var mc = AcquireMatchContext(currentPosition, totalMatchingNodeTest);
                            currentMatches = countPattern.Matches(current, mc.Value);
                        }
                    }
                    else
                    {
                        using var mc = AcquireMatchContext();
                        currentMatches = countPattern.Matches(current, mc.Value);
                    }

                    if (currentMatches)
                    {
                        long count = 0;
                        if (current.Parent is { } pid3 && pid3 != NodeId.None)
                        {
                            var parent = _nodeStore.GetNode(pid3);
                            if (parent != null)
                            {
                                var children = _nodeStore.GetChildren(parent).ToList();
                                int totalMatchingNodeTest = children.Count(c => countPattern.MatchesNodeTest(c));
                                int nodeTestPosition = 0;

                                foreach (var sibling in children)
                                {
                                    if (countPattern.MatchesNodeTest(sibling))
                                        nodeTestPosition++;

                                    bool siblingMatches;
                                    using (var mc = AcquireMatchContext(nodeTestPosition, totalMatchingNodeTest))
                                        siblingMatches = countPattern.Matches(sibling, mc.Value);
                                    if (siblingMatches)
                                        count++;

                                    if (sibling.Id == current.Id)
                                        break;
                                }
                            }
                        }
                        numbers.Insert(0, (object)(double)(count == 0 ? 1 : count));
                    }

                    // Check from pattern AFTER count — a node matching both from and count
                    // should still be counted before the walk stops
                    if (fromPattern != null)
                    {
                        bool fromMatched;
                        using (var mc = AcquireMatchContext())
                            fromMatched = fromPattern.Matches(current, mc.Value);
                        if (fromMatched) break;
                    }

                    if (current.Parent is not { } pid || pid == NodeId.None)
                        break;
                    current = _nodeStore.GetNode(pid);
                }

                return numbers;
            }

            case NumberLevel.Any:
            {
                // Count all preceding nodes (in document order) matching count
                if (countPattern == null)
                    countPattern = CreateDefaultCountPattern(xdmNode);

                // Find the root of the tree containing the selected node
                // This is important when select points to a variable tree (not the main document)
                var treeRoot = FindTreeRoot(xdmNode);

                long count = 0;
                CountNodesInDocOrder(treeRoot, xdmNode, countPattern, fromPattern, ref count, out var done);
                return count == 0 ? [] : [(object)(double)count];
            }

            default:
                return [1.0];
        }
    }
#pragma warning restore CS8602

    private void CountNodesInDocOrder(XdmNode? node, XdmNode target, XsltPattern countPattern,
        XsltPattern? fromPattern, ref long count, out bool done)
    {
        done = false;
        if (node == null)
            return;

        // Reset count if we hit the from pattern
        if (fromPattern != null)
        {
            bool fromMatched;
            using (var mc = AcquireMatchContext())
                fromMatched = fromPattern.Matches(node, mc.Value);
            if (fromMatched) count = 0;
        }

        bool countMatched;
        using (var mc2 = AcquireMatchContext())
            countMatched = countPattern.Matches(node, mc2.Value);
        if (countMatched) count++;

        if (node.Id == target.Id)
        {
            done = true;
            return;
        }

        // In XDM document order, attributes come after the element start but before children.
        // For level="any", the counting set is "descendants of AF plus the selected node".
        // Attributes are NOT descendants, so only check attributes when the target is an
        // attribute on THIS element — and only count the target itself (XSLT 3.0 §13.4).
        if (node is XdmElement elem && target is XdmAttribute && target.Parent == elem.Id)
        {
            foreach (var attr in _nodeStore!.GetAttributes(elem))
            {
                if (attr.Id == target.Id)
                {
                    if (fromPattern != null)
                    {
                        bool fromAttrMatched;
                        using (var mc = AcquireMatchContext())
                            fromAttrMatched = fromPattern.Matches(attr, mc.Value);
                        if (fromAttrMatched) count = 0;
                    }
                    bool countAttrMatched;
                    using (var mc2 = AcquireMatchContext())
                        countAttrMatched = countPattern.Matches(attr, mc2.Value);
                    if (countAttrMatched) count++;
                    done = true;
                    return;
                }
            }
        }

        // Process children in document order
        foreach (var child in _nodeStore!.GetChildren(node))
        {
            CountNodesInDocOrder(child, target, countPattern, fromPattern, ref count, out done);
            if (done)
                return;
        }
    }

    /// <summary>
    /// Matches a pattern against a node, computing the correct position context
    /// for predicate evaluation. Position is computed among siblings matching the node test.
    /// </summary>
    private bool MatchesWithSiblingPosition(XsltPattern pattern, XdmNode node)
    {
        if (node.Parent is not { } parentId || parentId == NodeId.None)
        {
            // Root node - no siblings, position is 1
            return pattern.Matches(node, CreateMatchContext(1, 1));
        }

        var parent = _nodeStore!.GetNode(parentId);
        if (parent == null)
            return pattern.Matches(node, CreateMatchContext(1, 1));

        var children = _nodeStore.GetChildren(parent).ToList();
        int totalMatchingNodeTest = children.Count(c => pattern.MatchesNodeTest(c));
        int position = 0;

        foreach (var sibling in children)
        {
            if (pattern.MatchesNodeTest(sibling))
                position++;
            if (sibling.Id == node.Id)
                break;
        }

        return pattern.Matches(node, CreateMatchContext(position, totalMatchingNodeTest));
    }

    /// <summary>
    /// Finds the root node of the tree containing the given node.
    /// This walks up through ancestors until reaching a node with no parent.
    /// </summary>
    private XdmNode FindTreeRoot(XdmNode node)
    {
        var current = node;
        while (current.Parent is { } parentId && parentId != NodeId.None)
        {
            var parent = _nodeStore!.GetNode(parentId);
            if (parent == null)
                break;
            current = parent;
        }
        return current;
    }

    private PathPattern CreateDefaultCountPattern(XdmNode node)
    {
        return node switch
        {
            XdmElement elem => CreateElementCountPattern(elem),
            XdmText => new PathPattern
            {
                Steps = [new PatternStep
                {
                    Axis = Axis.Child,
                    NodeTest = new KindTest { Kind = XdmNodeKind.Text }
                }]
            },
            XdmDocument => new PathPattern
            {
                Steps = [new PatternStep
                {
                    Axis = Axis.Self,
                    NodeTest = new KindTest { Kind = XdmNodeKind.Document }
                }]
            },
            _ => new PathPattern
            {
                Steps = [new PatternStep
                {
                    Axis = Axis.Child,
                    NodeTest = new KindTest { Kind = XdmNodeKind.None }
                }]
            }
        };
    }

    private PathPattern CreateElementCountPattern(XdmElement elem)
    {
        var nsUri = _nodeStore?.GetNamespaceUri(elem.Namespace);
        var nameTest = new NameTest { LocalName = elem.LocalName, NamespaceUri = nsUri };
        if (!string.IsNullOrEmpty(nsUri) && _nodeStore != null)
            nameTest.ResolveNamespace(_nodeStore.InternNamespace);
        return new PathPattern
        {
            Steps = [new PatternStep { Axis = Axis.Child, NodeTest = nameTest }]
        };
    }

    /// <summary>
    /// Resolves namespace URIs in patterns to NamespaceIds using the node store.
    /// Needed for xsl:number count/from patterns which are not resolved during stylesheet setup.
    /// </summary>
    private void ResolvePatternNamespacesLocal(XsltPattern? pattern)
    {
        if (pattern == null || _nodeStore == null)
            return;
        switch (pattern)
        {
            case PathPattern pp:
                foreach (var step in pp.Steps)
                    if (step.NodeTest is NameTest nt && !nt.ResolvedNamespace.HasValue)
                        nt.ResolveNamespace(_nodeStore.InternNamespace);
                break;
            case UnionPattern up:
                foreach (var p in up.Patterns)
                    ResolvePatternNamespacesLocal(p);
                break;
            case ExceptPattern ep:
                ResolvePatternNamespacesLocal(ep.Left);
                ResolvePatternNamespacesLocal(ep.Right);
                break;
            case IntersectPattern ip:
                ResolvePatternNamespacesLocal(ip.Left);
                ResolvePatternNamespacesLocal(ip.Right);
                break;
        }
    }

    // Cached delegates for CreateMatchContext. Method-group conversions allocate
    // a fresh delegate every time, and CreateMatchContext is on the per-element
    // template-match hot path — caching is worth ~37% of streaming alloc traffic.
    // Built once on first use; safe to share because the captured `this` and `_nodeStore`
    // are stable for the lifetime of the transformer.
    private Func<NodeId, XdmNode?>? _matchCtxNodeResolver;
    private Func<object, XQueryExpression, int, int, object?, bool>? _matchCtxPredicateEvaluator;
    private Func<object, NodeTest, object?, (int, int)>? _matchCtxPositionComputer;
    private Func<string, XQueryExpression, object, bool>? _matchCtxKeyPatternEvaluator;
    private Func<XQueryExpression, object, bool>? _matchCtxIdPatternEvaluator;
    private Func<QName, object?>? _matchCtxVariablePatternEvaluator;
    private Func<string, XdmNode?>? _matchCtxDocPatternEvaluator;

    // Pool of XsltContext instances. Each call to AcquireMatchContext pops one
    // (or allocates if empty) and stamps the per-call fields; the returned lease
    // pushes it back to the pool on Dispose. Bounded to keep nested-match cases
    // from inflating the pool unboundedly.
    private readonly Stack<XsltContext> _matchCtxPool = new();
    private const int MaxPooledMatchContexts = 8;

    /// <summary>
    /// Pooled lease over an <see cref="XsltContext"/>. Dispose returns the context
    /// to the transformer's pool. Use with `using var lease = AcquireMatchContext();`
    /// and pass <see cref="Value"/> to <c>Matches</c> / <c>FindMatchingTemplate</c>.
    /// </summary>
    internal readonly ref struct MatchContextLease
    {
        private readonly DefaultXsltExecutionContext _owner;
        public readonly XsltContext Value;
        internal MatchContextLease(DefaultXsltExecutionContext owner, XsltContext value)
        {
            _owner = owner;
            Value = value;
        }
        public void Dispose() => _owner.ReleaseMatchContext(Value);
    }

    private void EnsureMatchCtxDelegates()
    {
        if (_matchCtxPredicateEvaluator is null)
        {
            _matchCtxNodeResolver = _nodeStore != null ? id => _nodeStore.GetNode(id) : null;
            _matchCtxPredicateEvaluator = EvaluatePatternPredicate;
            _matchCtxPositionComputer = ComputeNodePosition;
            _matchCtxKeyPatternEvaluator = EvaluateKeyPattern;
            _matchCtxIdPatternEvaluator = EvaluateIdPattern;
            _matchCtxVariablePatternEvaluator = EvaluateVariablePattern;
            _matchCtxDocPatternEvaluator = EvaluateDocPattern;
        }
    }

    internal MatchContextLease AcquireMatchContext(int position = 0, int size = 0)
    {
        EnsureMatchCtxDelegates();
        var ctx = _matchCtxPool.TryPop(out var pooled) ? pooled : new XsltContext();
        ctx.CurrentNode = ContextItem;
        ctx.Position = position;
        ctx.Last = size;
        ctx.MatchedNode = null;
        ctx.DescendantPositionAncestor = null;
        ctx.NodeResolver = _matchCtxNodeResolver;
        ctx.PredicateEvaluator = _matchCtxPredicateEvaluator;
        ctx.PositionComputer = _matchCtxPositionComputer;
        ctx.KeyPatternEvaluator = _matchCtxKeyPatternEvaluator;
        ctx.IdPatternEvaluator = _matchCtxIdPatternEvaluator;
        ctx.VariablePatternEvaluator = _matchCtxVariablePatternEvaluator;
        ctx.DocPatternEvaluator = _matchCtxDocPatternEvaluator;
        return new MatchContextLease(this, ctx);
    }

    internal void ReleaseMatchContext(XsltContext ctx)
    {
        if (_matchCtxPool.Count >= MaxPooledMatchContexts) return;
        // Clear node references so the pool slot doesn't pin user data while idle.
        ctx.CurrentNode = null;
        ctx.MatchedNode = null;
        ctx.DescendantPositionAncestor = null;
        _matchCtxPool.Push(ctx);
    }

    /// <summary>
    /// Allocating fallback for callsites that can't naturally adopt the lease pattern
    /// (callers that store the context in a local for cross-method use). Prefer
    /// <see cref="AcquireMatchContext"/> on hot paths.
    /// </summary>
    internal XsltContext CreateMatchContext(int position = 0, int size = 0)
    {
        EnsureMatchCtxDelegates();
        return new XsltContext
        {
            CurrentNode = ContextItem,
            Position = position,
            Last = size,
            NodeResolver = _matchCtxNodeResolver,
            PredicateEvaluator = _matchCtxPredicateEvaluator,
            PositionComputer = _matchCtxPositionComputer,
            KeyPatternEvaluator = _matchCtxKeyPatternEvaluator,
            IdPatternEvaluator = _matchCtxIdPatternEvaluator,
            VariablePatternEvaluator = _matchCtxVariablePatternEvaluator,
            DocPatternEvaluator = _matchCtxDocPatternEvaluator,
        };
    }

#pragma warning disable CA1859 // Callback type requires XdmNode? not XdmDocument?
    private XdmNode? EvaluateDocPattern(string uri)
#pragma warning restore CA1859
    {
        try
        {
            return _policyResolver?.ResolveDocument(uri) ?? _documentResolver.ResolveDocument(uri);
        }
#pragma warning disable CA1031
        catch (Exception)
        {
            return null;
        }
#pragma warning restore CA1031
    }

    private object? EvaluateVariablePattern(QName variableName)
    {
        try
        {
            var value = GetVariable(variableName);
            // RTF variables need to be parsed to XDM for node identity matching
            if (value is ResultTreeFragment rtf)
                return ParseResultTreeFragment(rtf);
            return value;
        }
        catch (XsltException ex) when (ex.Message.Contains("XTDE0640", StringComparison.Ordinal))
        {
            throw; // Non-recoverable: circular reference must propagate
        }
        catch (XsltException)
        {
            return null;
        }
    }

    /// <summary>
    /// Computes the position of a node among its siblings matching the given node test.
    /// Returns (position, size) where position is 1-based.
    /// </summary>
    internal (int position, int size) ComputeNodePosition(object node, NodeTest nodeTest, object? descendantAncestor)
    {
        if (node is not XdmNode xdmNode || _nodeStore == null)
            return (1, 1);

        // For descendant axis patterns, compute position among ALL descendants of the ancestor
        if (descendantAncestor is XdmNode ancestor)
        {
            return ComputeDescendantPosition(xdmNode, nodeTest, ancestor);
        }

        if (xdmNode.Parent is not { } parentId || parentId == NodeId.None)
            return (1, 1);

        var parent = _nodeStore.GetNode(parentId);
        if (parent == null)
            return (1, 1);

        var children = _nodeStore.GetChildren(parent).ToList();
        int position = 0;
        int size = 0;

        foreach (var sibling in children)
        {
            if (MatchesNodeTest(sibling, nodeTest))
            {
                size++;
                if (sibling.Id == xdmNode.Id)
                    position = size;
            }
        }

        return position == 0 ? (1, 1) : (position, size);
    }

    /// <summary>
    /// Computes the position of a node among all descendants of an ancestor matching a node test.
    /// Used for descendant axis patterns like doc/descendant::*[position() mod 2 = 0].
    /// </summary>
    private (int position, int size) ComputeDescendantPosition(XdmNode node, NodeTest nodeTest, XdmNode ancestor)
    {
        int position = 0;
        int size = 0;

        void WalkDescendants(XdmNode parent)
        {
            foreach (var child in _nodeStore!.GetChildren(parent))
            {
                if (MatchesNodeTest(child, nodeTest))
                {
                    size++;
                    if (child.Id == node.Id)
                        position = size;
                }
                // Recurse into children for deeper descendants
                WalkDescendants(child);
            }
        }

        WalkDescendants(ancestor);
        return position == 0 ? (1, 1) : (position, size);
    }

    /// <summary>
    /// Tests if a node matches a given node test.
    /// </summary>
    private static bool MatchesNodeTest(XdmNode node, NodeTest nodeTest)
    {
        return (nodeTest, node) switch
        {
            (NameTest nt, XdmElement elem) => nt.Matches(XdmNodeKind.Element, elem.Namespace, elem.LocalName),
            (NameTest nt, XdmAttribute attr) => nt.Matches(XdmNodeKind.Attribute, attr.Namespace, attr.LocalName),
            (KindTest { Kind: XdmNodeKind.Element }, XdmElement) => true,
            (KindTest { Kind: XdmNodeKind.Text }, XdmText) => true,
            (KindTest { Kind: XdmNodeKind.Comment }, XdmComment) => true,
            (KindTest { Kind: XdmNodeKind.ProcessingInstruction }, XdmProcessingInstruction) => true,
            (KindTest { Kind: XdmNodeKind.Document }, XdmDocument) => true,
            (KindTest { Kind: XdmNodeKind.Attribute }, XdmAttribute) => true,
            (KindTest { Kind: XdmNodeKind.None }, _) => node is not XdmDocument, // node() matches all except document
            _ => false
        };
    }

    internal bool EvaluatePatternPredicate(object stepNode, XQueryExpression predicate, int position, int size, object? matchedNode)
    {
        // Push the step node as context item for predicate evaluation (for "." references)
        // Position and size are used for position() and last() functions
        PushContextItem(stepNode, position, size);

        // Per XSLT spec section 5.5.4: "The special rule for current() in patterns is that
        // current() refers to the node that is being matched by the pattern."
        // For multi-step patterns, this is the original node being matched (not the ancestor being checked).
        // If matchedNode is null (shouldn't happen), fall back to stepNode.
        PushCurrentItem(matchedNode ?? stepNode);
        try
        {
            var result = EvaluateAsync(predicate).AsTask().GetAwaiter().GetResult();

            // XPath numeric predicates: if the predicate evaluates to a number,
            // the predicate is true if and only if that number equals the context position
            if (result is int i)
                return i == position;
            if (result is long l)
                return l == position;
            if (result is double d)
                return Math.Abs(d - position) < 0.0001;
            if (result is decimal m)
                return m == position;

            return EffectiveBooleanValue(result);
        }
#pragma warning disable CA1031 // Predicate evaluation failure should not crash pattern matching
        catch (Exception ex) when (
            ex is not PhoenixmlDb.XQuery.Execution.XQueryRuntimeException { ErrorCode: "XPST0017" }
            && (ex is not XsltException xsltEx || !xsltEx.Message.Contains("XTDE0640", StringComparison.Ordinal)))
        {
            // XTDE0640: If predicate evaluation failed because a variable is not yet bound
            // and that variable is currently being evaluated (circular reference), propagate as XTDE0640
            if (ex is PhoenixmlDb.XQuery.Execution.XQueryRuntimeException { ErrorCode: "XPST0008" }
                && _globalsBeingEvaluated.Count > 0)
            {
                throw Error($"XTDE0640: Circular reference detected while evaluating global variable/parameter (predicate references a global that is currently being initialized)");
            }
            return false;
        }
#pragma warning restore CA1031
        finally
        {
            PopCurrentItem();
            PopContextItem();
        }
    }

    /// <summary>
    /// Evaluates a key() pattern during pattern matching.
    /// Checks if the given node is in the result set of key(keyName, valueExpr).
    /// </summary>
    internal bool EvaluateKeyPattern(string keyName, PhoenixmlDb.XQuery.Ast.XQueryExpression valueExpr, object node)
    {
        try
        {
            // Evaluate the value expression
            var value = EvaluateAsync(valueExpr).AsTask().GetAwaiter().GetResult();

            // Get the key function and invoke it
            var keyFunc = new XsltKeyFunction(this);
            var args = new List<object?> { keyName, value };
            var result = keyFunc.InvokeAsync(args, null!).AsTask().GetAwaiter().GetResult();

            // Check if node is in the result set
            if (result is object[] arr)
            {
                foreach (var item in arr)
                {
                    if (item is XdmNode resultNode && node is XdmNode targetNode &&
                        resultNode.Id == targetNode.Id)
                        return true;
                }
            }
            else if (result is IEnumerable<object> seq && result is not string)
            {
                foreach (var item in seq)
                {
                    if (item is XdmNode resultNode && node is XdmNode targetNode &&
                        resultNode.Id == targetNode.Id)
                        return true;
                }
            }
            return false;
        }
#pragma warning disable CA1031
        catch (XsltException ex) when (ex.Message.Contains("XTDE0640", StringComparison.Ordinal))
        {
            throw; // Non-recoverable: circular key reference must propagate
        }
        catch (Exception)
        {
            return false;
        }
#pragma warning restore CA1031
    }

    internal bool EvaluateIdPattern(PhoenixmlDb.XQuery.Ast.XQueryExpression valueExpr, object node)
    {
        try
        {
            // Evaluate the value expression
            var value = EvaluateAsync(valueExpr).AsTask().GetAwaiter().GetResult();

            // Find the document for the node being matched — id() searches within that document
            XdmDocument? doc = null;
            if (node is XdmDocument d)
                doc = d;
            else if (node is XdmNode n)
                doc = FindDocumentForNode(n);
            if (doc == null || _nodeStore == null)
                return false;

            var results = XsltIdFunction.FindElementsById(value, doc, _nodeStore);

            // Check if node is in the result set
            foreach (var item in results)
            {
                if (item is XdmNode resultNode && node is XdmNode targetNode &&
                    resultNode.Id == targetNode.Id)
                    return true;
            }
            return false;
        }
#pragma warning disable CA1031
        catch (Exception)
        {
            return false;
        }
#pragma warning restore CA1031
    }

    private static string FormatNumbers(List<object> numbers, string format, string? groupSep, int groupSize, string? ordinal = null, string? lang = null)
    {
        // Parse format string into tokens
        // Format string like "1.1" means first number uses "1", separator ".", second uses "1"
        var tokens = ParseFormatTokens(format);

        // XSLT spec: when there are no numbers, still output prefix and suffix
        if (numbers.Count == 0)
        {
            if (tokens.prefix != null || tokens.suffix != null)
                return (tokens.prefix ?? "") + (tokens.suffix ?? "");
            return "";
        }
        var sb = new StringBuilder();

        for (var i = 0; i < numbers.Count; i++)
        {
            if (i > 0)
            {
                // Use separator from format tokens, default "."
                var sepIdx = Math.Min(i, tokens.separators.Count) - 1;
                sb.Append(sepIdx >= 0 && sepIdx < tokens.separators.Count
                    ? tokens.separators[sepIdx]
                    : ".");
            }

            var tokenIdx = Math.Min(i, tokens.formats.Count - 1);
            var token = tokenIdx >= 0 ? tokens.formats[tokenIdx] : "1";

            string formatted;
            if (numbers[i] is BigInteger bigInt)
            {
                // BigInteger: already exact, no rounding needed
                if (bigInt >= long.MinValue && bigInt <= long.MaxValue)
                    formatted = FormatNumber((long)bigInt, token, ordinal, lang);
                else
                    formatted = FormatBigNumber(bigInt, token);
            }
            else
            {
                var dval = (double)numbers[i];
                if (double.IsNaN(dval))
                {
                    sb.Append("NaN");
                    continue;
                }
                var rounded = Math.Round(dval, MidpointRounding.AwayFromZero);
                if (rounded >= long.MinValue && rounded <= long.MaxValue)
                    formatted = FormatNumber((long)rounded, token, ordinal, lang);
                else
                    formatted = FormatBigNumber(DoubleToBigInteger(rounded), token);
            }
            if (groupSep != null && groupSize > 0 && IsNumericFormat(token))
            {
                formatted = AddGroupingSeparators(formatted, groupSep, groupSize);
            }
            sb.Append(formatted);
        }

        // Add prefix and suffix from format
        if (tokens.prefix != null)
            sb.Insert(0, tokens.prefix);
        if (tokens.suffix != null)
            sb.Append(tokens.suffix);

        return sb.ToString();
    }

    private static (string? prefix, List<string> formats, List<string> separators, string? suffix) ParseFormatTokens(string format)
    {
        if (string.IsNullOrEmpty(format))
            return (null, ["1"], ["."], null);

        var formats = new List<string>();
        var separators = new List<string>();
        string? prefix = null;
        string? suffix = null;

        var i = 0;

        // Extract prefix (non-format-token chars at start)
        var prefixEnd = 0;
        while (prefixEnd < format.Length && GetUnicodeFormatTokenLength(format, prefixEnd) == 0)
            prefixEnd++;
        if (prefixEnd > 0)
            prefix = format[..prefixEnd];
        i = prefixEnd;

        while (i < format.Length)
        {
            // Read format token (may include surrogate pairs)
            var tokenStart = i;
            int tokenLen;
            while ((tokenLen = GetUnicodeFormatTokenLength(format, i)) > 0)
                i += tokenLen;
            if (i > tokenStart)
                formats.Add(format[tokenStart..i]);

            // Read separator (non-format-token chars)
            var sepStart = i;
            while (i < format.Length && GetUnicodeFormatTokenLength(format, i) == 0)
                i++;
            if (i > sepStart)
            {
                if (i < format.Length) // More tokens follow
                    separators.Add(format[sepStart..i]);
                else
                    suffix = format[sepStart..i]; // Trailing chars are suffix
            }
        }

        if (formats.Count == 0)
        {
            formats.Add("1");
            // XSLT spec: if format contains only non-alphanumeric characters,
            // they are used as both prefix and suffix
            if (prefix != null && suffix == null)
                suffix = prefix;
        }

        return (prefix, formats, separators, suffix);
    }

    private static bool IsFormatToken(char c)
    {
        // Standard alphanumeric
        if (char.IsLetterOrDigit(c))
            return true;

        // Unicode number sequences (circled, parenthesized, full stop digits)
        // Circled digits: ① (U+2460) through ⑳ (U+2473)
        if (c >= '\u2460' && c <= '\u2473')
            return true;
        // Parenthesized digits: ⑴ (U+2474) through ⒇ (U+2487)
        if (c >= '\u2474' && c <= '\u2487')
            return true;
        // Full stop digits: ⒈ (U+2488) through ⒛ (U+249B)
        if (c >= '\u2488' && c <= '\u249B')
            return true;
        // Circled zero: ⓪ (U+24EA)
        if (c == '\u24EA')
            return true;
        // Negative circled zero: ⓿ (U+24FF)
        if (c == '\u24FF')
            return true;
        // Dingbat negative circled 11-20: ⓫ (U+24EB) to ⓴ (U+24F4)
        if (c >= '\u24EB' && c <= '\u24F4')
            return true;
        // Double circled digits: ⓵ (U+24F5) to ⓾ (U+24FE)
        if (c >= '\u24F5' && c <= '\u24FE')
            return true;
        // Dingbat negative circled digits: ❶ (U+2776) to ❿ (U+277F)
        if (c >= '\u2776' && c <= '\u277F')
            return true;
        // Dingbat circled sans-serif digits: ➀ (U+2780) to ➉ (U+2789)
        if (c >= '\u2780' && c <= '\u2789')
            return true;
        // Dingbat negative circled sans-serif digits: ➊ (U+278A) to ➓ (U+2793)
        if (c >= '\u278A' && c <= '\u2793')
            return true;
        // Parenthesized Ideograph: ㈠ (U+3220) to ㈩ (U+3229)
        if (c >= '\u3220' && c <= '\u3229')
            return true;
        // Circled Ideograph: ㊀ (U+3280) to ㊉ (U+3289)
        if (c >= '\u3280' && c <= '\u3289')
            return true;

        return false;
    }

    /// <summary>
    /// Checks if a string starts with a Unicode format token that may be a surrogate pair.
    /// Returns the token length (1 or 2) if it's a format token, 0 otherwise.
    /// </summary>
    private static int GetUnicodeFormatTokenLength(string s, int index)
    {
        if (index >= s.Length)
            return 0;

        var c = s[index];

        // Check for BMP format tokens
        if (IsFormatToken(c))
            return 1;

        // Check for surrogate pairs (SMP characters)
        if (char.IsHighSurrogate(c) && index + 1 < s.Length && char.IsLowSurrogate(s[index + 1]))
        {
            var codePoint = char.ConvertToUtf32(c, s[index + 1]);
            // DIGIT ZERO FULL STOP: 🄀 (U+1F100)
            if (codePoint == 0x1F100)
                return 2;
            // DIGIT COMMA sequence: 🄁-🄊 (U+1F101-U+1F10A)
            if (codePoint >= 0x1F101 && codePoint <= 0x1F10A)
                return 2;
            // Circled sans-serif zero: 🄋 (U+1F10B)
            if (codePoint == 0x1F10B)
                return 2;
            // Negative circled sans-serif zero: 🄌 (U+1F10C)
            if (codePoint == 0x1F10C)
                return 2;
            // Aegean Numbers: 𐄇 (U+10107) to 𐄐 (U+10110)
            if (codePoint >= 0x10107 && codePoint <= 0x10110)
                return 2;
            // Coptic Epact Numbers: 𐋡 (U+102E1) to 𐋪 (U+102EA)
            if (codePoint >= 0x102E1 && codePoint <= 0x102EA)
                return 2;
            // Rumi Numeral Symbols: 𐹠 (U+10E60) to 𐹩 (U+10E69)
            if (codePoint >= 0x10E60 && codePoint <= 0x10E69)
                return 2;
            // Brahmi Numbers: 𑁒 (U+11052) to 𑁛 (U+1105B)
            if (codePoint >= 0x11052 && codePoint <= 0x1105B)
                return 2;
            // Sinhala Archaic Numbers: 𑇡 (U+111E1) to 𑇪 (U+111EA)
            if (codePoint >= 0x111E1 && codePoint <= 0x111EA)
                return 2;
            // Counting Rod Numerals: 𝍠 (U+1D360) to 𝍨 (U+1D368)
            if (codePoint >= 0x1D360 && codePoint <= 0x1D368)
                return 2;
            // Mende Kikakui Digits: 𞣇 (U+1E8C7) to 𞣏 (U+1E8CF)
            if (codePoint >= 0x1E8C7 && codePoint <= 0x1E8CF)
                return 2;
        }

        return 0;
    }

    private static bool IsNumericFormat(string token)
    {
        return token.Length > 0 && char.IsDigit(token[0]);
    }

    private static string FormatNumber(long number, string token, string? ordinal = null, string? lang = null)
    {
        // Check for Unicode number sequences first
        if (token.Length > 0)
        {
            var unicodeResult = TryFormatUnicodeNumber(number, token);
            if (unicodeResult != null)
                return unicodeResult;
        }

        var result = token switch
        {
            "1" => number.ToString(CultureInfo.InvariantCulture),
            "01" => number.ToString("D2", CultureInfo.InvariantCulture),
            "001" => number.ToString("D3", CultureInfo.InvariantCulture),
            "a" => ToAlpha(number, lowercase: true, lang: lang),
            "A" => ToAlpha(number, lowercase: false, lang: lang),
            "i" => ToRoman(number, lowercase: true),
            "I" => ToRoman(number, lowercase: false),
            "w" => !string.IsNullOrEmpty(ordinal) ? ToOrdinalWords(number, lowercase: true, lang: lang) : ToWords(number, lowercase: true, lang: lang),
            "W" => !string.IsNullOrEmpty(ordinal) ? ToOrdinalWords(number, lowercase: false, lang: lang) : ToWords(number, lowercase: false, lang: lang),
            "Ww" => !string.IsNullOrEmpty(ordinal) ? ToOrdinalWords(number, titleCase: true, lang: lang) : ToWords(number, titleCase: true, lang: lang),
            _ when token.Length > 0 && char.IsDigit(token[0]) =>
                number.ToString($"D{token.Length}", CultureInfo.InvariantCulture),
            _ => number.ToString(CultureInfo.InvariantCulture)
        };

        // Apply ordinal suffix for numeric formats
        if (!string.IsNullOrEmpty(ordinal) && (token == "1" || (token.Length > 0 && char.IsDigit(token[0]))))
        {
            result += GetOrdinalSuffix(number, lang);
        }

        return result;
    }

    private static string FormatBigNumber(BigInteger number, string token)
    {
        // For BigInteger, support numeric digit formats and non-ASCII zero digit replacement
        var result = BigInteger.Abs(number).ToString(CultureInfo.InvariantCulture);

        // Detect non-ASCII zero digit for replacement
        char zeroDigit = '0';
        if (token.Length > 0 && !char.IsAscii(token[0]) && char.IsDigit(token[0]))
            zeroDigit = (char)(token[0] - (int)char.GetNumericValue(token[0]));

        // Zero-pad if format token has leading zeros
        if (token.Length > 1 && char.IsDigit(token[0]))
        {
            var padDigits = token.Length;
            if (result.Length < padDigits)
                result = result.PadLeft(padDigits, '0');
        }

        // Replace ASCII digits with target digit family
        if (zeroDigit != '0')
        {
            var chars = result.ToCharArray();
            for (var i = 0; i < chars.Length; i++)
            {
                if (chars[i] >= '0' && chars[i] <= '9')
                    chars[i] = (char)(zeroDigit + (chars[i] - '0'));
            }
            result = new string(chars);
        }

        return result;
    }

    /// <summary>
    /// Converts a double to BigInteger using the shortest decimal representation (via ToString("R"))
    /// rather than the raw binary representation (via new BigInteger(double)).
    /// This preserves the "conceptual" value: e.g., 1e100 becomes exactly 10^100 instead of
    /// 10000000000000000159028911097599180468... (the nearest IEEE 754 double).
    /// </summary>
    private static BigInteger DoubleToBigInteger(double d)
    {
        var s = d.ToString("R", CultureInfo.InvariantCulture);
        var eIdx = s.IndexOfAny(['E', 'e']);
        if (eIdx < 0)
        {
            // No scientific notation — truncate decimal part
            var dotIdx = s.IndexOf('.', StringComparison.Ordinal);
            return BigInteger.Parse(dotIdx < 0 ? s : s[..dotIdx], CultureInfo.InvariantCulture);
        }

        var mantissa = s[..eIdx];
        var exp = int.Parse(s[(eIdx + 1)..], CultureInfo.InvariantCulture);
        var dotIdx2 = mantissa.IndexOf('.', StringComparison.Ordinal);
        if (dotIdx2 >= 0)
        {
            var fracDigits = mantissa.Length - dotIdx2 - 1;
            mantissa = mantissa.Remove(dotIdx2, 1);
            exp -= fracDigits;
        }

        var result = BigInteger.Parse(mantissa, CultureInfo.InvariantCulture);
        if (exp > 0)
            result *= BigInteger.Pow(10, exp);
        else if (exp < 0)
            result /= BigInteger.Pow(10, -exp);
        return result;
    }

    /// <summary>
    /// Attempts to format a number using Unicode number sequences (circled digits, parenthesized digits, etc.)
    /// Returns null if the token is not a Unicode number sequence or the number is out of range.
    /// </summary>
    private static string? TryFormatUnicodeNumber(long number, string token)
    {
        if (string.IsNullOrEmpty(token))
            return null;

        // Handle SMP characters (surrogate pairs)
        int codePoint;
        if (char.IsHighSurrogate(token[0]) && token.Length > 1 && char.IsLowSurrogate(token[1]))
        {
            codePoint = char.ConvertToUtf32(token[0], token[1]);
        }
        else
        {
            codePoint = token[0];
        }

        return TryFormatUnicodeNumberByCodePoint(number, codePoint);
    }

    private static string? TryFormatUnicodeNumberByCodePoint(long number, int codePoint)
    {
        // Circled digits: ① (U+2460) through ⑳ (U+2473) for 1-20
        // Circled zero: ⓪ (U+24EA) - separate from main sequence
        // Circled 21-35: ㉑ (U+3251) through ㉟ (U+325F)
        // Circled 36-50: ㊱ (U+32B1) through ㊿ (U+32BF)
        if (codePoint >= 0x2460 && codePoint <= 0x2473)
        {
            if (number == 0)
                return "\u24EA"; // ⓪
            if (number >= 1 && number <= 20)
                return ((char)(0x2460 + number - 1)).ToString();
            if (number >= 21 && number <= 35)
                return ((char)(0x3251 + number - 21)).ToString();
            if (number >= 36 && number <= 50)
                return ((char)(0x32B1 + number - 36)).ToString();
            return number.ToString(CultureInfo.InvariantCulture); // Fallback for out of range
        }

        // Circled zero by itself (⓪ U+24EA)
        if (codePoint == 0x24EA)
        {
            if (number == 0)
                return "\u24EA";
            if (number >= 1 && number <= 20)
                return ((char)(0x2460 + number - 1)).ToString();
            if (number >= 21 && number <= 35)
                return ((char)(0x3251 + number - 21)).ToString();
            if (number >= 36 && number <= 50)
                return ((char)(0x32B1 + number - 36)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Parenthesized digits: ⑴ (U+2474) through ⒇ (U+2487) for 1-20
        if (codePoint >= 0x2474 && codePoint <= 0x2487)
        {
            if (number == 0)
                return "0"; // No parenthesized zero exists
            if (number >= 1 && number <= 20)
                return ((char)(0x2474 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Full stop digits: ⒈ (U+2488) through ⒛ (U+249B) for 1-20
        // Full stop zero: 🄀 (U+1F100) in SMP
        if (codePoint >= 0x2488 && codePoint <= 0x249B)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F100); // 🄀
            if (number >= 1 && number <= 20)
                return ((char)(0x2488 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Full stop zero (🄀 U+1F100) as format token
        if (codePoint == 0x1F100)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F100); // 🄀
            if (number >= 1 && number <= 20)
                return ((char)(0x2488 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat negative circled digits: ❶ (U+2776) to ❿ (U+277F) for 1-10
        // Dingbat negative circled 11-20: ⓫ (U+24EB) to ⓴ (U+24F4)
        // Dingbat negative circled zero: ⓿ (U+24FF)
        if (codePoint >= 0x2776 && codePoint <= 0x277F)
        {
            if (number == 0)
                return "\u24FF"; // ⓿
            if (number >= 1 && number <= 10)
                return ((char)(0x2776 + number - 1)).ToString();
            if (number >= 11 && number <= 20)
                return ((char)(0x24EB + number - 11)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Negative circled zero (⓿ U+24FF) as format token
        if (codePoint == 0x24FF)
        {
            if (number == 0)
                return "\u24FF"; // ⓿
            if (number >= 1 && number <= 10)
                return ((char)(0x2776 + number - 1)).ToString();
            if (number >= 11 && number <= 20)
                return ((char)(0x24EB + number - 11)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat negative circled 11-20: ⓫ (U+24EB) to ⓴ (U+24F4)
        if (codePoint >= 0x24EB && codePoint <= 0x24F4)
        {
            if (number == 0)
                return "\u24FF"; // ⓿
            if (number >= 1 && number <= 10)
                return ((char)(0x2776 + number - 1)).ToString();
            if (number >= 11 && number <= 20)
                return ((char)(0x24EB + number - 11)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Double circled digits: ⓵ (U+24F5) to ⓾ (U+24FE) for 1-10
        if (codePoint >= 0x24F5 && codePoint <= 0x24FE)
        {
            if (number >= 1 && number <= 10)
                return ((char)(0x24F5 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat circled sans-serif digits: ➀ (U+2780) to ➉ (U+2789) for 1-10
        // Dingbat circled sans-serif zero: 🄋 (U+1F10B) in SMP
        if (codePoint >= 0x2780 && codePoint <= 0x2789)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F10B); // 🄋
            if (number >= 1 && number <= 10)
                return ((char)(0x2780 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat circled sans-serif zero (🄋 U+1F10B) as format token
        if (codePoint == 0x1F10B)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F10B); // 🄋
            if (number >= 1 && number <= 10)
                return ((char)(0x2780 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat negative circled sans-serif digits: ➊ (U+278A) to ➓ (U+2793) for 1-10
        // Dingbat negative circled sans-serif zero: 🄌 (U+1F10C) in SMP
        if (codePoint >= 0x278A && codePoint <= 0x2793)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F10C); // 🄌
            if (number >= 1 && number <= 10)
                return ((char)(0x278A + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Dingbat negative circled sans-serif zero (🄌 U+1F10C) as format token
        if (codePoint == 0x1F10C)
        {
            if (number == 0)
                return char.ConvertFromUtf32(0x1F10C); // 🄌
            if (number >= 1 && number <= 10)
                return ((char)(0x278A + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // DIGIT COMMA sequence: 🄁 (U+1F101) to 🄊 (U+1F10A) for 0-9
        if (codePoint >= 0x1F101 && codePoint <= 0x1F10A)
        {
            if (number >= 0 && number <= 9)
                return char.ConvertFromUtf32(0x1F101 + (int)number);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Parenthesized Ideograph One to Ten: ㈠ (U+3220) to ㈩ (U+3229) for 1-10
        if (codePoint >= 0x3220 && codePoint <= 0x3229)
        {
            if (number >= 1 && number <= 10)
                return ((char)(0x3220 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Circled Ideograph One to Ten: ㊀ (U+3280) to ㊉ (U+3289) for 1-10
        if (codePoint >= 0x3280 && codePoint <= 0x3289)
        {
            if (number >= 1 && number <= 10)
                return ((char)(0x3280 + number - 1)).ToString();
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Aegean Number One: 𐄇 (U+10107) — range 1-10 (Ten = U+10110)
        if (codePoint >= 0x10107 && codePoint <= 0x10110)
        {
            if (number >= 1 && number <= 10)
                return char.ConvertFromUtf32(0x10107 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Coptic Epact Digit One: 𐋡 (U+102E1) — range 1-10 (Ten = U+102EA)
        if (codePoint >= 0x102E1 && codePoint <= 0x102EA)
        {
            if (number >= 1 && number <= 10)
                return char.ConvertFromUtf32(0x102E1 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Rumi Digit One: 𐹠 (U+10E60) — range 1-10 (Ten = U+10E69)
        if (codePoint >= 0x10E60 && codePoint <= 0x10E69)
        {
            if (number >= 1 && number <= 10)
                return char.ConvertFromUtf32(0x10E60 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Brahmi Number One: 𑁒 (U+11052) — range 1-10 (Ten = U+1105B)
        if (codePoint >= 0x11052 && codePoint <= 0x1105B)
        {
            if (number >= 1 && number <= 10)
                return char.ConvertFromUtf32(0x11052 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Sinhala Archaic Digit One: 𑇡 (U+111E1) — range 1-10 (Ten = U+111EA)
        if (codePoint >= 0x111E1 && codePoint <= 0x111EA)
        {
            if (number >= 1 && number <= 10)
                return char.ConvertFromUtf32(0x111E1 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Counting Rod Unit Digit One: 𝍠 (U+1D360) — range 1-9
        if (codePoint >= 0x1D360 && codePoint <= 0x1D368)
        {
            if (number >= 1 && number <= 9)
                return char.ConvertFromUtf32(0x1D360 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        // Mende Kikakui Digit One: 𞣇 (U+1E8C7) — range 1-9
        if (codePoint >= 0x1E8C7 && codePoint <= 0x1E8CF)
        {
            if (number >= 1 && number <= 9)
                return char.ConvertFromUtf32(0x1E8C7 + (int)number - 1);
            return number.ToString(CultureInfo.InvariantCulture);
        }

        return null; // Not a recognized Unicode number sequence
    }

    private static string GetOrdinalSuffix(long number, string? lang = null)
    {
        var langCode = lang?.Split('-')[0];

        // German uses "." as ordinal suffix (e.g., "1." for "first")
        if (string.Equals(langCode, "de", StringComparison.OrdinalIgnoreCase))
            return ".";

        // English ordinals
        var abs = Math.Abs(number);
        var lastTwo = abs % 100;
        var lastOne = abs % 10;

        if (lastTwo >= 11 && lastTwo <= 13)
            return "th";

        return lastOne switch
        {
            1 => "st",
            2 => "nd",
            3 => "rd",
            _ => "th"
        };
    }

    private static string ToAlpha(long number, bool lowercase, string? lang = null)
    {
        if (number <= 0)
            return number.ToString(CultureInfo.InvariantCulture);

        var sb = new StringBuilder();
        var n = number;
        while (n > 0)
        {
            n--;
            var c = (char)((n % 26) + (lowercase ? 'a' : 'A'));
            sb.Insert(0, c);
            n /= 26;
        }
        return sb.ToString();
    }

    private static string ToRoman(long number, bool lowercase)
    {
        if (number <= 0 || number >= 4000)
            return number.ToString(CultureInfo.InvariantCulture);

        ReadOnlySpan<(int value, string numeral)> romanNumerals =
        [
            (1000, "M"), (900, "CM"), (500, "D"), (400, "CD"),
            (100, "C"), (90, "XC"), (50, "L"), (40, "XL"),
            (10, "X"), (9, "IX"), (5, "V"), (4, "IV"), (1, "I")
        ];

        var sb = new StringBuilder();
        var n = (int)number;
        foreach (var (value, numeral) in romanNumerals)
        {
            while (n >= value)
            {
                sb.Append(numeral);
                n -= value;
            }
        }

        var result = sb.ToString();
        if (lowercase)
        {
            result = string.Create(result.Length, result, (chars, src) =>
            {
                for (var j = 0; j < src.Length; j++)
                    chars[j] = char.ToLower(src[j], CultureInfo.InvariantCulture);
            });
        }
        return result;
    }

    private static string ToWords(long number, bool lowercase = false, bool titleCase = false, string? lang = null)
    {
        // Normalize language code (e.g., "de-DE" -> "de")
        var langCode = lang?.Split('-')[0];
        var isGerman = string.Equals(langCode, "de", StringComparison.OrdinalIgnoreCase);

        string zeroWord = isGerman ? "null" : "zero";
        string minusWord = isGerman ? "minus " : "minus ";

        if (number == 0)
            return lowercase ? zeroWord : titleCase ? CultureInfo.InvariantCulture.TextInfo.ToTitleCase(zeroWord) : zeroWord.ToUpperInvariant();

        var words = isGerman ? NumberToWordsGerman(Math.Abs(number)) : NumberToWordsEnglish(Math.Abs(number));
        if (number < 0)
            words = minusWord + words;

        if (lowercase)
            return words;
        if (titleCase)
            return TitleCaseNumberWords(words);
        return words.ToUpperInvariant();
    }

    private static string ToOrdinalWords(long number, bool lowercase = false, bool titleCase = false, string? lang = null)
    {
        var langCode = lang?.Split('-')[0];
        var isGerman = string.Equals(langCode, "de", StringComparison.OrdinalIgnoreCase);

        if (number == 0)
        {
            var zeroOrd = isGerman ? "nullte" : "zeroth";
            if (lowercase) return zeroOrd;
            if (titleCase) return CultureInfo.InvariantCulture.TextInfo.ToTitleCase(zeroOrd);
            return zeroOrd.ToUpperInvariant();
        }

        string words;
        if (isGerman)
        {
            words = NumberToWordsGerman(Math.Abs(number)) + "ste";
        }
        else
        {
            words = NumberToOrdinalWordsEnglish(Math.Abs(number));
        }

        if (number < 0)
            words = "minus " + words;

        if (lowercase) return words;
        if (titleCase) return TitleCaseNumberWords(words);
        return words.ToUpperInvariant();
    }

    /// <summary>Title-case for number words, keeping "and"/"und" lowercase.</summary>
    private static string TitleCaseNumberWords(string words)
    {
        var parts = words.Split(' ');
        for (int i = 0; i < parts.Length; i++)
        {
            if (parts[i].Length > 0 && parts[i] is not ("and" or "und"))
                parts[i] = char.ToUpperInvariant(parts[i][0]) + parts[i][1..];
        }
        return string.Join(' ', parts);
    }

    private static string NumberToOrdinalWordsEnglish(long number)
    {
        // For ordinals, only the last word changes to ordinal form
        // E.g., "twenty-one" → "twenty-first", "one hundred" → "one hundredth"
        string[] onesOrdinal = ["", "first", "second", "third", "fourth", "fifth",
            "sixth", "seventh", "eighth", "ninth", "tenth", "eleventh", "twelfth",
            "thirteenth", "fourteenth", "fifteenth", "sixteenth", "seventeenth",
            "eighteenth", "nineteenth"];
        string[] tensOrdinal = ["", "", "twentieth", "thirtieth", "fortieth", "fiftieth",
            "sixtieth", "seventieth", "eightieth", "ninetieth"];

        if (number <= 0) return "";
        if (number < 20) return onesOrdinal[number];
        if (number < 100)
        {
            var remainder = number % 10;
            if (remainder == 0) return tensOrdinal[number / 10];
            string[] tens = ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"];
            return tens[number / 10] + " " + onesOrdinal[remainder];
        }

        // For larger numbers, build cardinal form for all but last component, then ordinal for last
        if (number < 1000)
        {
            string[] ones = ["", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"];
            var rest = number % 100;
            if (rest == 0) return ones[number / 100] + " hundredth";
            return ones[number / 100] + " hundred and " + NumberToOrdinalWordsEnglish(rest);
        }

        // Use standard groupings
        (long divisor, string name, string ordName)[] groups =
        [
            (1_000_000_000_000L, "trillion", "trillionth"),
            (1_000_000_000L, "billion", "billionth"),
            (1_000_000L, "million", "millionth"),
            (1_000L, "thousand", "thousandth")
        ];

        foreach (var (divisor, name, ordName) in groups)
        {
            if (number >= divisor)
            {
                var high = NumberToWordsEnglish(number / divisor);
                var rest = number % divisor;
                if (rest == 0) return $"{high} {ordName}";
                return $"{high} {name} {NumberToOrdinalWordsEnglish(rest)}";
            }
        }

        return number.ToString(CultureInfo.InvariantCulture);
    }

    private static string NumberToWordsEnglish(long number)
    {
        if (number == 0)
            return "";

        string[] ones = ["", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine",
            "ten", "eleven", "twelve", "thirteen", "fourteen", "fifteen", "sixteen", "seventeen", "eighteen", "nineteen"];
        string[] tens = ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"];

        if (number < 20)
            return ones[number];
        if (number < 100)
        {
            var t = tens[number / 10];
            var o = number % 10;
            return o > 0 ? $"{t} {ones[o]}" : t;
        }
        if (number < 1000)
        {
            var rest = number % 100;
            return rest > 0 ? $"{ones[number / 100]} hundred and {NumberToWordsEnglish(rest)}" : $"{ones[number / 100]} hundred";
        }

        (string name, long divisor)[] groups = [
            ("quintillion", 1_000_000_000_000_000_000L),
            ("quadrillion", 1_000_000_000_000_000L),
            ("trillion", 1_000_000_000_000L),
            ("billion", 1_000_000_000L),
            ("million", 1_000_000L),
            ("thousand", 1_000L)
        ];

        foreach (var (name, divisor) in groups)
        {
            if (number >= divisor)
            {
                var high = NumberToWordsEnglish(number / divisor);
                var rest = number % divisor;
                return rest > 0 ? $"{high} {name} {NumberToWordsEnglish(rest)}" : $"{high} {name}";
            }
        }

        return number.ToString(CultureInfo.InvariantCulture);
    }

    private static string NumberToWordsGerman(long number)
    {
        if (number == 0)
            return "";

        // German number words
        string[] ones = ["", "eins", "zwei", "drei", "vier", "fünf", "sechs", "sieben", "acht", "neun",
            "zehn", "elf", "zwölf", "dreizehn", "vierzehn", "fünfzehn", "sechzehn", "siebzehn", "achtzehn", "neunzehn"];
        // Note: "eins" becomes "ein" in compounds
        string[] onesCompound = ["", "ein", "zwei", "drei", "vier", "fünf", "sechs", "sieben", "acht", "neun"];
        string[] tens = ["", "", "zwanzig", "dreißig", "vierzig", "fünfzig", "sechzig", "siebzig", "achtzig", "neunzig"];

        if (number < 20)
            return ones[number];
        if (number < 100)
        {
            var t = tens[number / 10];
            var o = number % 10;
            // German reverses: 21 = "einundzwanzig" (one-and-twenty)
            return o > 0 ? $"{onesCompound[o]}und{t}" : t;
        }
        if (number < 1000)
        {
            var rest = number % 100;
            var hundredPart = onesCompound[number / 100] + "hundert";
            return rest > 0 ? $"{hundredPart}{NumberToWordsGerman(rest)}" : hundredPart;
        }

        // German uses "Milliarde" for billion (10^9), "Billion" for trillion (10^12)
        (string singular, string plural, long divisor)[] groups = [
            ("Trillion", "Trillionen", 1_000_000_000_000_000_000L),
            ("Billiarde", "Billiarden", 1_000_000_000_000_000L),
            ("Billion", "Billionen", 1_000_000_000_000L),
            ("Milliarde", "Milliarden", 1_000_000_000L),
            ("Million", "Millionen", 1_000_000L),
            ("tausend", "tausend", 1_000L)
        ];

        foreach (var (singular, plural, divisor) in groups)
        {
            if (number >= divisor)
            {
                var count = number / divisor;
                var rest = number % divisor;
                string groupWord;
                if (divisor == 1000)
                {
                    // "tausend" is lowercase and doesn't use "ein" for 1000
                    groupWord = count == 1 ? "tausend" : $"{NumberToWordsGerman(count)}tausend";
                }
                else
                {
                    // Use "eine" for feminine nouns (Million, Milliarde, Billion, etc.)
                    var countWord = count == 1 ? "eine" : NumberToWordsGerman(count);
                    groupWord = count == 1 ? $"{countWord} {singular}" : $"{countWord} {plural}";
                }
                return rest > 0 ? $"{groupWord} {NumberToWordsGerman(rest)}".Trim() : groupWord;
            }
        }

        return number.ToString(CultureInfo.InvariantCulture);
    }

    private static string AddGroupingSeparators(string number, string separator, int size)
    {
        if (size <= 0 || number.Length <= size)
            return number;

        var sb = new StringBuilder();
        var count = 0;
        for (var i = number.Length - 1; i >= 0; i--)
        {
            if (count > 0 && count % size == 0)
                sb.Insert(0, separator);
            sb.Insert(0, number[i]);
            count++;
        }
        return sb.ToString();
    }

    public override async ValueTask PerformSortAsync(XsltPerformSort instruction)
    {
        IEnumerable<object> items;

        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            // An XDM array/map is a single item to sort, not flattened.
            items = SelectResultItems(result);
        }
        else if (instruction.Content != null)
        {
            // Execute the content body and collect items.
            // Text from xsl:value-of goes to _sequenceAccumulator as individual items (for sorting).
            // Literal result elements serialize to the output buffer as XML strings
            // and are parsed back into individual XDM nodes for sorting.
            var savedAccumulator = _sequenceAccumulator;
            _sequenceAccumulator = new List<object?>();
            var savedCollectText = _collectTextAsSequenceItems;
            var savedElementDepth = _serializingElementDepth;
            _collectTextAsSequenceItems = true;
            _serializingElementDepth = 0; // Reset so perform-sort content starts at "top level"

            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            var savedLogicalStart = _outputLogicalStart;
            _outputLogicalStart = _output.Length;
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            var xmlContent = savedScope.GetWritten();
            savedScope.Dispose();
            _outputLogicalStart = savedLogicalStart;
            _collectTextAsSequenceItems = savedCollectText;
            _serializingElementDepth = savedElementDepth;

            var collected = new List<object>();

            // Add any xsl:sequence items first
            if (_sequenceAccumulator.Count > 0)
            {
                foreach (var item in _sequenceAccumulator)
                    if (item != null)
                        collected.Add(item);
            }

            // Parse serialized literal result elements into XDM nodes
            if (!string.IsNullOrEmpty(xmlContent) && _nodeStore != null)
            {
                try
                {
                    // Stream-parse rather than allocating a full XmlDocument.
                    var settings = new System.Xml.XmlReaderSettings
                    {
                        DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                        IgnoreWhitespace = false,
                        IgnoreComments = false,
                        IgnoreProcessingInstructions = false,
                    };
                    using var stringReader = new System.IO.StringReader($"<_sort_root_>{xmlContent}</_sort_root_>");
                    using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                    var parsedChildren = new List<object?>();
                    ReadAsBodyChunkChildren(reader, parsedChildren);
                    foreach (var child in parsedChildren)
                        if (child != null)
                            collected.Add(child);
                }
                catch (System.Xml.XmlException)
                {
                    // If parsing fails, just output as-is
                }
            }

            _sequenceAccumulator = savedAccumulator;
            items = collected;
        }
        else
        {
            items = [];
        }

        var sorted = await SortNodesAsync(items, instruction.Sorts).ConfigureAwait(false);

        // If sequence accumulator is active (e.g., inside a function body or xsl:value-of),
        // add items individually to preserve them as a sequence for separator handling
        if (_sequenceAccumulator != null)
        {
            foreach (var item in sorted)
                AppendToSeqAccumulator(item);
        }
        else
        {
            foreach (var item in sorted)
            {
                if (item is string s)
                {
                    // Sorted string items are atomic values — need §5.7.2 space separator
                    if (_lastResultWasAtomic && _attributeContentDepth == 0)
                        WriteText(_itemSeparatorOverride ?? " ", false);
                    WriteText(s, false);
                    _lastResultWasAtomic = true;
                }
                else
                {
                    SerializeResult(item);
                }
            }
        }
    }

    public override async ValueTask AnalyzeStringAsync(XsltAnalyzeString instruction)
    {
        var selectResult = await EvaluateAsync(instruction.Select).ConfigureAwait(false);

        // XPTY0004: select must evaluate to a single xs:string (or promotable: xs:anyURI, xs:untypedAtomic)
        // After atomization, numeric/boolean/date types are not promotable to xs:string.
        // Nodes are accepted (they atomize to xs:untypedAtomic which is promotable).
        if (selectResult is IList<object?> seq)
        {
            if (seq.Count > 1)
                throw Error("XPTY0004: The select expression of xsl:analyze-string must return a single xs:string value, got a sequence of " + seq.Count + " items");
            selectResult = seq.Count == 1 ? seq[0] : null;
        }
        if (selectResult is int or long or double or float or decimal or bool
            or DateTimeOffset or DateOnly or TimeOnly or TimeSpan or byte or short)
            throw Error("XPTY0004: The select expression of xsl:analyze-string must return a single xs:string value, got " + selectResult!.GetType().Name);

        var input = StringValueOf(selectResult);
        var pattern = await EvaluateAvtAsync(instruction.Regex).ConfigureAwait(false);
        var flags = instruction.Flags != null
            ? await EvaluateAvtAsync(instruction.Flags).ConfigureAwait(false)
            : "";

        // XTDE1145: Validate flags before processing
        foreach (var ch in flags)
        {
            if (ch is not ('s' or 'm' or 'i' or 'x' or 'q'))
                throw Error($"XTDE1145: Invalid flag '{ch}' in xsl:analyze-string flags attribute. Valid flags are: s, m, i, x, q");
        }

        var regexOptions = System.Text.RegularExpressions.RegexOptions.None;
        if (flags.Contains('i', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.IgnoreCase;
        if (flags.Contains('m', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.Multiline;
        if (flags.Contains('s', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.Singleline;
        if (flags.Contains('x', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.IgnorePatternWhitespace;

        // 'q' flag: treat pattern as literal string (no regex metacharacters)
        if (flags.Contains('q', StringComparison.Ordinal))
            pattern = System.Text.RegularExpressions.Regex.Escape(pattern);
        else
        {
            PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ValidateXsdRegex(pattern);
            pattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ConvertXPathPatternToNet(pattern);
        }
        pattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ConvertXsdEscapesToNet(pattern);
        if (!flags.Contains('m', StringComparison.Ordinal))
            pattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.FixDollarAnchor(pattern);
        pattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.FixDotForSurrogatePairs(pattern);

        var regex = new System.Text.RegularExpressions.Regex(pattern, regexOptions);

        // First pass: collect all matches to compute total substring count for position()/last()
        var matches = new List<System.Text.RegularExpressions.Match>();
        for (var m = regex.Match(input); m.Success; m = m.NextMatch())
            matches.Add(m);

        // Count total substrings: non-matching gaps + matching + possible trailing non-matching
        int totalSubstrings = 0;
        {
            int idx = 0;
            foreach (var m in matches)
            {
                if (m.Index > idx) totalSubstrings++; // non-matching before
                totalSubstrings++; // matching
                idx = m.Index + m.Length;
            }
            if (idx < input.Length) totalSubstrings++; // trailing non-matching
        }

        var lastIndex = 0;
        var position = 0;

        foreach (var match in matches)
        {
            // Non-matching substring before this match
            if (match.Index > lastIndex && instruction.NonMatchingSubstring != null)
            {
                position++;
                var nonMatching = input[lastIndex..match.Index];
                PushContextItem(nonMatching, position, totalSubstrings);
                PushCurrentItem(nonMatching);
                try
                {
                    await instruction.NonMatchingSubstring.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    PopCurrentItem();
                    PopContextItem();
                }
            }
            else if (match.Index > lastIndex)
            {
                position++; // count the non-matching substring even if no handler
            }

            // Matching substring
            position++;
            if (instruction.MatchingSubstring != null)
            {
                PushContextItem(match.Value, position, totalSubstrings);
                PushCurrentItem(match.Value);
                PushScope();
                // Set regex-group() function context — store the Match for the regex-group() function
                SetVariable(new QName(NamespaceId.None, "regex-groups"), match);
                for (var i = 0; i < match.Groups.Count; i++)
                {
                    SetVariable(new QName(NamespaceId.None, $"regex-group-{i}"), match.Groups[i].Value);
                }

                try
                {
                    await instruction.MatchingSubstring.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    PopScope();
                    PopCurrentItem();
                    PopContextItem();
                }
            }

            lastIndex = match.Index + match.Length;
        }

        // Trailing non-matching substring
        if (lastIndex < input.Length && instruction.NonMatchingSubstring != null)
        {
            position++;
            var nonMatching = input[lastIndex..];
            PushContextItem(nonMatching, position, totalSubstrings);
            PushCurrentItem(nonMatching);
            try
            {
                await instruction.NonMatchingSubstring.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                PopCurrentItem();
                PopContextItem();
            }
        }
    }

    public override void Break(XsltBreak instruction)
    {
        // Execute break's content/select before throwing — the BreakException signals
        // IterateAsync to skip on-completion. The select value contributes to the
        // iterate's result, mirroring xsl:sequence semantics: route through the
        // sequence accumulator when active so node identity / typed values survive
        // the iteration boundary (e.g. an iterate inside `as="element()?"` that
        // breaks with `select="."` must return the element, not its string value).
        // Found while transpiling Docbook xform-locale.xsl: fp:lookup-localization-template
        // returned the matched l:template element via xsl:break, but Break wrote its
        // string-value to the output buffer, so the function ended up returning a
        // whitespace string instead of the element.
        if (instruction.Select != null)
        {
            var result = EvaluateAsync(instruction.Select).AsTask().GetAwaiter().GetResult();
            if (result != null)
            {
                if (_sequenceAccumulator != null)
                {
                    if (result is object?[] arr)
                    {
                        foreach (var item in arr)
                            AppendToSeqAccumulator(item);
                    }
                    else if (result is System.Collections.IEnumerable enumerable
                        && result is not string && result is not XdmNode
                        && result is not IDictionary<object, object?>)
                    {
                        foreach (var item in enumerable)
                            AppendToSeqAccumulator(item);
                    }
                    else
                    {
                        AppendToSeqAccumulator(result);
                    }
                }
                else
                {
                    SerializeResult(result);
                }
            }
        }
        else if (instruction.Content != null)
        {
            instruction.Content.ExecuteAsync(this).AsTask().GetAwaiter().GetResult();
        }
        throw new BreakException();
    }

    public override void NextIteration(XsltNextIteration instruction)
    {
        throw new NextIterationException { WithParams = instruction.WithParams };
    }

    public override async ValueTask ForkAsync(XsltFork instruction)
    {
        // Streaming-aware sequential execution: prongs execute one at a time.
        // True parallel fork would require thread-safe output handling per prong;
        // keeping sequential for safety while streaming is about input processing.
        foreach (var feg in instruction.ForEachGroups)
        {
            await ForEachGroupAsync(feg).ConfigureAwait(false);
        }

        foreach (var seq in instruction.Sequences)
        {
            await seq.ExecuteAsync(this).ConfigureAwait(false);
        }

        foreach (var rd in instruction.ResultDocuments)
        {
            await ResultDocumentAsync(rd).ConfigureAwait(false);
        }
    }

    public override async ValueTask MergeAsync(XsltMerge instruction)
    {
        // Fast path: all sources are streamable + use for-each-source + select is a
        // single child-axis step. Run the K-way merge over per-URI XmlReader pulls
        // so we never materialize the full input documents.
        if (XsltMergeStreaming.CanStreamMerge(instruction))
        {
            await MergeAsyncStreaming(instruction).ConfigureAwait(false);
            return;
        }

        // Step 1: Collect items from each merge source
        var sourceSequences = new List<List<object>>();

        foreach (var source in instruction.Sources)
        {
            var allItems = new List<object>();

            if (source.ForEachItem != null)
            {
                // Evaluate for-each-item to get a sequence of items
                var forEachResult = await EvaluateAsync(source.ForEachItem).ConfigureAwait(false);
                var forEachItems = SelectResultItems(forEachResult).ToList();

                foreach (var item in forEachItems)
                {
                    PushContextItem(item, 1, 1);
                    try
                    {
                        var selected = await EvaluateAsync(source.Select).ConfigureAwait(false);
                        AddToList(allItems, selected);
                    }
                    finally
                    {
                        PopContextItem();
                    }
                }
            }
            else if (source.ForEachSource != null)
            {
                // Evaluate for-each-source to get URIs, then load each as a document
                var forEachResult = await EvaluateAsync(source.ForEachSource).ConfigureAwait(false);
                var forEachItems = SelectResultItems(forEachResult).ToList();

                foreach (var item in forEachItems)
                {
                    // for-each-source evaluates to URI strings; load each via doc()
                    object contextItem = item;
                    if (item is string uri)
                    {
                        var doc = _policyResolver?.ResolveDocument(uri) ?? _documentResolver.ResolveDocument(uri);
                        if (doc == null)
                            continue;
                        contextItem = doc;

                        // Compute specified accumulators on the merge source document
                        if (source.UseAccumulators.Count > 0 && _nodeStore != null)
                        {
                            var accumulators = new List<XsltAccumulator>();
                            foreach (var accName in source.UseAccumulators)
                            {
                                if (_stylesheet.Accumulators.TryGetValue(accName, out var acc))
                                    accumulators.Add(acc);
                            }
                            if (accumulators.Count > 0)
                                await PreComputeAccumulatorsAsync(doc, accumulators, _nodeStore).ConfigureAwait(false);
                        }
                    }

                    PushContextItem(contextItem, 1, 1);
                    try
                    {
                        var selected = await EvaluateAsync(source.Select).ConfigureAwait(false);
                        AddToList(allItems, selected);
                    }
                    finally
                    {
                        PopContextItem();
                    }
                }
            }
            else
            {
                // No for-each-item: evaluate select in current context
                var selected = await EvaluateAsync(source.Select).ConfigureAwait(false);
                AddToList(allItems, selected);
            }

            // Step 2: Sort items by merge keys if needed
            // sort-before-merge="yes" explicitly requests sorting.
            // Also sort when for-each-item/for-each-source is used: per spec these create
            // separate sub-sources in the K-way merge, but we concatenate them into one sequence,
            // so sorting is needed to produce correct merge results.
            var needsSort = source.SortBeforeMerge ||
                            source.ForEachItem != null || source.ForEachSource != null;
            if (needsSort && source.MergeKeys.Count > 0)
            {
                allItems = await SortByMergeKeysAsync(allItems, source.MergeKeys).ConfigureAwait(false);
            }

            sourceSequences.Add(allItems);
        }

        // Step 3: K-way merge
        // Pre-compute merge key values for all items in all sources
        var mergeKeysTemplate = instruction.Sources.Count > 0 ? instruction.Sources[0].MergeKeys : new List<XsltMergeKey>();

        // Resolve key orders and data types once (from first source)
        var keyOrders = new List<string>();
        var keyDataTypes = new List<string>();
        foreach (var mk in mergeKeysTemplate)
        {
            var order = mk.Order != null ? await EvaluateAvtAsync(mk.Order).ConfigureAwait(false) : "ascending";
            if (order != "ascending" && order != "descending")
                throw Error($"XTDE2210: Invalid value '{order}' for order attribute on xsl:merge-key (must be 'ascending' or 'descending')");
            keyOrders.Add(order);
            var dataType = mk.DataType != null ? await EvaluateAvtAsync(mk.DataType).ConfigureAwait(false) : "text";
            if (dataType != "text" && dataType != "number")
                throw Error($"XTDE2210: Invalid value '{dataType}' for data-type attribute on xsl:merge-key (must be 'text' or 'number')");
            keyDataTypes.Add(dataType);
        }

        // XTDE2210: Validate that merge-key order/data-type agree across all sources
        for (var si = 1; si < instruction.Sources.Count; si++)
        {
            var sourceKeys2 = instruction.Sources[si].MergeKeys;
            for (var ki = 0; ki < sourceKeys2.Count && ki < keyOrders.Count; ki++)
            {
                var mk2 = sourceKeys2[ki];
                var order2 = mk2.Order != null ? await EvaluateAvtAsync(mk2.Order).ConfigureAwait(false) : "ascending";
                if (order2 != keyOrders[ki])
                    throw Error($"XTDE2210: Merge key order differs across sources: '{keyOrders[ki]}' vs '{order2}'");
                var dt2 = mk2.DataType != null ? await EvaluateAvtAsync(mk2.DataType).ConfigureAwait(false) : "text";
                if (dt2 != keyDataTypes[ki])
                    throw Error($"XTDE2210: Merge key data-type differs across sources: '{keyDataTypes[ki]}' vs '{dt2}'");
            }
        }

        // Compute keys for each item in each source — keep raw typed values
        var sourceKeys = new List<List<List<object?>>>();
        for (var si = 0; si < sourceSequences.Count; si++)
        {
            var keysForSource = new List<List<object?>>();
            var currentSourceKeys = si < instruction.Sources.Count ? instruction.Sources[si].MergeKeys : mergeKeysTemplate;
            foreach (var item in sourceSequences[si])
            {
                PushContextItem(item, 1, 1);
                try
                {
                    var itemKeys = new List<object?>();
                    // XTDE1480: Merge key evaluation is in temporary output state
                    _temporaryOutputDepth++;
                    try
                    {
                        foreach (var mk in currentSourceKeys)
                        {
                            object? keyVal;
                            if (mk.Select != null)
                            {
                                keyVal = await EvaluateAsync(mk.Select).ConfigureAwait(false);
                                // XTTE1020: Merge key must be a singleton
                                if (keyVal is object?[] keyArr)
                                {
                                    if (keyArr.Length > 1)
                                        throw Error("XTTE1020: The value of a merge key must be a single atomic value");
                                    keyVal = keyArr.Length == 1 ? keyArr[0] : null;
                                }
                                else if (keyVal is IEnumerable<object> keySeq && keyVal is not string && keyVal is not Xdm.Nodes.XdmNode)
                                {
                                    var keyList = keySeq.ToList();
                                    if (keyList.Count > 1)
                                        throw Error("XTTE1020: The value of a merge key must be a single atomic value");
                                    keyVal = keyList.Count == 1 ? keyList[0] : null;
                                }
                            }
                            else if (mk.Content != null)
                            {
                                BeginSequenceCollection();
                                await mk.Content.ExecuteAsync(this).ConfigureAwait(false);
                                var items = EndSequenceCollection();
                                keyVal = items.Count == 1 ? items[0] : items.Count == 0 ? null : items;
                            }
                            else
                                keyVal = null;
                            itemKeys.Add(keyVal);
                        }
                    }
                    finally { _temporaryOutputDepth--; }
                    keysForSource.Add(itemKeys);
                }
                finally
                {
                    PopContextItem();
                }
            }
            // XTDE2220: Verify input is correctly sorted (unless sort-before-merge)
            // Only check when no for-each-item/for-each-source — those create independent sub-sequences
            var currentSource = si < instruction.Sources.Count ? instruction.Sources[si] : null;
            if (currentSource != null && !currentSource.SortBeforeMerge &&
                currentSource.ForEachItem == null && currentSource.ForEachSource == null &&
                keysForSource.Count > 1)
            {
                for (var ki = 1; ki < keysForSource.Count; ki++)
                {
                    var cmp = CompareMergeKeys(keysForSource[ki - 1], keysForSource[ki], keyOrders, keyDataTypes);
                    if (cmp > 0)
                        throw Error($"XTDE2220: Merge source '{currentSource.Name ?? ("source " + si)}' is not correctly sorted at item {ki + 1}");
                }
            }

            sourceKeys.Add(keysForSource);
        }

        // K-way merge using indices
        var indices = new int[sourceSequences.Count];
        var mergedGroups = new List<(List<object?> Key, List<(object Item, int SourceIndex)> Items)>();

        while (true)
        {
            // Find the source with the smallest current key
            int bestSource = -1;
            List<object?>? bestKey = null;

            for (var si = 0; si < sourceSequences.Count; si++)
            {
                if (indices[si] >= sourceSequences[si].Count)
                    continue;
                var currentKey = sourceKeys[si][indices[si]];

                if (bestKey == null || CompareMergeKeys(currentKey, bestKey, keyOrders, keyDataTypes) < 0)
                {
                    bestSource = si;
                    bestKey = currentKey;
                }
            }

            if (bestSource == -1)
                break; // All sources exhausted

            // Collect all items with equal keys across all sources, tracking source index
            var group = new List<(object Item, int SourceIndex)>();
            for (var si = 0; si < sourceSequences.Count; si++)
            {
                while (indices[si] < sourceSequences[si].Count &&
                       CompareMergeKeys(sourceKeys[si][indices[si]], bestKey!, keyOrders, keyDataTypes) == 0)
                {
                    group.Add((sourceSequences[si][indices[si]], si));
                    indices[si]++;
                }
            }

            mergedGroups.Add((bestKey!, group));
        }

        // Build source name-to-index map for named merge groups
        var sourceNames = new Dictionary<string, int>();
        for (var si = 0; si < instruction.Sources.Count; si++)
        {
            if (instruction.Sources[si].Name != null)
                sourceNames[instruction.Sources[si].Name!] = si;
        }

        // Step 4: Execute merge-action for each group
        var mergeGroupCount = mergedGroups.Count;
        var mergeGroupPosition = 0;
        foreach (var (key, taggedItems) in mergedGroups)
        {
            mergeGroupPosition++;
            var items = taggedItems.Select(t => t.Item).ToList();
            PushScope();
            SetVariable(new QName(NamespaceId.None, "current-merge-group"), items);
            // Set merge key — stringify for current-merge-key() function
            var mergeKeyValue = key.Count == 1
                ? (object)StringValueOf(key[0])
                : key.Select(k => StringValueOf(k)).ToArray();
            SetVariable(new QName(NamespaceId.None, "current-merge-key"), mergeKeyValue);

            // Store per-source groups for current-merge-group('name')
            foreach (var (name, idx) in sourceNames)
            {
                var sourceItems = taggedItems.Where(t => t.SourceIndex == idx).Select(t => t.Item).ToList();
                SetVariable(new QName(NamespaceId.None, $"current-merge-group:{name}"), sourceItems);
            }

            // Set context item to the first item in the group
            PushContextItem(items[0], mergeGroupPosition, mergeGroupCount);
            try
            {
                await instruction.Action.ExecuteAsync(this).ConfigureAwait(false);
            }
            finally
            {
                PopContextItem();
                PopScope();
            }
        }
    }

    private static void AddToList(List<object> list, object? value)
    {
        switch (value)
        {
            case null:
                break;
            case IEnumerable<object> seq:
                list.AddRange(seq);
                break;
            default:
                list.Add(value);
                break;
        }
    }

    private async Task<List<object>> SortByMergeKeysAsync(List<object> items, List<XsltMergeKey> mergeKeys)
    {
        // Resolve key orders and data types
        var orders = new List<string>();
        var dataTypes = new List<string>();
        foreach (var mk in mergeKeys)
        {
            var order = mk.Order != null ? await EvaluateAvtAsync(mk.Order).ConfigureAwait(false) : "ascending";
            if (order != "ascending" && order != "descending")
                throw Error($"XTDE2210: Invalid value '{order}' for order attribute on xsl:merge-key (must be 'ascending' or 'descending')");
            orders.Add(order);
            var dataType = mk.DataType != null ? await EvaluateAvtAsync(mk.DataType).ConfigureAwait(false) : "text";
            if (dataType != "text" && dataType != "number")
                throw Error($"XTDE2210: Invalid value '{dataType}' for data-type attribute on xsl:merge-key (must be 'text' or 'number')");
            dataTypes.Add(dataType);
        }

        // Compute keys for each item — keep raw typed values
        var keyed = new List<(object Item, List<object?> Keys)>();
        foreach (var item in items)
        {
            PushContextItem(item, 1, 1);
            try
            {
                var itemKeys = new List<object?>();
                _temporaryOutputDepth++;
                try
                {
                    foreach (var mk in mergeKeys)
                    {
                        object? keyVal;
                        if (mk.Select != null)
                            keyVal = await EvaluateAsync(mk.Select).ConfigureAwait(false);
                        else if (mk.Content != null)
                        {
                            BeginSequenceCollection();
                            await mk.Content.ExecuteAsync(this).ConfigureAwait(false);
                            var collected = EndSequenceCollection();
                            keyVal = collected.Count == 1 ? collected[0] : collected.Count == 0 ? null : collected;
                        }
                        else
                            keyVal = null;
                        itemKeys.Add(keyVal);
                    }
                }
                finally { _temporaryOutputDepth--; }
                keyed.Add((item, itemKeys));
            }
            finally
            {
                PopContextItem();
            }
        }

        keyed.Sort((a, b) => CompareMergeKeys(a.Keys, b.Keys, orders, dataTypes));

        return keyed.Select(k => k.Item).ToList();
    }

    private static int CompareMergeKeys(List<object?> a, List<object?> b, List<string> orders, List<string> dataTypes)
    {
        for (var i = 0; i < a.Count && i < b.Count && i < orders.Count; i++)
        {
            int cmp;
            var dataType = i < dataTypes.Count ? dataTypes[i] : "text";
            cmp = CompareKeyValues(a[i], b[i], dataType);
            if (orders[i] == "descending")
                cmp = -cmp;
            if (cmp != 0)
                return cmp;
        }
        return 0;
    }

    private static int CompareKeyValues(object? a, object? b, string dataType)
    {
        if (a is null && b is null)
            return 0;
        if (a is null)
            return -1;
        if (b is null)
            return 1;

        // For data-type="number", always compare as numeric
        if (dataType == "number")
        {
            var aNum = ToDouble(a);
            var bNum = ToDouble(b);
            if (!double.IsNaN(aNum) && !double.IsNaN(bNum))
                return aNum.CompareTo(bNum);
            if (!double.IsNaN(aNum))
                return -1;
            if (!double.IsNaN(bNum))
                return 1;
            return 0; // both NaN — maintain document order
        }

        // Use typed comparison based on actual value types
        if (a is long la && b is long lb)
            return la.CompareTo(lb);
        if (a is int ia && b is int ib)
            return ia.CompareTo(ib);
        if (IsMergeKeyNumeric(a) && IsMergeKeyNumeric(b))
            return ToDouble(a).CompareTo(ToDouble(b));
        if (a is XsDateTime xdta && b is XsDateTime xdtb)
            return xdta.CompareTo(xdtb);
        if (a is XsDate xda && b is XsDate xdb)
            return xda.CompareTo(xdb);
        if (a is XsTime xta && b is XsTime xtb)
            return xta.CompareTo(xtb);
        if (a is DateTimeOffset dtoa && b is DateTimeOffset dtob)
            return dtoa.CompareTo(dtob);
        if (a is decimal da && b is decimal db)
            return da.CompareTo(db);

        // XTTE2230: Check for incomparable types before falling back to string
        if (IsMergeKeyNumeric(a) != IsMergeKeyNumeric(b) && a is not string && b is not string)
            throw new XsltException($"XTTE2230: Merge key values are not comparable: {a.GetType().Name} vs {b.GetType().Name}");
        if ((a is TimeSpan or DayTimeDuration or YearMonthDuration) && b is not TimeSpan and not DayTimeDuration and not YearMonthDuration)
            throw new XsltException($"XTTE2230: Merge key values are not comparable: {a.GetType().Name} vs {b.GetType().Name}");
        if ((b is TimeSpan or DayTimeDuration or YearMonthDuration) && a is not TimeSpan and not DayTimeDuration and not YearMonthDuration)
            throw new XsltException($"XTTE2230: Merge key values are not comparable: {a.GetType().Name} vs {b.GetType().Name}");
        // DateTime/Date/Time vs non-DateTime types
        if ((a is XsDateTime or XsDate or XsTime or DateTimeOffset) && b is not XsDateTime and not XsDate and not XsTime and not DateTimeOffset)
            throw new XsltException($"XTTE2230: Merge key values are not comparable: {a.GetType().Name} vs {b.GetType().Name}");
        if ((b is XsDateTime or XsDate or XsTime or DateTimeOffset) && a is not XsDateTime and not XsDate and not XsTime and not DateTimeOffset)
            throw new XsltException($"XTTE2230: Merge key values are not comparable: {a.GetType().Name} vs {b.GetType().Name}");

        // Fall back to string comparison — atomize XDM nodes so attribute/element
        // selects produce string values (not "PhoenixmlDb.Xdm.Nodes.XdmAttribute").
        var aStr = AtomizeMergeKeyToString(a);
        var bStr = AtomizeMergeKeyToString(b);
        return string.Compare(aStr, bStr, StringComparison.Ordinal);
    }

    private static bool IsMergeKeyNumeric(object? v) => v is long or int or double or float or decimal;

    private static string AtomizeMergeKeyToString(object v) => v switch
    {
        Xdm.Nodes.XdmNode n => n.StringValue,
        XsUntypedAtomic ua => ua.Value,
        _ => v.ToString() ?? string.Empty
    };

    private static double ToDouble(object? v)
    {
        // Merge keys are typically XDM atomic values, but a path-step select
        // (e.g. select="@n") delivers a node — atomize before parsing or every
        // node compares equal under data-type="number" (NaN==NaN==no-op),
        // collapsing the K-way merge into a single group.
        switch (v)
        {
            case long l: return l;
            case int i: return i;
            case double d: return d;
            case float f: return f;
            case decimal m: return (double)m;
            case string s when TryParseDouble(s, out var sr): return sr;
            case Xdm.Nodes.XdmNode n when TryParseDouble(n.StringValue, out var nr): return nr;
            case XsUntypedAtomic ua when TryParseDouble(ua.Value, out var uar): return uar;
            default: return double.NaN;
        }
    }

    private static bool TryParseDouble(string s, out double r) =>
        double.TryParse(s, System.Globalization.NumberStyles.Float,
            System.Globalization.CultureInfo.InvariantCulture, out r);

    public override async ValueTask CreateMapAsync(XsltMap instruction)
    {
        var map = new OrderedXdmMap(EqualityComparer<object>.Default);
        _mapBuildStack.Push(map);

        // XTTE3375: Content of xsl:map must produce only map entries.
        // Monitor for stray items (non-map-entry content) by intercepting the sequence accumulator.
        var savedAccumulator = _sequenceAccumulator;
        var strayItems = new List<object?>();
        _sequenceAccumulator = strayItems;
        try
        {
            if (instruction.Content != null)
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            _sequenceAccumulator = savedAccumulator;
            _mapBuildStack.Pop();
        }

        // Content may produce maps (via xsl:sequence, xsl:apply-templates, etc.) — merge them.
        // XTTE3375: Only non-map items are errors. Whitespace-only text nodes (the source
        // formatting between `<xsl:map-entry>` siblings, e.g. `\n  `) are insignificant per
        // XSLT 3.0 §6.2 and must not trigger XTTE3375 — they'd be stripped during stylesheet
        // parsing, but our engine collects literal-text-element output to the accumulator
        // which sometimes leaks them. Treat empty-or-whitespace strings as no-ops here.
        foreach (var item in strayItems)
        {
            if (item is IDictionary<object, object?> mapItem)
            {
                foreach (var kvp in mapItem)
                {
                    if (map.ContainsKey(kvp.Key))
                        throw Error($"XTDE3365: Duplicate key '{kvp.Key}' in xsl:map");
                    map[kvp.Key] = kvp.Value;
                }
            }
            else if (item is string s && string.IsNullOrWhiteSpace(s))
            {
                // Insignificant whitespace text from source formatting — ignore.
            }
            else if (item is Xdm.TextNodeItem tni && string.IsNullOrWhiteSpace(tni.Value))
            {
                // Same, but already wrapped as a text-node item.
            }
            else if (item != null)
                throw Error($"XTTE3375: The content of xsl:map must consist entirely of xsl:map-entry instructions; found non-map content (got {item.GetType().Name}: {item})");
        }

        // Add the completed map to the output
        if (_sequenceAccumulator != null)
            AppendToSeqAccumulator(map);
        else if (_outputNsScopes.Count > 0)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a map");
        else
        {
            // Top-level map: serialize as JSON text per XSLT 3.0 §20 adaptive/JSON output
            WriteText(XsltTransformEngine.SerializeItemAsJson(map, true), false);
        }
    }

    public override async ValueTask CreateMapEntryAsync(XsltMapEntry instruction)
    {
        // Evaluate the key (xsl:map-entry key is an XPath expression, not an AVT)
        var keyVal = await EvaluateAsync(instruction.Key).ConfigureAwait(false);
        object key = keyVal ?? throw Error("XTDE3365: Map entry key must not be empty");

        // Evaluate the value
        object? value = null;
        if (instruction.Select != null)
        {
            value = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
        }
        else if (instruction.Content != null)
        {
            var savedAccum = _sequenceAccumulator;
            _sequenceAccumulator = new List<object?>();
            // Save/clear _output so text content is captured for the map entry value
            var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
            _temporaryOutputDepth++;
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                var items = _sequenceAccumulator;
                if (items.Count == 0 && savedScope.WrittenLength > 0)
                {
                    // Text-only content — use the text as the value
                    value = savedScope.GetWritten();
                }
                else
                {
                    value = items.Count switch
                    {
                        0 => null,
                        1 => items[0],
                        _ => items.ToArray()
                    };
                }
            }
            finally
            {
                _temporaryOutputDepth--;
                savedScope.Dispose();
                _sequenceAccumulator = savedAccum;
            }
        }

        if (_mapBuildStack.Count > 0)
        {
            // Inside xsl:map — add entry to the map being built
            var map = _mapBuildStack.Peek();
            // XTDE3365: duplicate key
            if (map.ContainsKey(key))
                throw Error($"XTDE3365: Duplicate key '{key}' in xsl:map");
            map[key] = value;
        }
        else
        {
            // Standalone xsl:map-entry — produce a singleton map
            var singletonMap = new OrderedXdmMap(EqualityComparer<object>.Default) { [key] = value };
            if (_sequenceAccumulator != null)
                AppendToSeqAccumulator(singletonMap);
            else
                OutputValue(singletonMap);
        }
    }

    public override async ValueTask CreateArrayAsync(XsltArray instruction)
    {
        var array = new List<object?>();
        _arrayBuildStack.Push(array);
        // Per XSLT 4.0 §22, every top-level item produced by the body becomes a member
        // of the new array. Redirect the sequence accumulator to `array` so items
        // emitted by xsl:map / xsl:sequence / atomic value-of inside the body land
        // directly as array members. Without this, those items leaked to whatever
        // outer accumulator was active and the array itself ended up empty (or with
        // only xsl:array-member contributions). Reported by Martin Honnen via the
        // streamed-JSON repro: the wrapping xsl:map-entry's value gathered the inner
        // maps plus an empty trailing [].
        var savedAccumulator = _sequenceAccumulator;
        _sequenceAccumulator = array;
        try
        {
            if (instruction.Content != null)
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            _sequenceAccumulator = savedAccumulator;
            _arrayBuildStack.Pop();
        }

        // Add the completed array to the output
        if (_sequenceAccumulator != null)
            AppendToSeqAccumulator(array.ToArray());
        // When no sequence accumulator, array is being serialized directly —
        // only valid with adaptive/json output methods. Silently ignore for now.
    }

    public override async ValueTask CreateArrayMemberAsync(XsltArrayMember instruction)
    {
        if (_arrayBuildStack.Count == 0)
            throw Error("XTDE0450: xsl:array-member must appear within xsl:array");

        var array = _arrayBuildStack.Peek();

        if (instruction.Select != null)
        {
            var value = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            array.Add(value);
        }
        else if (instruction.Content != null)
        {
            var savedAccum = _sequenceAccumulator;
            _sequenceAccumulator = new List<object?>();
            try
            {
                await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                var items = _sequenceAccumulator;
                var member = items.Count switch
                {
                    0 => (object?)null,
                    1 => items[0],
                    _ => items.ToArray()
                };
                array.Add(member);
            }
            finally
            {
                _sequenceAccumulator = savedAccum;
            }
        }
    }

    public override async ValueTask CreateRecordAsync(Ast.XsltRecord instruction)
    {
        // xsl:record produces an XDM map with string keys from xsl:entry children.
        // Each entry has a name (string key) and a value (from select or sequence constructor body).
        var map = new OrderedXdmMap(EqualityComparer<object>.Default);

        foreach (var (name, valueBody) in instruction.Entries)
        {
            // Evaluate the entry's sequence constructor to get the value
            object? value = null;
            if (valueBody != null && valueBody.Instructions.Count > 0)
            {
                var savedAccum = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();
                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                _temporaryOutputDepth++;
                try
                {
                    await valueBody.ExecuteAsync(this).ConfigureAwait(false);
                    var items = _sequenceAccumulator;
                    if (items.Count == 0 && savedScope.WrittenLength > 0)
                    {
                        value = savedScope.GetWritten();
                    }
                    else
                    {
                        value = items.Count switch
                        {
                            0 => null,
                            1 => items[0],
                            _ => items.ToArray()
                        };
                    }
                }
                finally
                {
                    _temporaryOutputDepth--;
                    savedScope.Dispose();
                    _sequenceAccumulator = savedAccum;
                }
            }

            if (map.ContainsKey(name))
                throw Error($"XTDE3365: Duplicate key '{name}' in xsl:record");
            map[name] = value;
        }

        // Add the completed map to the output (same as xsl:map)
        if (_sequenceAccumulator != null)
            AppendToSeqAccumulator(map);
        else if (_outputNsScopes.Count > 0)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a map");
    }

    public override async ValueTask WherePopulatedAsync(XsltWherePopulated instruction)
    {
        // Buffer output and track whether "real" content is produced
        var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
        var savedLogicalStart = _outputLogicalStart;
        _outputLogicalStart = _output.Length;

        // Save collected attributes so where-populated content captures attributes separately.
        // This allows filtering zero-length "insignificant" attributes per XSLT 3.0 §11.4.
        var savedAttrs = _attributeCollecting ? _collectedAttributes!.ToString() : null;
        if (_attributeCollecting)
            _collectedAttributes!.Clear();

        // When the surrounding scope is an `as=` template/function body, xsl:attribute goes
        // to `_sequenceAccumulator` rather than `_collectedAttributes`. Snapshot its length
        // here so we can identify (and filter) accumulator items produced inside this body.
        var accumStartCount = _sequenceAccumulator?.Count ?? 0;
        var capturePositionsStartCount = _currentAsBodyCapture?.Positions.Count ?? 0;

        _wherePopulatedDepth++;
        BeginPopulatedTracking();
        try
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            _wherePopulatedDepth--;
        }
        var trackingMarked = EndPopulatedTracking();

        // Filter accumulator items added during the body: drop XdmAttributes whose value is a
        // zero-length string (insignificant per §11.4). Other items (elements, text, etc.) are
        // preserved unconditionally — `where-populated` only filters at the attribute level.
        if (_sequenceAccumulator != null && _sequenceAccumulator.Count > accumStartCount)
        {
            var addedRange = _sequenceAccumulator.GetRange(accumStartCount, _sequenceAccumulator.Count - accumStartCount);
            _sequenceAccumulator.RemoveRange(accumStartCount, _sequenceAccumulator.Count - accumStartCount);
            // Drop the matching range of recorded positions when the active accumulator
            // is the as= body's capture — they're about to be re-added (or filtered out)
            // along with their items by the loop below.
            if (_currentAsBodyCapture is { } cap
                && ReferenceEquals(_sequenceAccumulator, cap.Accumulator)
                && cap.Positions.Count > capturePositionsStartCount)
                cap.Positions.RemoveRange(capturePositionsStartCount, cap.Positions.Count - capturePositionsStartCount);
            foreach (var item in addedRange)
            {
                if (item is XdmAttribute attr && string.IsNullOrEmpty(attr.Value))
                    continue;
                AppendToSeqAccumulator(item);
            }
        }

        var result = savedScope.GetWritten();
        savedScope.Dispose();
        _outputLogicalStart = savedLogicalStart;

        // Collect and filter attributes produced inside where-populated
        string? wpAttrs = null;
        if (_attributeCollecting)
        {
            var rawAttrs = _collectedAttributes!.ToString();
            _collectedAttributes!.Clear();
            _collectedAttributes.Append(savedAttrs);

            // Filter out zero-length attribute values (insignificant per spec)
            wpAttrs = FilterInsignificantAttributes(rawAttrs);
        }

        if (result.Length == 0 && string.IsNullOrEmpty(wpAttrs))
            return;

        // Per XSLT 3.0 §11.4: filter out insignificant top-level element children individually.
        // An element is insignificant if it has no children (or only zero-length text nodes).
        // Attributes alone do not make an element significant.
        var filtered = result.Length > 0 ? FilterWherePopulatedContent(result) : "";

        // Apply surviving attributes first, then element content
        if (!string.IsNullOrEmpty(wpAttrs))
        {
            _collectedAttributes!.Append(wpAttrs);
            MarkContentProduced();
        }
        if (filtered.Length > 0)
        {
            _output.Append(filtered);
            MarkContentProduced();
        }
        else if (trackingMarked && result.Length > 0)
        {
            // The filter removed everything, but content-producing instructions (like xsl:document)
            // explicitly marked content as produced. This handles cases where serialized output
            // loses node type info (e.g., a document node containing <e/> serializes as just <e/>,
            // which the filter sees as an insignificant empty element, but the document node itself
            // is significant because it has children).
            _output.Append(result);
            MarkContentProduced();
        }
    }

    /// <summary>
    /// Filters attributes with zero-length values (insignificant per XSLT 3.0 §11.4 where-populated).
    /// Among surviving attributes with the same name, last-wins applies.
    /// An attribute overridden by a zero-length attribute is preserved (the zero-length one is removed).
    /// </summary>
    private static string? FilterInsignificantAttributes(string rawAttrs)
    {
        if (string.IsNullOrEmpty(rawAttrs))
            return null;

        // Parse all attributes preserving order
        var all = new List<(string name, string value)>();
        var pos = 0;
        while (pos < rawAttrs.Length)
        {
            while (pos < rawAttrs.Length && char.IsWhiteSpace(rawAttrs[pos]))
                pos++;
            if (pos >= rawAttrs.Length) break;
            var nameStart = pos;
            while (pos < rawAttrs.Length && rawAttrs[pos] != '=')
                pos++;
            if (pos >= rawAttrs.Length) break;
            var name = rawAttrs[nameStart..pos].Trim();
            pos++; // skip '='
            while (pos < rawAttrs.Length && char.IsWhiteSpace(rawAttrs[pos]))
                pos++;
            if (pos >= rawAttrs.Length) break;
            var quote = rawAttrs[pos];
            if (quote != '"' && quote != '\'') break;
            pos++;
            var valueStart = pos;
            while (pos < rawAttrs.Length && rawAttrs[pos] != quote)
                pos++;
            var value = rawAttrs[valueStart..pos];
            if (pos < rawAttrs.Length) pos++;
            if (!string.IsNullOrEmpty(name))
                all.Add((name, value));
        }

        // Filter: keep only attributes with non-empty values, last-wins among non-empty
        // Zero-length attributes are insignificant and simply ignored (they do NOT override
        // a previous non-empty value — the insignificant attribute is discarded per spec)
        var surviving = new Dictionary<string, string>();
        foreach (var (name, value) in all)
        {
            if (value.Length > 0)
                surviving[name] = value;
            // Zero-length values are silently ignored
        }

        if (surviving.Count == 0)
            return null;

        var sb = new StringBuilder();
        foreach (var (name, value) in surviving)
        {
            sb.Append(' ');
            sb.Append(name);
            sb.Append("=\"");
            sb.Append(value);
            sb.Append('"');
        }
        return sb.ToString();
    }

    /// <summary>
    /// Filters insignificant top-level elements from where-populated output.
    /// Uses string scanning to preserve original serialization (avoids re-parsing
    /// which can reorder namespace declarations).
    /// </summary>
    private static string FilterWherePopulatedContent(string xml)
    {
        var nodes = ScanWherePopulatedNodes(xml);
        if (nodes == null)
            return xml; // Not parseable as XML fragments; keep as-is

        bool hasInsignificant = false;
        foreach (var (_, _, significant) in nodes)
        {
            if (!significant)
            { hasInsignificant = true; break; }
        }

        if (!hasInsignificant)
            return xml;

        var sb = new StringBuilder();
        foreach (var (start, end, significant) in nodes)
        {
            if (significant)
                sb.Append(xml, start, end - start);
        }
        return sb.ToString();
    }

    /// <summary>
    /// Scans serialized XML content to find top-level node boundaries and significance.
    /// Returns null if scanning fails (content will be kept unchanged).
    /// </summary>
    private static List<(int start, int end, bool significant)>? ScanWherePopulatedNodes(string xml)
    {
        var nodes = new List<(int start, int end, bool significant)>();
        int pos = 0;
        int len = xml.Length;

        while (pos < len)
        {
            if (xml[pos] == '<')
            {
                // Comment: <!-- ... --> — significant only if non-empty content
                if (pos + 3 < len && xml[pos + 1] == '!' && xml[pos + 2] == '-' && xml[pos + 3] == '-')
                {
                    int start = pos;
                    int endIdx = xml.IndexOf("-->", pos + 4, StringComparison.Ordinal);
                    if (endIdx < 0)
                        return null;
                    // Empty comment <!---->: content between <!-- and --> is empty
                    bool hasContent = endIdx > pos + 4;
                    pos = endIdx + 3;
                    nodes.Add((start, pos, hasContent));
                }
                // PI: <?target data?> — significant only if has data after target
                else if (pos + 1 < len && xml[pos + 1] == '?')
                {
                    int start = pos;
                    int endIdx = xml.IndexOf("?>", pos + 2, StringComparison.Ordinal);
                    if (endIdx < 0)
                        return null;
                    // Extract target+data between <? and ?>. PI is insignificant if no data after target.
                    var piContent = xml.AsSpan(pos + 2, endIdx - pos - 2);
                    var spaceIdx = piContent.IndexOf(' ');
                    bool hasData = spaceIdx >= 0 && piContent[(spaceIdx + 1)..].Trim().Length > 0;
                    pos = endIdx + 2;
                    nodes.Add((start, pos, hasData));
                }
                // Closing tag at top level — shouldn't happen but skip
                else if (pos + 1 < len && xml[pos + 1] == '/')
                {
                    int endIdx = xml.IndexOf('>', pos + 2);
                    if (endIdx < 0)
                        return null;
                    pos = endIdx + 1;
                }
                // Element
                else
                {
                    int start = pos;
                    var (endPos, hasContent) = ScanWherePopulatedElement(xml, pos);
                    if (endPos < 0)
                        return null;
                    pos = endPos;
                    nodes.Add((start, pos, hasContent));
                }
            }
            else
            {
                // Text node at top level
                int start = pos;
                while (pos < len && xml[pos] != '<')
                    pos++;
                // Text is significant if non-empty
                nodes.Add((start, pos, pos > start));
            }
        }
        return nodes;
    }

    /// <summary>
    /// Scans a single top-level element from its opening '&lt;' to its closing '&gt;'.
    /// Returns (endPosition, hasSignificantContent).
    /// An element is significant if it has at least one child that is not a zero-length text node.
    /// Element children always count as significant (non-recursive check per spec).
    /// </summary>
    private static (int endPos, bool hasSignificantContent) ScanWherePopulatedElement(string xml, int pos)
    {
        // pos points to '<'
        pos++; // skip '<'

        // Skip element name
        while (pos < xml.Length && xml[pos] != '>' && xml[pos] != '/' && !char.IsWhiteSpace(xml[pos]))
            pos++;

        // Skip attributes
        pos = SkipElementAttributes(xml, pos);
        if (pos >= xml.Length)
            return (-1, false);

        // Self-closing <foo/> — no children → insignificant
        if (xml[pos] == '/' && pos + 1 < xml.Length && xml[pos + 1] == '>')
            return (pos + 2, false);

        // Opening tag ends with '>'
        pos++; // skip '>'

        // Scan content for matching close tag and check for significant children
        int depth = 1;
        bool hasSignificantChild = false;

        while (pos < xml.Length && depth > 0)
        {
            if (xml[pos] == '<')
            {
                if (pos + 1 < xml.Length && xml[pos + 1] == '/')
                {
                    // Closing tag
                    depth--;
                    if (depth == 0)
                    {
                        int endIdx = xml.IndexOf('>', pos + 2);
                        if (endIdx < 0)
                            return (-1, false);
                        return (endIdx + 1, hasSignificantChild);
                    }
                    int closeEnd = xml.IndexOf('>', pos + 2);
                    if (closeEnd < 0)
                        return (-1, false);
                    pos = closeEnd + 1;
                }
                else if (pos + 3 < xml.Length && xml[pos + 1] == '!' && xml[pos + 2] == '-' && xml[pos + 3] == '-')
                {
                    // Comment child — significant at depth 1
                    if (depth == 1)
                        hasSignificantChild = true;
                    int endIdx = xml.IndexOf("-->", pos + 4, StringComparison.Ordinal);
                    if (endIdx < 0)
                        return (-1, false);
                    pos = endIdx + 3;
                }
                else if (pos + 1 < xml.Length && xml[pos + 1] == '?')
                {
                    // PI child — significant at depth 1
                    if (depth == 1)
                        hasSignificantChild = true;
                    int endIdx = xml.IndexOf("?>", pos + 2, StringComparison.Ordinal);
                    if (endIdx < 0)
                        return (-1, false);
                    pos = endIdx + 2;
                }
                else
                {
                    // Child element — always significant at depth 1 (element children count regardless)
                    if (depth == 1)
                        hasSignificantChild = true;
                    // Scan past this child element's opening tag
                    int tagPos = pos + 1;
                    // Skip element name
                    while (tagPos < xml.Length && xml[tagPos] != '>' && xml[tagPos] != '/' && !char.IsWhiteSpace(xml[tagPos]))
                        tagPos++;
                    tagPos = SkipElementAttributes(xml, tagPos);
                    if (tagPos >= xml.Length)
                        return (-1, false);

                    if (xml[tagPos] == '/' && tagPos + 1 < xml.Length && xml[tagPos + 1] == '>')
                    {
                        pos = tagPos + 2; // self-closing child
                    }
                    else
                    {
                        depth++;
                        pos = tagPos + 1;
                    }
                }
            }
            else
            {
                // Text content
                int textStart = pos;
                while (pos < xml.Length && xml[pos] != '<')
                    pos++;
                // Text is significant if non-empty at depth 1
                if (depth == 1 && pos > textStart)
                    hasSignificantChild = true;
            }
        }

        return (-1, false); // Malformed — never found closing tag
    }

    /// <summary>
    /// Skips past attribute declarations in an element tag, handling quoted values.
    /// Returns position at '>' or '/'.
    /// </summary>
    private static int SkipElementAttributes(string xml, int pos)
    {
        while (pos < xml.Length && xml[pos] != '>' && !(xml[pos] == '/' && pos + 1 < xml.Length && xml[pos + 1] == '>'))
        {
            if (xml[pos] == '"')
            {
                pos++;
                while (pos < xml.Length && xml[pos] != '"')
                    pos++;
                if (pos < xml.Length)
                    pos++;
            }
            else if (xml[pos] == '\'')
            {
                pos++;
                while (pos < xml.Length && xml[pos] != '\'')
                    pos++;
                if (pos < xml.Length)
                    pos++;
            }
            else
            {
                pos++;
            }
        }
        return pos;
    }




    public override async ValueTask OnEmptyAsync(XsltOnEmpty instruction)
    {
        // xsl:on-empty is handled specially by the parent element constructor.
        // If we get here directly, it means the parent didn't handle it,
        // so execute the content.
        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            if (result != null)
            {
                // xsl:on-empty select="..." produces atomic values (like xsl:sequence)
                if (result is string str)
                {
                    if (_lastResultWasAtomic && _attributeContentDepth == 0)
                        WriteText(" ", false);
                    WriteText(str, false);
                    _lastResultWasAtomic = true;
                }
                else
                {
                    SerializeResult(result);
                }
            }
        }
        else if (instruction.Content != null)
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
    }

    public override async ValueTask OnNonEmptyAsync(XsltOnNonEmpty instruction)
    {
        // xsl:on-non-empty: execute content (it will be included because the parent
        // verified that there IS non-empty output via where-populated)
        if (instruction.Select != null)
        {
            var result = await EvaluateAsync(instruction.Select).ConfigureAwait(false);
            if (result != null)
            {
                // xsl:on-non-empty select="..." produces atomic values
                if (result is string str)
                {
                    if (_lastResultWasAtomic && _attributeContentDepth == 0)
                        WriteText(" ", false);
                    WriteText(str, false);
                    _lastResultWasAtomic = true;
                }
                else
                {
                    SerializeResult(result);
                }
            }
        }
        else if (instruction.Content != null)
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
    }

    public override async ValueTask EvaluateInstructionAsync(XsltEvaluate instruction)
    {
        // xsl:evaluate: dynamically evaluate an XPath expression string
        // The xpath attribute is an XPath expression that produces the string to evaluate
        var xpathResult = await EvaluateAsync(instruction.Xpath).ConfigureAwait(false);
        var xpathStr = StringValueOf(xpathResult);

        // Parse the XPath expression
        XQueryExpression parsedExpr;
        try
        {
            parsedExpr = new PhoenixmlDb.XQuery.Parser.XQueryParserFacade { AllowNamespaceAxis = true }.Parse(xpathStr);
        }
        catch (Exception ex)
        {
            throw new XsltException($"XTDE3150: Dynamic XPath expression is not valid: {ex.Message}", instruction.Location);
        }

        // Determine namespace bindings for the dynamic expression.
        // Per XSLT 3.0 §19.4: namespace-context provides an element whose in-scope namespaces
        // are used for resolving prefixes. Otherwise, the in-scope namespaces of the
        // xsl:evaluate element are used.
        Dictionary<string, string> nsBindings;
        string? xpathDefaultNs = instruction.XpathDefaultNamespace;
        if (instruction.NamespaceContext != null)
        {
            var nsCtxResult = await EvaluateAsync(instruction.NamespaceContext).ConfigureAwait(false);
            // XTTE3170: namespace-context must be a single node
            if (nsCtxResult is object?[] nsArr)
            {
                if (nsArr.Length != 1)
                    throw new XsltException("XTTE3170: The namespace-context attribute of xsl:evaluate must evaluate to a single node", instruction.Location);
                nsCtxResult = nsArr[0];
            }
            if (nsCtxResult is not (Xdm.Nodes.XdmElement or Xdm.Nodes.XdmNode or System.Xml.XmlNode or System.Xml.Linq.XNode))
                throw new XsltException("XTTE3170: The namespace-context attribute of xsl:evaluate must evaluate to a single node", instruction.Location);
            nsBindings = ExtractNamespaceBindings(nsCtxResult);
            // Default namespace from the namespace-context element overrides xpath-default-namespace
            if (nsBindings.TryGetValue("", out var defaultNs) && defaultNs.Length > 0)
                xpathDefaultNs = defaultNs;
            else
                xpathDefaultNs = null; // No default namespace in context element
        }
        else
        {
            nsBindings = instruction.DefaultNamespaceBindings;
        }

        // Resolve namespace prefixes in the parsed expression using the determined bindings
        ResolveExpressionNamespacesRuntime(parsedExpr, nsBindings, xpathDefaultNs);

        // Evaluate context-item if specified
        object? contextItem = null;
        if (instruction.ContextItem != null)
        {
            contextItem = await EvaluateAsync(instruction.ContextItem).ConfigureAwait(false);
        }

        // Evaluate base-uri AVT if specified
        string? baseUri = null;
        if (instruction.BaseUri != null)
        {
            var sb = new System.Text.StringBuilder();
            foreach (var part in instruction.BaseUri.Parts)
                sb.Append(await part.EvaluateAsync(this).ConfigureAwait(false));
            baseUri = sb.ToString();
        }

        // Bind with-param values as variables in the evaluation scope
        PushScope();
        try
        {
            // Handle xsl:with-param child elements first (lower precedence)
            foreach (var param in instruction.WithParams)
            {
                var value = await EvaluateAsync(param.Select!).ConfigureAwait(false);
                SetVariable(param.Name, value);
            }
            // Handle with-params attribute (map expression) — higher precedence, overwrites children
            if (instruction.WithParamsExpr != null)
            {
                var mapResult = await EvaluateAsync(instruction.WithParamsExpr).ConfigureAwait(false);
                if (mapResult is IDictionary<object, object?> paramMap)
                {
                    foreach (var (key, val) in paramMap)
                    {
                        if (key is PhoenixmlDb.Core.QName qn)
                            SetVariable(qn, val);
                        else
                            throw new XsltException("XTTE3165: The keys in the with-params map must be of type xs:QName", instruction.Location);
                    }
                }
            }

            // Push context item for the dynamic expression.
            // Per XSLT 3.0 §19.4: if context-item is not specified OR evaluates to
            // empty sequence, context is absent (XPDY0002 if accessed).
            if (contextItem != null)
                PushContextItem(contextItem, 1, 1);
            else
                PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);

            // Set default collation for the evaluation: explicit attribute > inherited
            var effectiveCollation = instruction.EvaluateDefaultCollation ?? instruction.DefaultCollation;
            if (effectiveCollation != null)
                _defaultCollationStack.Push(effectiveCollation);

            // Push base-uri for static-base-uri() and base-uri() within the evaluation
            if (baseUri != null)
                _staticBaseUriStack.Push(baseUri);

            // Override PrefixNamespaceBindings for the evaluation so functions like
            // system-property() and QName resolution use the correct namespace context
            var savedNsBindings = _evaluateNamespaceBindings;
            _evaluateNamespaceBindings = nsBindings;

            _insideXslEvaluateDepth++;
            try
            {
                var result = await EvaluateAsync(parsedExpr).ConfigureAwait(false);

                // Apply type coercion via 'as' attribute (XSLT 3.0 §19.4)
                // Like xsl:variable 'as': atomize nodes, coerce types, check cardinality
                if (instruction.As != null)
                    result = CoerceEvaluateResult(result, instruction.As, instruction.Location);

                if (result != null)
                {
                    // If sequence accumulator is active (e.g., inside variable with as="function(*)"),
                    // add the result directly to avoid XTDE0450 for function/map items
                    if (_sequenceAccumulator != null)
                    {
                        if (result is object?[] arr)
                            foreach (var item in arr) AppendToSeqAccumulator(item);
                        else
                            AppendToSeqAccumulator(result);
                    }
                    else
                    {
                        // Serialize the result: nodes are deep-copied (like xsl:copy-of),
                        // atomic values are output as text
                        OutputEvaluateResult(result);
                    }
                }
            }
            finally
            {
                _insideXslEvaluateDepth--;
                _evaluateNamespaceBindings = savedNsBindings;
                if (baseUri != null)
                    _staticBaseUriStack.Pop();
                if (effectiveCollation != null)
                    _defaultCollationStack.Pop();
                PopContextItem();
            }
        }
        finally
        {
            PopScope();
        }
    }

    /// <summary>
    /// Extract namespace bindings from an element (XDM or System.Xml) for xsl:evaluate namespace-context.
    /// </summary>
    private Dictionary<string, string> ExtractNamespaceBindings(object? element)
    {
        var bindings = new Dictionary<string, string>();
        switch (element)
        {
            case Xdm.Nodes.XdmElement xdmElem:
            {
                // XDM element from in-memory node store — read NamespaceDeclarations
                foreach (var nsDecl in xdmElem.NamespaceDeclarations)
                {
                    var prefix = nsDecl.Prefix ?? "";
                    var uri = _nodeStore?.GetNamespaceUri(nsDecl.Namespace) ?? "";
                    if (prefix != "xml" && !bindings.ContainsKey(prefix))
                        bindings[prefix] = uri;
                }
                // Also add the element's own namespace if it has a prefix binding not yet covered
                if (xdmElem.Namespace != NamespaceId.None)
                {
                    var elemUri = _nodeStore?.GetNamespaceUri(xdmElem.Namespace) ?? "";
                    var elemPrefix = xdmElem.Prefix ?? "";
                    if (!bindings.ContainsKey(elemPrefix) && elemPrefix != "xml")
                        bindings[elemPrefix] = elemUri;
                }
                break;
            }
            case System.Xml.XmlElement xmlElem:
            {
                var nav = xmlElem.CreateNavigator();
                if (nav != null)
                {
                    foreach (var kvp in nav.GetNamespacesInScope(System.Xml.XmlNamespaceScope.All))
                        if (kvp.Key != "xml") bindings[kvp.Key] = kvp.Value;
                }
                break;
            }
            case System.Xml.Linq.XElement xElem:
            {
                foreach (var attr in xElem.Attributes())
                {
                    if (attr.IsNamespaceDeclaration)
                    {
                        var p = attr.Name.LocalName == "xmlns" ? "" : attr.Name.LocalName;
                        if (!bindings.ContainsKey(p) && p != "xml")
                            bindings[p] = attr.Value;
                    }
                }
                // Walk ancestors for inherited namespace declarations
                var ancestor = xElem.Parent;
                while (ancestor != null)
                {
                    foreach (var attr in ancestor.Attributes())
                    {
                        if (attr.IsNamespaceDeclaration)
                        {
                            var p = attr.Name.LocalName == "xmlns" ? "" : attr.Name.LocalName;
                            if (!bindings.ContainsKey(p) && p != "xml")
                                bindings[p] = attr.Value;
                        }
                    }
                    ancestor = ancestor.Parent;
                }
                break;
            }
            case System.Xml.XPath.XPathNavigator nav:
            {
                if (nav.NodeType == System.Xml.XPath.XPathNodeType.Element)
                {
                    foreach (var kvp in nav.GetNamespacesInScope(System.Xml.XmlNamespaceScope.All))
                        if (kvp.Key != "xml") bindings[kvp.Key] = kvp.Value;
                }
                break;
            }
        }
        return bindings;
    }

    /// <summary>
    /// Resolve namespace prefixes in a dynamically parsed XPath expression at runtime.
    /// Similar to StylesheetParser.ResolveExpressionNamespaces but works with a prefix→URI dictionary.
    /// </summary>
    private void ResolveExpressionNamespacesRuntime(XQueryExpression expr, Dictionary<string, string> nsBindings, string? xpathDefaultNs)
    {
        switch (expr)
        {
            case PhoenixmlDb.XQuery.Ast.VariableReference vr:
                if (!string.IsNullOrEmpty(vr.Name.Prefix) && vr.Name.Namespace == NamespaceId.None)
                    vr.Name = ResolveQNameRuntime(vr.Name.Prefix!, vr.Name.LocalName, nsBindings);
                break;
            case PhoenixmlDb.XQuery.Ast.FunctionCallExpression fc:
                if (!string.IsNullOrEmpty(fc.Name.Prefix) && fc.Name.Namespace == NamespaceId.None)
                    fc.Name = ResolveQNameRuntime(fc.Name.Prefix!, fc.Name.LocalName, nsBindings);
                foreach (var arg in fc.Arguments)
                    ResolveExpressionNamespacesRuntime(arg, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.BinaryExpression be:
                ResolveExpressionNamespacesRuntime(be.Left, nsBindings, xpathDefaultNs);
                ResolveExpressionNamespacesRuntime(be.Right, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.UnaryExpression ue:
                ResolveExpressionNamespacesRuntime(ue.Operand, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.PathExpression pe:
                if (pe.InitialExpression != null)
                    ResolveExpressionNamespacesRuntime(pe.InitialExpression, nsBindings, xpathDefaultNs);
                foreach (var step in pe.Steps)
                    ResolveExpressionNamespacesRuntime(step, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.StepExpression se:
                if (se.NodeTest is PhoenixmlDb.XQuery.Ast.NameTest nt)
                {
                    if (!string.IsNullOrEmpty(nt.Prefix) && nt.Prefix != "*" && nt.NamespaceUri == null)
                    {
                        if (nsBindings.TryGetValue(nt.Prefix, out var ns))
                            nt.NamespaceUri = ns;
                    }
                    else if (nt.Prefix == null && nt.NamespaceUri == null && !nt.IsLocalNameWildcard
                             && se.Axis != PhoenixmlDb.XQuery.Ast.Axis.Attribute
                             && se.Axis != PhoenixmlDb.XQuery.Ast.Axis.Namespace)
                    {
                        if (xpathDefaultNs != null)
                            nt.NamespaceUri = xpathDefaultNs;
                    }
                }
                foreach (var pred in se.Predicates)
                    ResolveExpressionNamespacesRuntime(pred, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.FilterExpression fe:
                ResolveExpressionNamespacesRuntime(fe.Primary, nsBindings, xpathDefaultNs);
                foreach (var pred in fe.Predicates)
                    ResolveExpressionNamespacesRuntime(pred, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.IfExpression ie:
                ResolveExpressionNamespacesRuntime(ie.Condition, nsBindings, xpathDefaultNs);
                ResolveExpressionNamespacesRuntime(ie.Then, nsBindings, xpathDefaultNs);
                if (ie.Else != null)
                    ResolveExpressionNamespacesRuntime(ie.Else, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.FlworExpression flwor:
                foreach (var clause in flwor.Clauses)
                {
                    if (clause is PhoenixmlDb.XQuery.Ast.ForClause forClause)
                        foreach (var binding in forClause.Bindings)
                            ResolveExpressionNamespacesRuntime(binding.Expression, nsBindings, xpathDefaultNs);
                    else if (clause is PhoenixmlDb.XQuery.Ast.LetClause letClause)
                        foreach (var binding in letClause.Bindings)
                            ResolveExpressionNamespacesRuntime(binding.Expression, nsBindings, xpathDefaultNs);
                    else if (clause is PhoenixmlDb.XQuery.Ast.WhereClause whereClause)
                        ResolveExpressionNamespacesRuntime(whereClause.Condition, nsBindings, xpathDefaultNs);
                    else if (clause is PhoenixmlDb.XQuery.Ast.OrderByClause orderBy)
                        foreach (var spec in orderBy.OrderSpecs)
                            ResolveExpressionNamespacesRuntime(spec.Expression, nsBindings, xpathDefaultNs);
                }
                ResolveExpressionNamespacesRuntime(flwor.ReturnExpression, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.SequenceExpression seq:
                foreach (var item in seq.Items)
                    ResolveExpressionNamespacesRuntime(item, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.InstanceOfExpression inst:
                ResolveExpressionNamespacesRuntime(inst.Expression, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.CastExpression cast:
                ResolveExpressionNamespacesRuntime(cast.Expression, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.SimpleMapExpression sme:
                ResolveExpressionNamespacesRuntime(sme.Left, nsBindings, xpathDefaultNs);
                ResolveExpressionNamespacesRuntime(sme.Right, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.StringConcatExpression sce:
                foreach (var operand in sce.Operands)
                    ResolveExpressionNamespacesRuntime(operand, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.RangeExpression re:
                ResolveExpressionNamespacesRuntime(re.Start, nsBindings, xpathDefaultNs);
                ResolveExpressionNamespacesRuntime(re.End, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.ArrowExpression ae:
                ResolveExpressionNamespacesRuntime(ae.Expression, nsBindings, xpathDefaultNs);
                ResolveExpressionNamespacesRuntime(ae.FunctionCall, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.InlineFunctionExpression ife:
                if (ife.Body != null)
                    ResolveExpressionNamespacesRuntime(ife.Body, nsBindings, xpathDefaultNs);
                break;
            case PhoenixmlDb.XQuery.Ast.DynamicFunctionCallExpression dfc:
                ResolveExpressionNamespacesRuntime(dfc.FunctionExpression, nsBindings, xpathDefaultNs);
                foreach (var arg in dfc.Arguments)
                    ResolveExpressionNamespacesRuntime(arg, nsBindings, xpathDefaultNs);
                break;
        }
    }

    private QName ResolveQNameRuntime(string prefix, string localName, Dictionary<string, string> nsBindings)
    {
        if (nsBindings.TryGetValue(prefix, out var nsUri) && !string.IsNullOrEmpty(nsUri))
        {
            var nsId = StylesheetParser.ResolveNamespaceUri(nsUri);
            // Ensure the function library knows about this namespace
            _functionLibrary.RegisterNamespaceUri(nsUri, nsId);
            return new QName(nsId, localName, prefix);
        }
        // Use stylesheet namespaces as fallback
        if (_stylesheet.Namespaces.TryGetValue(prefix, out var fallbackUri))
        {
            var nsId = StylesheetParser.ResolveNamespaceUri(fallbackUri);
            if (nsId != NamespaceId.None)
                return new QName(nsId, localName, prefix);
        }
        return new QName(NamespaceId.None, localName, prefix);
    }

    /// <summary>
    /// Coerce and validate the result of xsl:evaluate against the 'as' type.
    /// Follows XSLT 3.0 function coercion: atomize nodes → cast untypedAtomic → check type.
    /// Returns the coerced result, or throws XPTY0004 on type mismatch.
    /// </summary>
    private static object? CoerceEvaluateResult(object? result, XdmSequenceType targetType, SourceLocation? location)
    {
        // Check cardinality for empty
        if (result == null || (result is object?[] arr0 && arr0.Length == 0))
        {
            if (targetType.Occurrence == Occurrence.ExactlyOne || targetType.Occurrence == Occurrence.OneOrMore)
                throw new XsltException($"XPTY0004: xsl:evaluate result is empty but required type is {targetType}", location);
            return result;
        }

        var items = result is object?[] arr ? arr : new[] { result };
        if (items.Length > 1 && (targetType.Occurrence == Occurrence.ExactlyOne || targetType.Occurrence == Occurrence.ZeroOrOne))
            throw new XsltException($"XPTY0004: xsl:evaluate result has {items.Length} items but required type is {targetType}", location);

        // For item() type, accept everything
        if (targetType.ItemType == ItemType.Item)
            return result;

        // Coerce each item per XSLT function coercion rules
        var coerced = new object?[items.Length];
        for (int i = 0; i < items.Length; i++)
        {
            var item = items[i];
            if (item == null) { coerced[i] = null; continue; }

            // For atomic target types: atomize nodes, then cast untypedAtomic
            var isAtomicTarget = targetType.ItemType >= ItemType.AnyAtomicType;
            if (isAtomicTarget && !IsNodeType(targetType.ItemType))
            {
                // Step 1: Atomize nodes → produces xs:untypedAtomic (for non-schema-aware)
                if (item is Xdm.Nodes.XdmNode or Xdm.Nodes.XdmAttribute or Xdm.Nodes.XdmElement
                    or System.Xml.XmlNode or System.Xml.Linq.XNode)
                    item = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AtomizeTyped(item);

                // Step 2: Cast xs:untypedAtomic to target type
                if (item is Xdm.XsUntypedAtomic)
                {
                    item = CoerceToType(item, targetType);
                }

                // Step 3: Validate the (possibly coerced) item matches the target type
                if (item != null && !PhoenixmlDb.XQuery.Execution.TypeCastHelper.MatchesItemType(item, targetType.ItemType))
                    throw new XsltException($"XPTY0004: xsl:evaluate result of type {item.GetType().Name} does not match required type {targetType}", location);

                coerced[i] = item;
            }
            else
            {
                // For node/function/map/array target types: validate directly
                if (!PhoenixmlDb.XQuery.Execution.TypeCastHelper.MatchesItemType(item, targetType.ItemType))
                    throw new XsltException($"XPTY0004: xsl:evaluate result of type {item.GetType().Name} does not match required type {targetType}", location);
                coerced[i] = item;
            }
        }

        return coerced.Length == 1 ? coerced[0] : coerced;
    }

    public override async ValueTask CreateLiteralElementAsync(XsltLiteralResultElement instruction)
    {
        if (_recursionDepth >= MaxRecursionDepth)
            return;
        _recursionDepth++;
        try
        {
            await CreateLiteralElementCoreAsync(instruction).ConfigureAwait(false);
        }
        finally
        {
            _recursionDepth--;
        }
    }

    private async ValueTask CreateLiteralElementCoreAsync(XsltLiteralResultElement instruction)
    {
        // Inside attribute/comment/PI content, suppress element tags and pass through
        // only text content (atomization per XSLT spec 5.7.2)
        if (_textContentDepth > 0)
        {
            // When collecting simple content items, atomized elements are separate items
            if (_collectTextAsSequenceItems && _sequenceAccumulator != null && _serializingElementDepth == 0)
            {
                var pending = _output.ToString();
                if (pending.Length > 0)
                {
                    AppendToSeqAccumulator(new Xdm.TextNodeItem(pending));
                    _output.Clear();
                }
                _collectTextAsSequenceItems = false;
                try
                {
                    await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
                }
                finally
                {
                    _collectTextAsSequenceItems = true;
                }
                var elementText = _output.ToString();
                _output.Clear();
                if (elementText.Length > 0)
                    AppendToSeqAccumulator(elementText);
                return;
            }
            // Simple content construction: space between items from different nodes
            // (only for comment/PI content; attribute content uses empty-string separator)
            if (_attributeContentDepth == 0 && _output.Length > 0)
                _output.Append(' ');
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
            if (_attributeContentDepth == 0)
                _simpleContentLastWasNode = true;
            return;
        }

        // Build a prefix→URI map from the instruction's namespace declarations for alias resolution
        var prefixToUri = new Dictionary<string, string>();
        foreach (var (p, u) in instruction.NamespaceDeclarations)
            prefixToUri[p] = u;

        // Apply namespace aliases to element name
        var elemPrefix = instruction.Name.Prefix;
        var elemLocalName = instruction.Name.LocalName;
        if (_stylesheet.NamespaceAliases.Count > 0)
        {
            // Determine the element's current namespace URI
            string elemNsUri;
            if (elemPrefix != null)
                elemNsUri = prefixToUri.GetValueOrDefault(elemPrefix, "");
            else
                elemNsUri = prefixToUri.GetValueOrDefault("", ""); // Default namespace or empty

            if (_stylesheet.NamespaceAliases.TryGetValue(elemNsUri, out var elemAlias))
                elemPrefix = string.IsNullOrEmpty(elemAlias.ResultPrefix) ? null : elemAlias.ResultPrefix;
        }

        var elemName = elemPrefix != null
            ? $"{elemPrefix}:{elemLocalName}"
            : elemLocalName;

        // Collect all attributes in a dictionary (last-wins deduplication)
        var attributes = new Dictionary<string, string>();

        // Build set of prefixes in use by the element and its attributes (using aliased prefixes)
        var usedPrefixes = new HashSet<string>();
        if (elemPrefix != null)
            usedPrefixes.Add(elemPrefix);
        else
            usedPrefixes.Add(""); // default namespace is in use

        // Add attribute prefixes BEFORE processing namespace declarations so that
        // exclude-result-prefixes does not remove namespaces needed by attributes
        foreach (var (attrName, _) in instruction.Attributes)
        {
            var aPrefix = attrName.Prefix;
            if (aPrefix != null && prefixToUri.TryGetValue(aPrefix, out var aNsUri)
                && _stylesheet.NamespaceAliases.TryGetValue(aNsUri, out var aAlias))
            {
                usedPrefixes.Add(string.IsNullOrEmpty(aAlias.ResultPrefix) ? "" : aAlias.ResultPrefix);
            }
            else if (aPrefix != null)
                usedPrefixes.Add(aPrefix);
        }

        // Pre-compute namespace bindings for this element (so children can see them in scope)
        // Apply namespace aliases: transform URIs and prefixes
        var nsBindings = new Dictionary<string, string>();
        foreach (var (prefix, uri) in instruction.NamespaceDeclarations)
        {
            var effectiveUri = uri;
            var effectivePrefix = prefix;

            // Apply namespace alias if this URI is aliased
            if (_stylesheet.NamespaceAliases.TryGetValue(uri, out var alias))
            {
                effectiveUri = alias.ResultUri;
                effectivePrefix = alias.ResultPrefix;
            }

            // XSLT spec: A namespace node whose string value is a zero-length string is not created.
            // xmlns="" on an LRE does not produce a namespace node; it simply removes the default namespace.
            if (string.IsNullOrEmpty(effectiveUri))
                continue;
            // Skip XSLT namespace unless it's the result of a namespace alias
            if (effectiveUri == "http://www.w3.org/1999/XSL/Transform"
                && !_stylesheet.NamespaceAliases.TryGetValue(uri, out _))
                continue;
            if (effectiveUri == "http://www.w3.org/XML/1998/namespace")
                continue;
            // Skip the original stylesheet URI that was aliased (it's replaced by the result)
            if (uri != effectiveUri && uri == "http://www.w3.org/1999/XSL/Transform")
                continue;

            // Check exclude-result-prefixes using the ORIGINAL prefix (from stylesheet)
            var isInUse = usedPrefixes.Contains(effectivePrefix);
            if (!isInUse && (
                instruction.ExcludeResultPrefixes.Contains("#all") ||
                (!string.IsNullOrEmpty(prefix) && (_stylesheet.ExcludeResultPrefixes.Contains(prefix) || instruction.ExcludeResultPrefixes.Contains(prefix))) ||
                (string.IsNullOrEmpty(prefix) && (_stylesheet.ExcludeResultPrefixes.Contains("#default") || instruction.ExcludeResultPrefixes.Contains("#default"))) ||
                (!string.IsNullOrEmpty(prefix) && _stylesheet.ExtensionElementPrefixes.Contains(prefix))))
                continue;

            nsBindings[effectivePrefix] = effectiveUri;
        }

        // Ensure the element's aliased namespace is declared if not already present
        if (_stylesheet.NamespaceAliases.Count > 0 && elemPrefix != null)
        {
            // The element uses an aliased prefix — make sure that prefix → URI binding exists
            string elemNsUri;
            if (instruction.Name.Prefix != null)
                elemNsUri = prefixToUri.GetValueOrDefault(instruction.Name.Prefix, "");
            else
                elemNsUri = prefixToUri.GetValueOrDefault("", "");

            if (_stylesheet.NamespaceAliases.TryGetValue(elemNsUri, out var eAlias)
                && !nsBindings.ContainsKey(eAlias.ResultPrefix))
            {
                nsBindings[eAlias.ResultPrefix] = eAlias.ResultUri;
            }
        }

        // Push effective version and collation if set on this element
        // (must be before AVT evaluation so BC mode / collation affects attribute values)
        if (instruction.Version != null)
            _effectiveVersionStack.Push(instruction.Version);
        if (instruction.DefaultCollation != null)
            _defaultCollationStack.Push(instruction.DefaultCollation);

        // 1. Apply use-attribute-sets FIRST (lowest priority - can be overridden)
        if (instruction.UseAttributeSets.Count > 0)
        {
            var attrSetParts = new StringBuilder();
            await ApplyAttributeSetsAsync(instruction.UseAttributeSets, attrSetParts).ConfigureAwait(false);
            ParseAttributeString(attrSetParts.ToString(), attributes);
        }

        // 2. Inline attributes (override attribute-set values)
        foreach (var (name, avt) in instruction.Attributes)
        {
            var value = await EvaluateAvtAsync(avt).ConfigureAwait(false);
            // Apply namespace alias to attribute prefix
            var attrPrefix = name.Prefix;
            if (attrPrefix != null && prefixToUri.TryGetValue(attrPrefix, out var attrNsUri)
                && _stylesheet.NamespaceAliases.TryGetValue(attrNsUri, out var attrAlias))
            {
                attrPrefix = string.IsNullOrEmpty(attrAlias.ResultPrefix) ? null : attrAlias.ResultPrefix;
            }
            var attrName = attrPrefix != null
                ? $"{attrPrefix}:{name.LocalName}"
                : name.LocalName;
            attributes[attrName] = EscapeAttributeValue(value);
        }

        // 3. xsl:attribute instructions in body (highest priority)
        // Push namespace scope before processing body so children can see our ns bindings
        _collectedAttributesStack.Push(new StringBuilder());

        var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
        var savedLogicalStart = _outputLogicalStart;
        _outputLogicalStart = _output.Length;
        var savedLastAtomic = _lastResultWasAtomic;
        _lastResultWasAtomic = false;

        // Track element name for CDATA section serialization
        _outputElementStack.Push(instruction.Name);
        // Track whether element is in a namespace (for XTDE0440)
        var elemHasNs = elemPrefix != null
            || (nsBindings.TryGetValue("", out var defNs) && !string.IsNullOrEmpty(defNs))
            || GetInScopeDefaultNamespace() != null;
        _outputElementHasNsStack.Push(elemHasNs);
        _outputElementIsLreStack.Push(true); // literal result element
        _xslNamespaceBindings.Push(new Dictionary<string, string>());

        // inherit-namespaces="no" on parent: add default ns undeclaration so children
        // don't inherit the parent's xmlns="..." in the serialized output
        if (_forceDefaultNsUndeclaration && !nsBindings.ContainsKey("")
            && GetInScopeDefaultNamespace() != null)
        {
            nsBindings[""] = "";
        }

        PushOutputNsScope(nsBindings);
        PushOutputNsScope(new Dictionary<string, string>()); // Separate scope for attribute-emitted ns decls
        PushScope(); // Variables declared inside this element should be scoped to this element
        var savedSeqAccum3 = _sequenceAccumulator;
        _sequenceAccumulator = null; // Suspend accumulation inside element content
        _serializingElementDepth++;
        Dictionary<string, string>? xslNsBindingsForFixup = null;
        // Save/set inherit-namespaces flag for children
        var savedForceNsUndecl3 = _forceDefaultNsUndeclaration;
        _forceDefaultNsUndeclaration = instruction.InheritNamespaces == false
            && nsBindings.ContainsKey("") && !string.IsNullOrEmpty(nsBindings.GetValueOrDefault(""));
        // Push xml:base onto static base URI stack so document()/resolve-uri() resolve against it
        if (instruction.StaticBaseUri != null)
            _staticBaseUriStack.Push(instruction.StaticBaseUri);
        try
        {
            await instruction.Content.ExecuteAsync(this).ConfigureAwait(false);
        }
        finally
        {
            if (instruction.StaticBaseUri != null)
                _staticBaseUriStack.Pop();
            _forceDefaultNsUndeclaration = savedForceNsUndecl3;
            _serializingElementDepth--;
            _sequenceAccumulator = savedSeqAccum3;
            PopScope();
            PopOutputNsScope(); // attribute ns decls scope
            PopOutputNsScope(); // element ns scope
            if (instruction.DefaultCollation != null)
                _defaultCollationStack.Pop();
            if (instruction.Version != null)
                _effectiveVersionStack.Pop();
            _outputElementStack.Pop();
            _outputElementHasNsStack.Pop();
            _outputElementIsLreStack.Pop();
            // Save xsl:namespace bindings for namespace fixup before popping
            xslNsBindingsForFixup = _xslNamespaceBindings.Peek().Count > 0
                ? new Dictionary<string, string>(_xslNamespaceBindings.Peek())
                : null;
            _xslNamespaceBindings.Pop();
        }

        var collectedAttrs = _collectedAttributesStack.Pop();
        var content = savedScope.GetWritten();
        savedScope.Dispose();
        _outputLogicalStart = savedLogicalStart;
        // After producing an element node, reset atomic state (nodes break atomic adjacency)
        _lastResultWasAtomic = false;

        // Parse collected attributes and add to dictionary (overriding earlier values)
        ParseAttributeString(collectedAttrs.ToString(), attributes);

        // Namespace fixup: if xsl:namespace redefined the element's prefix to a different URI,
        // either do namespace fixup (if prefix was excluded) or throw XTDE0430 (XSLT 3.0 §11.7)
        if (xslNsBindingsForFixup != null && elemPrefix != null)
        {
            if (xslNsBindingsForFixup.TryGetValue(elemPrefix, out var xslUri))
            {
                // Get the element's original namespace URI
                var elemNsUri = nsBindings.GetValueOrDefault(elemPrefix, "");
                if (elemNsUri.Length == 0)
                {
                    // The prefix may have been excluded; look up the original declaration
                    foreach (var (p, u) in instruction.NamespaceDeclarations)
                    {
                        if (p == elemPrefix) { elemNsUri = u; break; }
                    }
                    // Apply namespace alias if applicable
                    if (_stylesheet.NamespaceAliases.TryGetValue(elemNsUri, out var alias2))
                        elemNsUri = alias2.ResultUri;
                }
                if (xslUri != elemNsUri)
                {
                    // Check if the prefix was in exclude-result-prefixes
                    var prefixWasExcluded = instruction.ExcludeResultPrefixes.Contains(elemPrefix)
                        || instruction.ExcludeResultPrefixes.Contains("#all")
                        || _stylesheet.ExcludeResultPrefixes.Contains(elemPrefix);
                    if (!prefixWasExcluded)
                        throw Error($"XTDE0430: Namespace node with prefix '{elemPrefix}' and URI '{xslUri}' conflicts with the element's own namespace binding '{elemPrefix}' → '{elemNsUri}'");

                    var newPfx = GenerateUniquePrefix(elemPrefix);
                    elemName = $"{newPfx}:{elemLocalName}";
                    // Add new prefix → element namespace to nsBindings; remove old conflicting entry
                    nsBindings.Remove(elemPrefix);
                    nsBindings[newPfx] = elemNsUri;
                    // Remove the old xmlns:PREFIX from attributes dict — it will be emitted from nsBindings
                    // The xsl:namespace's binding stays in attributes as xmlns:ORIGINAL_PREFIX
                    attributes.Remove($"xmlns:{newPfx}"); // Ensure no conflict with new prefix
                }
            }
        }

        // Build element output
        _output.Append('<');
        _output.Append(elemName);

        // Namespace declarations — emit only those not already in scope from ancestor elements
        foreach (var (prefix, uri) in nsBindings)
        {
            // Skip if already declared by an ancestor with same prefix→URI
            if (IsNamespaceInScope(prefix, uri))
                continue;

            // Skip xmlns="" (default namespace undeclaration) if there's no non-empty
            // default namespace in scope — the undeclaration would be redundant
            if (string.IsNullOrEmpty(prefix) && string.IsNullOrEmpty(uri)
                && GetInScopeDefaultNamespace() == null)
                continue;

            _output.Append(" xmlns");
            if (!string.IsNullOrEmpty(prefix))
            {
                _output.Append(':');
                _output.Append(prefix);
            }
            _output.Append("=\"");
            _output.Append(EscapeAttributeValue(uri));
            _output.Append('"');
        }

        // Default namespace undeclaration: if this element is in the null namespace
        // (no prefix, no default ns declared), but the output tree has a non-empty
        // default namespace in scope, emit xmlns="" to undeclare it.
        if (elemPrefix == null && !nsBindings.ContainsKey(""))
        {
            var parentDefaultNs = GetInScopeDefaultNamespace();
            if (parentDefaultNs != null)
            {
                _output.Append(" xmlns=\"\"");
            }
        }
        // inherit-namespaces="no": also undeclare inherited default namespace
        else if (instruction.InheritNamespaces == false && !nsBindings.ContainsKey(""))
        {
            var inheritedDefaultNs = GetInScopeDefaultNamespace();
            if (inheritedDefaultNs != null)
            {
                _output.Append(" xmlns=\"\"");
            }
        }

        // Emit deduplicated attributes
        foreach (var (attrName, attrValue) in attributes)
        {
            _output.Append(' ');
            _output.Append(attrName);
            _output.Append("=\"");
            _output.Append(attrValue);
            _output.Append('"');
        }

        if (content.Length > 0)
        {
            _output.Append('>');
            _output.Append(content);
            _output.Append("</");
            _output.Append(elemName);
            _output.Append('>');
        }
        else
        {
            _output.Append("/>");
        }

        // LRE element is "significant" (populated) only if it has child content
        // (attributes alone don't count as "populated" per XSLT 3.0 spec)
        if (content.Length > 0)
            MarkContentProduced();
    }

    /// <summary>
    /// Parses a raw attribute string (e.g., ' color="black" size="14pt"') into a dictionary.
    /// Last occurrence of same name wins.
    /// </summary>
    private static void ParseAttributeString(string attrString, Dictionary<string, string> target)
    {
        var pos = 0;
        while (pos < attrString.Length)
        {
            // Skip whitespace
            while (pos < attrString.Length && char.IsWhiteSpace(attrString[pos]))
                pos++;

            if (pos >= attrString.Length)
                break;

            // Read attribute name (until '=')
            var nameStart = pos;
            while (pos < attrString.Length && attrString[pos] != '=')
                pos++;

            if (pos >= attrString.Length)
                break;

            var name = attrString[nameStart..pos].Trim();
            pos++; // skip '='

            // Skip optional whitespace and opening quote
            while (pos < attrString.Length && char.IsWhiteSpace(attrString[pos]))
                pos++;

            if (pos >= attrString.Length)
                break;

            var quote = attrString[pos];
            if (quote != '"' && quote != '\'')
                break;
            pos++; // skip opening quote

            // Read value until closing quote
            var valueStart = pos;
            while (pos < attrString.Length && attrString[pos] != quote)
                pos++;

            var value = attrString[valueStart..pos];
            if (pos < attrString.Length)
                pos++; // skip closing quote

            if (!string.IsNullOrEmpty(name))
            {
                target[name] = value;
            }
        }
    }

    private async ValueTask<string> EvaluateAvtAsync(XsltAttributeValueTemplate avt)
    {
        // Fast paths for the common case: most AVTs are either a single literal
        // (e.g. <foo bar="baz"/>) or a single expression (<foo bar="{$x}"/>).
        // Skipping the StringBuilder removes allocation pressure on large workloads:
        // ProjectToReport hits 24K AVT evals at ~18-20µs each, where most are 1-part.
        var parts = avt.Parts;
        if (parts.Count == 0) return string.Empty;
        if (parts.Count == 1)
            return await parts[0].EvaluateAsync(this).ConfigureAwait(false);

        var sb = new StringBuilder();
        foreach (var part in parts)
            sb.Append(await part.EvaluateAsync(this).ConfigureAwait(false));
        return sb.ToString();
    }

    private async Task<IEnumerable<object>> SortNodesAsync(IEnumerable<object> nodes, List<XsltSort> sorts)
    {
        if (sorts.Count == 0)
            return nodes;

        var list = nodes.ToList();

        // Resolve sort order directions, data types, lang, case-order, and collation upfront
        var descending = new bool[sorts.Count];
        var isNumeric = new bool[sorts.Count];
        var caseOrder = new string?[sorts.Count];
        var langs = new string?[sorts.Count];
        var collations = new string?[sorts.Count];
        for (var i = 0; i < sorts.Count; i++)
        {
            if (sorts[i].Order != null)
            {
                var orderValue = await EvaluateAvtAsync(sorts[i].Order!).ConfigureAwait(false);
                descending[i] = string.Equals(orderValue, "descending", StringComparison.OrdinalIgnoreCase);
            }
            if (sorts[i].DataType != null)
            {
                var dtValue = await EvaluateAvtAsync(sorts[i].DataType!).ConfigureAwait(false);
                isNumeric[i] = string.Equals(dtValue, "number", StringComparison.OrdinalIgnoreCase);
            }
            if (sorts[i].CaseOrder != null)
            {
                caseOrder[i] = await EvaluateAvtAsync(sorts[i].CaseOrder!).ConfigureAwait(false);
            }
            if (sorts[i].Lang != null)
            {
                langs[i] = await EvaluateAvtAsync(sorts[i].Lang!).ConfigureAwait(false);
                // XTDE0030: lang must be a valid language tag
                if (!string.IsNullOrEmpty(langs[i]) && !IsValidLanguageTag(langs[i]!))
                    throw new InvalidOperationException($"XTDE0030: Invalid language tag '{langs[i]}' in xsl:sort");
            }
            if (sorts[i].Collation != null)
            {
                collations[i] = await EvaluateAvtAsync(sorts[i].Collation!).ConfigureAwait(false);
                // Validate collation URI — only codepoint, html-ascii, and Unicode collation are supported
                if (!string.IsNullOrEmpty(collations[i])
                    && !string.Equals(collations[i], "http://www.w3.org/2005/xpath-functions/collation/codepoint", StringComparison.Ordinal)
                    && !string.Equals(collations[i], "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", StringComparison.Ordinal)
                    && !string.Equals(collations[i], "http://www.w3.org/2013/collation/UCA", StringComparison.Ordinal)
                    && !collations[i]!.StartsWith("http://www.w3.org/2013/collation/UCA?", StringComparison.Ordinal))
                    throw Error($"XTDE1035: Unknown collation URI '{collations[i]}'");
            }
        }

        // Build sort keys - preserve type information for XSLT 2.0+ typed comparison
        var keyed = new List<(object node, object?[] keys, int index)>();
        var idx = 0;
        foreach (var node in list)
        {
            var keys = new object?[sorts.Count];
            PushContextItem(node, idx + 1, list.Count);
            // Per XSLT 3.0 §20.4.2: "Within a sort key, the current function
            // returns the same node that is the context node."
            PushCurrentItem(node);

            try
            {
                for (var i = 0; i < sorts.Count; i++)
                {
                    var sort = sorts[i];
                    object? raw;
                    if (sort.Select != null)
                    {
                        raw = await EvaluateAsync(sort.Select).ConfigureAwait(false);
                    }
                    else if (sort.Content != null)
                    {
                        raw = await EvaluateSequenceConstructorAsync(sort.Content).ConfigureAwait(false);
                    }
                    else
                    {
                        raw = node;
                    }
                    // XTTE1020: Sort key must be a single atomic value in XSLT 2.0+
                    // In backwards-compatible mode, use first item of sequence
                    if (raw is object[] multiKey && multiKey.Length > 1)
                    {
                        if (IsBackwardsCompatible)
                            raw = multiKey[0];
                        else
                            throw Error($"XTTE1020: Sort key value is a sequence of {multiKey.Length} items; a single value is required");
                    }
                    keys[i] = raw;
                }
            }
            finally
            {
                PopCurrentItem();
                PopContextItem();
            }

            keyed.Add((node, keys, idx++));
        }

        // Stable sort: use index as tiebreaker to preserve document order
        keyed.Sort((a, b) =>
        {
            for (var i = 0; i < sorts.Count; i++)
            {
                var cmp = CompareSortKeys(a.keys[i], b.keys[i], isNumeric[i], langs[i], caseOrder[i], collations[i]);
                if (cmp != 0)
                    return descending[i] ? -cmp : cmp;
            }
            return a.index.CompareTo(b.index);
        });

        return keyed.Select(k => k.node);
    }

    /// <summary>
    /// Evaluates a sequence constructor and returns its result value.
    /// Used for sort key evaluation where the sort key is defined by content.
    /// Captures both typed values (via xsl:sequence / _sequenceAccumulator) and text output.
    /// </summary>
    internal async ValueTask<object?> EvaluateSequenceConstructorAsync(XsltSequenceConstructor content)
    {
        var savedAccumulator = _sequenceAccumulator;
        _sequenceAccumulator = new List<object?>();
        var savedLen = _output.Length;

        await content.ExecuteAsync(this).ConfigureAwait(false);

        var textOutput = _output.ToString(savedLen, _output.Length - savedLen);
        _output.Length = savedLen;
        var accumulatedItems = _sequenceAccumulator;
        _sequenceAccumulator = savedAccumulator;

        // Prefer typed sequence items over text output
        if (accumulatedItems.Count == 1)
            return accumulatedItems[0];
        if (accumulatedItems.Count > 1)
            return accumulatedItems.ToArray();

        return textOutput;
    }

    /// <summary>
    /// Returns a StringComparer appropriate for the given collation URI.
    /// </summary>
    internal static StringComparer GetCollationComparer(string? collationUri)
    {
        if (string.IsNullOrEmpty(collationUri))
            return StringComparer.Ordinal;
        if (string.Equals(collationUri, "http://www.w3.org/2005/xpath-functions/collation/codepoint", StringComparison.Ordinal))
            return StringComparer.Ordinal;
        if (string.Equals(collationUri, "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", StringComparison.Ordinal))
            return StringComparer.OrdinalIgnoreCase;
        if (collationUri!.StartsWith("http://www.w3.org/2013/collation/UCA", StringComparison.Ordinal))
        {
            if (collationUri.Contains("strength=primary", StringComparison.OrdinalIgnoreCase)
                || collationUri.Contains("strength=secondary", StringComparison.OrdinalIgnoreCase))
                return StringComparer.OrdinalIgnoreCase;
            return StringComparer.InvariantCulture;
        }
        return StringComparer.Ordinal;
    }

    /// <summary>
    /// Compares two sort key values with proper type-aware semantics.
    /// In XSLT 2.0+, numeric values compare numerically regardless of data-type attribute.
    /// </summary>
#pragma warning disable CA1309 // Locale-aware comparison is intentional for xsl:sort lang/case-order support
    private static int CompareSortKeys(object? a, object? b, bool forceNumeric,
        string? lang = null, string? caseOrder = null, string? collation = null)
    {
        // Extract numeric values from sort keys
        var aNum = ToSortDouble(a, forceNumeric);
        var bNum = ToSortDouble(b, forceNumeric);

        if (aNum.HasValue && bNum.HasValue)
        {
            // Both are numeric — compare as doubles
            // Per XSLT spec, NaN is less than any other numeric value
            var av = aNum.Value;
            var bv = bNum.Value;
            if (double.IsNaN(av) && double.IsNaN(bv))
                return 0;
            if (double.IsNaN(av))
                return -1;
            if (double.IsNaN(bv))
                return 1;
            return av.CompareTo(bv);
        }

        // XTDE1030: Detect type mismatch — one value is typed numeric, the other is not
        if (aNum.HasValue != bNum.HasValue && a is not null && b is not null)
            throw new XsltException("XTDE1030: Cannot compare sort keys of incompatible types (numeric vs non-numeric)");

        // XTDE1030: xs:duration values are not totally ordered and cannot be sorted
        if (a is XsDuration || b is XsDuration)
            throw new XsltException("XTDE1030: Cannot compare sort keys of type xs:duration (durations are not totally ordered)");

        // Detect type mismatch: comparing typed non-numeric values with strings is XTDE1030
        var aIsTyped = a is DateOnly or DateTimeOffset or TimeOnly or TimeSpan or XsDateTime or XsDate or XsTime or YearMonthDuration;
        var bIsTyped = b is DateOnly or DateTimeOffset or TimeOnly or TimeSpan or XsDateTime or XsDate or XsTime or YearMonthDuration;
        if (aIsTyped != bIsTyped && a is not null && b is not null)
            throw new XsltException("XTDE1030: Cannot compare sort keys of incompatible types");

        // Typed date/time/duration comparison — use CompareTo instead of string fallback
        if (aIsTyped && bIsTyped)
            return CompareValues(a!, b!);

        // Fall back to string comparison
        var aStr = a switch
        {
            null => "",
            string s => s,
            _ => StringValueOf(a)
        };
        var bStr = b switch
        {
            null => "",
            string s => s,
            _ => StringValueOf(b)
        };

        // Codepoint collation: use Ordinal (Unicode codepoint order)
        if (string.Equals(collation, "http://www.w3.org/2005/xpath-functions/collation/codepoint", StringComparison.Ordinal))
            return string.Compare(aStr, bStr, StringComparison.Ordinal);

        // HTML ASCII case-insensitive collation
        if (string.Equals(collation, "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive", StringComparison.Ordinal))
            return string.Compare(aStr, bStr, StringComparison.OrdinalIgnoreCase);

        // UCA collation (with optional parameters like strength=secondary for case-insensitive)
        if (collation != null && collation.StartsWith("http://www.w3.org/2013/collation/UCA", StringComparison.Ordinal))
            return string.Compare(aStr, bStr, CultureInfo.InvariantCulture, CompareOptions.IgnoreCase);

        // Use locale-aware comparison (default behavior per XSLT spec)
        CultureInfo culture;
        try
        {
            culture = !string.IsNullOrEmpty(lang) ? CultureInfo.GetCultureInfo(lang) : CultureInfo.InvariantCulture;
        }
        catch (CultureNotFoundException)
        {
            culture = CultureInfo.InvariantCulture;
        }

        var options = CompareOptions.None;
        if (string.Equals(caseOrder, "upper-first", StringComparison.OrdinalIgnoreCase))
        {
            // Upper-case letters sort before lower-case
            var cmp = string.Compare(aStr, bStr, culture, CompareOptions.IgnoreCase);
            if (cmp != 0)
                return cmp;
            // Tie-break: Ordinal puts uppercase first (A=0x41 < a=0x61)
            return string.Compare(aStr, bStr, StringComparison.Ordinal);
        }
        if (string.Equals(caseOrder, "lower-first", StringComparison.OrdinalIgnoreCase))
        {
            // Lower-case letters sort before upper-case
            var cmp = string.Compare(aStr, bStr, culture, CompareOptions.IgnoreCase);
            if (cmp != 0)
                return cmp;
            // Tie-break: negate Ordinal to put lowercase first
            return -string.Compare(aStr, bStr, StringComparison.Ordinal);
        }

        return string.Compare(aStr, bStr, culture, options);
    }
#pragma warning restore CA1309

    /// <summary>
    /// Attempts to extract a double from a sort key value.
    /// Returns non-null for numeric types or when forceNumeric is true.
    /// </summary>
    private static double? ToSortDouble(object? value, bool forceNumeric)
    {
        return value switch
        {
            double d => d,
            float f => (double)f,
            int i => (double)i,
            long l => (double)l,
            decimal m => (double)m,
            System.Numerics.BigInteger bi => (double)bi,
            short s => (double)s,
            byte b => (double)b,
            _ when forceNumeric => double.TryParse(StringValueOf(value), NumberStyles.Any,
                CultureInfo.InvariantCulture, out var parsed) ? parsed : double.NaN,
            _ => null
        };
    }

    /// <summary>
    /// Evaluates a with-param value, handling both select and content body.
    /// </summary>
    private async ValueTask<object?> EvaluateWithParamAsync(XsltWithParam param)
    {
        if (param.Select != null)
        {
            return await EvaluateAsync(param.Select).ConfigureAwait(false);
        }
        if (param.Content != null)
        {
            // If the param has a sequence type (as="type *" or as="type +"),
            // use the sequence accumulator to collect individual items
            var isSequenceType = param.As != null &&
                (param.As.Occurrence == Occurrence.ZeroOrMore || param.As.Occurrence == Occurrence.OneOrMore);

            if (isSequenceType)
            {
                var savedAccumulator = _sequenceAccumulator;
                _sequenceAccumulator = new List<object?>();

                var savedScope = new XsltTransformEngine.ScopedOutputBuffer(_output);
                var savedLogicalStart = _outputLogicalStart;
                _outputLogicalStart = _output.Length;
                _temporaryOutputDepth++;
                try
                { await param.Content.ExecuteAsync(this).ConfigureAwait(false); }
                finally { _temporaryOutputDepth--; }
                var textContent = savedScope.GetWritten();
                savedScope.Dispose();
                _outputLogicalStart = savedLogicalStart;

                var sequenceItems = new List<object?>();
                foreach (var item in _sequenceAccumulator)
                    if (item != null)
                        sequenceItems.Add(item);

                if (!string.IsNullOrEmpty(textContent) && _nodeStore != null && textContent.Contains('<', StringComparison.Ordinal))
                {
                    try
                    {
                        // Stream-parse rather than allocating a full XmlDocument.
                        var settings = new System.Xml.XmlReaderSettings
                        {
                            DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                            IgnoreWhitespace = false,
                            IgnoreComments = false,
                            IgnoreProcessingInstructions = false,
                        };
                        using var stringReader = new System.IO.StringReader($"<_seq_root_>{textContent}</_seq_root_>");
                        using var reader = System.Xml.XmlReader.Create(stringReader, settings);
                        var parsedChildren = new List<object?>();
                        ReadAsBodyChunkChildren(reader, parsedChildren);
                        foreach (var child in parsedChildren)
                        {
                            if (child is XdmNode cn)
                                cn.Parent = null;
                            sequenceItems.Add(child);
                        }
                    }
                    catch (System.Xml.XmlException)
                    {
                        sequenceItems.Add(new ResultTreeFragment(textContent));
                    }
                }
                else if (!string.IsNullOrEmpty(textContent))
                {
                    sequenceItems.Add(new Xdm.XsUntypedAtomic(StripXmlMarkup(textContent)));
                }

                _sequenceAccumulator = savedAccumulator;
                return sequenceItems.Count > 0 ? sequenceItems.ToArray() : Array.Empty<object?>();
            }

            var savedScope2 = new XsltTransformEngine.ScopedOutputBuffer(_output);
            var savedLogicalStart2 = _outputLogicalStart;
            _outputLogicalStart = _output.Length;
            // Save/restore sequence accumulator to prevent xsl:map/xsl:array
            // inside with-param content from leaking into the outer accumulator
            var savedAccum2 = _sequenceAccumulator;
            _sequenceAccumulator = new List<object?>();
            _temporaryOutputDepth++;
            try
            { await param.Content.ExecuteAsync(this).ConfigureAwait(false); }
            finally { _temporaryOutputDepth--; }
            var contentAccum = _sequenceAccumulator;
            _sequenceAccumulator = savedAccum2;
            var result = savedScope2.GetWritten();
            savedScope2.Dispose();
            _outputLogicalStart = savedLogicalStart2;
            // If the content produced typed items (maps, arrays, functions, nodes)
            // via sequence accumulator, use those directly instead of serialized output
            if (contentAccum.Count > 0 && string.IsNullOrEmpty(result))
            {
                object? paramValue = contentAccum.Count == 1 ? contentAccum[0] : contentAccum.ToArray();
                if (param.As != null)
                    paramValue = CoerceToType(paramValue, param.As);
                return paramValue;
            }
            // Wrap as RTF if content contains XML markup so copy-of preserves it
            object? paramValue2 = result.Contains('<', StringComparison.Ordinal) ? new ResultTreeFragment(result) : (object)new Xdm.XsUntypedAtomic(StripXmlMarkup(result));
            // Apply as="" type coercion on the with-param value
            if (param.As != null)
                paramValue2 = CoerceToType(paramValue2, param.As);
            return paramValue2;
        }
        // If 'as' specifies an optional/empty-allowed type, return empty sequence (null);
        // otherwise default to empty string (matches XSLT 1.0/2.0 behavior for untyped params).
        if (param.As != null && param.As.Occurrence is Occurrence.ZeroOrOne or Occurrence.ZeroOrMore)
            return null;
        return "";
    }

    private static int CompareValues(object? a, object? b)
    {
        if (a == null && b == null)
            return 0;
        if (a == null)
            return -1;
        if (b == null)
            return 1;

        return (a, b) switch
        {
            (string sa, string sb) => string.Compare(sa, sb, StringComparison.Ordinal),
            // Date/time/duration types implement IComparable<T> but not IComparable
            (Xdm.XsDateTime ldt, Xdm.XsDateTime rdt) => ldt.CompareTo(rdt),
            (Xdm.XsDate ld, Xdm.XsDate rd) => ld.CompareTo(rd),
            (Xdm.XsTime lt, Xdm.XsTime rt) => lt.CompareTo(rt),
            (Xdm.YearMonthDuration lym, Xdm.YearMonthDuration rym) => lym.CompareTo(rym),
            (Xdm.XsDuration lxd, Xdm.XsDuration rxd) => lxd.CompareTo(rxd),
            _ when IsNumeric(a) && IsNumeric(b) => CompareNumeric(a, b),
            (IComparable ca, _) => ca.CompareTo(b),
            _ => 0
        };
    }

    private static int CompareNumeric(object a, object b)
    {
        var da = a is System.Numerics.BigInteger abi ? (double)abi : Convert.ToDouble(a, CultureInfo.InvariantCulture);
        var db = b is System.Numerics.BigInteger bbi ? (double)bbi : Convert.ToDouble(b, CultureInfo.InvariantCulture);
        return da.CompareTo(db);
    }

    /// <summary>
    /// Serializes an XDM node to its XML string representation for passing to a sub-transform.
    /// </summary>
    internal string SerializeXdmNodeToXml(XdmNode node)
    {
        if (_nodeStore == null)
            return node.StringValue;
        var sb = new StringBuilder();
        SerializeXdmNodeToXml(node, sb);
        return sb.ToString();
    }

    private void SerializeXdmNodeToXml(XdmNode node, StringBuilder sb)
    {
        switch (node)
        {
            case XdmDocument doc:
                foreach (var child in _nodeStore!.GetChildren(doc))
                    SerializeXdmNodeToXml(child, sb);
                break;
            case XdmElement elem:
                var prefix = elem.Prefix;
                var localName = elem.LocalName;
                var qname = !string.IsNullOrEmpty(prefix) ? $"{prefix}:{localName}" : localName;
                sb.Append('<').Append(qname);
                foreach (var nsDecl in elem.NamespaceDeclarations)
                {
                    var nsUri = _nodeStore!.GetNamespaceUri(nsDecl.Namespace) ?? "";
                    if (string.IsNullOrEmpty(nsDecl.Prefix))
                        sb.Append(" xmlns=\"").Append(nsUri).Append('"');
                    else
                        sb.Append(" xmlns:").Append(nsDecl.Prefix).Append("=\"").Append(nsUri).Append('"');
                }
                foreach (var attr in _nodeStore!.GetAttributes(elem))
                {
                    var attrName = !string.IsNullOrEmpty(attr.Prefix) ? $"{attr.Prefix}:{attr.LocalName}" : attr.LocalName;
                    sb.Append(' ').Append(attrName).Append("=\"").Append(EscapeAttributeValue(attr.Value)).Append('"');
                }
                var children = _nodeStore.GetChildren(elem).ToList();
                if (children.Count == 0)
                {
                    sb.Append("/>");
                }
                else
                {
                    sb.Append('>');
                    foreach (var child in children)
                        SerializeXdmNodeToXml(child, sb);
                    sb.Append("</").Append(qname).Append('>');
                }
                break;
            case XdmText text:
                sb.Append(System.Security.SecurityElement.Escape(text.Value));
                break;
            case XdmComment comment:
                sb.Append("<!--").Append(comment.Value).Append("-->");
                break;
            case XdmProcessingInstruction pi:
                sb.Append("<?").Append(pi.Target);
                if (!string.IsNullOrEmpty(pi.Value))
                    sb.Append(' ').Append(pi.Value);
                sb.Append("?>");
                break;
        }
    }

    private IEnumerable<object> GetChildren(object? node)
    {
        if (node is XdmNode xdmNode && _nodeStore != null)
        {
            return _nodeStore.GetChildren(xdmNode).Cast<object>();
        }
        return [];
    }

    private static bool EffectiveBooleanValue(object? value)
    {
        return value switch
        {
            null => false,
            bool b => b,
            string s => s.Length > 0,
            Xdm.XsUntypedAtomic ua => ua.Value.Length > 0,
            Xdm.XsAnyUri uri => uri.Value.Length > 0,
            int i => i != 0,
            long l => l != 0,
            double d => d != 0 && !double.IsNaN(d),
            decimal m => m != 0,
            System.Numerics.BigInteger bi => !bi.IsZero,
            Xdm.Nodes.XdmNode => true,
            Xdm.TextNodeItem => true,
            ResultTreeFragment => true,
            System.Xml.XmlNode => true,
            System.Xml.Linq.XNode => true,
            IDictionary<object, object?> => throw new XsltException("FORG0006: Effective boolean value not defined for a map"),
            IEnumerable<object> seq => EbvOfSequence(seq),
            _ => throw new XsltException($"FORG0006: Effective boolean value not defined for type {value!.GetType().Name}")
        };
    }

    private static bool EbvOfSequence(IEnumerable<object> seq)
    {
        using var enumerator = seq.GetEnumerator();
        if (!enumerator.MoveNext())
            return false; // empty sequence
        var first = enumerator.Current;
        // First item is a node → true
        if (first is Xdm.Nodes.XdmNode or ResultTreeFragment or System.Xml.XmlNode or System.Xml.Linq.XNode)
            return true;
        // First item is atomic — only valid if single item
        if (!enumerator.MoveNext())
            return EffectiveBooleanValue(first); // single atomic → recurse
        // 2+ items starting with non-node → FORG0006
        throw new XsltException("FORG0006: Effective boolean value not defined for a sequence of two or more items starting with a non-node value");
    }

    /// <summary>
    /// Validates the return value of a template against its declared 'as' type (XTTE0505).
    /// </summary>
    private static void ValidateCollation(string? collationUri, string errorCode)
    {
        if (string.IsNullOrEmpty(collationUri))
            return;
        // Accept known collation URIs
        if (collationUri!.StartsWith("http://www.w3.org/2013/collation/UCA", StringComparison.Ordinal))
            return;
        if (collationUri == "http://www.w3.org/2005/xpath-functions/collation/codepoint")
            return;
        if (collationUri == "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive")
            return;
        if (collationUri == "http://saxon.sf.net/collation")
            return; // Saxon compatibility
        throw new XsltException($"{errorCode}: Unknown collation URI '{collationUri}'");
    }

    private void ValidateTemplateReturnType(XsltTemplate template, List<object?> resultItems)
    {
        if (template.As == null)
            return;

        var targetType = template.As.ItemType;
        var occurrence = template.As.Occurrence;
        // Include template identity in error messages for diagnostics
        var templateId = template.Name != null ? $" '{template.Name.Value.LocalName}'" :
            template.Match != null ? $" match=\"{template.Match}\"" : "";
        var locInfo = templateId;

        // Apply function conversion rules: atomize nodes for atomic target types
        var isAtomicTarget = targetType is not ItemType.Item and not ItemType.Node
            and not ItemType.Element and not ItemType.Text and not ItemType.Comment
            and not ItemType.ProcessingInstruction and not ItemType.Attribute
            and not ItemType.Document and not ItemType.Function and not ItemType.Map
            and not ItemType.Array;

        if (isAtomicTarget)
        {
            for (int i = 0; i < resultItems.Count; i++)
            {
                if (resultItems[i] is XdmNode node)
                    resultItems[i] = node.StringValue; // atomize: node → string
            }
        }

        var nonNullCount = resultItems.Count(i => i != null);

        // Cardinality check
        if (occurrence == Occurrence.Zero && nonNullCount != 0)
            throw Error($"XTTE0505: Template{locInfo} return value does not match declared type empty-sequence(): expected zero items, got {nonNullCount}");
        if (occurrence == Occurrence.Zero)
            return; // empty-sequence() — no item type check needed
        if (occurrence == Occurrence.ExactlyOne && nonNullCount != 1)
            throw Error($"XTTE0505: Template{locInfo} return value does not match declared type {template.As.ItemType}: expected exactly one item, got {nonNullCount}");
        if (occurrence == Occurrence.ZeroOrOne && nonNullCount > 1)
            throw Error($"XTTE0505: Template{locInfo} return value does not match declared type {template.As.ItemType}: expected zero or one item, got {nonNullCount}");
        if (occurrence == Occurrence.OneOrMore && nonNullCount == 0)
            throw Error($"XTTE0505: Template{locInfo} return value does not match declared type {template.As.ItemType}: expected one or more items, got 0");

        // Item type check — for atomic types, attempt coercion from string (function conversion rules)
        if (isAtomicTarget)
        {
            for (int i = 0; i < resultItems.Count; i++)
            {
                var item = resultItems[i];
                if (item == null)
                    continue;

                // Already the correct type?
                var alreadyMatches = (targetType, item) switch
                {
                    (ItemType.String, string) => true,
                    (ItemType.UntypedAtomic, string) => true,
                    (ItemType.UntypedAtomic, Xdm.XsUntypedAtomic) => true,
                    (ItemType.Integer, long) => true,
                    (ItemType.Integer, int) => true,
                    (ItemType.Double, double) => true,
                    (ItemType.Float, float) => true,
                    (ItemType.Decimal, decimal) => true,
                    (ItemType.Boolean, bool) => true,
                    (ItemType.AnyAtomicType, _) when item is not XdmNode => true,
                    (ItemType.Duration, TimeSpan or Xdm.DayTimeDuration or Xdm.YearMonthDuration or Xdm.XsDuration) => true,
                    (ItemType.YearMonthDuration, Xdm.YearMonthDuration) => true,
                    (ItemType.DayTimeDuration, TimeSpan or Xdm.DayTimeDuration) => true,
                    (ItemType.Date, Xdm.XsDate) => true,
                    (ItemType.DateTime, Xdm.XsDateTime) => true,
                    (ItemType.Time, Xdm.XsTime) => true,
                    (ItemType.AnyUri, Xdm.XsAnyUri) => true,
                    (ItemType.QName, QName) => true,
                    _ => false
                };
                if (alreadyMatches)
                    continue;

                // Attempt function conversion: cast string/untypedAtomic to target type
                var sv = item is string s ? s : item.ToString()!;
                var coerced = TryCoerceStringToType(sv, targetType);
                if (coerced != null)
                {
                    resultItems[i] = coerced;
                }
                else if (IsStrictlyIncompatible(sv, targetType))
                {
                    // Only raise error for clearly invalid conversions (e.g., "hello" → xs:double)
                    throw Error($"XTTE0505: Template{locInfo} return value '{sv}' cannot be cast to declared type {template.As.ItemType}");
                }
                // else: conversion failed but might be due to unsupported features (e.g., negative years);
                // pass the string value through to maintain previous behavior
            }
        }
        else if (targetType is not ItemType.Item and not ItemType.Node)
        {
            // Node type check
            foreach (var item in resultItems)
            {
                if (item == null)
                    continue;
                var matches = (targetType, item) switch
                {
                    (ItemType.Element, XdmElement el) =>
                        MatchesElementName(el, template.As.ElementName, template.As.ElementNamespace),
                    (ItemType.Text, XdmText or string or Xdm.TextNodeItem) => true,
                    (ItemType.Comment, XdmComment) => true,
                    (ItemType.ProcessingInstruction, XdmProcessingInstruction) => true,
                    (ItemType.Attribute, XdmAttribute) => true,
                    (ItemType.Document, XdmDocument doc) =>
                        template.As.DocumentElementName == null ||
                        doc.DocumentElementLocalName == template.As.DocumentElementName,
                    (ItemType.Function, XQueryFunction) => true,
                    (ItemType.Map, IDictionary<object, object?>) => true,
                    (ItemType.Array, List<object?>) => true,
                    _ => false
                };
                if (!matches)
                {
                    var valuePreview = item is string vs ? $"\"{(vs.Length > 80 ? vs[..80] + "…" : vs)}\"" : item.ToString() ?? "(null)";
                    if (valuePreview.Length > 100) valuePreview = valuePreview[..100] + "…";
                    throw Error($"XTTE0505: Template{locInfo} return value item of type {item.GetType().Name} does not match declared type {template.As.ItemType}; value={valuePreview}");
                }
            }
        }
    }

    /// <summary>
    /// Returns true if the string value is clearly incompatible with the target type
    /// (not just failing due to unsupported features like negative years).
    /// </summary>
    private static bool IsStrictlyIncompatible(string value, ItemType targetType)
    {
        var v = value.Trim();
        return targetType switch
        {
            // Numeric types: check if value looks like a number at all
            ItemType.Integer or ItemType.Decimal or ItemType.Double or ItemType.Float
                => !v.All(c => char.IsDigit(c) || c is '.' or '-' or '+' or 'e' or 'E' or 'N' or 'a' or 'I' or 'F')
                   || v.Length == 0,
            ItemType.Boolean => v is not ("true" or "false" or "1" or "0"),
            // For date/time/duration types, don't be strict — parsing can fail for many reasons
            _ => false
        };
    }

    /// <summary>
    /// Attempts to coerce a string value to the specified atomic type (function conversion rules).
    /// Returns the coerced value, or null if conversion is not possible.
    /// </summary>
    private static object? TryCoerceStringToType(string value, ItemType targetType)
    {
        try
        {
            return targetType switch
            {
                ItemType.String => value,
                ItemType.UntypedAtomic => new Xdm.XsUntypedAtomic(value),
                ItemType.Integer => long.TryParse(value.Trim(), out var l) ? l : null,
                ItemType.Decimal => decimal.TryParse(value.Trim(), System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var d) ? d : null,
                ItemType.Double => double.TryParse(value.Trim(), System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var dbl)
                    ? dbl
                    : value.Trim() is "INF" ? double.PositiveInfinity
                    : value.Trim() is "-INF" ? double.NegativeInfinity
                    : value.Trim() is "NaN" ? double.NaN
                    : null,
                ItemType.Float => float.TryParse(value.Trim(), System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var f)
                    ? f
                    : value.Trim() is "INF" ? float.PositiveInfinity
                    : value.Trim() is "-INF" ? float.NegativeInfinity
                    : value.Trim() is "NaN" ? float.NaN
                    : null,
                ItemType.Boolean => value.Trim() switch
                {
                    "true" or "1" => (object)true,
                    "false" or "0" => (object)false,
                    _ => null
                },
                ItemType.Duration => (object?)Xdm.XsDuration.Parse(value.Trim()),
                ItemType.YearMonthDuration => (object?)new Xdm.YearMonthDuration(
                    System.Xml.XmlConvert.ToTimeSpan(value.Trim()).Days / 30), // approximation
                ItemType.DayTimeDuration => (object?)System.Xml.XmlConvert.ToTimeSpan(value.Trim()),
                ItemType.Date => (object?)Xdm.XsDate.Parse(value.Trim()),
                ItemType.DateTime => (object?)Xdm.XsDateTime.Parse(value.Trim()),
                ItemType.Time => (object?)Xdm.XsTime.Parse(value.Trim()),
                ItemType.AnyUri => (object?)new Xdm.XsAnyUri(value.Trim()),
                ItemType.AnyAtomicType => value,
                _ => value // unknown atomic types: pass through as string
            };
        }
        catch (Exception ex) when (ex is not OutOfMemoryException and not StackOverflowException)
        {
            _ = ex; // suppress CA1031: conversion failure is expected
            return null; // conversion failed
        }
    }

    /// <summary>
    /// Flattens nested arrays and unwraps ResultTreeFragments into actual XDM nodes.
    /// Used before type checking variables declared as node types (element()*, document-node()*, etc.)
    /// </summary>
    private object?[] FlattenAndUnwrapToNodes(object?[] items, ItemType targetType = ItemType.Node, string? docElementName = null)
    {
        var result = new List<object?>();
        FlattenItems(items, result);
        return result.ToArray();

        void FlattenItems(object?[] arr, List<object?> output)
        {
            foreach (var item in arr)
            {
                if (item == null)
                    continue;
                if (item is object?[] nested)
                {
                    FlattenItems(nested, output);
                }
                else if (item is ResultTreeFragment rtf && _nodeStore != null)
                {
                    // When target type is document-node(), wrap RTF as a proper XdmDocument
                    // so instance-of checks work correctly
                    if (targetType == ItemType.Document)
                    {
                        var docNode = ParseResultTreeFragment(rtf);
                        if (docNode != null)
                        {
                            output.Add(docNode);
                        }
                        else
                        {
                            output.Add(item);
                        }
                    }
                    else
                    {
                        // Parse RTF XML content into actual XDM nodes (children only) —
                        // stream via XmlReader rather than allocating an XmlDocument and
                        // re-converting it. Same hot-path optimization as the as=-body
                        // assembly path.
                        try
                        {
                            var rtfSettings = new System.Xml.XmlReaderSettings
                            {
                                DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                                IgnoreWhitespace = false,
                                IgnoreComments = false,
                                IgnoreProcessingInstructions = false,
                            };
                            using var rtfStringReader = new System.IO.StringReader($"<_rtf_wrap_>{rtf.XmlContent}</_rtf_wrap_>");
                            using var rtfReader = System.Xml.XmlReader.Create(rtfStringReader, rtfSettings);
                            var rtfChildren = new List<object?>();
                            ReadAsBodyChunkChildren(rtfReader, rtfChildren);
                            foreach (var child in rtfChildren)
                            {
                                if (child is XdmNode xn)
                                    output.Add(xn);
                            }
                        }
                        catch (System.Xml.XmlException)
                        {
                            output.Add(item); // Keep as-is if unparseable
                        }
                    }
                }
                else
                {
                    output.Add(item);
                }
            }
        }
    }

    /// <summary>
    /// Checks if an item can be coerced to the target type via function conversion rules.
    /// Strings are treated as potentially untypedAtomic (castable to matching types).
    /// </summary>
    private static bool CanCoerceToItemType(object item, ItemType targetType)
    {
        if (XQuery.Execution.TypeCastHelper.MatchesItemType(item, targetType))
            return true;

        // Numeric promotion: integer → double/float, decimal → double/float, float → double
        if (targetType == ItemType.Double && item is int or long or float or decimal)
            return true;
        if (targetType == ItemType.Float && item is int or long)
            return true;
        if (targetType == ItemType.Decimal && item is int or long)
            return true;

        // UntypedAtomic can be cast to any atomic type
        if (item is Xdm.XsUntypedAtomic)
            return true;

        // xs:anyURI satisfies xs:string per XPath function conversion rules (F&O §1.6.3,
        // step 4): "If the supplied value is an instance of xs:anyURI ... and the
        // expected type is xs:string, the value is cast to xs:string." This was missing,
        // so `<xsl:variable as="xs:string" select="resolve-uri(...)">` raised XTTE0570.
        // Found while triaging Martin Honnen's Docbook TNG report — `templates.xsl`
        // declares such a variable and resolve-uri() returns xs:anyURI.
        if (item is Xdm.XsAnyUri && targetType == ItemType.String)
            return true;

        // XDM nodes can be atomized: extract string value and try coercion
        string? s = item switch
        {
            string str => str,
            XdmNode node => node.StringValue,
            Xdm.XsAnyUri uri => uri.Value,
            _ => null
        };

        if (s != null)
        {
            return targetType switch
            {
                ItemType.String or ItemType.AnyAtomicType => true,
                ItemType.Integer => long.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.Double => double.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.Decimal => decimal.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.Float => float.TryParse(s, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.Boolean => s is "true" or "false" or "0" or "1",
                ItemType.Date => DateOnly.TryParse(s, System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.DateTime => DateTimeOffset.TryParse(s, System.Globalization.CultureInfo.InvariantCulture, out _),
                ItemType.Time => TimeOnly.TryParse(s, System.Globalization.CultureInfo.InvariantCulture, out _),
                _ => true // for unknown types, be lenient
            };
        }

        return false;
    }

    /// <summary>
    /// Extracts the string value of any result (XDM node or primitive).
    /// </summary>
    internal static string StringValueOf(object? value)
    {
        return value switch
        {
            null => "",
            LazyValue lazy => StringValueOf(lazy.GetValueAsync().AsTask().GetAwaiter().GetResult()),
            XdmNode node => node.StringValue,
            ResultTreeFragment rtf => StripXmlMarkup(rtf.XmlContent),
            Xdm.TextNodeItem tni => tni.Value,
            Xdm.XsAnyUri uri => uri.Value,
            string s => s,
            bool b => b ? "true" : "false",
            double d => FormatDouble(d),
            float f => FormatFloat(f),
            decimal m => FormatDecimal(m),
            XsDateTime xdt => xdt.ToString(),
            XsDate xd => xd.ToString(),
            XsTime xt => xt.ToString(),
            DateTimeOffset dto => FormatDateTimeOffset(dto),
            DateOnly dateOnly => dateOnly.ToString("yyyy-MM-dd", System.Globalization.CultureInfo.InvariantCulture),
            TimeOnly timeOnly => timeOnly.ToString("HH:mm:ss", System.Globalization.CultureInfo.InvariantCulture),
            TimeSpan ts => System.Xml.XmlConvert.ToString(ts),
            IDictionary<object, object?> => throw new XsltException("FOTY0013: Atomization is not defined for maps"),
            List<object?> arrayList => string.Join(" ", arrayList.Select(StringValueOf)),
            XQueryFunction => throw new XsltException("FOTY0013: Atomization is not defined for function items"),
            object[] arr => string.Join(" ", arr.Select(StringValueOf)),
            IEnumerable<object?> seq => string.Join(" ", seq.Select(StringValueOf)),
            _ => value.ToString() ?? ""
        };
    }

    /// <summary>
    /// Coerces a value to match the specified XDM sequence type.
    /// </summary>
    private static object? CoerceToType(object? value, XdmSequenceType targetType)
    {
        if (value == null)
            return null;
        // For sequence types (*, +), coerce each item individually rather than
        // joining the whole array into a single value (e.g., xs:string* should
        // produce an array of strings, not one space-joined string).
        if (value is object?[] arr && arr.Length > 1 &&
            targetType.Occurrence is Occurrence.ZeroOrMore or Occurrence.OneOrMore)
        {
            var coerced = new object?[arr.Length];
            for (int i = 0; i < arr.Length; i++)
                coerced[i] = CoerceToType(arr[i], targetType);
            return coerced;
        }
        return targetType.ItemType switch
        {
            ItemType.String => StringValueOf(value),
            ItemType.Integer => value is long ? value : long.TryParse(StringValueOf(value), out var l) ? l : value,
            // xs:integer is a subtype of xs:decimal — accept int/long without conversion
            ItemType.Decimal => value is decimal or int or long ? value : decimal.TryParse(StringValueOf(value), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var d) ? d : value,
            ItemType.Double => value is double ? value : double.TryParse(StringValueOf(value), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var dbl) ? dbl : value,
            ItemType.Boolean => CoerceToBoolean(value),
            ItemType.GYear => value is Xdm.XsGYear ? value : new Xdm.XsGYear(StringValueOf(value)),
            ItemType.GYearMonth => value is Xdm.XsGYearMonth ? value : new Xdm.XsGYearMonth(StringValueOf(value)),
            ItemType.GMonthDay => value is Xdm.XsGMonthDay ? value : new Xdm.XsGMonthDay(StringValueOf(value)),
            ItemType.GDay => value is Xdm.XsGDay ? value : new Xdm.XsGDay(StringValueOf(value)),
            ItemType.GMonth => value is Xdm.XsGMonth ? value : new Xdm.XsGMonth(StringValueOf(value)),
            ItemType.UntypedAtomic => value is Xdm.XsUntypedAtomic ? value : new Xdm.XsUntypedAtomic(StringValueOf(value)),
            _ => value
        };
    }

    /// <summary>
    /// Coerces an arbitrary value to xs:boolean. Recognizes the lexical forms accepted
    /// by xs:boolean (<c>"true"</c>, <c>"false"</c>, <c>"1"</c>, <c>"0"</c>) regardless
    /// of whether the source is xs:string, xs:untypedAtomic, or already a .NET bool.
    /// Previously only xs:untypedAtomic was converted, which broke
    /// <c>&lt;xsl:variable as="xs:boolean"&gt;...&lt;xsl:sequence select="false()"/&gt;...&lt;/xsl:variable&gt;</c>:
    /// the body's xs:boolean was serialized to text output as <c>"false"</c>, then
    /// failed to coerce back. Found in Docbook TNG <c>$process</c> evaluation.
    /// </summary>
    private static object CoerceToBoolean(object? value)
    {
        return value switch
        {
            bool b => b,
            Xdm.XsUntypedAtomic ua => StringValueOf(ua) is "true" or "1",
            string s => s is "true" or "1" ? true
                       : s is "false" or "0" ? (object)false
                       : value!, // unrecognized lexical form — leave alone, downstream check will catch
            _ => value!
        };
    }

    /// <summary>
    /// Applies XSLT 3.0 §5.4.1 function conversion rules:
    /// 1. Atomize node values  2. Cast untypedAtomic to target type  3. Numeric promotion
    /// </summary>
    private static object? ApplyFunctionConversionRules(object? value, XdmSequenceType targetType)
    {
        if (value == null) return null;

        // For sequences, apply rules to each item
        if (value is object?[] arr)
        {
            var result = new object?[arr.Length];
            for (int i = 0; i < arr.Length; i++)
                result[i] = ApplyFunctionConversionRulesSingle(arr[i], targetType);
            return result;
        }

        return ApplyFunctionConversionRulesSingle(value, targetType);
    }

    private static object? ApplyFunctionConversionRulesSingle(object? value, XdmSequenceType targetType)
    {
        if (value == null) return null;

        // Only atomize nodes when the target type is an atomic type (not node/item/function types)
        if (!IsNodeType(targetType.ItemType) && targetType.ItemType is not ItemType.Item
            and not ItemType.Map and not ItemType.Array and not ItemType.Function)
        {
            // Step 1: Atomize nodes → produces xs:untypedAtomic (for non-schema-aware processors)
            if (value is Xdm.Nodes.XdmNode or System.Xml.XmlNode or System.Xml.Linq.XNode)
                value = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AtomizeTyped(value);

            if (value == null) return null;

            // Step 2: Cast xs:untypedAtomic to target type (ONLY untypedAtomic gets implicit casting)
            if (value is Xdm.XsUntypedAtomic)
                return CoerceToType(value, targetType);

            // Step 3: Numeric promotion (xs:integer → xs:double, xs:float → xs:double, etc.)
            if (targetType.ItemType == ItemType.Double && value is int or long or float or decimal)
                return Convert.ToDouble(value, System.Globalization.CultureInfo.InvariantCulture);
            if (targetType.ItemType == ItemType.Float && value is int or long or decimal)
                return Convert.ToSingle(value, System.Globalization.CultureInfo.InvariantCulture);
            if (targetType.ItemType == ItemType.Decimal && value is int or long)
                return Convert.ToDecimal(value, System.Globalization.CultureInfo.InvariantCulture);

            // No implicit casting for other type mismatches (e.g., xs:string → xs:integer)
            return value;
        }

        return value;
    }

    /// <summary>
    /// Checks whether a target type is a strict atomic type where type mismatches
    /// should always be reported as errors (not silently accepted).
    /// </summary>
    /// <summary>
    /// Checks if an element matches a declared element name, handling both simple names
    /// and EQName syntax (Q{uri}local or uri}local after Q{ is stripped).
    /// </summary>
    /// <summary>
    /// Per XSLT 3.0 §2.5.5, an element(QName) test matches when both the element's local name
    /// and (when constrained) its namespace URI agree with the declared name. The earlier
    /// implementation only checked local name, so e.g. element(Q{xhtml}html) accepted an
    /// element named "html" in any namespace — including the null namespace produced by the
    /// xsl:copy copy-namespaces="no" bug fixed in 1.3.5.
    /// </summary>
    private bool MatchesElementName(XdmElement el, string? declaredLocalName, string? declaredNamespace)
    {
        if (declaredLocalName != null)
        {
            // EQName: strip Q{uri}local form to bare local part for comparison
            var localPart = declaredLocalName;
            var closeBrace = declaredLocalName.LastIndexOf('}');
            if (closeBrace >= 0 && closeBrace < declaredLocalName.Length - 1)
                localPart = declaredLocalName[(closeBrace + 1)..];
            if (el.LocalName != localPart)
                return false;
        }
        if (declaredNamespace != null)
        {
            var elNs = _nodeStore?.GetNamespaceUri(el.Namespace) ?? "";
            if (elNs != declaredNamespace)
                return false;
        }
        return true;
    }

    private static bool IsStrictAtomicType(ItemType type) => type is
        ItemType.Integer or ItemType.Double or ItemType.Float or ItemType.Decimal
        or ItemType.Date or ItemType.DateTime or ItemType.Time
        or ItemType.Duration or ItemType.YearMonthDuration or ItemType.DayTimeDuration
        or ItemType.Boolean or ItemType.QName;

    /// <summary>Public alias used by the engine's global-variable initialization path.</summary>
    internal static bool IsStrictAtomicTypePublic(ItemType type) => IsStrictAtomicType(type);

    /// <summary>Public alias used by the engine's global-variable initialization path.</summary>
    internal static object? TryCoerceStringToTypePublic(string value, ItemType targetType) =>
        TryCoerceStringToType(value, targetType);

    /// <summary>
    /// Returns true for any atomic type (strict + string/anyURI/untypedAtomic).
    /// Used for TextNodeItem coercion in function return values — atomizing a text
    /// node always produces a string, which can then be cast to the target type.
    /// </summary>
    private static bool IsAtomicReturnType(ItemType type) =>
        IsStrictAtomicType(type) || type is ItemType.String or ItemType.AnyUri
            or ItemType.UntypedAtomic or ItemType.AnyAtomicType;

    private static bool IsNodeType(ItemType type) => type is
        ItemType.Node or ItemType.Element or ItemType.Attribute or ItemType.Text
        or ItemType.Comment or ItemType.ProcessingInstruction or ItemType.Document;

    /// <summary>
    /// Validates that function item(s) passed as arguments are coercible to the required
    /// typed function type. Per XSLT 3.0 §5.4.3, function coercion checks arity but
    /// allows broader declared types — the wrapper validates at invocation time.
    /// Raises XPTY0004 only for arity mismatches (non-coercible).
    /// </summary>
    private static void ValidateFunctionTypeArgument(object? value, XdmSequenceType targetType,
        string paramName, string funcName)
    {
        if (value == null) return;

        var requiredArity = targetType.FunctionParameterTypes!.Count;
        var items = value is object?[] arr ? arr : new[] { value };
        foreach (var item in items)
        {
            if (item is PhoenixmlDb.XQuery.Ast.XQueryFunction fn)
            {
                // Function coercion only fails for arity mismatch (XSLT 3.0 §5.4.11)
                // Type incompatibilities are detected later when the coerced function is invoked
                if (fn.Arity != requiredArity)
                {
                    throw new XsltException(
                        $"XPTY0004: Function item passed to parameter ${paramName} in function {funcName} " +
                        $"has arity {fn.Arity} but required type expects arity {requiredArity}");
                }
            }
            else if (item != null)
            {
                // Non-function item where function expected
                throw new XsltException(
                    $"XPTY0004: Non-function item passed to parameter ${paramName} in function {funcName} " +
                    $"where function type is required");
            }
        }
    }

    /// <summary>
    /// Wraps callable items in coercion wrappers per XSLT 3.0 §5.4.11.
    /// The wrapper validates return types at invocation time.
    /// </summary>
    private static object? WrapInCoercionWrapper(object? value, XdmSequenceType targetType)
    {
        if (value == null) return null;

        var paramTypes = targetType.FunctionParameterTypes!;
        var returnType = targetType.FunctionReturnType!;

        if (value is object?[] arr)
        {
            var wrapped = new object?[arr.Length];
            for (int i = 0; i < arr.Length; i++)
            {
                if (arr[i] is PhoenixmlDb.XQuery.Ast.XQueryFunction fn)
                    wrapped[i] = new FunctionCoercionWrapper(fn, paramTypes, returnType);
                else
                    wrapped[i] = arr[i];
            }
            return wrapped;
        }

        if (value is PhoenixmlDb.XQuery.Ast.XQueryFunction singleFn)
            return new FunctionCoercionWrapper(singleFn, paramTypes, returnType);

        return value;
    }

    /// <summary>
    /// Checks if a value is compatible with a target type after applying
    /// XSLT function conversion rules (including numeric promotion and untypedAtomic casting).
    /// </summary>
    private static bool IsTypeCompatible(object? value, ItemType targetType)
    {
        if (value == null)
            return false;
        if (XQuery.Execution.TypeCastHelper.MatchesItemType(value, targetType))
            return true;

        // UntypedAtomic → any atomic type (per XSLT function conversion rules)
        if (value is Xdm.XsUntypedAtomic)
            return true;

        // Numeric promotion: integer → double, integer → decimal, float → double
        return targetType switch
        {
            ItemType.Double => value is int or long or float or decimal,
            ItemType.Decimal => value is int or long,
            ItemType.Float => value is int or long,
            _ => false
        };
    }

    /// <summary>
    /// Validates that a value matches the declared type after coercion.
    /// Only validates strict atomic types to avoid false positives with
    /// string/node/anyURI/untypedAtomic coercion paths.
    /// </summary>
    internal void ValidateValueMatchesType(object? value, XdmSequenceType targetType, string errorCode, string contextName)
    {
        // Validate node types: when the target is a node type, non-node values must fail.
        // Only apply to with-param/tunnel-param paths (XTTE0590), not default value paths
        // (XTTE0600) since content constructors may not properly capture all node types.
        if (IsNodeType(targetType.ItemType) && errorCode is "XTTE0590" or "XTTE0780")
        {
            if (value == null)
            {
                if (targetType.Occurrence is Occurrence.ExactlyOne or Occurrence.OneOrMore)
                    throw Error($"{errorCode}: {contextName} requires a node but the empty sequence was supplied");
                return;
            }
            // Check single value
            if (value is not object?[])
            {
                ValidateSingleNodeAgainstType(value, targetType, errorCode, contextName);
                return;
            }
            // For sequences, check each item
            if (value is object?[] nodeArr)
            {
                foreach (var item in nodeArr)
                    if (item != null)
                        ValidateSingleNodeAgainstType(item, targetType, errorCode, contextName);
                return;
            }
            return;
        }

        // Only validate strict atomic types — string, anyURI, etc. have
        // complex coercion rules that can't be validated simply after CoerceToType
        if (!IsStrictAtomicType(targetType.ItemType))
            return;

        if (value == null)
        {
            if (targetType.Occurrence == Occurrence.ExactlyOne || targetType.Occurrence == Occurrence.OneOrMore)
                throw Error($"{errorCode}: {contextName} requires a value of type {targetType.ItemType} but the empty sequence was supplied");
            return;
        }

        // For arrays (sequences), check each item
        if (value is object?[] arr)
        {
            if (arr.Length == 0 && (targetType.Occurrence == Occurrence.ExactlyOne || targetType.Occurrence == Occurrence.OneOrMore))
                throw Error($"{errorCode}: {contextName} requires a value of type {targetType.ItemType} but the empty sequence was supplied");

            foreach (var item in arr)
            {
                if (item != null && !IsTypeCompatible(item, targetType.ItemType))
                    throw Error($"{errorCode}: {contextName} requires type {targetType.ItemType} but got {item.GetType().Name}");
            }
            return;
        }

        // Single item — check type with promotion rules
        if (!IsTypeCompatible(value, targetType.ItemType))
            throw Error($"{errorCode}: {contextName} requires type {targetType.ItemType} but got {value.GetType().Name}");
    }

    /// <summary>
    /// Per XSLT 3.0 §3.7 (sequence-type matching): validates a single value against a node-typed
    /// declaration, including element/attribute name and namespace constraints (element(QName),
    /// attribute(QName), document-node(element(QName)), processing-instruction("name")).
    ///
    /// The node-type branch of <see cref="ValidateValueMatchesType"/> previously only checked
    /// "is it a node?" — it accepted strings, ResultTreeFragments, and elements in the wrong
    /// namespace. That gap was the reason several recent typed-shape bugs surfaced only as
    /// downstream XPTY0020 axis-step errors instead of XTTE0780 at the construction boundary.
    /// </summary>
    private void ValidateSingleNodeAgainstType(object value, XdmSequenceType targetType, string errorCode, string contextName)
    {
        // ResultTreeFragment is opaque markup — we accept it for any node type since the
        // caller will (re)parse on first axis access. Refining ResultTreeFragment further
        // would force eager parsing of every variable body for the validator's sake.
        if (value is ResultTreeFragment)
            return;

        if (value is not XdmNode node)
            throw Error($"{errorCode}: {contextName} requires type {targetType.ItemType} but got {value.GetType().Name}");

        var matches = (targetType.ItemType, node) switch
        {
            (ItemType.Node, _) => true,
            (ItemType.Element, XdmElement el) =>
                MatchesElementName(el, targetType.ElementName, targetType.ElementNamespace),
            (ItemType.Attribute, XdmAttribute attr) =>
                (targetType.AttributeName == null || attr.LocalName == targetType.AttributeName)
                && (targetType.AttributeNamespace == null
                    || (_nodeStore?.GetNamespaceUri(attr.Namespace) ?? "") == targetType.AttributeNamespace),
            (ItemType.Text, XdmText) => true,
            (ItemType.Comment, XdmComment) => true,
            (ItemType.ProcessingInstruction, XdmProcessingInstruction pi) =>
                targetType.PIName == null || pi.Target == targetType.PIName,
            (ItemType.Document, XdmDocument doc) =>
                targetType.DocumentElementName == null
                || doc.DocumentElementLocalName == targetType.DocumentElementName,
            _ => false
        };

        if (!matches)
        {
            var what = node switch
            {
                XdmElement el => el.Prefix != null
                    ? $"element {el.Prefix}:{el.LocalName} (Q{{{_nodeStore?.GetNamespaceUri(el.Namespace) ?? ""}}}{el.LocalName})"
                    : $"element {el.LocalName} in namespace \"{_nodeStore?.GetNamespaceUri(el.Namespace) ?? ""}\"",
                XdmAttribute attr => $"attribute {attr.LocalName}",
                XdmText => "text node",
                XdmComment => "comment",
                XdmProcessingInstruction pi => $"processing-instruction({pi.Target})",
                XdmDocument doc => $"document-node(element({doc.DocumentElementLocalName ?? "?"}))",
                _ => node.GetType().Name
            };
            var declared = targetType.ElementName != null
                ? $"{targetType.ItemType}({(targetType.ElementNamespace != null ? "Q{" + targetType.ElementNamespace + "}" : "")}{targetType.ElementName})"
                : targetType.ItemType.ToString();
            throw Error($"{errorCode}: {contextName} requires type {declared} but got {what}");
        }
    }

    /// <summary>
    /// Enforces xsl:context-item constraints on a template invocation.
    /// Returns true if the context item should be made absent (use="optional" with type mismatch).
    /// </summary>
    private bool EnforceContextItemConstraint(XsltTemplate template)
    {
        var ci = ContextItem;
        var isAbsent = ci == null || ci == PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus;

        switch (template.ContextItemUse)
        {
            case ContextItemUse.Required when isAbsent:
                throw Error("XTTE3090: The template requires a context item, but none has been supplied");
            case ContextItemUse.Absent:
                // Context item will be made absent within the template body (handled at call site)
                return false;
        }

        // Type checking: if as attribute is specified, verify the context item matches
        if (template.ContextItemAs != null && !isAbsent)
        {
            var typeMatches = XQuery.Execution.TypeCastHelper.MatchesSequenceItemType(ci, template.ContextItemAs);

            // Additional check for document-node(element(name)): verify document element name
            if (typeMatches && template.ContextItemAs.DocumentElementName != null
                && ci is Xdm.Nodes.XdmDocument doc && _nodeStore != null)
            {
                var docElem = doc.Children
                    .Select(id => _nodeStore.GetNode(id))
                    .OfType<Xdm.Nodes.XdmElement>()
                    .FirstOrDefault();
                if (docElem == null || docElem.LocalName != template.ContextItemAs.DocumentElementName)
                    typeMatches = false;
            }

            if (!typeMatches)
            {
                if (template.ContextItemUse == ContextItemUse.Optional)
                {
                    // XSLT 3.0 §9.6.2: If use="optional" and the context item doesn't match the type,
                    // the template executes as if the context item were absent.
                    return true;
                }
                throw Error("XTTE0590: The context item does not match the required type declared by xsl:context-item");
            }
        }
        return false;
    }

    /// <summary>
    /// Compares two composite keys for value equality using XQuery deep-equal semantics.
    /// Numeric values are compared by value (5 == 5.0 == 5m).
    /// </summary>
    /// <summary>
    /// Generates a canonical string key for group-by/group-adjacent comparison.
    /// Per XSLT 3.0 §15.3, grouping uses the eq operator for comparison.
    /// QNames compare by namespace URI + local name (ignoring prefix).
    /// </summary>
    private string GroupingKeyString(object? key)
    {
        if (key is PhoenixmlDb.Core.QName qn)
        {
            // Use expanded name for QName comparison — prefixes are irrelevant
            var ns = qn.ResolvedNamespace ?? _nodeStore?.GetNamespaceUri(qn.Namespace) ?? "";
            return string.IsNullOrEmpty(ns) ? qn.LocalName : $"Q{{{ns}}}{qn.LocalName}";
        }
        return StringValueOf(key);
    }

    private static bool CompositeKeysEqual(List<object?> key1, List<object?> key2, StringComparer? comparer = null)
    {
        if (key1.Count != key2.Count)
            return false;

        for (int i = 0; i < key1.Count; i++)
        {
            if (!ValuesEqual(key1[i], key2[i], comparer))
                return false;
        }
        return true;
    }

    /// <summary>
    /// Compares two atomic values for equality using XQuery semantics.
    /// </summary>
    private static bool ValuesEqual(object? a, object? b, StringComparer? comparer = null)
    {
        if (ReferenceEquals(a, b))
            return true;
        if (a is null || b is null)
            return a is null && b is null;

        // Numeric comparison: use XPath type promotion rules (§B.2)
        // float vs double → both to double; decimal vs float → both to float;
        // decimal vs double → both to double; integer vs X → both to X
        if (IsNumeric(a) && IsNumeric(b))
        {
            bool aIsFloat = a is float;
            bool bIsFloat = b is float;
            bool aIsDecimal = a is decimal;
            bool bIsDecimal = b is decimal;
            // decimal vs float: promote decimal to float (NOT to double)
            if ((aIsDecimal && bIsFloat) || (aIsFloat && bIsDecimal))
            {
                var fa = Convert.ToSingle(a, CultureInfo.InvariantCulture);
                var fb = Convert.ToSingle(b, CultureInfo.InvariantCulture);
                if (float.IsNaN(fa) || float.IsNaN(fb))
                    return false;
                return fa == fb;
            }
            // All other numeric combinations: promote to double
            var da = a is System.Numerics.BigInteger abi ? (double)abi : Convert.ToDouble(a, CultureInfo.InvariantCulture);
            var db = b is System.Numerics.BigInteger bbi ? (double)bbi : Convert.ToDouble(b, CultureInfo.InvariantCulture);
            if (double.IsNaN(da) || double.IsNaN(db))
                return false;
            return da == db;
        }

        var cmp = comparer ?? StringComparer.Ordinal;

        // For XDM nodes, compare string values
        if (a is XdmNode na && b is XdmNode nb)
            return cmp.Equals(na.StringValue, nb.StringValue);
        if (a is XdmNode nodeA)
            return cmp.Equals(nodeA.StringValue, StringValueOf(b));
        if (b is XdmNode nodeB)
            return cmp.Equals(StringValueOf(a), nodeB.StringValue);

        // String-like comparisons: treat XsUntypedAtomic and XsAnyUri as strings
        var sa = a is string s1 ? s1 : a is Xdm.XsUntypedAtomic ua1 ? ua1.Value : a is Xdm.XsAnyUri u1 ? u1.Value : null;
        var sb = b is string s2 ? s2 : b is Xdm.XsUntypedAtomic ua2 ? ua2.Value : b is Xdm.XsAnyUri u2 ? u2.Value : null;
        if (sa != null && sb != null)
            return cmp.Equals(sa, sb);
        if (sa != null || sb != null)
            return cmp.Equals(sa ?? StringValueOf(a), sb ?? StringValueOf(b));

        return object.Equals(a, b);
    }

    private static bool IsNumeric(object? value)
    {
        return value is byte or sbyte or short or ushort or int or uint
            or long or ulong or float or double or decimal or System.Numerics.BigInteger;
    }

    private static string FormatDateTimeOffset(DateTimeOffset dto)
    {
        // Use Z for UTC offsets (XML Schema canonical form) instead of +00:00
        var formatted = dto.ToString("yyyy-MM-ddTHH:mm:ss", System.Globalization.CultureInfo.InvariantCulture);
        if (dto.Offset == TimeSpan.Zero)
            return formatted + "Z";
        return formatted + dto.ToString("zzz", System.Globalization.CultureInfo.InvariantCulture);
    }

    internal static string FormatDouble(double d) => XQuery.Functions.ConcatFunction.FormatDoubleXPath(d);

    internal static string FormatFloat(float f) => XQuery.Functions.ConcatFunction.FormatFloatXPath(f);

    private static string FormatDecimal(decimal m)
    {
        // XPath canonical decimal format: no trailing zeros, no leading zeros (except single 0 before decimal point)
        // E.g., 5.0 -> "5", 5.00 -> "5", 0.5 -> "0.5", -0.5 -> "-0.5"
        var s = m.ToString("G", CultureInfo.InvariantCulture);
        // Remove trailing zeros after decimal point
        if (s.Contains('.', StringComparison.Ordinal))
        {
            s = s.TrimEnd('0').TrimEnd('.');
        }
        return s == "-0" ? "0" : s;
    }

    /// <summary>
    /// Output a value to the result tree as text.
    /// </summary>
    private void OutputValue(object? value)
    {
        if (value == null)
            return;

        // XTDE0450: Maps and function items cannot be added to element/document content
        if (value is IDictionary<object, object?>)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a map");
        if (value is PhoenixmlDb.XQuery.Ast.XQueryFunction)
            throw Error("XTDE0450: An item in a sequence used as the content of an element or document node is a function item");
        // XSLT 3.0 §5.7.2: Arrays are flattened — serialize each member
        if (value is List<object?> arrayList)
        {
            foreach (var member in arrayList)
                OutputValue(member);
            return;
        }

        var text = StringValueOf(value);
        if (!string.IsNullOrEmpty(text))
        {
            _output.Append(EscapeText(text));
        }
    }

    /// <summary>
    /// Output the result of xsl:evaluate. Node results are serialized (deep-copied like
    /// xsl:copy-of), while atomic values are output as text. Sequences of atomic values
    /// are space-separated per XSLT sequence serialization rules.
    /// </summary>
    private void OutputEvaluateResult(object? value)
    {
        if (value == null)
            return;

        if (value is object?[] arr)
        {
            // Check if any item is a node — if so, serialize each item individually
            var hasNodes = false;
            foreach (var item in arr)
            {
                if (item is XdmNode or XdmAttribute or System.Xml.XmlNode or System.Xml.Linq.XNode)
                {
                    hasNodes = true;
                    break;
                }
            }
            if (hasNodes)
            {
                for (int i = 0; i < arr.Length; i++)
                {
                    if (arr[i] is XdmNode or XdmAttribute or System.Xml.XmlNode or System.Xml.Linq.XNode)
                        SerializeNode(arr[i]!);
                    else if (arr[i] != null)
                    {
                        var text = StringValueOf(arr[i]);
                        if (!string.IsNullOrEmpty(text))
                            _output.Append(EscapeText(text));
                    }
                }
                return;
            }
            // All atomic values — fall through to OutputValue for space-separated output
            OutputValue(value);
            return;
        }

        // Single node result: serialize (deep-copy) to output
        if (value is XdmNode or XdmAttribute or System.Xml.XmlNode or System.Xml.Linq.XNode)
        {
            SerializeNode(value);
            return;
        }

        // Atomic values: output as text
        OutputValue(value);
    }

    private static bool IsXmlWhitespaceOnly(string? value)
    {
        if (string.IsNullOrEmpty(value))
            return true;
        foreach (var c in value)
        {
            if (c != ' ' && c != '\t' && c != '\r' && c != '\n')
                return false;
        }
        return true;
    }

    private static string EscapeText(string text)
        => CharacterEscaper.EscapeXmlText(text);

    private static string EscapeAttributeValue(string value)
        => CharacterEscaper.EscapeXmlAttribute(value);

    private int _nsPrefixCounter;
    private string GenerateNsPrefix(string nsUri)
    {
        // Use well-known prefixes for common namespaces
        if (nsUri == "http://www.w3.org/1999/xhtml")
            return "xhtml";
        if (nsUri == "http://www.w3.org/2000/svg")
            return "svg";
        if (nsUri == "http://www.w3.org/1999/XSL/Transform")
            return "xsl";
        return $"ns{_nsPrefixCounter++}";
    }

    private static string EscapeCommentValue(string value)
    {
        value = value.Replace("--", "- -", StringComparison.Ordinal);
        if (value.EndsWith('-'))
            value += " ";
        return value;
    }

    private static string EscapePIValue(string value)
    {
        return value.Replace("?>", "? >", StringComparison.Ordinal);
    }

    /// <summary>
    /// HTML void elements that should not have closing tags.
    /// </summary>
    private static readonly HashSet<string> HtmlVoidElements = new(StringComparer.OrdinalIgnoreCase)
    {
        "area", "base", "br", "col", "embed", "hr", "img", "input",
        "link", "meta", "param", "source", "track", "wbr"
    };

    /// <summary>
    /// Post-processes output for HTML/XHTML method.
    /// Converts self-closing void elements to HTML style and expands non-void self-closing elements.
    /// </summary>
    internal static string PostProcessHtmlOutput(string output)
    {
        // Convert <br/> → <br> for void elements, <div/> → <div></div> for non-void
        var sb = new StringBuilder(output.Length);
        var i = 0;
        while (i < output.Length)
        {
            if (output[i] == '<' && i + 1 < output.Length && output[i + 1] != '/' && output[i + 1] != '!' && output[i + 1] != '?')
            {
                // Opening tag - find tag name and check for self-closing
                var tagStart = i;
                i++; // skip '<'
                var nameStart = i;
                while (i < output.Length && output[i] != ' ' && output[i] != '>' && output[i] != '/' && output[i] != '\t' && output[i] != '\n' && output[i] != '\r')
                    i++;
                var tagName = output[nameStart..i];

                // Find end of tag
                while (i < output.Length && output[i] != '>')
                    i++;

                if (i > 0 && output[i - 1] == '/')
                {
                    // Self-closing tag: <tag ... />
                    if (HtmlVoidElements.Contains(tagName))
                    {
                        // Void element: output without /> → just >
                        sb.Append(output.AsSpan(tagStart, i - 1 - tagStart)); // everything up to /
                        sb.Append('>');
                    }
                    else
                    {
                        // Non-void: expand <tag/> → <tag></tag>
                        sb.Append(output.AsSpan(tagStart, i - 1 - tagStart)); // everything up to /
                        sb.Append("></");
                        sb.Append(tagName);
                        sb.Append('>');
                    }
                    if (i < output.Length)
                        i++; // skip >
                }
                else
                {
                    // Normal opening tag
                    sb.Append(output.AsSpan(tagStart, i + 1 - tagStart));
                    if (i < output.Length)
                        i++;
                }
            }
            else
            {
                sb.Append(output[i]);
                i++;
            }
        }
        return sb.ToString();
    }

    /// <summary>
    /// Inserts a meta element with Content-Type as the first child of head elements.
    /// Per XSLT serialization spec: when include-content-type is "yes" (default for html/xhtml).
    /// </summary>
    internal static string InsertContentTypeMeta(string output, XsltOutput outputDecl)
    {
        var encoding = outputDecl.Encoding ?? "UTF-8";
        var mediaType = outputDecl.MediaType ?? "text/html";
        var content = $"{mediaType}; charset={encoding}";

        string metaElement;
        if (outputDecl.EffectiveMethod == OutputMethod.Xhtml)
            metaElement = $"<meta http-equiv=\"Content-Type\" content=\"{content}\" />";
        else
            metaElement = $"<meta http-equiv=\"Content-Type\" content=\"{content}\">";

        // Find <head> or <head ...> tags and insert meta as first child.
        // Per XSLT 3.0 §27.6.4 (HTML/XHTML output): the serializer adds a Content-Type
        // meta only if one is not already present in the head. Without this check,
        // a stylesheet that emits its own meta (e.g. Docbook TNG's XHTML-style
        // `<meta http-equiv="Content-Type" content="…" />`) ends up with two of them.
        var result = output;
        var searchFrom = 0;
        while (true)
        {
            var idx = result.IndexOf("<head", searchFrom, StringComparison.OrdinalIgnoreCase);
            if (idx < 0) break;

            var afterName = idx + 5; // length of "<head"
            if (afterName >= result.Length) break;

            var ch = result[afterName];
            if (ch == '>' || ch == ' ' || ch == '\t' || ch == '\n' || ch == '\r')
            {
                // Find closing > of the opening tag
                var closeTag = result.IndexOf('>', afterName);
                if (closeTag >= 0 && result[closeTag - 1] != '/') // not self-closing
                {
                    // Locate the matching </head> and search the head's content for an
                    // existing Content-Type meta. If found, skip insertion for this head.
                    var endHead = result.IndexOf("</head", closeTag + 1, StringComparison.OrdinalIgnoreCase);
                    var headContent = endHead > 0
                        ? result.AsSpan(closeTag + 1, endHead - closeTag - 1)
                        : result.AsSpan(closeTag + 1);
                    if (!ContainsContentTypeMeta(headContent))
                    {
                        result = result.Insert(closeTag + 1, metaElement);
                        searchFrom = closeTag + 1 + metaElement.Length;
                        continue;
                    }
                    searchFrom = endHead > 0 ? endHead : result.Length;
                    continue;
                }
            }
            searchFrom = afterName;
        }
        return result;
    }

    /// <summary>
    /// Scans a run of head content for an existing http-equiv="Content-Type" meta tag
    /// (case-insensitive). Used to suppress duplicate insertion by InsertContentTypeMeta.
    /// </summary>
    private static bool ContainsContentTypeMeta(ReadOnlySpan<char> headContent)
    {
        var i = 0;
        while (i < headContent.Length)
        {
            var lt = headContent.Slice(i).IndexOf('<');
            if (lt < 0) break;
            i += lt;
            // Match <meta (case-insensitive) followed by whitespace or end
            if (i + 5 <= headContent.Length
                && (headContent[i + 1] == 'm' || headContent[i + 1] == 'M')
                && (headContent[i + 2] == 'e' || headContent[i + 2] == 'E')
                && (headContent[i + 3] == 't' || headContent[i + 3] == 'T')
                && (headContent[i + 4] == 'a' || headContent[i + 4] == 'A')
                && (i + 5 == headContent.Length || headContent[i + 5] == ' '
                    || headContent[i + 5] == '\t' || headContent[i + 5] == '\n'
                    || headContent[i + 5] == '\r' || headContent[i + 5] == '/'
                    || headContent[i + 5] == '>'))
            {
                var gt = headContent.Slice(i).IndexOf('>');
                if (gt < 0) break;
                var tag = headContent.Slice(i, gt + 1);
                // Look for http-equiv="Content-Type" or http-equiv='Content-Type'
                // (HTML attributes are case-insensitive; values per spec are too).
                if (tag.IndexOf("http-equiv", StringComparison.OrdinalIgnoreCase) >= 0
                    && tag.IndexOf("Content-Type", StringComparison.OrdinalIgnoreCase) >= 0)
                {
                    return true;
                }
                i += gt + 1;
                continue;
            }
            i++;
        }
        return false;
    }

    /// <summary>
    /// Strips all XML markup from output, returning only text content.
    /// Used for xsl:output method="text".
    /// </summary>
    internal static string StripXmlMarkup(string output)
    {
        var sb = new StringBuilder(output.Length);
        var i = 0;
        while (i < output.Length)
        {
            if (output[i] == '<')
            {
                // Skip entire tag (including CDATA, comments, PIs)
                var end = output.IndexOf('>', i);
                if (end >= 0)
                {
                    i = end + 1;
                }
                else
                {
                    i++;
                }
            }
            else if (output[i] == '&')
            {
                // Decode entity references
                var semi = output.IndexOf(';', i);
                if (semi >= 0 && semi - i < 10)
                {
                    var entity = output.AsSpan(i + 1, semi - i - 1);
                    if (entity.SequenceEqual("amp"))
                        sb.Append('&');
                    else if (entity.SequenceEqual("lt"))
                        sb.Append('<');
                    else if (entity.SequenceEqual("gt"))
                        sb.Append('>');
                    else if (entity.SequenceEqual("quot"))
                        sb.Append('"');
                    else if (entity.SequenceEqual("apos"))
                        sb.Append('\'');
                    else if (entity.Length > 1 && entity[0] == '#')
                    {
                        // Numeric character reference
                        var numStr = entity[1] == 'x'
                            ? entity[2..].ToString()
                            : entity[1..].ToString();
                        var style = entity[1] == 'x' ? NumberStyles.HexNumber : NumberStyles.Integer;
                        if (int.TryParse(numStr, style, CultureInfo.InvariantCulture, out var cp))
                            sb.Append(char.ConvertFromUtf32(cp));
                    }
                    else
                    {
                        // Unknown entity, pass through
                        sb.Append(output, i, semi - i + 1);
                    }
                    i = semi + 1;
                }
                else
                {
                    sb.Append(output[i]);
                    i++;
                }
            }
            else
            {
                sb.Append(output[i]);
                i++;
            }
        }
        return sb.ToString();
    }

    private sealed class Scope
    {
        // Lazy-init Variables / TunnelParameters dictionaries: most scopes (e.g. the
        // shallow-copy identity template fire) bind no variables, so eagerly allocating
        // two Dictionaries per PushScope burned ~28% of the streaming bench's
        // post-delegate-cache allocation. Readers use `VariablesOrNull`/`TunnelParametersOrNull`
        // to short-circuit on empty; the public getters lazy-allocate only on write.
        private Dictionary<QName, object?>? _variables;
        private Dictionary<QName, object?>? _tunnelParameters;

        public Dictionary<QName, object?> Variables => _variables ??= new();
        public Dictionary<QName, object?> TunnelParameters => _tunnelParameters ??= new();

        /// <summary>Returns the backing variables dictionary or <c>null</c> if no variable has been bound.</summary>
        public Dictionary<QName, object?>? VariablesOrNull => _variables;
        /// <summary>Returns the backing tunnel-parameter dictionary or <c>null</c> if no parameter has been bound.</summary>
        public Dictionary<QName, object?>? TunnelParametersOrNull => _tunnelParameters;

        public Scope? Parent { get; set; }
        /// <summary>
        /// When true, tunnel parameter search stops at this scope boundary.
        /// Used for xsl:function calls where tunnel params must not leak through.
        /// </summary>
        public bool IsTunnelBarrier { get; set; }

        public Scope(Scope? parent = null)
        {
            Parent = parent;
        }

        /// <summary>
        /// Clears all state so this Scope can be returned to a pool. Keeps the
        /// dictionaries allocated (if any) so subsequent xsl:variable-heavy scopes
        /// reuse them via Clear() rather than re-allocating.
        /// </summary>
        public void Reset()
        {
            Parent = null;
            IsTunnelBarrier = false;
            _variables?.Clear();
            _tunnelParameters?.Clear();
        }
    }

    private sealed class BreakException : XsltException
    {
        public BreakException() : base("Break") { }
        public BreakException(string message) : base(message) { }
        public BreakException(string message, Exception innerException) : base(message, innerException) { }
    }

    private sealed class NextIterationException : XsltException
    {
        public NextIterationException() : base("NextIteration") { }
        public NextIterationException(string message) : base(message) { }
        public NextIterationException(string message, Exception innerException) : base(message, innerException) { }
        public List<XsltWithParam> WithParams { get; init; } = new();
    }

    /// <summary>
    /// Calls an XSLT user-defined function (xsl:function) and returns its result.
    /// </summary>
    internal async ValueTask<object?> CallXsltFunctionAsync(XsltFunction func, IReadOnlyList<object?> arguments)
    {
        // Trace: function call
        if (_options?.TraceListener != null)
            _options.TraceListener(_templateDepth, "call-function", $"{func.Name.LocalName}#{arguments.Count}");

        // cache="yes" memoization: check cache before executing function body
        string? cacheKey = null;
        if (func.Cache)
        {
            var keyBuilder = new System.Text.StringBuilder();
            keyBuilder.Append(func.Name.Namespace.Value).Append(':').Append(func.Name.LocalName).Append('(');
            for (var ai = 0; ai < arguments.Count; ai++)
            {
                if (ai > 0) keyBuilder.Append(',');
                AppendCacheKey(keyBuilder, arguments[ai]);
            }
            keyBuilder.Append(')');
            cacheKey = keyBuilder.ToString();
            if (_functionCache.TryGetValue(cacheKey, out var cachedResult))
                return cachedResult;
        }

        _recursionDepth++;
        if (_recursionDepth > MaxRecursionDepth)
            throw Error($"Maximum recursion depth ({MaxRecursionDepth}) exceeded in function '{func.Name.LocalName}'");
        // Probe the physical stack: recursive stylesheet functions overflow the native
        // stack (uncatchable SIGABRT) well before _recursionDepth hits the limit above,
        // because each call burns ~15 async frames. CheckResourceLimits converts that
        // into a catchable error.
        CheckResourceLimits();

        _currentXsltFunctionStack.Push(func);
        PushScope();
        // Mark this scope as a tunnel barrier — per XSLT spec, tunnel parameters
        // are not propagated through stylesheet function calls
        _scopes.Peek().IsTunnelBarrier = true;
        // Per XSLT spec, context item is absent inside stylesheet functions (XPDY0002)
        PushContextItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus, 0, 0);
        // current() must also return absent focus in functions (XTDE1360)
        PushCurrentItem(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus);
        // Per XSLT 2.0 erratum E19: mode="#current" in functions reverts to unnamed mode
        var savedMode = _currentMode;
        _currentMode = null;
        try
        {
            // Shadow context-specific variables that shouldn't leak into function scope
            // Per XSLT spec, regex-group(), current-group(), etc. return empty inside functions
            SetVariable(new QName(NamespaceId.None, "regex-groups"), null);
            SetVariable(new QName(NamespaceId.None, "current-group"), null);
            SetVariable(new QName(NamespaceId.None, "current-grouping-key"), null);
            SetVariable(new QName(NamespaceId.None, "current-merge-group"), null);
            SetVariable(new QName(NamespaceId.None, "current-merge-key"), null);

            // Bind parameters with function conversion rules (XSLT 3.0 §5.4.1):
            // Atomize node values and coerce to target type when target is atomic
            // Then validate with XTTE0790 for strict atomic types
            for (var i = 0; i < func.Parameters.Count && i < arguments.Count; i++)
            {
                var param = func.Parameters[i];
                var value = arguments[i];
                if (param.As != null && IsStrictAtomicType(param.As.ItemType))
                {
                    // Apply function conversion rules: atomize nodes, coerce to target type
                    value = ApplyFunctionConversionRules(value, param.As);
                    ValidateValueMatchesType(value, param.As, "XTTE0790",
                        $"Value of parameter ${param.Name.LocalName} in function {func.Name.LocalName}");
                }
                else if (param.As != null && param.As.ItemType == ItemType.Function
                    && param.As.FunctionParameterTypes != null)
                {
                    // Validate arity and wrap in coercion wrappers (XSLT 3.0 §5.4.11)
                    ValidateFunctionTypeArgument(value, param.As, param.Name.LocalName, func.Name.LocalName);
                    value = WrapInCoercionWrapper(value, param.As);
                }
                SetVariable(param.Name, value);
            }

            // Use sequence accumulator to capture xsl:sequence return values as typed results
            var savedAccumulator = _sequenceAccumulator;
            _sequenceAccumulator = new List<object?>();

            // Save _lastResultWasAtomic — function body's internal text/sequence ops
            // must not leak into the caller's atomic spacing state
            var savedLastResultWasAtomic = _lastResultWasAtomic;

            // Also capture any text output (function body is temporary output state)
            var savedOutput = _output.Length;
            // Save and clear namespace scopes so LRE elements in the function body
            // emit all needed namespace declarations. The function output is extracted
            // as a separate text fragment, so it must be self-contained.
            var savedNsScopesFunc = new List<Dictionary<string, string>>(_outputNsScopes);
            _outputNsScopes.Clear();
            // Save/restore serialization state so nested function calls
            // (e.g., recursive copy within document construction) don't inherit
            // the caller's element/document/attribute collection context
            var savedDocNodeDepth = _documentNodeDepth;
            var savedAttrStackFunc = new List<StringBuilder>(_collectedAttributesStack);
            _documentNodeDepth = 0;
            // Reset _serializingElementDepth so xsl:value-of inside functions produces
            // TextNodeItem (proper text nodes) instead of plain text strings. The result
            // assembly code already coerces TextNodeItem to atomic types when as= is set.
            var savedSerializingElementDepth = _serializingElementDepth;
            _serializingElementDepth = 0;
            _collectedAttributesStack.Clear();
            _temporaryOutputDepth++;
            _functionBodyDepth++;
            try
            { await func.Body.ExecuteAsync(this).ConfigureAwait(false); }
            finally
            {
                _functionBodyDepth--;
                _temporaryOutputDepth--;
                // Restore namespace scopes
                _outputNsScopes.Clear();
                foreach (var scope in savedNsScopesFunc.AsEnumerable().Reverse())
                    _outputNsScopes.Push(scope);
                // Restore serialization state
                _documentNodeDepth = savedDocNodeDepth;
                _serializingElementDepth = savedSerializingElementDepth;

                _collectedAttributesStack.Clear();
                foreach (var sb in savedAttrStackFunc.AsEnumerable().Reverse())
                    _collectedAttributesStack.Push(sb);
            }
            var textOutput = _output.ToString(savedOutput, _output.Length - savedOutput);
            _output.Length = savedOutput;

            var accumulatedItems = _sequenceAccumulator;
            _sequenceAccumulator = savedAccumulator;
            _lastResultWasAtomic = savedLastResultWasAtomic;

            // Determine function return value from accumulated items and/or text output
            object? funcResult;
            if (accumulatedItems.Count == 1 && string.IsNullOrEmpty(textOutput))
            {
                funcResult = accumulatedItems[0];
                // TextNodeItem from TVTs/xsl:text/xsl:value-of: coerce to atomic return type if needed.
                // Includes string/anyURI types — atomization of text nodes always produces a string.
                if (funcResult is Xdm.TextNodeItem tni && func.As != null && IsAtomicReturnType(func.As.ItemType))
                    funcResult = CoerceToType(tni.Value, func.As);
                ValidateFunctionReturnType(funcResult, func);
            }
            else if (accumulatedItems.Count > 1 && string.IsNullOrEmpty(textOutput))
            {
                // Coerce TextNodeItems to atomic types if function has atomic return type
                if (func.As != null && IsAtomicReturnType(func.As.ItemType))
                {
                    for (var i = 0; i < accumulatedItems.Count; i++)
                    {
                        if (accumulatedItems[i] is Xdm.TextNodeItem tni2)
                            accumulatedItems[i] = CoerceToType(tni2.Value, func.As);
                    }
                }
                funcResult = accumulatedItems.ToArray();
            }
            else if (string.IsNullOrEmpty(textOutput) && accumulatedItems.Count == 0)
            {
                ValidateFunctionReturnType(null, func);
                funcResult = null;
            }
            else if (!string.IsNullOrEmpty(textOutput)
                && _nodeStore != null
                // Parse text output to XDM nodes when:
                //   (a) the text contains XML markup — a parented subtree to extract, or
                //   (b) the function's declared return is a node type — we need to produce
                //       text nodes, not concatenated strings. Found in Docbook chunk-cleanup
                //       f:chunk-title (as="node()*") whose apply-templates result was plain
                //       text; without (b) the function returned the string and the caller's
                //       `descendant-or-self::text()` axis step blew up with XPTY0020.
                && (textOutput.Contains('<', StringComparison.Ordinal)
                    || (func.As != null
                        && func.As.ItemType is ItemType.Element or ItemType.Node or ItemType.Document
                            or ItemType.Comment or ItemType.ProcessingInstruction or ItemType.Text))
                && (func.As == null
                    || func.As.ItemType is ItemType.Element or ItemType.Node or ItemType.Document
                        or ItemType.Comment or ItemType.ProcessingInstruction or ItemType.Text))
            {
                // Parse text output to XDM nodes. This handles:
                // - Functions with node return type (as="node()") — so instance-of checks work
                // - Functions with no as attribute (XSLT 3.0 §10.3: result used directly)
                funcResult = null;
                try
                {
                    // Stream-parse via XmlReader rather than allocating a full XmlDocument
                    // and re-converting to XDM. Children parented under the synthetic
                    // wrapper, then unparented before being returned as the function result.
                    var fnSettings = new System.Xml.XmlReaderSettings
                    {
                        DtdProcessing = System.Xml.DtdProcessing.Prohibit,
                        IgnoreWhitespace = false,
                        IgnoreComments = false,
                        IgnoreProcessingInstructions = false,
                    };
                    using var fnStringReader = new System.IO.StringReader($"<_fn_root_>{textOutput}</_fn_root_>");
                    using var fnReader = System.Xml.XmlReader.Create(fnStringReader, fnSettings);
                    var fnChildren = new List<object?>();
                    ReadAsBodyChunkChildren(fnReader, fnChildren);
                    var parsedItems = new List<object?>();
                    foreach (var child in fnChildren)
                    {
                        if (child is XdmNode cn)
                            cn.Parent = null;
                        parsedItems.Add(child);
                    }
                    foreach (var item in accumulatedItems)
                    {
                        if (item is not Xdm.TextNodeItem)
                            parsedItems.Add(item);
                    }
                    funcResult = parsedItems.Count == 1 ? parsedItems[0] : parsedItems.Count > 1 ? parsedItems.ToArray() : null;
                }
                catch (System.Xml.XmlException)
                {
                    // Fall through to RTF wrapping
                }
                funcResult ??= textOutput.Contains('<', StringComparison.Ordinal) ? new ResultTreeFragment(textOutput) : StripXmlMarkup(textOutput);
            }
            else if (accumulatedItems.Count > 0 && !string.IsNullOrEmpty(textOutput))
            {
                // Combine accumulated items with text output — return the accumulated items
                // (text is typically from LREs inside the function)
                // Coerce TextNodeItems to atomic types if function has atomic return type
                if (func.As != null && IsAtomicReturnType(func.As.ItemType))
                {
                    for (var i = 0; i < accumulatedItems.Count; i++)
                    {
                        if (accumulatedItems[i] is Xdm.TextNodeItem tni)
                            accumulatedItems[i] = CoerceToType(tni.Value, func.As);
                    }
                }
                funcResult = accumulatedItems.Count == 1 ? accumulatedItems[0] : accumulatedItems.ToArray();
            }
            else if (string.IsNullOrEmpty(textOutput))
            {
                ValidateFunctionReturnType(null, func);
                funcResult = null;
            }
            else
            {
                // If text output contains XML markup, wrap as ResultTreeFragment so StringValueOf strips it
                funcResult = textOutput.Contains('<', StringComparison.Ordinal) ? new ResultTreeFragment(textOutput) : StripXmlMarkup(textOutput);
            }

            // If the function's return type is a typed function type, wrap returned
            // function items in coercion wrappers (XSLT 3.0 §5.4.11)
            if (funcResult != null && func.As != null
                && func.As.ItemType == ItemType.Function
                && func.As.FunctionParameterTypes != null)
            {
                funcResult = WrapInCoercionWrapper(funcResult, func.As);
            }

            // String → atomic coercion at function boundary (Saxon-compatible). When the
            // function body produces a string (typically via `xsl:number` or `xsl:value-of`)
            // and the declared return is a strict atomic type (xs:integer, xs:double, …),
            // attempt to cast it. Per XSLT 3.0 spec the body's text result is treated as
            // untypedAtomic, which casts to the target. Without this, the function-body
            // chain in Docbook fp:number (`as="xs:integer?"` whose body is
            // `<xsl:apply-templates select="$node" mode="mp:label-number"/>` and the
            // matching templates use `<xsl:number/>`) returns the formatted string and the
            // tightened validator now rejects it as XTTE0780.
            if (funcResult is string fs && func.As != null && IsStrictAtomicType(func.As.ItemType))
            {
                var coerced = TryCoerceStringToType(fs, func.As.ItemType);
                if (coerced != null)
                    funcResult = coerced;
            }
            else if (funcResult is object?[] resultArr && func.As != null && IsStrictAtomicType(func.As.ItemType))
            {
                for (var i = 0; i < resultArr.Length; i++)
                {
                    if (resultArr[i] is string sStr)
                    {
                        var coerced = TryCoerceStringToType(sStr, func.As.ItemType);
                        if (coerced != null)
                            resultArr[i] = coerced;
                    }
                }
            }

            // XTTE0780 final gate: catch wrong-shape values that slipped past the per-branch
            // funcResult assembly. Several recent bugs (xsl:break atomizing an element to a
            // string, xsl:copy copy-namespaces="no" producing a wrong-namespace element,
            // function body whose text-only output would have returned a string for an
            // `as="node()"` declaration) were only detected downstream as XPTY0020 axis errors
            // because branches that synthesize funcResult from textOutput skipped validation.
            // Validating once here, after every branch converges, surfaces those mismatches
            // at the function boundary instead.
            ValidateFunctionReturnType(funcResult, func);

            if (cacheKey != null)
                _functionCache[cacheKey] = funcResult;
            return funcResult;
        }
        finally
        {
            _currentMode = savedMode;
            PopCurrentItem();
            PopContextItem();
            PopScope();
            _currentXsltFunctionStack.Pop();
            _recursionDepth--;
        }
    }

    /// <summary>
    /// Validates the return value of an xsl:function against its declared as type (XTTE0780).
    /// </summary>
    private void ValidateFunctionReturnType(object? result, XsltFunction func)
    {
        if (func.As == null)
            return;
        ValidateValueMatchesType(result, func.As, "XTTE0780", $"Function {func.Name.LocalName} return value");
    }

    /// <summary>
    /// Serializes a function return value to the output for initial-function invocation.
    /// Nodes are serialized as XML; atomic values are written as their string representation.
    /// </summary>
    internal void SerializeFunctionResult(object? result, StringBuilder outputBuilder)
    {
        if (result == null)
            return;

        if (result is object[] arr)
        {
            for (var i = 0; i < arr.Length; i++)
            {
                if (i > 0)
                    _output.Append(' ');
                SerializeFunctionResult(arr[i], outputBuilder);
            }
            return;
        }

        if (result is XdmNode node)
        {
            // Use SerializeNode which writes to _output
            SerializeNode(node);
            return;
        }

        if (result is ResultTreeFragment rtf)
        {
            _output.Append(rtf.XmlContent);
            return;
        }

        // Atomic values: serialize as string
        _output.Append(StringValueOf(result));
    }

    /// <summary>
    /// Produces a concise node description for trace output.
    /// </summary>
    private static string DescribeTraceNode(object? node)
    {
        return node switch
        {
            XdmDocument => "document-node()",
            XdmElement elem => elem.Prefix != null ? $"{elem.Prefix}:{elem.LocalName}" : elem.LocalName,
            XdmAttribute attr => $"@{attr.LocalName}",
            XdmText t => $"text(\"{Truncate(t.Value, 20)}\")",
            XdmComment => "comment()",
            XdmProcessingInstruction pi => $"processing-instruction({pi.Target})",
            System.Xml.Linq.XElement xe => xe.Name.LocalName,
            System.Xml.Linq.XDocument => "document-node()",
            string s => $"\"{Truncate(s, 20)}\"",
            null => "(empty)",
            _ => node.GetType().Name
        };

        static string Truncate(string s, int max)
        {
            s = s.Replace('\n', ' ').Replace('\r', ' ');
            return s.Length <= max ? s : string.Concat(s.AsSpan(0, max), "...");
        }
    }
}

/// <summary>
/// Adapts an XSLT user-defined function (xsl:function) to the XQuery function interface.
/// </summary>
internal sealed class XsltUserFunctionAdapter : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly XsltFunction _xsltFunc;
    private readonly DefaultXsltExecutionContext _context;

    public XsltUserFunctionAdapter(XsltFunction xsltFunc, DefaultXsltExecutionContext context)
    {
        _xsltFunc = xsltFunc;
        _context = context;
    }

    public override QName Name
    {
        get
        {
            var name = _xsltFunc.Name;
            if (name.ResolvedNamespace == null && name.Namespace != NamespaceId.None)
            {
                // Resolve NamespaceId to URI string for fn:function-name() introspection
                var nsUri = PhoenixmlDb.XQuery.Functions.FunctionNamespaces.ResolveNamespace(name.Namespace);
                if (nsUri == null)
                {
                    // Check dynamic namespaces (user-defined function namespaces)
                    foreach (var (uri, nsId) in StylesheetParser.DynamicNamespaces)
                    {
                        if (nsId == name.Namespace)
                        {
                            nsUri = uri;
                            break;
                        }
                    }
                }
                if (nsUri != null)
                    return new QName(name.Namespace, name.LocalName, name.Prefix) { RuntimeNamespace = nsUri };
            }
            return name;
        }
    }

    public override XdmSequenceType ReturnType =>
        _xsltFunc.As ?? XdmSequenceType.ZeroOrMoreItems;

    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        _xsltFunc.Parameters.Select(p => new FunctionParameterDef
        {
            Name = p.Name,
            Type = p.As ?? XdmSequenceType.ZeroOrMoreItems
        }).ToList();

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // XTDE3160: Private stylesheet functions cannot be called from xsl:evaluate
        if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec && qec.InsideXslEvaluate
            && _xsltFunc.Visibility != Ast.Visibility.Public && _xsltFunc.Visibility != Ast.Visibility.Final)
            throw new XsltException($"XTDE3160: The stylesheet function {_xsltFunc.Name.LocalName}() is not public and cannot be called from xsl:evaluate");
        return await _context.CallXsltFunctionAsync(_xsltFunc, arguments).ConfigureAwait(false);
    }
}

/// <summary>
/// Dynamic adapter for xsl:original() function calls in package overrides.
/// Resolves the original function at runtime via _currentXsltFunctionStack.
/// </summary>
internal sealed class XsltOriginalFunctionAdapter : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltOriginalFunctionAdapter(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(NamespaceId.Xslt, "original");
    public override XdmSequenceType ReturnType => XdmSequenceType.ZeroOrMoreItems;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];
    public override bool IsVariadic => true;
    public override int MaxArity => 20;

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (_context._currentXsltFunctionStack.Count == 0)
            throw new XsltException("XTDE3058: xsl:original invoked but no overriding function is active");

        var currentFunc = _context._currentXsltFunctionStack.Peek();
        var originalFunc = currentFunc.OriginalFunction
            ?? throw new XsltException("XTDE3058: xsl:original invoked but no overridden function is available");

        return await _context.CallXsltFunctionAsync(originalFunc, arguments).ConfigureAwait(false);
    }
}

/// <summary>
/// Wraps a callable item in a coercion wrapper per XSLT 3.0 §5.4.11.
/// At invocation time, validates return value against the declared return type.
/// Argument type mismatches are detected naturally when the inner callable rejects them.
/// </summary>
internal sealed class FunctionCoercionWrapper : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly PhoenixmlDb.XQuery.Ast.XQueryFunction _innerFunction;
    private readonly IReadOnlyList<XdmSequenceType> _declaredParamTypes;
    private readonly XdmSequenceType _declaredReturnType;

    public FunctionCoercionWrapper(
        PhoenixmlDb.XQuery.Ast.XQueryFunction innerFunction,
        IReadOnlyList<XdmSequenceType> declaredParamTypes,
        XdmSequenceType declaredReturnType)
    {
        _innerFunction = innerFunction;
        _declaredParamTypes = declaredParamTypes;
        _declaredReturnType = declaredReturnType;
    }

    public override QName Name => _innerFunction.Name;

    public override XdmSequenceType ReturnType => _declaredReturnType;

    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        _declaredParamTypes.Select((t, i) => new FunctionParameterDef
        {
            Name = i < _innerFunction.Parameters.Count
                ? _innerFunction.Parameters[i].Name
                : new QName(NamespaceId.None, $"arg{i + 1}"),
            Type = t
        }).ToList();

    public override bool IsAnonymous => _innerFunction.IsAnonymous;

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // Pass arguments through — atomization, untypedAtomic casting, and numeric
        // promotion are handled by the dynamic function call mechanism
        var result = await _innerFunction.InvokeAsync(arguments, context).ConfigureAwait(false);

        // Validate return value against declared return type
        ValidateCoercedReturnValue(result, _declaredReturnType, _innerFunction.Name.LocalName);

        return result;
    }

    private static void ValidateCoercedReturnValue(object? result, XdmSequenceType declaredReturn, string funcName)
    {
        // Check return type compatibility
        if (result == null)
        {
            if (declaredReturn.Occurrence is Occurrence.ExactlyOne or Occurrence.OneOrMore)
                throw new XsltException(
                    $"XPTY0004: Coercion wrapper for {funcName}() — returned empty sequence " +
                    $"but requires return type {declaredReturn}");
            return;
        }

        if (result is object?[] arr)
        {
            foreach (var item in arr)
            {
                if (item != null && !IsReturnTypeCompatible(item, declaredReturn.ItemType))
                    throw new XsltException(
                        $"XPTY0004: Coercion wrapper for {funcName}() — returned value of type " +
                        $"{item.GetType().Name} but requires return type {declaredReturn}");
            }
        }
        else if (!IsReturnTypeCompatible(result, declaredReturn.ItemType))
        {
            throw new XsltException(
                $"XPTY0004: Coercion wrapper for {funcName}() — returned value of type " +
                $"{result.GetType().Name} but requires return type {declaredReturn}");
        }
    }

    /// <summary>
    /// Checks if a return value is compatible with the declared return type,
    /// including numeric promotion (integer/decimal → double, integer → decimal).
    /// </summary>
    private static bool IsReturnTypeCompatible(object value, ItemType targetType)
    {
        if (XQuery.Execution.TypeCastHelper.MatchesItemType(value, targetType))
            return true;

        // Numeric promotion: int/long → double/decimal/float, float → double, decimal → double
        return targetType switch
        {
            ItemType.Double => value is int or long or float or decimal,
            ItemType.Decimal => value is int or long,
            ItemType.Float => value is int or long,
            _ => false
        };
    }
}

/// <summary>
/// XSLT root($arg) function - traverses parent chain to the root of the containing tree.
/// </summary>
internal sealed class XsltRootFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltRootFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "root");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalNode;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "arg"), Type = XdmSequenceType.OptionalNode }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var arg = arguments[0];
        if (arg is not XdmNode node)
            return ValueTask.FromResult<object?>(null);
        return ValueTask.FromResult<object?>(TraverseToRoot(node));
    }

    internal XdmNode TraverseToRoot(XdmNode node)
    {
        var current = node;
        while (current.Parent is { } parentId)
        {
            var parent = _context._nodeStore?.GetNode(parentId);
            if (parent == null)
                break;
            current = parent;
        }
        return current;
    }
}

/// <summary>
/// XSLT root() function (0-arg) - returns the root of the tree containing the context item.
/// </summary>
internal sealed class XsltRoot0Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    private XsltRootFunction? _rootFunc;

    public XsltRoot0Function(DefaultXsltExecutionContext context) => _context = context;

    internal void SetRootFunc(XsltRootFunction rootFunc) => _rootFunc = rootFunc;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "root");
    public override XdmSequenceType ReturnType => XdmSequenceType.Node;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var contextItem = _context.ContextItem;
        if (contextItem is not XdmNode node)
            return ValueTask.FromResult<object?>(null);
        if (_rootFunc != null)
            return ValueTask.FromResult<object?>(_rootFunc.TraverseToRoot(node));
        return ValueTask.FromResult<object?>(node);
    }
}

/// <summary>
/// XSLT generate-id($node) function - returns a unique string identifier for a node.
/// </summary>
internal sealed class XsltGenerateIdFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltGenerateIdFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "generate-id");
    public override XdmSequenceType ReturnType => XdmSequenceType.String;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "node"), Type = XdmSequenceType.OptionalNode }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var node = arguments[0];
        if (node is null)
            return ValueTask.FromResult<object?>("");
        // Use the hash code as a stable identifier
        return ValueTask.FromResult<object?>($"d{node.GetHashCode():x}");
    }
}

/// <summary>
/// XSLT generate-id() function - 0-arg version uses context item.
/// </summary>
internal sealed class XsltGenerateId0Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltGenerateId0Function(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "generate-id");
    public override XdmSequenceType ReturnType => XdmSequenceType.String;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // Use the XQuery execution context's context item (correct inside predicates)
        // rather than the XSLT context item which may be stale.
        object? node = null;
        try
        { node = context.ContextItem; }
#pragma warning disable CA1031 // ContextItem throws InvalidOperationException for absent focus
        catch (InvalidOperationException) { /* XPDY0002 absent focus */ }
#pragma warning restore CA1031
        node ??= _context.ContextItem;
        if (node is null)
            return ValueTask.FromResult<object?>("");
        return ValueTask.FromResult<object?>($"d{node.GetHashCode():x}");
    }
}

/// <summary>
/// XSLT current() function - returns the current context item (outer context, not inner).
/// </summary>
internal sealed class XsltCurrentFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltCurrentFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "current");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalItem;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];
    public override string? DynamicCallErrorCode => "XTDE1360";

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec && qec.InsideXslEvaluate)
            throw new XsltException("XTDE3160: The function current() is not available within xsl:evaluate");
        // current() returns the "outer" XSLT context item, not the inner XPath context
        var item = _context.CurrentItem;
        // XTDE1360: current() called when context item is absent (e.g., inside xsl:function)
        if (item != null && ReferenceEquals(item, PhoenixmlDb.XQuery.Execution.QueryExecutionContext.AbsentFocus))
            throw new XsltException("XTDE1360: The current() function is called when the context item is absent");
        return ValueTask.FromResult(item);
    }
}

internal sealed class XsltCurrentGroupFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltCurrentGroupFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "current-group");
    public override XdmSequenceType ReturnType => XdmSequenceType.ZeroOrMoreItems;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];
    public override string? DynamicCallErrorCode => "XTDE1061";
    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (_context.TryGetVariable(new QName(NamespaceId.None, "current-group"), out var group) && group != null)
        {
            // Return as object?[] so FunctionCallOperator yields items individually.
            // List<object> must not be returned directly because at runtime it matches
            // the "is List<object?>" check (nullable reference types are erased) and
            // would be yielded as a single XDM array item instead of being iterated.
            if (group is List<object> list)
                return ValueTask.FromResult<object?>(list.ToArray());
            return ValueTask.FromResult<object?>(group);
        }

        // XSLT 3.0: calling current-group() when there is no current group is a dynamic error
        throw new XsltException("XTDE1061: current-group() called when there is no current group");
    }
}

internal sealed class XsltCurrentGroupingKeyFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
