internal sealed class XsltRegexGroupFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltRegexGroupFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "regex-group");
    public override XdmSequenceType ReturnType => XdmSequenceType.String;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "number"), Type = XdmSequenceType.Integer }];
    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var groupNum = Convert.ToInt32(arguments[0], System.Globalization.CultureInfo.InvariantCulture);
        // Per XSLT spec, regex-group() returns empty string when called outside xsl:analyze-string
        if (_context.TryGetVariable(new QName(NamespaceId.None, "regex-groups"), out var groups) &&
            groups is System.Text.RegularExpressions.Match match)
        {
            if (groupNum >= 0 && groupNum < match.Groups.Count)
                return ValueTask.FromResult<object?>(match.Groups[groupNum].Value);
        }
        return ValueTask.FromResult<object?>("");
    }
}

internal sealed class XsltFunctionAvailableFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly PhoenixmlDb.XQuery.Functions.FunctionLibrary _library;
    public XsltFunctionAvailableFunction(PhoenixmlDb.XQuery.Functions.FunctionLibrary library) => _library = library;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "function-available");
    public override XdmSequenceType ReturnType => XdmSequenceType.Boolean;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "name"), Type = XdmSequenceType.String }];
    public override bool IsVariadic => true;
    public override int MaxArity => 2;
    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var nameArg = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(arguments[0]);
        var name = nameArg?.ToString() ?? "";
        // XTDE1400: Validate name is a valid EQName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE1400", "function-available");
        var arityArg = arguments.Count > 1 ? PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(arguments[1]) : null;
        // Handle arity arg that may come as object?[] wrapper
        if (arityArg is object?[] arityArr && arityArr.Length > 0)
            arityArg = arityArr[0];
        var arity = arityArg != null ? Convert.ToInt32(arityArg, System.Globalization.CultureInfo.InvariantCulture) : -1;
        // Parse the function name
        QName qname;
        if (name.StartsWith("Q{", StringComparison.Ordinal))
        {
            // EQName syntax: Q{namespace-uri}local-name
            var braceClose = name.IndexOf('}', StringComparison.Ordinal);
            if (braceClose > 1)
            {
                var namespaceUri = name[2..braceClose];
                var localName = name[(braceClose + 1)..];
                qname = new QName(NamespaceId.None, localName, "") { ExpandedNamespace = namespaceUri };
            }
            else
            {
                qname = new QName(NamespaceId.None, name);
            }
        }
        else if (name.Contains(':', StringComparison.Ordinal))
        {
            var parts = name.Split(':');
            qname = new QName(NamespaceId.None, parts[1], parts[0]);
        }
        else
        {
            qname = new QName(NamespaceId.None, name);
        }
        // Try to resolve with various arities
        if (arity >= 0)
        {
            return ValueTask.FromResult<object?>(_library.Resolve(qname, arity) != null);
        }
        // Try common arities 0-3
        for (int i = 0; i <= 3; i++)
        {
            if (_library.Resolve(qname, i) != null)
                return ValueTask.FromResult<object?>(true);
        }
        return ValueTask.FromResult<object?>(false);
    }
}

internal sealed class XsltElementAvailableFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly HashSet<string> _extensionNamespaces;

    public XsltElementAvailableFunction(HashSet<string> extensionNamespaces)
    {
        _extensionNamespaces = extensionNamespaces;
    }

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "element-available");
    public override XdmSequenceType ReturnType => XdmSequenceType.Boolean;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "name"), Type = XdmSequenceType.String }];
    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var name = arguments[0]?.ToString() ?? "";
        // XTDE1440: Validate name is a valid EQName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE1440", "element-available");
        string? namespaceUri = null;

        // Handle EQName syntax: Q{namespace-uri}local-name
        if (name.StartsWith("Q{", StringComparison.Ordinal))
        {
            var braceClose = name.IndexOf('}', StringComparison.Ordinal);
            if (braceClose > 1)
            {
                namespaceUri = name[2..braceClose];
                name = name[(braceClose + 1)..];
            }
        }
        else if (name.Contains(':', StringComparison.Ordinal))
        {
            var parts = name.Split(':');
            var prefix = parts[0];
            name = parts[1];
            // Resolve the prefix to a namespace URI
            if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec
                && qec.PrefixNamespaceBindings != null
                && qec.PrefixNamespaceBindings.TryGetValue(prefix, out var resolvedNs))
            {
                namespaceUri = resolvedNs;
            }
            else if (prefix == "xsl")
            {
                namespaceUri = "http://www.w3.org/1999/XSL/Transform";
            }
            else
            {
                // Unresolvable prefix — definitely not an XSLT element
                return ValueTask.FromResult<object?>(false);
            }
        }

        // element-available returns true for extension element namespaces
        if (namespaceUri != null && namespaceUri != "http://www.w3.org/1999/XSL/Transform")
            return ValueTask.FromResult<object?>(_extensionNamespaces.Contains(namespaceUri));

        // XSLT 3.0 instruction elements
        var available = name switch
        {
            "apply-templates" or "call-template" or "choose" or "copy" or "copy-of" or
            "element" or "attribute" or "text" or "value-of" or "variable" or "param" or
            "if" or "for-each" or "for-each-group" or "sort" or "message" or "number" or
            "comment" or "processing-instruction" or "sequence" or "iterate" or
            "try" or "catch" or "next-match" or "apply-imports" or "result-document" or
            "analyze-string" or "matching-substring" or "non-matching-substring" or
            "where-populated" or "on-empty" or "on-non-empty" or "fallback" or
            "namespace" or "output" or "strip-space" or "preserve-space" or
            "stylesheet" or "transform" or "template" or "function" or
            "import" or "include" or "import-schema" or "decimal-format" or
            "character-map" or "output-character" or "key" or
            "document" or "source-document" or "with-param" or
            "when" or "otherwise" or "break" or "next-iteration" or
            "accumulator" or "accumulator-rule" or
            "context-item" or "global-context-item" or
            "map" or "map-entry" or "array" or "assert" or
            "merge" or "merge-source" or "merge-action" or "merge-key" or
            "fork" or "accept" or "expose" or "override" or "use-package" => true,
            _ => false
        };
        return ValueTask.FromResult<object?>(available);
    }
}

/// <summary>
/// XSLT document() function — loads external document(s).
/// </summary>
internal sealed class XsltDocumentFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltDocumentFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "document");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore
    };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "uri-sequence"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalString }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // The document() function loads external documents by URI.
        // It can accept a sequence of URIs (e.g., document(node-set/@attr)).
        var arg = arguments[0];
        if (arg == null)
            return ValueTask.FromResult<object?>(null);

        // Handle sequence of URIs
        if (arg is object?[] arr)
            return LoadMultipleDocuments(arr, context);
        if (arg is IEnumerable<object?> seq && arg is not string && arg is not Xdm.Nodes.XdmNode)
            return LoadMultipleDocuments(seq, context);

        return LoadSingleDocument(arg, context);
    }

    private static ValueTask<object?> LoadMultipleDocuments(IEnumerable<object?> items, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var results = new List<object?>();
        foreach (var item in items)
        {
            if (item == null)
                continue;
            // Per XSLT §16.1: when the argument is a node, relative URIs are resolved
            // against the base URI of that node, not the static base URI.
            var nodeBaseUri = GetNodeBaseUri(item, context);
            var uri = PhoenixmlDb.XQuery.Functions.ConcatFunction.XQueryStringValue(
                PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(item));
            if (uri == null)
                continue;

            // Extract fragment identifier
            string? fragment = null;
            var hashIdx = uri.IndexOf('#', StringComparison.Ordinal);
            if (hashIdx >= 0)
            {
                fragment = uri[(hashIdx + 1)..];
                uri = uri[..hashIdx];
            }

            if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qc &&
                qc.DocumentResolver is not null)
            {
                uri = nodeBaseUri != null
                    ? ResolveUriAgainstBase(uri, nodeBaseUri)
                    : ResolveUriAgainstStaticBase(uri, qc);
                var doc = qc.DocumentResolver.ResolveDocument(uri);
                if (doc != null)
                {
                    if (fragment != null && qc.DocumentResolver is XsltDocumentResolver xsltResolver
                        && xsltResolver.NodeStore is { } nodeStore)
                    {
                        var matches = XsltIdFunction.FindElementsById(fragment, doc, nodeStore);
                        if (matches.Length > 0)
                            results.Add(matches[0]);
                        // Fragment not found → skip (empty result for this URI)
                    }
                    else
                    {
                        results.Add(doc);
                    }
                }
                else
                    throw new XsltException($"FODC0005: Cannot retrieve document at URI '{uri}'");
            }
            else
                throw new XsltException($"FODC0005: Cannot retrieve document at URI '{uri}'");
        }
        return ValueTask.FromResult<object?>(results.ToArray());
    }

    private static ValueTask<object?> LoadSingleDocument(object arg, PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // Per XSLT §16.1: when the argument is a node, relative URIs are resolved
        // against the base URI of that node, not the static base URI.
        var nodeBaseUri = GetNodeBaseUri(arg, context);
        var uri = PhoenixmlDb.XQuery.Functions.ConcatFunction.XQueryStringValue(
            PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(arg));
        if (uri == null)
            return ValueTask.FromResult<object?>(null);

        // Extract fragment identifier (e.g., "doc.xml#frag" → fragment="frag")
        string? fragment = null;
        var hashIdx = uri.IndexOf('#', StringComparison.Ordinal);
        if (hashIdx >= 0)
        {
            fragment = uri[(hashIdx + 1)..];
            uri = uri[..hashIdx];
        }

        if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext queryContext &&
            queryContext.DocumentResolver is not null)
        {
            uri = nodeBaseUri != null
                ? ResolveUriAgainstBase(uri, nodeBaseUri)
                : ResolveUriAgainstStaticBase(uri, queryContext);
            var doc = queryContext.DocumentResolver.ResolveDocument(uri);
            if (doc != null)
            {
                // If a fragment identifier is present, select element by ID
                if (fragment != null && queryContext.DocumentResolver is XsltDocumentResolver xsltResolver
                    && xsltResolver.NodeStore is { } nodeStore)
                {
                    var matches = XsltIdFunction.FindElementsById(fragment, doc, nodeStore);
                    if (matches.Length > 0)
                        return ValueTask.FromResult(matches[0]);
                    // Fragment not found → return empty sequence (per XSLT §13.1)
                    return ValueTask.FromResult<object?>(null);
                }
                return ValueTask.FromResult<object?>(doc);
            }
        }

        // FODC0005: Cannot resolve document URI
        throw new XsltException($"FODC0005: Cannot retrieve document at URI '{uri}'");
    }

    /// <summary>
    /// Resolves a URI against the static base URI of the calling module.
    /// Empty URIs resolve to the static base URI itself; relative URIs resolve against it.
    /// </summary>
    private static string ResolveUriAgainstStaticBase(string uri, PhoenixmlDb.XQuery.Execution.QueryExecutionContext queryContext)
    {
        if (queryContext.StaticBaseUri == null)
            return uri;
        if (uri.Length == 0)
            return queryContext.StaticBaseUri;
        // Only resolve relative URIs — absolute URIs are used as-is
        if (!Uri.TryCreate(uri, UriKind.Absolute, out _))
        {
            if (Uri.TryCreate(queryContext.StaticBaseUri, UriKind.Absolute, out var baseUri))
            {
                var resolved = new Uri(baseUri, uri);
                return resolved.AbsoluteUri;
            }
        }
        return uri;
    }

    /// <summary>
    /// Extracts the base URI from a node item for document() relative URI resolution.
    /// Returns null for non-node items.
    /// </summary>
    private static string? GetNodeBaseUri(object? item, PhoenixmlDb.XQuery.Ast.ExecutionContext? context = null)
    {
        if (item is System.Xml.XmlNode xmlNode)
        {
            var baseUri = xmlNode.BaseURI;
            return !string.IsNullOrEmpty(baseUri) ? baseUri : null;
        }
        if (item is Xdm.Nodes.XdmNode xdmNode)
        {
            var nodeProvider = (context as PhoenixmlDb.XQuery.Execution.QueryExecutionContext)?.NodeProvider;
            return PhoenixmlDb.XQuery.Functions.BaseUriFunction.ComputeBaseUri(xdmNode, nodeProvider);
        }
        if (item is System.Xml.Linq.XObject xObj)
        {
            var baseUri = xObj.BaseUri;
            return !string.IsNullOrEmpty(baseUri) ? baseUri : null;
        }
        return null;
    }

    /// <summary>
    /// Resolves a relative URI against a given base URI string.
    /// </summary>
    private static string ResolveUriAgainstBase(string uri, string baseUriStr)
    {
        if (string.IsNullOrEmpty(baseUriStr))
            return uri;
        if (uri.Length == 0)
            return baseUriStr;
        if (!Uri.TryCreate(uri, UriKind.Absolute, out _))
        {
            if (Uri.TryCreate(baseUriStr, UriKind.Absolute, out var baseUri))
            {
                var resolved = new Uri(baseUri, uri);
                return resolved.AbsoluteUri;
            }
        }
        return uri;
    }
}

/// <summary>
/// XSLT document() with 2 args — URI + base node.
/// </summary>
internal sealed class XsltDocument2Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltDocument2Function(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "document");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore
    };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "uri-sequence"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalString },
        new() { Name = new QName(NamespaceId.None, "base-node"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ExactlyOne } }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // The second argument provides the base URI for resolving relative URIs.
        // Per XSLT 3.0 §13.1: the relative URI is resolved against the base URI of the
        // document containing the node supplied as the second argument.
        var baseNode = arguments.Count > 1 ? arguments[1] : null;
        string? baseUri = null;
        if (baseNode is Xdm.Nodes.XdmNode node)
        {
            // Use the node's base URI (for document nodes, this is the document URI)
            baseUri = node.BaseUri;
            // If the node doesn't have a base URI but is in a document, resolve via the node store
            if (baseUri == null && _context._nodeStore != null && node.Parent.HasValue)
            {
                var docNode = _context._nodeStore.GetNode(node.Parent.Value);
                while (docNode is Xdm.Nodes.XdmNode parentNode && parentNode is not Xdm.Nodes.XdmDocument && parentNode.Parent.HasValue)
                    docNode = _context._nodeStore.GetNode(parentNode.Parent.Value);
                if (docNode is Xdm.Nodes.XdmDocument docDoc)
                    baseUri = docDoc.BaseUri;
            }
        }

        // Resolve URIs from the first argument against the base URI from the second argument
        var uriArg = arguments[0];
        if (uriArg == null)
            return ValueTask.FromResult<object?>(null);

        // If we have a base URI from the second argument, resolve all URIs against it
        if (baseUri != null && context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qc &&
            qc.DocumentResolver is not null)
        {
            // Handle sequence of URIs
            if (uriArg is object?[] arr)
                return LoadDocumentsWithBase(arr, baseUri, qc);
            if (uriArg is IEnumerable<object?> seq && uriArg is not string && uriArg is not Xdm.Nodes.XdmNode)
                return LoadDocumentsWithBase(seq, baseUri, qc);

            // Single URI
            return LoadSingleDocumentWithBase(uriArg, baseUri, qc);
        }

        // XTDE1162: If a second argument was provided but no base URI could be determined
        // (e.g., parentless text node), it's a dynamic error
        if (baseNode != null)
            throw new XsltException("XTDE1162: The second argument to the document() function has no base URI (e.g. a parentless node)");

        // Fall back to the 1-argument behavior (resolve against static base URI)
        return new XsltDocumentFunction(_context).InvokeAsync(arguments, context);
    }

    private static async ValueTask<object?> LoadDocumentsWithBase(IEnumerable<object?> items, string baseUri,
        PhoenixmlDb.XQuery.Execution.QueryExecutionContext qc)
    {
        var results = new List<object?>();
        foreach (var item in items)
        {
            if (item == null) continue;
            var doc = await LoadSingleDocumentWithBase(item, baseUri, qc).ConfigureAwait(false);
            if (doc != null)
                results.Add(doc);
        }
        return results.ToArray();
    }

    private static ValueTask<object?> LoadSingleDocumentWithBase(object uriArg, string baseUri,
        PhoenixmlDb.XQuery.Execution.QueryExecutionContext qc)
    {
        var uri = PhoenixmlDb.XQuery.Functions.ConcatFunction.XQueryStringValue(
            PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(uriArg));
        if (uri == null)
            return ValueTask.FromResult<object?>(null);

        // Extract fragment identifier
        string? fragment = null;
        var hashIdx = uri.IndexOf('#', StringComparison.Ordinal);
        if (hashIdx >= 0)
        {
            fragment = uri[(hashIdx + 1)..];
            uri = uri[..hashIdx];
        }

        // Resolve against the base node's document URI
        if (uri.Length == 0)
            uri = baseUri;
        else if (!Uri.TryCreate(uri, UriKind.Absolute, out _))
        {
            if (Uri.TryCreate(baseUri, UriKind.Absolute, out var baseUriObj))
                uri = new Uri(baseUriObj, uri).AbsoluteUri;
        }

        var doc = qc.DocumentResolver!.ResolveDocument(uri);
        if (doc != null)
        {
            if (fragment != null && qc.DocumentResolver is XsltDocumentResolver xsltResolver
                && xsltResolver.NodeStore is { } nodeStore)
            {
                var matches = XsltIdFunction.FindElementsById(fragment, doc, nodeStore);
                if (matches.Length > 0)
                    return ValueTask.FromResult(matches[0]);
                return ValueTask.FromResult<object?>(null);
            }
            return ValueTask.FromResult<object?>(doc);
        }
        throw new XsltException($"FODC0005: Cannot retrieve document at URI '{uri}'");
    }
}

/// <summary>
/// XSLT key() function — looks up keys defined by xsl:key.
/// </summary>
internal sealed class XsltKeyFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    [ThreadStatic]
    private static HashSet<string>? _keysBeingBuilt;

    public XsltKeyFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "key");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore
    };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "name"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String },
        new() { Name = new QName(NamespaceId.None, "value"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.AnyAtomicType, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore } }
    ];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var keyName = arguments[0]?.ToString() ?? "";

        // XTDE1260: Validate key name is a valid QName
        try
        {
            var colonIdx = keyName.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx >= 0)
            {
                System.Xml.XmlConvert.VerifyNCName(keyName[..colonIdx]);
                System.Xml.XmlConvert.VerifyNCName(keyName[(colonIdx + 1)..]);
            }
            else
            {
                System.Xml.XmlConvert.VerifyNCName(keyName);
            }
        }
        catch (System.Xml.XmlException)
        {
            throw new XsltException($"XTDE1260: The first argument of the key() function ('{keyName}') is not a valid QName");
        }

        // Look up the xsl:key definition in the stylesheet
        var keyDef = ResolveKeyDefinition(keyName);
        if (keyDef == null)
            throw new XsltException($"XTDE1260: No xsl:key declaration found with name '{keyName}'");

        // Detect re-entrancy (circular key references)
        var keysSet = _keysBeingBuilt ??= new HashSet<string>();
        if (!keysSet.Add(keyName))
            throw new XsltException($"XTDE0640: Circular reference detected in key '{keyName}'");

        try
        {
            // Collect individual lookup values from the second argument (typed for eq comparison)
            // In BC mode (XSLT 1.0), convert lookup values to strings first per XSLT 1.0 semantics
            var bcMode = _context.IsBackwardsCompatibleMode;
            var lookupTypedValues = bcMode
                ? GetIndividualStringValues(arguments[1]).Cast<object>().ToList()
                : GetIndividualTypedValues(arguments[1]);

            // Resolve collation comparer for string matching
            StringComparer? collationComparer = keyDef.Collation != null
                ? DefaultXsltExecutionContext.GetCollationComparer(keyDef.Collation) : null;

            // Find the document containing the context node (key() 2-arg searches context document)
            // Prefer XQuery context (set by path step evaluator) over XSLT context,
            // so that document('')/key(...) searches the stylesheet document, not the source.
            var contextItem = _context.CurrentItem ?? _context.ContextItem;
            // Guard: only when context is non-null (EvaluateKeyPattern passes null context)
            if (context != null)
            {
                try
                {
                    var xqContextItem = context.ContextItem;
                    if (xqContextItem is XdmNode xqNode && _context.FindDocumentForNode(xqNode) != null)
                        contextItem = xqContextItem;
                }
                catch (InvalidOperationException) { /* absent focus */ }
            }

            // XTDE1270: key() requires document-rooted nodes
            XdmNode? searchRoot;
            var isSubtreeScoped = arguments.Count > 2;
            if (isSubtreeScoped)
            {
                // 3-argument: search subtree rooted at the third argument (XSLT 3.0 §16.3.2)
                var thirdArg = arguments[2];
                if (thirdArg is not XdmNode thirdNode || _context.FindDocumentForNode(thirdNode) == null)
                    throw new XsltException("XTDE1270: The root of the tree containing the node supplied as the third argument to key() is not a document node");
                searchRoot = thirdNode;
            }
            else
            {
                // 2-argument: search context document
                if (contextItem == null)
                    throw new XsltException("XTDE1270: The key() function with two arguments requires a context node, but there is no context node");
                if (contextItem is not XdmNode contextNode || _context.FindDocumentForNode(contextNode) == null)
                    throw new XsltException("XTDE1270: The root of the tree containing the context node is not a document node");
                searchRoot = _context.FindDocumentForNode(contextNode);
            }

            // Collect candidate nodes from the search root
            var candidates = new List<XdmNode>();
            if (searchRoot != null)
            {
                // For 3-arg key(), include the search root itself (it's part of its own subtree)
                if (isSubtreeScoped)
                    candidates.Add(searchRoot);
                CollectDescendants(searchRoot, candidates);
            }
            else if (_context._nodeStore != null)
                candidates.AddRange(_context._nodeStore.GetAllNodes());

            // Build index: match nodes and evaluate use expression
            // Iterate all definitions for this key name (supports multiple xsl:key with same name)
            var isComposite = keyDef.Composite;
            var results = new List<object>();
            var seen = new HashSet<NodeId>();
            foreach (var node in candidates)
            {
                foreach (var def in keyDef.AllDefinitions)
                {
                    bool defMatched;
                    using (var mc = _context.AcquireMatchContext())
                        defMatched = def.Match.Matches(node, mc.Value);
                    if (defMatched)
                    {
                        var useValues = await EvaluateUseExpression(def, node).ConfigureAwait(false);
                        if (isComposite)
                        {
                            // Composite key: all use values form a single tuple, compared componentwise
                            if (useValues.Count == lookupTypedValues.Count)
                            {
                                bool allMatch = true;
                                for (int i = 0; i < useValues.Count; i++)
                                {
                                    var uv = bcMode ? (object)DefaultXsltExecutionContext.StringValueOf(useValues[i]) : useValues[i];
                                    if (!KeyValueEquals(uv, lookupTypedValues[i], collationComparer))
                                    {
                                        allMatch = false;
                                        break;
                                    }
                                }
                                if (allMatch && seen.Add(node.Id))
                                    results.Add(node);
                            }
                        }
                        else
                        {
                            // Non-composite: each use value is a separate key
                            foreach (var rawUv in useValues)
                            {
                                var uv = bcMode ? (object)DefaultXsltExecutionContext.StringValueOf(rawUv) : rawUv;
                                foreach (var lv in lookupTypedValues)
                                {
                                    if (KeyValueEquals(uv, lv, collationComparer) && seen.Add(node.Id))
                                    {
                                        results.Add(node);
                                        break;
                                    }
                                }
                                if (seen.Contains(node.Id))
                                    break;
                            }
                        }
                    }
                    if (seen.Contains(node.Id))
                        break; // already added by another definition
                }
            }
            return results.Count > 0 ? results.ToArray() : Array.Empty<object>();
        }
        finally
        {
            keysSet.Remove(keyName);
        }
    }

    /// <summary>
    /// Extracts individual string values from a key() argument.
    /// When the argument is a sequence, each item produces a separate lookup value.
    /// </summary>
    internal static HashSet<string> GetIndividualStringValues(object? value, StringComparer? comparer = null)
    {
        var values = new HashSet<string>(comparer ?? StringComparer.Ordinal);
        switch (value)
        {
            case null:
                break;
            case object[] arr:
                foreach (var item in arr)
                    values.Add(DefaultXsltExecutionContext.StringValueOf(item));
                break;
            case IEnumerable<object?> seq when value is not string && value is not XdmNode:
                foreach (var item in seq)
                    values.Add(DefaultXsltExecutionContext.StringValueOf(item));
                break;
            default:
                values.Add(DefaultXsltExecutionContext.StringValueOf(value));
                break;
        }
        return values;
    }

    /// <summary>
    /// Extracts individual typed values from a key() argument, preserving XPath types
    /// (integers, doubles, DateTimeOffset, etc.) instead of converting to strings.
    /// </summary>
    internal static List<object> GetIndividualTypedValues(object? value)
    {
        var values = new List<object>();
        switch (value)
        {
            case null:
                break;
            case ResultTreeFragment rtf:
                // RTFs (temporary trees from variables/params without as="") are string-valued
                values.Add(rtf.ToString());
                break;
            case object[] arr:
                foreach (var item in arr)
                {
                    if (item is ResultTreeFragment itemRtf)
                        values.Add(itemRtf.ToString());
                    else if (item != null)
                        values.Add(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(item) ?? item);
                }
                break;
            case IEnumerable<object?> seq when value is not string && value is not XdmNode:
                foreach (var item in seq)
                {
                    if (item is ResultTreeFragment seqRtf)
                        values.Add(seqRtf.ToString());
                    else if (item != null)
                        values.Add(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(item) ?? item);
                }
                break;
            default:
                values.Add(PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(value) ?? value);
                break;
        }
        return values;
    }

    /// <summary>
    /// Compares two key values using XPath eq semantics for key matching.
    /// Returns true if the values are equal under typed comparison rules.
    /// NaN != NaN, different incompatible types → no match.
    /// </summary>
    internal static bool KeyValueEquals(object? useValue, object? lookupValue, StringComparer? collationComparer = null)
    {
        if (useValue is null || lookupValue is null)
            return useValue is null && lookupValue is null;

        // Normalize untyped-atomic and anyURI wrappers to their underlying string.
        // A use="@attr" value atomizes to xs:untypedAtomic (a CLR XsUntypedAtomic struct,
        // not a string), so without this it would never match a string lookup key.
        // Per XPath key-matching semantics an xs:untypedAtomic use value compares against
        // the lookup value as though cast to the lookup value's type — string-vs-string
        // here, and the cast-to-numeric branch below handles the numeric-lookup case.
        // xs:anyURI is promotable to xs:string, so it is normalized the same way.
        if (useValue is XsUntypedAtomic useUntyped)
            useValue = useUntyped.Value;
        else if (useValue is XsAnyUri useUri)
            useValue = useUri.Value;
        if (lookupValue is XsUntypedAtomic lookupUntyped)
            lookupValue = lookupUntyped.Value;
        else if (lookupValue is XsAnyUri lookupUri)
            lookupValue = lookupUri.Value;

        var useIsNumeric = IsNumericForKey(useValue);
        var lookupIsNumeric = IsNumericForKey(lookupValue);

        // Both numeric: compare with numeric promotion, NaN != NaN
        if (useIsNumeric && lookupIsNumeric)
        {
            var ud = Convert.ToDouble(useValue, System.Globalization.CultureInfo.InvariantCulture);
            var ld = Convert.ToDouble(lookupValue, System.Globalization.CultureInfo.InvariantCulture);
            if (double.IsNaN(ud) || double.IsNaN(ld))
                return false;
            return ud == ld;
        }

        // Both strings: string comparison (using collation if specified)
        if (useValue is string us && lookupValue is string ls)
            return collationComparer != null
                ? collationComparer.Equals(us, ls)
                : string.Equals(us, ls, StringComparison.Ordinal);

        // xs:untypedAtomic (string) vs typed: cast the string to the typed type
        if (useValue is string useStr && lookupIsNumeric)
        {
            if (double.TryParse(useStr, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out var d))
            {
                var ld = Convert.ToDouble(lookupValue, System.Globalization.CultureInfo.InvariantCulture);
                if (double.IsNaN(d) || double.IsNaN(ld))
                    return false;
                return d == ld;
            }
            return false;
        }
        if (lookupValue is string lookupStr && useIsNumeric)
        {
            // Typed use value vs string lookup → different types, no match
            // (Per XSLT spec, only untyped use values get promoted, not the other way)
            return false;
        }

        // Date/time comparison with new types
        if (useValue is XsDateTime uxdt && lookupValue is XsDateTime lxdt)
            return uxdt.Value.UtcDateTime == lxdt.Value.UtcDateTime;
        if (useValue is XsDate uxd && lookupValue is XsDate lxd)
            return uxd == lxd;
        if (useValue is XsTime uxt && lookupValue is XsTime lxt)
            return uxt == lxt;

        // DateTimeOffset comparison
        if (useValue is DateTimeOffset udto && lookupValue is DateTimeOffset ldto)
            return udto.UtcDateTime == ldto.UtcDateTime;

        // DateOnly comparison
        if (useValue is DateOnly udo && lookupValue is DateOnly ldo)
            return udo == ldo;

        // Fall back to object equality
        return object.Equals(useValue, lookupValue);
    }

    private static bool IsNumericForKey(object? obj) =>
        obj is byte or sbyte or short or ushort or int or uint or long or ulong
            or float or double or decimal or System.Numerics.BigInteger;

    /// <summary>
    /// Resolves a key name (lexical QName) to the corresponding XsltKey definition.
    /// Handles both unprefixed names and prefixed names like "baz:mykey".
    /// </summary>
    internal PhoenixmlDb.Xslt.Ast.XsltKey? ResolveKeyDefinition(string keyName)
    {
        // Try exact QName lookup (for unprefixed names)
        var qname = new QName(NamespaceId.None, keyName);
        if (_context._stylesheet.Keys.TryGetValue(qname, out var keyDef))
            return keyDef;

        // Handle namespace-prefixed key names like "baz:mykey"
        var colonIdx = keyName.IndexOf(':', StringComparison.Ordinal);
        if (colonIdx > 0)
        {
            var prefix = keyName[..colonIdx];
            var localName = keyName[(colonIdx + 1)..];

            // Resolve prefix to namespace URI using stylesheet namespace bindings,
            // then use the parser's static namespace resolver (keys are stored with parser-time IDs)
            if (_context._stylesheet.Namespaces.TryGetValue(prefix, out var nsUri))
            {
                var nsId = StylesheetParser.ResolveNamespaceUri(nsUri);
                var nsQname = new QName(nsId, localName);
                if (_context._stylesheet.Keys.TryGetValue(nsQname, out keyDef))
                    return keyDef;
            }


        }

        return null;
    }

    /// <summary>
    /// Evaluates the use expression (or use content) for a matched node,
    /// returning individual typed values (preserving XPath types for proper eq comparison).
    /// </summary>
    private async ValueTask<List<object>> EvaluateUseExpression(PhoenixmlDb.Xslt.Ast.XsltKey keyDef, XdmNode node)
    {
        var values = new List<object>();
        _context.PushContextItem(node, 1, 1);
        try
        {
            object? result = null;
            if (keyDef.Use != null)
                result = await _context.EvaluateAsync(keyDef.Use).ConfigureAwait(false);
            else if (keyDef.UseContent != null)
                result = await _context.EvaluateSequenceConstructorAsync(keyDef.UseContent).ConfigureAwait(false);
            else
                return values;

            // Each item in the result produces a separate key value (atomized, preserving type)
            if (result is null)
            {
                // null result → no key value
            }
            else if (result is object[] arr)
            {
                foreach (var item in arr)
                {
                    if (item != null)
                    {
                        var a = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(item);
                        values.Add(a ?? item);
                    }
                }
            }
            else if (result is IEnumerable<object?> seq && result is not string && result is not XdmNode)
            {
                foreach (var el in seq)
                {
                    if (el != null)
                    {
                        var a = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(el);
                        values.Add(a ?? el);
                    }
                }
            }
            else
            {
                var atomized = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(result);
                values.Add(atomized ?? result);
            }
        }
        finally
        {
            _context.PopContextItem();
        }
        return values;
    }

    private void CollectDescendants(object? node, List<XdmNode> descendants)
    {
        if (node == null || _context._nodeStore == null)
            return;

        if (node is XdmDocument doc)
        {
            foreach (var childId in doc.Children)
            {
                var child = _context._nodeStore.GetNode(childId);
                if (child != null)
                { descendants.Add(child); CollectDescendants(child, descendants); }
            }
        }
        else if (node is XdmElement elem)
        {
            // Include attributes
            foreach (var attrId in elem.Attributes)
            {
                var attr = _context._nodeStore.GetNode(attrId);
                if (attr != null)
                    descendants.Add(attr);
            }
            foreach (var childId in elem.Children)
            {
                var child = _context._nodeStore.GetNode(childId);
                if (child != null)
                { descendants.Add(child); CollectDescendants(child, descendants); }
            }
        }
    }
}

/// <summary>
/// XSLT key() with 3 args (name, value, top).
/// </summary>
internal sealed class XsltKey3Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltKey3Function(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "key");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore
    };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "name"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String },
        new() { Name = new QName(NamespaceId.None, "value"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.AnyAtomicType, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore } },
        new() { Name = new QName(NamespaceId.None, "top"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ExactlyOne } }
    ];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var keyName = arguments[0]?.ToString() ?? "";
        var topNode = arguments[2];

        // XTDE1270: The root of the tree containing the 3rd argument must be a document node
        if (topNode is XdmNode topXdmNode)
        {
            var docRoot = _context.FindDocumentForNode(topXdmNode);
            if (docRoot == null)
                throw new XsltException("XTDE1270: The root of the tree containing the node supplied as the third argument to key() is not a document node");
        }
        else if (topNode is not System.Xml.Linq.XNode)
        {
            throw new XsltException("XTDE1270: The third argument to key() must be a node");
        }

        // Resolve key name using shared resolver (handles namespace-prefixed names)
        var keyFunc = new XsltKeyFunction(_context);
        var keyDef = keyFunc.ResolveKeyDefinition(keyName);
        if (keyDef == null)
            return Array.Empty<object>();

        if (_context._nodeStore == null)
            return Array.Empty<object>();

        // Collect individual lookup values from the second argument (typed for eq comparison)
        var lookupTypedValues = XsltKeyFunction.GetIndividualTypedValues(arguments[1]);

        // Resolve collation comparer for string matching
        StringComparer? collationComparer = keyDef.Collation != null
            ? DefaultXsltExecutionContext.GetCollationComparer(keyDef.Collation) : null;

        // Collect all nodes in the tree rooted at $top (per XSLT spec §20.2)
        // This includes $top itself plus all its descendants
        var descendants = new List<XdmNode>();
        if (topNode is XdmNode topForCollection)
            descendants.Add(topForCollection);
        CollectDescendants(topNode, descendants);

        var isComposite = keyDef.Composite;
        var results = new List<object>();
        var seen = new HashSet<NodeId>();
        foreach (var node in descendants)
        {
            foreach (var def in keyDef.AllDefinitions)
            {
                bool defMatched;
                using (var mc = _context.AcquireMatchContext())
                    defMatched = def.Match.Matches(node, mc.Value);
                if (defMatched)
                {
                    var useValues = await EvaluateUseExpression(def, node).ConfigureAwait(false);
                    if (isComposite)
                    {
                        // Composite key: all use values form a single tuple, compared componentwise
                        if (useValues.Count == lookupTypedValues.Count)
                        {
                            bool allMatch = true;
                            for (int i = 0; i < useValues.Count; i++)
                            {
                                if (!XsltKeyFunction.KeyValueEquals(useValues[i], lookupTypedValues[i], collationComparer))
                                {
                                    allMatch = false;
                                    break;
                                }
                            }
                            if (allMatch && seen.Add(node.Id))
                                results.Add(node);
                        }
                    }
                    else
                    {
                        // Non-composite: each use value is a separate key
                        foreach (var uv in useValues)
                        {
                            foreach (var lv in lookupTypedValues)
                            {
                                if (XsltKeyFunction.KeyValueEquals(uv, lv, collationComparer) && seen.Add(node.Id))
                                {
                                    results.Add(node);
                                    break;
                                }
                            }
                            if (seen.Contains(node.Id))
                                break;
                        }
                    }
                }
                if (seen.Contains(node.Id))
                    break;
            }
        }

        return results.Count > 0 ? results.ToArray() : Array.Empty<object>();
    }

    private async ValueTask<List<object>> EvaluateUseExpression(PhoenixmlDb.Xslt.Ast.XsltKey keyDef, XdmNode node)
    {
        var values = new List<object>();
        _context.PushContextItem(node, 1, 1);
        try
        {
            object? result = null;
            if (keyDef.Use != null)
                result = await _context.EvaluateAsync(keyDef.Use).ConfigureAwait(false);
            else if (keyDef.UseContent != null)
                result = await _context.EvaluateSequenceConstructorAsync(keyDef.UseContent).ConfigureAwait(false);
            else
                return values;

            if (result is null)
            {
                // null result → no key value
            }
            else if (result is object[] arr)
            {
                foreach (var item in arr)
                {
                    if (item != null)
                    {
                        var a = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(item);
                        values.Add(a ?? item);
                    }
                }
            }
            else if (result is IEnumerable<object?> seq && result is not string && result is not XdmNode)
            {
                foreach (var el in seq)
                {
                    if (el != null)
                    {
                        var a = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(el);
                        values.Add(a ?? el);
                    }
                }
            }
            else
            {
                var atomized = PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(result);
                values.Add(atomized ?? result);
            }
        }
        finally
        {
            _context.PopContextItem();
        }
        return values;
    }

    private void CollectDescendants(object? node, List<XdmNode> descendants)
    {
        if (node == null || _context._nodeStore == null)
            return;

        if (node is XdmDocument doc)
        {
            foreach (var childId in doc.Children)
            {
                var child = _context._nodeStore.GetNode(childId);
                if (child != null)
                { descendants.Add(child); CollectDescendants(child, descendants); }
            }
        }
        else if (node is XdmElement elem)
        {
            foreach (var attrId in elem.Attributes)
            {
                var attr = _context._nodeStore.GetNode(attrId);
                if (attr != null)
                    descendants.Add(attr);
            }
            foreach (var childId in elem.Children)
            {
                var child = _context._nodeStore.GetNode(childId);
                if (child != null)
                { descendants.Add(child); CollectDescendants(child, descendants); }
            }
        }
    }
}

/// <summary>
/// XSLT system-property() function.
/// </summary>
internal sealed class XsltSystemPropertyFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "system-property");
    public override XdmSequenceType ReturnType => XdmSequenceType.String;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "property-name"), Type = XdmSequenceType.String }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec && qec.InsideXslEvaluate)
            throw new XsltException("XTDE3160: The function system-property() is not available within xsl:evaluate");
        var name = arguments[0]?.ToString() ?? "";
        // XTDE1390: Validate name is a valid QName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE1390", "system-property");
        // Resolve and strip prefix if present
        string? namespaceUri = null;
        if (name.StartsWith("Q{", StringComparison.Ordinal))
        {
            var braceClose = name.IndexOf('}', StringComparison.Ordinal);
            if (braceClose > 1)
            {
                namespaceUri = name[2..braceClose];
                name = name[(braceClose + 1)..];
            }
        }
        else if (name.Contains(':', StringComparison.Ordinal))
        {
            var parts = name.Split(':');
            var prefix = parts[0];
            var bindings = (context as PhoenixmlDb.XQuery.Execution.QueryExecutionContext)?.PrefixNamespaceBindings;
            if (bindings != null)
            {
                // XTDE1390: Verify prefix is declared in scope
                if (!bindings.TryGetValue(prefix, out var resolvedUri))
                    throw new XsltException($"XTDE1390: Namespace prefix '{prefix}' in the argument to system-property() has not been declared");
                namespaceUri = resolvedUri;
            }
            name = parts[1];
        }
        // Only return system properties for the XSLT namespace.
        // Unprefixed names are in no namespace — they don't match XSLT properties.
        var xsltNs = "http://www.w3.org/1999/XSL/Transform";
        if (namespaceUri != xsltNs)
            return ValueTask.FromResult<object?>("");
        var result = name switch
        {
            "version" => "3.0",
            "vendor" => "PhoenixmlDb",
            "vendor-url" => "https://endpointsystems.com",
            "product-name" => "PhoenixmlDb XSLT",
            "product-version" => typeof(XsltTransformEngine).Assembly.GetName().Version?.ToString(3) ?? "1.0",
            "is-schema-aware" => "no",
            "supports-serialization" => "yes",
            "supports-backwards-compatibility" => "yes",
            "supports-namespace-axis" => "yes",
            "supports-streaming" => "yes",
            "supports-dynamic-evaluation" => "yes",
            "supports-higher-order-functions" => "yes",
            "xpath-version" => "4.0",
            "xsd-version" => "1.1",
            _ => ""
        };
        return ValueTask.FromResult<object?>(result);
    }
}

/// <summary>
/// XSLT available-system-properties() function.
/// </summary>
internal sealed class XsltAvailableSystemPropertiesFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private const string XsltNamespaceUri = "http://www.w3.org/1999/XSL/Transform";

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "available-system-properties");
    public override XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.QName,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrMore
    };
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        string[] localNames =
        [
            "version", "vendor", "vendor-url",
            "product-name", "product-version",
            "is-schema-aware", "supports-serialization",
            "supports-backwards-compatibility",
            "supports-namespace-axis", "supports-streaming",
            "supports-dynamic-evaluation", "supports-higher-order-functions",
            "xpath-version", "xsd-version"
        ];

        // Use hash-based NamespaceId consistent with the QName() constructor function
        var nsId = new NamespaceId((uint)Math.Abs(XsltNamespaceUri.GetHashCode(StringComparison.Ordinal)));
        var props = new List<object>(localNames.Length);
        foreach (var ln in localNames)
        {
            props.Add(new QName(nsId, ln, "xsl") { RuntimeNamespace = XsltNamespaceUri });
        }
        return ValueTask.FromResult<object?>(props);
    }
}

/// <summary>
/// XSLT type-available() function.
/// </summary>
internal sealed class XsltTypeAvailableFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "type-available");
    public override XdmSequenceType ReturnType => XdmSequenceType.Boolean;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "type-name"), Type = XdmSequenceType.String }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var name = arguments[0]?.ToString() ?? "";
        // XTDE1428: Validate name is a valid EQName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE1428", "type-available");
        // Strip prefix
        if (name.Contains(':', StringComparison.Ordinal))
        {
            var parts = name.Split(':');
            name = parts[1];
        }
        // Common XSD types
        var available = name switch
        {
            "string" or "boolean" or "decimal" or "float" or "double" or
            "integer" or "long" or "int" or "short" or "byte" or
            "nonNegativeInteger" or "positiveInteger" or "nonPositiveInteger" or "negativeInteger" or
            "unsignedLong" or "unsignedInt" or "unsignedShort" or "unsignedByte" or
            "date" or "time" or "dateTime" or "duration" or
            "dayTimeDuration" or "yearMonthDuration" or
            "anyURI" or "QName" or "NOTATION" or "hexBinary" or "base64Binary" or
            "normalizedString" or "token" or "language" or "NMTOKEN" or "Name" or "NCName" or
            "gYearMonth" or "gYear" or "gMonthDay" or "gDay" or "gMonth" or
            "untyped" or "untypedAtomic" or "anyAtomicType" or "anySimpleType" or "anyType" or
            "IDREF" or "IDREFS" or "ENTITY" or "ENTITIES" or "NMTOKENS" or "ID" => true,
            _ => false
        };
        return ValueTask.FromResult<object?>(available);
    }
}

/// <summary>
/// Shared URI resolution and file reading for unparsed-text functions.
/// </summary>
internal static class UnparsedTextHelper
{
    internal static string? ResolveFilePath(string href, Uri? baseUri)
    {
        if (Uri.TryCreate(href, UriKind.Absolute, out var absUri) && absUri.IsFile)
            return absUri.LocalPath;

        if (baseUri != null)
        {
            var resolved = new Uri(baseUri, href);
            if (resolved.IsFile && System.IO.File.Exists(resolved.LocalPath))
                return resolved.LocalPath;
        }

        if (System.IO.File.Exists(href))
            return href;

        return null;
    }

    /// <summary>
    /// Checks that text does not contain characters forbidden in XML (NUL U+0000).
    /// Throws FOUT1190 if invalid characters are found.
    /// </summary>
    internal static void ValidateTextContent(string text)
    {
        if (text.Contains('\0', StringComparison.Ordinal))
            throw new XsltException("FOUT1190: The text resource contains a character that is not permitted in XML (NUL U+0000)");
    }

    /// <summary>
    /// Reads a file with automatic encoding detection:
    /// 1. BOM detection (UTF-8, UTF-16 LE/BE, UTF-32)
    /// 2. XML declaration encoding sniffing (for files starting with &lt;?xml)
    /// 3. UTF-8 fallback
    /// </summary>
    internal static async Task<string> ReadWithEncodingDetectionAsync(string filePath)
    {
        var bytes = await System.IO.File.ReadAllBytesAsync(filePath).ConfigureAwait(false);
        var encoding = DetectEncoding(bytes);
        var text = encoding.GetString(bytes);
        // Strip BOM character (U+FEFF) if present at start of decoded text
        if (text.Length > 0 && text[0] == '\uFEFF')
            text = text[1..];
        return text;
    }

    private static System.Text.Encoding DetectEncoding(byte[] bytes)
    {
        if (bytes.Length == 0)
            return System.Text.Encoding.UTF8;

        // Check BOM
        if (bytes.Length >= 3 && bytes[0] == 0xEF && bytes[1] == 0xBB && bytes[2] == 0xBF)
            return System.Text.Encoding.UTF8;
        if (bytes.Length >= 2 && bytes[0] == 0xFF && bytes[1] == 0xFE)
            return System.Text.Encoding.Unicode; // UTF-16 LE
        if (bytes.Length >= 2 && bytes[0] == 0xFE && bytes[1] == 0xFF)
            return System.Text.Encoding.BigEndianUnicode; // UTF-16 BE

        // Try to detect XML encoding declaration: <?xml ... encoding="..."?>
        // Only check ASCII-compatible bytes for the prolog
        if (bytes.Length >= 5 && bytes[0] == '<' && bytes[1] == '?' && bytes[2] == 'x' && bytes[3] == 'm' && bytes[4] == 'l')
        {
            // Find encoding="..." in the XML declaration (scan ASCII bytes)
            var prologEnd = System.Array.IndexOf(bytes, (byte)'>', 5);
            if (prologEnd > 0 && prologEnd < 200)
            {
                var prolog = System.Text.Encoding.ASCII.GetString(bytes, 0, prologEnd);
                var encIdx = prolog.IndexOf("encoding", StringComparison.OrdinalIgnoreCase);
                if (encIdx > 0)
                {
                    var eqIdx = prolog.IndexOf('=', encIdx + 8);
                    if (eqIdx > 0)
                    {
                        var quote = eqIdx + 1 < prolog.Length ? prolog[eqIdx + 1] : '\0';
                        if (quote is '"' or '\'')
                        {
                            var closeQuote = prolog.IndexOf(quote, eqIdx + 2);
                            if (closeQuote > 0)
                            {
                                var encName = prolog[(eqIdx + 2)..closeQuote].Trim();
                                try
                                {
                                    return System.Text.Encoding.GetEncoding(encName);
                                }
                                catch (ArgumentException)
                                {
                                    // Unknown encoding, fall through to UTF-8
                                }
                            }
                        }
                    }
                }
            }
        }

        return System.Text.Encoding.UTF8;
    }
}

/// <summary>
/// XSLT unparsed-text() function — reads text files.
/// </summary>
internal sealed class XsltUnparsedTextFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltUnparsedTextFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "unparsed-text");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalString;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "href"), Type = XdmSequenceType.OptionalString }];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var href = arguments[0]?.ToString();
        if (string.IsNullOrEmpty(href))
            return null;

        try
        {
            // Check policy and try custom resolver first
            var policyText = _context.ResolveUnparsedTextViaPolicy(href, null);
            if (policyText != null)
            {
                UnparsedTextHelper.ValidateTextContent(policyText);
                return policyText;
            }

            var filePath = UnparsedTextHelper.ResolveFilePath(href, _context._stylesheet.BaseUri);
            if (filePath != null)
            {
                var text = await UnparsedTextHelper.ReadWithEncodingDetectionAsync(filePath).ConfigureAwait(false);
                UnparsedTextHelper.ValidateTextContent(text);
                return text;
