/// <summary>
/// XSLT stream-available() function — checks if a URI resolves to streamable XML.
/// </summary>
internal sealed class XsltStreamAvailableFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltStreamAvailableFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "stream-available");
    public override XdmSequenceType ReturnType => XdmSequenceType.Boolean;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "uri"), Type = XdmSequenceType.String }];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var uri = arguments[0]?.ToString();
        if (string.IsNullOrEmpty(uri))
            return false;

        try
        {
            // Resolve URI
            string? filePath = null;
            if (Uri.TryCreate(uri, UriKind.Absolute, out var absUri) && absUri.IsFile)
            {
                filePath = absUri.LocalPath;
            }
            else if (_context._stylesheet.BaseUri != null)
            {
                var resolved = new Uri(_context._stylesheet.BaseUri, uri);
                if (resolved.IsFile)
                    filePath = resolved.LocalPath;
            }
            else if (System.IO.File.Exists(uri))
            {
                filePath = uri;
            }

            if (filePath == null || !System.IO.File.Exists(filePath))
                return false;

            // Check if the file contains parseable XML
            var stream = System.IO.File.OpenRead(filePath);
            await using var _ = stream.ConfigureAwait(false);
            var settings = new System.Xml.XmlReaderSettings
            {
                DtdProcessing = System.Xml.DtdProcessing.Ignore,
                XmlResolver = null,
                ConformanceLevel = System.Xml.ConformanceLevel.Fragment,
                Async = true
            };
            using var reader = System.Xml.XmlReader.Create(stream, settings);
            // Try to read the first element — if we can, the stream is available
            while (await reader.ReadAsync().ConfigureAwait(false))
            {
                if (reader.NodeType == System.Xml.XmlNodeType.Element)
                    return true;
            }
            // No element found (e.g., DTD-only file)
            return false;
        }
        catch (Exception ex) when (ex is IOException or System.Xml.XmlException or UnauthorizedAccessException)
        {
            return false;
        }
    }
}

/// <summary>
/// XSLT current-output-uri() function.
/// </summary>
internal sealed class XsltCurrentOutputUriFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "current-output-uri");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalString;
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec && qec.InsideXslEvaluate)
            throw new XsltException("XTDE3160: The function current-output-uri() is not available within xsl:evaluate");
        // Per XSLT 3.0 §20.3.7: The current-output-uri property is initially absent.
        // When absent, calling current-output-uri() returns an empty sequence.
        // Since we don't track output URIs for result-document (inline output),
        // return explicit empty sequence (not null, which may cause issues in sequence construction).
        return ValueTask.FromResult<object?>(Array.Empty<object>());
    }
}

