internal sealed class XsltAccumulatorBeforeFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltAccumulatorBeforeFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "accumulator-before");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalItem;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "name"), Type = XdmSequenceType.String }];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var name = arguments[0]?.ToString() ?? throw new XsltException("XTDE3340: accumulator-before() requires a name argument");
        // XTDE3340: Validate the name is a valid EQName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE3340", "accumulator-before");
        var accName = _context.ResolveAccumulatorName(name);

        // XTDE3340: Check if the accumulator is applicable in the current mode
        if (!_context.IsAccumulatorApplicable(accName))
            throw new XsltException($"XTDE3340: Accumulator '{name}' is not applicable in the current mode (not listed in use-accumulators)");

        // Use XQuery context item (from path step) if available, fall back to XSLT context item.
        // The XQuery context is preferred because in path expressions like $v/w/accumulator-before('x'),
        // the XSLT context is the template match node, not the path step's current node.
        object? node;
        try { node = context.ContextItem; } catch (InvalidOperationException) { node = null; }
        node ??= _context.ContextItem
            ?? throw new XsltException("XTDE3340: accumulator-before() called with no context item");

        // Lazily compute accumulators for this document if not yet done
        await _context.EnsureAccumulatorsComputedAsync(accName, node).ConfigureAwait(false);

        var values = _context.GetAccumulatorValue(accName, node)
            ?? throw new XsltException($"XTDE3340: No accumulator named '{name}' is available for the current node");

        // Re-throw deferred errors from accumulator evaluation
        if (values.before is AccumulatorDeferredError deferredError)
            throw deferredError.Error;
        return values.before;
    }
}

internal sealed class XsltAccumulatorAfterFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltAccumulatorAfterFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "accumulator-after");
    public override XdmSequenceType ReturnType => XdmSequenceType.OptionalItem;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "name"), Type = XdmSequenceType.String }];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var name = arguments[0]?.ToString() ?? throw new XsltException("XTDE3340: accumulator-after() requires a name argument");
        // XTDE3340: Validate the name is a valid EQName
        XsltFunctionValidation.ValidateQNameArgument(name, "XTDE3340", "accumulator-after");
        var accName = _context.ResolveAccumulatorName(name);

        // XTDE3340: Check if the accumulator is applicable in the current mode
        if (!_context.IsAccumulatorApplicable(accName))
            throw new XsltException($"XTDE3340: Accumulator '{name}' is not applicable in the current mode (not listed in use-accumulators)");

        // Use XQuery context item (from path step) if available, fall back to XSLT context item.
        // The XQuery context is preferred because in path expressions like $v/w/accumulator-after('x'),
        // the XSLT context is the template match node, not the path step's current node.
        object? node;
        try { node = context.ContextItem; } catch (InvalidOperationException) { node = null; }
        node ??= _context.ContextItem
            ?? throw new XsltException("XTDE3340: accumulator-after() called with no context item");

        // Lazily compute accumulators for this document if not yet done
        await _context.EnsureAccumulatorsComputedAsync(accName, node).ConfigureAwait(false);

        var values = _context.GetAccumulatorValue(accName, node, isAfter: true)
            ?? throw new XsltException($"XTDE3340: No accumulator named '{name}' is available for the current node");

        // Re-throw deferred errors from accumulator evaluation
        if (values.after is AccumulatorDeferredError deferredError)
            throw deferredError.Error;

        return values.after;
    }
}

/// <summary>
/// IDocumentResolver for XSLT — loads documents via file URIs, converts to XDM,
/// and caches them so repeated doc() calls for the same URI return the same document.
/// </summary>
internal sealed class XsltDocumentResolver : PhoenixmlDb.XQuery.IDocumentResolver
{
    private readonly XsltStylesheet _stylesheet;
    private readonly XdmInMemoryStore? _nodeStore;
    private readonly Dictionary<string, XdmDocument?> _cache = new(StringComparer.OrdinalIgnoreCase);
    private Dictionary<string, List<string>>? _collections;

    /// <summary>
    /// Pre-fetched contents for URIs the host already loaded asynchronously. Consulted
    /// before <see cref="HttpDocumentLoader.OpenRead"/>; required on Blazor WebAssembly.
    /// </summary>
    internal PreloadedResources? PreloadedResources { get; set; }

    /// <summary>Set of absolute URIs that have been read via doc()/document() during this transformation.</summary>
    internal IReadOnlyCollection<string> ReadDocumentUris => _cache.Keys;

    public XsltDocumentResolver(XsltStylesheet stylesheet, XdmInMemoryStore? nodeStore)
    {
        _stylesheet = stylesheet;
        _nodeStore = nodeStore;
    }

    /// <summary>The node store used for ID lookups in fragment identifiers.</summary>
    internal XdmInMemoryStore? NodeStore => _nodeStore;

    public void SetCollections(Dictionary<string, List<string>> collections)
    {
        _collections = collections;
    }

    /// <summary>
    /// Pre-populates the document cache with the source document so that
    /// doc(document-uri(.)) returns the same node (identity preservation).
    /// </summary>
    public void SeedSourceDocument(XdmDocument doc)
    {
        if (doc.DocumentUri != null)
            _cache[doc.DocumentUri] = doc;
    }

    public XdmDocument? ResolveDocument(string uri)
    {
        // Per XSLT spec, document('') and doc('') return the stylesheet document
        if (uri.Length == 0 && _stylesheet.BaseUri != null)
            uri = _stylesheet.BaseUri.AbsoluteUri;

        if (_cache.TryGetValue(uri, out var cached))
            return cached;

        var doc = LoadDocument(uri);
        _cache[uri] = doc;
        return doc;
    }

    public bool IsDocumentAvailable(string uri)
    {
        // Per XSLT spec, document('') and doc('') return the stylesheet document
        if (uri.Length == 0 && _stylesheet.BaseUri != null)
            uri = _stylesheet.BaseUri.AbsoluteUri;

        if (_cache.TryGetValue(uri, out var cached))
            return cached != null;

        try
        {
            var resolvedUri = ResolveUri(uri);
            if (resolvedUri.IsFile)
                return System.IO.File.Exists(resolvedUri.LocalPath);
            if (resolvedUri.Scheme == Uri.UriSchemeHttp || resolvedUri.Scheme == Uri.UriSchemeHttps)
            {
                // For HTTP we have to fetch (or HEAD) to know — reuse ResolveDocument so
                // a successful fetch is cached and the next doc() call is free.
                return ResolveDocument(uri) != null;
            }
            return false;
        }
        catch (UriFormatException)
        {
            return false;
        }
        catch (System.IO.IOException)
        {
            return false;
        }
    }

    public IEnumerable<XdmNode> ResolveCollection(string? uri)
    {
        if (_collections == null)
            return [];

        var key = uri ?? "";
        if (!_collections.TryGetValue(key, out var paths))
            return [];

        var nodes = new List<XdmNode>();
        foreach (var path in paths)
        {
            // Handle fragment identifiers (e.g., "doc15.xml#frag2")
            var hashIdx = path.IndexOf('#', StringComparison.Ordinal);
            var filePath = hashIdx >= 0 ? path[..hashIdx] : path;
            var fragment = hashIdx >= 0 ? path[(hashIdx + 1)..] : null;

            var doc = LoadDocument(filePath);
            if (doc == null)
                continue;

            if (fragment != null && _nodeStore != null)
            {
                // Fragment identifier selects element by xml:id
                var matches = XsltIdFunction.FindElementsById(fragment, doc, _nodeStore);
                foreach (var match in matches)
                {
                    if (match is XdmNode node)
                        nodes.Add(node);
                }
            }
            else
            {
                nodes.Add(doc);
            }
        }
        return nodes;
    }

    private Uri ResolveUri(string uri)
    {
        if (Uri.TryCreate(uri, UriKind.Absolute, out var absUri))
            return absUri;

        if (_stylesheet.BaseUri != null)
            return new Uri(_stylesheet.BaseUri, uri);

        return new Uri(uri, UriKind.RelativeOrAbsolute);
    }

    private XdmDocument? LoadDocument(string uri)
    {
        try
        {
            var resolvedUri = ResolveUri(uri);
            if (!resolvedUri.IsAbsoluteUri)
                return null;

            string xmlContent;
            if (resolvedUri.Scheme == Uri.UriSchemeHttp || resolvedUri.Scheme == Uri.UriSchemeHttps)
            {
                // Fetch over HTTP. Same opt-in-by-scheme rule as xsl:import — if a stylesheet
                // running over HTTPS calls fn:doc with a relative URI that resolves to HTTPS,
                // we honor it. ResourcePolicy still gates this when configured (the policy-
                // enforcing wrapper sits in front of this resolver in the call chain).
                //
                // Preload-cache check: callers running on Blazor WebAssembly (or any runtime
                // that disallows monitor waits) must supply pre-fetched content here, since
                // the synchronous HttpClient call below blocks the calling thread.
                if (PreloadedResources is { } preloaded && preloaded.TryGet(resolvedUri, out var preloadedContent))
                {
                    xmlContent = preloadedContent;
                }
                else if (OperatingSystem.IsBrowser())
                {
                    throw new XsltException(
                        $"FODC0002: Cannot fetch '{resolvedUri}' on Blazor WebAssembly: " +
                        "synchronous HTTP I/O is not supported. Pre-fetch the document " +
                        "asynchronously and pass it through PreloadedResources to LoadStylesheetAsync.");
                }
                else
                {
                    using var stream = HttpDocumentLoader.OpenRead(resolvedUri);
                    using var reader = new System.IO.StreamReader(stream);
                    xmlContent = reader.ReadToEnd();
                }
            }
            else if (resolvedUri.IsFile)
            {
                if (!System.IO.File.Exists(resolvedUri.LocalPath))
                    return null;
                xmlContent = System.IO.File.ReadAllText(resolvedUri.LocalPath);
            }
            else
            {
                return null;
            }

            var xmlDoc = new XmlDocument { PreserveWhitespace = true };
            xmlDoc.LoadXml(xmlContent);

            var nodeStore = _nodeStore ?? new XdmInMemoryStore();
            var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, nodeStore, resolvedUri.AbsoluteUri);

            // Apply xsl:strip-space declarations
            if (_stylesheet.StripSpace.Count > 0)
            {
                foreach (var nt in _stylesheet.StripSpace)
                    nt.ResolveNamespace(nodeStore.InternNamespace);
                foreach (var nt in _stylesheet.PreserveSpace)
                    nt.ResolveNamespace(nodeStore.InternNamespace);

                XsltTransformEngine.StripWhitespaceNodes(xdmDoc, _stylesheet.StripSpace, _stylesheet.PreserveSpace, nodeStore);
            }

            return xdmDoc;
        }
        catch (UriFormatException)
        {
            return null;
        }
        catch (System.IO.IOException)
        {
            return null;
        }
        catch (System.Net.Http.HttpRequestException)
        {
            return null;
        }
        catch (TaskCanceledException)
        {
            return null;
        }
        catch (XmlException)
        {
            return null;
        }
    }
}

/// <summary>
/// Sentinel value stored in accumulator value maps when evaluation raises a dynamic error.
/// The error is deferred until the accumulator value is accessed.
/// </summary>
internal sealed record AccumulatorDeferredError(Exception Error);

/// <summary>
/// fn:lang($testlang) as xs:boolean — checks xml:lang on context node and ancestors.
/// </summary>
internal sealed class XsltLangFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltLangFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "lang");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.Boolean;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "testlang"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalString }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var testLang = arguments[0]?.ToString() ?? "";
        var node = context.ContextItem;
        return ValueTask.FromResult<object?>(MatchLang(testLang, node));
    }

    internal bool MatchLang(string testLang, object? node)
    {
        // Walk up the ancestor chain looking for xml:lang attribute
        var current = node;
        while (current is XdmNode xdmNode)
        {
            if (current is XdmElement elem)
            {
                foreach (var attr in _context._nodeStore!.GetAttributes(elem))
                {
                    if (attr.Namespace == NamespaceId.Xml &&
                        string.Equals(attr.LocalName, "lang", StringComparison.Ordinal))
                    {
                        // Found xml:lang — check if it matches
                        return LangMatches(attr.Value, testLang);
                    }
                }
            }
            // Move to parent
            if (xdmNode.Parent.HasValue)
                current = _context._nodeStore?.GetNode(xdmNode.Parent.Value);
            else
                break;
        }
        return false;
    }

    /// <summary>
    /// Per XPath spec: lang('en') matches 'en', 'EN', 'en-US', etc.
    /// The language matches if testLang equals the lang value or is a prefix followed by '-'.
    /// </summary>
    private static bool LangMatches(string langValue, string testLang)
    {
        if (string.Equals(langValue, testLang, StringComparison.OrdinalIgnoreCase))
            return true;
        if (langValue.Length > testLang.Length &&
            langValue[testLang.Length] == '-' &&
            langValue.StartsWith(testLang, StringComparison.OrdinalIgnoreCase))
            return true;
        return false;
    }
}

/// <summary>
