/// <summary>
/// XSLT-aware fn:deep-equal($parameter1, $parameter2) — performs proper structural comparison of XDM nodes.
/// </summary>
internal sealed class XsltDeepEqualFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltDeepEqualFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "deep-equal");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.Boolean;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "parameter1"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems },
        new() { Name = new QName(NamespaceId.None, "parameter2"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // Resolve the effective collation: use the XSLT transformer's default collation
        var collationUri = _context.DefaultCollation;
        var comparison = collationUri switch
        {
            null or "" or "http://www.w3.org/2005/xpath-functions/collation/codepoint" => StringComparison.Ordinal,
            "http://www.w3.org/2005/xpath-functions/collation/html-ascii-case-insensitive" => StringComparison.OrdinalIgnoreCase,
            _ when collationUri.StartsWith("http://www.w3.org/2013/collation/UCA", StringComparison.Ordinal) => StringComparison.InvariantCultureIgnoreCase,
            _ => StringComparison.Ordinal
        };

        var seqA = ToList(arguments[0]);
        var seqB = ToList(arguments[1]);

        if (seqA.Count != seqB.Count)
            return ValueTask.FromResult<object?>(false);

        for (int i = 0; i < seqA.Count; i++)
        {
            if (!DeepEqualItems(seqA[i], seqB[i], comparison))
                return ValueTask.FromResult<object?>(false);
        }
        return ValueTask.FromResult<object?>(true);
    }

    private static List<object?> ToList(object? arg) => arg switch
    {
        null => [],
        IEnumerable<object?> seq => seq.ToList(),
        _ => [arg]
    };

    private bool DeepEqualItems(object? a, object? b, StringComparison comparison)
    {
        if (a is null && b is null)
            return true;
        if (a is null || b is null)
            return false;

        // Both are nodes — structural comparison
        if (a is XdmNode nodeA && b is XdmNode nodeB)
            return DeepEqualNodes(nodeA, nodeB, comparison);

        // Both are atomic — value comparison
        return PhoenixmlDb.XQuery.Execution.TypeCastHelper.DeepEquals(
            PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(a),
            PhoenixmlDb.XQuery.Execution.QueryExecutionContext.Atomize(b),
            comparison);
    }

    private bool DeepEqualNodes(XdmNode a, XdmNode b, StringComparison comparison)
    {
        if (a.NodeKind != b.NodeKind)
            return false;
        var store = _context._nodeStore;
        if (store == null)
            return false;

        return (a, b) switch
        {
            (XdmElement elemA, XdmElement elemB) => DeepEqualElements(elemA, elemB, store, comparison),
            (XdmText, XdmText) => string.Equals(a.StringValue, b.StringValue, comparison),
            (XdmComment, XdmComment) => string.Equals(a.StringValue, b.StringValue, StringComparison.Ordinal),
            (XdmDocument docA, XdmDocument docB) => DeepEqualChildren(docA, docB, store, comparison),
            _ when a.IsProcessingInstruction && b.IsProcessingInstruction =>
                a.NodeName?.LocalName == b.NodeName?.LocalName &&
                string.Equals(a.StringValue, b.StringValue, StringComparison.Ordinal),
            _ when a.IsAttribute && b.IsAttribute =>
                a.NodeName?.LocalName == b.NodeName?.LocalName &&
                a.NodeName?.Namespace == b.NodeName?.Namespace &&
                string.Equals(a.StringValue, b.StringValue, comparison),
            (XdmNamespace nsA, XdmNamespace nsB) =>
                string.Equals(nsA.Prefix, nsB.Prefix, StringComparison.Ordinal) &&
                string.Equals(nsA.Uri, nsB.Uri, comparison),
            _ => false
        };
    }

    private bool DeepEqualElements(XdmElement a, XdmElement b, XdmInMemoryStore store, StringComparison comparison)
    {
        // Compare element names (names always use ordinal comparison)
        if (a.Namespace != b.Namespace || !string.Equals(a.LocalName, b.LocalName, StringComparison.Ordinal))
            return false;

        // Compare attributes (unordered)
        var attrsA = store.GetAttributes(a).ToList();
        var attrsB = store.GetAttributes(b).ToList();
        if (attrsA.Count != attrsB.Count)
            return false;

        foreach (var attrA in attrsA)
        {
            var match = attrsB.FirstOrDefault(ab =>
                ab.Namespace == attrA.Namespace &&
                string.Equals(ab.LocalName, attrA.LocalName, StringComparison.Ordinal));
            if (match == null || !string.Equals(attrA.Value, match.Value, comparison))
                return false;
        }

        // Compare children (ordered)
        return DeepEqualChildren(a, b, store, comparison);
    }

    private bool DeepEqualChildren(XdmNode a, XdmNode b, XdmInMemoryStore store, StringComparison comparison)
    {
        var childrenA = store.GetChildren(a).ToList();
        var childrenB = store.GetChildren(b).ToList();
        if (childrenA.Count != childrenB.Count)
            return false;

        for (int i = 0; i < childrenA.Count; i++)
        {
            if (!DeepEqualNodes(childrenA[i], childrenB[i], comparison))
                return false;
        }
        return true;
    }
}

/// <summary>
/// fn:outermost($nodes as node()*) as node()* — returns nodes that have no ancestor in the input sequence.
/// </summary>
internal sealed class XsltOutermostFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltOutermostFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "outermost");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "nodes"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var items = arguments[0] switch
        {
            null => Array.Empty<object?>(),
            IEnumerable<object?> seq => seq.ToArray(),
            _ => new[] { arguments[0] }
        };

        var store = _context._nodeStore;
        if (store == null || items.Length == 0)
            return ValueTask.FromResult<object?>(items);

        // Collect all node IDs in the input
        var nodeIds = new HashSet<NodeId>();
        foreach (var item in items)
        {
            if (item is XdmNode node)
                nodeIds.Add(node.Id);
        }

        // Filter: keep nodes whose ancestor chain doesn't contain another node from the set
        var result = new List<object?>();
        foreach (var item in items)
        {
            if (item is XdmNode node)
            {
                var hasAncestorInSet = false;
                var current = node;
                while (current.Parent.HasValue)
                {
                    var parent = store.GetNode(current.Parent.Value);
                    if (parent == null)
                        break;
                    if (nodeIds.Contains(parent.Id))
                    {
                        hasAncestorInSet = true;
                        break;
                    }
                    current = parent;
                }
                if (!hasAncestorInSet)
                    result.Add(item);
            }
            else
            {
                result.Add(item); // non-node items pass through
            }
        }

        return ValueTask.FromResult<object?>(result.ToArray());
    }
}

/// <summary>
/// fn:innermost($nodes as node()*) as node()* — returns nodes that have no descendant in the input sequence.
/// </summary>
internal sealed class XsltInnermostFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltInnermostFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "innermost");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "nodes"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.ZeroOrMoreItems }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var items = arguments[0] switch
        {
            null => Array.Empty<object?>(),
            IEnumerable<object?> seq => seq.ToArray(),
            _ => new[] { arguments[0] }
        };

        var store = _context._nodeStore;
        if (store == null || items.Length == 0)
            return ValueTask.FromResult<object?>(items);

        // Collect all node IDs in the input
        var nodeIds = new HashSet<NodeId>();
        foreach (var item in items)
        {
            if (item is XdmNode node)
                nodeIds.Add(node.Id);
        }

        // For innermost: exclude nodes that are ancestors of another node in the set.
        // Walk each node's ancestor chain; mark ancestors that are in the set as "has descendant in set"
        var hasDescendantInSet = new HashSet<NodeId>();
        foreach (var item in items)
        {
            if (item is XdmNode node)
            {
                var current = node;
                while (current.Parent.HasValue)
                {
                    var parent = store.GetNode(current.Parent.Value);
                    if (parent == null)
                        break;
                    if (nodeIds.Contains(parent.Id))
                        hasDescendantInSet.Add(parent.Id);
                    current = parent;
                }
            }
        }

        // Keep only nodes not marked
        var result = new List<object?>();
        foreach (var item in items)
        {
            if (item is XdmNode node)
            {
                if (!hasDescendantInSet.Contains(node.Id))
                    result.Add(item);
            }
            else
            {
                result.Add(item);
            }
        }

        return ValueTask.FromResult<object?>(result.ToArray());
    }
}

/// <summary>
/// fn:snapshot($input as item()*) as item()* — creates deep copies of nodes independent from original tree.
/// Ancestors are preserved as shallow copies (only the path to the target node).
/// </summary>
internal sealed class XsltSnapshotFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltSnapshotFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "snapshot");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Item, Occurrence = Occurrence.ZeroOrMore };
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "input"), Type = new XdmSequenceType { ItemType = ItemType.Item, Occurrence = Occurrence.ZeroOrMore } }];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var input = arguments[0];
        return await SnapshotHelper.ProcessSnapshotAsync(input, _context).ConfigureAwait(false);
    }
}

/// <summary>
/// fn:snapshot() as item() — 0-arg version, snapshots the context item.
/// </summary>
internal sealed class XsltSnapshot0Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltSnapshot0Function(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "snapshot");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Item, Occurrence = Occurrence.ExactlyOne };
    public override IReadOnlyList<FunctionParameterDef> Parameters => [];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var item = context.ContextItem ?? _context.ContextItem;
        if (item is null)
            return null;
        return await SnapshotHelper.ProcessSnapshotAsync(item, _context).ConfigureAwait(false);
    }
}

/// <summary>
/// Helper class for fn:snapshot implementation. Creates pruned deep copies of nodes.
/// </summary>
internal static class SnapshotHelper
{
    /// <summary>
    /// Deep copy items without ancestor chains (for fn:copy-of).
    /// </summary>
    public static object? DeepCopyItems(object? input, XdmInMemoryStore store,
        Dictionary<NodeId, NodeId>? nodeMapping = null)
    {
        if (input is null)
            return null;
        var docId = new DocumentId(1);

        if (input is object?[] arr)
        {
            var results = new List<object?>();
            foreach (var item in arr)
            {
                if (item is XdmNode node)
                    results.Add(DeepCopyNode(node, NodeId.None, docId, store, nodeMapping));
                else if (item is not null)
                    results.Add(item);
            }
            return results.ToArray();
        }

        if (input is IEnumerable<object?> seq && input is not XdmNode)
        {
            var results = new List<object?>();
            foreach (var item in seq)
            {
                if (item is XdmNode node)
                    results.Add(DeepCopyNode(node, NodeId.None, docId, store, nodeMapping));
                else if (item is not null)
                    results.Add(item);
            }
            return results.ToArray();
        }

        if (input is XdmNode singleNode)
            return DeepCopyNode(singleNode, NodeId.None, docId, store, nodeMapping);

        return input;
    }

    public static async ValueTask<object?> ProcessSnapshotAsync(object? input, DefaultXsltExecutionContext context)
    {
        if (input is null)
            return null;

        // Ensure accumulators are computed for source nodes before snapshot
        if (context._stylesheet.Accumulators.Count > 0)
        {
            foreach (var accName in context._stylesheet.Accumulators.Keys)
                await context.EnsureAccumulatorsComputedForInputAsync(accName, input).ConfigureAwait(false);
        }

        var nodeMapping = new Dictionary<NodeId, NodeId>();

        if (input is object?[] arr)
        {
            var results = new List<object?>();
            foreach (var item in arr)
            {
                if (item is not null)
                    results.Add(SnapshotItem(item, context, nodeMapping));
            }
            context.CopyAccumulatorValues(nodeMapping);
            return results.ToArray();
        }

        var result = SnapshotItem(input, context, nodeMapping);
        context.CopyAccumulatorValues(nodeMapping);
        return result;
    }

    public static object? SnapshotItem(object item, DefaultXsltExecutionContext context,
        Dictionary<NodeId, NodeId>? nodeMapping = null)
    {
        if (item is not XdmNode node)
            return item; // Non-node items pass through unchanged

        var store = context._nodeStore;
        if (store is null)
            return item;

        var docId = new DocumentId(1);

        // Build the ancestor chain from root to the target node
        var ancestors = new List<XdmNode>();
        var current = node;
        while (current.Parent is { } parentId && parentId != NodeId.None)
        {
            var parent = store.GetNode(parentId);
            if (parent is null)
                break;
            ancestors.Add(parent);
            current = parent;
        }
        ancestors.Reverse(); // Now: root → ... → parent of target

        // Case 1: Document node — deep copy the entire document
        if (node is XdmDocument)
        {
            return DeepCopyNode(node, NodeId.None, docId, store, nodeMapping);
        }

        // Case 2: Orphan node (no parent) — deep copy just the node
        if (ancestors.Count == 0)
        {
            return DeepCopyNode(node, NodeId.None, docId, store, nodeMapping);
        }

        // Case 3: Node with ancestors — create pruned tree
        XdmNode? previousCopy = null;
        NodeId previousCopyId = NodeId.None;

        foreach (var ancestor in ancestors)
        {
            if (ancestor is XdmDocument ancestorDoc)
            {
                var newDocId = store.NextId();
                nodeMapping?.TryAdd(ancestorDoc.Id, newDocId);
                var newDoc = new XdmDocument
                {
                    Id = newDocId,
                    Document = docId,
                    Parent = NodeId.None,
                    DocumentUri = null, // Snapshot docs lose their URI
                    Children = [] // Will be updated via LinkChild
                };
                store.Register(newDoc);
                previousCopy = newDoc;
                previousCopyId = newDocId;
            }
            else if (ancestor is XdmElement ancestorElem)
            {
                var newElemId = store.NextId();
                nodeMapping?.TryAdd(ancestorElem.Id, newElemId);

                // Copy attributes
                var newAttrIds = new List<NodeId>();
                foreach (var attrId in ancestorElem.Attributes)
                {
                    if (store.GetNode(attrId) is XdmAttribute origAttr)
                    {
                        var newAttrId = store.NextId();
                        nodeMapping?.TryAdd(origAttr.Id, newAttrId);
                        var newAttr = new XdmAttribute
                        {
                            Id = newAttrId,
                            Document = docId,
                            Parent = newElemId,
                            Namespace = origAttr.Namespace,
                            LocalName = origAttr.LocalName,
                            Prefix = origAttr.Prefix,
                            Value = origAttr.Value
                        };
                        store.Register(newAttr);
                        newAttrIds.Add(newAttrId);
                    }
                }

                var newElem = new XdmElement
                {
                    Id = newElemId,
                    Document = docId,
                    Parent = previousCopyId,
                    Namespace = ancestorElem.Namespace,
                    LocalName = ancestorElem.LocalName,
                    Prefix = ancestorElem.Prefix,
                    Attributes = newAttrIds,
                    Children = [], // Will be updated via LinkChild
                    NamespaceDeclarations = ancestorElem.NamespaceDeclarations
                };
                store.Register(newElem);

                // Link previous level to this element
                LinkChild(previousCopy, newElemId, store);

                previousCopy = newElem;
                previousCopyId = newElemId;
            }
        }

        // Deep-copy the target node and attach it to the last ancestor copy
        var targetCopy = DeepCopyNode(node, previousCopyId, docId, store, nodeMapping);

        // Link the target copy to the last ancestor
        if (targetCopy is not null)
            LinkChild(previousCopy, targetCopy.Id, store);

        // Compute string values for ancestor chain
        if (targetCopy is not null)
            ComputeAncestorStringValues(previousCopy, targetCopy, store);

        return targetCopy;
    }

    private static void LinkChild(XdmNode? parent, NodeId childId, XdmInMemoryStore store)
    {
        if (parent is XdmDocument doc)
        {
            var newDoc = new XdmDocument
            {
                Id = doc.Id,
                Document = doc.Document,
                Parent = doc.Parent,
                DocumentUri = doc.DocumentUri,
                DocumentElement = childId,
                Children = [childId],
                DocumentElementLocalName = (store.GetNode(childId) as XdmElement)?.LocalName
            };
            store.Register(newDoc);
        }
        else if (parent is XdmElement elem)
        {
            var newElem = new XdmElement
            {
                Id = elem.Id,
                Document = elem.Document,
                Parent = elem.Parent,
                Namespace = elem.Namespace,
                LocalName = elem.LocalName,
                Prefix = elem.Prefix,
                Attributes = elem.Attributes,
                Children = [childId],
                NamespaceDeclarations = elem.NamespaceDeclarations
            };
            // Recompute string value after adding child
            var child = store.GetNode(childId);
            newElem._stringValue = child?.StringValue ?? elem.StringValue;
            store.Register(newElem);
        }
    }

    private static void ComputeAncestorStringValues(XdmNode? lastAncestorCopy, XdmNode targetCopy, XdmInMemoryStore store)
    {
        var targetStringValue = targetCopy.StringValue;
        var current = lastAncestorCopy;
        while (current is not null)
        {
            if (current is XdmElement e)
                e._stringValue = targetStringValue;
            else if (current is XdmDocument d)
                d._stringValue = targetStringValue;

            if (current.Parent is { } pid && pid != NodeId.None)
                current = store.GetNode(pid);
            else
                break;
        }
    }

    private static XdmNode? DeepCopyNode(XdmNode node, NodeId parentId, DocumentId docId,
        XdmInMemoryStore store, Dictionary<NodeId, NodeId>? nodeMapping = null)
    {
        switch (node)
        {
            case XdmDocument doc:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(doc.Id, newId);
                var childIds = new List<NodeId>();
                NodeId? docElemId = null;

                foreach (var childId in doc.Children)
                {
                    if (store.GetNode(childId) is { } child)
                    {
                        var copy = DeepCopyNode(child, newId, docId, store, nodeMapping);
                        if (copy is not null)
                        {
                            childIds.Add(copy.Id);
                            if (copy is XdmElement && docElemId is null)
                                docElemId = copy.Id;
                        }
                    }
                }

                var newDoc = new XdmDocument
                {
                    Id = newId,
                    Document = docId,
                    Parent = NodeId.None,
                    DocumentUri = null,
                    DocumentElement = docElemId,
                    Children = childIds,
                    DocumentElementLocalName = docElemId.HasValue ? (store.GetNode(docElemId.Value) as XdmElement)?.LocalName : null
                };
                newDoc._stringValue = doc.StringValue;
                store.Register(newDoc);
                return newDoc;
            }

            case XdmElement elem:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(elem.Id, newId);

                // Copy attributes
                var newAttrIds = new List<NodeId>();
                foreach (var attrId in elem.Attributes)
                {
                    if (store.GetNode(attrId) is XdmAttribute origAttr)
                    {
                        var newAttrId = store.NextId();
                        nodeMapping?.TryAdd(origAttr.Id, newAttrId);
                        var newAttr = new XdmAttribute
                        {
                            Id = newAttrId,
                            Document = docId,
                            Parent = newId,
                            Namespace = origAttr.Namespace,
                            LocalName = origAttr.LocalName,
                            Prefix = origAttr.Prefix,
                            Value = origAttr.Value
                        };
                        store.Register(newAttr);
                        newAttrIds.Add(newAttrId);
                    }
                }

                // Deep copy children
                var childIds = new List<NodeId>();
                foreach (var childId in elem.Children)
                {
                    if (store.GetNode(childId) is { } child)
                    {
                        var copy = DeepCopyNode(child, newId, docId, store, nodeMapping);
                        if (copy is not null)
                            childIds.Add(copy.Id);
                    }
                }

                var newElem = new XdmElement
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Namespace = elem.Namespace,
                    LocalName = elem.LocalName,
                    Prefix = elem.Prefix,
                    Attributes = newAttrIds,
                    Children = childIds,
                    NamespaceDeclarations = elem.NamespaceDeclarations
                };
                newElem._stringValue = elem.StringValue;
                store.Register(newElem);
                return newElem;
            }

            case XdmText text:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(text.Id, newId);
                var newText = new XdmText
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Value = text.Value
                };
                store.Register(newText);
                return newText;
            }

            case XdmComment comment:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(comment.Id, newId);
                var newComment = new XdmComment
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Value = comment.Value
                };
                store.Register(newComment);
                return newComment;
            }

            case XdmProcessingInstruction pi:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(pi.Id, newId);
                var newPi = new XdmProcessingInstruction
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Target = pi.Target,
                    Value = pi.Value
                };
                store.Register(newPi);
                return newPi;
            }

            case XdmAttribute attr:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(attr.Id, newId);
                var newAttr = new XdmAttribute
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Namespace = attr.Namespace,
                    LocalName = attr.LocalName,
                    Prefix = attr.Prefix,
                    Value = attr.Value
                };
                store.Register(newAttr);
                return newAttr;
            }

            case XdmNamespace ns:
            {
                var newId = store.NextId();
                nodeMapping?.TryAdd(ns.Id, newId);
                var newNs = new XdmNamespace
                {
                    Id = newId,
                    Document = docId,
                    Parent = parentId,
                    Prefix = ns.Prefix,
                    Uri = ns.Uri
                };
                store.Register(newNs);
                return newNs;
            }

            default:
                return null;
        }
    }
}

