    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var node = context.ContextItem ?? _context.ContextItem;
        var hasChildren = node switch
        {
            XdmDocument doc => doc.Children.Count > 0,
            XdmElement elem => elem.Children.Count > 0,
            _ => false
        };
        return ValueTask.FromResult<object?>(hasChildren);
    }
}

// ─── fn:parse-xml ───────────────────────────────────────────────────────────

/// <summary>
/// fn:parse-xml($arg as xs:string?) as document-node(element(*))?
/// Parses an XML document from a string and returns a document node.
/// </summary>
internal sealed class XsltParseXmlFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltParseXmlFunction(DefaultXsltExecutionContext context) { _context = context; }

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "parse-xml");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Document, Occurrence = Occurrence.ZeroOrOne };
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "arg"), Type = XdmSequenceType.OptionalString }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var arg = arguments[0];
        if (arg == null)
            return ValueTask.FromResult<object?>(null);
        var xmlStr = arg.ToString() ?? "";
        try
        {
            // Convert to XDM so XPath axis navigation works (e.g., $tree//e)
            if (_context._nodeStore != null)
            {
                var xmlDoc = new System.Xml.XmlDocument();
                xmlDoc.PreserveWhitespace = true;
                xmlDoc.LoadXml(xmlStr);
                var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, _context._nodeStore, documentUri: null);
                // Temporary trees have no document URI per XSLT 3.0 §11.9.1
                xdmDoc.DocumentUri = null;
                return ValueTask.FromResult<object?>(xdmDoc);
            }
            // Fallback to LINQ XDocument when no node store available
            var doc = System.Xml.Linq.XDocument.Parse(xmlStr);
            return ValueTask.FromResult<object?>(doc);
        }
        catch (System.Xml.XmlException ex)
        {
            throw new XsltException($"FODC0006: Error parsing XML: {ex.Message}");
        }
    }
}

// ─── fn:parse-xml-fragment ──────────────────────────────────────────────────

/// <summary>
/// fn:parse-xml-fragment($arg as xs:string?) as document-node()?
/// Parses an XML fragment from a string and returns a document node.
/// </summary>
internal sealed class XsltParseXmlFragmentFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltParseXmlFragmentFunction(DefaultXsltExecutionContext context) { _context = context; }

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "parse-xml-fragment");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Document, Occurrence = Occurrence.ZeroOrOne };
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
        [new() { Name = new QName(NamespaceId.None, "arg"), Type = XdmSequenceType.OptionalString }];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var arg = arguments[0];
        if (arg == null)
            return ValueTask.FromResult<object?>(null);
        var xmlStr = arg.ToString() ?? "";
        if (string.IsNullOrEmpty(xmlStr))
        {
            if (_context._nodeStore != null)
            {
                // Create an empty XDM document node directly
                var docId = _context._nodeStore.NextId();
                var emptyDoc = new Xdm.Nodes.XdmDocument
                {
                    Id = docId,
                    Document = new DocumentId(1),
                    Parent = NodeId.None,
                    DocumentElement = NodeId.None,
                    DocumentUri = null,
                    Children = [],
                };
                emptyDoc._stringValue = "";
                _context._nodeStore.Register(emptyDoc);
                return ValueTask.FromResult<object?>(emptyDoc);
            }
            return ValueTask.FromResult<object?>(new System.Xml.Linq.XDocument());
        }
        try
        {
            if (_context._nodeStore != null)
            {
                // Wrap in a root element to handle fragments with multiple roots or text content
                var xmlDoc = new System.Xml.XmlDocument();
                xmlDoc.PreserveWhitespace = true;
                var wasWrapped = false;
                try
                {
                    xmlDoc.LoadXml(xmlStr);
                }
                catch (System.Xml.XmlException)
                {
                    xmlDoc.LoadXml($"<_rtf_root_>{xmlStr}</_rtf_root_>");
                    wasWrapped = true;
                }
                var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, _context._nodeStore, documentUri: null);
                xdmDoc.DocumentUri = null;
                if (wasWrapped)
                    xdmDoc.BaseUri = null;
                return ValueTask.FromResult<object?>(xdmDoc);
            }
            // Fallback to LINQ XDocument when no node store available
            var wrapped = $"<_r>{xmlStr}</_r>";
            var tempDoc = System.Xml.Linq.XDocument.Parse(wrapped);
            var doc = new System.Xml.Linq.XDocument();
            foreach (var node in tempDoc.Root!.Nodes())
                doc.Add(node);
            return ValueTask.FromResult<object?>(doc);
        }
        catch (System.Xml.XmlException ex)
        {
            throw new XsltException($"FODC0006: Error parsing XML fragment: {ex.Message}");
        }
    }
}

// ─── fn:xml-to-json ─────────────────────────────────────────────────────────

/// <summary>
/// fn:xml-to-json($input as node()?) as xs:string?
/// Converts the XML representation of JSON (using the XPath functions namespace)
/// back to a JSON string.
/// </summary>
internal sealed class XsltXmlToJsonFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltXmlToJsonFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "xml-to-json");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalString;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "input"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalNode }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        return ValueTask.FromResult<object?>(ToJsonString(arguments[0], _context));
    }

    /// <summary>
    /// Core of fn:xml-to-json: resolves the input to the root element of an XML JSON
    /// representation and serializes it to a (compact) JSON string. Returns null for an
    /// empty input. Shared by the 1-arg and 2-arg (options) overloads.
    /// </summary>
    internal static string? ToJsonString(object? input, DefaultXsltExecutionContext context, bool indent = false)
    {
        if (input is null)
            return null;
        // XPTY0004: xml-to-json expects a single node, not a sequence
        if (input is object?[] arr && arr.Length > 1)
            throw new XsltException("XPTY0004: A sequence of " + arr.Length + " items is not allowed as the first argument of xml-to-json()");

        var store = context._nodeStore;
        if (store is null)
            throw new XsltException("FOJS0006: xml-to-json requires a node store");

        var elem = ResolveToElement(input, store);
        if (elem is null)
            return null;

        var sb = new System.Text.StringBuilder();
        SerializeJsonElement(elem, store, sb, indent, 0);
        return sb.ToString();
    }

    internal static XdmElement? ResolveToElement(object? input, XdmInMemoryStore store)
    {
        if (input is XdmElement el)
            return el;
        if (input is XdmDocument doc)
        {
            // Find first element child, but check for multiple elements (FOJS0006)
            XdmElement? first = null;
            foreach (var childId in doc.Children)
            {
                if (store.GetNode(childId) is XdmElement child)
                {
                    if (first != null)
                        throw new XsltException("FOJS0006: xml-to-json input contains multiple element children");
                    first = child;
                }
            }
            return first;
        }
        return null;
    }

    internal static void SerializeJsonElement(XdmElement elem, XdmInMemoryStore store, System.Text.StringBuilder sb, bool indent = false, int depth = 0)
    {
        // Elements must be in the http://www.w3.org/2005/xpath-functions namespace
        var localName = elem.LocalName;

        switch (localName)
        {
            case "null":
            {
                // Null must have no non-whitespace text content and no element children
                ValidateNoElementChildren(elem, store, "null");
                var nullText = GetTextContent(elem, store).Trim();
                if (nullText.Length > 0)
                    throw new XsltException("FOJS0006: null element must have no content");
                ValidateAttributes(elem, store, "null", ["key", "escaped-key"]);
                sb.Append("null");
                break;
            }

            case "boolean":
            {
                ValidateNoElementChildren(elem, store, "boolean");
                ValidateAttributes(elem, store, "boolean", ["key", "escaped-key"]);
                var text = GetTextContent(elem, store).Trim();
                // Accepts "true", "false", "1", "0"
                sb.Append(text switch
                {
                    "true" or "1" => "true",
                    "false" or "0" => "false",
                    _ => throw new XsltException($"FOJS0006: Invalid boolean value: '{text}'")
                });
                break;
            }

            case "number":
            {
                ValidateNoElementChildren(elem, store, "number");
                ValidateAttributes(elem, store, "number", ["key", "escaped-key"]);
                var text = GetTextContent(elem, store).Trim();
                // Validate it's a valid JSON number
                if (!IsValidJsonNumber(text))
                    throw new XsltException($"FOJS0006: Invalid number value: '{text}'");
                sb.Append(text);
                break;
            }

            case "string":
            {
                // String elements must contain only text nodes (no element children)
                ValidateNoElementChildren(elem, store, "string");
                var escaped = GetAttributeValue(elem, "escaped", store);
                ValidateBooleanAttribute(escaped, "escaped");
                ValidateAttributes(elem, store, "string", ["key", "escaped-key", "escaped"]);
                var isEscaped = IsTruthy(escaped);
                var text = GetTextContent(elem, store);

                sb.Append('"');
                if (isEscaped)
                    AppendValidatedEscapedJsonString(text, sb);
                else
                    AppendJsonString(text, sb);
                sb.Append('"');
                break;
            }

            case "array":
            {
                ValidateAttributes(elem, store, "array", ["key", "escaped-key"]);
                // Array must not contain non-whitespace text
                ValidateNoSignificantText(elem, store, "array");
                sb.Append('[');
                var first = true;
                foreach (var childId in elem.Children)
                {
                    var child = store.GetNode(childId);
                    if (child is XdmElement childElem && childElem.Namespace == NamespaceId.Fn)
                    {
                        if (!first)
                            sb.Append(',');
                        if (indent)
                            XsltTransformEngine.AppendJsonNewlineIndent(sb, depth + 1);
                        first = false;
                        SerializeJsonElement(childElem, store, sb, indent, depth + 1);
                    }
                    else if (child is XdmElement childElem2)
                    {
                        // Element not in fn namespace — try processing anyway
                        // (namespace IDs may differ in RTF node stores)
                        if (!first)
                            sb.Append(',');
                        if (indent)
                            XsltTransformEngine.AppendJsonNewlineIndent(sb, depth + 1);
                        first = false;
                        SerializeJsonElement(childElem2, store, sb, indent, depth + 1);
                    }
                }
                if (!first && indent)
                    XsltTransformEngine.AppendJsonNewlineIndent(sb, depth);
                sb.Append(']');
                break;
            }

            case "map":
            {
                ValidateAttributes(elem, store, "map", ["key", "escaped-key"]);
                // Map must not contain non-whitespace text
                ValidateNoSignificantText(elem, store, "map");
                sb.Append('{');
                var first = true;
                var seenKeys = new HashSet<string>(StringComparer.Ordinal);
                foreach (var childId in elem.Children)
                {
                    var child = store.GetNode(childId);
                    if (child is XdmElement childElem && childElem.Namespace == NamespaceId.Fn)
                    {
                        if (!first)
                            sb.Append(',');
                        if (indent)
                            XsltTransformEngine.AppendJsonNewlineIndent(sb, depth + 1);
                        first = false;

                        // Get the key
                        var key = GetAttributeValue(childElem, "key", store);
                        if (key is null)
                            throw new XsltException("FOJS0006: Map entry missing 'key' attribute");

                        var escapedKey = GetAttributeValue(childElem, "escaped-key", store);
                        ValidateBooleanAttribute(escapedKey, "escaped-key");
                        var isEscapedKey = IsTruthy(escapedKey);

                        // Duplicate detection uses decoded key values
                        var decodedKey = DecodeJsonKey(key, isEscapedKey);
                        if (!XsltTransformEngine.TryAddJsonKey(seenKeys, decodedKey))
                            throw new XsltException($"FOJS0006: Duplicate key in map: '{key}'");

                        sb.Append('"');
                        if (isEscapedKey)
                            AppendValidatedEscapedJsonString(key, sb);
                        else
                            AppendJsonString(key, sb);
                        sb.Append('"');
                        sb.Append(indent ? ": " : ":");
                        SerializeJsonElement(childElem, store, sb, indent, depth + 1);
                    }
                    else if (child is XdmElement childElem2)
                    {
                        // Element not in fn namespace — try processing anyway
                        // (namespace IDs may differ in RTF node stores)
                        if (!first)
                            sb.Append(',');
                        if (indent)
                            XsltTransformEngine.AppendJsonNewlineIndent(sb, depth + 1);
                        first = false;

                        var key2 = GetAttributeValue(childElem2, "key", store);
                        if (key2 is null)
                            throw new XsltException("FOJS0006: Map entry missing 'key' attribute");

                        var escapedKey2 = GetAttributeValue(childElem2, "escaped-key", store);
                        ValidateBooleanAttribute(escapedKey2, "escaped-key");
                        var isEscapedKey2 = IsTruthy(escapedKey2);

                        var decodedKey2 = DecodeJsonKey(key2, isEscapedKey2);
                        if (!XsltTransformEngine.TryAddJsonKey(seenKeys, decodedKey2))
                            throw new XsltException($"FOJS0006: Duplicate key in map: '{key2}'");

                        sb.Append('"');
                        if (isEscapedKey2)
                            AppendValidatedEscapedJsonString(key2, sb);
                        else
                            AppendJsonString(key2, sb);
                        sb.Append('"');
                        sb.Append(indent ? ": " : ":");
                        SerializeJsonElement(childElem2, store, sb, indent, depth + 1);
                    }
                }
                if (!first && indent)
                    XsltTransformEngine.AppendJsonNewlineIndent(sb, depth);
                sb.Append('}');
                break;
            }

            default:
                throw new XsltException($"FOJS0006: Unknown JSON element type: '{localName}'");
        }
    }

    /// <summary>
    /// Gets the concatenated text content of an element (ignoring comments and PIs).
    /// </summary>
    internal static string GetTextContent(XdmElement elem, XdmInMemoryStore store)
    {
        var sb = new System.Text.StringBuilder();
        foreach (var childId in elem.Children)
        {
            var child = store.GetNode(childId);
            if (child is XdmText text)
                sb.Append(text.Value);
        }
        return sb.ToString();
    }

    /// <summary>
    /// Gets an attribute value by local name (no namespace).
    /// </summary>
    internal static string? GetAttributeValue(XdmElement elem, string localName, XdmInMemoryStore store)
    {
        foreach (var attrId in elem.Attributes)
        {
            var attr = store.GetNode(attrId) as XdmAttribute;
            if (attr != null && attr.LocalName == localName && attr.Namespace == NamespaceId.None)
                return attr.Value;
        }
        return null;
    }

    /// <summary>
    /// Checks if a string attribute value is truthy (true/1, ignoring whitespace).
    /// </summary>
    internal static bool IsTruthy(string? value)
    {
        if (value is null)
            return false;
        var trimmed = value.Trim();
        return trimmed == "true" || trimmed == "1";
    }

    /// <summary>
    /// Appends a string to the JSON output, escaping characters that need it per JSON spec.
    /// Used when escaped="false" (or absent) — the input is plain text.
    /// </summary>
    internal static void AppendJsonString(string text, System.Text.StringBuilder sb)
    {
        foreach (var c in text)
        {
            if (c == '\\') { sb.Append("\\\\"); continue; }
            CharacterEscaper.AppendJsonEscapedChar(sb, c);
        }
    }

    /// <summary>
    /// Appends a string to the JSON output when escaped="true" — the input already contains
    /// JSON escape sequences like \n, \uXXXX etc. We pass through backslash sequences as-is
    /// but still need to escape any characters that would be invalid in a JSON string.
    /// </summary>
    internal static void AppendEscapedJsonString(string text, System.Text.StringBuilder sb)
    {
        for (int i = 0; i < text.Length; i++)
        {
            var c = text[i];
            if (c == '\\' && i + 1 < text.Length)
            {
                // Pass through recognized JSON escape sequences
                var next = text[i + 1];
                switch (next)
                {
                    case '"':
                    case '\\':
                    case '/':
                    case 'b':
                    case 'f':
                    case 'n':
                    case 'r':
                    case 't':
                        sb.Append(c);
                        sb.Append(next);
                        i++;
                        continue;
                    case 'u' when i + 5 < text.Length:
                        // \uXXXX — pass through
                        sb.Append(text, i, 6);
                        i += 5;
                        continue;
                }
            }

            CharacterEscaper.AppendJsonEscapedChar(sb, c);
        }
    }

    /// <summary>
    /// Validates that a string is a valid JSON number.
    /// </summary>
    internal static bool IsValidJsonNumber(string text)
    {
        if (string.IsNullOrEmpty(text))
            return false;
        // Allow a superset: optional minus, digits, optional dot+digits, optional E/e +/- digits
        int i = 0;
        if (i < text.Length && text[i] == '-')
            i++;
        if (i >= text.Length)
            return false;

        // Integer part (allow leading zeros for lenient parsing)
        bool hasDigit = false;
        while (i < text.Length && text[i] >= '0' && text[i] <= '9')
        { i++; hasDigit = true; }

        // Fractional part
        if (i < text.Length && text[i] == '.')
        {
            i++;
            while (i < text.Length && text[i] >= '0' && text[i] <= '9')
            { i++; hasDigit = true; }
        }

        if (!hasDigit)
            return false;

        // Exponent part
        if (i < text.Length && (text[i] == 'e' || text[i] == 'E'))
        {
            i++;
            if (i < text.Length && (text[i] == '+' || text[i] == '-'))
                i++;
            bool hasExpDigit = false;
            while (i < text.Length && text[i] >= '0' && text[i] <= '9')
            { i++; hasExpDigit = true; }
            if (!hasExpDigit)
                return false;
        }

        return i == text.Length;
    }

    /// <summary>
    /// Validates that an element has no child elements (only text/comments/PIs allowed).
    /// </summary>
    internal static void ValidateNoElementChildren(XdmElement elem, XdmInMemoryStore store, string type)
    {
        foreach (var childId in elem.Children)
        {
            if (store.GetNode(childId) is XdmElement)
                throw new XsltException($"FOJS0006: {type} element must not contain child elements");
        }
    }

    /// <summary>
    /// Validates that a container element (array/map) has no non-whitespace text content.
    /// </summary>
    internal static void ValidateNoSignificantText(XdmElement elem, XdmInMemoryStore store, string type)
    {
        foreach (var childId in elem.Children)
        {
            if (store.GetNode(childId) is XdmText text && text.Value.AsSpan().Trim().Length > 0)
                throw new XsltException($"FOJS0006: {type} element must not contain text content");
        }
    }

    /// <summary>
    /// Validates that only allowed attributes are present on an element.
    /// </summary>
    internal static void ValidateAttributes(XdmElement elem, XdmInMemoryStore store, string type, string[] allowed)
    {
        foreach (var attrId in elem.Attributes)
        {
            var attr = store.GetNode(attrId) as XdmAttribute;
            if (attr == null)
                continue;
            if (attr.Namespace == NamespaceId.None)
            {
                bool found = false;
                foreach (var a in allowed)
                {
                    if (attr.LocalName == a)
                    { found = true; break; }
                }
                if (!found)
                    throw new XsltException($"FOJS0006: Invalid attribute '{attr.LocalName}' on {type} element");
            }
            else
            {
                // Check if this is an attribute in the fn namespace — reject unknown ones
                var nsUri = store.GetNamespaceUri(attr.Namespace);
                if (nsUri == "http://www.w3.org/2005/xpath-functions")
                    throw new XsltException($"FOJS0006: Invalid attribute in fn namespace '{attr.LocalName}' on {type} element");
            }
        }
    }

    /// <summary>
    /// Validates that a boolean-like attribute has value "true", "false", "1", or "0".
    /// </summary>
    internal static void ValidateBooleanAttribute(string? value, string attrName)
    {
        if (value is null)
            return;
        var trimmed = value.Trim();
        if (trimmed != "true" && trimmed != "false" && trimmed != "1" && trimmed != "0")
            throw new XsltException($"FOJS0006: Invalid value '{value}' for attribute '{attrName}'");
    }

    /// <summary>
    /// Like AppendEscapedJsonString but validates that escape sequences are valid JSON.
    /// Throws FOJS0006 for invalid escape sequences.
    /// </summary>
    internal static void AppendValidatedEscapedJsonString(string text, System.Text.StringBuilder sb)
    {
        for (int i = 0; i < text.Length; i++)
        {
            var c = text[i];
            if (c == '\\')
            {
                if (i + 1 >= text.Length)
                    throw new XsltException("FOJS0006: Incomplete escape sequence at end of string");
                var next = text[i + 1];
                switch (next)
                {
                    case '"':
                    case '\\':
                    case '/':
                    case 'b':
                    case 'f':
                    case 'n':
                    case 'r':
                    case 't':
                        sb.Append(c);
                        sb.Append(next);
                        i++;
                        continue;
                    case 'u':
                        if (i + 5 >= text.Length)
                            throw new XsltException("FOJS0006: Incomplete \\u escape sequence");
                        // Validate hex digits
                        for (int j = i + 2; j < i + 6; j++)
                        {
                            if (!IsHexDigit(text[j]))
                                throw new XsltException($"FOJS0006: Invalid \\u escape sequence: '{text.Substring(i, 6)}'");
                        }
                        sb.Append(text, i, 6);
                        i += 5;
                        continue;
                    default:
                        throw new XsltException($"FOJS0006: Invalid escape sequence '\\{next}'");
                }
            }

            CharacterEscaper.AppendJsonEscapedChar(sb, c);
        }
    }

    private static bool IsHexDigit(char c) =>
        (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F');

    /// <summary>
    /// Decodes a JSON key to its actual string value for duplicate detection.
    /// When escaped-key is true, JSON escape sequences (\n, \uXXXX, \", \\, etc.) are decoded.
    /// When escaped-key is false, the raw key IS the decoded value.
    /// </summary>
    internal static string DecodeJsonKey(string rawKey, bool isEscaped)
    {
        if (!isEscaped)
            return rawKey;

        var sb = new System.Text.StringBuilder(rawKey.Length);
        for (int i = 0; i < rawKey.Length; i++)
        {
            var c = rawKey[i];
            if (c == '\\' && i + 1 < rawKey.Length)
            {
                var next = rawKey[i + 1];
                switch (next)
                {
                    case '"':
                        sb.Append('"');
                        i++;
                        continue;
                    case '\\':
                        sb.Append('\\');
                        i++;
                        continue;
                    case '/':
                        sb.Append('/');
                        i++;
                        continue;
                    case 'b':
                        sb.Append('\b');
                        i++;
                        continue;
                    case 'f':
                        sb.Append('\f');
                        i++;
                        continue;
                    case 'n':
                        sb.Append('\n');
                        i++;
                        continue;
                    case 'r':
                        sb.Append('\r');
                        i++;
                        continue;
                    case 't':
                        sb.Append('\t');
                        i++;
                        continue;
                    case 'u' when i + 5 < rawKey.Length:
                        var hex = rawKey.Substring(i + 2, 4);
                        if (int.TryParse(hex, System.Globalization.NumberStyles.HexNumber,
                            System.Globalization.CultureInfo.InvariantCulture, out var codePoint))
                        {
                            sb.Append((char)codePoint);
                            i += 5;
                            continue;
                        }
                        break;
                }
            }
            sb.Append(c);
        }
        return sb.ToString();
    }
}

/// <summary>
/// fn:xml-to-json($input, $options) as xs:string? — 2-arg version
/// </summary>
internal sealed class XsltXmlToJson2Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltXmlToJson2Function(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "xml-to-json");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalString;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "input"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalNode },
        new() { Name = new QName(NamespaceId.None, "options"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Item, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrOne } }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // Validate options map and read the indent option.
        var options = arguments[1];
        var indent = false;
        if (options is IDictionary<object, object?> map)
        {
            if (map.TryGetValue("indent", out var indentVal))
            {
                if (indentVal is not bool b)
                    throw new XsltException("XPTY0004: Option 'indent' must be a boolean value");
                indent = b;
            }
            if (map.TryGetValue("validate", out var validateVal))
            {
                if (validateVal is not bool)
                    throw new XsltException("XPTY0004: Option 'validate' must be a boolean value");
                if (validateVal is true)
                    throw new XsltException("FOJS0004: Option 'validate' is true but the processor is not schema-aware");
            }
        }

        var json = XsltXmlToJsonFunction.ToJsonString(arguments[0], _context, indent);
        return ValueTask.FromResult<object?>(json);
    }
}

// ─── fn:json-to-xml ─────────────────────────────────────────────────────────

/// <summary>
/// fn:json-to-xml($json-text as xs:string) as document-node()?
/// Converts a JSON string to the XML representation using the XPath functions namespace.
/// </summary>
internal sealed class XsltJsonToXmlFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltJsonToXmlFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "json-to-xml");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new() { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrOne };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "json-text"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var jsonText = arguments[0]?.ToString();
        if (jsonText is null)
            return ValueTask.FromResult<object?>(null);

        var store = _context._nodeStore;
        if (store is null)
            throw new XsltException("FOJS0001: json-to-xml requires a node store");

        try
        {
            var doc = JsonToXmlConverter.Convert(jsonText, store, liberal: false, duplicates: "use-first");
            return ValueTask.FromResult<object?>(doc);
        }
        catch (System.Text.Json.JsonException ex)
        {
            throw new XsltException($"FOJS0001: Invalid JSON: {ex.Message}");
        }
    }
}

/// <summary>
/// fn:json-to-xml($json-text, $options) — 2-arg version
/// </summary>
internal sealed class XsltJsonToXml2Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltJsonToXml2Function(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "json-to-xml");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new() { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Node, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrOne };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "json-text"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String },
        new() { Name = new QName(NamespaceId.None, "options"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Item, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrOne } }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var jsonText = arguments[0]?.ToString();
        if (jsonText is null)
            return ValueTask.FromResult<object?>(null);

        var store = _context._nodeStore;
        if (store is null)
            throw new XsltException("FOJS0001: json-to-xml requires a node store");

        // Parse options map
        var liberal = false;
        var escape = false;
        var duplicates = "use-first";
        var options = arguments[1];
        if (options is IDictionary<object, object?> map)
        {
            // liberal option: must be xs:boolean
            if (map.TryGetValue("liberal", out var liberalVal))
            {
                if (liberalVal is bool lb)
                    liberal = lb;
                else if (liberalVal is null || liberalVal is object?[] arr && arr.Length == 0)
                    throw new XsltException("FOJS0001: Option 'liberal' must be a boolean value, got empty sequence");
                else
                    throw new XsltException("FOJS0001: Option 'liberal' must be a boolean value");
            }

            // validate option: must be xs:boolean
            if (map.TryGetValue("validate", out var validateVal))
            {
                if (validateVal is true)
                    throw new XsltException("FOJS0004: Option 'validate' is true but the processor is not schema-aware");
                if (validateVal is bool)
                { /* false — no action needed */ }
                else if (validateVal is null || validateVal is object?[] va && va.Length == 0)
                    throw new XsltException("XPTY0004: Option 'validate' must be a boolean value, got empty sequence");
                else if (validateVal is string)
                    throw new XsltException("XPTY0004: Option 'validate' must be a boolean value");
                else if (validateVal is object?[] va2 && va2.Length > 1)
                    throw new XsltException("XPTY0004: Option 'validate' must be a single boolean value");
                else
                    throw new XsltException("XPTY0004: Option 'validate' must be a boolean value");
            }

            // escape option: must be xs:boolean
            if (map.TryGetValue("escape", out var escapeVal))
            {
                if (escapeVal is bool eb)
                    escape = eb;
                else if (escapeVal is null || escapeVal is object?[] ea && ea.Length == 0)
                    throw new XsltException("XPTY0004: Option 'escape' must be a boolean value, got empty sequence");
                else if (escapeVal is string)
                    throw new XsltException("XPTY0004: Option 'escape' must be a boolean value");
                else if (escapeVal is object?[] ea2 && ea2.Length > 1)
                    throw new XsltException("XPTY0004: Option 'escape' must be a single boolean value");
                else
                    throw new XsltException("XPTY0004: Option 'escape' must be a boolean value");
            }

            // fallback option: must be a function
            if (map.TryGetValue("fallback", out var fallbackVal))
            {
                if (fallbackVal is not Delegate && fallbackVal is not PhoenixmlDb.XQuery.Ast.XQueryFunction)
                    throw new XsltException("XPTY0004: Option 'fallback' must be a function");
            }

            // duplicates option: must be xs:string with value use-first, retain, or reject
            if (map.TryGetValue("duplicates", out var dupVal))
            {
                if (dupVal is string ds)
                {
                    duplicates = ds switch
                    {
                        "use-first" or "retain" or "reject" => ds,
                        _ => throw new XsltException($"FOJS0005: Invalid value '{ds}' for option 'duplicates'; must be use-first, retain, or reject")
                    };
                }
                else
                    throw new XsltException("XPTY0004: Option 'duplicates' must be a string value");
            }
        }

        try
        {
            var doc = JsonToXmlConverter.Convert(jsonText, store, liberal, duplicates, escape);
            return ValueTask.FromResult<object?>(doc);
        }
        catch (System.Text.Json.JsonException ex)
        {
            throw new XsltException($"FOJS0001: Invalid JSON: {ex.Message}");
        }
    }
}

/// <summary>
/// Converts JSON strings to XDM document trees using the XPath functions namespace.
/// </summary>
internal static class JsonToXmlConverter
{
    private static readonly NamespaceId FnNs = NamespaceId.Fn;

    public static XdmDocument Convert(string json, XdmInMemoryStore store, bool liberal = false, string duplicates = "use-first", bool escape = false)
    {
        using var jsonDoc = System.Text.Json.JsonDocument.Parse(json,
            new System.Text.Json.JsonDocumentOptions { AllowTrailingCommas = liberal, CommentHandling = System.Text.Json.JsonCommentHandling.Skip });

        // Ensure the fn namespace is registered in the store for serialization
        EnsureFnNamespace(store);

        var docId = store.NextId();
        var rootElem = ConvertValue(jsonDoc.RootElement, null, store, duplicates, isRoot: true, escape: escape);

        var doc = new XdmDocument
        {
            Id = docId,
            Document = default,
            Children = new[] { rootElem.Id },
            DocumentElement = rootElem.Id
        };
        store.Register(doc);
        rootElem.Parent = docId;

        return doc;
    }

    private static XdmElement ConvertValue(System.Text.Json.JsonElement je, string? key, XdmInMemoryStore store, string duplicates, bool isRoot = false, bool escape = false)
    {
        return je.ValueKind switch
        {
            System.Text.Json.JsonValueKind.Object => ConvertObject(je, key, store, duplicates, isRoot, escape),
            System.Text.Json.JsonValueKind.Array => ConvertArray(je, key, store, duplicates, isRoot, escape),
            System.Text.Json.JsonValueKind.String => CreateStringElement(je, key, store, isRoot, escape),
            System.Text.Json.JsonValueKind.Number => CreateSimpleElement("number", je.GetRawText(), key, store, isRoot),
            System.Text.Json.JsonValueKind.True => CreateSimpleElement("boolean", "true", key, store, isRoot),
            System.Text.Json.JsonValueKind.False => CreateSimpleElement("boolean", "false", key, store, isRoot),
            System.Text.Json.JsonValueKind.Null => CreateNullElement(key, store, isRoot),
            _ => throw new XsltException($"FOJS0001: Unsupported JSON value kind: {je.ValueKind}")
        };
    }

    private static readonly IReadOnlyList<NamespaceBinding> FnNsDecl = new[] { new NamespaceBinding("", FnNs) };

    private static XdmElement ConvertObject(System.Text.Json.JsonElement je, string? key, XdmInMemoryStore store, string duplicates, bool isRoot = false, bool escape = false)
    {
        var elemId = store.NextId();
        var children = new List<NodeId>();
        var attrs = new List<NodeId>();

        if (key != null)
            AddKeyAttribute(elemId, key, attrs, store);

        var seenKeys = duplicates != "retain" ? new HashSet<string>() : null;
        foreach (var prop in je.EnumerateObject())
        {
            if (seenKeys != null && !seenKeys.Add(prop.Name))
            {
                // Duplicate key found
                if (duplicates == "reject")
                    throw new XsltException($"FOJS0003: Duplicate key '{prop.Name}' in JSON object");
                // use-first: skip subsequent occurrences
                continue;
            }
            var child = ConvertValue(prop.Value, prop.Name, store, duplicates, escape: escape);
            child.Parent = elemId;
            children.Add(child.Id);
        }

        var elem = new XdmElement
        {
            Id = elemId,
            Document = default,
            Namespace = FnNs,
            LocalName = "map",
            Prefix = null,
            Attributes = attrs,
            Children = children,
            NamespaceDeclarations = isRoot ? FnNsDecl : System.Collections.Immutable.ImmutableArray<NamespaceBinding>.Empty
        };
        store.Register(elem);
        return elem;
    }

    private static XdmElement ConvertArray(System.Text.Json.JsonElement je, string? key, XdmInMemoryStore store, string duplicates, bool isRoot = false, bool escape = false)
    {
        var elemId = store.NextId();
        var children = new List<NodeId>();
        var attrs = new List<NodeId>();

        if (key != null)
            AddKeyAttribute(elemId, key, attrs, store);

        foreach (var item in je.EnumerateArray())
        {
            var child = ConvertValue(item, null, store, duplicates, escape: escape);
            child.Parent = elemId;
            children.Add(child.Id);
        }

        var elem = new XdmElement
        {
            Id = elemId,
            Document = default,
            Namespace = FnNs,
            LocalName = "array",
            Prefix = null,
            Attributes = attrs,
            Children = children,
            NamespaceDeclarations = isRoot ? FnNsDecl : System.Collections.Immutable.ImmutableArray<NamespaceBinding>.Empty
        };
        store.Register(elem);
        return elem;
    }

    /// <summary>
    /// Creates a fn:string element, adding escaped="true" attribute when the escape option is set
    /// and the JSON string contains backslash escape sequences.
    /// </summary>
    private static XdmElement CreateStringElement(System.Text.Json.JsonElement je, string? key, XdmInMemoryStore store, bool isRoot, bool escape)
    {
        var interpreted = je.GetString() ?? "";
        if (!escape)
            return CreateSimpleElement("string", interpreted, key, store, isRoot);

        // When escape=true, check if the raw JSON string contains escape sequences
        var raw = je.GetRawText(); // includes surrounding quotes
        var hasEscapes = raw.Length > 2 && raw.AsSpan(1, raw.Length - 2).Contains('\\');
        var elem = CreateSimpleElement("string", interpreted, key, store, isRoot);
        if (hasEscapes)
        {
            // Add escaped="true" attribute per XSLT 3.0 §22.1.2
            AddAttribute(elem.Id, NamespaceId.None, "escaped", "true", elem.Attributes as List<NodeId> ?? new List<NodeId>(), store);
        }
        return elem;
    }

    private static XdmElement CreateSimpleElement(string localName, string textValue, string? key, XdmInMemoryStore store, bool isRoot = false)
    {
        var elemId = store.NextId();
        var attrs = new List<NodeId>();

        if (key != null)
            AddKeyAttribute(elemId, key, attrs, store);

        var textId = store.NextId();
        var text = new XdmText
        {
            Id = textId,
            Document = default,
            Value = textValue,
            Parent = elemId
        };
        store.Register(text);

        var elem = new XdmElement
        {
            Id = elemId,
            Document = default,
            Namespace = FnNs,
            LocalName = localName,
            Prefix = null,
            Attributes = attrs,
            Children = new[] { textId },
            NamespaceDeclarations = isRoot ? FnNsDecl : System.Collections.Immutable.ImmutableArray<NamespaceBinding>.Empty,
            _stringValue = textValue
        };
        store.Register(elem);
        return elem;
    }

    private static XdmElement CreateNullElement(string? key, XdmInMemoryStore store, bool isRoot = false)
    {
        var elemId = store.NextId();
        var attrs = new List<NodeId>();

        if (key != null)
            AddKeyAttribute(elemId, key, attrs, store);

        var elem = new XdmElement
        {
            Id = elemId,
            Document = default,
            Namespace = FnNs,
            LocalName = "null",
            Prefix = null,
            Attributes = attrs,
            Children = System.Collections.Immutable.ImmutableArray<NodeId>.Empty,
            NamespaceDeclarations = isRoot ? FnNsDecl : System.Collections.Immutable.ImmutableArray<NamespaceBinding>.Empty
        };
        store.Register(elem);
        return elem;
    }

    private static void AddKeyAttribute(NodeId parentId, string key, List<NodeId> attrs, XdmInMemoryStore store)
    {
        AddAttribute(parentId, NamespaceId.None, "key", key, attrs, store);
    }

    private static void AddAttribute(NodeId parentId, NamespaceId ns, string localName, string value, List<NodeId> attrs, XdmInMemoryStore store)
    {
        var attrId = store.NextId();
        var attr = new XdmAttribute
        {
            Id = attrId,
            Document = default,
            Namespace = ns,
            LocalName = localName,
            Value = value,
            Parent = parentId
        };
        store.Register(attr);
        attrs.Add(attrId);
    }

    private static void EnsureFnNamespace(XdmInMemoryStore store)
    {
        store.RegisterKnownNamespace(FnNs, "http://www.w3.org/2005/xpath-functions");
    }
}

// ─── fn:parse-json ──────────────────────────────────────────────────────────

/// <summary>
/// fn:parse-json($json-text as xs:string) as item()?
/// Parses a JSON string and returns an XDM map/array/atomic value.
/// </summary>
internal sealed class XsltParseJsonFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltParseJsonFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "parse-json");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalItem;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "json-text"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        var jsonText = arguments[0]?.ToString();
        if (jsonText is null)
            return ValueTask.FromResult<object?>(null);

        try
        {
            using var jsonDoc = System.Text.Json.JsonDocument.Parse(jsonText,
                new System.Text.Json.JsonDocumentOptions { AllowTrailingCommas = true, CommentHandling = System.Text.Json.JsonCommentHandling.Skip });
            var result = ConvertJsonToXdm(jsonDoc.RootElement);
            return ValueTask.FromResult(result);
        }
        catch (System.Text.Json.JsonException ex)
        {
            throw new XsltException($"FOJS0001: Invalid JSON: {ex.Message}");
        }
    }

    internal static object? ConvertJsonToXdm(System.Text.Json.JsonElement je)
    {
        return je.ValueKind switch
        {
            System.Text.Json.JsonValueKind.Object => ConvertObject(je),
            System.Text.Json.JsonValueKind.Array => ConvertArray(je),
            System.Text.Json.JsonValueKind.String => je.GetString(),
            System.Text.Json.JsonValueKind.Number => je.TryGetInt64(out var l) ? (object)l : je.GetDouble(),
            System.Text.Json.JsonValueKind.True => true,
            System.Text.Json.JsonValueKind.False => false,
            System.Text.Json.JsonValueKind.Null => null,
            _ => throw new XsltException($"FOJS0001: Unsupported JSON value kind: {je.ValueKind}")
        };
    }

    private static OrderedXdmMap ConvertObject(System.Text.Json.JsonElement je)
    {
        var map = new OrderedXdmMap(EqualityComparer<object>.Default);
        foreach (var prop in je.EnumerateObject())
        {
            map[prop.Name] = ConvertJsonToXdm(prop.Value);
        }
        return map;
    }

    private static List<object?> ConvertArray(System.Text.Json.JsonElement je)
    {
        // Return List<object?> — the engine's XDM array representation (a single item).
        // Returning object?[] would be treated as a SEQUENCE and flattened by the
        // function-call machinery, so parse-json('[...]') would lose its array-ness
        // (Martin Honnen: parse-json($json)?* yielded the flattened members, and a
        // subsequent ?lookup hit a string → XPTY0004).
        var items = new List<object?>();
        foreach (var item in je.EnumerateArray())
        {
            items.Add(ConvertJsonToXdm(item));
        }
        return items;
    }
}

/// <summary>
/// fn:parse-json($json-text, $options) — 2-arg version
/// </summary>
internal sealed class XsltParseJson2Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;

    public XsltParseJson2Function(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "parse-json");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => PhoenixmlDb.XQuery.Ast.XdmSequenceType.OptionalItem;
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "json-text"), Type = PhoenixmlDb.XQuery.Ast.XdmSequenceType.String },
        new() { Name = new QName(NamespaceId.None, "options"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType { ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Item, Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ZeroOrOne } }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        return new XsltParseJsonFunction(_context).InvokeAsync(
            new object?[] { arguments[0] }, context);
    }
}

/// <summary>
/// Validates that a string argument is a valid QName or EQName.
/// Used by system-property, function-available, element-available, and key functions.
/// </summary>
file static class XsltFunctionValidation
{
    internal static void ValidateQNameArgument(string name, string errorCode, string functionName)
    {
        if (string.IsNullOrEmpty(name))
            throw new XsltException($"{errorCode}: The argument to {functionName}() is a zero-length string");

        // EQName syntax Q{...}local is always valid if it can be parsed
        if (name.StartsWith("Q{", StringComparison.Ordinal))
            return;

        try
        {
            var colonIdx = name.IndexOf(':', StringComparison.Ordinal);
            if (colonIdx >= 0)
            {
                System.Xml.XmlConvert.VerifyNCName(name[..colonIdx]);
                System.Xml.XmlConvert.VerifyNCName(name[(colonIdx + 1)..]);
            }
            else
            {
                System.Xml.XmlConvert.VerifyNCName(name);
            }
        }
        catch (System.Xml.XmlException)
        {
            throw new XsltException($"{errorCode}: The argument to {functionName}() ('{name}') is not a valid EQName");
        }
    }
}

// ─── fn:analyze-string ──────────────────────────────────────────────────────

/// <summary>
/// fn:analyze-string($input as xs:string?, $pattern as xs:string) as element(fn:analyze-string-result)
/// </summary>
internal sealed class XsltAnalyzeStringFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private static readonly System.Xml.Linq.XNamespace FnNs = "http://www.w3.org/2005/xpath-functions";

    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "analyze-string");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Element, Occurrence = Occurrence.ExactlyOne };
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "input"), Type = XdmSequenceType.OptionalString },
        new() { Name = new QName(NamespaceId.None, "pattern"), Type = XdmSequenceType.String }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        return AnalyzeStringCore(arguments[0], arguments[1]?.ToString() ?? "", "");
    }

    internal static ValueTask<object?> AnalyzeStringCore(object? inputArg, string pattern, string flags)
    {
        var input = inputArg?.ToString() ?? "";

        // Validate flags
        foreach (var ch in flags)
        {
            if (ch is not ('s' or 'm' or 'i' or 'x' or 'q'))
                throw new XsltException($"FORX0001: Invalid flag '{ch}' in fn:analyze-string flags. Valid flags are: s, m, i, x, q");
        }

        var regexOptions = System.Text.RegularExpressions.RegexOptions.None;
        if (flags.Contains('i', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.IgnoreCase;
        if (flags.Contains('m', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.Multiline;
        if (flags.Contains('s', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.Singleline;
        if (flags.Contains('x', StringComparison.Ordinal))
            regexOptions |= System.Text.RegularExpressions.RegexOptions.IgnorePatternWhitespace;

        string netPattern;
        if (flags.Contains('q', StringComparison.Ordinal))
        {
            netPattern = System.Text.RegularExpressions.Regex.Escape(pattern);
        }
        else
        {
            PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ValidateXsdRegex(pattern);
            netPattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ConvertXPathPatternToNet(pattern);
        }
        netPattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.ConvertXsdEscapesToNet(netPattern);
        if (!flags.Contains('m', StringComparison.Ordinal))
            netPattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.FixDollarAnchor(netPattern);
        netPattern = PhoenixmlDb.XQuery.Functions.XQueryRegexHelper.FixDotForSurrogatePairs(netPattern);

        System.Text.RegularExpressions.Regex regex;
        try
        {
            regex = new System.Text.RegularExpressions.Regex(netPattern, regexOptions);
        }
        catch (System.ArgumentException ex)
        {
            throw new XsltException($"FORX0002: Invalid regular expression '{pattern}': {ex.Message}");
        }

        // Check that the pattern doesn't match a zero-length string
        if (regex.IsMatch(""))
            throw new XsltException($"FORX0003: The regular expression '{pattern}' matches a zero-length string");

        var result = new System.Xml.Linq.XElement(FnNs + "analyze-string-result");
        var lastIndex = 0;

        for (var match = regex.Match(input); match.Success; match = match.NextMatch())
        {
            // Non-matching text before this match
            if (match.Index > lastIndex)
            {
                result.Add(new System.Xml.Linq.XElement(FnNs + "non-match", input[lastIndex..match.Index]));
            }

            // Build the match element
            var matchElem = new System.Xml.Linq.XElement(FnNs + "match");

            if (match.Groups.Count <= 1)
            {
                // No capturing groups — just the match text
                matchElem.Add(match.Value);
            }
            else
            {
                // Has capturing groups — build group elements
                BuildMatchContent(matchElem, match, input, match.Index, match.Index + match.Length);
            }

            result.Add(matchElem);
            lastIndex = match.Index + match.Length;
        }

        // Trailing non-matching text
        if (lastIndex < input.Length)
        {
            result.Add(new System.Xml.Linq.XElement(FnNs + "non-match", input[lastIndex..]));
        }

        return ValueTask.FromResult<object?>(result);
    }

    /// <summary>
    /// Build the content of a fn:match element, interleaving text and fn:group elements.
    /// Groups are identified by their capture index (Groups[1], Groups[2], etc.).
    /// </summary>
    private static void BuildMatchContent(System.Xml.Linq.XElement matchElem, System.Text.RegularExpressions.Match match, string input, int start, int end)
    {
        // Collect all group captures with their positions, sorted by position
        var segments = new List<(int Start, int End, int GroupNr, string Value)>();

        for (int g = 1; g < match.Groups.Count; g++)
        {
            var group = match.Groups[g];
            if (group.Success)
            {
                segments.Add((group.Index, group.Index + group.Length, g, group.Value));
            }
        }

        // Sort by start position, then by widest span (outermost first)
        segments.Sort((a, b) =>
        {
            var cmp = a.Start.CompareTo(b.Start);
            if (cmp != 0)
                return cmp;
            return b.End.CompareTo(a.End); // wider (outer) first
        });

        // Build a flat list of match text and group elements
        // For simplicity, handle non-nested groups
        var pos = start;
        foreach (var seg in segments)
        {
            // Skip groups that are contained within a previous group we already processed
            if (seg.Start < pos)
                continue;

            // Text before this group
            if (seg.Start > pos)
            {
                matchElem.Add(input[pos..seg.Start]);
            }

            var groupElem = new System.Xml.Linq.XElement(FnNs + "group",
                new System.Xml.Linq.XAttribute("nr", seg.GroupNr),
                seg.Value);
            matchElem.Add(groupElem);
            pos = seg.End;
        }

        // Trailing text after last group
        if (pos < end)
        {
            matchElem.Add(input[pos..end]);
        }
    }
}

/// <summary>
/// fn:analyze-string($input as xs:string?, $pattern as xs:string, $flags as xs:string) as element(fn:analyze-string-result)
/// </summary>
internal sealed class XsltAnalyzeString3Function : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "analyze-string");
    public override XdmSequenceType ReturnType => new() { ItemType = ItemType.Element, Occurrence = Occurrence.ExactlyOne };
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "input"), Type = XdmSequenceType.OptionalString },
        new() { Name = new QName(NamespaceId.None, "pattern"), Type = XdmSequenceType.String },
        new() { Name = new QName(NamespaceId.None, "flags"), Type = XdmSequenceType.String }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        return XsltAnalyzeStringFunction.AnalyzeStringCore(arguments[0], arguments[1]?.ToString() ?? "", arguments[2]?.ToString() ?? "");
    }
}

/// <summary>
/// EXSLT exsl:node-set() — converts a result tree fragment to a node set.
/// In XSLT 2.0+, RTFs are automatically treated as node sequences, so this is an identity function.
/// </summary>
internal sealed class ExslNodeSetFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private static readonly NamespaceId ExslNs = StylesheetParser.ResolveNamespaceUri("http://exslt.org/common");
    private readonly DefaultXsltExecutionContext _context;

    public ExslNodeSetFunction(DefaultXsltExecutionContext context) => _context = context;

    public override QName Name => new(ExslNs, "node-set", "exsl");
    public override XdmSequenceType ReturnType => XdmSequenceType.ZeroOrMoreItems;
    public override IReadOnlyList<FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "rtf"), Type = XdmSequenceType.ZeroOrMoreItems }
    ];

    public override ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        // In XSLT 2.0+, exsl:node-set() is an identity function since RTFs are automatically
        // converted to XDM node sequences. Use ConvertRtfForXQuery to handle RTF conversion.
        return ValueTask.FromResult(_context.ConvertRtfForXQuery(arguments[0]));
    }
}

/// <summary>
/// fn:transform($options as map(*)) as map(*)
/// Runs an XSLT transformation and returns the result as a map.
/// XSLT 3.0 §25.3 / XPath Functions and Operators §17.2.
/// </summary>
internal sealed class XsltTransformFunction : PhoenixmlDb.XQuery.Ast.XQueryFunction
{
    private readonly DefaultXsltExecutionContext _context;
    public XsltTransformFunction(DefaultXsltExecutionContext context) => _context = context;
    public override QName Name => new(PhoenixmlDb.XQuery.Functions.FunctionNamespaces.Fn, "transform");
    public override PhoenixmlDb.XQuery.Ast.XdmSequenceType ReturnType => new()
    {
        ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Map,
        Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ExactlyOne
    };
    public override IReadOnlyList<PhoenixmlDb.XQuery.Ast.FunctionParameterDef> Parameters =>
    [
        new() { Name = new QName(NamespaceId.None, "options"), Type = new PhoenixmlDb.XQuery.Ast.XdmSequenceType
        {
            ItemType = PhoenixmlDb.XQuery.Ast.ItemType.Map,
            Occurrence = PhoenixmlDb.XQuery.Ast.Occurrence.ExactlyOne
        }}
    ];

    public override async ValueTask<object?> InvokeAsync(
        IReadOnlyList<object?> arguments,
        PhoenixmlDb.XQuery.Ast.ExecutionContext context)
    {
        if (arguments[0] is not IDictionary<object, object?> options)
            throw new XsltException("FOXT0001: The argument to fn:transform must be a map");

        // Extract options
        var stylesheetLocation = GetStringOption(options, "stylesheet-location");
        var stylesheetNode = GetOption(options, "stylesheet-node");
        var stylesheetText = GetStringOption(options, "stylesheet-text");
        var packageName = GetStringOption(options, "package-name");
        var packageVersion = GetStringOption(options, "package-version");
        var deliveryFormat = GetStringOption(options, "delivery-format") ?? "document";
        var postProcessFn = GetOption(options, "post-process") as PhoenixmlDb.XQuery.Ast.XQueryFunction;
        var initialTemplate = GetQNameOption(options, "initial-template");
        var initialMode = GetQNameOption(options, "initial-mode");
        var initialFunctionQName = GetQNameOption(options, "initial-function");
        var functionParamsRaw = GetOption(options, "function-params");
        var sourceNode = GetOption(options, "source-node");
        var initialMatchSelection = GetOption(options, "initial-match-selection");
        var staticParamsMap = GetOption(options, "static-params") as IDictionary<object, object?>;

        // Load the stylesheet
        string stylesheetXml;
        Uri? baseUri = null;

        if (stylesheetLocation != null)
        {
            // Resolve relative URI against static base URI
            var resolvedUri = stylesheetLocation;
            string? staticBase = null;
            if (context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qec)
                staticBase = qec.StaticBaseUri;
            if (staticBase != null && !Uri.TryCreate(resolvedUri, UriKind.Absolute, out _))
            {
                if (Uri.TryCreate(staticBase, UriKind.Absolute, out var sbu))
                {
                    var resolved = new Uri(sbu, resolvedUri);
                    resolvedUri = resolved.AbsoluteUri;
                    baseUri = resolved;
                }
            }
            else if (Uri.TryCreate(resolvedUri, UriKind.Absolute, out var absUri))
            {
                baseUri = absUri;
            }

            // Load the stylesheet content from the resolved URI
            if (baseUri != null && baseUri.IsFile)
                stylesheetXml = await System.IO.File.ReadAllTextAsync(baseUri.LocalPath).ConfigureAwait(false);
            else if (baseUri != null && (baseUri.Scheme == Uri.UriSchemeHttp || baseUri.Scheme == Uri.UriSchemeHttps))
            {
                // HTTP(S) stylesheet-location: consult preload cache first, then fetch.
                // Previously this hit File.ReadAllTextAsync(resolvedUri) which on Linux/WASM
                // mangled "https://host/..." into "/https:/host/..." (Path normalization
                // collapsed the double slash) and threw FileNotFoundException — Martin
                // Honnen's Docbook-on-Blazor fn:transform repro.
                var preloaded = _context._options.PreloadedResources;
                if (preloaded != null && preloaded.TryGet(baseUri, out var preloadedContent))
                {
                    stylesheetXml = preloadedContent;
                }
                else if (OperatingSystem.IsBrowser())
                {
                    throw new XsltException(
                        $"FOXT0001: Cannot fetch stylesheet '{baseUri}' on Blazor WebAssembly: " +
                        "synchronous HTTP I/O is not supported. Pre-fetch the stylesheet " +
                        "asynchronously and pass it through PreloadedResources to LoadStylesheetAsync.");
                }
                else
                {
                    stylesheetXml = await HttpResourceLoader.GetStringAsync(baseUri).ConfigureAwait(false);
                }
            }
            else if (baseUri != null)
                stylesheetXml = await System.IO.File.ReadAllTextAsync(resolvedUri).ConfigureAwait(false);
            else
            {
                // Try as file path
                var dir = staticBase != null
                    ? System.IO.Path.GetDirectoryName(new Uri(staticBase).LocalPath) ?? "."
                    : ".";
                var fullPath = System.IO.Path.Combine(dir, resolvedUri);
                stylesheetXml = await System.IO.File.ReadAllTextAsync(fullPath).ConfigureAwait(false);
                baseUri = new Uri(fullPath);
            }
        }
        else if (stylesheetNode is Xdm.Nodes.XdmNode node)
        {
            // Serialize the node to XML — StringValue strips markup which breaks parsing
            stylesheetXml = _context.SerializeXdmNodeToXml(node);
            if (string.IsNullOrWhiteSpace(stylesheetXml))
                throw new XsltException("FOXT0001: Stylesheet node has no content");
        }
        else if (stylesheetText != null)
        {
            stylesheetXml = stylesheetText;
        }
        else if (packageName != null)
        {
            // Resolve package from catalog
            var catalog = _context._stylesheet.PackageCatalog;
            if (catalog == null || !catalog.TryGetValue(packageName, out var entries))
                throw new XsltException($"FOXT0001: Package '{packageName}' not found");

            // Version matching
            string? matchedFile = null;
            foreach (var (ver, path) in entries)
            {
                if (packageVersion == null || StylesheetParser.VersionMatchesPublic(ver, packageVersion))
                {
                    matchedFile = path;
                    break;
                }
            }
            if (matchedFile == null)
                throw new XsltException($"FOXT0001: No matching version for package '{packageName}' (requested '{packageVersion}')");

            stylesheetXml = await System.IO.File.ReadAllTextAsync(matchedFile).ConfigureAwait(false);
            baseUri = new Uri(System.IO.Path.GetFullPath(matchedFile));
        }
        else
        {
            throw new XsltException("FOXT0001: No stylesheet specified (stylesheet-location, stylesheet-node, stylesheet-text, or package-name required)");
        }

        // Parse the stylesheet, passing static-params if provided. Forward
        // PreloadedResources so xsl:imports inside the dynamically-loaded
        // stylesheet also benefit from the host's pre-fetched cache (WASM).
        var exprParser = new PhoenixmlDb.Xslt.XQueryExpressionParser();
        var catalog2 = _context._stylesheet.PackageCatalog;
        var parser = catalog2 != null
            ? new StylesheetParser(exprParser, catalog2) { PreloadedResources = _context._options.PreloadedResources }
            : new StylesheetParser(exprParser) { PreloadedResources = _context._options.PreloadedResources };
        Dictionary<string, string>? externalStaticParams = null;
        if (staticParamsMap != null)
        {
            externalStaticParams = new Dictionary<string, string>();
            foreach (var (key, value) in staticParamsMap)
            {
                // Keys are QNames — use local name for unprefixed, Q{uri}local for namespaced
                var paramName = key is QName qn
                    ? (qn.Namespace != NamespaceId.None && !string.IsNullOrEmpty(qn.ExpandedNamespace)
                        ? $"Q{{{qn.ExpandedNamespace}}}{qn.LocalName}"
                        : qn.LocalName)
                    : key.ToString() ?? "";
                externalStaticParams[paramName] = DefaultXsltExecutionContext.StringValueOf(value);
            }
        }
        var stylesheet = parser.Parse(stylesheetXml, baseUri, externalStaticParams);

        // Unwrap source-node if it came wrapped in a single-item sequence (from map constructor)
        if (sourceNode is object?[] srcArr && srcArr.Length == 1)
            sourceNode = srcArr[0];

        // Build transform options
        var hasSource = sourceNode is Xdm.Nodes.XdmNode;
        string? initialModeSelect = null;
        if (initialMatchSelection != null && !hasSource && !initialTemplate.HasValue)
            initialModeSelect = ConvertToSelectExpression(initialMatchSelection);

        // Build initial parameters from static-params (they serve as both compile-time
        // and runtime values) plus any regular stylesheet-params
        var initialParams = new Dictionary<QName, object?>();
        if (staticParamsMap != null)
        {
            foreach (var (key, value) in staticParamsMap)
            {
                var qn = key is QName q ? q : new QName(NamespaceId.None, key.ToString() ?? "");
                initialParams[qn] = DefaultXsltExecutionContext.StringValueOf(value);
            }
        }

        // initial-function: extract function-params (XDM array → IList) and pass to engine.
        // Mirrors XsltTransformProvider's path used when fn:transform is invoked from
        // XQuery — the XSLT-internal path was previously dropping these on the floor,
        // so calling fn:transform with initial-function from inside an XSLT silently
        // returned empty (Martin Honnen 2026-05-15 follow-up to #60).
        //
        // XdmNode arguments are serialized to XML here using the OUTER engine's node
        // store (this is the only place we still have access to it). The inner engine's
        // TransformRawAsync recognises the CrossStoreNodeRef wrapper and re-parses the
        // XML into its own node store, so xsl:evaluate / XPath inside the function can
        // navigate the node (Martin Honnen 2026-05-18: string($context-item) was
        // returning empty because the foreign node's child NodeIds didn't resolve in
        // the inner store).
        //
        // fn:QName(uri, localName) creates a QName with NamespaceId.None and only
        // ResolvedNamespace populated. The engine's function lookup keys on QName
        // equality, which uses the interned NamespaceId — so we must re-intern the
        // namespace via StylesheetParser to match the registered function key.
        QName? resolvedInitialFunction = initialFunctionQName;
        if (initialFunctionQName is { } ifq && !string.IsNullOrEmpty(ifq.ResolvedNamespace))
        {
            var nsId = StylesheetParser.ResolveNamespaceUri(ifq.ResolvedNamespace);
            if (nsId != ifq.Namespace)
            {
                resolvedInitialFunction = new QName(nsId, ifq.LocalName, ifq.Prefix)
                { ExpandedNamespace = ifq.ExpandedNamespace, RuntimeNamespace = ifq.RuntimeNamespace };
            }
        }
        var initialFunctionArgs = new List<object?>();
        if (resolvedInitialFunction != null && functionParamsRaw is System.Collections.IList paramList)
        {
            foreach (var item in paramList)
            {
                if (item is Xdm.Nodes.XdmElement or Xdm.Nodes.XdmDocument)
                {
                    // Wrap with the outer engine's XML serialization. The inner engine
                    // unwraps and re-parses into its own node store.
                    var xml = _context.SerializeXdmNodeToXml((Xdm.Nodes.XdmNode)item);
                    initialFunctionArgs.Add(new XsltTransformEngine.CrossStoreNodeRef(xml, IsElement: item is Xdm.Nodes.XdmElement));
                }
                else
                {
                    initialFunctionArgs.Add(item);
                }
            }
        }

        var transformOptions = new XsltTransformOptions
        {
            InitialTemplate = initialTemplate,
            InitialMode = initialMode,
            InitialFunction = resolvedInitialFunction,
            InitialFunctionArguments = initialFunctionArgs,
            HasSourceDocument = hasSource,
            InitialModeSelect = initialModeSelect,
            InitialParameters = initialParams,
        };

        // Create engine and run transformation
        var engine = new XsltTransformEngine(stylesheet);
        var isRaw = string.Equals(deliveryFormat, "raw", StringComparison.Ordinal);

        // Determine the base URI to stamp on result document nodes (delivery-format='document').
        // Per XSLT 3.0 a result tree's document node carries a non-null static base URI; without
        // this the parsed result tree had base-uri(.)='' and DocBook's m:docbook pass (which runs
        // over the in-engine fn:transform result) hit FORG0002 in resolve-uri(@fileref, base-uri(.)).
        // DocBook's fp:run-transforms calls transform() from *inside* an XSLT stylesheet, so it
        // runs through this in-engine path — not XsltTransformProvider.
        // Precedence: base-output-uri option → source node's base → caller's static base.
        string? resultBaseUri = GetStringOption(options, "base-output-uri");
        if (resultBaseUri == null && sourceNode is Xdm.Nodes.XdmNode srcBaseNode)
            resultBaseUri = PhoenixmlDb.XQuery.Functions.BaseUriFunction.ComputeBaseUri(srcBaseNode, _context._nodeStore);
        if (resultBaseUri == null && context is PhoenixmlDb.XQuery.Execution.QueryExecutionContext qecBase)
            resultBaseUri = qecBase.StaticBaseUri;

        // Build result map
        var resultMap = new OrderedXdmMap(EqualityComparer<object>.Default);

        if (isRaw)
        {
            // Raw delivery: get XDM values directly (preserves function items, maps, etc.)
            object? rawResult;
            if (sourceNode is Xdm.Nodes.XdmNode srcNode)
            {
                var rawSrcXml = _context.SerializeXdmNodeToXml(srcNode);
                rawResult = await engine.TransformRawAsync(rawSrcXml, transformOptions).ConfigureAwait(false);
            }
            else
            {
                rawResult = await engine.TransformRawAsync("<empty/>", transformOptions).ConfigureAwait(false);
            }
            resultMap["output"] = rawResult;

            foreach (var (href, content) in engine.SecondaryResultDocuments)
                resultMap[href] = ParseResultAsXdm(content);
        }
        else
        {
            string result;
            if (sourceNode is Xdm.Nodes.XdmNode srcNode)
            {
                // Serialize the source node to XML so the inner engine can parse and
                // register it in its own node store. Passing the outer node store directly
                // doesn't work because the inner engine needs its own independent store
                // for nodes it creates during transformation.
                var srcXml = _context.SerializeXdmNodeToXml(srcNode);
                result = await engine.TransformAsync(srcXml, transformOptions).ConfigureAwait(false);
            }
            else
            {
                result = await engine.TransformAsync("<empty/>", transformOptions).ConfigureAwait(false);
            }

            if (string.Equals(deliveryFormat, "serialized", StringComparison.Ordinal))
            {
                resultMap["output"] = result;
            }
            else
            {
                resultMap["output"] = !string.IsNullOrEmpty(result) ? ParseResultAsDocument(result, _context._nodeStore, resultBaseUri) : null;
            }

            foreach (var (href, content) in engine.SecondaryResultDocuments)
            {
                if (string.Equals(deliveryFormat, "serialized", StringComparison.Ordinal))
                    resultMap[href] = content;
                else
                {
                    // A secondary result document's base URI is its own (absolute) href,
                    // resolved against the result base when relative.
                    string? secondaryBase = href;
                    if (!Uri.TryCreate(href, UriKind.Absolute, out _)
                        && resultBaseUri != null
                        && Uri.TryCreate(resultBaseUri, UriKind.Absolute, out var rbu)
                        && Uri.TryCreate(rbu, href, out var resolvedHref))
                    {
                        secondaryBase = resolvedHref.AbsoluteUri;
                    }
                    resultMap[href] = ParseResultAsDocument(content, _context._nodeStore, secondaryBase);
                }
            }
        }

        // Apply post-process function to each result document
        if (postProcessFn != null)
        {
            var keys = new List<object>(resultMap.Keys);
            foreach (var key in keys)
            {
                var uri = key is string s ? s : key.ToString() ?? "";
                var result = resultMap[key];
                var args = new List<object?> { uri, result };
                var processed = await postProcessFn.InvokeAsync(args, context).ConfigureAwait(false);
                resultMap[key] = processed;
            }
        }

        return resultMap;
    }

    private static string ConvertToSelectExpression(object? value)
    {
        // Convert a runtime value to an XPath expression string
        if (value is null) return "''";
        return value switch
        {
            int i => i.ToString(System.Globalization.CultureInfo.InvariantCulture),
            long l => l.ToString(System.Globalization.CultureInfo.InvariantCulture),
            double d => DefaultXsltExecutionContext.FormatDouble(d),
            decimal m => m.ToString(System.Globalization.CultureInfo.InvariantCulture),
            string s => $"'{s.Replace("'", "''", StringComparison.Ordinal)}'",
            bool b => b ? "true()" : "false()",
            _ => value.ToString() ?? "''"
        };
    }

    private static object? ParseResultAsDocument(string xml, XdmInMemoryStore? store = null, string? resultBaseUri = null)
    {
        if (string.IsNullOrWhiteSpace(xml))
            return null;
        try
        {
            var xmlDoc = new System.Xml.XmlDocument();
            xmlDoc.PreserveWhitespace = true;
            xmlDoc.LoadXml(xml);
            store ??= new XdmInMemoryStore();
            var doc = XsltTransformEngine.ConvertToXdm(xmlDoc, store);
            // Result trees have no document URI, but per XSLT 3.0 their document node carries
            // a non-null static base URI. DocBook's m:docbook pass runs over this tree and a
            // null base produced base-uri(.)='' → FORG0002 in resolve-uri(@fileref, base-uri(.)).
            if (resultBaseUri != null)
                doc.BaseUri = resultBaseUri;
            return doc;
        }
        catch (System.Xml.XmlException)
        {
            // Not well-formed XML — return as text
            return xml;
        }
    }

    private static object? ParseResultAsXdm(string xml)
    {
        if (string.IsNullOrWhiteSpace(xml))
            return null;
        try
        {
            var xmlDoc = new System.Xml.XmlDocument();
            xmlDoc.PreserveWhitespace = true;
            xmlDoc.LoadXml($"<_wrap_>{xml}</_wrap_>");
            var nodeStore = new XdmInMemoryStore();
            var xdmDoc = XsltTransformEngine.ConvertToXdm(xmlDoc, nodeStore);
            if (xdmDoc.DocumentElement.HasValue && xdmDoc.DocumentElement.Value != NodeId.None)
            {
                var wrapper = nodeStore.GetNode(xdmDoc.DocumentElement.Value) as Xdm.Nodes.XdmElement;
                if (wrapper != null)
                {
                    var children = nodeStore.GetChildren(wrapper).ToList();
                    if (children.Count == 1)
                    {
                        if (children[0] is Xdm.Nodes.XdmNode cn)
                            cn.Parent = null;
                        return children[0];
                    }
                    foreach (var child in children)
                    {
                        if (child is Xdm.Nodes.XdmNode cn)
                            cn.Parent = null;
                    }
                    return children.ToArray();
                }
            }
            return xml;
        }
        catch (System.Xml.XmlException)
        {
            return xml;
        }
    }

    private static string? GetStringOption(IDictionary<object, object?> options, string key)
    {
        if (options.TryGetValue(key, out var val) && val != null)
            return DefaultXsltExecutionContext.StringValueOf(val);
        return null;
    }

    private static object? GetOption(IDictionary<object, object?> options, string key)
    {
        options.TryGetValue(key, out var val);
        return val;
    }

    private static QName? GetQNameOption(IDictionary<object, object?> options, string key)
    {
        if (!options.TryGetValue(key, out var val) || val == null)
            return null;
        if (val is QName qn)
        {
            // Resolve RuntimeNamespace/ExpandedNamespace to well-known NamespaceId
            // fn:QName() creates hash-based NamespaceIds that don't match well-known ones
            var resolved = qn.ResolvedNamespace;
            if (resolved != null)
            {
                var nsId = ResolveWellKnownNamespace(resolved);
                if (nsId != qn.Namespace)
                {
                    return new QName(nsId, qn.LocalName, qn.Prefix)
                        { ExpandedNamespace = qn.ExpandedNamespace, RuntimeNamespace = qn.RuntimeNamespace };
                }
            }
            return qn;
        }
        // String value — parse as QName (NCName or EQName)
        var str = DefaultXsltExecutionContext.StringValueOf(val);
        if (str.StartsWith("Q{", StringComparison.Ordinal))
        {
            var closeBrace = str.IndexOf('}', 2);
            if (closeBrace > 0)
            {
                var ns = str[2..closeBrace];
                var local = str[(closeBrace + 1)..];
                var nsId = ResolveWellKnownNamespace(ns);
                return new QName(nsId, local) { ExpandedNamespace = ns };
            }
        }
        return new QName(NamespaceId.None, str);
    }

    private static NamespaceId ResolveWellKnownNamespace(string uri)
    {
        return uri switch
        {
            "http://www.w3.org/1999/XSL/Transform" => NamespaceId.Xslt,
            "http://www.w3.org/2001/XMLSchema" => NamespaceId.Xsd,
            "http://www.w3.org/XML/1998/namespace" => NamespaceId.Xml,
            "http://www.w3.org/2000/xmlns/" => NamespaceId.Xmlns,
            "http://www.w3.org/2005/xpath-functions" => NamespaceId.Fn,
            "http://www.w3.org/2005/xpath-functions/map" => NamespaceId.Map,
            "http://www.w3.org/2005/xpath-functions/array" => NamespaceId.Array,
            "http://www.w3.org/2005/xpath-functions/math" => NamespaceId.Math,
            _ => NamespaceId.None
        };
    }
}
